INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73kx0002eh0s4qyjorou', 'STAR POINT', 'star-point', NULL, 'Moda', 'VestuĂĄrios', 'Rede de lojas especializadas na comercializaĂ§ĂŁo de equipamentos de surf e skate, acessĂłrios moda praia e surfwear', 2000, 2005, '[\"https://www.youtube.com/watch?v=false\"]', '2026-04-01 02:00:00.205', '2025-08-05 22:20:24.033', 39, NULL, 1, 1982, 'A Star Point Ă© uma rede de lojas franqueadas especializada na comercializaĂ§ĂŁo de produtos masculinos e femininos moda praia, surf e skate, e possui as mais renomadas marcas nacionais e internacionais. O mix de produtos Ă© composto por camisetas, calĂ§as, bermudas, jaquetas, biquĂ­nis, maiĂŽs, Ăłculos, relĂłgios, tĂȘnis, pranchas e equipamentos de surf e skate. \nDesde 1984, a Star Point Ă© apontada como a melhor surf shop em todas as pesquisas das principais revistas de surf no paĂ­s. Em 2004 foi reconhecida como a âLoja do Anoâ por um colĂ©gio eleitoral composto por representantes da mĂ­dia e entidades do setor, fato que se repetiu em 2006. Em 2010 conquistou o PrĂȘmio de Design que premia arquitetura e ambientaĂ§ĂŁo de loja, promovido pela ABF / Retail Design Institute (RDI), prĂȘmio tambĂ©m conquistado em 2012. Ainda em 2010 o prĂȘmio \"Os melhores da Praiaâ concedido pela revista Alma Surf fato que se repetiu tambĂ©m em 2011. Â  Â   \nDesde 2000 a Star Point resolveu expandir seus limites e formatou um projeto de franquia e como nĂŁo poderia deixar de ser, o sucesso se repetiu nessas lojas, que multiplicam, a cada dia, o conceito de uma \"surf shop for real surfers\". A Star Point conta com lojas situadas nos melhores shoppings do Brasil. Como empresa franqueadora conquistou em 2011 o selo de excelĂȘncia em franchising pela ABF (AssociaĂ§ĂŁo Brasileira de Franchising) e o prĂȘmio Alshop (AssociaĂ§ĂŁo Brasileira de Lojistas de Shoppings) na categoria moda surf. \nA contĂ­nua busca por inovaĂ§Ă”es e tendĂȘncias, acompanhadas de um atendimento com excelĂȘncia, tornam a Star Point uma referĂȘncia em seu segmento. A Star Point oferece uma sĂ©rie de vantagens aos franqueados, como a assessoria na seleĂ§ĂŁo de ponto comercial, planejamento financeiro, suporte e treinamento para equipe, alĂ©m de aĂ§Ă”es de marketing. \nA Star Point busca candidatos para as principais cidades do PaĂ­s.', NULL, 'SĂO PAULO', 1, NULL, 11, NULL, NULL, '2026-03-08 16:10:54.263', 'https://franquias.portaldofranchising.com.br/franquia-star-point-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '435000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
