INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ll0005eh0sfyvwydkc', 'SPIDER KICK', 'spider-kick', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studio de treinamento funcional com elementos da preparaĂ§ĂŁo fĂ­sica do Anderson Silva, que utiliza a metodologia HIIT e monitoramento cardĂ­aco do cliente durante toda a experiĂȘncia de treino.', 2021, 2021, '[\"https://www.youtube.com/watch?v=qT_dOTOzBZ4\"]', '2026-04-01 02:00:00.256', '2025-08-05 22:20:24.058', 42, NULL, 1, 2020, 'A SPIDER KICK nasceu da parceria entre o maior campeĂŁo de todos os tempos no MMA, Anderson Silva, e a experiĂȘncia de um dos maiores nomes do fitness nacional, Fernando Nero, que dentre suas realizaĂ§Ă”es empreendedoras de sucesso fundou e geriu, durante os quatro primeiros anos, a Bluefit, a segunda maior rede do paĂ­s.Â  Â  \nĂ um modelo de microacademia especializada capaz de proporcionar o melhor custo-benefĂ­cio aos alunos e a possibilidade de alta rentabilidade aos franqueados. \nOferece sessĂ”es de treino previamente agendadas, com duraĂ§ĂŁo de atĂ© 60 minutos, sob o mĂ©todo de treinamento intervalado de alta intensidade, que utiliza elementos das artes marciais, realiza o controle de frequĂȘncia cardĂ­aca do aluno como forma de estimulĂĄ-lo a atingir seus objetivos e, ainda, utiliza a tecnologia a favor da experiĂȘncia do aluno. \nTodas as aulas sĂŁo planejadas e testadas previamente e seu conteĂșdo varia diariamente, alternando exercĂ­cios, grupos musculares, movimentos, tempo, intervalo, carga, velocidade. \nOs treinos nunca se repetem, porĂ©m, por se tratar de um Sistema de Franquia, no mesmo dia todas as unidades devem realizar exatamente o mesmo treino, promovendo assim uma troca de experiĂȘncia entre os alunos e profissionais, os quais deverĂŁo ter seu registro ativo no Conselho Federal/Regional de EducaĂ§ĂŁo FĂ­sica. \nPeriodicamente, e a critĂ©rio exclusivo da franqueadora, as atividades propostas na metodologia poderĂŁo sofrer alteraĂ§ĂŁo conforme demanda do mercado.Â  \nPor se tratar de um modelo de microacademias especializadas, as unidades SPIDER KICK atendem um nĂșmero prĂ©-determinado de alunos ao mesmo tempo, cujos treinos devem ser agendados por meio de um aplicativo especĂ­fico. \nA precificaĂ§ĂŁo das unidades Ă© feita com base em pesquisa de mercado e da concorrĂȘncia. Por isso, o franqueado deverĂĄ seguir rigorosamente as orientaĂ§Ă”es estabelecidas pela franqueadora.  Sob a Ăłtica do consumidor, os principais diferenciais da SPIDER KICK sĂŁo:\n(a) oferecer um treino de alta intensidade com monitoramento cardĂ­aco durante toda a sessĂŁo, permitindo ao aluno controlar a intensidade e observar seu prĂłprio desempenho; e\n(b) utilizar os elementos de artes marciais na sessĂŁo de treino, empoderando o aluno e criando um maior senso de equipe. AlĂ©m disso, sob a Ăłtica do parceiro franqueado, ainda temos, como principais diferenciais:\n(c) o valor de investimento acessĂ­vel com possibilidade de grande rentabilidade;\n(d) a oferta dos melhores pontos e regiĂ”es aos franqueados, eliminando qualquer conflito por territĂłrio; e\n(e) a possibilidade de financiamento das obras para instalaĂ§ĂŁo da unidade franqueada (exclusivamente para os candidatos que forem elegĂ­veis a critĂ©rio da franqueadora, apĂłs anĂĄlise documental e de capacidade de pagamento). \nTodo o conceito do negĂłcio, identidade visual, padronizaĂ§ĂŁo de processos, recrutamento e treinamento de profissionais, polĂ­tica comercial, oferta de serviĂ§os e procedimentos operacionais foram cuidadosamente planejados para gerar escalabilidade e disponibilizar ao franqueado um modelo fĂĄcil de operar e com grande atratividade ao consumidor. \nCom um aprendizado desenvolvido sobre os diferentes modelos de microacademias existentes no Brasil e no mundo, a SPIDER KICK traz ao mercado um formato atrativo para diferentes territĂłrios e perfis de investidor. As unidades sĂŁo instaladas em regiĂ”es de alto fluxo de pessoas e devem ter ĂĄrea construĂ­da entre 250 mÂČ e 400 mÂČ, em pavimento Ășnico, podendo ser uma loja de rua ou localizada em centros comerciais e shopping centers.Â  \nTodo o know how desenvolvido pela franqueadora Ă© repassado aos franqueados por meio do sistema de franquia SPIDER KICK, que visa capacitar os franqueados para operar uma unidade com o mais alto padrĂŁo de qualidade, entregando uma experiĂȘncia exclusiva aos alunos.  Â O sistema de franquias SPIDER KICK disponibiliza ao seu franqueado: Suporte completo na escolha do ponto comercial. Caderno TĂ©cnico de Arquitetura e EscritĂłrio(s) de Arquitetura homologado(s) para a confecĂ§ĂŁo do projeto arquitetĂŽnico e compatibilizaĂ§ĂŁo deste com os projetos complementares. AnĂĄlise dos relatĂłrios de obra e construĂ§ĂŁo com o objetivo de garantir o padrĂŁo arquitetĂŽnico SPIDER KICK. Fornecedores homologados para a execuĂ§ĂŁo da obra, bem como para a compra dos materiais e equipamentos necessĂĄrios Ă  instalaĂ§ĂŁo de uma unidade. Treinamento Inicial (Operacional e TĂ©cnico) para o gestor e os colaboradores da primeira equipe da unidade franqueada, bem como plataforma para EducaĂ§ĂŁo Continuada, que inclui treinamento aos novos colaboradores. Manual de OperaĂ§Ă”es para assegurar a transferĂȘncia de know how sobre como operar uma unidade franqueada SPIDER KICK; RecomendaĂ§ĂŁo de precificaĂ§ĂŁo adequada para cada praĂ§a. SessĂ”es de treino (workouts) prĂ©-determinados para que no mesmo dia sejam aplicados simultaneamente em todas as unidades SPIDER KICK. Planejamento de Marketing inaugural, comunicaĂ§ĂŁo visual padronizada, acompanhamento de performance digital e gerenciamento de toda a estratĂ©gia de comunicaĂ§ĂŁo do franqueado com o consumidor final. Sistema operacional (software de gestĂŁo) previamente homologado pela franqueadora. Consultoria de campo, auditoria e relatĂłrios periĂłdicos de indicadores de desempenho.', NULL, 'SĂO PAULO', 1, NULL, 5, NULL, NULL, '2026-03-08 17:05:34.672', 'https://franquias.portaldofranchising.com.br/franquia-spider-kick/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '370000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ls0006eh0sbltth6xt', 'BRASIL CANADĂ - EDUCAĂĂO BILĂNGUE', 'brasil-canada-educacao-bilingue', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'O Brasil CanadĂĄ â EducaĂ§ĂŁo BilĂ­ngue Ă© uma rede de escolas que atua hĂĄ 20 anos com ensino infantil e fundamental atravĂ©s de uma proposta eficaz e de altĂ­ssima qualidade.', 2017, 2019, NULL, '2026-04-01 02:00:00.268', '2025-08-05 22:20:24.064', 43, NULL, 1, 2000, '', NULL, 'SĂO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-08 17:25:56.418', 'https://franquias.portaldofranchising.com.br/franquia-brasil-canada-educacao-bilingue/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73lx0007eh0sy4dmr2p3', 'CYMACO', 'cymaco', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'PrestaĂ§ĂŁo de serviĂ§os para a construĂ§ĂŁo civil/ Sistema de ConstruĂ§Ă”es Inteligentes', 2008, 2010, NULL, '2026-04-01 02:00:00.280', '2025-08-05 22:20:24.070', 44, NULL, 1, 2000, 'FRANQUIA Sabemos que a decisĂŁo de ter uma franquia, vai alĂ©m de valores financeiros. A ESCOLHA DA FRANQUIA, antes de tudo deve ser baseada em AFINIDADE COM A ĂREA E COMPROMETIMENTO de ambas partes, para que o negĂłcio traga um Ăłtimo resultado. E Ă© por isso que nĂłs temos o compromisso de levar para vocĂȘ, uma marca sĂłlida, preparada e de SUCESSO. Fazer parte da CYMACO, Ă© poder contar com toda a expertise de 40Â anos de presenĂ§a no mercado, constante inovaĂ§ĂŁo e suporte para grandes obras feitas por uma empresa que jĂĄ Ă© fortemente estabelecida e em constante desenvolvimento. Estamos presentes em 5 estados do Brasil em 8 unidades. O Setor da construĂ§ĂŁo Ă© responsĂĄvel por 60% da composiĂ§ĂŁo do PIB total da cadeia produtiva da construĂ§ĂŁo, somada a 5,7% de serviĂ§os (Fonte: ABRAMAT FGV 2018). O aumento da demanda de reparos e melhorias nos imĂłveis, tem tornado esse nĂșmero ainda mais expressivo. A CYMACO oferece SERVIĂOS - que englobam ManutenĂ§ĂŁo Predial e Retrofit - e CONSTRUĂĂES INTELIGENTES. Sendo um franqueado CYMACO vocĂȘ pode optar por um desses dois tipos de franquia. Mas vamos te explicar abaixo o que Ă© tudo isso.  MANUTENĂĂO PREDIAL MANUTENĂĂO PREDIAL sĂŁo todas as atividades de manutenĂ§ĂŁo de prĂ©dios ou empreendimentos, relativos Ă  pequenas reformas, reparos, recuperaĂ§ĂŁo estrutural,Â  manutenĂ§Ă”es preventivas necessĂĄrias que impedem o surgimento de problemas, manutenĂ§Ă”es corretivas, como resolver infiltraĂ§Ă”es, trocar pastilhas, pintar o prĂ©dio entre outros problemas que toda estrutura pode ter.  RETROFIT O RETROFIT Ă© a renovaĂ§ĂŁo de um condomĂ­nio, casa ou loja, onde hĂĄ significativas modificaĂ§Ă”es que vĂŁo alĂ©m daquelas pequenas reformas. Vai desde troca de elevadores, modernizaĂ§ĂŁo de sistemas elĂ©tricos, hidrĂĄulicos, atualizaĂ§ĂŁo dos sistemas de seguranĂ§a atĂ© a modificaĂ§ĂŁo da fachada, para a modernizaĂ§ĂŁo tambĂ©m estĂ©tica do prĂ©dio. Esse serviĂ§o surgiu na Europa com o intuito de se modernizarem os prĂ©dios mais antigos para melhorar a sua funcionalidade, aspecto e seguranĂ§a. Essa tĂ©cnica chegou ao Brasil e a Cymaco tem orgulho em ser a empresa que mais executou Retrofit no Brasil. O resultado? MORADORES SATISFEITOS, IMĂVEL MAIS ECONĂMICO E MUITO MAIS VALORIZADO. Nem vocĂȘ sabia que essa modernizaĂ§ĂŁo era tĂŁo forte, nĂŁo Ă© mesmo?  CONSTRUĂĂES INTELIGENTES EntĂŁo vamos para as CONSTRUĂĂES INTELIGENTES. Imagine uma obra que demora 60% a menos do tempo convencional e tem 80% na reduĂ§ĂŁo da mĂŁo de obra. Estamos falando das construĂ§Ă”es inteligentes. A ConstruĂ§ĂŁo Inteligente consiste na produĂ§ĂŁo em escala, de paredes e lajes em concreto armado levando para a obra paredes prontas e rebocadas.  Este sistema utiliza os mesmos materiais do sistema convencional, com a vantagem de incorporar Ă s paredes e lajes os dutos e as tubulaĂ§Ă”es e fazer toda a obra em menos tempo, com MENOS MĂO DE OBRA E MENOR CUSTO. A ConstruĂ§ĂŁo Inteligente influencia diretamente no gasto de todas as fases da obra, por isso ela DIMINUI EM 40% O INVESTIMENTO por metro quadrado construĂ­do e ainda otimiza a utilizaĂ§ĂŁo de materiais fazendo cair em 20% O DESPERDĂCIO DE MATERIAIS e Ă© tambĂ©m uma alternativa para a construĂ§ĂŁo e para a dificuldade em contrataĂ§ĂŁo de mĂŁo de obra. Veja algumas etapas do processo:  *dependendo do tamanhoÂ das obras Se vocĂȘ Ă© engenheiro ou arquiteto a CYMACO com certeza Ă© a franquia certa para vocĂȘ! Mas se vocĂȘ nĂŁo Ă© da ĂĄrea, pode ficar tranquilo: Ă© necessĂĄrio apenas que vocĂȘ tenha na franquia um engenheiro contratado. Clique no formulĂĄrio abaixo ou visite o nosso site para falar diretamente com o nosso Diretor e ter mais informaĂ§Ă”es sobre a franquia que ajuda a TRANSFORMAR e CONSTRUIR a vida dos brasileiros! MAIS SUCESSO, MAIS CYMACO.', NULL, 'SANTA CATARINA', 1, NULL, 9, NULL, NULL, '2026-03-08 16:42:08.572', 'https://franquias.portaldofranchising.com.br/franquia-cymaco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '310000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
