INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73m90009eh0s4echl139', 'ATHUS', 'athus', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escolas de Ensino de Idiomas MĂ©todo prĂłprio de InglĂȘs', 2004, 2018, '[\"https://www.youtube.com/watch?v=rm3fbdAqw6Y\",\"https://www.youtube.com/watch?v=wS2e8HqCgOk\",\"https://www.youtube.com/watch?v=60lHumNQEn4\",\"https://www.youtube.com/watch?v=-Xo-8nhKJtc\"]', '2026-04-01 02:00:00.304', '2025-08-05 22:20:24.082', 46, NULL, 1, 2004, 'Foi com objetivo de atender uma enorme demanda para o ensino de InglĂȘs de forma diferenciada, e tambĂ©m de construir um sistema de franchising que trouxesse o sucesso empresarial para os futuros Franqueados, que em 2004 foi fundada a ATHUS. No primeiro momento, a rede ATHUS cresceu baseada exclusivamente na grandiosa qualidade de seu mĂ©todo. Os primeiros Franqueados foram pessoas que, em sua maioria, eram professores de InglĂȘs experientes e que se encantaram pela nova maneira de ensinar InglĂȘs que o mĂ©todo ATHUS permitia. Paralelamente, a FRANQUEADORA buscava incessantemente desenvolver sistemas de gestĂŁo da Unidade, captaĂ§ĂŁo de alunos, e formas de transformar cada Unidade ATHUS numa fĂĄbrica de grande satisfaĂ§ĂŁo para os alunos e excelentes lucros para o FRANQUEADO. Com isso, a experiĂȘncia da FRANQUEADORA em captaĂ§ĂŁo de alunos e gestĂŁo de Unidades se multiplicou. Foi aĂ­ que no inĂ­cio de 2006, a ATHUS passou a ofertar aos consumidores, de forma inĂ©dita, um menu de cursos, trazendo opĂ§Ă”es aos alunos. Este foi um grande marco, que resultou em grande melhora nos lucros de todas as Unidades da rede. E Ă© esta experiĂȘncia, este mĂ©todo e este know-how, que exigiu da FRANQUEADORA, cinco anos de pesquisa e por enquanto mais quatorze anos de atividades com a marca, que se oferta de maneira organizada no sistema de franchising ATHUS. Todos esses anos se transferem ao FRANQUEADO pelo contrato de franquia, com o treinamento inicial e posteriores treinamentos propiciados pela FRANQUEADORA conforme cada fase por que passe a Unidade Franqueada.', NULL, 'PARANĂ', 1, NULL, 29, NULL, NULL, '2026-03-08 16:44:11.491', 'https://franquias.portaldofranchising.com.br/franquia-athus/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '82000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
