INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73o2000leh0s0qnm7d6b', 'SUSHI EM CASA', 'sushi-em-casa', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Modelo baseado em delivery de comida japonesa, com possibilidade de extensĂ”es para retirada e consumo no local;', 2019, 2023, '[\"https://www.youtube.com/watch?v=vn8MlyN1ZNs\",\"https://www.youtube.com/watch?v=q9VxQiMit7I\"]', '2026-04-01 02:00:00.451', '2025-08-05 22:20:24.146', 58, NULL, 1, 2019, 'Em meados de 2007, durante um intercĂąmbio na AustrĂĄlia, nosso sĂłcio fundador Bruno teve a oportunidade de conhecer novos amigos japoneses que o introduziram Ă  culinĂĄria oriental. Inspirado por suas experiĂȘncias prĂĄticas nessa terra estrangeira, Bruno retornou ao Brasil e imediatamente comeĂ§ou a ministrar cursos sobre a arte de fazer sushi. Com o tempo, sua paixĂŁo pela culinĂĄria japonesa o levou a realizar eventos em diferentes ocasiĂ”es, incluindo casamentos, formaturas e aniversĂĄrios. Diante da crescente demanda, Bruno decidiu arriscar algo novo em 2015, inaugurando o Sushi em Casa Delivery dentro de seu condomĂ­nio. O objetivo era oferecer aos alunos e clientes o melhor da culinĂĄria japonesa, entregando-a diretamente em suas casas. O sucesso dessa iniciativa foi notĂĄvel e, em 2018, juntamente com seus sĂłcios, iniciou-se o processo de expansĂŁo da marca. Atualmente, o Sushi em Casa conta com dez unidades, sendo seis localizadas no interior de SĂŁo Paulo, uma em JundiaĂ­ e trĂȘs em SĂŁo Paulo capital.', NULL, 'SĂO PAULO', 1, NULL, 10, NULL, NULL, '2026-03-08 17:32:43.420', 'https://franquias.portaldofranchising.com.br/franquia-sushi-em-casa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73o7000meh0sk4btx1bd', 'SEGCREDI', 'segcredi', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'ServiĂ§os financeiros, crĂ©dito consignado, financiamentos e refinanciamentos, crĂ©dito pessoal, cartĂ”es de crĂ©dito e consĂłrcio.', 2017, 2018, NULL, '2026-04-01 02:00:00.462', '2025-08-05 22:20:24.151', 59, NULL, 1, 2017, 'A Segcredi faz parte do Grupo Zanon - Holding de Franquias que possui alta experiĂȘncia no mercado de franchising, atua em vĂĄrios segmentos e estĂĄ presente em todo o territĂłrio brasileiro. Atualmente o Grupo Zanon Ă© responsĂĄvel por comercializar mais de 1.500 unidades dentre as 6 marcas consolidadas no Brasil: Segcredi, Seguralta, Los Mex, Derma Nail, Bionatus e Belinda.\nA Segcredi atingiu mais de 100 unidades com 1 mĂȘs de atuaĂ§ĂŁo graĂ§as ao know how na ĂĄrea de franquias. Oferecemos soluĂ§Ă”es financeiras aos nossos clientes atravĂ©s de consĂłrcios e os mais diversos produtos financeiros, como crĂ©dito consignado, financiamento de veĂ­culos, crĂ©dito pessoal, entre outros. \nTrabalhamos com parceiros homologados e credenciados, assim disponibilizamos diversas opĂ§Ă”es de produtos com o objetivo de proporcionar a chance de organizar a vida financeira, alĂ©m de abrir espaĂ§o para idealizar objetivos e realizar sonhos.  TRANQUILIDADE FINANCEIRA NĂO TEM PREĂO. \nPODE CONTAR COM A GENTE. \nTemos 2 modelos de negĂłcio, faĂ§a sua escolha para o caminho do sucesso!! \nStandard | Office | \nParticipe do mercado que supera a marca de R$20 bi em movimentaĂ§Ă”es, cresce acima de 11,5% ao ano e tenha um negĂłcio com baixo capital de giro e custo operacional com rĂĄpido retorno do seu investimento e todo suporte que somente o Grupo Zanon pode te oferecer.', NULL, 'SĂO PAULO', 1, NULL, NULL, NULL, NULL, '2026-03-08 17:33:25.263', 'https://franquias.portaldofranchising.com.br/franquia-segcredi/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73od000neh0s3lr0kmyn', 'ELAV LAVANDERIA', 'elav-lavanderia', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Lavanderia', 'Lavanderia inovadora, especialista em gerar economia e qualidade para clientes e franqueados. Atendemos a famĂ­lias, segmentos especĂ­ficos de empresas e lavagens avulsas.', 2019, 2020, '[\"https://www.youtube.com/watch?v=q0mCsPcytiQ\",\"https://www.youtube.com/watch?v=Lik4v6-6MQw\",\"https://www.youtube.com/watch?v=TFPPVqhntxE\",\"https://www.youtube.com/watch?v=050uMWdKejc\"]', '2026-04-01 02:00:00.473', '2025-08-05 22:20:24.157', 60, NULL, 1, 2015, 'A eLav LavanderiaÂź nasceu em 2019 quando surgiu, por parte do empresĂĄrio Fernando Reis Vigato, a ideia de construir um modelo de lavanderia especializada, com alta qualidade e preĂ§os acessĂ­veis. Analisando o mercado, o empresĂĄrio percebeu uma crescente busca pelo serviĂ§o de lavanderia especializada, com base em um novo estilo de vida onde a praticidade e qualidade Ă© cada vez mais a prioridade na vida das pessoas de classe B, AB e A. Apesar das vantagens em contratar uma lavanderia e da tendĂȘncia crescente desse segmento, Fernando percebeu que a maioria das lavanderias praticavam um preĂ§o muito alto e pouco acessĂ­vel para pessoas de classe mĂ©dia, com baixa qualidade de atendimento e prestaĂ§ĂŁo de serviĂ§os. Quando o empresĂĄrio iniciou no ramo, em 2015, comeĂ§ou a rever os processos operacionais para entregar o melhor serviĂ§o de lavanderia do mercado, ao mesmo tempo baratear o valor do serviĂ§o, ajustando a configuraĂ§ĂŁo das mĂĄquinas, comprando novos equipamentos, usufruindo da tecnologia e dos sistemas para agilizar a operaĂ§ĂŁo e economizar nos custos. Ganhando mercado e se destacando na cidade de Varginha-MG, origem da eLav, Fernando decidiu em 2019 formatar o modelo de franquias, compartilhando know-how especializado. Desde entĂŁo, a franquia eLav cresce a cada ano, hoje atingindo mais de 140 unidades, em todo o Brasil. A eLav Ă© uma marca que se destaca no mercado de lavanderias especializadas, com uma entrega de alto nĂ­vel de qualidade a um valor acessĂ­vel a seus clientes. Nosso diferencial estĂĄ na transferĂȘncia de know-how, de donos de lavanderia, com mais de 140 unidades e suporte ao franqueado em todas as ĂĄreas fundamentais para o sucesso do negĂłcio: suporte operacional, de implantaĂ§ĂŁo, de marketing e bem-estar. Nosso posicionamento de mercado Ă© um grande diferencial, pois atingimos as classes B, AB e A, tendo como principal pĂșblico a classe AB que Ă© onde hĂĄ o maior crescimento no nĂșmero de novos usuĂĄrios do serviĂ§o de lavanderia.', NULL, 'MINAS GERAIS', 1, NULL, 87, NULL, NULL, '2026-03-08 17:34:17.858', 'https://franquias.portaldofranchising.com.br/franquia-elav-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
