INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73os000qeh0sx6yungjz', 'VIVA EVENTOS', 'viva-eventos', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e RecreaĂ§ĂŁo', 'Empresa de produĂ§ĂŁo de eventos de formaturas. Auxilia os clientes na gestĂŁo e na contrataĂ§ĂŁo dos serviĂ§os', 2012, 2013, '[\"https://www.youtube.com/watch?v=FpsWFhiFCNQ\",\"https://www.youtube.com/watch?v=Yq0BvJksHZY\",\"https://www.youtube.com/watch?v=fR3nFvvOjzo\",\"https://www.youtube.com/watch?v=7eZ4otq1N9o\",\"https://www.youtube.com/watch?v=Hje6sx5xN3s\"]', '2026-04-01 02:00:00.509', '2025-08-05 22:20:24.173', 63, NULL, 1, 2007, 'Por que ser um Franqueado VIVA EVENTOS? JĂĄ pensou em fazer parte de um mercado dinĂąmico, em franco crescimento e que pode dobrar de tamanho na prĂłxima dĂ©cada? Melhor ainda: Se posicionar neste mercado atravĂ©s de uma marca forte, que alia tecnologia e know-how para entregar produtos e serviĂ§os de alta qualidade, proporcionando felicidade e satisfaĂ§ĂŁo de seus clientes! O mercado de eventos cresceu mais de 14% no Ășltimo ano e aÂ VIVA EventosÂ estĂĄ em pleno processo de expansĂŁo nacional, selecionado franqueados que possam levar a marca e a sua cultura para todos as regiĂ”es do paĂ­s. Para garantir a qualidade do serviĂ§o prestado por todos os franqueados, a rede tem um setor de inovaĂ§ĂŁo voltado para novos produtos e serviĂ§os, o VIVA Lab; uma universidade corporativa focada em treinamentos EAD para aperfeiĂ§oamento dos franqueados e de suas equipes (VIVA Academy); software prĂłprio de gestĂŁo para garantir maior eficiĂȘncia administrativa e financeira; aplicativo exclusivo para gestĂŁo do fundo de formatura pelos formandos; sistema financeiro online prĂłprio para uso do cliente final; setor de qualidade; modelo de festas personalizadas, as Privates VIVA; e portfĂłlio exclusivo de itens de decoraĂ§ĂŁo para formaturas. A capilaridade do modelo VIVA permite que todos os diferenciais e novos produtos sejam rapidamente aderidos por toda a rede e disponibilizado aos clientes. Â  Â  HistĂłria da franquia VIVA EVENTOS\nÂ  AÂ VIVA EventosÂ nasceu de uma inquietaĂ§ĂŁo... ou melhor, de cinco. Com a insatisfaĂ§ĂŁo natural de empreendedores e o espĂ­rito revolucionĂĄrio tĂ­pico dos jovens, cinco amigos passaram a criar diversos eventos universitĂĄrios, sempre apostando no lanĂ§amento de novos produtos e inovaĂ§Ă”es no mercado. E foram justamente essas inovaĂ§Ă”es a mola propulsora daÂ VIVA Eventos. Percebendo que o mercado de empresas de formatura nĂŁo era muito aberto a mudanĂ§as, resolveram eles prĂłprios criar uma empresa que agregasse criatividade, e profissionalismo. Assim, em 2007 nascia em Juiz de Fora (MG) aÂ VIVA Eventos, com a promessa de revolucionar o mercado de formaturas da regiĂŁo â e, posteriormente, de todo o Brasil. O clima descontraĂ­do da empresa, aliado Ă  sensibilidade no relacionamento com clientes, colaboradores e fornecedores, fez da VIVA Eventos um sucesso imediato. Nos primeiros oito meses de funcionamento a empresa se tornou lĂ­der de mercado em tempo recorde. Atendendo atualmente a mais de 200 cidades, com 24 franquias em 5 estados do Sudeste e do Sul do Brasil, a VIVA Eventos, originada em Juiz de Fora (MG), Ă© a primeira rede de franquias de festas de formatura do paĂ­s. Com gestĂŁo financeira inovadora, a empresa traz a atmosfera â e a postura â das startups para dentro de seu modelo de negĂłcios com aposta em metodologias ĂĄgeis, baseada no uso da tecnologia, para levar sua expertise em formaturas a todas as regiĂ”es brasileiras. Com o mercado cada vez mais profissionalizado, Ă© preciso dedicaĂ§ĂŁo redobrada para entregar festas de excelĂȘncia. E Ă© nesse contexto que a VIVA Eventos se destaca por meio da inovaĂ§ĂŁo tecnolĂłgica. A empresa foi fundada em 2007 e se tornou referĂȘncia no ramo. Em 2012, quando se associou Ă  ABF (AssociaĂ§ĂŁo Brasileira de Franchising), a empresa nĂŁo identificou nenhum modelo de negĂłcios semelhante no mundo. De lĂĄ para cĂĄ a empresa cresce a uma taxa superior a 40% ao ano. Nos planos de crescimento da empresa, estĂĄ a presenĂ§a em todos os estados brasileiros atĂ© 2023, alcanĂ§ando 80 franquias. AÂ VIVA EventosÂ Ă© hoje seguramente a maior empresa de formaturas do Brasil e o principal case de sucesso na ĂĄrea, sendo uma referĂȘncia no mercado nacional. Marca forte, associada a robustez e credibilidade, mas sem perder o espĂ­rito jovial e inovador que fez com que a empresa chegasse tĂŁo longe em tĂŁo pouco tempo.', NULL, 'MINAS GERAIS', 1, NULL, 38, NULL, NULL, '2026-03-08 17:36:06.067', 'https://franquias.portaldofranchising.com.br/franquia-viva-eventos-entretenimento-e-lazer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
