INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73pv000weh0svlbznik6', 'MAGIC FEET', 'magic-feet', NULL, 'Moda', 'CalĂ§ados', 'CALĂADOS, TĂNIS, ACESSĂRIOS EM GERAL COMO BOLSAS, MOCHILAS, BOLAS,MEIAS E CONFECĂĂES INFANTIS E INFANTO JUVENIS', 2008, 2009, NULL, '2026-04-01 02:00:00.587', '2025-08-05 22:20:24.212', 69, NULL, 1, 2008, 'Fundada em 2008, pelo Grupo Afeet, a Franquia Magic Feet Ă© a maior rede de lojas de calĂ§ados infantis do Brasil e fruto da oportunidade detectada pela companhia de lanĂ§ar um player forte no nicho infantil. \nA rede oferece diversos estilos para crianĂ§as de 0 a 10 anos, atendimento personalizado e grande variedade de produtos das principais marcas do mercado como Nike, adidas, Puma, Converse, Vans, Asics, Tip Toey Joey, Pampili, Skechers e Crocs. \nAlĂ©m disso, a Magic Feet proporciona experiĂȘncia Ă­mpar ao pĂșblico-usuĂĄrio (crianĂ§a) e pĂșblico-decisor (adulto), por meio de constante revitalizaĂ§ĂŁo das unidades e capacitaĂ§ĂŁo da equipe de atendimento.Â  \nO layout e a atmosfera das lojas sĂŁo pensados para o mundo infantil de modo a criar uma experiĂȘncia mĂĄgica no momento da compra. Atualmente, a rede possui 50 lojas distribuĂ­das nos principais Shoppings Centers em oito estados brasileiros: SĂŁo Paulo, Minas Gerais, Rio de Janeiro, EspĂ­rito Santo, ParanĂĄ, Pernambuco, PiauĂ­ e Amazonas.', NULL, 'SĂO PAULO', 1, NULL, 12, NULL, NULL, '2026-03-08 17:39:42.954', 'https://franquias.portaldofranchising.com.br/franquia-magic-feet-calcados-e-tenis-infantis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73q2000xeh0s3tfa5re1', 'ACTIONCOACH BRASIL', 'actioncoach-brasil', NULL, 'EducaĂ§ĂŁo', 'Treinamento Profissional e CapacitaĂ§ĂŁo', 'Coaching Empresarial (Business Coaching) para pequenas e mĂ©dias empresas', 1997, 2008, '[\"https://www.youtube.com/watch?v=aOxXC5CkhnQ\",\"https://www.youtube.com/watch?v=kb4vsBf-YU4\",\"https://www.youtube.com/watch?v=DfO_7iguTCc\"]', '2026-04-01 02:00:00.600', '2025-08-05 22:20:24.218', 70, NULL, 1, 1993, 'Adquirir uma franquia ActionCOACH Ă© a oportunidade de investimento ideal para quem busca um negĂłcio B2B que ofereĂ§a um Ăłtimo retorno do investimento, fluxo de caixa constante e escalabilidade, mas que alĂ©m de tudo isso, se transforme em um negĂłcio do qual vocĂȘ possa se orgulhar impacto positivo que gera nas PMEs da sua regiĂŁo. A ActionCOACH nasceu em 1993 com a ideia de ajudar os pequenos e mĂ©dios empresĂĄrios a melhorarem seus resultados, otimizar seus negĂłcios e melhorar sua qualidade de vida, tendo de volta seu tempo livre. Seu fundador, Brad Sugars, inicia entĂŁo um programa de treinamento em toda a AustrĂĄlia. Ele realizava importantes seminĂĄrios que contavam com a participaĂ§ĂŁo de 2.000 empresĂĄrios por evento. Em pouco tempo, a ActionCOACH consegue se posicionar em tal nĂ­vel que sua fama comeĂ§a a crescer atĂ© chegar Ă  Nova ZelĂąndia, Ăsia e Estados Unidos. A ActionCOACH tornou-se franquia em 1997. A partir de entĂŁo conseguiu uma rĂĄpida expansĂŁo que nos levou a estar presente hoje nos 5 continentes e em mais de 80 paĂ­ses e com mais de 1.000 franqueados.Â  Durante as Ășltimas 2 dĂ©cadas, a franquia ActionCOACH recebeu vĂĄrios reconhecimentos por publicaĂ§Ă”es de prestĂ­gio como Entrepreneur, Forbes, Franchise Direct, Franchise Review, Elite Franchise, entre outros, obtendo o selo de excelĂȘncia ABF por mais de 10 anos consecutivos. - Exclusividade Territorial: Um territĂłrio que tenha no mĂ­nimo 30.000 empresas registradas e com um nĂșmero ilimitado de coaches empregados. - Valor do Investimento Ă© cotado em DĂłlares, entĂŁo serĂĄ respeitado a cotaĂ§ĂŁo do dia. Investimento: $ 95.000,00 USD (DĂłlares); $ 150.000,00 totais.', NULL, 'SĂO PAULO', 1, NULL, 27, NULL, NULL, '2026-03-08 17:40:23.726', 'https://franquias.portaldofranchising.com.br/franquia-actioncoach-brasil-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '555000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73q7000yeh0s7jljrem7', 'OPHICINA E OPHICINA FOOTWEAR', 'ophicina-e-ophicina-footwear', NULL, 'Moda', 'VESTUĂRIO', 'A marca OPHICINA existe no mercado de confecĂ§Ă”es desde 1996, sempre associada Ă  moda casual, surfwear e streetwear, tanto feminina quanto masculina. Em suas diversas linhas de roupas e acessĂłrios.', 2013, 2022, NULL, '2026-04-01 02:00:00.612', '2025-08-05 22:20:24.224', 71, NULL, 1, 1996, '', NULL, 'SĂO PAULO', 1, NULL, 78, NULL, NULL, '2025-08-20 17:41:45.000', 'https://franquias.portaldofranchising.com.br/franquia-ophicina-e-ophicina-footwear-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73qf000zeh0six7e9t04', 'ALĂM DO OLHAR', 'alem-do-olhar', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'A AlĂ©m do Olhar Ă© especialista em cuidados com a beleza, contemplando estĂ©tica facial e corporal. Uma franquia completa na ĂĄrea da beleza com os mais diversos serviĂ§os e tratamentos.', 2016, 2021, '[\"https://www.youtube.com/watch?v=6UCKv6GsLn4\",\"https://www.youtube.com/watch?v=4yijzmNxGM4\",\"https://www.youtube.com/watch?v=0l-dtscYBk0\",\"https://www.youtube.com/watch?v=e0I57FRMksA\"]', '2026-04-01 02:00:00.624', '2025-08-05 22:20:24.231', 72, NULL, 1, 2014, 'A AlĂ©m do Olhar existe por causa do sonho da Rose. A vida da nossa fundadora se transformou apĂłs se tornar gerente de vendas na Avon, onde trabalhou por cinco anos. \nNela teve a ideia de empreender no ramo da beleza e entĂŁo, em 2014, pediu demissĂŁo da multinacional para seguir com seu sonho de empreender. Com o dinheiro da rescisĂŁo da Avon abriu a primeira unidade da AlĂ©m do Olhar. A ideia do projeto era criar um ambiente aconchegante que em nada lembrasse os salĂ”es de belezas, com bolos e cafĂ©s. Hoje seu maior desejo Ă© espalhar esse conhecimento ao mundo e transformar a vida de milhares de mulheres, que assim como ela, sonham em ter seu prĂłprio negĂłcio. AlĂ©m do Olhar se diferencia no mercado por que amadurece junto de nossas clientes e entende suas necessidades como prioridades. \nCresce Ă  medida que nossas especialistas crescem, incentivando-as constantemente. \nReconhecemos a importĂąncia do carinho ao longo prazo, com atenĂ§ĂŁo personalizada. Somos defensores da beleza real e despretensiosa \nUtilizamos da tecnologia e dos bioestimuladores para atingirmos a melhor versĂŁo de nossas pacientes. \nSomos nĂŁo ao exagero e portanto nĂŁo ao preenchimento desnecessĂĄrio US$ 124,7 BI. Hoje o mercado de estĂ©tica lideraÂ  \nĂ o que deve movimentar o setor atĂ© 2028 e expandir a uma taxa de 9.8% entre 2021 e 2028. O Brasil Ă© o 4Â° lugar fica somente atrĂĄs de EUA, China e JapĂŁo no mercado de estĂ©tica. \nĂ um dos maiores do mundo! 1.5 MI de procedimentos estĂ©ticos por ano no Brasil, movimentando mais de R$ 48 BI no paĂ­s. 560% De crescimento entre os anos 2018 a 2022, em relaĂ§ĂŁo aos anos anteriores, no Brasil.', NULL, 'SĂO PAULO', 1, NULL, 30, NULL, NULL, '2026-03-08 17:41:29.135', 'https://franquias.portaldofranchising.com.br/franquia-alem-do-olhar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '180001', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
