INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rf0014eh0sal5m9zr6', 'MULTIFILMES WINDOW FILM', 'multifilmes-window-film', NULL, 'ServiĂ§os Automotivos', 'LocaĂ§ĂŁo de veĂ­culos', 'Rede especializada na instalaĂ§ĂŁo de pelĂ­culas de controle solar, seguranĂ§a e decorativas. ProteĂ§ĂŁo de pintura-PPF e envelopamento em geral. Linhas de produtos de alta performance, com marca prĂłpria.', 2015, 2021, '[\"https://www.youtube.com/watch?v=gJwo_aMizaA\",\"https://www.youtube.com/watch?v=0IOA_CC98lA\",\"https://www.youtube.com/watch?v=PgkSDV5ujc8\",\"https://www.youtube.com/watch?v=5f0F1EiHRRg\"]', '2026-04-01 02:00:00.699', '2025-08-05 22:20:24.267', 77, NULL, 1, 1999, 'A Marca MULTIFILMES surgiu como resultado da ĂĄrdua luta de seu Presidente, JĂșnior Ruciretta, que entrou para o mundo do trabalho desde a infĂąncia. Foi coletor de reciclados na rua, empacotador em supermercados, entregador de panfletos e vendedor de Coca-Cola em semĂĄforos. \nAinda muito jovem, teve a oportunidade de trabalhar no ramo de aplicaĂ§ĂŁo de pelĂ­culas em automĂłveis. Pelos seus serviĂ§os, recebia um salĂĄrio mĂ­nimo mensal. Certa vez, por um descuido ocasional, acabou quebrando o vidro de um veĂ­culo quando estava aplicando a pelĂ­cula. O dono do negĂłcio exigiu o ressarcimento do prejuĂ­zo atravĂ©s dos serviĂ§os de Ruciretta, o qual trabalhou meses sem remuneraĂ§ĂŁo. Depois de haver quitado o prejuĂ­zo, o jovem foi dispensado e recebeu apenas R$80,00 a tĂ­tulo de acerto trabalhista. \nCom esse valor em mĂŁos e seu espĂ­rito empreendedor, criou a MULTIFILMES na modalidade delivery, jĂĄ que nĂŁo possuĂ­a condiĂ§Ă”es financeiras para locar um espaĂ§o para os carros. Iniciou comprando trĂȘs pelĂ­culas automotivas e saiu em busca de clientes. A estratĂ©gia deu certo, e Ruciretta foi multiplicando a compra de pelĂ­culas Ă  medida que conquistava novos clientes. \nEm 2001, em razĂŁo do contĂ­nuo crescimento da clientela, foi necessĂĄria a locaĂ§ĂŁo de um espaĂ§o nos fundos de uma oficina para estocar os produtos. Ruciretta dedicou-se arduamente ao seu projeto como empreendedor, trabalhando incansavelmente todos os dias atĂ© tarde da noite, em finais de semana e tambĂ©m feriados. \nSua dedicaĂ§ĂŁo garantiu-lhe a crescente conquista de novos clientes. Em 2003, apenas dois anos apĂłs alugar um espaĂ§o fĂ­sico para a MULTIFILMES, o jovem empreendedor firmou sua primeira parceria com uma concessionĂĄria de RibeirĂŁo Preto. Novas parcerias surgiram atĂ© o impressionante nĂșmero de 14 (quatorze) concessionĂĄrias, totalizando cerca de 600 (seiscentos) carros atendidos por mĂȘs. Ficou evidente que seria necessĂĄrio expandir o negĂłcio para atender a todos de modo eficiente e adequado. Quatro funcionĂĄrios foram contratados para auxiliĂĄ-lo e o fundo da oficina, local desprovido de internet, foi trocado por uma sala maior. \nAtento aos interesses de seu pĂșblico, percebeu que a maioria dos clientes pertencia Ă s classes A e B, e estes se encontravam na zona sul de RibeirĂŁo Preto, distante de onde a MULTIFILMES tinha sede. Em razĂŁo disso, em 2015, instalou a loja que hoje figura como Unidade Modelo da empresa em regiĂŁo nobre da Cidade. Preocupado com a melhoria constante dos serviĂ§os prestados, passou a oferecer produtos de melhor qualidade. Introduziu entre eles a pelĂ­cula de alta performance, atĂ© entĂŁo distribuĂ­da por uma Ășnica empresa no Brasil. Desse modo, a MULTIFILMES tornou-se pioneira no interior do Estado de SĂŁo Paulo na aplicaĂ§ĂŁo desse tipo de pelĂ­cula. \nEm 2017 a MULTIFILMES ousou um pouco mais e expandiu o negĂłcio para os Estados Unidos. Ruciretta estava apostando alto na aplicaĂ§ĂŁo da pelĂ­cula de alta performance dentro e fora do Brasil e nĂŁo contava com a reviravolta que estava por vir: seu Fornecedor optou por dar exclusividade do produto a outro cliente, deixando o jovem empresĂĄrio sem escolha. Como consequĂȘncia, as finanĂ§as da MULTIFILMES levaram Ruciretta de volta Ă  estaca zero. \nCom alma empreendedora e a incansĂĄvel vontade de vencer, o empresĂĄrio continuou dedicando-se ao trabalho e agora tambĂ©m Ă  pesquisa de um novo Fornecedor. Seus esforĂ§os foram recompensados quando ele encontrou uma pelĂ­cula de alta performance diferenciada para o mercado. Seu produto, entĂŁo com a marca MULTIFILMES, surpreendeu os clientes em razĂŁo do custo-benefĂ­cio e vem conquistando um mercado cada vez maior.Â  \nCom visĂŁo estratĂ©gica, Ruciretta ampliou suas opĂ§Ă”es de mercado e inseriu papĂ©is de parede na linha de produtos da empresa. Tais estratĂ©gias garantiram a retomada do sucesso da MULTIFILMES, que, em 2019, expandiu os negĂłcios para outras 03 (trĂȘs) Unidades. \nAssim como em um ano atĂ­pico como 2020, nossa estratĂ©gia de expansĂŁo foi um sucesso, seguimos no mesmo caminho, hoje contamos com 35 franquias vendidas, em processo de abertura, sendo uma prĂłpria em RibeirĂŁo Preto. Nossa expectativa Ă© inaugurar mais 100 franquias atĂ© o final de 2021. \nAtualmente, a Unidade Modelo atende cerca de 300 (trezentos) carros e 100 (cem) arquiteturas por mĂȘs, perfazendo um lucro de mais de R$1,5 milhĂŁo de reais. Nos Estados Unidos, o faturamento anual Ă© de cerca de $72 mil dĂłlares. O crescimento da MULTIFILMES mantĂ©m-se acelerado, pois supera as expectativas dos clientes ao oferecer produtos e serviĂ§os com qualidade totalmente diferenciada no mercado. \nSe vocĂȘ se identifica com essa caracterĂ­stica de inovaĂ§ĂŁo, presente no DNA da MULTIFILMES, junte-se ao nosso time e prepare-se para o sucesso!', NULL, 'SĂO PAULO', 1, NULL, 22, NULL, NULL, '2026-03-08 17:43:52.445', 'https://franquias.portaldofranchising.com.br/franquia-multifilmes-window-film/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '129990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rl0015eh0suspag5vg', 'MINHA LAVANDERIA', 'minha-lavanderia', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Lavanderia', 'Lavanderia EcolĂłgica, com alta tecnologia e produtos para cuidados com o vestuĂĄrio e a casa.', 1994, 2012, '[\"https://www.youtube.com/watch?v=owlZexaxVB8\",\"https://www.youtube.com/watch?v=KUS21-NFzu0\",\"https://www.youtube.com/watch?v=3_GQd1WyBMg\"]', '2026-04-01 02:00:00.716', '2025-08-05 22:20:24.273', 78, NULL, 1, 1994, 'Com serviĂ§os de lavanderia especializada, aliando tecnologia e sustentabilidade, e um modelo de negĂłcio enxuto, a Minha Lavanderia traz seguranĂ§a e solidez para seu investimento. \nTemos o orgulho de compartilhar que nunca fechamos uma operaĂ§ĂŁo. Com foco em qualidade e ecologia, a Minha Lavanderia aliou o que existe de mais moderno e tecnolĂłgico em lavanderia, com uma soluĂ§ĂŁo sustentĂĄvel para lavar as roupas: o Wetcleaning.Â  \nO resultado sĂŁo peĂ§as mais limpas e cheirosas, e o meio ambiente preservado. Tudo isso, com preĂ§os competitivos no mercado.Â  \nHoje a Minha Lavanderia Ă© uma marca valorizada e reconhecida pela qualidade dos serviĂ§os e credibilidade da rede. \nCom mais de 100.000 mil consumidores ativos no Brasil temos um Ă­ndice de satisfaĂ§ĂŁo dos nossos serviĂ§os acima de 94% com base em quem jĂĄ utilizou. \nA Franquia possui 12 anos no mercado e oferece a nossos franqueados 4 fontes de renda em um Ășnico negĂłcio. \nLavanderia completa, tingimento profissional, renovaĂ§ĂŁo de couro e venda de mais de 100 produtos inovadores.\nÂ   \nO Grupo Restaura Ă© formado por trĂȘs marcas especializadas em cuidar bem das suas roupas e da sua alimentaĂ§ĂŁo: a Restaura Jeans, a Minha Lavanderia e a DNA Natural. Atualmente sĂŁo mais de 230 unidades em todo o paĂ­s e mais de 28 anos de experiĂȘncia e resultados em franchising. \nQuer saber mais sobre essa histĂłria de sucesso? Vem com a gente!  Na Minha Lavanderia temos um Suporte 360, ou seja, um suporte completo. \nComo franqueado vocĂȘ contarĂĄ com uma equipe especialista nas mais diversas ĂĄreas de negĂłcio para dar seguranĂ§a em todas as fases, da implantaĂ§ĂŁo Ă  operaĂ§ĂŁo da sua franquia. Â   ConheĂ§a mais do modelo de negĂłcio e dos indicadores financeiros. FaĂ§a seu cadastro agora mesmo!', NULL, 'SANTA CATARINA', 1, NULL, 58, NULL, NULL, '2026-03-08 17:46:49.894', 'https://franquias.portaldofranchising.com.br/franquia-minha-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rq0016eh0smq6rmqf0', 'ECHOSIS', 'echosis', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'ComunicaĂ§ĂŁo e MĂ­dia', 'A Echosis Ă© uma Franquia de Marketing Digital Home Based que atua com serviĂ§os digitais como Redes Sociais, Google Adwords, GeraĂ§ĂŁo de Leads, Marketing de AutomaĂ§ĂŁo, GeraĂ§ĂŁo de ConteĂșdo e Outros.', 2016, 2018, '[\"https://www.youtube.com/watch?v=U-cD6DRwJW0\",\"https://www.youtube.com/watch?v=s4PxynYAiiA\",\"https://www.youtube.com/watch?v=AO42a6gcUsA\",\"https://www.youtube.com/watch?v=5NYaqAJP80w\"]', '2026-04-01 02:00:00.731', '2025-08-05 22:20:24.278', 79, NULL, 1, 2010, 'Fundada em 2010, a Echosis comeĂ§ou atuando no desenvolvimento de jogos e dois anos mais tarde se posicionou no mercado como especialista em marketing digital e soluĂ§Ă”es online. \nPresente em todo o paĂ­s, a Echosis tambĂ©m possui uma unidade nos EUA, que nos proporcionou durante 3 anos consecutivos o prĂȘmio de franquia internacional pela ABF.Â  \nEspecialista em estratĂ©gias digitais, a Echosis oferece diversos serviĂ§os para empresas que desejam crescer na internet, como E-mail Marketing, Social Media, GeraĂ§ĂŁo de ConteĂșdo, Google Adwords, OtimizaĂ§ĂŁo SEO, Remarketing, Google Shopping, entre outros. O modelo da franquia Ă© home based, ou seja, nĂŁo Ă© necessĂĄrio investir em um ponto comercial, podendo trabalhar diretamente de casa, sem gastar com aluguel, funcionĂĄrios e outras despesas extras. \nAinda, Ă© possĂ­vel organizar seus prĂłprios horĂĄrios e contar com uma agenda flexĂ­vel, ideal para quem deseja conciliar o emprego com a gestĂŁo da franquia, sendo uma segunda fonte de renda. A Echosis Ă© a opĂ§ĂŁo ideal para quem deseja comeĂ§ar o prĂłprio negĂłcio e atuar em um dos segmentos que mais cresce no mundo. Ficou interessado na franquia de marketing digital Echosis? Preencha o formulĂĄrio para que a gente possa conversar melhor e esclarecer todas as suas dĂșvidas sobre este modelo de negĂłcio!', NULL, 'SANTA CATARINA', 1, NULL, 25, NULL, NULL, '2026-03-08 17:48:00.948', 'https://franquias.portaldofranchising.com.br/franquia-echosis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '44000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73rx0017eh0sk19t33qj', 'SAMELLO', 'samello', NULL, 'Moda', 'CalĂ§ados', 'COMĂRCIO DE CALĂADOS E ACESSĂRIOS DE COURO EM GERAL', 1999, 2001, NULL, '2026-04-01 02:00:00.747', '2025-08-05 22:20:24.285', 80, NULL, 1, 1926, 'ABRA UMA LOJA SAMELLO Â  E INAUGURE UMA FASE DE BONS NEGĂCIOS NA SUA VIDA   Â   HISTĂRIA \nA Franquia Samello sempre se destacou entre as maiores e mais conceituadas marcas de calĂ§ados masculinos do paĂ­s e se posicionou no mercado como uma grande lanĂ§adora de tendĂȘncias. Entre suas aĂ§Ă”es pioneiras estĂŁo o lanĂ§amento dos mocassins na dĂ©cada de 40, dos drivers na dĂ©cada de 70 e na de 80, os deckshoes. \nCom mais de 90Â anos de atividade, a empresa Ă© reconhecida como uma das mais experientes do mercado. Utiliza de matĂ©ria-prima da maior qualidade em seus calĂ§ados prezando o refinamento nos acabamentos. Este cuidado sempre fez parte da filosofia Samello.  SAMELLO FRANCHISING \nO sistema de franquia pode ser considerado como o grande marco da Samello nos anos 90. A marca consolidou-se no sistema de varejo, inaugurando lojas em todo o paĂ­s que comercializam exclusivamente a marca Samello, todas norteadas pelos conceitos de diferenciais do negĂłcio e foco no consumidor final.  MARCA \nA marca Samello reflete o estilo de vida de pessoas bem sucedidas, bem informadas e exigentes. Apreciam design, qualidade e estilo diferenciado. \nUma marca que se apresenta atravĂ©s de um espĂ­rito brasileiro sofisticado e cosmopolita que Ă© refletido num design chique e moderno. \nSempre com uma visĂŁo aprimorada em suas coleĂ§Ă”es, a Samello traduz nos seus produtos a qualidade tradicional e lanĂ§a o novo que as pessoas desejam.  OPORTUNIDADE \nInvista em um negĂłcio de futuro, lastreado em uma das marcas mais reconhecidas no segmento de calĂ§ados e acessĂłrios de couro. \nA marca que durante sua trajetĂłria sempre inovou em design e estilo, posicionando-se no mercado como lanĂ§adora de tendĂȘncia, agora estarĂĄ na frente de uma loja que pode ser sua.  FRANQUIA \nA franquia da Samello atua no segmento de moda, na linha de calĂ§ados e acessĂłrios de couro, como cintos, meias, carteiras, etc, tendo como foco principal a venda de calĂ§ados masculinos. Â  Â    OBJETIVOS \n- Atender de forma mais eficaz todos os consumidores da marca.\n- Buscar a excelĂȘncia dos serviĂ§os de venda e pĂłs-venda a um pĂșblico cada vez mais exigente que faz questĂŁo de um atendimento personalizado e qualificado.\n- Ampliar e sedimentar a percepĂ§ĂŁo do conceito Samello, resultando, assim, no fortalecimento de nossa marca e de nossos parceiros junto aos consumidores.  FRANQUEADOR \n- A Samello fornece a seus franqueados todo o composto de seus produtos, sempre sob critĂ©rio do franqueador, garantindo a padronizaĂ§ĂŁo da rede.\n-Â Assegura, atravĂ©s de treinamento, a preparaĂ§ĂŁo de seus parceiros para a gestĂŁo da franquia sob a perspectiva mercadolĂłgica, operacional, legal e de recursos humanos.\n- Na fase de negociaĂ§ĂŁo a Samello fornece todo o apoio necessĂĄrio, desde a definiĂ§ĂŁo do ponto, passando pela montagem completa da loja atĂ© o fornecimento de materiais promocionais para a sua inauguraĂ§ĂŁo.\n-Â Adicionalmente a Samello colocarĂĄ Ă  disposiĂ§ĂŁo do franqueado um consultor de campo, cuja principal funĂ§ĂŁo Ă© a de acompanhar e facilitar a gestĂŁo da franquia.\n- Oferece ainda treinamentos de atendimento e produto para facilitar o processoÂ de venda, material sobre as tendĂȘncias de moda, alĂ©m de apoio no desenvolvimentoÂ de aĂ§Ă”es de marketing local.  PROJETO ARQUITETĂNICO \n- A loja Samello Ă© totalmente padronizada, visando conceitos como modernidade, conforto e identificaĂ§ĂŁo com os produtos e clientes.\n- O projeto arquitetĂŽnico da franquia Samello Ă© modular, facilitando sua adaptaĂ§ĂŁo a diversas situaĂ§Ă”es.\n- O layout da loja, no padrĂŁo da franqueadora, serĂĄ apresentado ao franqueador ainda em fase de negociaĂ§ĂŁo. Â  Â  Â  Â   \nAgora vocĂȘ jĂĄ tem as principais informaĂ§Ă”es sobre nosso sistema de franchising. Para dar inicio a uma parceria de futuro entre em contato com a Samello.  SAMELLO FRANCHISING LTDA\nRua Coronel Tamarindo, 2300\n14405-140 - Franca/SP - Brasil\n0800 34 1010 - (16) 3711-2400 - (16) 3711-2550', NULL, 'SĂO PAULO', 1, NULL, 2, NULL, NULL, '2026-03-08 17:48:59.693', 'https://franquias.portaldofranchising.com.br/franquia-samello-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '440000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
