INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73sv001deh0se7ahvaht', 'FAST ESCOVA', 'fast-escova', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Somos uma rede de franquia especializada em escova. Realizamos procedimentos sem hora marcada, com uma vasta gama de produtos para tratamento in loco, e home care.', 2018, 2022, NULL, '2026-04-01 02:00:00.838', '2025-08-05 22:20:24.319', 86, NULL, 1, 2018, 'JĂĄ imaginou ter a sua prĂłpria franquia de beleza com alta demanda de clientes todos os dias? Na franquia Fast Escova isso Ă© realidade. Mais de 160 franquias comercializadas Presente em todos os estados do Brasil Suporte ao franqueado desde a implantaĂ§ĂŁo Custo operacional baixo e alta lucratividade InovaĂ§ĂŁo: atendimento sem hora marcada VocĂȘ nĂŁo precisa entender de beleza: a gente te ensina tudo Â  UM NOVO MERCADO:Â MAIS FORTE E ALTAMENTE RENTĂVEL O Brasil Ă© o 3Âș maior mercado consumidor de beleza, atrĂĄs somente dos EUA e China. As franquias de beleza ocupam a 2Âș posiĂ§ĂŁo entre as franquias mais lucrativas do Brasil. A procura por produtos e serviĂ§os que oferecem autoestima e bem-estar Ă© uma crescente no paĂ­s e no mundo. A franquia Fast Escova criou uma novo nicho dentro deste mercado, atingindo um pĂșblico amplo e muito fiel. Â  INVESTIMENTO 50% ABAIXO DA MĂDIAÂ DE FRANQUIAS DE BELEZA E 3 FORMAS DE GANHO Ao comprar uma franquia Fast Escova vocĂȘ tem acesso ao nosso know-how de operaĂ§ĂŁo completo e jĂĄ formatado, alĂ©m de contar com um suporte da franqueadora em todos os momentos desde a implantaĂ§ĂŁo atĂ© o dia-a-dia do negĂłcio! PrestaĂ§ĂŁo de ServiĂ§os de Beleza\n\tEscova, HidrataĂ§ĂŁo, Penteado e Maquiagem. OpĂ§Ă”es de ServiĂ§os por Assinatura\n\tFature com compras recorrentes, recebendo uma mensalidade. Venda de Produtos de Marca PrĂłpria\n\tMaravilhosos produtos de Upsell exclusivo para nossos franqueados. FUNDADA EM 2018, FRANQUIA FAST ESCOVA Ă UM SUCESSO E JĂ ULTRAPASSOU A MARCA DE 160 UNIDADES VENDIDAS NO BRASIL!', NULL, 'GOIĂS', 1, NULL, 168, NULL, NULL, '2026-03-08 17:52:38.995', 'https://franquias.portaldofranchising.com.br/franquia-fast-escova/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
