INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73t5001feh0swul53ikx', 'VIZINHANDO BOTECAGEM DE RAIZ', 'vizinhando-botecagem-de-raiz', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Vizinhando Ă© o quintal dos bairros! O melhor boteco para se sentir em casa, curtir a vida sem amarras, ser feliz despretensiosamente, tudo isso com muito sabor, irreverĂȘncia e chopp trincando.', 2015, 2015, '[\"https://www.youtube.com/watch?v=-Hm9-EcSRgk\"]', '2026-04-01 02:00:00.860', '2025-08-05 22:20:24.330', 88, NULL, 1, 2014, 'O Vizinhando Ă© a mistura ideal de bar e restaurante. Mais que um destino casual, somos o quintal dos bairros. Aqui a cerveja Ă© sempre gelada e os pratos sĂŁo bem servidos, com aquele gostinho e criatividade que sĂł um bom vizinho tem a oferecer. Ă um lugar onde vocĂȘ pode confiar e se sentir verdadeiramente Ă  vontade. Acreditamos que nĂŁo precisamos de muito: enquanto a cerveja estiver gelada e o espeto gostoso, estaremos mais que felizes. Nossas saideiras sĂŁo daquelas de trĂȘs rodadas. Buscamos a diversĂŁo na vida e nĂŁo somos muito a favor de regras. Queremos fazer parte da histĂłria das pessoas, criando memĂłrias gostosas, de muitas risadas e calor no coraĂ§ĂŁo. O Vizinhando existe para promover (re)encontros.\nÂ  POR QUE SER UM FRANQUEADO VIZINHANDO? O Vizinhando Ă© uma marca do Grupo Alento Franchising, franqueadora do ramo de alimentaĂ§ĂŁo que ainda possui outras marcas como Billy The Grill, o Naa! Sushi Bar e tambĂ©m a Cloud Kitchen Brazil, a nossa cozinha na nuvem, um negĂłcio totalmente voltado para delivery com oito marcas conglomeradas. Nosso grupo nasceu em 2010 e jĂĄ conta com mais de 50 lojas franqueadas. Mais de 50% da nossa rede franqueada possui duas ou mais unidades do negĂłcio. Se vocĂȘ quiser saber mais sobre nossa rede, entre em contato com a gente atravĂ©s dos nossos contatos no topo desta pĂĄgina.', NULL, 'RIO DE JANEIRO', 1, NULL, 15, NULL, NULL, '2026-03-08 17:54:26.381', 'https://franquias.portaldofranchising.com.br/franquia-vizinhando-botecagem-de-raiz-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73ta001geh0s59jn0omc', 'LUKRO', 'lukro', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Franquia home office , plataforma de gestĂŁo completa e 100% online para lojas e restaurantes. SoluĂ§ĂŁo inovadora do segmento de ampla expansĂŁo. Com app de delivery,Pdv, fiscal, financeiro e muito mais.', 2021, 2022, '[\"https://www.youtube.com/watch?v=tS9zXCDVCGg\",\"https://www.youtube.com/watch?v=dPwMvUo3kmk\"]', '2026-04-01 02:00:00.871', '2025-08-05 22:20:24.334', 89, NULL, 1, 2017, 'O lukro Ă© a sua oportunidade de empreender no formato home office e com baixo investimento,Â zero capital de giro e zero capital de instalaĂ§ĂŁo,Â  retorno do investimento em atĂ© 90 dias. Uma franquia que vocĂȘ terĂĄ acesso a vĂĄrios produtos para comercializar no formato b2b. Imagine todos os comĂ©rcios, lojistas, varejos, bares e restaurantes do seu bairro da cidade e outros estados serem seus clientes e gerar uma receita recorrente e vitalĂ­cia para sua franquia?Â  Ter uma franquia lukro Ă© se tornar parte de uma empresa com 3 certificaĂ§Ă”es internacionais ISO 27001 / ISO 27701 / GTPW . uma empresa consolidada com 20 anos de mercado.Â  AlĂ©m disso, ele tambĂ©m Ă© uma franquia pertencente Ă  AssociaĂ§ĂŁo Brasileira de Franchising (ABF). Com esse sistema o franqueado tem a oportunidade de comercializar uma plataforma de gestĂŁo simplificada, que traz eficiĂȘncia para as principais tarefas diĂĄrias de uma empresa, seja ela de pequeno, mĂ©dio ou grande porte.Â  Lukro redefiniu a gestĂŁo empresarial, introduzindo um sistema moderno que revoluciona os processos de gestĂŁo que eleva a eficiĂȘncia. Seja parte da vanguarda da inovaĂ§ĂŁo! *FORMAS DE GANHOS*\n100% do valor de implantaĂ§ĂŁo do franqueado!\nvalor medio de implataĂ§ĂŁo de R$1,000Â \nvenda media 7 vendas mesÂ \n7.000 mil de implataĂ§ĂŁo mĂȘs esses ganhos podem ser superioresÂ  *GANHOS RECORRENTES*Â \ncada clientes que entra na carteira gera uma recorrĂȘncia das mensalidades de 40%Â \nvalor medio das mensalidades R$200,00Â  50 clientes recorrĂȘncia R$ 4,000\n100 clientes recorrĂȘncia R$ 8,000\n200 clientes recorrĂȘncia R$ 16,000Â  Uma franquia que vocĂȘ pode empreender apartir de casa, e montar seu time de vendas e parceiros para prospecĂ§ĂŁo de novos clientes.Â  As parceiras com contadores, associaĂ§Ă”es. RECEBA LISTAS DE CLIENTES A CADA 15 DAIS PARA VOCE PROSPECTAR A PARTIR DE CASA.Â  CDL ABRASEL FECOMERCIO tenha na prateleira de produtos da franquia lukro outros produtos para gerar mais receita recorrentes como certificados digitais eÂ Representante comercial STONE.', NULL, 'MATO GROSSO', 1, NULL, 12, NULL, NULL, '2026-03-08 17:55:14.379', 'https://franquias.portaldofranchising.com.br/franquia-lukro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
