INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73tl001ieh0snbpn0umc', 'IT\'S GRILL EXPRESS', 'it-s-grill-express', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Com o objetivo de oferecer cortes e carnes especiais dentro da praĂ§a de alimentaĂ§ĂŁo, a Itâs Grill traz uma seleĂ§ĂŁo de acompanhamentos diferenciados, pratos executivos, risotos e saladas.', 2011, 2018, NULL, '2026-04-01 02:00:00.894', '2025-08-05 22:20:24.346', 91, NULL, 1, 2011, 'As carnes nobres vĂȘm ocupando espaĂ§o relevante na mesa dos brasileiros, que tĂȘm cada vez mais levado a experiĂȘncia vivida na alta gastronomia para o seu dia a dia. De olho nesta tendĂȘncia de consumo, a Itâs Grill Express foi idealizada e implantada em 2011, tendo como premissa o desenvolvimento de um fast food focado em grelhados que se diferenciasse dos padrĂ”es jĂĄ existentes no mercado. A ideia em trazer para o fast food o mesmo corte e sabor servidos na alta gastronomia foi sucesso absoluto pela imediata aceitaĂ§ĂŁo do pĂșblico, decorrente do preĂ§o e, especialmente, apelo nutricional do cardĂĄpio. Para quem aprecia carne fresca, macia e suculenta, vai encontrar cortes especiais de Picanha, Mignon, T BonĂ©, Entrecot, entre outros, alĂ©m de acompanhamentos, risotos e saladas. E para atender o mais variado tipo e perfil de consumidor, tambĂ©m sĂŁo servidos pratos executivos. O cardĂĄpio Ă© preparado com insumos de primeirĂ­ssima linha e de procedĂȘncias reconhecidas no mercado. Nossos clientes demonstram bastante satisfaĂ§ĂŁo na relaĂ§ĂŁo custo x benefĂ­cio e reconhecem como justo o preĂ§o praticado. Atualmente a rede conta com 7 lojas em Curitiba, nos Shoppings Mueller, Curitiba, Barigui, PĂĄtio Batel, Palladium, EstaĂ§ĂŁo e Jockey Plaza, e em breve chegarĂĄ ao Shopping Boulevard Curitiba.', NULL, 'PARANĂ', 1, NULL, 12, NULL, NULL, '2026-03-08 17:56:40.499', 'https://franquias.portaldofranchising.com.br/franquia-its-grill-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
