INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73uu001peh0sodp849nr', 'ISLA BOLSAS', 'isla-bolsas', NULL, 'Moda', 'VestuĂĄrios', 'Bolsas e clutches Ășnicas e atemporais. AtravĂ©s do garimpo pelas mais nobres e sofisticadas matĂ©rias-primas, surgem formas exclusivas que logo viram objetos de desejo para mulheres de todas as idades.', 2019, 2021, '[\"https://www.youtube.com/watch?v=GUbNRSae5L4\"]', '2026-04-01 02:00:00.975', '2025-08-05 22:20:24.391', 98, NULL, 1, 2007, 'Fundada em 2007 pela mineira Silvia Monteiro, a Isla Ă© uma marca consolidada no mercado de luxo, reconhecida por suas bolsas exclusivas, sofisticadas e atemporais. \nO design autoral, o uso de materiais nobres e o cuidado artesanal colocaram a Isla em destaque desde sua linha festa â e hoje, a marca oferece um mix completo de produtos, que acompanham a mulher em todos os momentos, da praia ao dia a dia. Em 2020, ampliamos nosso propĂłsito com uma linha sustentĂĄvel, feita a partir de resĂ­duos tĂȘxteis e tecimento manual, promovendo inclusĂŁo social por meio do trabalho de artesĂŁs locais. \nPresente em lojas nos melhores shoppings do paĂ­s, multimarcas renomadas e marketplaces de luxo no Brasil e no exterior, a Isla Ă© sinĂŽnimo de elegĂąncia com consciĂȘncia.', NULL, 'MINAS GERAIS', 1, NULL, 9, NULL, NULL, '2026-03-08 17:59:31.207', 'https://franquias.portaldofranchising.com.br/franquia-isla-bolsas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '445000', NULL, NULL, NULL, '45000', NULL, '40', '2', '350000', '50000', 0);
