INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73va001reh0s4qvcwl68', 'LIG LIG', 'lig-lig', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'COMIDA CHINESA', 1994, 1989, '[\"https://www.youtube.com/watch?v=hgqHH1KRe1Y\",\"https://www.youtube.com/watch?v=E6eLCO8OkhY\",\"https://www.youtube.com/watch?v=5cnBWoMgmMc\",\"https://www.youtube.com/watch?v=aqVfhqx_Ek8\",\"https://www.youtube.com/watch?v=2dvkhW9DdBU\"]', '2026-04-01 02:00:00.999', '2025-08-05 22:20:24.406', 100, NULL, 1, 1992, 'A VERDADEIRA COMIDA CHINESA ABRE SUAS PORTAS Â  Em 1992, Thomas Liu recebeu a proposta de se tornar sĂłcio fundador de um negĂłcio que jĂĄ era sucesso na AmĂ©rica: o delivery de comida chinesa.Â  Filho de chineses e apaixonado pela culinĂĄria do paĂ­s, Thomas aceitou a oferta e se tornou sĂłcio do Lig-Lig, o primeiro delivery de comida chinesa do Brasil.Â  Com o crescimento natural da rede, Thomas assumiu a direĂ§ĂŁo do negĂłcio, comprou a parte de seus sĂłcios e hoje comanda 27 lojas, sendo trĂȘs prĂłprias.Â  UM PEDACINHO DA CHINA NO BRASILÂ  Um dos principais diferenciais da Lig-Lig Ă© a disseminaĂ§ĂŁo da cultura chinesa.Â  Atualmente, Thomas Liu tambĂ©m Ă© o chef de cozinha da rede e elabora todas suas receitas baseadas nos condimentos e demais ingredientes utilizados na China.Â  AlĂ©m disso, o chef tambĂ©m segue os quatro mandamentos da culinĂĄria chinesa, que sĂŁo:Â \ncor, perfume, paladar e apresentaĂ§ĂŁo esmerada.Â  Pratos coloridos, aromatizados por temperos e condimentos em profusĂŁo e cuidadosamente equilibrados para agradar nĂŁo apenas ao paladar, mas tambĂ©m ao olfato e Ă  visĂŁo, alĂ©m de um rigoroso controle de qualidade e processo, que sĂŁo o grande diferencial do Lig-Lig.Â  As inovaĂ§Ă”es do Lig-Lig em publicidade, social media e tecnologia sĂŁo constantes.Â \nExecutamos um planejamento de marketing que conecta aĂ§Ă”es de mĂ­dia, digital e offline.Â  Em 25 anos de rede, nos tornamos uma rede consolidada e sabemos que sĂŁo os laĂ§os fortes que solidificam o sistema. Assim, tratamos nossos franqueados com muito respeito e atenĂ§ĂŁo e atribuĂ­mos nosso constante sucesso Ă  parceria construĂ­da nessa relaĂ§ĂŁo.Â  VALORES LIG-LIGÂ  Divulgar a cultura chinesa Parceria e relaĂ§ĂŁo de qualidade com os franqueados PadronizaĂ§ĂŁo de processos LaĂ§os fortes: o sucesso dos franqueados, Ă© o nosso sucesso Trabalho focado na rentabilidade do franqueado', NULL, 'SĂO PAULO', 1, NULL, 33, NULL, NULL, '2026-03-08 18:00:30.375', 'https://franquias.portaldofranchising.com.br/franquia-lig-lig-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '422000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
