INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73vz001veh0sf0zdk0az', 'CAFĂ DO FEIRANTE', 'cafe-do-feirante', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'CAFETERIA E LANCHES', 2007, 2009, NULL, '2026-04-01 02:00:01.043', '2025-08-05 22:20:24.432', 104, NULL, 1, 2000, 'O SABOR QUE TEM HISTĂRIA Poucos lugares conseguem ser tĂŁo charmosos quanto uma cafeteria.  A franquia do CafĂ© do Feirante consiste em um negĂłcio que comercializa histĂłria, tradiĂ§ĂŁo e sabor. O ambiente acolhedor, as diversidades de produtos, a escolha dos mĂłveis, das cores, do cardĂĄpio, da arquitetura, estimulam novos hĂĄbitos nos consumidores, que cada vez mais se sentem atraĂ­dos pelo espaĂ§o. O CafĂ© do Feirante traz consigo os sabores tradicionalmente brasileiros, resgatando sensaĂ§Ă”es, aromas e o prazer de apreciar um alimento caseiro, preparado com produtos selecionados e de Ăłtima qualidade. O CafĂ© do Feirante prima pela valorizaĂ§ĂŁo do cliente, pelo respeito e pela qualidade de seus produtos e serviĂ§os. Presente no mercado hĂĄ mais de 10 anos, inaugurou sua primeira loja na cidade de MarĂ­lia, interior de SĂŁo Paulo.  Atualmente a Rede conta com vĂĄrias lojas e busca parceiros capacitados para dar continuidade ao processo de expansĂŁo em um segmento que nĂŁo pĂĄra de crescer. O CafĂ© do Feirante possui um conceito simples, inspirador e genuinamente brasileiro. O ambiente alegre, que remete ao campo, Ă  fazenda, permite ao cliente viver esse conceito, inclusive atravĂ©s do mix variado, como: produtos caseiros, doces, salgados, lanches especiais, bebidas quentes e geladas Ă  base de cafĂ©, chĂĄs, sucos e muito mais, que agrada a todos os paladares, do mais simples ao mais exigente. Para isso, seleciona ingredientes de qualidade e combinam sabores que sĂŁo uma verdadeira tentaĂ§ĂŁo. Â  FaĂ§a parte dessa tradiĂ§ĂŁo. Seja um franqueado!', NULL, 'SĂO PAULO', 1, NULL, 11, NULL, NULL, '2026-03-08 18:02:34.054', 'https://franquias.portaldofranchising.com.br/franquia-cafe-do-feirante/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73w5001weh0sh1dcilik', 'BOULANGERIE CARIOCA', 'boulangerie-carioca', NULL, 'AlimentaĂ§ĂŁo', 'PADARIAS', 'Somos a Boulangerie Carioca. Um pedacinho da FranĂ§a e do Mundo aqui no Brasil.', 2016, 2018, NULL, '2026-04-01 02:00:01.055', '2025-08-05 22:20:24.437', 105, NULL, 1, 2015, 'ConheĂ§a a Boulangerie Carioca â A boulangerie pĂątisserie com receitas irresistĂ­veis direto da FranĂ§a A Boulangerie Carioca foi planejada para mudar o mercado de panificaĂ§ĂŁo no Brasil. Fundada em 2015, no Rio de Janeiro, ela vem encantando clientes todos os dias com suas deliciosas receitas e ambientes aconchegantes. Investir na Boulangerie Carioca Ă© aceitar fazer parte de um time que tem como objetivo levar um pedaĂ§o da FranĂ§a para todos os cantos do paĂ­s. E entender que um simples cafĂ© da manhĂŁ parisiense com um toque carioca pode fazer toda a diferenĂ§a na vida de alguĂ©m. A marca oferece produtos fresquinhos da mais alta qualidade, com fermentaĂ§ĂŁo artesanal e natural que fazem toda a diferenĂ§a para o negĂłcio. E com um ambiente aconchegante e acolhedor como as padarias francesas, a Boulangerie Carioca se destaca no mercado e conquista clientes todos os dias. Nossos franqueados amam fazer parte da Boulangerie Carioca! Confira depoimentos de quem tem uma franquia Boulangerie Carioca e venha fazer parte dessa histĂłria.', NULL, 'SĂO PAULO', 1, NULL, 3, NULL, NULL, '2025-09-22 15:02:24.000', 'https://franquias.portaldofranchising.com.br/franquia-boulangerie-carioca/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
