 NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73wt0020eh0shvubooeh', 'MAX SUSHI JAPANESE FOOD', 'max-sushi-japanese-food', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Restaurante de Comida Japonesa Presencial e Delivery', 2008, 2012, '[\"https://www.youtube.com/watch?v=_XWIhsY3p-g\"]', '2026-04-01 02:00:01.088', '2025-08-05 22:20:24.462', 109, NULL, 1, 2007, 'A Max Sushi restaurante de comidas tipicamente japonesa. Fundada em novembro de 2007, inovou no mercado atuando no modo fast food, garantindo rapidez, versatilidade, variedade, qualidade, e principalmente, escolha, uma vez que Ă© o prĂłprio cliente quem monta seu prato. Sua primeira loja, localizada no Shopping Boungainville em GoiĂąnia, logo de inĂ­cio superou todas as expectativas, seu faturamento esperado para 3 anos foram alĂ§ados em apenas 6 meses de operaĂ§ĂŁo, e isso por si sĂł Ă© surpreendente. PorĂ©m, o pĂșblico ficou tĂŁo entusiasmado que a proposta de franquia foi inevitĂĄvel. A rede Max Sushi em 5 anos de mercado, conta com franquias em 9 estados do Brasil com um total de 13 lojas, ganhando prĂȘmios de empreendedorismo e de melhores resultados em vendas. Sua histĂłria tem traĂ§os de grandes conquistas e surpresas. Em meio a abertura de lojas com filas enormes de mais de 70 clientes e salva de palmas inesperadas em inauguraĂ§ĂŁo de expansĂŁo. Obteve resultados surpreendentes com anos de crescimento maiores de 400%. Os produtos tĂȘm caracterĂ­sticas originais da culinĂĄria japonesa e chinesa com diferencial no sabor e presteza no atendimento. Na Max Sushi a comida Ă© por quilo, o que permite aos clientes liberdade de escolha, onde saboreiam o que quiserem na quantia desejada com qualidade de alto padrĂŁo em boas prĂĄticas de higiene e manipulaĂ§ĂŁo de alimentos. Seus sonhos sĂŁo ainda maiores para os prĂłximos anos e espera que mais colaboradores e clientes possam fazer parte dessa histĂłria.', NULL, 'GOIĂS', 1, NULL, 8, NULL, NULL, '2026-03-08 18:05:13.637', 'https://franquias.portaldofranchising.com.br/franquia-max-sushi-japanese-food-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '55000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
