, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73x90023eh0s7uan5gg5', 'GRUPO MEDNET MEDICINA E SEGURANĂA DO TRABALHO', 'grupo-mednet-medicina-e-seguranca-do-trabalho', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'Medicina e SeguranĂ§a do Trabalho.', 2006, 2012, NULL, '2026-04-01 02:00:01.123', '2025-08-05 22:20:24.477', 112, NULL, 1, 1994, 'Fundada em 1994 na cidade de Americana/SP, no coraĂ§ĂŁo da RegiĂŁo Metropolitana de Campinas, a MEDNET SaĂșde Ocupacional dedica-se Ă  prestaĂ§ĂŁo de serviĂ§os ocupacionais, com realizaĂ§ĂŁo de exames clĂ­nicos, audiomĂ©tricos, laboratoriais, cardiolĂłgicos, oftalmolĂłgicos, radiolĂłgicos, e demais especialidades envolvidas nas atividades laborais de seus clientes. A empresa atende as demandas de vĂĄrios clientes por todo o territĂłrio nacional, desde instituiĂ§Ă”es privadas a instituiĂ§Ă”es governamentais e autarquias. AtravĂ©s de constante pesquisa, estudo, e investimento em tecnologia o Grupo MEDNET busca a perfeiĂ§ĂŁo em seus serviĂ§os. A empresa conta com uma equipe de profissionais capacitados e certificados que sĂŁo sujeitos a constantes treinamentos para atualizaĂ§ĂŁo e aprimoramento que permite que ultrapassemos os resultados esperados pelos nossos clientes. Uma das razĂ”es que tornam o Grupo MEDNET uma empresa lĂ­der em seu segmento Ă© sua atitude arrojada e desbravadora, estando sempre Ă  frente de seu tempo, prevendo tendĂȘncias e se antecipando a elas. Nessa linha foi que o Grupo MEDNET em 2002 criou a divisĂŁo SEGNET, especializada na ĂĄrea de seguranĂ§a do trabalho, com uma ampla equipe de profissionais, composta de engenheiros e tĂ©cnicos de seguranĂ§a do trabalho em constante reciclagem e capacitaĂ§ĂŁo, proporcionando aos nossos clientes a facilidade de poder contar com todos os serviĂ§os de medicina e seguranĂ§a do trabalho centralizados em um Ășnico fornecedor. O resultado desta uniĂŁo Ă© mais agilidade e melhor qualidade nos serviĂ§os prestados. Como resposta a grande aceitaĂ§ĂŁo do mercado, o Grupo MEDNET instalou unidades em polos estratĂ©gicos de negĂłcio, para poder atender cada vez melhor os seus clientes. Este tambĂ©m foi o embriĂŁo da MEDNET Franchising. Com o gerenciamento remoto destas unidades regionais, foram aprimoradas as ferramentas e os processos para a abertura de unidades franqueadas. Como prĂłximo passo, foi inaugurada em 2006 a unidade Limeira, pioneira como unidade franqueada. Desde entĂŁo o sistema tem se aperfeiĂ§oado e novas unidades franqueadas foram inauguradas. Por todos estes motivos que o Grupo MEDNET Ă© a escolha ideal quando se busca eficiĂȘncia na ĂĄrea de SaĂșde Ocupacional e SeguranĂ§a do Trabalho.', NULL, 'SĂO PAULO', 1, NULL, 58, NULL, NULL, '2026-03-08 18:07:19.926', 'https://franquias.portaldofranchising.com.br/franquia-mednet-medicina-e-seguranca-do-trabalho/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
