INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73yq002ceh0stz7bzwvi', 'S.A. CASA DO SUSHI', 's-a-casa-do-sushi', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'BUFFET DE COMIDA JAPONESA - SUSHI', 2019, 2022, '[\"https://www.youtube.com/watch?v=iJVUjCrN7mk\"]', '2026-04-01 02:00:01.227', '2025-08-05 22:20:24.531', 121, NULL, 1, 2017, 'OlĂĄ, somos a S.A. Casa do Sushi e Restaurante LTDA.\nÂ  Estamos no mercado desde 2017 no ramo de comida japonesa. \nVisando a necessidade do mercado de trazer a culinĂĄria oriental, para o maior nĂșmero de pessoas, de forma acessĂ­vel a todos com qualidade e baixo custo, inauguramos nosso primeiro restaurante na cidade de CamboriĂș-SC. \nO sucesso de nosso negĂłcio foi tamanho que buscamos a expansĂŁo, e Ă  medida em que a demanda aumentava, tornamo-nos franqueadores.\nÂ  Hoje, contamos com 25 unidades espalhadas por Santa Catarina, ParanĂĄ e tambĂ©m SĂŁo Paulo, sĂŁo elas: Itapema-SC, CamboriĂș-SC, SĂŁo JosĂ© dos Pinhais-PR, Araquari-SC, Castro-PR, SĂŁo JosĂ©-SC, Tijucas-SC, ParanaguĂĄ-PR, Ponta Grossa-PR, Joinville-SC nos bairros Zona Sul e IririĂș, JaraguĂĄ do Sul-SC, Colombo-PR, Brusque-SC, AraucĂĄria-PR, Londrina-PR, UniĂŁo da VitĂłria-PR, Pinhais-PR, MaringĂĄ-PR, Praia Grande-SP, Curitiba-PR nos bairros Alto da XV, Novo Mundo, MercĂȘs e SĂ­tio Cercado.\nÂ  Em todas as franquias buscamos manter nossa essĂȘncia e qualidade, fornecendo um ambiente acolhedor, com atendimento diferenciado e preĂ§o justo, o comprometimento em garantir a satisfaĂ§ĂŁo de nossos clientes Ă© nossa prioridade.', NULL, 'SANTA CATARINA', 1, NULL, 27, NULL, NULL, '2026-03-08 18:12:10.122', 'https://franquias.portaldofranchising.com.br/franquia-sa-casa-do-sushi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '210000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
