INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73z1002eeh0s4retiiw9', 'ARTWALK', 'artwalk', NULL, 'Moda', 'CalĂ§ados', 'TĂNIS CASUAIS/SNEAKERS, DAS PRINCIPAIS MARCAS MUNDIAIS ALĂM DE ACESSĂRIOS COMO BONĂS, CAMISETAS E MEIAS', 2006, 2009, NULL, '2026-04-01 02:00:01.266', '2025-08-05 22:20:24.541', 123, NULL, 1, 2006, 'Fundada em 2006, a Franquia Artwalk pertence ao Grupo Afeet, que, Ă  Ă©poca, percebeu a falta de um player forte em seu nicho no paĂ­s, detectando a oportunidade de implementar uma rede de sneaker stores no Brasil. \nA Artwalk Ă© focada em calĂ§ados de moda, casuais e sneakers, e disponibiliza ainda um mix complementar de âTsâ(camisetas), caps (bonĂ©s), meias descoladas e mochilas. \nOferece aos seus clientes, que buscam estilo e atitude na hora de comprar um tĂȘnis, um mix de produtos atualizado com as tendĂȘncias internacionais e, como diferencial, a melhor experiĂȘncia de compra em um ambiente diferenciado, com vendedores especializados na âcultura sneakerâ. \nEntre as marcas comercializadas pela rede estĂŁo Nike, adidas Originals, Vans, Converse, New Balance, Puma, Reebok, New Era, Jansport, Sprayground e Stance. \nAtualmente, a Artwalk, alĂ©m da loja virtual, possui 38Â lojas distribuĂ­das nos principais Shoppings de sete estados brasileiros: SĂŁo Paulo, Rio de Janeiro, Minas Gerais, EspĂ­rito Santo, ParanĂĄ, Bahia e Pernambuco.', NULL, 'SĂO PAULO', 1, NULL, 73, NULL, NULL, '2026-03-08 18:13:23.673', 'https://franquias.portaldofranchising.com.br/franquia-artwalk-acessorios-pessoais-calcados-e-tenis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza73z7002feh0sl1d746nx', 'CHICKEN TOWN', 'chicken-town', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Ă uma rede de franquia de frango frito empanado do estilo Americano, que tem origens inglesas e entrou no mercado para trazer algo inovador na receita de frango frito que fosse crocante e suculento.', 2019, 2021, '[\"https://www.youtube.com/watch?v=wHbNLyCs0qY\",\"https://www.youtube.com/watch?v=7mVuYQ-R-Nk\",\"https://www.youtube.com/watch?v=i3sifbo-yCc\",\"https://www.youtube.com/watch?v=gpLDjdJD0h0\"]', '2026-04-01 02:00:01.284', '2025-08-05 22:20:24.547', 124, NULL, 1, 2019, 'Aposte na melhor franquia de delivery do Brasil Confira as vantagens de ter uma franquia Chicken Town de Frango Frito Empanado. 100% Focado em Delivery OperaĂ§ĂŁo simples e otimizada Treinamento TeĂłricos e PrĂĄticos Marketing Integrado Alta Rentabilidade Baixo Investimento Suporte de ImplantaĂ§ĂŁo Produtos Bem Avaliados Somos associados ABF (AssociaĂ§ĂŁo Brasileira de Franchising)  AÂ Chicken TownÂ Ă© uma rede de franquia de frango frito empanado do estilo Americano que atua no segmento de alimentaĂ§ĂŁo, com foco em delivery e refeiĂ§Ă”es rĂĄpidas, estiloÂ fast food. Nasceu em UberlĂąndia cidade do interior de Minas Gerais, estĂĄ no mercado desde 2019. Com apenas dois anos de operaĂ§ĂŁo, jĂĄ possui mais de 21 unidades distribuĂ­das pelo paĂ­s, sua meta para 2022 Ă© mais que dobrar o nĂșmero de unidades. Nossos produtos ConheĂ§a a qualidade incomparĂĄvel e crocĂąncia dos nossos produtos com uma receita inglesa ultrassecreta. AlĂ©m de contar com uma excelente qualidade, trabalhamos com diversas opĂ§Ă”es servindo porĂ§Ă”es individuais atĂ© combos que atendem diversas pessoas, ideal para promover o encontro de amigos, reuniĂ”es de famĂ­lia, confraternizaĂ§Ă”es de empresas etc. Aos franqueados, aÂ Chicken TownÂ garante treinamento completo para preservaĂ§ĂŁo de qualidade nos serviĂ§os, marketing e atendimentos da rede. O empreendedor investe em um modelo de negĂłcio jĂĄ testado e consolidado no segmento de alimentaĂ§ĂŁo, com bons Ă­ndices de rentabilidade. A franqueadora auxilia na praticidade da gestĂŁo dos modelos de franquia, alĂ©m de treinamentos teĂłricos e prĂĄticos. Aos interessados em um modelo de franquia da rede, aÂ Chicken TownÂ disponibiliza trĂȘs modalidades de investimento. Dark Kitchen, que Ă© um modelo onde o restaurante funciona exclusivamente para o serviĂ§o de delivery. Ou seja, nĂŁo possui instalaĂ§Ă”es para refeiĂ§ĂŁo no local, como salĂŁo, mesas e cadeiras.Â  O investimento aproximado Ă© de 75 mil reais. Delivery, requer que o ponto comercial tenha dimensĂ”es mĂ­nimas de atĂ© 35 metros quadrados, possui atendimento presencial / balcĂŁo (para pedido e retirada), mas nĂŁo possui espaĂ§o para refeiĂ§ĂŁo no local. O investimento aproximado Ă© de 85 mil reais. StandardÂ com ĂĄrea exigida acima de 35 mÂČ, com espaĂ§o completo para refeiĂ§ĂŁo no local e Delivery. O investimento aproximado Ă© de 120 mil reais. Em todos os modelos de franquia aÂ Chicken TownÂ auxilia no apoio presencial e treinamento completo. O modelo de logĂ­stica elaborado pela Chicken Town permite que a rede esteja por todo o Brasil, hoje atuamos em SP, MG, ES, GO e SC.', NULL, 'SĂO PAULO', 1, NULL, 17, NULL, NULL, '2026-03-08 18:14:06.891', 'https://franquias.portaldofranchising.com.br/franquia-chicken-town/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '115000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
