INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza742x0032eh0s9iiwlpc6', 'TEREZA ZANCHI SHIATSU E BEM ESTAR', 'tereza-zanchi-shiatsu-e-bem-estar', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'TEREZA ZANCHI Shiatsu e Bem-estar oferece terapias de relaxamento e bem-estar atravĂ©s de um mĂ©todo prĂłprio e exclusivo em shopping centers, pontos de rua e SPA. 12 unidades em operaĂ§ĂŁo (base: 2024)', 2005, 2016, NULL, '2026-04-01 02:00:01.715', '2025-08-05 22:20:24.681', 147, NULL, 1, 2003, 'TUDO O QUE VOCĂ PROCURAVA NUM EXCELENTE NEGĂCIO! SEGURANĂA: Investimento seguro. NegĂłcio de sucesso testado e comprovado. Acesso a um mercado muito promissor e pouquĂ­ssimo explorado.Â  NOVIDADE: Conceito moderno e de alto valor agregado, com posicionamento diferenciado e lideranĂ§a no mercado.Â  LOCALIZAĂĂO: Diferentes formatos e modelos de negĂłcios viĂĄveis e atraentes para localizaĂ§Ă”es comerciais âPremiumâ: Operamos em Shopping Centers, Centros Comerciais e hotĂ©is. KNOW-HOW: Metodologias e tĂ©cnicas orientais inspiradas no âShiatsuâ, sistematizadas e adaptadas Ă s necessidades do mercado brasileiro.Â \nÂ  EXPERIĂNCIA: Mais de 30 anos de atuaĂ§ĂŁo bem sucedida no segmento, atravĂ©s do MĂ©todo Tereza Zanchi. CUSTO-BENEFĂCIO: Ătima lucratividade, baixo custo operacional e rĂĄpido retorno de investimento.Â  EXPANSĂO: Em breve, aÂ Tereza Zanchi Shiatsu e Bem-Estar estarĂĄ nas principais regiĂ”es do paĂ­s.Â   SUPORTE DA FRANQUEADORA: ServiĂ§o de apoio Ă  seleĂ§ĂŁo e avaliaĂ§ĂŁo de pontos comerciais e de potencial de mercado Projeto arquitetĂŽnico, decoraĂ§ĂŁo e montagem do estabelecimento (serviĂ§o prestado por terceiros) SupervisĂŁo durante as obras, a ser executada por equipe local Suporte para compra dos mĂłveis, equipamentos e utensĂ­lios para o estabelecimento TransferĂȘncia do direito de uso da marca, logotipo e outros sinais visuais caracterĂ­sticos Exclusividade territorial em determinado bairro, cidade ou regiĂŁo Treinamento inicial do franqueado, de seu gerente operacional (multiplicador) e principais funcionĂĄrios: na ĂĄrea administrativa, tĂ©cnica e operacional TransferĂȘncia do know-how comercial e operacional Central de Compras, Central de Treinamento e Central de Eventos Apoio comercial e operacional na inauguraĂ§ĂŁo da unidade OrientaĂ§ĂŁo quanto Ă  promoĂ§ĂŁo de lanĂ§amento Publicidade contĂ­nua de modo cooperado Contrato de 5 anos (bem superior ao payback estimado, condiĂ§ĂŁo favorĂĄvel ao franqueado), e renovĂĄvel automaticamente por iguais perĂ­odos anuais Know-how apĂłs expiraĂ§ĂŁo do contrato: Requer nĂŁo concorrĂȘncia direta com o segmento de atuaĂ§ĂŁo do franqueador no decorrer do perĂ­odo de vigĂȘncia do contrato de franquia e por 5 anos contados a partir de sua expiraĂ§ĂŁoÂ  Sistema de gestĂŁo informatizado Controles administrativos e financeiros: visitas dos consultores de campo, relatĂłrios gerenciais e financeiros Assessoria contĂ­nua do franqueador e treinamento contĂ­nuo, em funĂ§ĂŁo de eventuais lanĂ§amentos de novos serviĂ§os ou produtos complementares, ou ainda novos procedimentos operacionais Ă permitido ao Franqueado gerenciar mais do que uma unidade, sendo incentivado ao franqueado que invista seus lucros na abertura de mais de uma unidade Â  NĂO Ă EXIGIDO DO CANDIDATO FRANQUEADO: ExperiĂȘncia anterior no ramo (embora seja desejĂĄvel) Conhecimentos profissionais na ĂĄrea de massoterapia, porĂ©m isto deve ser exigido dos colaboradores que irĂŁo prestar serviĂ§os na unidade e serĂŁo treinados no MĂ©todo Tereza Zanchi. Â  O QUE SĂ NĂS TEMOS: Empresa pioneira e rede de referĂȘncia no segmento de massagens terapĂȘuticas em Shopping Centers (desde 2003), Centros Comerciais, hoteis e SPAs, sem concorrentes diretos, sendo a maior rede do sul do Brasil; MĂ©todo prĂłprio e exclusivo criado por Tereza Zanchi â MĂ©todo Tereza ZanchiÂ© Know-how manualizado de sucesso testado e comprovado e nĂŁo disponĂ­vel por nenhuma outra fonte. Infraestrutura de apoio e suporte de gestĂŁo; Treinamento contĂ­nuo e pesquisa constante no lanĂ§amento de novos produtos e serviĂ§os em relaxamento e bem-estar; Simplicidade da operaĂ§ĂŁo e facilidade de replicaĂ§ĂŁo em diferentes praĂ§as; Diferenciais de atendimento e fidelizaĂ§ĂŁo; OĂĄsis de tranquilidade nos turbulentos centros urbanos; Bom ticket mĂ©dio por cliente (pĂșblico classes A/B); Excelente faturamento e rentabilidade, negĂłcio duradouro; Consulte-nos para oportunidades no exterior; Atividade em alta em 2021;Â  Rede associada Ă  ABF; Descubra e saiba mais sobre esta rara oportunidade que oferecemos para todo o Brasil na qualidade de pioneiras e lĂ­deres num ramo ainda pouco explorado do segmento de SaĂșde, Beleza e Bem Estar!', NULL, 'PARANĂ', 1, NULL, 12, NULL, NULL, '2026-03-08 18:25:01.726', 'https://franquias.portaldofranchising.com.br/franquia-centro-shiatsu-tereza-zanchi-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
