INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza743m0035eh0sdulz3oji', 'ĂGUA DE CHEIRO', 'agua-de-cheiro', NULL, 'SaĂșde, Beleza e Bem Estar', 'COSMĂTICOS E PERFUMARIA', 'Ăgua de Cheiro a primeira marca de franquias de beleza do Brasil.', 1976, 2017, NULL, '2026-04-01 02:00:01.762', '2025-08-05 22:20:24.706', 150, NULL, 1, 1976, 'A marca ĂGUA DE CHEIRO surgiu em 1976, com uma pequena loja de perfumaria na cidade de Belo Horizonte. O sucesso foi imediato e, em 1980, a empresa jĂĄ contava uma rede de 45 lojas. Pioneira no mercado de franquias de beleza e perfumaria, iniciou o processo de franchising na dĂ©cada de 80, e jĂĄ na dĂ©cada de 90, era lĂ­der de mercado no segmento de beleza. Hoje com mais de 40 anos no mercado, a ĂGUA DE CHEIRO Ă© reconhecida pela qualidade de seus cosmĂ©ticos e fragrĂąncias. Em 2013, a rede contava com 900 lojas, mas com uma direĂ§ĂŁo que enfrentava problemas de gestĂŁo. AtĂ© o inĂ­cio de 2014 contava tambĂ©m com um fabricante de perfumes e algumas lojas prĂłprias. Diante de acentuada dificuldade financeira, em agosto de 2014 a antiga direĂ§ĂŁo protocolou na JustiĂ§a pedido de RecuperaĂ§ĂŁo Judicial. Em 2016, a Marca ĂGUA DE CHEIRO foi adquirida pela BEAUTY FRANCHISING, empresa que integra o grupo de empresas da HOLDING NARSANA. Em 2017, a empresa retomou o processo de expansĂŁo pelo sistema de franchising, hoje conta com cerca de 200 lojas em todo o Brasil. EXPERIĂNCIA E SOLIDEZ Atualmente a BEAUTY FRANCHISING Ă© responsĂĄvel pela gestĂŁo do negĂłcio de Franquias da marca ĂGUA DE CHEIRO. A HOLDING NARSANA Ă© um grupo sĂłlido, composto por 17 empresas com de mais de 27 anos de experiĂȘncia de varejo de produto, gestĂŁo, logĂ­stica, desenvolvimento de produto e marketing no mercado de beleza nos segmentos de Luxo, Seletivo, Semi Prestigio, Massivo e Profissional. As atividades do grupo abrangem mais de 50 marcas nacionais e internacionais de perfumes, cosmĂ©ticos, produtos de toucador em um portfĂłlio de mais de 1.000 diferentes produtos, entre marcas prĂłprias, licenciadas e representadas com exclusividade para todo o Brasil. No segmento de Franquias, o grupo Ă© tambĂ©m o Master Franqueador da marca Argentina HAVANNA no Brasil desde 2005 e hoje conta com mais de 65 lojas em todo o paĂ­s, sendo reconhecida pelos seus alfajores, doce de leite e seus exclusivos cafĂ©s. NOSSA MISSĂO VANTAGEM COMPETITIVA DA MARCA ĂGUA DE CHEIRO FORMAS DE ATUAĂĂO O Franqueado pode atuar no formato Loja FĂ­sica, seja de rua ou shopping, ou ainda no formato quiosque com metragens que vĂŁo de 8 a 16 metros. LOJA CONCEITO Shopping Metro Itaquera, SP Investimento a partir de R$ 180 mil QUIOSQUE Em 4 formatos de 8 a 16 m2 Investimento a partir de R$ 80 mil A partir de R$ 80 mil reais, vocĂȘ jĂĄ pode investir em uma unidade quiosque da ĂGUA DE CHEIRO. Ficou interessado? Entre em contato! Shirleine Diniz Executiva de ExpansĂŁo', NULL, 'SĂO PAULO', 1, NULL, 135, NULL, NULL, '2025-02-04 12:29:25.000', 'https://franquias.portaldofranchising.com.br/franquia-agua-de-cheiro-cosmeticos-e-perfumaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza743s0036eh0sriph3ty3', 'FORTEC', 'fortec', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'âEducaĂ§ĂŁo de NĂ­vel TĂ©cnico, EducaĂ§ĂŁo Infantil, Ensino Fundamental e MĂ©dio, Cursos TĂ©cnicos a NĂ­vel MĂ©dio e PĂłs MĂ©dio, Ensino Superior e PĂłs GraduaĂ§ĂŁo, Cursos de qualificaĂ§ĂŁo ou requalificaĂ§ĂŁoâ', 2023, 2023, NULL, '2026-04-01 02:00:01.777', '2025-08-05 22:20:24.712', 151, NULL, 1, 1983, 'HistĂłria da Marca Escola e Faculdade FORTEC fundada em 1983, teve seu inĂ­cio a partir da implantaĂ§ĂŁo dos cursos tĂ©cnicos em EletrĂŽnica e InstrumentaĂ§ĂŁo, a primeira turma de alunos formou-se em 1987. Em 1989, na Av. Presidente Wilson, nÂ° 754, em SĂŁo Vicente, ao lado trĂȘs amigos - tendo como um dos grandes incentivadores, o doutor Walter Iervolino - teve um comeĂ§o humilde com 120 alunos, 12 professores e 2 funcionĂĄrios administrativos e em seus primeiros anos de existĂȘncia, a Escola TĂ©cnica Fortec passou a suprir a necessidade existente no Polo PetroquĂ­mico de CubatĂŁo, oferecendo mĂŁo de obra especializada na ĂĄrea de AutomaĂ§ĂŁo para o mercado de trabalho. Em 1987, foi implantado o curso EducaĂ§ĂŁo infantil e apĂłs o Ensino Fundamental. Em 1990, inaugurou-se a sua segunda unidade localizada Ă  rua CĂąndido Rodrigues, nÂ° 304, em SĂŁo Vicente, com os cursos EducaĂ§ĂŁo Infantil, Ensino Fundamental e cursos TĂ©cnicos. Em 1993, a Fortec expandiu suas fronteiras, levando para a cidade de Praia Grande, sua terceira unidade localizada na Rua IndaiĂĄ, 119 - Jardim Guilhermina. Em 1998, inaugurou-se sua quarta unidade localizada em SĂŁo Vicente, na Av. Presidente Wilson, nÂ° 1013, em SĂŁo Vicente. AlĂ©m disso, aos poucos, a sociedade foi sendo integrada Ă  Fortec, principalmente por meio de projetos sociais. Um dos primeiros projetos sociais foi a palestra sobre drogas, inĂ­cio de um trabalho de conscientizaĂ§ĂŁo, depois vieram outros e atĂ© hoje a Fortec desenvolve diversos projetos sociais. Em 2001, a Fortec se expandiu para a cidade de CubatĂŁo, inaugurando uma nova unidade, localizada na Av. NaĂ§Ă”es Unidas, 956, tendo surgido, concomitantemente, a Faculdade FORTEC na cidade de SĂŁo Vicente a qual continuou crescendo ao longo destes anos com diversos cursos superiores, procurando atender as necessidades educacionais de nossa regiĂŁo. E hoje possui 03 (quatro) unidades educacionais na cidade de SĂŁo Vicente no estado de SĂŁo Paulo. Em suas unidades educacionais jĂĄ se formaram mais de 16.000 jovens e adultos ao longo desses anos. Hoje ministramos cursos para os nĂ­veis: EducaĂ§ĂŁo Infantil, Ensino Fundamental, Ensino MĂ©dio, Ensino MĂ©dio/TĂ©cnico, Ensino Superior e TĂ©cnico a DistĂąncia. Hoje contamos com um projeto de expansĂŁo ousado para, atravĂ©s do sistema de franquias, ser uma grande rede com marca reconhecida nacionalmente.', NULL, 'SĂO PAULO', 1, NULL, NULL, NULL, NULL, '2026-03-08 18:27:31.523', 'https://franquias.portaldofranchising.com.br/franquia-fortec-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '960000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
