INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza744r003beh0s051lxg05', 'NOHA SHOES', 'noha-shoes', NULL, 'Moda', 'CALĂADOS', 'A Noha nasce para criar possibilidades ao mercado de moda masculina. Ofertamos de tudo que um homem pode querer referente a sapatos: de sandĂĄlia a bota. Mais que sapatos, criamos possibilidades.', 2018, 2022, NULL, '2026-04-01 02:00:01.852', '2025-08-05 22:20:24.747', 156, NULL, 1, 2016, 'A Noha tem a honra de nascer e viver numa Ă©poca em que o homem comeĂ§a a dar muito mais valor Ă  maneira com que se apresenta ao mundo e temos muito orgulho de ser um vetor importante dessa transformaĂ§ĂŁo. Nascemos a partir de uma insatisfaĂ§ĂŁo com a moda masculina nacional, onde o segmento de calĂ§ados estava congelado hĂĄ pelo menos 20 anos. As mesmas marcas ofereciam os mesmos modelos de sapatos com o mesmo design, nas mesmas cores, dentro de um mesmo ambiente de loja hĂĄ mais de duas dĂ©cadas. Um paĂ­s do tamanho do Brasil nĂŁo podia se contentar com esse cenĂĄrio. Sonhamos abrir portas para as tendĂȘncias internacionais com elegĂąncia e autenticidade. Sonhamos permitir que todos possam expressar-se atravĂ©s da moda. Sonhamos a Noha e o sonho virou realidade. Uma marca sĂłlida. Somos uma marca jovem, mas extremamente sĂłlida. Passamos pelo perĂ­odo mais difĂ­cil da histĂłria do varejo nacional com muita responsabilidade e organizaĂ§ĂŁo. Temos como prioridade nĂșmero um a rentabilidade dos nossos franqueados e por isso trabalhamos todos os dias. Atravessamos esses dois anos de pandemia sem deixar de crescer. Desde MarĂ§o de 2020 sĂŁo 9 lojas inauguradas e uma meta de mais 9 em 2022, fechando o ano com 30 operaĂ§Ă”es no paĂ­s.\"', NULL, 'PERNAMBUCO', 1, NULL, 23, NULL, NULL, '2025-02-10 13:16:50.000', 'https://franquias.portaldofranchising.com.br/franquia-noha-shoes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
