INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza745n003heh0s5qwvpju6', 'SESTINI', 'sestini', NULL, 'Moda', 'AcessĂłrios Pessoais', 'A Sestini Ă© especialista no segmento de malas de viagem, mochilas, bolsas e acessĂłrios de qualidade e com o melhor custo-benefĂ­cio, para acompanhar nossos clientes em todas as etapas da vida.', 2013, 2012, '[\"https://www.youtube.com/watch?v=eEJ8OBzb4Eo\",\"https://www.youtube.com/watch?v=9dzFVjv0Xds\",\"https://www.youtube.com/watch?v=rgfGtD25V8I\",\"https://www.youtube.com/watch?v=cn-8gdTwZTY\"]', '2026-04-01 02:00:01.963', '2025-08-05 22:20:24.779', 162, NULL, 1, 1995, 'Fundada em 1994 por Alexandre Roberto Benedek, a Sestini nasceu de um sonho de seu fundador de empreender no paĂ­s que recebeu seus pais. Criou o negĂłcio Sestini com o propĂłsito de oferecer malas, mochilas e acessĂłrios de alta qualidade ao mercado brasileiro, aproveitando a abertura da economia na Ă©poca. Ao longo dos anos, a marca se destacou pela capacidade de antecipar tendĂȘncias e evoluir junto com o mercado. Em 2005, consolidou-se como lĂ­der na distribuiĂ§ĂŁo de mochilas escolares com grandes licenĂ§as, como Disney, Mattel e Marvel. A partir de 2013, a Sestini redefiniu sua estratĂ©gia para fortalecer a marca, investindo em lojas prĂłprias e franqueadas e no e-commerce, e em pouco tempo de consolida nesse mercado, atingindo mais de 60 operaĂ§Ă”es em territĂłrio nacional no ano de 2019, sempre buscando crescer franqueados alinhados ao perfil da marca e com operaĂ§Ă”es rentĂĄveis e sustentĂĄveis no longo prazo. Comemorando 30 anos em 2024, a Sestini se consolidou como uma referĂȘncia nacional, mantendo seu compromisso com inovaĂ§ĂŁo, qualidade e excelĂȘncia no atendimento aos seus consumidores. Hoje, a marca conta com uma ampla rede de franquias e distribuiĂ§ĂŁo nacional, sendo reconhecida pela confiabilidade e pelo cuidado com seus produtos. A franquia Sestini oferece uma oportunidade Ășnica para quem busca investir em um negĂłcio consolidado e de alta demanda no mercado de malas, mochilas e acessĂłrios. Com mais de 30 anos de tradiĂ§ĂŁo, a Sestini Ă© reconhecida pela qualidade, inovaĂ§ĂŁo e confianĂ§a, sendo a Ășnica marca nacional do setor a expandir por meio de franquias monomarca. Ao se tornar franqueado Sestini, vocĂȘ contarĂĄ com um modelo de negĂłcio testado e aprovado, suporte completo em todas as etapas, desde a escolha do ponto comercial atĂ© a operaĂ§ĂŁo da loja. A rede de franquias oferece uma ampla linha de produtos, com destaque para malas de viagem, mochilas escolares e produtos licenciados, atendendo a diferentes pĂșblicos. A Sestini investe fortemente em marketing, inovaĂ§ĂŁo e desenvolvimento de novos produtos, o que permite uma alta rotatividade de estoque e uma excelente margem de lucro para seus franqueados. Com um plano de expansĂŁo audacioso e um mercado em constante crescimento, impulsionado pelo aumento nas viagens e a demanda por produtos de qualidade, a franquia Sestini se destaca como uma oportunidade segura e lucrativa. AlĂ©m disso, o franqueado tem acesso a treinamentos contĂ­nuos e ferramentas de gestĂŁo que garantem o sucesso da operaĂ§ĂŁo.', NULL, 'SĂO PAULO', 1, NULL, 61, NULL, NULL, '2026-03-08 18:32:39.284', 'https://franquias.portaldofranchising.com.br/franquia-sestini/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '444000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
