INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza746e003meh0slo0wngku', 'MUNDO VERDE', 'mundo-verde', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'LOJAS DE PRODUTOS NATURAIS, SUPLEMENTO PARA ATLETAS E BEM ESTAR', 1993, 1989, NULL, '2026-04-01 02:00:02.057', '2025-08-05 22:20:24.806', 167, NULL, 1, 1987, 'Invista em um Futuro SaudĂĄvel e Lucrativo com o Mundo Verde. Junte-se Ă  maior rede de produtos naturais e bem-estar do Brasil. \nDescubra como se tornar um franqueado de sucesso de uma das maiores lojas especializadas em produtos naturais e orgĂąnicos da AmĂ©rica Latina!  Investimento Inicial: A partir de R$250.000. Prazo de Retorno: De 24 a 36 meses. Taxas e Royalties: 5% de royalties e 1% de fundo de marketing. Â   Â  ConheĂ§a nossa histĂłria de sucesso:Â  Â  Â Linha do Tempo Â  1987 -Â FundaĂ§ĂŁo com a primeira loja em PetrĂłpolis/RJ.  1993Â - InĂ­cio da rede de franquias e inauguraĂ§ĂŁo da primeira franquia.  1994 - Chegada ao Rio de Janeiro/RJ.  2007 - Atingimos 100 lojas.  2009Â - Controle adquirido por um fundo de investimento.  2011 - InauguraĂ§ĂŁo de mais de 30 lojas.  2012 - InĂ­cio da venda de produtos com marca prĂłpria.  2014 - Controle pelo Grupo Sforza.  2018 - AquisiĂ§ĂŁo do maior e-commerce de produtos saudĂĄveis e suplementos do Brasil.  2019 - LanĂ§amento do e-commerce Mundo Verde.  2022 -TransiĂ§ĂŁo do e-commerce para um marketplace da rede franqueada.  2024 - ReformulaĂ§ĂŁo e rebranding dos produtos de marca prĂłpria. Â  Desde o inĂ­cio o objetivo da marca Mundo Verde Ă© levar mais saĂșde Ă s mesas brasileiras sem deixar o sabor de lado. Â  Â Hoje somos:Â  Â   Â  Â  Â Neste formato hoje, o Mundo Verde recebeu vĂĄrios prĂȘmios: Â   Â  Â  Â Depoimento dos nossos franqueados: Â   Â  Â   Â  Seja um franqueado Â  Por que escolher o Mundo Verde? Â   Marca Reconhecida e Premiada:\nConfianĂ§a e reputaĂ§ĂŁo construĂ­das ao longo de 37 anos.Â  Know-how Comprovado:\nConsiderada a maior curadoria de produtos ligados Ă  saĂșde, treino e bem-estar da AmĂ©rica Latina.Â  Mix de Produtos Homologados:\nDiversidade e qualidade garantidas.Â  GestĂŁo Participativa:\nConselho de franqueados ativo. PresenĂ§a Digital Forte:\nVenda em mĂșltiplos canais, incluindo site, WhatsApp, aplicativos e lojas fĂ­sicas. Top of Mind no Segmento:\nReconhecimento como lĂ­der de mercado. Â  Â  Â  Apoio e treinamento garantido Â  ServiĂ§o de Atendimento ao Franqueado:\nSuporte contĂ­nuo; Â  Treinamentos Iniciais e PeriĂłdicos:\nCapacitaĂ§ĂŁo constante;  Universidade Mundo Verde:\nCursos especializados;  Equipe de Consultores de Campo:\nAssistĂȘncia prĂĄtica e estratĂ©gica. Â  Â  Â  Suporte ContĂ­nuo em Marketing e OperaĂ§Ă”es    Campanhas Mensais:\nAĂ§Ă”es de marketing consistentes; Â  AĂ§Ă”es de marketing consistentes:\nVisibilidade e alcance ampliados;Â  Â  Suporte em AĂ§Ă”es Pontuais:\nPersonalizaĂ§ĂŁo de estratĂ©gias locais. Â  Â  Â  Â   Nosso diferencial Â   Â  Â   Â  Como se tornar um franqueado Mundo Verde Passo a passo:Â  Â   Â  Tempo MĂ©dio do Processo:Â De 20 a 90 dias, dependendo da escolha do ponto comercial', NULL, 'SĂO PAULO', 1, NULL, 166, NULL, NULL, '2026-03-08 18:35:52.369', 'https://franquias.portaldofranchising.com.br/franquia-mundo-verde-produtos-naturais/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '335000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
