INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7471003qeh0s5csrv4ol', 'TIMES IDIOMAS', 'times-idiomas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'ESCOLAS DE IDIOMAS e EDUCAĂĂO', 2014, 2019, '[\"https://www.youtube.com/watch?v=wZ3RwBzJ3RU\",\"https://www.youtube.com/watch?v=Q70fN9XsCYc\",\"https://www.youtube.com/watch?v=koFkXOU6VMQ\",\"https://www.youtube.com/watch?v=4SIvSrJhmW8\"]', '2026-04-01 02:00:02.107', '2025-08-05 22:20:24.829', 171, NULL, 1, 2014, 'Fundada em janeiro de 2014, por profissionais com amplo Know How no segmento, a Times optou pelo franchising em julho de 2015, com a venda da primeira escola na condiĂ§ĂŁo de franquia.\nÂ  Somos associados pela ABF desde 2019, conquistamos o selo de excelĂȘncia em 2023. A marca disponibiliza para o mercado 03 (trĂȘs) modelos de Franquias, sendo o primeiro de Franquia Comercial, o segundo de Franquias de Escolas e depois de amplo sucesso, com a mudanĂ§a de comportamento dos alunos por conta da pandemia, a Times se transforma numa EdTech, lanĂ§ando com exclusividade o modelo de negĂłcio Nexus, com alta lucratividade e baixo custo operacional.Â  Â  Diferenciais Â  A qualidade do ensino e a experiĂȘncia do aluno, sempre foram foco principal da franqueadora.\nÂ  Esta satisfaĂ§ĂŁo, mais a disciplina operacional construĂ­da de forma inteligente, garantem nĂșmeros impressionantes na mĂ©dia da rede Times, como: 95% de retenĂ§ĂŁo de alunos e inadimplĂȘncia abaixo de 5%, impactando positivamente no resultado financeiro da operaĂ§ĂŁo. Â  No modelo TIMES NEXUS, a receita Ă© compartilhada e a gestĂŁo operacional fica com a franqueadora. \nO Parceiro comercial ganha sobre: MatrĂ­culas Material DidĂĄtico Mensalidades AlĂ©m disso, nĂŁo cobramos Royalties para este modelo, ou seja, com um custo operacional muito baixo. \nA lucratividade da operaĂ§ĂŁo ultrapassa os 25%, atingindo o ponto de equilĂ­brio quase que de imediato e o retorno do investimento em atĂ© 12 meses. Â  Contamos com outros modelos de negĂłcio, que se ajustam a capacidade de investimento dos candidatos e da regiĂŁo de interesse. \nModelo Escola, retorno do investimento em 24 meses, franquia comercial em 6 meses.', NULL, 'SĂO PAULO', 1, NULL, 40, NULL, NULL, '2026-03-08 18:38:17.286', 'https://franquias.portaldofranchising.com.br/franquia-times-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza747a003reh0sxkt2rb67', 'YANG', 'yang', NULL, 'Moda', 'VESTUĂRIO', 'Industria de modeladores corporais, linha lingeries modeladoras funcionais, linha gestante e pos parto , linha pĂłs operatĂłria e linha masculina', 2009, 2021, '[\"https://www.youtube.com/watch?v=eg9MBknqJlc\",\"https://www.youtube.com/watch?v=QIkvqUWH9QQ\",\"https://www.youtube.com/watch?v=ZMApQEVoe_g\",\"https://www.youtube.com/watch?v=-fHFklbFPQo\"]', '2026-04-01 02:00:02.119', '2025-08-05 22:20:24.838', 172, NULL, 1, 2004, 'A franquia Yang nasceu do sonho de trazer elegĂąncia, conforto e funcionalidade para as mulheres modernas. NĂŁo era sobre se esconder, era sobre se amar e atravĂ©s deste sentimento o grande objetivo da marca se tornou a inovaĂ§ĂŁo constante do produto e a busca pela entrega de uma lingerie elegante, sensual e moderna, mas sem abrir mĂŁo da funcionalidade dos produtos. Hoje orientamos sobre a escolha da Lingerie correta para cada biotipo, defendemos que nĂŁo existem padrĂ”es, somos diferentes e temos direitos iguais, portanto a Yang trabalha para todas, nos esforĂ§amos ao mĂĄximo para a entrega de resultados, e assim obter a realizaĂ§ĂŁo das nossas clientes. As mulheres que hoje sĂŁo consumidoras Yang, sabem o real diferencial da nossa marca, nĂŁo somos uma marca de Lingerie comum, somos a marca de lingerie que pode mudar a autoestima dela atravĂ©s dos benefĂ­cios que nossos produtos oferecem. A YANG Ă© a principal franqueadora de lingeries funcionais no Brasil, liderando o mercado hĂĄ mais de 20 anos. Nossa missĂŁo Ă© fornecer soluĂ§Ă”es em moda Ă­ntima que combinem conforto, benefĂ­cios e elegĂąncia para mulheres de todas as idades e estilos. Hoje estamos em 8 estados com 22 franquias Suporte Abrangente OrientaĂ§Ă”es Sobre GestĂŁo & Pessoas Controle De Estoque Marketing EstratĂ©gico Treinamentos Imersivos Para Vendedores E Franqueados OperaĂ§ĂŁo Otimizada Com Equipe E Sistemas Integrados Design E InovaĂ§ĂŁo Em Todas As Linhas FabricaĂ§ĂŁo PrĂłpria De Todos Os Produtos Tecnologia De Ponta No Desenvolvimento Dos Nossos Produtos Loja Modelo De 45 A 60m2 Certificada Pela Anvisa', NULL, 'RIO GRANDE DO SUL', 1, NULL, 19, NULL, NULL, '2025-02-14 00:00:17.000', 'https://franquias.portaldofranchising.com.br/franquia-yang/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
