portaldofranchising.com.br/franquia-bolo-da-madre/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '93000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza747l003teh0setebvila', 'PEZINHO E CIA', 'pezinho-e-cia', NULL, 'Moda', 'CalĂ§ados', 'Rede de calĂ§ados e acessĂłrios infantis.', 2010, 2012, NULL, '2026-04-01 02:00:02.145', '2025-08-05 22:20:24.849', 174, NULL, 1, 2000, 'Acreditamos na forĂ§a do amor pela crianĂ§a. Muito trabalho e dedicaĂ§ĂŁo levaram a Pezinho e Cia a ser presenĂ§a marcante na vida e nos melhores momentos de milhares de famĂ­lias. Este sonho cresceu e se fortificou ano apĂłs ano pelo carinho e pela confianĂ§a dos nossos clientes, pela rigorosa busca de fornecedores de qualidade e pelo respeito e uniĂŁo entre todo quadro de funcionĂĄrios. \nEm abril de 2011, apĂłs a formataĂ§ĂŁo da marca âPezinho e Ciaâ, constituiu-se a empresa Pezinho Franchising e Comercio Ltda, respaldada em 32 anos de experiĂȘncia no mercado de varejo, adquirida com a empresa Boutique Futura MamĂŁe, que iniciou suas atividades em 1979, quando abriu a 1ÂȘ loja na PraĂ§a TamandarĂ©, em GoiĂąnia, atuando no segmento de moda gestante e infantil, incluindo calĂ§ados e acessĂłrios infantis. \nEm 1981 a loja foi transferida para o 1Âș shopping de GoiĂąnia â Flamboyant Shopping Center e em 2000 alterou o nome fantasia para Pezinho & Cia tornando â se especializada em calĂ§ados e acessĂłrios da linha infantil e infanto-juvenil. Â Com o sucesso das lojas inauguradas na cidade de GoiĂąnia em bairros nobres Marista e Bueno e nos principais shoppings da cidade surge um novo desafio na Pezinho Franchising e ComĂ©rcio:Â  expandir sua atuaĂ§ĂŁo no mercado nacional. \nAssim, ao longo dos anos, no segmento infantil em calĂ§ados e acessĂłrios a franquia Pezinho vem inaugurando lojas em todo Brasil sempre prezando pela qualidade de seus produtos e fornecedores oferecendo as melhores marcas nacionais e importadas. FaĂ§a parte dessa histĂłria! Venha ser nosso Franqueado!', NULL, 'GOIĂS', 1, NULL, 31, NULL, NULL, '2026-03-08 18:39:58.349', 'https://franquias.portaldofranchising.com.br/franquia-pezinho-e-cia-calcados-infantis/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
