INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7489003xeh0s2untsly8', 'AMERICANA SAĂDE', 'americana-saude', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'Franquia de drogarias com mais de 400 lojas, suporte completo em gestĂŁo e vendas, foco em crescimento sustentĂĄvel e aumento de rentabilidade para donos de farmĂĄcias.', 2007, 2012, '[\"https://www.youtube.com/watch?v=uGtm-s-yMmA\"]', '2026-04-01 02:00:02.201', '2025-08-05 22:20:24.874', 178, NULL, 1, 2007, 'A Drogaria Americana nasceu com o propĂłsito de oferecer serviĂ§os e produtos farmacĂȘuticos de qualidade a preĂ§os acessĂ­veis, sempre com foco no bem-estar e na saĂșde de seus clientes. Desde a sua fundaĂ§ĂŁo, a marca cresceu e se consolidou como uma das maiores redes de drogarias do Brasil, integrando o Grupo AMR SaĂșde, que atualmente conta com mais de 400 unidades em operaĂ§ĂŁo e um faturamento anual superior a R$ 1,5 bilhĂŁo. O que comeĂ§ou como uma farmĂĄcia de bairro, dedicada ao atendimento prĂłximo e personalizado, rapidamente ganhou a confianĂ§a do mercado, expandindo sua presenĂ§a para vĂĄrias regiĂ”es do paĂ­s. Em 2010, apĂłs perceber a necessidade de profissionalizar e padronizar o modelo de negĂłcios, a Drogaria Americana iniciou sua trajetĂłria no mercado de franquias, tornando-se uma oportunidade valiosa para empreendedores que desejam crescer no setor farmacĂȘutico. POR QUE SER UM FRANQUEADO DA DROGARIA AMERICANA? 1. Poder de negociaĂ§ĂŁo e condiĂ§Ă”es exclusivas Ao fazer parte da Drogaria Americana, vocĂȘ ganha acesso a negociaĂ§Ă”es diferenciadas com os maiores fornecedores do mercado. Isso garante melhores preĂ§os, maior variedade de produtos e condiĂ§Ă”es comerciais exclusivas, aumentando a competitividade da sua loja. 2. Marketing estratĂ©gico e campanhas promocionais A rede oferece suporte completo em marketing, com campanhas sazonais, estratĂ©gias de fidelizaĂ§ĂŁo e forte presenĂ§a digital, ajudando sua drogaria a atrair e reter mais clientes. AlĂ©m disso, promovemos aĂ§Ă”es de incentivo e campanhas promocionais que aumentam o fluxo de vendas. 3. Suporte e treinamento contĂ­nuo O sucesso dos nossos franqueados Ă© a nossa prioridade. Por isso, oferecemos acompanhamento constante em gestĂŁo de loja, vendas, controle de estoque e treinamentos especĂ­ficos para capacitar sua equipe. Assim, vocĂȘ estarĂĄ sempre atualizado com as melhores prĂĄticas do mercado. 4. Tecnologia e inovaĂ§ĂŁo A Drogaria Americana investe constantemente em tecnologia para ajudar vocĂȘ a otimizar a gestĂŁo do negĂłcio. Sistemas integrados facilitam o controle de vendas, relacionamento com clientes e acompanhamento de resultados, trazendo mais eficiĂȘncia para o seu dia a dia. FaĂ§a parte da nossa rede de sucesso! Ao se tornar um franqueado da Drogaria Americana, vocĂȘ estarĂĄ ingressando em uma rede consolidada, com uma trajetĂłria de crescimento e inovaĂ§ĂŁo no setor farmacĂȘutico. Se vocĂȘ jĂĄ possui uma drogaria, pode converter a bandeira para a nossa marca e aproveitar todas as vantagens que oferecemos. Se ainda nĂŁo tem experiĂȘncia no segmento, tambĂ©m estamos prontos para te orientar em cada etapa do processo. Entre em contato e descubra como podemos transformar seu negĂłcio!', NULL, 'MINAS GERAIS', 1, NULL, 197, NULL, NULL, '2026-03-08 18:41:44.973', 'https://franquias.portaldofranchising.com.br/franquia-americana-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza748l003yeh0sdw3zrp4l', 'OUTER. SHOES', 'outer-shoes', NULL, 'Moda', 'CalĂ§ados', 'A OUTER. Ă© uma marca conceito que desenvolve produtos femininos e masculinos exclusivos, a partir de elementos naturais com design e sofisticaĂ§ĂŁo.', 2010, 2024, NULL, '2026-04-01 02:00:02.217', '2025-08-05 22:20:24.885', 179, NULL, 1, 2004, 'Seja bem-vindo a um novo conceito de desenvolvimento de calĂ§ados: a Outer. Uma marca inovadora, que desde 2004 vem mantendo um ritmo contĂ­nuo de crescimento, oferecendo ao mercado produtos com design diferenciado, reconhecidos pela sofisticaĂ§ĂŁo e conforto e projetados por pessoas que respeitam as leis da natureza e estĂŁo sempre atentas Ă  ela, buscando expressar tal caracterĂ­stica atravĂ©s de designs inovadores. \nSempre movida pelo empreendedorismo, inovaĂ§ĂŁo e paixĂŁo, a Outer abriu sua primeira loja em 2005 no Shopping CittĂĄ AmĂ©rica no Rio de Janeiro, seguida pela abertura da loja do Shopping Leblon. JĂĄ nos anos seguintes, a Outer. deu inicio ao seu projeto de expansĂŁo abrindo mais cinco lojas nos principais pontos comerciais do Rio e de NiterĂłi e uma no Shopping Recife, marcando o inĂ­cio da expansĂŁo para todo o paĂ­s.  Nossa missĂŁo:\nA Outer. nĂŁo se resume a produzir calĂ§ados sofisticados e cheios de personalidade. Nossa missĂŁo Ă© ser a melhor marca conceito de calĂ§ados do Brasil, que permite a transformaĂ§ĂŁo do homem absorvido pelo ritmo cosmopolita em um homem mais integrado ao compasso da natureza, sem perder sua modernidade e sofisticaĂ§ĂŁo contemporĂąnea.  Nossos valores:\nO que torna a Outer. uma empresa diferente das demais Ă© forma como ela se relaciona com os clientes, colaboradores, concorrentes, fornecedores e, acima de tudo, como busca atingir seus objetivos de negĂłcios. \nPara Outer., tratar os clientes com carinho, valorizar os colaboradores, respeitar os concorrentes, desenvolver relacionamentos sĂłlidos com os fornecedores, respirar empreendedorismo e sempre buscar melhorar cada processo, sĂŁo os passos para se alcanĂ§ar seus objetivos.', NULL, 'RIO DE JANEIRO', 1, NULL, 32, NULL, NULL, '2026-03-08 18:43:01.101', 'https://franquias.portaldofranchising.com.br/franquia-outer-shoes-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '515000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza748t003zeh0saeit1fl1', 'GOLDEN MIX ĂTICA', 'golden-mix-otica', NULL, 'SaĂșde, Beleza e Bem Estar', 'ĂTICAS', 'ComĂ©rcio varejista de artigos de Ăłptica.', 2017, 2022, NULL, '2026-04-01 02:00:02.228', '2025-08-05 22:20:24.893', 180, NULL, 1, 1999, 'Destaque no ramo Ăłptico, a Golden Mix atua de maneira humanizada Muito alĂ©m de um modelo de negĂłcio, a Golden Mix Ă© uma empresa com uma proposta validada no ramo Ăłptico com mais de 23 anos de mercado. Como a Golden Mix surgiu? A primeira unidade da Golden Mix surgiu em 1999, na cidade de Suzano, na regiĂŁo do Alto TietĂȘ. Com a capacidade de servir, de entregar um serviĂ§o humanizado e de qualidade, a primeira unidade foi um sucesso e a marca se expandiu para as principais cidades de SĂŁo Paulo. ApĂłs a validaĂ§ĂŁo do trabalho de qualidade, de treinamentos especĂ­ficos aos gestores e aos colaboradores, a Golden decidiu expandir a marca e se tornou uma franquia apĂłs 19 anos. Em 2018, a empresa inaugurou a primeira franquia no centro de SĂŁo Paulo e hoje, jĂĄ conta com 12 lojas franqueadas ao todo. A Golden atinge classes variadas e estĂĄ localizada nos melhores pontos As unidades da Golden Mix estĂŁo espalhadas por toda SĂŁo Paulo e em pontos estratĂ©gicos de cada uma das cidades. As lojas ficam localizadas nos centros comerciais, onde existe uma maior concentraĂ§ĂŁo de passantes. Os principais clientes da rede Golden Mix atualmente sĂŁo: B-, C, D e E. Com um estoque variado que conta com produtos exclusivos e das principais marcas de grife do mundo, a rede Golden Mix promove a melhora da qualidade de vida das pessoas com preĂ§os acessĂ­veis e boa margem de lucro aos franqueados. A rede Golden Mix entrega um fullservice de excelĂȘncia, conta com laboratĂłrios prĂłprios, produtos de qualidade, atendimento premiado e humanizado. Os Ăłculos sĂŁo essenciais na vida das pessoas Os Ăłculos jĂĄ se tornaram essenciais na vida de muitas pessoas. Segundo a estimativa feita pela OrganizaĂ§ĂŁo Mundial da SaĂșde, atĂ© 2050, 50% da populaĂ§ĂŁo mundial deverĂĄ usar Ăłculos. A Golden Mix faz parte de um ramo de serviĂ§os essenciais, estĂĄ ligado diretamente com a melhora da qualidade de vida das pessoas. 80% da comunicaĂ§ĂŁo das pessoas com o mundo, se dĂĄ pela visĂŁo. EntĂŁo, o uso do Ăłculos Ă© muito essencial na vida das pessoas. Por isso, apesar da crise econĂŽmica que vĂĄrios setores enfrentaram nos Ășltimos anos de pandemia, o mercado Ăłptico seguiu crescendo. Segundo a AssociaĂ§ĂŁo Brasileira da IndĂșstria Ăptica (AbiĂłptica), a estimativa de crescimento anual Ă© de 20% para o setor nos prĂłximos dez anos. Em 2021, o setor contou com um crescimento e expansĂŁo sobre o ano anterior e chegou a 9,7%. A Golden se preocupa com o investidor Com um modelo de negĂłcio de sucesso, a Golden Mix criou o modelo de franquias e procura por investidores que desejam crescer junto Ă  empresa, independente da experiĂȘncia prĂ©via no ramo. Para que o investidor nĂŁo se sinta incapaz ou tenha que passar por uma difĂ­cil adaptaĂ§ĂŁo, a rede conta com treinamentos exclusivos aos franqueados e aos colaboradores das novas unidades. Os treinamentos sĂŁo feitos remotamente e presencialmente, completando a experiĂȘncia necessĂĄria para que o investidor se sinta seguro para gerir a prĂłpria loja. Suportes fornecidos aos investidores A Golden Mix auxilia o investidor em todos os processos, desde a escolha do ponto, atĂ© a estruturaĂ§ĂŁo da unidade. Oferece treinamentos individuais, de equipe e de gestĂŁo, alĂ©m claro, de suportes de T.I, de marketing e muito mais! Dentre os treinamentos ao franqueado estĂŁo: O treinamento de lojas vai introduzir o franqueado na rotina da loja, entendendo a dinĂąmica e como funcionam os processos; O treinamento tĂ©cnico, para otimizar o trabalho dele em meio aos processos e de como lidar com as situaĂ§Ă”es do dia a dia na loja. Quer abrir um negĂłcio estruturado, com um modelo de negĂłcio seguro e validado? Escolha a Golden Mix e venha escrever mais um capĂ­tulo de sucesso conosco!', NULL, 'SĂO PAULO', 1, NULL, 60, NULL, NULL, '2025-02-13 13:02:49.000', 'https://franquias.portaldofranchising.com.br/franquia-golden-mix-otica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
