INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749s0044eh0snxfg1j9y', 'DĂDIO PIZZA', 'didio-pizza', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'DĂ­dio Pizza Modelo de negĂłcio chave na mĂŁo - KNOW HOW de mais de 28 anos, pioneira no segmento, com operaĂ§ĂŁo 100% Delivery, com processos bem definidos nĂŁo dependendo de mĂŁo de obra especializada.', 2006, 2010, '[\"https://www.youtube.com/watch?v=L6yVZAxYRK4\"]', '2026-04-01 02:00:02.287', '2025-08-05 22:20:24.928', 185, NULL, 1, 1994, 'Em 1993, ElĂ­dio Biazini inaugurou a primeira unidade, pensando em operar como uma rede de pizzarias, prĂłpria ou atravĂ©s de franquia. Logo veio a segunda unidade, ainda nĂŁo formatada, porĂ©m franqueada. DĂ­dio era a forma carinhosa como seu avĂŽ, imigrante italiano natural da cidade de Silea/Treviso, apelidava as pessoas que ele nĂŁo sabia o nome. Tanto Ă© que acabou virando o seu apelido tambĂ©m. A Didio Pizza surgiu com foco total no Delivery. Atualmente, a rede estĂĄ presente nas principais regiĂ”es da cidade de SĂŁo Paulo, Grande SP e Interior. Os Pilares de crescimento da marca estĂŁo alicerĂ§ados no investimento constante em tecnologia, na qualidade dos produtos e serviĂ§os e na entrega rĂĄpida (no mĂĄximo 30 minutos apĂłs o pedido). Ao longo de 29 anos, a DĂ­dio Pizza investe em infraestrutura, processos e desenvolvimento de produtos, sendo pioneira em pizzas com massa integral, sem glĂșten e receitas de pizzas veganas. A marca DĂ­dio Ă© inovadora no seguimento Food e segue em plena expansĂŁo, mantendo a gestĂŁo familiar com a participaĂ§ĂŁo da segunda geraĂ§ĂŁo no negĂłcio.', NULL, 'SĂO PAULO', 1, NULL, 21, NULL, NULL, '2026-03-08 18:46:49.231', 'https://franquias.portaldofranchising.com.br/franquia-didio-pizza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza749y0045eh0s5vpo242u', 'TECFIT', 'tecfit', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studios para condicionamento fĂ­sico atravĂ©s da utilizaĂ§ĂŁo de equipamentos de eletroestimulaĂ§ĂŁo muscular. \"Academia sem pesos\".', 2017, 2023, '[\"https://www.youtube.com/watch?v=6m6KOQthT_E\",\"https://www.youtube.com/watch?v=nWNPOFXJOZo\"]', '2026-04-01 02:00:02.301', '2025-08-05 22:20:24.934', 186, NULL, 1, 2017, 'Descubra a revolucionĂĄria franquia TECFIT - ACADEMIA SEM PESOS, fruto de uma parceria estratĂ©gica com a XBODY, lĂ­der mundial em eletroestimulaĂ§ĂŁo muscular e a Ășnica com aval da ANVISA e do FDA (semelhante Ă  Anvisa no EUA) no Brasil. A tecnologia de eletroestimulaĂ§ĂŁo muscular nasceu na dĂ©cada de 1960 e inicialmente foi utilizada por fisioterapeutas e fisiologistas somente para o tratamento e recuperaĂ§ĂŁo de lesĂ”es musculares. Contudo, no inĂ­cio dos anos 2000 um novo rumo foi dado Ă  utilizaĂ§ĂŁo desta tecnologia. Em busca de resultados excepcionais e com o fim de reduzir a probabilidade de lesĂ”es, nadadores profissionais buscaram otimizar seu tempo fora das piscinas, reduzindo o seu tempo de musculaĂ§ĂŁo e aumentando o seu desempenho nos treinos de forĂ§a com a tecnologia de eletroestimulaĂ§ĂŁo muscular. A partir de 2017 surge a TECFIT, pioneira no Brasil, tornou essa inovaĂ§ĂŁo acessĂ­vel a todos. Treinos personalizados de 20 minutos ativam centenas de mĂșsculos pelo corpo inteiro e sem riscos de lesĂ”es. Sob a lideranĂ§a de especialistas renomados e uma equipe de sucesso, cresceu mesmo na crise do COVID-19. Atualmente contamos com mais de 40 unidades em todo o paĂ­s, Ă© uma franquia promissora que tem como visĂŁo: \"Mudar a Vida das Pessoas\".', NULL, 'SĂO PAULO', 1, NULL, 44, NULL, NULL, '2026-03-08 18:47:30.829', 'https://franquias.portaldofranchising.com.br/franquia-tecfit/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
