INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74b1004deh0sk9szk6db', 'CALIFORNIA COFFEE', 'california-coffee', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Coffee Shop', 2005, 2004, NULL, '2026-04-01 02:00:02.395', '2025-08-05 22:20:24.974', 194, NULL, 1, 2002, 'O California Coffee Ă© uma empresa que busca viver novas experiĂȘncias para que vocĂȘ possa viver as suas. O nosso conceito Ă© fruto de uma visita feita ao Brasil em 1999, quando nos questionamos por que o maior exportador de cafĂ© do mundo, que produz um cafĂ© tĂŁo fino e de alta qualidade nĂŁo tem a oportunidade de saborear o melhor que produz. A resposta era muito simples: quase toda a produĂ§ĂŁo dos melhores e mais finos cafĂ©s Ă© vendida para exportaĂ§ĂŁo. A partir de entĂŁo os fundadores do California Coffee decidiram trazer a ideia do Specialty Coffee House para o Brasil. Hoje, oferecemos somente a melhor classe de cafĂ© arĂĄbica, cultivado em grandes altitudes, tornando o crescimento mais lento e um sabor mais refinado. Temos nossa prĂłpria torrefaĂ§ĂŁo, onde torramos nosso cafĂ© diariamente seguindo os mais restritos padrĂ”es europeus. Trabalhamos constantemente para aprimorar a qualidade e a consistĂȘncia do nosso cafĂ© para trazer o melhor de cada grĂŁo para vocĂȘ. Nossa missĂŁo: ser uma empresa inovadores, contemporĂąnea com o objetivo de servir o melhor e mais moderno conceito em cafĂ© do Brasil.', NULL, 'RIO DE JANEIRO', 1, NULL, 41, NULL, NULL, '2026-03-08 18:50:58.212', 'https://franquias.portaldofranchising.com.br/franquia-california-coffee/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
