INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74bh004geh0sd8u6sblo', 'IP SCHOOL INGLĂS PARTICULAR', 'ip-school-ingles-particular', NULL, 'EducaĂ§ĂŁo', 'EDUCAĂĂO', 'Aulas de InglĂȘs Particulares e Personalizadas Ă  partir dos 6 anos. Foco no objetivo dos alunos. Metodologia prĂłpria, ensinamos o idioma mais presente no mundo de forma Natural, sem livros.', 2020, 2021, NULL, '2026-04-01 02:00:02.427', '2025-08-05 22:20:24.989', 197, NULL, 1, 2015, 'Com microfranquia homebased e sem material didĂĄtico, IP School revoluciona o ensino de inglĂȘs! Rede dobra de tamanho na pandemia e se mostra pronta para oferecer suporte a franqueados de todo o Brasil Com apenas R$ 33 mil, o investidor pode se tornar franqueado da IPSchool â InglĂȘs Particular, uma escola de ensino de inglĂȘs que dobrou de tamanho na pandemia e traz uma proposta bastante inovadora ao mercado:a de ensinar o idioma apenas em aulas particulares e sem a venda de material didĂĄtico ao aluno.Ă isso mesmo: na IP School, o franqueado nĂŁo se preocupa em cumprir com quotas de compras de livros, que oneram seu faturamento e tambĂ©m fazem com que o aluno tenha o aprendizado engessado. âNossa metodologia Ă© baseada nas necessidades e vivĂȘncias do aluno, o que faz com que as aulas sejam personalizadas. Dessa forma, elas se tornam mais interessantes e focadas no que ele mais precisa, que Ă© falar inglĂȘs, de uma vez por todas!â, diz MĂĄrcio Cafezeiro, sĂłcio-franqueador e coordenador pedagĂłgico da rede. Com o aluno âsoltando a lĂ­nguaâ, vem a fidelizaĂ§ĂŁo e a indicaĂ§ĂŁo de mais alunos. âO microfranqueado pode formar uma rede de professores, que atendem virtualmente ou em empresas. Ele tem um raio de atuaĂ§ĂŁo e sua atividade Ă© bastante comercial, buscando clientes e parcerias. Ele nĂŁo precisa ser fluente no idioma e nem ministrar as aulasâ, diz Rauel Araruna, sĂłcio-franqueador responsĂĄvel pela ExpansĂŁo. A IP School tem 12 unidades, entre prĂłprias e franqueadas, no Estado de SĂŁo Paulo. AlĂ©m da microfranquia, tambĂ©m possui escolas fĂ­sicas â e quem deseja abrir uma delas investe a partir de R$ 149 mil. Nos dois Ășltimos anos, a rede faturou R$ 2 milhĂ”es (por ano), mantendo-se estĂĄvel mesmo na pandemia. âO ano de 2020 foi realmente mais difĂ­cil. Mas, implantamos com rapidez a modalidade virtual e os alunos adoraram. Ă atĂ© difĂ­cil nos lembrarmos de que praticamente nĂŁo tĂ­nhamos aulas virtuais antes da pandemia e que, agora, essa Ă© a modalidade predominante e preferida dos nossos alunosâ, comenta FĂĄbio Ferreira, o mais novo sĂłcio da franqueadora, que cuida da gestĂŁo da rede.Os trĂȘs sĂłcios tĂȘm a meta de chegar a todo o Brasil. O franqueado recebe todo o treinamento comercial, de gestĂŁo da unidade franqueada (seja ela uma microfranquia ou franquia fĂ­sica) e os professores tĂȘm treinamentos constantes sobre a metodologia da marca, que foi criada e Ă© constantemente aperfeiĂ§oada por MĂĄrcio Cafezeiro. âNĂłs nos baseamos na programaĂ§ĂŁo neurolinguĂ­stica para aprimorar o ensino e esse diferencial faz parte da transferĂȘncia de know-how da franqueadora para a rede franqueadaâ, comenta o especialista. O suporte da IP School pode ser oferecido a franqueados de todo o Brasil, atĂ© mesmo de forma remota.', NULL, 'SĂO PAULO', 1, NULL, 14, NULL, NULL, '2025-03-07 15:55:50.000', 'https://franquias.portaldofranchising.com.br/franquia-ip-school-ingles-particular/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74bm004heh0sc38nl0og', 'NTW CONTABILIDADE E GESTĂO EMPRESARIAL', 'ntw-contabilidade-e-gestao-empresarial', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Especialista em Contabilidade Consultiva e GestĂŁo Empresarial, a NTW Ă© perfeita para quem quer empreender ou fazer a conversĂŁo de seu escritĂłrio, Seja parte da maior e mais premiada rede ContĂĄbil', 2010, 2011, '[\"https://www.youtube.com/watch?v=vQeUplMTmSE\",\"https://www.youtube.com/watch?v=m_au9NC9Qxw\"]', '2026-04-01 02:00:02.438', '2025-08-05 22:20:24.994', 198, NULL, 1, 1989, 'Em 2015, 2016, 2017, 2018, 2019, 2020, 2022, 2023 e 2024, a NTW Franquia ContĂĄbil foi chancelada com o Selo de ExcelĂȘncia em Franchising pela ABF (AssociaĂ§ĂŁo Brasileira de Franchising), sendo a Ășnica franquia contĂĄbil a receber este Selo Internacional por 5 anos consecutivos. Em 2015, 2016, 2017, 2018, 2019, 2020, 2021, 2022, 2023 e 2024 a NTW Franquia ContĂĄbil conquistou o prĂȘmio Melhores Franquias do Brasil pela revista Pequenas Empresas & Grandes NegĂłcios. Â  Somos a maior e mais premiada rede de escritĂłrios contĂĄbeis da AmĂ©rica Latina Â  Com mais de 35 anos de atuaĂ§ĂŁo, a NTW Ă© a maior e mais premiada rede de escritĂłrios contĂĄbeis da AmĂ©rica Latina. Possuindo mais de 270 unidades no Brasil, Portugal e MoĂ§ambique, a empresa tambĂ©m tem presenĂ§a nos Emirados Ărabes, alĂ©m de jĂĄ ter atendido mais de 22 mil clientes. Especialista em contabilidade consultiva e gestĂŁo empresarial, nossa experiĂȘncia e presenĂ§a internacional nos permitem oferecer soluĂ§Ă”es precisas e resultados consistentes. Â  Contamos com uma rede de parceiros estratĂ©gicos para enriquecer nossas soluĂ§Ă”es e garantir a excelĂȘncia em cada serviĂ§o prestado. E com o objetivo de fazer negĂłcios e estabelecer conexĂ”es empresariais lucrativas, temos o ConexĂŁo NTW, o IntercĂąmbio de NegĂłcios da NTW em que disponibilizamos a oportunidade de contadores franqueados e seus clientes conhecerem o mundo.Â  Â  NTW Prime Â  A NTW Prime Ă© um clube de vantagem das unidades referĂȘncias da NTW Franquia ContĂĄbil. Reconhecidos pelos prĂłprios clientes pela excelĂȘncia em serviĂ§os contĂĄbeis, os escritĂłrios NTW Prime mantĂ©m um alto padrĂŁo na qualidade dos serviĂ§os e satisfaĂ§ĂŁo do cliente. Â  NTW Doctor Â  A NTW Doctor, a nossa franquia especializada para o setor da saĂșde, oferece soluĂ§Ă”es contĂĄbeis totalmente dedicadas para atender as necessidades de clĂ­nicas, consultĂłrios mĂ©dicos e profissionais da ĂĄrea. Com estratĂ©gias personalizadas para o pĂșblico alvo, capacitamos contadores em um dos ramos que mais cresce no Brasil.Â  Â  Se vocĂȘ Ă© contador ou possui um sĂłcio contador e deseja se especializar nesta ĂĄrea, a NTW Doctor Ă© a oportunidade perfeita. Aqui, vocĂȘ encontrarĂĄ treinamento por unidade para se especializar no setor da saĂșde, participando de um modelo colaborativo com excelentes oportunidades de negĂłcios. Â  NTW Agro Â  A NTW Agro Ă© a nossa franquia contĂĄbil especializada em atender o agronegĂłcio, um setor em constante crescimento no Brasil. Com possibilidades de lucro e expansĂŁo, a NTW Agro oferece soluĂ§Ă”es contĂĄbeis altamente especializadas para produtores rurais, empresas do setor e demais profissionais da ĂĄrea, garantindo um atendimento excepcional Ă s demandas exclusivas do agronegĂłcio. Â  Contando com todo o suporte da maior e mais premiada rede de escritĂłrios contĂĄbeis da AmĂ©rica Latina, a NTW Agro Ă© ideal para contadores ou sĂłcios de contadores que desejam se especializar neste setor vital da economia brasileira. Com nosso treinamento e estratĂ©gias personalizadas, vocĂȘ pode se tornar uma referĂȘncia em contabilidade para o agronegĂłcio na sua cidade. Â  Â  ConheĂ§a nossas Modalidades e Franquias Segmentadas Â  A NTW Ă© uma rede de franquia para vocĂȘ, contador que desejar investir no seu primeiro escritĂłrio contĂĄbil ou para vocĂȘ que jĂĄ possui o seu escritĂłrio e deseja fazer a conversĂŁo da sua marca. Nossos modelos de negĂłcio sĂŁo:Â  Â  Start: Para cidades de atĂ© 30 mil habitantes, a Start Ă© a opĂ§ĂŁo perfeita para quem deseja ter o seu primeiro negĂłcio contĂĄbil. Modalidade em que o franqueado irĂĄ implantar uma unidade home office ou em coworking, sendo toda a operaĂ§ĂŁo processada pela franqueada ou por fornecedor homologado, por ela indicado. Â Â  Light: Modalidade ideal Ă© para vocĂȘ que jĂĄ Ă© empreendedor ou deseja empreender com baixo custo de investimento em cidades com atĂ© 30 mil habitantes, podendo investir do zero ou fazendo a conversĂŁo da sua marca. A unidade pode ser implantada em home office, coworking ou fĂ­sica. Â  Express: Modalidade desenvolvida para quem deseja empreender com baixo custo de investimento em cidades acima de 30 mil habitantes. A unidade pode ser implantada em home office ou coworking.Â  Â  Select: Nossa modalidade Select Ă© para vocĂȘ que jĂĄ Ă© empreendedor ou deseja empreender em uma cidade acima de 30 mil habitantes. VocĂȘ pode implantar uma unidade fĂ­sica ou converter a sua marca com todas as vantagens que sĂł a NTW tem. Â  NTW Doctor e NTW Agro: Nossas franquias especializadas no setor da saĂșde e do agronegĂłcio Ă© para vocĂȘ que deseja se tornar um contador especializado nos setores que mais crescem no paĂ­s. Com o nosso apoio, uma variedade de serviĂ§os contĂĄbeis e um software especializado, garantimos um treinamento que irĂĄ te capacitar e destacar no mercado atual. A unidade pode ser implantada em formato fĂ­sico, coworking ou home. Â  Na rede NTW, 98,6%* dos franqueados da NTW abririam esta franquia novamente e 99,1%* indicariam para amigos e familiares que buscam um novo negĂłcio. Â  MĂĄrcio Torezzi: âSou apaixonado pela rede NTW. Sou um entusiasta dessa empresa. Temos treinamento de vendas, lideranĂ§a e convenĂ§Ă”es, alĂ©m dos sistemas que nos ajudam no controle de processos e atividades. Eu sou suspeito de falar, jĂĄ que tenho 4 unidades da NTW Contabilidade e 1 unidade da Tutoreanos Consultores de NegĂłcios (Franquia do Grupo NTW). Tenho muita satisfaĂ§ĂŁo com minha escolha e, principalmente, o retorno financeiro desejado.â MĂĄrcio Torezzi â NTW Prime Pirassununga / NTW Prime SĂŁo Carlos / NTW SĂŁo Carlos Centro / NTW Prime RibeirĂŁo Preto / Tutoreanos SĂŁo Carlos Â  Alzieth Vilhena: âMontei meu escritĂłrio iniciando do zero e hoje tenho uma estrutura impecĂĄvel! Posso afirmar que a expansĂŁo da unidade acontece com muita animaĂ§ĂŁo e cuidado. Conquistei clientes importantes na minha regiĂŁo e em vĂĄrios estados do paĂ­s com muito orgulho. Meu escritĂłrio nĂŁo para de crescer!â Alzieth Vilhena â NTW Prime BelĂ©m Metropolitan Tower Â  Alexandre Castro: âEu jĂĄ estava estudando o mercado de franquias contĂĄbeis hĂĄ muito tempo porque sentia a necessidade de expandir meu negĂłcio. TambĂ©m queria estruturar melhor os trĂȘs pilares que movem meu escritĂłrio: pessoas, processos e ferramentas. E foi aĂ­ que eu encontrei a NTW! Fiquei encantado com o modelo de negĂłcio e as melhorias contĂ­nuas, sempre pensando em como atender melhor seus clientes. Hoje, possuo 2 unidades NTW Contabilidade.âÂ  Alexandre Castro â NTW Prime TeresĂłpolis / NTW Juiz de Fora Santa Helena', NULL, 'MINAS GERAIS', 1, NULL, 201, NULL, NULL, '2026-03-08 18:52:37.674', 'https://franquias.portaldofranchising.com.br/franquia-ntw-contabilidade-e-gestao-empresarial/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
