INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74cd004meh0s2p9x4jbj', 'SHEKINĂ BURGER & AĂAĂ', 'shekina-burger-acai', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO RĂPIDO', 'Consiste em hamburguerias especializadas na comercializaĂ§ĂŁo de hambĂșrgueres artesanais, disponibilizando aos clientes um cardĂĄpio amplo e ainda uma ampla variedade em aĂ§aĂ­s.', 2021, 2022, NULL, '2026-04-01 02:00:02.486', '2025-08-05 22:20:25.021', 203, NULL, 1, 1990, 'A histĂłria da empresa ShekinĂĄ Burger & AĂ§aĂ­ comeĂ§ou em 2017, quando o sĂłcio proprietĂĄrio, jĂĄ inserido no ramo de restaurantes desde sua infĂąncia, quando chegou a uma cidade Chamada Guer na SuĂ­Ă§a, onde conheceu a fabricaĂ§ĂŁo do queijo Camembert, o qual ficou impressionado pelo sabor e qualidade, foi entĂŁo que partiu para o ramo de hamburguerias, para que pudesse criar seu primeiro lanche que seria com o queijo camembert, o qual fora criado no mesmo ano de 2017, denominado âcheeseâ. Inspirada no cenĂĄrio histĂłrico das cozinhas em que fora familiarizado desde pequeno e tambĂ©m pela cozinha europeia, trouxe para a regiĂŁo de AraĂ§atuba e Birigui SP, uma releitura singular desses dois Ă­cones gastronĂŽmicos. A vontade de inovar nĂŁo parou por aĂ­. Logo decidiu inovar na diversificaĂ§ĂŁo de lanches e na produĂ§ĂŁo prĂłpria do hamburguer, molhos e temperos em suas lojas, e ainda realizou a junĂ§ĂŁo da comercializaĂ§ĂŁo de aĂ§aĂ­ nas hamburguerias. AtĂ© agora, jĂĄ percorremos um caminho de inovaĂ§ĂŁo e bom atendimento protagonizados por um delicioso e Ășnico sabor. Ă assim que conquistamos muitos clientes no interior de SĂŁo Paulo e regiĂŁo, contando com lojas em shoppings e no centro da cidade. Esperamos espalhar por todo Brasil, para que todos possam experimentar esse sabor inigualĂĄvel, nĂŁo apenas na regiĂŁo da sede mas em todo Brasil.', NULL, 'SĂO PAULO', 1, NULL, 6, NULL, NULL, '2025-03-06 18:00:28.000', 'https://franquias.portaldofranchising.com.br/franquia-shekina-burger-acai/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
