INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74cu004peh0slkzkxq88', 'IE INTERCĂMBIO NO EXTERIOR', 'ie-intercambio-no-exterior', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'IntercĂąmbio no Exterior, Especialista em EducaĂ§ĂŁo Internacional e Carreira, Cursos de idiomas, Ensino MĂ©dio e Superior. Oportunidades em diversos paĂ­ses para idade entre 10 a 60 anos.', 2005, 2010, '[\"https://www.youtube.com/watch?v=668Ip-gwcjs\",\"https://www.youtube.com/watch?v=E1ZpLB9oJPI\"]', '2026-04-01 02:00:02.516', '2025-08-05 22:20:25.039', 206, NULL, 1, 1998, 'Desde 1998, a IE IntercĂąmbio orienta estudantes e profissionais na realizaĂ§ĂŁo de intercĂąmbios pelo mundo. Com franquias espalhadas de norte a sul do Brasil e tambĂ©m no exterior, a IE Ă© uma das mais tradicionais e premiadas agĂȘncias do segmento. Com um modelo de negĂłcios simplificado, durante a nossa histĂłria aprendemos como oferecer diversos recursos de tecnologia, ferramentas de capacitaĂ§ĂŁo, alĂ©m de encontros e aĂ§Ă”es que permitem uma gestĂŁo participativa do franqueado, tornando-os especialistas em educaĂ§ĂŁo internacional e donos do seu prĂłprio negĂłcio. Â A IE se preocupa muito com a satisfaĂ§ĂŁo de seus colaboradores, monitoramos atravĂ©s de pesquisas internas e externas os indicadores de performance e satisfaĂ§ĂŁo de cada Franqueado. Como em qualquer negĂłcio, o franqueado IE terĂĄ que trabalhar duro e superar muitos desafios para conquistar o sucesso. Por isso sabemos da importĂąncia de prestar um suporte profissional e sempre bem prĂłximo ao franqueado.', NULL, 'SĂO PAULO', 1, NULL, 31, NULL, NULL, '2026-03-08 18:57:16.181', 'https://franquias.portaldofranchising.com.br/franquia-ie-intercambio-no-exterior-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '22000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
