INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74d6004reh0seq294euy', 'CCAA', 'ccaa', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'ENSINO DE INGLĂS E ESPANHOL', 1969, 1989, '[\"https://www.youtube.com/watch?v=VkINBY6jc2U\"]', '2026-04-01 02:00:02.536', '2025-08-05 22:20:25.050', 208, NULL, 1, 1961, 'Desde 1961, nossa metodologia exclusiva e nosso material didĂĄtico prĂłprio transformam vidas com a proficiĂȘncia dos idiomas InglĂȘs / Espanhol. \nCom educaĂ§ĂŁo, as pessoas podem fazer mais escolhas sobre suas vidas. A capacitaĂ§ĂŁo, a valorizaĂ§ĂŁo dos professores, o estĂ­mulo ao protagonismo dos alunos e a inserĂ§ĂŁo tecnolĂłgica transformaram o CCAA numa escola de alto padrĂŁo de qualidade. Essa informaĂ§ĂŁo Ă© corroborada por meio de depoimentos de alunos e ex-alunos, alĂ©m dos resultados por eles obtidos, como uma das melhores colocaĂ§Ă”es do Brasil no exame TOEFL ITPÂź, que estĂĄ entre as principais certificaĂ§Ă”es internacionais da lĂ­ngua inglesa. \nAlĂ©m das franquias espalhadas por todo o paĂ­s e no exterior, o CCAA tambĂ©m estĂĄ presente nas aulas de idiomas de escolas e colĂ©gios de todo o Brasil, que tĂȘm a oportunidade de oferecer aos seus alunos a excelĂȘncia do mĂ©todo de ensino CCAA.Â  Nas franquias as aulas sĂŁo hĂ­bridas, com turmas online ao vivo e presencial. \nDessa forma, os alunos tĂȘm flexibilidade e liberdade para decidir, a cada dia, onde querem aprender inglĂȘs e espanhol: em uma unidade ou em qualquer outro lugar.Â  E foi assim, a partir do sonho apaixonado do Sr. Waldyr Lima, que teve inĂ­cio a jornada desta marca. Uma marca em que a histĂłria das pessoas se mistura Ă  histĂłria das suas vidas.\nÂ    Mais do que motivos, temos motivaĂ§Ă”es. Veja como apoiamos nossos franqueados:  Depoimentos de franqueados \nÂ   Â  Abrir uma franquia CCAA significa tornar-se parceiro de uma empresa forte, unir-se a uma marca consolidada e ter, desde o inĂ­cio do negĂłcio, todo suporte, orientaĂ§ĂŁo e ferramentas necessĂĄrias para ter uma franquia e um empreendimento bem-sucedido.Â  Venha fazer parte dessa trajetĂłria de sucesso!', NULL, 'RIO DE JANEIRO', 1, NULL, 650, NULL, NULL, '2026-03-08 18:58:25.163', 'https://franquias.portaldofranchising.com.br/franquia-ccaa-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
