INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ec004zeh0s9tshub3t', 'CONTAINER SEGURANĂA', 'container-seguranca', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'LocaĂ§ĂŁo de Containers, MĂłdulos HabitĂĄveis e Equipamentos para Obras. Sistema Inovador e EconĂŽmico e Banheiros EcolĂłgicos.', 2012, 2020, '[\"https://www.youtube.com/watch?v=aHArQkQ-WeY\"]', '2026-04-01 02:00:02.617', '2025-08-05 22:20:25.093', 216, NULL, 1, 2009, 'Venha fazer parte da Maior Rede de Franquias de LocaĂ§ĂŁo de Containers do Brasil! Presente em mais 1000 cidades A Container SeguranĂ§a revolucionou o segmento, criando uma soluĂ§ĂŁo de armazenamento mĂłvel, simples, barata, segura e ĂĄgil que Ă© utilizado por equipes em obras, em todo o Brasil, para acondicionar os materiais e ferramentas ou por qualquer pessoa que deseja guardar algo de valor em um cofre de aĂ§o (Container). Foi reconhecida como a melhor franquia pela âPequenas Empresas & Grandes NegĂłciosâ, por sua qualidade e responsabilidade, sendo destaque do programa de TV da Rede Globo de TelevisĂŁo, alĂ©m da participaĂ§ĂŁo em diversas mĂ­dias, como âExameâ, âUolâ, âEstadĂŁoâ eÂ âO Globoâ. Com unidades atendendo mais de 1.000 cidades do Brasil, Ă© associada ABF (AssociaĂ§ĂŁo Brasileira de Franchising) e destaque entre as franqueadoras de serviĂ§os em geral,Â tornando-se a maior franquia desse segmento hĂĄ anos. Mais do que uma franquia,Â a Container SeguranĂ§a busca constantemente a inovaĂ§ĂŁo para trazer mais praticidade e conforto para as obras, atravĂ©s de produtos ecologicamente corretos e investimentos em tecnologia.  Vantagens de ser um franqueado Marca consolidada ExperiĂȘncia no segmento de locaĂ§ĂŁo de CONTAINERS Fornecedores homologados Treinamento e suporte Marketing e publicidade Modelo de NegĂłcio testado e aprovado PadronizaĂ§ĂŁo e reconhecimento Maior poder de negociaĂ§ĂŁo Troca de conhecimento Ăndice de sucesso muito maior AuxĂ­lio de uma equipe experiente Apoio na gestĂŁo do negĂłcio Apoio nos aspectos jurĂ­dicos AuxĂ­lio no planejamento financeiro Estamos com condiĂ§Ă”es especiais para novas unidades. A hora Ă© agora!', NULL, 'SĂO PAULO', 1, NULL, 35, NULL, NULL, '2026-03-08 19:02:10.481', 'https://franquias.portaldofranchising.com.br/franquia-container-seguranca/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74eh0050eh0sl86xih77', 'SHOPPING DA VISĂO', 'shopping-da-visao', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'Comercio varejista de artigos Ăłpticos', 2019, 2023, NULL, '2026-04-01 02:00:02.627', '2025-08-05 22:20:25.098', 217, NULL, 1, 2019, '', NULL, 'PERNAMBUCO', 1, NULL, NULL, NULL, NULL, '2026-03-08 19:03:05.258', 'https://franquias.portaldofranchising.com.br/franquia-shopping-da-visao-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74em0051eh0sw5cgtr1k', 'SENSE BIKE', 'sense-bike', NULL, 'SaĂșde, Beleza e Bem Estar', 'ESPORTE E RECREAĂĂO', 'A Rede S2 Bike Shop Ă© a mais COMPLETA rede de comercializaĂ§ĂŁo de Bicicletas, AcessĂłrios e ServiĂ§os do Brasil: SĂŁo 26 operaĂ§Ă”es em 36 meses de expansĂŁo, com unidades em 7 estados mais o DF.', 2020, 2023, NULL, '2026-04-01 02:00:02.636', '2025-08-05 22:20:25.103', 218, NULL, 1, 2019, 'PaixĂŁo Ă© a palavra que nos define. Antes mesmo de sermos uma empresa com foco em lucros, nĂłsÂ somos apaixonados por bikes, pelo que fazemos e principalmente em causar boas sensaĂ§Ă”es. Nascemos em 2009, inicialmente apenas como fĂĄbrica e comĂ©rcio atacadista de bicicletas, como braĂ§o da LAGOA PARTICIPAĂĂES, com o objetivo de atender as demandas voltadas para a mobilidade urbana e, desde entĂŁo nos tornamos referĂȘncia no mercado pelos projetos elĂ©tricos pouco explorados por marcas nacionais. Em 2012 lanĂ§amos nossos trĂȘs primeiros modelos: EASY, BREEZE e WIND, com a tecnologia de pedal assistido, bateria de lĂ­tio e 24v, que logo tomaram as ruas. Fomos tĂŁo inspiradores que em novembro de 2013, nossas bikes serviram de modelo para o Conselho Nacional de TrĂąnsito (CONTRAN), regulamentar a utilizaĂ§ĂŁo das bicicletas elĂ©tricas atravĂ©s da resoluĂ§ĂŁo 465. ExperiĂȘncia? Temos de sobra! Com mais de 40 anos de atuaĂ§ĂŁo no ramo das 2 rodas, possuĂ­mos estrutura prĂłpria que conta com os processos de: criaĂ§ĂŁo, importaĂ§ĂŁo, estoque, distribuiĂ§ĂŁo pĂłs-venda e comercial. Em 2014 fomos alĂ©m. Inauguramos nossa fĂĄbrica prĂłpria com grande apelo ecolĂłgico em gestĂŁo de resĂ­duos, e com maquinĂĄrios de ponta passamos a fabricar nossos quadros e criamos uma linha de montagem moderna para bikes elĂ©tricas e convencionais na cidade de Manaus/AM. JĂĄ em 2015 firmamos parceria com a Swift Carbon empresa Sul-Africana com grande know-how na confecĂ§ĂŁo de quadros de carbono e passamos a vislumbrar uma linha de bikes de alta performance que poderia elevar a SENSE a outro patamar no segmento. 2(dois) anos mais tarde entendemos que terĂ­amos que concentrar esforĂ§os e investimentos para chegarmos ao nosso objetivo de sermos a marca de bikes mais relevante noÂ cenĂĄrio nacional e para isso adquirimos nossa parceira Swift Carbon e instalamos uma nova fĂĄbrica em Portugal na cidade do Porto. PĂłs estudar a demanda do mercado, a necessidade da mobilidade urbana, o desejo dos consumidores entendemos que poderĂ­amos com nossa dedicaĂ§ĂŁo e paixĂŁo fazer algo mais.Â  Nasce em 2019 o projeto S2 Bike Shop, um projeto sĂ©rio e rentĂĄvel com design inovador e portfĂłlio 100% das marcas Sense Bike e Swift Carbon com complemento de acessĂłrios das principais marcas do mercado. E atualmente? Atualmente somos 26 operaĂ§Ă”es ativas em 7 estados mais o Distrito Federal e buscamos novos parceiros que assim como nĂłs Ă© apaixonado pelo ciclismo e empreendedorismo. PERFIL DO FRANQUEADO Apaixonado pelo ciclismo; Ter experiĂȘncia comprovada de atuaĂ§ĂŁo no setor de varejo (mĂ­nimo 12 meses); Possuir capacidade de investimento com recursos prĂłprios; Dedicar-se aos negĂłcios da franquia, atuando conforme as regras estabelecidas; Ter aptidĂŁo e desejo de atuar em um modelo de negĂłcio jĂĄ formatado; Comprometimento com administraĂ§ĂŁo da operaĂ§ĂŁo; DedicaĂ§ĂŁo de 8 a 12 horas diĂĄrias para a operaĂ§ĂŁo; Dinamismo, com espĂ­rito empreendedor; Proatividade, que reĂșna capacidade de anĂĄlise e discernimento; Conhecimento do mercado local VANTAGENS E BENEFICIOS Ătimo custo x benefĂ­cio para instalaĂ§ĂŁo; IsenĂ§ĂŁo de royalties e taxa de publicidade nos dois primeiros anos de operaĂ§ĂŁo; Empresa com mais de 40 anos de experiĂȘncia no mercado das 2 rodas; FĂĄbrica prĂłpria com 10mil m2 dedicada Ă  tecnologia para quadros em alumĂ­nio; FabricaĂ§ĂŁo de quadros em carbono by Swift Carbon; Projetos ArquitetĂŽnicos para as lojas; Suporte em marketing, avaliaĂ§ĂŁo de varejo e treinamento especializado; ConvenĂ§Ă”es anuais para lanĂ§amento do Model Year; Marketing nacional, com investimentos em revistas, influenciadores, eventos prĂłprios com chancela CBC e equipes de nĂ­veis nacional e internacional SUPORTE QUE OFERECEMOS Estudo de viabilidade do negĂłcio; Apoio na busca do ponto comercial; Acompanhamento prĂ© e pĂłs inauguraĂ§ĂŁo; Equipe capacitada para suporte focada em resultados; Projeto arquitetĂŽnico; Sistema de controle operacional PROCESSO DE IMPLANTAĂĂO Preenchimento de cadastro prĂ©-qualificaĂ§ĂŁo enviado pelo departamento de franquias; Visita ao QG da empresa; Entrevista com departamento de franquias/expansĂŁo; Assinatura da circular de oferta de franquia (COF); Assinatura do contrato de franquia; Processo de seleĂ§ĂŁo do ponto comercial; AprovaĂ§ĂŁo do ponto comercial; Planejamento para inauguraĂ§ĂŁo (projetos, layout, obra e adaptaĂ§Ă”es); Treinamento inicial do franqueado e equipe; InauguraĂ§ĂŁo da loja; Acompanhamento pĂłs-inaugural, atravĂ©s de consultoria de campo e apoio operacional periĂłdico.', NULL, 'SĂO PAULO', 1, NULL, 26, NULL, NULL, '2026-03-08 19:03:28.568', 'https://franquias.portaldofranchising.com.br/franquia-sense-bike/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74es0052eh0sh6fijelr', 'PATRONI PIZZA', 'patroni-pizza', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Pizzaria (Forno a Lenha) Trattoria (Carnes e Massas) Chopperia (Petiscos e Chopp)', 2003, 1989, '[\"https://www.youtube.com/watch?v=UrHLd3o7pnM\"]', '2026-04-01 02:00:02.645', '2025-08-05 22:20:25.108', 219, NULL, 1, 1984, 'Uma franquia diferente \nApĂłs quase 20 anos de sucesso, a Patroni Pizza formatou seu prĂłprio modelo de franquia e em 2003, abriu sua operaĂ§ĂŁo de franchising, atendendo a uma forte demanda do mercado. Para fazer um modelo de franquia que levasse a marca da Patroni vĂĄrios detalhes foram analisados. O compromisso com o consumidor, por exemplo, deve se estender a todas as franquias, de forma que a qualidade dos produtos e a excelĂȘncia do atendimento sejam similares ao das lojas prĂłprias. Para suprir esta necessidade, nosso modelo inclui treinamento e apoio para franqueadores e suas equipes. Com estes e outros cuidados, em poucos anos nos tornamos referĂȘncia em franquia no ramo de alimentaĂ§ĂŁo.  Bons negĂłcios para todos \nNossa tradiĂ§ĂŁo no ramo de pizzarias unida a um projeto de franquia customizado faz toda a diferenĂ§a para nossos franqueados. Enquanto o mercado registra um crescimento anual mĂ©dio de 14% em faturamento, a Patroni Pizza tem um crescimento de 210%. Todas as etapas de negĂłcio jĂĄ foram e continuam sendo testadas e otimizadas pelo franqueador. Os franqueados nĂŁo trabalham em um processo de tentativa e erro, pois contam com metodologia, filosofia de negĂłcios, sistemas e apoio que dĂŁo seguranĂ§a ao desenvolvimento de seus restaurantes. Outro ponto positivo para o sucesso Ă© a percepĂ§ĂŁo de qualidade e preĂ§o justo que os clientes tĂȘm em relaĂ§ĂŁo Ă  Patroni Pizza. Em comparaĂ§ĂŁo com o mercado a Patroni Pizza tem o menor investimento mĂ©dio de capital, o menor prazo mĂ©dio de retorno, a menor cobranĂ§a de taxas e a maior rentabilidade mĂ©dia de investimento. Com certeza um bom negĂłcio para quem estĂĄ pensando em trabalhar no ramo da alimentaĂ§ĂŁo.  Os grandes diferenciais da franquia Patroni Pizza  Uso da Marca - a Patroni Pizza cede sua marca para ser explorada pelo franqueado em seu territĂłrio, conforme nossas normas e padrĂ”es.  Apoio na seleĂ§ĂŁo de pontos comerciais - considerando as caracterĂ­sticas consideradas ideais para o local de uma unidade Patroni, orientamos o potencial franqueado na procura de pontos comerciais.  Financiamento bancĂĄrio - podemos auxiliar cada franqueado na elaboraĂ§ĂŁo de projeto para encaminhamento e anĂĄlise de financiamento bancĂĄrio com condiĂ§Ă”es especiais e competitivas, dependendo Ășnica e exclusivamente da aprovaĂ§ĂŁo do crĂ©dito, por parte do banco.  Montagem da loja - vocĂȘ pode escolher entre ter nossa assessoria junto aos profissionais de arquitetura que cuidarĂŁo do desenvolvimento do projeto e execuĂ§ĂŁo de obra.  Treinamento ao franqueado e Ă  sua equipe - a unidade piloto Patroni Pizza serve de centro de treinamento do franqueado e sua equipe, trabalhando com todos os produtos, serviĂ§os e equipamentos que serĂŁo oferecidos na franquia.  Pesquisa e desenvolvimento de novos produtos, equipamentos e serviĂ§os - este Ă© um trabalho permanente, que garante a qualidade da Patroni Pizza.  Apoio operacional no inĂ­cio de operaĂ§ĂŁo da franquia - disponibilizamos funcionĂĄrios para acompanhar os primeiros dias de operaĂ§ĂŁo da nova franquia in loco.  SupervisĂŁo de campo constante e planejada - temos uma equipe de consultores de campo que garante o relacionamento aberto e contĂ­nuo entre franqueador e franqueados. Os consultores resolvem problemas e orientam profissionalmente o franqueado na busca do sucesso, alĂ©m de promover treinamentos locais em cada franquia. \nAcompanhamento de desempenho - o termo Ă© feed-back. Em funĂ§ĂŁo de relatĂłrios periĂłdicos dos franqueados, acompanhamos o desempenho de cada unidade.', NULL, 'SĂO PAULO', 1, NULL, 101, NULL, NULL, '2026-03-08 19:05:46.839', 'https://franquias.portaldofranchising.com.br/franquia-patroni-pizza-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ey0053eh0s2e10pior', 'BEM COSMĂTICOS', 'bem-cosmeticos', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Loja especializada de cosmĂ©ticos multimarcas', 2023, 2024, NULL, '2026-04-01 02:00:02.655', '2025-08-05 22:20:25.114', 220, NULL, 1, 2023, '', NULL, 'GOIĂS', 1, NULL, 11, NULL, NULL, '2026-03-08 19:07:38.008', 'https://franquias.portaldofranchising.com.br/franquia-bem-cosmeticos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '330000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74f30054eh0s8sxppdj1', 'SETH', 'seth', NULL, 'Moda', 'ACESSĂRIOS PESSOAIS', 'A Seth Ă© uma marca de joias reconhecida pelo design sofisticado e ousado. Uma joia feita com primor, rica em detalhes e alto padrĂŁo de acabamento. A Seth Ă© Design e inovaĂ§ĂŁo com Bossa Brasileira!', 2024, 2024, NULL, '2026-04-01 02:00:02.664', '2025-08-05 22:20:25.119', 221, NULL, 1, 2012, '', NULL, 'MINAS GERAIS', 1, NULL, 11, NULL, NULL, '2025-03-17 15:02:46.000', 'https://franquias.portaldofranchising.com.br/franquia-seth-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74f80055eh0syajjd8i3', 'SIRĂNE FISH & CHIPS', 'sirene-fish-chips', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O SirĂšne Ă© um lugar onde se alimenta o corpo e a alma com as melhores coisas da vida com o Melhor Fish & Chips & Fun. Uma franquia com fĂĄcil gestĂŁo, equipe enxuta e boas vibraĂ§Ă”es o ano todo.', 2018, 2020, '[\"https://www.youtube.com/watch?v=wwUrpOOCMk8\"]', '2026-04-01 02:00:02.673', '2025-08-05 22:20:25.124', 222, NULL, 1, 2016, 'O SirĂšne nasceu de um jeito meio louco. A ideia inicial era que o espaĂ§o, locado por Afonso Neto, um dos sĂłcios, se tornasse uma livraria. Quando sua mĂŁe, que seria sua sĂłcia no negĂłcio, desistiu da ideia, veio a inspiraĂ§ĂŁo de transformar o espaĂ§o â que fica na Trajano Reis, centro da boemia curitibana â em um bar. Mas nĂŁo era para ser sĂł mais um bar. Tinha que ser diferente. Especial. Afonso havia acabado de voltar de uma viagem Ă  AustrĂĄlia, onde conheceu o fish & chips, iguaria ainda pouco explorada por aqui. Apostar neste sabor diferenciado foi o primeiro acerto do SirĂšne. Afonso entĂŁo uniu forĂ§as com dois amigos, Lucas Muller e Raphael Umbellino. A uniĂŁo nĂŁo foi apenas financeira: eles literalmente colocaram âmĂŁos Ă  obraâ para fazer o bar acontecer. Reformaram todo o imĂłvel, derrubaram paredes, pintaram, lixaram, restauraram... deixaram o ambiente do jeito estiloso e descolado que cativa todo mundo que passa por lĂĄ. Logo, outro amigo â Alexandre Lopes â entrou na onda, para ajudar na administraĂ§ĂŁo do bar. Em janeiro de 2016, era inaugurado o primeiro SirĂšne, e a mistura de culinĂĄria diferenciada, cerveja gelada e o carisma dos jovens sĂłcios â que tambĂ©m atendiam no balcĂŁo â fez o bar cair no gosto do pĂșblico. O SirĂšne comeĂ§ou a crescer, e logo nĂŁo coube mais sĂł na Trajano: outras filiais abriram pela capital paranaense. O sucesso fez clientes tornarem-se potenciais investidores, e âcomo faĂ§o para abrir uma filial do SirĂšne na minha cidade?â tornou-se a pergunta da vez. O inĂ­cio desta expansĂŁo foi planejado com cuidado, e logo um sĂłlido modelo de franquias foi estruturado. Hoje o SirĂšne conta com 8 lojas em 4 estados (PR, SC, SP e MG). Formou-se uma grande famĂ­lia de pessoas que vibram na mesma frequĂȘncia, curtem o melhor da vida e estĂŁo sempre atrĂĄs dos melhores rolĂȘs. Se identificou? Quer entrar pra essa famĂ­lia? EntĂŁo chega mais e vamo pra cima!', NULL, 'PARANĂ', 1, NULL, 11, NULL, NULL, '2026-03-08 19:08:11.573', 'https://franquias.portaldofranchising.com.br/franquia-sirene-fish-chips/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fd0056eh0suf3eosjv', 'PHENOM IDIOMAS', 'phenom-idiomas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Franquia de escola de idiomas', 2021, 2022, '[\"https://www.youtube.com/watch?v=MoIVgmTBkm4\"]', '2026-04-01 02:00:02.683', '2025-08-05 22:20:25.130', 223, NULL, 1, 2020, 'A Phenom Ă© uma escola de idiomas com uma metodologia Ășnica e avanĂ§ada. \nAqui nossos franqueados possuem suporte vitalĂ­cio desde o primeiro momento. \nCom a Phenom o investimento toma forma, gera lucros e obtĂ©m resultados surpreendentes. Mesmo em pouco tempo, a Phenom Idiomas jĂĄ traz grandes resultados com unidades vendidas em todas as regiĂ”es do Brasil. Isso acontece tambĂ©m por conta da nossa metodologia Ășnica, onde acreditamos que assim como a sociedade, o idioma evolui de forma incessante. \nNossa metodologia acompanha essas mudanĂ§as e busca estar sempre atualizada.   Â  Metodologia Phenomenal \nO mĂ©todo Phenom Ă© fĂĄcil, possĂ­vel e real. FĂĄcil porque qualquer um consegue aprender. \nPossĂ­vel pois Ă© uma metodologia especificamente criada para nativos da lĂ­ngua portuguesa. \nĂ real porque ensina conteĂșdo do dia a dia, onde o aluno aprende e aplica todo o seu conhecimento na prĂĄtica. AlĂ©m disso, trazemos um diferencial de tudo o que hĂĄ no mercado de idiomas. \nA Phenom conta com um mĂłdulo gamificado, onde o ambiente lĂșdico Ă© trazido para dentro da sala de aula, tornando o aprendizado leve e eficaz.   \nÂ  Franqueados Phenom Idiomas \nAqui acreditamos que uma verdadeira parceria ocorre quando ambos os lados trabalham juntos para o avanĂ§o de um negĂłcio. \nPor isso, o investidor recebe consultoria completa durante toda a implantaĂ§ĂŁo, desde as primeiras escolhas, atĂ© treinamentos de gestĂŁo e confirmaĂ§ĂŁo da data de inauguraĂ§ĂŁo de sua escola. \nAlĂ©m do suporte vitalĂ­cio a todo momento.Â  AlĂ©m disso, a Phenom nĂŁo cobra um centavo sequer de royalties. Ou seja, 100% do valor das mensalidades dos alunos ficam para o franqueado. \nNosso Ășnico vĂ­nculo se dĂĄ por meio do material didĂĄtico.', NULL, 'SANTA CATARINA', 1, NULL, 35, NULL, NULL, '2026-03-08 19:09:17.113', 'https://franquias.portaldofranchising.com.br/franquia-phenom-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fl0057eh0s4nnoak0e', 'CI', 'ci', NULL, 'Hotelaria e Turismo', 'AgĂȘncias de Turismo', 'TURISMO JOVEM E INTERCĂMBIO CULTURAL EDUCACIONAL', 1992, 1991, '[\"https://www.youtube.com/watch?v=9h8EgjvoeqE\",\"https://www.youtube.com/watch?v=h38rGeOLd5Q\",\"https://www.youtube.com/watch?v=a8J008qsRGY\",\"https://www.youtube.com/watch?v=rVDYlFNtbB0\"]', '2026-04-01 02:00:02.693', '2025-08-05 22:20:25.138', 224, NULL, 1, 1988, 'Fundada em 1988, a Franquia CI Ă© a maior empresa de intercĂąmbio e turismo jovem do paĂ­s. \nEm 1992 a empresa passou a trabalhar com o formato de franquia, sendo a primeira do segmento a atuar dessa forma. \nAo longo desses 28 anos, construiu uma forte presenĂ§a com mais de 90 lojas espalhadas por todo o Brasil. \nAtualmente Ă© a maior franqueadora do segmento e conta com vĂĄrias filiaĂ§Ă”es, prĂȘmios e reconhecimento internacional. A CI JĂĄ foi premiada sete vezes com o Selo de ExcelĂȘncia em Franchising pela ABF, alĂ©m de ser reconhecida como melhor operadora de cursos no Exterior pela Revista Viagem e Turismo. \nA empresa tem interesse em fortalecer a sua presenĂ§a nacional, expandindo o nĂșmero de unidades por todo o Brasil. \nPossuĂ­mos o modelo de lojaÂ  ideal para cada mercado.', NULL, 'SĂO PAULO', 1, NULL, 88, NULL, NULL, '2026-03-08 19:10:25.778', 'https://franquias.portaldofranchising.com.br/franquia-ci-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '18000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74fs0058eh0s4tloq3j8', 'ROVAL PET - MANIPULAĂĂO VETERINĂRIA', 'roval-pet-manipulacao-veterinaria', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'FarmĂĄcia de ManipulaĂ§ĂŁo exclusivamente veterinĂĄria', 2013, 2015, '[\"https://www.youtube.com/watch?v=Fj0Mu-QrNfs\",\"https://www.youtube.com/watch?v=8Xkjncmwdh8\",\"https://www.youtube.com/watch?v=CXhRN8n7JkU\",\"https://www.youtube.com/watch?v=Xbic1gRxb_U\"]', '2026-04-01 02:00:02.702', '2025-08-05 22:20:25.145', 225, NULL, 1, 1988, 'A FARMĂCIA ROVAL DE MANIPULAĂĂO foi fundada em 1988, no Recife, com a proposta de âmanipular medicamentos para todas as especialidades mĂ©dicasâ e com o firme propĂłsito de criar o intercĂąmbio MĂ©dico-FarmacĂȘutico, tĂŁo importantes para a melhoria da qualidade do tratamento dispensado ao cliente. Em 2010, optou-se por expandir o negĂłcio, atravĂ©s da ROVAL FRANCHISING LTDA e da criaĂ§ĂŁo de um sistema Ășnico de franquia que refletisse a sua expertise no segmento, a credibilidade da sua marca e a sua bem-sucedida atuaĂ§ĂŁo, nos moldes da Lei 13966/19; e tambĂ©m se associou Ă  ABF â AssociaĂ§ĂŁo Brasileira de Franquias, de quem recebeu um selo de excelĂȘncia apĂłs pesquisa junto aos seus franqueados, e atualmente conta com diversas unidades prĂłprias e franqueadas. Ao longo de todos estes anos, A ROVAL PET - FARMĂCIA DE MANIPULAĂĂO VETERINĂRIA tem aprimorado a sua vocaĂ§ĂŁo de prestadora de serviĂ§os de saĂșde e tem participado ativamente da vida das comunidades onde atua, contribuindo com a melhoria da qualidade de vida nestas comunidades. A ROVAL PET - FARMĂCIA DE MANIPULAĂĂO VETERINĂRIA acredita que por trĂĄs da atividade mercantilista de vender o medicamento, estĂĄ o serviĂ§o prestado ao cliente e, sobretudo, a missĂŁo de manipular medicamentos com seguranĂ§a e precisĂŁo. Posturas como estas tĂȘm garantido Ă  ROVAL PET - FARMĂCIA DE MANIPULAĂĂO VETERINĂRIA o respaldo de farmĂĄcia sĂ©ria, comprometida com a saĂșde e o bem-estar das pessoas. NOSSO PROPĂSITO: Transformar a saĂșde e a vida das pessoas e dos animais. Diferenciais: Desenvolvemos formas farmacĂȘuticas diferenciadas que auxiliam a adesĂŁo dos pets ao tratamento dos pacientes com necessidades especiais: biscoitos terapĂȘuticos, pasta oral terapĂȘutica , xarope saborizado, gel transdĂ©rmico, cĂĄpsulas, shampoo, queijinho, sachĂȘs, wipes, cremes, loĂ§Ă”es, soluĂ§ĂŁo otolĂłgica, flavorizaĂ§ĂŁo. Excipientes exclusivamente veterinĂĄrios (p.ex.: isentos de lactose) Rigoroso critĂ©rio de qualidade, atendendo Ă s normas exigidas pelo MinistĂ©rio da Agricultura. MatĂ©rias-primas exclusivas selecionadas para cada necessidade. Palatabilizantes preferidos dos animais para cachorros, gatos, cavalos e animais silvestres. E mais: AuxĂ­lio na escolha e definiĂ§ĂŁo do ponto comercial; Projetos arquitetĂŽnicos/executivos; Treinamento ao franqueado e equipe; Suporte e acompanhamento durante implantaĂ§ĂŁo; InauguraĂ§ĂŁo e operaĂ§ĂŁo do pdv; Equipe de mkt para suprir as demandas da rede; Consultoria de campo; Programa de gestĂŁo ao franqueados/gerentes manuais de gestĂŁo/identidade visual/operaĂ§ĂŁo/RH; Guia veterinĂĄrio magistral; Compra coletiva; Linha de produtos Roval PET exclusiva AnĂĄlise, acompanhamento e suporte da operaĂ§ĂŁo da franquia sob um sistema em que utiliza boas prĂĄticas da governanĂ§a corporativa Apoio em eventos e parcerias', NULL, 'PERNAMBUCO', 1, NULL, 4, NULL, NULL, '2026-03-08 19:11:09.229', 'https://franquias.portaldofranchising.com.br/franquia-roval-pet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74g10059eh0sbzne3t2o', 'MOLDURA MINUTO', 'moldura-minuto', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Somos a Ășnica e maior rede de franquia de emolduramento de luxo do paĂ­s e lĂ­der no segmento, alĂ©m de galeria com foco na valorizaĂ§ĂŁo da arte, temos mais de 25 anos de histĂłria', 2000, 1990, '[\"https://www.youtube.com/watch?v=Oq9Igu7oJ4E\",\"https://www.youtube.com/watch?v=MrlHbxjns6k\",\"https://www.youtube.com/watch?v=qRRMf00jSQM\",\"https://www.youtube.com/watch?v=ftdq1aYVgxY\"]', '2026-04-01 02:00:02.712', '2025-08-05 22:20:25.153', 226, NULL, 1, 1999, 'Venha fazer parte da maior franquia de emolduramento do paĂ­s. Um mercado milionĂĄrio estĂĄ esperando por vocĂȘ! A moldura minuto Ă© uma marca lĂ­der de mercado com uma das maiores margens de lucro no segmento de franquias do brasil. com mais de 2 dĂ©cadas de experiĂȘncia, somos a maior rede de franquias no segmento de emolduramento e decoraĂ§ĂŁo com quadros alto padrĂŁo e um negĂłcio milionĂĄrio para vocĂȘ lucrar! \nSĂŁo mais de 30 mil quadros vendidos por mĂȘs, alĂ©m da marca ter 94% de Ă­ndice de satisfaĂ§ĂŁo dos franqueados, segundo a abf, possuĂ­mos 8 selos de excelĂȘncia em franchising e somos a Ășnica rede com emolduramento personalizado e galeria de artes e fotografias. \nNĂłs oferecemos alta lucratividade, seguranĂ§a, solidez, baixo custo operacional, e uma marca que jĂĄ possui seu nome consolidado no mercado nacional e internacional, com mais de 60 lojas no brasil e mais 3 no exterior: paraguai, uruguai e bolĂ­via. \nNosso propĂłsito Ă© fazer parte da vida e contar a histĂłria de nossos clientes atravĂ©s do emolduramento de fotografias, imagens, artes e mais variados objetos. \nEstamos focados em transmitir seguranĂ§a atravĂ©s da nossa assessoria humanizada e especializada com foco em ajudar o cliente a decorar seu ambiente de forma personalizada, com eficiĂȘncia e comodidade para atender Ă s suas expectativas atravĂ©s da excelĂȘncia no serviĂ§o de emolduramento.Â \nÂ  HISTĂRIA DA MOLDURA MINUTO A Moldura Minuto deu o pontapĂ© para se tornar referĂȘncia no segmento de emolduramento em 1999, quando fundou sua primeira unidade no Shopping ButantĂŁ, em SĂŁo Paulo, no entanto, a proposta de montar uma rede que oferecesse o serviĂ§o de emolduramento rĂĄpido veio muito antes.Â  Antonio Viegas, CEO da Moldura Minuto atuava como odontologista em Portugal quando ao reformar seu consultĂłrio optou pela decoraĂ§ĂŁo com quadros e se espantou com a espera estimada para que os mesmos ficassem prontos. Inspirado nisso, ao voltar para o Brasil, apostou no seu prĂłprio negĂłcio, inaugurando a primeira sede da Moldura Minuto.Â  Com o propĂłsito de emolduramento rĂĄpido em atĂ© uma hora, nasceu a Franquia Moldura Minuto, que hoje conta com mais de 60 unidades espalhadas pelo Brasil e AmĂ©rica Latina.Â  Hoje, a Moldura Minuto estĂĄ posicionada no segmento de decoraĂ§ĂŁo com quadros e oferece aos clientes mais do que apenas quadros emoldurados. \nNĂłs queremos estar inseridos nos momentos mais marcantes da vida de nossos clientes, fazer parte da sua vida e contar a sua histĂłria.Â  E Ă© por isso, que a Moldura Minuto conta com uma equipe treinada e especializada em decoraĂ§ĂŁo com quadros, com atendimento humanizado, alta qualidade e perfeiĂ§ĂŁo nos detalhes e acabamentos.Â  E tudo isso sĂł Ă© possĂ­vel graĂ§as a nossa tecnologia de ponta, know-how focado nos ideias da marca e experiĂȘncia de mais de 20 anos no mercado, que garante um modelo de negĂłcio voltado para o sucesso.Â   Sobre o Mercado \nA Moldura Minuto Ă© uma franquia com uma das maiores margens de lucro do mercado no segmento, que jĂĄ fatura mais de R$ 1,5 bilhĂ”es ao ano com a venda de mais de 30 mil quadros ao mĂȘs, alĂ©m da venda para todo o mercado corporativo, como arquitetos, decoradores e fotĂłgrafos.Â  Um mercado que Ă© altamente lucrativo e com baixĂ­ssima concorrĂȘncia, baixo custo operacional e alta conversĂŁo de vendas no PDV.Â  Â  Quem sĂŁo os clientes Moldura MinutoÂ  Â Gostam de decoraĂ§ĂŁo; Â Gostam de viajar e trazer recordaĂ§Ă”es das viagens; Â Adoram coleĂ§Ă”es e querem expor na decoraĂ§ĂŁo; Â Adoram fotos em famĂ­lia; Â SĂŁo fotĂłgrafos por hobby; Â SĂŁo fotĂłgrafos profissionais; Â Possuem recordaĂ§Ă”es de famĂ­lia e desejam expor como verdadeiras obras de arte; Â SĂŁo apaixonadas por esportes e querem expor medalhas; Â SĂŁo apaixonados por futebol e possuem objetos assinados pelos seus Ă­dolos; Â SĂŁo arquitetos; Â SĂŁo designers de interiores; Â Possuem consultĂłrios mĂ©dicos ou odontolĂłgicos; Possuem escritĂłrios comerciais, hotĂ©is e pousadas; Â  ConheĂ§a as vantagens de ser um franqueado Moldura Minuto\nÂ  O modelo de negĂłcios Moldura Minuto Ă© estruturado para ser compatĂ­vel com centros urbanos e pequenas cidades que tenham mais de 90 mil habitantes.Â  Somos reconhecidos por nossos franqueados com 94% de Ă­ndice de satisfaĂ§ĂŁo e temos 8 selos de excelĂȘncia em franchising pela ABF.Â  Somos uma franquia com:Â  BAIXO CUSTO FIXO\n\tLoja compacta gerando o lucro que vocĂȘ merece, com equipe enxuta e eficaz.\n\tÂ  BAIXO CUSTO OPERACIONAL\n\tSem estoque para o seu dinheiro nĂŁo ficar parado, sem perda de produto com vencimento ou item fora de linha.\n\tÂ  FĂCIL DE OPERAR\n\tCom foco 100% na venda.\n\tÂ  ALTA LUCRATIVIDADE\n\tUma das maiores margens de lucro entre todo o mercado de franquias no brasil! Â  PossuĂ­mos 4 modelos de negĂłcios:\nÂ  Loja de Shopping A Loja de Shopping concentra versatilidade e dinamismo em um ambiente compacto e arrojado. \nEstrategicamente projetada para atender a latente demanda do pĂșblico dos centros de compras. Â    Loja Home Um espaĂ§o aconchegante desenhado para acomodar quadros, decoraĂ§ĂŁo e celebrar o bom gosto de forma a consagrar e aguĂ§ar a percepĂ§ĂŁo sensorial dos consumidores e artistas. Â  Â  \nÂ  Moldura Minuto Smart Ă nosso principal modelo com foco em expansĂŁo atualmente, ideal para vocĂȘ que deseja investir pouco, mas com a garantia de ter um retorno de alta margem de lucro. Â  Â  Â  Â   ContĂȘiner Moldura Minuto Para vocĂȘ que deseja mobilidade, baixo risco de operacional e lucro. Â  Â  Â  Â  Â  Â  Vamos trabalhar com vocĂȘ os 5 pilares do sucesso: PraĂ§a:\nVocĂȘ terĂĄ acesso a um profundo estudo de geomarketing para validar o potencial da sua praĂ§a. Ponto:\nVamos te ajudar na escolha do melhor ponto comercial com o estudo de geolocalizaĂ§ĂŁo. Franqueado:\nVocĂȘ terĂĄ uma formaĂ§ĂŁo completa, para se tornar um excelente gestor da sua operaĂ§ĂŁo e da sua equipe.Â  Equipe:\nSua equipe terĂĄ acesso ao programa Moldura Minuto Loja de ExcelĂȘncia, para entregar mais resultados, se mantendo motivados e engajados.Â  Marca:\nVocĂȘ farĂĄ parte de uma marca forte, com mais de duas dĂ©cadas de experiĂȘncia, reconhecida internacionalmente e que dita tendĂȘncias.Â  \nÂ  Suportes Moldura Minuto:  PrĂ©-abertura \nA Moldura Minuto garante a todos os seus franqueados o suporte prĂ©-abertura, que conta com um plano de negĂłcios estruturado para oferecer toda a assistĂȘncia necessĂĄria: Â  Desenvolvimento de plano de negĂłcio customizado ao mercado alvo Suporte no estudo da viabilidade do ponto comercial Desenvolvimento e acompanhamento do cronograma de implantaĂ§ĂŁo AuxĂ­lio na negociaĂ§ĂŁo dos valores de contrato de locaĂ§ĂŁo Desenvolvimento de projeto arquitetĂŽnico e de marcenaria Desenvolvimento das aĂ§Ă”es de Marketing inaugural TransferĂȘncia de âKnow-Howâ e tecnologia atravĂ©s de treinamento teĂłrico e prĂĄtico para franqueados e toda a equipe Acompanhamento presencial do inĂ­cio das novas operaĂ§Ă”es AuxĂ­lio na busca por perfis de colaboradores RealizaĂ§ĂŁo da primeira compra de produtos e insumos, alĂ©m do maquinĂĄrio, visando o melhor desempenho do franqueado na abertura de sua loja Estudo e desenvolvimento do primeiro enxoval de quadros na loja, conforme coleĂ§ĂŁo vigente Â  PĂłs-abertura \nPĂłs-abertura, a Moldura Minuto tambĂ©m conta com um planejamento para colaborar com a gestĂŁo de seus franqueados oferecendo toda a ajuda necessĂĄria para sua operaĂ§ĂŁo: Suporte full-time de operaĂ§Ă”es, gestĂŁo, financeiro e marketing nos diversos canais de comunicaĂ§ĂŁo Desenvolvimento das metas mensais Feedback periĂłdico do desempenho da loja com anĂĄlise dos Ă­ndices operacionais Treinamentos mensais online e/ou apresentaĂ§Ă”es. AuxĂ­lio na contrataĂ§ĂŁo de colaboradores ConvenĂ§ĂŁo anual de franqueados GestĂŁo participativa de marketing juntamente com o Conselho de franqueados SAF â ServiĂ§o de atendimento ao franqueado Desenvolvimento constante de novos produtos Busca constante de novos fornecedores com os melhores produtos e preĂ§os exclusivos para rede Software de gestĂŁo online Campanhas de marketing periĂłdicas Suporte na aquisiĂ§ĂŁo de produtos, atravĂ©s do clube de compras\n\tÂ  Produtos e serviĂ§os oferecidos: Â Emolduramento customizado; Â ComposiĂ§Ă”es personalizadas de quadros; Â Consultoria em projetos de decoraĂ§ĂŁo com quadros; Â ImpressĂŁo digital em papel fotogrĂĄfico e canvas; Â Quadros prontos; Â Artes e fotografias do acervo Moldura Minuto; Â Espelhos; Â MM Instala; Â MM Imprime;', NULL, 'SĂO PAULO', 1, NULL, 53, NULL, NULL, '2026-03-08 19:12:46.764', 'https://franquias.portaldofranchising.com.br/franquia-moldura-minuto-decoracao-e-presentes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74gd005aeh0s8ruwwex6', 'FARMĂCIAS SĂO RAFAEL', 'farmacias-sao-rafael', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'Franquia no segmento de FarmĂĄcias e Drogarias com atuaĂ§ĂŁo nacional', 2016, 2016, '[\"https://www.youtube.com/watch?v=0TmG-FZqZDM\"]', '2026-04-01 02:00:02.723', '2025-08-05 22:20:25.165', 227, NULL, 1, 1997, 'A FarmĂĄcia SĂŁo Rafael iniciou as suas atividades em marĂ§o de 1997 na cidade de ChapecĂł em Santa Catarina. Uma trajetĂłria empreendedora, com muitos desafios e aprendizados. Em 2017, a SĂŁo Rafael completou 20 anos da sua trajetĂłria, chegando ao total de 11 lojas prĂłprias e duas unidades franqueadas. Em 2020, com um total de 33 lojas em operaĂ§ĂŁo a SĂŁo Rafael jĂĄ Ă© uma franquia consolidada, um sucesso em resultados e com a expansĂŁo a pleno vapor nas regiĂ”es Sul e Sudeste do Brasil. Dispomos de experiĂȘncia e know-how suficientes para estender esse modelo aos parceiros que desejam obter o mesmo ĂȘxito que conseguimos. Confira abaixo algumas vantagens de se investir em uma Franquia FarmĂĄcias SĂŁo Rafael: Marca reconhecida e qualidade percebida pelos consumidores; AnĂĄlise do ponto e estudo de viabilidade de implantaĂ§ĂŁo; Disponibilizamos o projeto de interiores comercial e layout de fachada; Suporte em todo o processo de implantaĂ§ĂŁo; Treinamento ao Franqueado e equipe para trabalhar nos padrĂ”es da marca; Manuais da franquia; Estudo de mercado e sugestĂŁo do mix ideal para dar inĂ­cio as atividades e precificaĂ§ĂŁo a ser aplicada; NegociaĂ§Ă”es estratĂ©gicas com fornecedores; Produtos exclusivos com qualidade e rentabilidade diferenciada; Acesso a uma estratĂ©gia de marketing mais agressiva e efetiva; Suporte especializado na gestĂŁo; Acompanhamento full time dos indicadores de desempenho da franquia; Tabloide de ofertas com produtos selecionados estrategicamente para garantir os resultados; Ferramentas que irĂŁo reduzir a inadimplĂȘncia a zero; ConvĂȘnio Corporativo com gestĂŁo totalmente on-line, facilidade e agilidade no processo; ComunicaĂ§ĂŁo direta com a Franqueadora para facilitar as orientaĂ§Ă”es e a troca de informaĂ§Ă”es; Consultoria de campo especializada, com suporte efetivo focado em resultado, proporcionando crescimento e permanĂȘncia no mercado farmacĂȘutico. \nA uniĂŁo de um mercado muito promissor a uma marca que fundamenta o seu modelo de negĂłcio na excelĂȘncia do atendimento, layout e mix de produtos diferenciados para proporcionar sempre a melhor experiĂȘncia aos seus clientes, pode ser a sua receita de sucesso tambĂ©m. Â  Invista em uma Franquia FarmĂĄcias SĂŁo Rafael!', NULL, 'SANTA CATARINA', 1, NULL, 60, NULL, NULL, '2026-03-08 19:17:16.822', 'https://franquias.portaldofranchising.com.br/franquia-farmacias-sao-rafael-farmacias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '233000.01', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
