INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74go005ceh0sbnmkge3c', 'ORAL SIN IMPLANTES', 'oral-sin-implantes', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'CLĂNICAS ODONTOLĂGICAS COM ATENDIMENTO ESPECIALIZADO EM IMPLANTES DENTĂRIOS.', 2010, 2017, '[\"https://www.youtube.com/watch?v=DmQgJB0upDc\"]', '2026-04-01 02:00:02.743', '2025-08-05 22:20:25.177', 229, NULL, 1, 2004, 'A Oral Sin foi fundada em 2004 na cidade de Arapongas â PR com o objetivo de levar tratamento odontolĂłgico de qualidade com um preĂ§o justo. Resultado de um trabalho de excelĂȘncia, em 2008, a clĂ­nica inaugurou sua primeira afiliada na cidade de Londrina â PR e, desde entĂŁo, nĂŁo parou mais de crescer, levando saĂșde bucal para todo o Brasil. Em 2014 a Oral Sin foi considerada a rede NÂș 1 de implantes no paĂ­s pelos principais fornecedores de insumos de implantes do Brasil. Atualmente, a rede conta com centenas de unidades em todos os estados do Brasil e mais de 1500 colaboradores, que transformam a saĂșde dos pacientes.', NULL, 'SĂO PAULO', 1, NULL, 390, NULL, NULL, '2026-03-08 19:18:55.181', 'https://franquias.portaldofranchising.com.br/franquia-oral-sin-implantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '830000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74gu005deh0sg5hlj5f5', 'LASER&CO', 'laser-co', NULL, 'SaĂșde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'ServiĂ§os estĂ©ticos a laser. Somos mais que depilaĂ§ĂŁo, trabalhamos com vĂĄrios lasers que fazem vĂĄrios serviĂ§os, desde rejuvenescimento, clareamento, remoĂ§ĂŁo de manchas e tatuagens etc...', 2023, 2023, NULL, '2026-04-01 02:00:02.754', '2025-08-05 22:20:25.182', 230, NULL, 1, 2022, 'A LASER&CO Ă© a primeira rede de serviĂ§os estĂ©ticos a laser do Brasil. NĂŁo somos âmais umaâ rede de depilaĂ§ĂŁo, realizamos diversos outros serviĂ§os a laser como rejuvenescimento facial, tratamentos de manchas e melasma, remoĂ§ĂŁo de tatuagens e micropigmentaĂ§ĂŁo, clareamento de virilha e axila a laser, alĂ©m de tratamentos com Ultrassom, que produzem uma lipo sem cortes, reduĂ§ĂŁo de papada, lifting facial, reduĂ§ĂŁo de atĂ© 20% de gordura corporal e estimula o aumento de colĂĄgeno. Enquanto uma empresa ânormalâ de depilaĂ§ĂŁo pode depilar uma virilha, nĂłs podemos depilar, clarear e rejuvenescer a regiĂŁo Ă­ntima. Isso sem falar que podemos realizar diversos outros tratamentos em outras regiĂ”es, potencializando muito mais os atendimentos em cada cliente. AlĂ©m do mais, enquanto falamos que uma depilaĂ§ĂŁo Ă© âdefinitivaâ, temos tratamentos que sĂŁo RECORRENTES, como o Rejuvenescimento Facial a laser (afinal, envelhecemos todos os dias), ou seja, temos potencial para ter clientes para sempre! Nossos serviĂ§os estavam restritos apenas a MĂ©dicos e clĂ­nicas de alto padrĂŁo, que cobram caro e atendem um pĂșblico âAâ, que corresponde a 1% do pĂșblico consumidor. NĂłs somos a resposta para todo o pĂșblico B/C, que corresponde a cerca de 90% do pĂșblico consumidor e que nunca teve acesso a este tipo de serviĂ§o, com equipamentos de ponta e preĂ§os acessĂ­veis, democratizando este tipo de serviĂ§o. TambĂ©m temos ampla vantagem em relaĂ§ĂŁo a clĂ­nicas de HarmonizaĂ§ĂŁo, pois nĂŁo temos estoque, nĂŁo dependemos de fornecedores nem de mĂŁo de obra qualificada (afinal, nossa mĂĄquina Ă© a artista principal). Nosso serviĂ§o possui um valor agregado por sessĂŁo muito melhor que depilaĂ§ĂŁo ou harmonizaĂ§ĂŁo, alĂ©m de uma barreira de entrada muito mais alta (equipamento) sendo um mercado inovador criado pela LASER&CO e, por isso, com baixa concorrĂȘncia, ao contrĂĄrio dos mercados de depilaĂ§ĂŁo e harmonizaĂ§ĂŁo. Vantagens da franquia Laser&Co: Diversos serviĂ§os a Laser executados pelo mesmo equipamento. Equipamento exclusivo, financiado e pago pela operaĂ§ĂŁo. Baixo custo de investimento e alta taxa de retorno (rĂĄpido payback). Baixa concorrĂȘncia e alta barreira de entrada. Facilidade de gestĂŁo: sem estoque, poucos funcionĂĄrios, alto ticket mĂ©dio.', NULL, 'SĂO PAULO', 1, NULL, 36, NULL, NULL, '2025-09-03 14:52:00.000', 'https://franquias.portaldofranchising.com.br/franquia-laserco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
