INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74hn005jeh0sdu3sg32u', 'OTICAS IPANEMA', 'oticas-ipanema', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ĂTICAS', 'ComĂ©rcio varejista de Ăłculos, lentes oftĂĄlmicas e acessĂłrios.', 2009, 2012, '[\"https://www.youtube.com/watch?v=ukgJsPPfW7A\"]', '2026-04-01 02:00:02.832', '2025-08-05 22:20:25.211', 236, NULL, 1, 1981, 'AÂ ĂTICASÂ IPANEMAÂ seÂ pautaÂ pelaÂ prĂĄticaÂ deÂ preĂ§osÂ competitivos,Â aliadosÂ Ă Â altaÂ qualidade tĂ©cnica e de atendimento, instalaĂ§Ă”es e serviĂ§os; fatores esses imprescindĂ­veisÂ paraÂ oÂ sucessoÂ deÂ qualquerÂ atividadeÂ comercial.Â AÂ ĂTICASÂ IPANEMAÂ cresceuÂ suaÂ participaĂ§ĂŁoÂ noÂ mercadoÂ atravĂ©sÂ deÂ umÂ trabalhoÂ bemÂ estruturado,Â alicerĂ§adoÂ porÂ princĂ­piosÂ de qualidade. A empresa Ă© administrada de forma dinĂąmica ao longo de seus 40 (quarenta) anos deÂ existĂȘncia, fortemente conhecida em sua ĂĄrea de atuaĂ§ĂŁo, por contar com um alto poderÂ de penetraĂ§ĂŁo no mercado e dispor de uma altĂ­ssima qualidade em seus produtos eÂ serviĂ§os. Este histĂłrico vem ao encontro do perfil dos sĂłcios e responsĂĄveis pela marca eÂ pelo sistema de operaĂ§ĂŁo de unidadesÂ ĂTICAS IPANEMA, que buscam exatamenteÂ envolvimento, responsabilidade e profissionalismo no que executam e nas parcerias queÂ desenvolvem. Em janeiro de 1981, sob a lideranĂ§a dos irmĂŁos Silvio e Sinval Ferreira, foi aberta aÂ primeira unidadeÂ ĂTICAS IPANEMA, na cidade de Indaiatuba, Estado de SĂŁo Paulo. ComÂ Â ousadia e espĂ­rito empreendedor, em pouco tempo, tornaram-se uma referĂȘncia nacionalÂ no segmentoÂ Ăłptico.Â Atualmente, a rede conta com 57 unidades.', NULL, 'SĂO PAULO', 1, NULL, 33, NULL, NULL, '2026-03-08 19:21:47.022', 'https://franquias.portaldofranchising.com.br/franquia-oticas-ipanema/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
