INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74iz005reh0szrifinkb', 'ĂTICAS FERRI', 'oticas-ferri', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'Rede de Ăłticas inserida no varejo, com marca prĂłpria de lentes e armaĂ§Ă”es, alĂ©m de laboratĂłrio prĂłprio com tecnologia FREEFORM, o que garante markup acima da mĂ©dia para o segmento.', 2015, 2021, '[\"https://www.youtube.com/watch?v=Mn5xK5c1THQ\",\"https://www.youtube.com/watch?v=w9G4aTznhuI\",\"https://www.youtube.com/watch?v=XBk4SdYcM2M\"]', '2026-04-01 02:00:02.984', '2025-08-05 22:20:25.259', 244, NULL, 1, 1999, 'Toda nossa histĂłria comeĂ§ou com a fundaĂ§ĂŁo da ĂTICAS FERRI no ano de 1999, no bairro Estreito, na cidade de FlorianĂłpolis/SC, quando atuĂĄvamos apenas como distribuidora de produtos Ăłticos. ApĂłs 5 (cinco) anos no mercado, os sĂłcios, Eglo Ferri e Milena Ferri, observando diversas necessidades no segmento varejista, a empresa estendeu as atividades no setor Ăłtico, ramo promissor atĂ© os dias atuais, sendo que sempre buscaram o atendimento de excelĂȘncia, vendendo produtos de qualidade a preĂ§o justo. Os irmĂŁos cresceram em uma famĂ­lia empreendedora e aprenderam com os pais o gosto pelo empreendedorismo. Eglo construiu sua carreira corporativa em uma empresa multinacional do setor Ăłtico. Trabalhando neste grande player, aprendeu as questĂ”es tĂ©cnicas e adquiriu a visĂŁo do setor, o que mais tarde o auxiliou a consolidar a ĂTICAS FERRI. Estudou e se formou em tĂ©cnico em Ătica, cumprindo assim os requisitos necessĂĄrios para a abertura de seu negĂłcio. Em 2004, fundou a primeira loja na cidade de BiguaĂ§u/SC. Mais tarde, Milena passou a incorporar a sociedade, auxiliando no crescimento da rede. Â A partir de 10 (dez) anos de atuaĂ§ĂŁo especĂ­fica no comĂ©rcio de venda, jĂĄ contendo 05 (cinco) unidades prĂłprias na ocasiĂŁo, em julho de 2016 iniciamos nossa trajetĂłria no franchising, contando com uma equipe de especialistas e com muita experiĂȘncia adquiridas em outras grandes redes, botamos em prĂĄtica nosso sonho de termos uma rede completa, que gera resultados e proporciona expansĂŁo aos franqueados. A FRANQUIA ĂTICAS FERRI consolidou-se no mercado conquistando a confianĂ§a dos seus clientes e trazendo toda a experiĂȘncia destes anos de trabalho para oferecer a mĂĄxima qualidade para a saĂșde dos olhos. A preocupaĂ§ĂŁo em fornecer as melhores opĂ§Ă”es a seus clientes, o ĂTICAS FERRI trabalha com os Ășltimos lanĂ§amentos em termos de lentes e armaĂ§ĂŁo para Ăłculos, buscando melhorar a saĂșde visual e ocular, proporcionando conforto para seus clientes, alĂ©m de contarmos com uma equipe altamente capacitada para desenvolver a rede e os franqueados. A expansĂŁo estĂĄ aberta em 04 (quatro) estados, SP, SC, RS e PR, com produtos e distribuiĂ§ĂŁo prĂłprios, o que favorece o negĂłcio aumentando mark-up do franqueado. AlĂ©m disso, temos atualmente um plano especĂ­fico e com muitos benefĂ­cios para favorecer o franqueado expandir organicamente, ou seja, com duas ou mais unidades. Saiba como preenchendo o formulĂĄrio e conheĂ§a mais sobre nossa marca e trajetĂłria.', NULL, 'SANTA CATARINA', 1, NULL, 36, NULL, NULL, '2026-03-08 19:26:57.564', 'https://franquias.portaldofranchising.com.br/franquia-oticas-ferri/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74j3005seh0sv8m6w3uq', 'LEMAX HAMBURGUERIA', 'lemax-hamburgueria', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Hamburgueria', 2019, 2019, '[\"https://www.youtube.com/watch?v=Zbsv87citZU\",\"https://www.youtube.com/watch?v=6BcS6X5HLeM\",\"https://www.youtube.com/watch?v=07U-EJThvos\"]', '2026-04-01 02:00:02.994', '2025-08-05 22:20:25.264', 245, NULL, 1, 2014, 'Em 2013 os sĂłcios atuais do LeMax possuem 4 lojas franqueadas de outra marca. Neste momento eles decidem criar uma marca prĂłpria e convidam o Chef Hugo Grillo para se juntar Ă  sociedade. Assim nasce o projeto LeMax . \nNo ano seguinte inauguramos, no Centro do Rio de Janeiro, o LeMax cafĂ© e sanduĂ­ches, vendendo alĂ©m de sanduĂ­ches, almoĂ§o e cafĂ©.Â  No ano de 2015 o LeMax mostrou seu verdadeiro DNA, vender hambĂșrguer, desta forma, os sĂłcios decidem fazer uma remodelaĂ§ĂŁo da marca, passando a se chamar Lemax Hamburgueria.Â  \nEm 2016 o Lemax se torna sucesso no Centro do Rio, com a loja lotada todos os dias, a partir daĂ­, pensando no crescimento, em 2017 inauguramos a segunda loja em Botafogo, com sucesso ainda maior, bombando de dia e de noite.Â  ApĂłs a consolidaĂ§ĂŁo do sucesso da marca LeMax, em 2019, estruturamos o negĂłcio para franquear e a partir do ano de 2020 abrimos as 3 primeiras lojas franqueadas com grande sucesso. \nCom a pandemia, freamos a expansĂŁo e investimos no crescimento do delivery.Â  \nApĂłs se tornar um sucesso no delivery, tendo aumentado em 20 vezes o seu faturamento neste canal, em 2021 voltamos a aceitar novos franqueados e terminamos o ano com 6 unidades. O Lemax dobra o tamanho em 2022 e termina o ano com 13 unidades, batendo o recorde de faturamento todos os meses.', NULL, 'RIO DE JANEIRO', 1, NULL, 12, NULL, NULL, '2026-03-08 19:28:23.970', 'https://franquias.portaldofranchising.com.br/franquia-lemax-hamburgueria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74j8005teh0si9ampotd', 'PHITOFARMA', 'phitofarma', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'FarmĂĄcia de ManipulaĂ§ĂŁo, especialista em fĂłrmulas sob medida, dispensaĂ§ĂŁo de fĂłrmulas em blisters', 2012, 2011, '[\"https://www.youtube.com/watch?v=se4be2dw91w\",\"https://www.youtube.com/watch?v=Xpb7cqyqKDQ\"]', '2026-04-01 02:00:03.005', '2025-08-05 22:20:25.269', 246, NULL, 1, 1970, 'A histĂłria da franquiaÂ PhitofarmaÂ remonta ao inĂ­cio do sĂ©culo XX, quando a manipulaĂ§ĂŁo de fĂłrmulas personalizadas e a fitoterapia comeĂ§aram a ganhar destaque como alternativas Ă  medicina tradicional. Desde entĂŁo, a Phitofarma tem desempenhado um papel fundamental na histĂłria da farmĂĄcia no Brasil, sendo uma das pioneiras e lĂ­deres no setor de medicamentos manipulados. Com 53 anos de atuaĂ§ĂŁo, a empresa estabeleceu padrĂ”es de qualidade e inovaĂ§ĂŁo que moldaram o cenĂĄrio farmacĂȘutico do paĂ­s. HĂĄ 11 anos, a Phitofarma expandiu sua influĂȘncia ao oferecer franquias, solidificando ainda mais sua posiĂ§ĂŁo icĂŽnica na histĂłria da farmĂĄcia no Brasil. A Phitofarma tambĂ©m desempenhou um papel importante na promoĂ§ĂŁo da fitoterapia como uma abordagem legĂ­tima e eficaz para a saĂșde, enquanto continuava a oferecer serviĂ§os de manipulaĂ§ĂŁo de fĂłrmulas personalizadas.', NULL, 'SĂO PAULO', 1, NULL, 23, NULL, NULL, '2026-03-08 19:29:24.257', 'https://franquias.portaldofranchising.com.br/franquia-phitofarma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
