INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ko0063eh0svlgm7pcx', 'PELO ZERO DEPILAĂĂO', 'pelo-zero-depilacao', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'DepilaĂ§ĂŁo Expressa feminina e masculina, designer de sobrancelhas e depilaĂ§ĂŁo oriental e DepilaĂ§ĂŁo Definitiva', 2002, 2008, '[\"https://www.youtube.com/watch?v=1681nLBCQfc\",\"https://www.youtube.com/watch?v=CGMuox4_6hE\",\"https://www.youtube.com/watch?v=rUoEtHABlCo\"]', '2026-04-01 02:00:03.111', '2025-08-05 22:20:25.320', 256, NULL, 1, 1998, 'Pelo Zero DepilaĂ§ĂŁo â uma histĂłria marcada por desafios e conquistas Perseguindo a excelĂȘncia, dificuldades e desafios foram atrativos para que a Pelo Zero DepilaĂ§ĂŁo alcanĂ§asse o sucesso.Â  O que teve inĂ­cio em uma discreta loja no bairro de Vila Isabel, no Rio de Janeiro, destaca-se hoje por um continuado trabalho, que se distingue nĂŁo sĂł pela qualidade do produto e dos serviĂ§os prestados, como tambĂ©m pela reafirmaĂ§ĂŁo diĂĄria de princĂ­pios e valores Ă©ticos e sociais. Hoje a Pelo Zero DepilaĂ§ĂŁo Ă© o sonho realizado de muitos empreendedores.Â  Com mais de 20 anos de experiĂȘncia no segmento de depilaĂ§ĂŁo expressa, a rede â com mais de 30 Unidades - conta com mais de 400 mil clientes atendidos e mais de 17 milhĂ”es de serviĂ§os realizados. Isso se traduz em prestar um excelente serviĂ§o, direcionado Ă  satisfaĂ§ĂŁo dos clientes, tendo como principal objetivo cuidar da beleza, aliando um atendimento ĂĄgil a serviĂ§os de qualidade.Â  Sistema de Franquia Pelo Zero DepilaĂ§ĂŁo  Primando por uma atuaĂ§ĂŁo consistente e de qualidade, que conferiu Ă  marca a conquista do Selo de ExcelĂȘncia em Franchising da ABF por 8 anos consecutivos, o sistema de franquia Pelo Zero DepilaĂ§ĂŁo consiste em parceria formada com o franqueado visando o fortalecimento da marca, o que traz como resultado uma operaĂ§ĂŁo comercial com um continuado potencial de desenvolvimento.', NULL, 'RIO DE JANEIRO', 1, NULL, 34, NULL, NULL, '2026-03-08 19:33:56.383', 'https://franquias.portaldofranchising.com.br/franquia-pelo-zero-depilacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
