INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74l20066eh0ssah1mroz', 'BELGO CERCAS', 'belgo-cercas', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Venda e instalaĂ§ĂŁo de materiais para Cercas Urbanas', 2017, 2018, NULL, '2026-04-01 02:00:03.144', '2025-08-05 22:20:25.335', 259, NULL, 1, 1921, 'A Belgo Bekaert Arames Ă© uma parceria entre a Arcelor Mittal â lĂ­der mundial na produĂ§ĂŁo de aĂ§o â e a Bekaert â lĂ­der mundial em tecnologia de transformaĂ§ĂŁo e revestimento de arame de aĂ§o. Unindo a forĂ§a desses acionistas, que juntos somam mais de 200 anos de atuaĂ§ĂŁo, a Belgo Bekaert Arames Ă© pioneira e lĂ­der no mercado brasileiro de arames. \nLĂ­der na AmĂ©rica do Sul em produĂ§ĂŁo de arames, a Belgo Bekaert Ă© uma associaĂ§ĂŁo da ArcelorMittal (lĂ­der mundial na produĂ§ĂŁo de aĂ§o) e Bekaert (lĂ­der mundial em tecnologia de transformaĂ§ĂŁo e revestimento de arames). E nessa marca mundial e de presenĂ§a consolidada, vocĂȘ pode confiar.  Por que investir na franquia Belgo Cercas? \nForĂ§a da marca Belgo Bekaert LĂ­der de mercado; Empresa global; Pioneira no segmento de Cercas Urbanas no Brasil.  Qualidade Sistemas de cercamento com estĂ©tica, funcionalidade, seguranĂ§a e durabilidade; Tecnologia de ponta; Pesquisa e desenvolvimento constantes para aprimorar a linha de produtos.  Mercado Crescente Cercas urbanas modulares sĂŁo tendĂȘncia no mundo todo; PadrĂŁo de construĂ§ĂŁo em quase todos os paĂ­ses da Europa; Alto crescimento no Brasil: os sistemas de cercamento Belgo Bekaert jĂĄ estĂŁo em mais de 300 mil empreendimentos.  Suporte Acesso a um know-how para planejar um negĂłcio sĂłlido, com resultados competitivos; Apoio total na escolha do ponto, manuais de gestĂŁo e treinamentos regulares.', NULL, 'MINAS GERAIS', 1, NULL, 24, NULL, NULL, '2026-03-08 19:35:22.556', 'https://franquias.portaldofranchising.com.br/franquia-belgo-cercas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
