INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74mu006jeh0svmoy13d0', 'SIMPLE ORGANIC', 'simple-organic', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'CosmĂ©ticos naturais e orgĂąnicos, livres de crueldade animal e pautados na sustentabilidade da biodiversidade.', 2017, 2019, '[\"https://www.youtube.com/watch?v=TS2cn6wRUX0\"]', '2026-04-01 02:00:03.390', '2025-08-05 22:20:25.399', 272, NULL, 1, 2016, 'Fundada em 2016 pela publicitĂĄria Patricia Lima, a marca foi lanĂ§ada oficialmente na maior semana de moda do Brasil: SĂŁo Paulo Fashion Week. Ao levar o conceito de cosmĂ©ticos orgĂąnicos e veganos para a passarela, se tornou a marca orgĂąnica mais conhecida do Brasil. \nA marca foi concebida a partir do desejo da fundadora em criar uma marca sustentĂĄvel, com impacto social positivo. \nA ideia surgiu apĂłs a maternidade da PatrĂ­cia, que decidiu buscar um novo caminho para sua vida, pensando no futuro das prĂłximas geraĂ§Ă”es, inspirada em sua filha (com seis anos atualmente).  A Maior Franquia de CosmĂ©ticos OrgĂąnicos, Veganos e SustentĂĄveis Temos a missĂŁo de democratizar a beleza natural, com produtos livre de ingredientes sintĂ©ticos, pesticidas e nocivos Ă  pele, que prezam pela saĂșde por meio do respeito Ă  natureza, Ă s pessoas e aos animais. \nAcreditamos que a beleza vem junto com a saĂșde e, desta forma, levamos esse propĂłsito para todo o Brasil. \nA marca nasceu digital, porĂ©m a demanda do mercado por uma rede de franquias que atendesse o consumidor com a experiĂȘncia da marca, fez com que abrĂ­ssemos a possibilidade de franquias e rapidamente abrimos inĂșmeras lojas que levam os nossos valores de sustentabilidade para todo territĂłrio nacional.Â  Somos reconhecidos como case de sucesso dentro do segmento, tanto na comunicaĂ§ĂŁo / marketing, como produtos e tambĂ©m nas estratĂ©gias comerciais. \nSomos pioneiros no formato franquia de cosmĂ©ticos orgĂąnicos, veganos e sem gĂȘnero. AliĂĄs, inovaĂ§ĂŁo Ă© um dos pilares da marca, junto com a sustentabilidade. \nCom o maior mix de produtos orgĂąnicos, veganos, os lanĂ§amentos sĂŁo mensais e com a criaĂ§ĂŁo da maior variedade de cores de bases liquidas orgĂąnicas, corretivos compactos e tantos outros produtos que ainda nĂŁo existiam no mercado de beleza natural, conquistamos o reconhecimento como referĂȘncia de produtos com alta performance. O resultado entregue para o nosso consumidor Ă© reconhecido nacionalmente e internacionalmente, sĂł no primeiro semestre de 2019 foram trĂȘs produtos premiados e o Blending Facial jĂĄ foi eleito como melhor hidratante facial orgĂąnico dos EUA, em 2017. \nNossas franquias representam o conceito contemporĂąneo da marca e sĂŁo inclusivas, com objetivo de receber da melhor maneira cada consumidor presente nas lojas', NULL, 'SANTA CATARINA', 1, NULL, 15, NULL, NULL, '2026-03-08 19:52:00.203', 'https://franquias.portaldofranchising.com.br/franquia-simple-organic/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '110000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
