INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74n4006leh0s1lxslgu3', 'VILESOFT', 'vilesoft', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'ComunicaĂ§ĂŁo e MĂ­dia', 'Softwares de gestĂŁo empresarial ERP / RH', 2005, 2007, '[\"https://www.youtube.com/watch?v=2i-Qk4JcK6A\",\"https://www.youtube.com/watch?v=LIFifmoRTcs\",\"https://www.youtube.com/watch?v=Mhp8TyvMmUQ\"]', '2026-04-01 02:00:03.421', '2025-08-05 22:20:25.409', 274, NULL, 1, 1986, 'A Vilesoft tem experiĂȘncia deÂ  mais trĂȘs dĂ©cadas com softwares de gestĂŁo empresarial. \nTrabalha com o modelo de franquias desde 2005, Ă© filiada a ABF â AssociaĂ§ĂŁo Brasileira de Franchising deste 2007 e foi a primeira franquia de software de gestĂŁo, no Brasil.Â Â  \nRecentemente a Vilesoft, optou em modernizar todo seu processo de franquias, incluindo outras modalidades que permite estar mais perto do cliente, utilizar novos conceitos de gestĂŁo e principalmente, permitir que profissionais de consultoria, contabilidade e outras especializaĂ§Ă”es do ecossistema empresarial, tambĂ©m tenham a oportunidade de se tornarem um franqueado de sucesso Vilesoft. \nDurante toda nossa trajetĂłria, a Vilesoft tem sido premiada seguidamente pela pela mĂ­dia e o mercado especializado, entre as melhores redes de franquias em vĂĄrios quesitos, e principalmente na avaliaĂ§ĂŁo do franqueado. \nA VilesoftÂ  tem clientesÂ  em vĂĄrias cidades do Brasil, alĂ©m de consultores e parceiros comerciais nos principais centros comerciais e empresariais do paĂ­s. Possui uma fĂĄbrica de software certificada pela SOFTEX/MinistĂ©rio da CiĂȘncia e Tecnologia em mps.BR nĂ­vel \'G\' em Minas Gerais, produz e fornece softwares de gestĂŁo empresarial ERP, para empresas privadas de portes e segmentos diferentes, como o setor de Transportes â TMS, Avicultura, IndĂșstria, Telemarketing de ArrecadaĂ§ĂŁo,Â  Recursos Humanos, Controladoria e serviĂ§os. \nEm 2021 iniciou seu processo de internacionalizaĂ§ĂŁo, com sua primeira Master Franquia nos Estados Unidos da AmĂ©rica.Â  Com objetivo de fortalecer sua marca e oferecer seus produtos e o seu modelo de franquias, tambĂ©m, na AmĂ©rica do Norte. \nA Vilesoft tem em seu portfĂłlio muita experiĂȘncia no que faz, uma equipe afinada com seus clientes e principalmente sabe aliar com muita precisĂŁo, a tecnologia Ă  gestĂŁo empresarial para realmente tornar efetivos os resultados que toda organizaĂ§ĂŁo necessita. \nVILESOFT, sĂŁo mais de trĂȘs dĂ©cadas de AmĂ©rica, entregando resultados. Se vocĂȘ Ă© sĂ©rio, gosta de desafios, trabalhar em equipe, compartilhar talentos; fale conosco e venha fazer parte do nosso time de ĂĄguias.', NULL, 'MINAS GERAIS', 1, NULL, 4, NULL, NULL, '2026-03-08 19:53:41.537', 'https://franquias.portaldofranchising.com.br/franquia-vilesoft/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74n9006meh0s5upypg3w', 'PAREDES BETEL', 'paredes-betel', NULL, 'Casa e ConstruĂ§ĂŁo', 'CONSTRUĂĂO', 'A marca estĂĄ hĂĄ mais de 50 anos no mercado, decidiu expandir o seu mĂ©todo facilitador para todo o territĂłrio brasileiro, realizando sonhos de todos os clientes, em todo Brasil.', 2022, 2024, '[\"https://www.youtube.com/watch?v=ttcEX8IgZHs\",\"https://www.youtube.com/watch?v=1KLrWJTD5g0\",\"https://www.youtube.com/watch?v=fg-Ana-9c70\",\"https://www.youtube.com/watch?v=L3QR6uuxGAM\"]', '2026-04-01 02:00:03.440', '2025-08-05 22:20:25.414', 275, NULL, 1, 1997, 'A histĂłria emocionante da Paredes Betel se entrelaĂ§a com os Ășltimos 54 anos de inovaĂ§ĂŁo e paixĂŁo na construĂ§ĂŁo civil. Desde 1969, quando o visionĂĄrio Walter Pedro da Silva fundou a empresa em GoianĂ©sia, nossa jornada comeĂ§ou com tijolos de cerĂąmica, uma base sĂłlida para sonhos que se elevam aos cĂ©us. Somos parte do Grupo Betel, uma famĂ­lia de nove empresas dedicadas, incluindo trĂȘs indĂșstrias de cerĂąmica vermelha, quatro distribuidoras de AĂ§o e EPS, uma loja de materiais para construĂ§ĂŁo e uma fĂĄbrica de produtos de EPS. A evoluĂ§ĂŁo da cerĂąmica para o EPS simboliza nĂŁo apenas uma mudanĂ§a de material, mas uma transiĂ§ĂŁo que marca o nosso compromisso com a inovaĂ§ĂŁo e o futuro da construĂ§ĂŁo. A Paredes Betel, nascida como uma indĂșstria de produtos de EPS em 2003, tinha inicialmente a missĂŁo de atender Ă  regiĂŁo de BrasĂ­lia e ao centro-oeste. No entanto, Ă  medida que nosso compromisso com a qualidade e a visĂŁo sustentĂĄvel ganharam destaque, a popularidade de nossos produtos transcendeu fronteiras. Hoje, com especialistas em todos os estados e principais cidades do paĂ­s, estamos orgulhosos de ver nossas criaĂ§Ă”es transformando e aprimorando a paisagem arquitetĂŽnica nacional. Cada produto que oferecemos conta uma histĂłria de dedicaĂ§ĂŁo, qualidade e inovaĂ§ĂŁo. Estamos moldando o amanhĂŁ da construĂ§ĂŁo civil, e cada tijolo, cada peĂ§a de EPS, Ă© um testemunho do nosso comprometimento em construir nĂŁo apenas estruturas, mas legados que resistem ao teste do tempo.', NULL, 'GOIĂS', 1, NULL, 16, NULL, NULL, '2025-04-02 17:19:42.000', 'https://franquias.portaldofranchising.com.br/franquia-paredes-betel/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ne006neh0sgim1y1ip', 'TOUAREG CORRETORA DE SEGUROS', 'touareg-corretora-de-seguros', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Os corretores de seguros tĂȘm como funĂ§ĂŁo a distribuiĂ§ĂŁo e venda de seguros, tendo em vista que sĂŁo intermediĂĄrios independentes que negociam contratos de seguro para clientes que procuram proteĂ§ĂŁo.', 2016, 2017, NULL, '2026-04-01 02:00:03.454', '2025-08-05 22:20:25.418', 276, NULL, 1, 2011, '', NULL, 'BAHIA', 1, NULL, 200, NULL, NULL, '2026-03-08 19:55:02.436', 'https://franquias.portaldofranchising.com.br/franquia-touareg-corretora-de-seguros/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '25000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74nj006oeh0s1xg9bzo7', 'PIASEG SEGUROS', 'piaseg-seguros', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Somos uma franqueadora de corretoras de seguros.', 2021, 2021, '[\"https://www.youtube.com/watch?v=DjWjKeCuYMM\"]', '2026-04-01 02:00:03.468', '2025-08-05 22:20:25.423', 277, NULL, 1, 2020, 'Nossa HistĂłria comeĂ§a lĂĄ em 1979, quando Wilson Piacentine (mais conhecido como PiĂĄ) foi contratado por uma grande seguradora, e por lĂĄ ficou por 15 anos, e o desejo de empreender foi ficando cada vez maior, quando em 1991 juntamente com outro funcionĂĄrio da seguradora resolveu iniciar sua prĂłpria empresa, como os recursos eram limitados, a Sra Maria do Carmo, esposa, abraĂ§ou a ideia junto com ele dando inĂ­cio do negĂłcio.Â  Em 2001 houve a cisĂŁo da sociedade, mas o PiĂĄ e a Sra Maria do Carmo continuaram firme com seu propĂłsito de empreendedorismo, nascendo a Piaseg Seguros, o nome Surgiu da ideia de aproveitar o nome PiĂĄ que jĂĄ era muito conhecido na cidade, somado com a palavra seguros, Pia + seg , nascendo a Piaseg. \nLĂĄ se vĂŁo 30 anos contemplando toda essa jornada, de sucesso e muitos desafios, que surgiram na vontade de empreender. Em 2020 demos mais um passo importante para o crescimento do negĂłcio, nasceu a Piaseg Seguros Franchising, com o propĂłsito de replicar o modelo de sucesso que executamos durante esses 30 anos de histĂłria, nosso propĂłsito Ă© trazer facilidade, ensinamos nossos franqueados os caminhos para ter uma empresa de sucesso, com processos fĂĄcil e proporcionando alta rentabilidade. A Piaseg Franchising Ă© uma empresa inovadora, que acompanha bem de perto seus franqueados dando todo o suporte necessĂĄrio para o impulsionamento da sua franquia. \nNossos franqueados poderĂŁo comercializar as apĂłlices das melhores seguradoras do mercado Brasileiro em qualquer parte do territĂłrio nacional.Â  A Piaseg proporcionarĂĄ ao seu franqueado liberdade financeira e geogrĂĄfica, ser dono do seu prĂłprio negĂłcio, com autonomia de trabalho, nĂŁo precisando passar por toda essa jornada que seus fundadores passaram, trazemos nosso propĂłsito muito a sĂ©rio, que Ă© gerar facilidade e alta rentabilidade aos nossos franqueados.', NULL, 'MATO GROSSO DO SUL', 1, NULL, 7, NULL, NULL, '2026-03-08 19:55:28.910', 'https://franquias.portaldofranchising.com.br/franquia-ps-piaseg-seguros/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
