INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74s5007leh0scihzqfwu', 'ACG HOME CARE', 'acg-home-care', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'AtenĂ§ĂŁo Domiciliar Ă  SaĂșde no segmento de Home Care, com atendimentos de enfermeiros, equipe de tĂ©cnicos de enfermagem, cuidadores de pessoas, medico geral, fisioterapia, fonoaudiologia e nutriĂ§ĂŁo.', 2021, 2022, '[\"https://www.youtube.com/watch?v=EbRi8bshjuI\"]', '2026-04-01 02:00:03.874', '2025-08-05 22:20:25.590', 310, NULL, 1, 2000, 'A FRANQUIA MAIS BARATA DO BRASIL NO SEGMENTO DE HOME CARE FaĂ§a parte de um negĂłcio que sĂł cresce na ĂĄrea da saĂșde. E nĂŁo pense vocĂȘ que estamos falando isso para vender um produto, mas os dados falam por si. âO nĂșmero de brasileiros com mais de 60 anos superou os 30 milhĂ”es em 2017, segundo a Pesquisa Nacional por Amostra de DomicĂ­lios ContĂ­nua (Pnad) divulgada nesta quinta-feira pelo IBGE, e a tendĂȘncia Ă© que o envelhecimento da populaĂ§ĂŁo acelere de forma a, em 2031, o nĂșmero de idosos superar o de crianĂ§as e adolescentes de 0 a 14 anos no Brasilâ Somos uma das mais antigas empresas de AtenĂ§ĂŁo Domiciliar do Brasil, desde 2000 no mercado do Rio Grande do Sul. Oferecemos Ă  vocĂȘ mais que uma bandeira, mas uma consultoria constante para te fazer crescer, alĂ©m de uma estrutura de logĂ­stica para a entrega de materiais mĂ©dicos hospitalares, medicamentos e dietas enterais. Se vocĂȘ possui os 3 pontos abaixo, fale conosco: 1) EspĂ­rito empreendedor\n2) Ama cuidar de pessoas\n3) Vontade de vencer', NULL, 'RIO GRANDE DO SUL', 1, NULL, 6, NULL, NULL, '2026-03-08 20:21:23.180', 'https://franquias.portaldofranchising.com.br/franquia-acg-home-care/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
