INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ue007zeh0svnjm7q3s', 'GELA BOCA SORVETES', 'gela-boca-sorvetes', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Uma rede de sorveterias que Ă© sucesso em todas as regiĂ”es onde atua. Investimento sob medida para quem valoriza a inovaĂ§ĂŁo, o relacionamento com o cliente e a mais alta qualidade em produtos.', 2010, 2018, '[\"https://www.youtube.com/watch?v=NYfei0E7xNM\",\"https://www.youtube.com/watch?v=h1EP7wdjGys\"]', '2026-04-01 02:00:04.036', '2025-08-05 22:20:25.670', 324, NULL, 1, 2000, 'A Gela Boca surgiu no ano 2000 em MaringĂĄ, no norte do ParanĂĄ, em um pequeno espaĂ§o deÂ  120 mÂČ que funcionava como fĂĄbrica e loja, atendendo diretamente ao consumidor final. Depois de ganhar a preferĂȘncia em seu bairro, conquistou notoriedade por toda cidade, que reconhecia nos produtos Gela Boca a qualidade, originalidade e o preĂ§o justo. Logo a demanda e produĂ§ĂŁo aumentaram, assim como o investimento em inovaĂ§ĂŁo e matĂ©ria-prima de excelĂȘncia. Depois da abertura das primeiras filiais, alinhadas com um sistema de gestĂŁo que funcionava com alto padrĂŁo de excelĂȘncia,Â  veio um novo projeto de expansĂŁo que consistia na formataĂ§ĂŁo do sistema de franquias. em 2010 nasceram as primeiras lojas franqueadas da Gela Boca e em 2011 a rede conquistou mais 16 novas franquias. Duas dĂ©cadas se passaram e hoje a Gela Boca conta com uma fĂĄbrica que ocupa 8.000mÂČ e mais deÂ  70 lojas franqueadas espalhadas pelos estados do ParanĂĄ, Santa Catarina e SĂŁo Paulo. O crescimento Ă© constante e as projeĂ§Ă”es sĂŁo animadoras. Com inovaĂ§ĂŁo no DNA e simplicidade nos processos, a Gela Boca estĂĄÂ  diariamente em busca de novos conhecimentos para se modernizar, elevar ainda mais a qualidade e variedade dos produtos e gerar novas experiĂȘncias ao consumidor. Tudo isso para atender com cuidado as principais necessidades dos clientes e franqueados que ajudam a construir essa deliciosa histĂłria de sucesso.', NULL, 'PARANĂ', 1, NULL, 146, NULL, NULL, '2026-03-08 20:26:31.464', 'https://franquias.portaldofranchising.com.br/franquia-gela-boca-sorvetes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ui0080eh0sf68yyqqz', 'TT BURGER', 'tt-burger', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'CNAE 56.11-2-01 - Restaurantes e similares', 2021, 2022, '[\"https://www.youtube.com/watch?v=e0mU4e0neaM\",\"https://www.youtube.com/watch?v=UHU3NJtp1xw\",\"https://www.youtube.com/watch?v=V9WvgA0YziA\",\"https://www.youtube.com/watch?v=L-s_sBxD19w\"]', '2026-04-01 02:00:04.048', '2025-08-05 22:20:25.675', 325, NULL, 1, 2013, 'Desde 2013, o T.T. Burger vem mudando o jogo da gastronomia brasileira. Com cardĂĄpio assinado pelo chef Thomas Troisgros, premiado com estrela Michelin e eleito Melhor Chef do Ano (PrĂȘmio Rio Show de Gastronomia 2025), nasceu com um propĂłsito claro: criar o primeiro burger 100% brasileiro. Nada de copiar fĂłrmula gringa. Aqui, a gente mistura, inventa e transforma. Do pĂŁo ao molho, do nome Ă s combinaĂ§Ă”es, cada detalhe Ă© um tributo Ă  nossa cultura e Ă  criatividade brasileira. O que comeĂ§ou como uma hamburgueria com alma carioca se tornou o Grupo T.T., um ecossistema que jĂĄ movimenta mais de 18 toneladas de carne por mĂȘs, reĂșne 300 pessoas entre lojas prĂłprias e franquias e estĂĄ presente em diversas cidades do paĂ­s. Depois de recalcular a rota durante a pandemia, os sĂłcios Thomas Troisgros e AndrĂ© Meisler aceleraram a expansĂŁo apostando em inovaĂ§ĂŁo, eficiĂȘncia e sabor autĂȘntico. O resultado? R$ 60 milhĂ”es faturados em 2024, crescimento de 40% em relaĂ§ĂŁo ao ano anterior, e uma ambiĂ§ĂŁo ousada pela frente: 200 franquias e R$ 1 bilhĂŁo em faturamento nos prĂłximos cinco anos. Hoje, o Grupo T.T. reĂșne quatro marcas: T.T. Burger, TrĂȘs Gordos, Marola e Tom Ticken, e segue com o mesmo propĂłsito que inspirou o inĂ­cio de tudo: mostrar que o Brasil tem sabor, histĂłria e identidade o suficiente pra liderar o futuro da gastronomia. Mais do que um hambĂșrguer, o T.T. Ă© um movimento de sabor, brasilidade e ousadia.? E vocĂȘ pode fazer parte dele.', NULL, 'RIO DE JANEIRO', 1, NULL, 18, NULL, NULL, '2026-03-08 20:27:23.642', 'https://franquias.portaldofranchising.com.br/franquia-tt-burger/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '780000', NULL, NULL, NULL, '160000', NULL, '7', '2', '780000', '100000', 0);
