IMISSIMI conta hoje com mais de 1.315 lojas em mais de 32 paĂ­ses, incluindo a ItĂĄlia.', NULL, 'SĂO PAULO', 1, NULL, 72, NULL, NULL, '2026-03-08 20:28:44.845', 'https://franquias.portaldofranchising.com.br/franquia-intimissimi-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '480000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
