INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vg0087eh0soy4ntcx5', 'ACHEI NO PĂO', 'achei-no-pao', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'ComunicaĂ§ĂŁo e MĂ­dia', 'A Achei no PĂŁo Ă© uma franquia de publicidade em sacos de pĂŁo, com mĂ­dia de grande impacto a baixo custo e conceito sustentĂĄvel. Invista em uma franquia de sucesso com retornos financeiros atraentes.', 2014, 2019, '[\"https://www.youtube.com/watch?v=BpNMYYrOJuo\",\"https://www.youtube.com/watch?v=5YmCHE_aa6g\"]', '2026-04-01 02:00:04.133', '2025-08-05 22:20:25.708', 332, NULL, 1, 2013, 'A franquia Achei no PĂŁo foi criada em SĂŁo JosĂ© do Rio Preto pelo casal de empresĂĄrios Junior Talhaferro e Glaucia Sato. \nEspecializada em publicidade em sacos de pĂŁo por meio de microfranquias, a empresa se destaca por sua estratĂ©gia de mĂ­dia de grande abrangĂȘncia, com um conceito sustentĂĄvel e eficiente. \nCom um baixo custo de operaĂ§ĂŁo, as embalagens de papel sĂŁo uma ferramenta de marketing diferenciada e presente no cotidiano dos brasileiros. A Achei no PĂŁo oferece oportunidades Ășnicas de crescimento e desenvolvimento de negĂłcios para nossos franqueados. \nCom sua estratĂ©gia de mĂ­dia inovadora, a franquia se destaca no mercado publicitĂĄrio e Ă© uma opĂ§ĂŁo acessĂ­vel e democrĂĄtica para quem deseja empreender. \nAlĂ©m disso, a franqueadora oferece suporte completo, treinamento e transferĂȘncia de know-how para garantir o sucesso da unidade. Os franqueados tambĂ©m tĂȘm acesso Ă  Universidade de treinamentos em todas as ĂĄreas da franquia e ao aplicativo Achei no PĂŁo Ofertas, que une a mĂ­dia offline com a mĂ­dia online, potencializando os resultados dos anunciantes. \nCom a Achei no PĂŁo, vocĂȘ pode investir em uma franquia de sucesso com retornos financeiros atraentes e uma proposta sustentĂĄvel e inovadora.', NULL, 'SĂO PAULO', 1, NULL, 54, NULL, NULL, '2026-03-08 20:30:57.431', 'https://franquias.portaldofranchising.com.br/franquia-achei-no-pao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '5700', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
