INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74vq0089eh0sbpr2gvq2', 'INSTITUTO BRASILEIRO DE LĂNGUAS', 'instituto-brasileiro-de-linguas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escola de Idiomas (InglĂȘs, Espanhol, FrancĂȘs, Italiano, AlemĂŁo e JaponĂȘs)', 2006, 2009, '[\"https://www.youtube.com/watch?v=T0zSQYimevo\",\"https://www.youtube.com/watch?v=Os7I683CKgs\",\"https://www.youtube.com/watch?v=mFCyd42GpxQ\",\"https://www.youtube.com/watch?v=Z-YzZnVjpDc\"]', '2026-04-01 02:00:04.156', '2025-08-05 22:20:25.718', 334, NULL, 1, 1992, 'O Instituto Brasileiro de LĂ­nguas (IBL) Ă© uma franquia especializada no ensino de idiomas, com uma trajetĂłria de sucesso e inovaĂ§ĂŁo desde sua fundaĂ§ĂŁo em 1992. Utilizando uma metodologia prĂłpria, baseada em tĂ©cnicas neurolinguĂ­sticas, o IBL se destaca por oferecer um processo de ensino dinĂąmico e moderno, focando na comunicaĂ§ĂŁo efetiva. Desde 2006, adotou o sistema de franchising, ampliando sua presenĂ§a e consolidando sua marca. A franquia oferece um amplo portfĂłlio de idiomas, incluindo inglĂȘs, espanhol, alemĂŁo, francĂȘs, italiano e japonĂȘs, atendendo a diferentes faixas etĂĄrias e necessidades. Com sĂłlida experiĂȘncia dos fundadores e um modelo de negĂłcio estruturado, o IBL representa um investimento seguro e rentĂĄvel. Presente em vĂĄrias regiĂ”es do paĂ­s e na Europa, nosso sistema de franquia Ă© bem estruturado para proporcionar aos franqueados um excelente atendimento e assessoramento. Esta formataĂ§ĂŁo garante Ă  rede um alicerce sĂłlido quanto Ă  implantaĂ§ĂŁo, administraĂ§ĂŁo e gestĂŁo das unidades oferecendo suporte completo aos franqueados, com treinamentos, assistĂȘncia jurĂ­dica, em marketing e gestĂŁo. Os cursos do IBL integram a tecnologia ao aprendizado, permitindo aos alunos estudar tambĂ©m online, trazendo flexibilidade e modernidade ao processo educativo com o portal \"Sem Legenda\" atendendo Ă s demandas modernas de educaĂ§ĂŁo online e ampliando seu alcance. AlĂ©m de oferecer aos nossos alunos CertificaĂ§ĂŁo Internacional. O Instituto Brasileiro de LĂ­nguas (IBL) se diferencia no mercado por sua capacidade de atender a uma ampla gama de pĂșblicos, desde crianĂ§as atĂ© adultos, abrangendo diversas classes sociais. Essa versatilidade permite que a franquia alcance um vasto espectro de alunos, adaptando-se Ă s necessidades e objetivos especĂ­ficos de cada faixa etĂĄria e grupo social. Esse enfoque inclusivo e abrangente Ă© um forte atrativo para franqueados, pois amplia o potencial de mercado e reforĂ§a o compromisso do IBL com a educaĂ§ĂŁo acessĂ­vel e de qualidade para todos. O IBL Ă© mais do que uma franquia, Ă© a oportunidade de investir em um negĂłcio seguro e rentĂĄvel, com suporte completo jurĂ­dico, marketing e gestĂŁo. Transforme seu sonho de empreender no setor educacional em realidade com o Instituto Brasileiro de LĂ­nguas (IBL)! Seja lĂ­der no mercado educacional com uma marca consagrada. Descubra como fazer parte desta rede vitoriosa de ensino de idiomas. Acesse agora e dĂȘ o primeiro passo para um futuro brilhante com o Instituto Brasileiro de LĂ­nguas!', NULL, 'ALAGOAS', 1, NULL, 16, NULL, NULL, '2026-03-08 20:32:10.473', 'https://franquias.portaldofranchising.com.br/franquia-instituto-brasileiro-de-linguas-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
