INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74we008eeh0sxyrz4eve', 'SPEDINI TRATTORIA EXPRESSA', 'spedini-trattoria-expressa', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'A Spedini Ă© um negĂłcio no ramo de alimentaĂ§ĂŁo que agrega agilidade, variedade facilidade na operaĂ§ĂŁo e baixos custos, com a mesma qualidade de uma autentica Trattoria Italiana.', 1994, 1994, '[\"https://www.youtube.com/watch?v=Uq_q3JTs4Xs\"]', '2026-04-01 02:00:04.214', '2025-08-05 22:20:25.743', 339, NULL, 1, 1994, 'Quando a Spedini foi idealizada, o foco foi desenvolver um negĂłcio no ramo de alimentaĂ§ĂŁo que agregasse agilidade, variedade, facilidade na operaĂ§ĂŁo e baixos custos; importantes caracterĂ­sticas do Fast Food, mas com a mesma qualidade de uma autĂȘntica Trattoria Italiana.\nÂ  HĂĄ mais de 25 anos no mercado, a Spedini Trattoria Expressa leva ao consumidor o melhor da culinĂĄria Italiana. Nossas receitas sĂŁo elaboradas com os melhores ingredientes e com o mesmo carinho da comida da ânonnaâ. Nossos molhos sĂŁo produzidos diariamente na prĂłpria unidade, proporcionando o frescor de nossos pratos e fazendo da sua refeiĂ§ĂŁo um momento Ășnico, pois adicionados Ă s massas de grano duro ou massas artesanais alcanĂ§am a combinaĂ§ĂŁo perfeita. \nA empresa detentora da marca e negĂłcio Spedini Ă© formada por profissionais com larga experiĂȘncia que em 1996, buscando novas oportunidades de negĂłcios, decidiram investir na ĂĄrea de alimentaĂ§ĂŁo. \nCom sede prĂłpria instalada em Curitiba desde 2002, a Spedini vem investindo constantemente no desenvolvimento e qualificaĂ§ĂŁo de seus colaboradores para cada vez melhor atender seus franqueados e stakeholders. \nInserida em um mercado competitivo, a Spedini mantĂ©m uma equipe tĂ©cnica para prestar ampla assessoria aos franqueados, dentro do mais elevado grau de profissionalismo e alinhada com as melhores prĂĄticas do mercado. Â  Diferenciais da Marca: Â  O cardĂĄpio tem um mix diferenciado, com produtos de alta qualidade e preparados na prĂłpria loja, mantendo o frescor dos alimentos; Apoio na negociaĂ§ĂŁo para aquisiĂ§ĂŁo do ponto comercial; Acompanhamento da obra para montagem da unidade; Treinamento do franqueado para gestĂŁo do negĂłcio; Apoio na contrataĂ§ĂŁo de colaboradores para inĂ­cio da operaĂ§ĂŁo; Treinamento prĂ©-operacional dos colaboradores; Manuais e receituĂĄrios de execuĂ§ĂŁo e atendimento; Visitas tĂ©cnicas realizadas por profissionais com grande conhecimento em padronizaĂ§ĂŁo de rede e gestĂŁo de negĂłcios.', NULL, 'PARANĂ', 1, NULL, 15, NULL, NULL, '2026-03-08 20:34:58.566', 'https://franquias.portaldofranchising.com.br/franquia-spedini-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74wj008feh0sxyls4e64', 'FICHIPS FOOD', 'fichips-food', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Primeira Franquia de culinĂĄria Inglesa no Brasil.', 2018, 2020, '[\"https://www.youtube.com/watch?v=MOuh3Zs40ns\",\"https://www.youtube.com/watch?v=IDUdxymQL0k\",\"https://www.youtube.com/watch?v=ibtTdR59wt4\",\"https://www.youtube.com/watch?v=ZfFu1awUkI8\"]', '2026-04-01 02:00:04.228', '2025-08-05 22:20:25.747', 340, NULL, 1, 2013, 'A Fichips nasceu em 2013 quando eu estava desempregado e olhei uma foto minha em Londres e me deu um insight de trazer a iguaria inglesa o âFish and Chipsâ para o Brasil, naquela mesma noite, comecei a desenhar o Plano de negĂłcios da Fichips, quando estava prestes a finalizar com os olhos ardendo de sono percebi que jĂĄ tinha clareado o dia, passei toda a noite desenvolvendo. Procurei diversos locais para comer o âfish and chipsâ porĂ©m sĂł encontrado em PUBS no qual teria que pagar para entrar. AlĂ©m de trazer essa iguaria o modelo de negĂłcio seria em um foodtruck que na Ă©poca era uma novidade no Brasil, pois o âboomâ dos foodtrucks sĂł viria 2 anos depois em 2015. Iniciei a operaĂ§ĂŁo em um mini foodtruck em Dezembro de 2013 na regiĂŁo da Berrini em SP, com um manequim vestido o uniforme de um soldado inglĂȘs segurando o cardĂĄpio, cujo nome Ă© âAquilesâ (O Nome Aquiles foi dado devido a um ano antes eu ter rompido o tendĂŁo de aquiles da perna esquerda e tive algumas complicaĂ§Ă”es na cirurgia no qual fiquei 6 meses sem andar) por isso o nome âAquilesâ, hoje continua presente em todas as nossas unidades espalhadas em todo o territĂłrio Nacional, segurando o cardĂĄpio e trouxemos nele uma versĂŁo de auto-atendimento tambĂ©m a nossos franqueados. Em 2014 a Fichips foi considerada entre as 11 empresas que mais inovaram no ramo de alimentaĂ§ĂŁo no Brasil, pela revista Pequenas Empresas & Grandes NegĂłcios.\nÂ \nÂ Participamos dos maiores eventos, Lollapalooza, Maximum Festival, Olimpiadas Tocha Olimpica (Olimpiadas no Brasil, Evento da Premier League (Campeonato Ingles de futebol) taĂ§a no Brasil, entre outros. Fizemos parceria com a maior industria de batatas do PaĂ­s (Bem Brasil). Em 2018 seguindo o plano de negĂłcios, montamos nossa primeira unidade fĂ­sica, uma Loja shopping no coraĂ§ĂŁo de SP, travessa da Av.Paulista, no mesmo ano contratamos um engenheiro de alimentos para iniciar nosso delivery, pois delivery de fritura era um enorme desafio e essa era nossa preocupaĂ§ĂŁo entregar um excelente produto via delivery tambĂ©m, deu muito certo, caixinha estratĂ©gica juntamente com pacote que dizia THANK YOU com o nome do cliente, pois para nĂłs clientes nĂŁo sĂŁo apenas nĂșmeros. E deu muito certo, nossa unidade com apenas 20m2 bombou tanto PDV quanto Delivery que o espaĂ§o passou a ficar pequeno para a operaĂ§ĂŁo de tanta demanda, pois desta unidade em 2019 iniciamos as vendas das franquias. No mesmo ano 2019 participei do programa Shark Tank no qual JoĂŁo ApolinĂĄrio e JosĂ© Carlos Semenzato tiveram interesse na Fichips, posteriormente decidi nĂŁo seguir com os tubarĂ”es pois jĂĄ estavamos com 23 contratos e unidades nos principais Shoppings no final do ano de 2019. Em 2020 venho a pandemia e criamos um modelo de negĂłcio mais enxuto com parceria com a Industria GermĂąnia, (quiosques Fichips e GermĂąnia), com um maquinario e frita sozinho os alimentos sem fumaĂ§a e sem cheiro, fritadeira com sistema de exaustĂŁo prĂłprio, crescemos 300% na pandemia, inauguramos quiosques em Shoppings e em redes de mercados Atacadistas. Inclusive temos um showroom do quiosque na fĂĄbrica da GermĂąnia em Vinhedo\\SP. Contamos com 60 contratos de franquia no Brasil e 1 em Portugal Contamos com 5 modelos de negĂłcio: LOJA SHOPPING, LOJA RUA\\PUB, LOJA CONTAINER, LOJA QUIOSQUE e MODELO DELIVERY (todas as operaĂ§Ă”es\\modelo possuem Delivery)', NULL, 'SĂO PAULO', 1, NULL, 26, NULL, NULL, '2026-03-08 20:36:05.302', 'https://franquias.portaldofranchising.com.br/franquia-fichips-food/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '109000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
