INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74x7008keh0s1j9l3bnq', 'MICROVENDING', 'microvending', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Vending Machines pequenas', 2023, 2023, NULL, '2026-04-01 02:00:04.283', '2025-08-05 22:20:25.772', 345, NULL, 1, 2023, '', NULL, 'PARANĂ', 1, NULL, 1, NULL, NULL, '2026-03-08 20:45:43.641', 'https://franquias.portaldofranchising.com.br/franquia-microvending/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '27500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74xd008leh0s03laauz6', 'ĂTICAS MERCADĂTICA', 'oticas-mercadotica', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'ComĂ©rcio de produtos Ăłpticos: lentes, armaĂ§Ă”es e Ăłculos solares. Com 30 anos de experiĂȘncia no setor.', 2012, 2013, '[\"https://www.youtube.com/watch?v=81v8NDREB4Q\"]', '2026-04-01 02:00:04.297', '2025-08-05 22:20:25.777', 346, NULL, 1, 1991, 'A Franquia MercadĂłtica Ă© um modelo de negĂłcio muito interessante para novos empreendedores, pois permite o uso de uma marca jĂĄ consolidada, testada e padronizada, diminuindo os riscos e problemas de administraĂ§ĂŁo que podem surgir decorrentes de um novo negĂłcio. \nEm poucas palavras: O sucesso serĂĄ compartilhado pelo franqueado e pelo franqueador.\nÂ  TEMOS TODA A EXPERIĂNCIA QUE VOCĂ PRECISA \nTenha a perspectiva de sucesso de um negĂłcio jĂĄ experimentado, com marca consagrada no mercado que mais cresce no Brasil. \nCom acesso ao planejamento e pesquisas, orientaĂ§Ă”es e aperfeiĂ§oamentos sob a responsabilidade do franqueador, vocĂȘ estarĂĄ pronto para abrir a sua loja.\nÂ  +40 lojas,Â +30 cidades presentes,Â +8 estados,Â +150 colaboradores \nBenefĂ­cios: 1 - 30 anos de experiĂȘncia em Ăłptica:Â  \nIsso mesmo! A MercadĂłtica existe desde 1991 e jĂĄ tem toda a experiĂȘncia do setor Ăłptico bem consolidada. \nConhecemos todas as informaĂ§Ă”es, estratĂ©gias, procedimentos e produtos desse setor. \nSem contar que, nesses 30 anos jĂĄ conquistamos a confianĂ§a de milhares de clientes que atestaram a qualidade de nossos produtos, atendimento e marca.Â \nÂ  2 - Franquia desde 2012: \nA MercadĂłtica se iniciou no Franchising em 2012, seguindo todo o processo de formataĂ§ĂŁo exigido pela legislaĂ§ĂŁo brasileira. \nTemos todo o conhecimento no setor de Franchising que Ă© necessĂĄrio para guiar vocĂȘ no processo de se converter em um Franqueado. \nAlĂ©mÂ  disso, somos parte da ABF (AssociaĂ§ĂŁo Brasileira de Franchising) e jĂĄ conquistamos a confianĂ§a de nossos Franqueados graĂ§as ao sucesso que tiveram com a MercadĂłtica. \nTodos os nossos Franqueados possuem mais de uma loja.\nÂ  3 - Acesso aos diretores e fundadores da marca:Â  \nApesar da Franquia MercadĂłtica contar com uma equipe especializada para a implantaĂ§ĂŁo de Franquias, a marca se destaca por ser uma empresa integrada e na qual os diretores participam de forma ativa em todos os processos, incluindo a implantaĂ§ĂŁo e supervisĂŁo de Franquias.Â \nÂ  4 - Treinamento e capacitaĂ§ĂŁo de equipes de forma constante:Â  \nDurante a implantaĂ§ĂŁo de Franquia acontece o treinamento do Franqueado e de sua equipe de vendas. \nO treinamento aborda todos os assuntos relacionados com o setor Ăłptico, tĂ©cnicas de vendas, marketing e boas prĂĄticas do varejo. \nAlĂ©m disso, duas vezes por ano, acontece o FĂłrum de Franqueados MercadĂłtica, onde todos os colaboradores da rede participam de forma gratuita e sĂŁo atualizados sobre diversos assuntos relacionados com o setor Ăłptico.Â \nÂ  5 -Â  Â LaboratĂłrio prĂłprio:Â  \nA MercadĂłtica possui um laboratĂłrio prĂłprio de montagem e surfaĂ§agem. \nDesta forma, nĂŁo dependemos integralmente de terceiros e mantemos o tempo de entrega ao cliente final dentro de altos padrĂ”es de satisfaĂ§ĂŁo. \nA maioria de nossas entregas acontecem antes do tempo previsto. Ainda, permite que o controle de qualidade seja feito de forma mais rigorosa e os produtos sejam entregues sem defeitos.\nÂ  6 - Parcerias com laboratĂłrio e fornecedores:Â  \nAlĂ©m do laboratĂłrio prĂłprio, a MercadĂłtica tambĂ©m tem parceria com os maiores fornecedores do mercado Ăłptico como a Essilor, Zeiss, Hoya, Ray-Ban, Vogue, Hugo Boss, Colcci, Mormaii. Desta forma, temos acesso a uma diversidade de armaĂ§Ă”es e lentes oftĂĄlmicas da mais alta gama do mercado e com condiĂ§Ă”es diferenciadas para os nossos Franqueados.Â \nÂ  7 - Suporte:Â  \nA Franquia MercadĂłtica possui uma equipe altamente capacitada de Suporte ao Franqueado que fica disponĂ­vel para auxiliar Franqueados e Colaboradores durante as operaĂ§Ă”es diĂĄrias. \nAssim como mediar o contato entre lojas e fornecedores, a fim de agilizar procedimentos dentro da rede.', NULL, 'BAHIA', 1, NULL, 35, NULL, NULL, '2026-03-08 20:46:10.865', 'https://franquias.portaldofranchising.com.br/franquia-oticas-mercadotica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
