INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74xq008neh0swtcjpe6u', 'DORTPREV', 'dortprev', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'Medicina Ocupacional, Check-Up MĂ©dico e SeguranĂ§a no Trabalho', 2012, 2020, NULL, '2026-04-01 02:00:04.319', '2025-08-05 22:20:25.790', 348, NULL, 1, 2002, 'O caminho certo para um grande negocio! \nA DortPrev Medicinal Ocupacional e SeguranĂ§a no Trabalho Ă© exatamente o que vocĂȘ procura para um investimento em franquia. Atuando num segmento que vem se expandindo pela necessidade e obrigatoriedade do mercado. Podendo ainda ser trabalhada com vĂĄrias alternativas e flexibilizaĂ§ĂŁo de negĂłcios e serviĂ§os. \nSendo ainda mais atrativa por pertencer a um segmento de baixa concorrĂȘncia. E ainda ser de fĂĄcil implantaĂ§ĂŁo. \nAlĂ©m disso, outros fatores contribuem atrair o empreendedor para a rede de franquias DORTPREV; \n- ServiĂ§os especializados prestados por profissionais capacitados e especialmente treinados para atender as necessidades dos clientes;- PadronizaĂ§ĂŁo das unidades nos projetos arquitetĂŽnicos e de comunicaĂ§ĂŁo visual, interna e externa de nossa rede; \n- Possibilidade de realizar todos os exames necessĂĄrios a medicina ocupacional em qualquer uma de nossas unidades; \n- AtenĂ§ĂŁo dedicada Ă  manutenĂ§ĂŁo da qualidade do atendimento prestado pela rede, atravĂ©s de monitoramento ON LINE, via internet dos serviĂ§os realizados em nossas unidades; \n- Sistema prĂłprio desenvolvido, totalmente digital que permite a entrega dos resultados pela internet; e parceria estratĂ©gica com o maior LaboratĂłrio de Exames ClĂ­nicos e Laboratoriais do paĂ­s (Sergio Franco). \nPor todos estas caracterĂ­sticas a Franquia DortPrev Ă© garantia de sucesso. \nA DortPrev, hoje pertencente ao DORTGROUP, comeĂ§ou sua histĂłria de sucesso a mais de uma dĂ©cada. Tendo sua primeira criada na Cidade de Duque de Caxias, Rio de Janeiro. \nHoje a DortPrev Ă© referĂȘncia em todo paĂ­s no segmento em que atua. Sendo sinĂŽnimo de eficiĂȘncia e competĂȘncia na ĂĄrea de Medicinal Ocupacional e SeguranĂ§a no Trabalho. \nAtualmente contamos com 3 unidades de negĂłcio e mais 2 em implantaĂ§ĂŁo. SĂŁo mais de 100 funcionĂĄrios. \nA DortBusiness, tem a missĂŁo de levar ao franquiado DortPrev toda sua experiĂȘncia em anos de atuaĂ§ĂŁo no mercado. Sendo responsĂĄvel por todo o apoio na aquisiĂ§ĂŁo, abertura e operaĂ§ĂŁo da sua franquia DortPrev.  \nFale com a DortBusiness \nÂ Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â  FaĂ§a parte dessa histĂłria de sucesso. \nÂ Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â Â  Juntos vamos ultrapassar suas expectativas.', NULL, 'RIO DE JANEIRO', 1, NULL, 7, NULL, NULL, '2026-03-08 20:48:11.453', 'https://franquias.portaldofranchising.com.br/franquia-dortprev/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74y1008peh0s1z8h1jvw', 'LAUNDROMAT', 'laundromat', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Lavanderia', 'Lavanderia Self-Service 100 % automĂĄtica.', 1987, 2010, '[\"https://www.youtube.com/watch?v=lpo2uyKvUkA\"]', '2026-04-01 02:00:04.330', '2025-08-05 22:20:25.801', 350, NULL, 1, 1987, 'A marca mais inovadora do segmento de Lavanderias. A inovaĂ§ĂŁo faz parte do nosso DNA. Fomos os pioneiros do segmento de lavanderias self service na AmĂ©rica Latina. Os primeiros a viabilizar lojas-contĂȘineres, ampliando assim as possibilidades de pontos comerciais e proporcionando economia no custo de ocupaĂ§ĂŁo. Estamos inovando mais uma vez, com as lojas 100% automatizadas. Um modelo ainda mais simples de gestĂŁo, com o melhor modelo do mercado, pois possibilita a ampliaĂ§ĂŁo e flexibilidade na configuraĂ§ĂŁo da unidade, conforme os objetivos do franqueado. AlĂ©m da inovaĂ§ĂŁo, somos tambĂ©m a marca mais consolidada do setor, com mais de 200 unidades em todo o territĂłrio nacional e uma experiĂȘncia e conhecimento do mercado de lavanderias acumulados nos Ășltimos 40 anos.', NULL, 'RIO DE JANEIRO', 1, NULL, 318, NULL, NULL, '2026-03-08 20:49:39.987', 'https://franquias.portaldofranchising.com.br/franquia-laundromat-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '85000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74y6008qeh0s6teb6tnj', 'UNITED INSTITUTE', 'united-institute', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Franquia de escola de inglĂȘs para adultos, com muito mais tecnologia e diferenciais como horĂĄrios de aula flexĂ­veis, material online interativo e equipe comercial para captaĂ§ĂŁo de alunos.', 2008, 2012, NULL, '2026-04-01 02:00:04.340', '2025-08-05 22:20:25.807', 351, NULL, 1, 2008, 'VocĂȘ estĂĄ em busca em um bom negĂłcio e vĂȘ no modelo de franquia uma oportunidade de nĂŁo comeĂ§ar do zero? Nossa rede de franquias de escola de idiomas United Idiomas tem 10 anos de mercado e os sĂłcios-fundadores jĂĄ possuem mais de 27 anos de experiĂȘncia no segmento de idiomas e estĂŁo Ă  frente da operaĂ§ĂŁo, comprometidos com a rede e seus franqueados. A United Idiomas conta com 26 unidades espalhadas pelo Brasil, sendo 25 franquias e uma unidade prĂłpria e estĂĄ em plena expansĂŁo. PossuĂ­mos um modelo de negĂłcio consolidado, testado e aprovado por mais de 70 mil alunos que jĂĄ estudaram na rede. TambĂ©m temos a chancela da AssociaĂ§ĂŁo Brasileira de Franquias, a ABF, dando ainda mais credibilidade Ă  marca. Ă muito fĂĄcil ingressar no mercado de idiomas quando falamos de uma rede forte, que Ă© pioneira em tecnologia, e estĂĄ Ă  frente neste quesito dos principais players do mercado. A United Idiomas se antecipa Ă s tendĂȘncias tecnolĂłgicas, oferecendo recursos interativos, desde aplicativos para os alunos agendarem as aulas pela internet, atĂ© visualizar a evoluĂ§ĂŁo do curso e ter acesso aos mĂłdulos online de acompanhamento das aulas presenciais. E o resultado para seu investimento Ă© rĂĄpido! Mas claro, depende da sua dedicaĂ§ĂŁo como franqueado. O melhor Ă© que temos uma equipe de suporte pronta para te ajudar desde a escolha do ponto ideal, implantaĂ§ĂŁo da sua unidade e acompanhamento no dia a dia buscando sempre os melhores resultados.  Temos uma equipe comercial que faz a captaĂ§ĂŁo de alunos para sua unidade! \nVocĂȘ tambĂ©m pensou que alĂ©m do negĂłcio mudar sua via, pode mudar a vida de outras pessoas? Ter uma franquia com propĂłsito Ă© fundamental! Oferecemos cursos para adultos que querem se desenvolver profissionalmente e que para crescer na carreira precisam do idioma. Nossos alunos tambĂ©m querem aproveitar novas oportunidades culturais, viagens, conteĂșdos em inglĂȘs para desenvolvimento de teses de especializaĂ§ĂŁo, por exemplo, ou acompanhar as principais inovaĂ§Ă”es e tendĂȘncias mundiais, e muitos conteĂșdos em diversas ĂĄreas profissionais sĂŁo disponibilizados apenas em inglĂȘs. E nĂłs participamos da vida dos alunos atravĂ©s deste crescimento por meio do idioma, oferecendo um mĂ©todo de aprendizagem rĂĄpido e dinĂąmico, perfeito para o dia a dia do pĂșblico adulto que precisa falar fluentemente, em menos tempo que os mĂ©todos tradicionais.', NULL, 'SĂO PAULO', 1, NULL, 20, NULL, NULL, '2026-03-08 20:50:18.015', 'https://franquias.portaldofranchising.com.br/franquia-united-institute-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '45000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
