INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74ym008teh0s68mnc7if', 'CAFĂ DU CENTRE', 'cafe-du-centre', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Cafeteria e doceria', 2015, 2018, '[\"https://www.youtube.com/watch?v=BxWnhghjvs0\",\"https://www.youtube.com/watch?v=5jhqgO3CIpg\",\"https://www.youtube.com/watch?v=qgp_N8uCfN4\",\"https://www.youtube.com/watch?v=VnZ216uOPmk\"]', '2026-04-01 02:00:04.360', '2025-08-05 22:20:25.823', 354, NULL, 1, 2014, 'Somos duas irmĂŁs, Paula FotĂłgrafa e Administradora e Bruna, PsicĂłloga. Nossa histĂłria comeĂ§a assim: CostumĂĄvamos nos finais de tarde nos sentar em alguma cafeteria para conversar sobre o nosso dia. Com isso aprendemos a tomar e apreciar um bom cafĂ©!Â  \nComo nĂŁo se apaixonar por essa bebida tĂŁo grave, quente e peculiar?Â  \nAssim nossos encontros casuais passaram -se a tornar um hĂĄbito diĂĄrio. Por nossa cidade apresentar um dĂ©ficit de um bom lugar para tal, tĂ­nhamos que nos deslocar para cidades vizinhas. \nEra final de mais uma temporada de verĂŁo, e disponibilizĂĄvamos de um pequeno espaĂ§o comercial, e porque nĂŁo uma cafeteria? As dĂșvidas eram muitas. A vontade de empreender e Ă  uma possĂ­vel perda das nossas ocupaĂ§Ă”es profissionais. \nDevido as nossas profissĂ”es nĂŁo terĂ­amos disponibilidade para se dedicar integralmente a ao novo negĂłcio, e o desafio de trazer uma proposta diferenciada para uma cidade de pouco mais de 50.000 habitantes. \nNossa proposta era o diferente, o clĂĄssico, a excelĂȘncia e um novo conceito de cafeteria no Brasil.Â  \nHoje o CafĂ© du Centre Ă© referĂȘncia de qualidade, luxo e sofisticaĂ§ĂŁo, trata-se de um ambiente Ășnico, com caracterĂ­sticas prĂłprias, receitas exclusivas, arte na apresentaĂ§ĂŁo dos produtos com padrĂŁo Europeu. Com lojas no Brasil e no exterior. \nNossos Clientes desfrutam de uma decoraĂ§ĂŁo inspirada na charmosa Paris {FranĂ§a} e tambĂ©m uma trilha sonora francesa. \nHoje conseguimos manter nossas profissĂ”es e a cafeteria, estamos realizadas, encantadas, pois essa bebida tĂŁo especial: o cafĂ©, tornou-se arte e protagonista do nosso pequeno e aconchegante espaĂ§o.', NULL, 'SANTA CATARINA', 1, NULL, 13, NULL, NULL, '2026-03-08 20:52:12.842', 'https://franquias.portaldofranchising.com.br/franquia-cafe-du-centre/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
