INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74z7008xeh0stweem321', 'FIRST CLASS', 'first-class', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Cama, Mesa, Banho e Sonhos.', 2008, 2010, NULL, '2026-04-01 02:00:04.402', '2025-08-05 22:20:25.843', 358, NULL, 1, 2000, 'A First Class jĂĄ Ă© a 2ÂȘ maior empresa de cama mesa e banho do paĂ­s. \nA First Class nasceu da uniĂŁo e vocaĂ§ĂŁo empresarial de seus dois sĂłcios, AndrĂ© Pivetti e Orlando Pedro.\nAmbos com histĂłria de vidas bem distintas, mas que resultou em uma parceria de sucesso. \nCom 14 anos no mercado CAMEBA - cama, mesa e banho, a carioca First ClassÂź possui hoje um market share de 155* operaĂ§Ă”es disseminadas pelo Brasil, presente em 20 estados e 62 cidades e uma internacionalizaĂ§ĂŁo da marca, em Luanda-Angola. \nA parceria resultou em novas lojas, mas o sucesso de fato sĂł se concretizou depois de alguns anos de muito trabalho e adaptaĂ§Ă”es as exigĂȘncias do mercado. As oscilaĂ§Ă”es econĂŽmicas do paĂ­s e as dificuldades de dar uniformidade Ă  rede e de contrabalanĂ§ar os custos foram o maior desafio. VĂĄrias mudanĂ§as foram feitas para impulsionar os negĂłcios atĂ© formar um grupo financeiramente equilibrado e comercialmente lucrativo. \nCom isso, a sociedade que atĂ© entĂŁo comportava a mesma supra mencionada, em 2014, com a saĂ­da do sĂłcio Orlando Ferreira, integra-se a sociedade junto ao AndrĂ© Pivetti, a figura atual do seu novo sĂłcio, SĂ©rgio Lombardi, cuja experiĂȘncia tĂȘxtil Ă© de aproximadamente 20 anos administrando a fĂĄbrica da Bouton, com sede em Brusque â SC, licenciada e exclusiva da marca Buettner do segmento cama, banho e importados e vem a somar e muito nessa nova empreitada.Â Â  Antes somente com um olhar fabril, agora alinha essa estratĂ©gia comercial com os pontos de venda, formando uma parceria estratĂ©gica de sucesso. \nQualidade, inovaĂ§ĂŁo, democratizaĂ§ĂŁo, preĂ§o e atendimento sĂŁo os nossos diferenciais e certamente o que garante a posiĂ§ĂŁo de destaque entre as melhores do segmento. \nAlĂ©m de produtos das principais indĂșstrias de marcas nacionais, cada vez mais a First Class investe na fabricaĂ§ĂŁo prĂłpria e na importaĂ§ĂŁo de produtos exclusivos. \nConsiderando perspectivas de expansĂŁo para 2014  O sucesso da marca tem sido reconhecido em diversas pesquisas de varejo com renome nacional:  Em 2010 associou-se a ABF â AssociaĂ§ĂŁo Brasileira de Franchising; \nEm 2012 e 2013 foi reconhecida por adotar as melhores prĂĄticas de gestĂŁo no varejo de franquia. \nEm 2012 e 2013 foi eleita, pelo voto do consumidor, a melhor loja de Cama Mesa e banho do Brasil.  Em 2012 e 2013 Participou pelo 3Â° ano da pesquisa feita pela PEGN â Pequenas Empresas e Grandes NegĂłcios, obtendo destaque de maior nota de satisfaĂ§ĂŁo de franqueado comparado a diversas marcas de renome no varejo nacional.  Em 2013 e 2014 Participou pelo 4Â° ano da pesquisa feita pelaÂ  PEGN â Pequenas Empresas e Grandes NegĂłcios, sendo elegida a 1ÂȘ no ranking Casa, DecoraĂ§ĂŁo e Presente e mais uma vez foi destaque de maior nota de satisfaĂ§ĂŁo de franqueado comparado a diversas marcas de renome no varejo nacional.  MissĂŁo\nEncantar o cliente, fazendo por ele mais do que ele espera. Democratizar o consumo, trazendo sempre os melhores produtos pelos menores preĂ§os. Permitir a todas as classes o acesso aos seus sonhos deÂ qualidade dos produtos de cama, mesa e banho.  VisĂŁo\nTornar-se a melhor e maior empresa de cama, mesa e banho, sendo reconhecida por vender produtos de qualidade pelos menores preĂ§os do Brasil.  PĂșblico Alvo\nClasse: A, B e C\nDemocratizaĂ§ĂŁo de consumo. Permitindo a todas as classes o acesso a produtos de qualidade e preĂ§o.\n90% Feminino / 10% Masculino Â  Â  âSonhos...\nTransformam vidas. Criam mundos. Acredite nos seus sonhos.\nAlimente-se deles. Sonhos criaram nossa histĂłria.\nTransformaram nossa vida. âCom fĂ© e forĂ§a sonhos se realizam.â\nFirst Class.', NULL, 'SANTA CATARINA', 1, NULL, 230, NULL, NULL, '2026-03-08 20:54:13.455', 'https://franquias.portaldofranchising.com.br/franquia-first-class-artigos-para-o-lar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zc008yeh0s2jzjrisy', 'MR CHEFF GASTRONOMIA', 'mr-cheff-gastronomia', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Fast Food, com excelĂȘncia em pratos executivos e porĂ§Ă”es', 2018, 2020, '[\"https://www.youtube.com/watch?v=JIu1_i9oe5c\"]', '2026-04-01 02:00:04.413', '2025-08-05 22:20:25.849', 359, NULL, 1, 2011, 'O MR. CHEFF GASTRONOMIA Ă© uma marca com cardĂĄpio variado que oferece as mais diversas opĂ§Ă”es de pratos executivos, massas e porĂ§Ă”es que sĂŁo produzidas uma a uma diariamente, com cuidado e dedicaĂ§ĂŁo em suas receitas. Nascemos devido a falta que o fundador sentiu Ă  Ă©poca de ter no mercado opĂ§Ă”es de pratos que ofereciam qualidade e quantidade por um custo acessĂ­vel que atendesse a todos. \nDesse modo, o objetivo da empresa sempre foi prestar um excelente serviĂ§o que oferecesse uma memorĂĄvel experiĂȘncia gastronĂŽmica a todas as classes sociais, prezando acima de tudo a satisfaĂ§ĂŁo de seus consumidores e diante do cenĂĄrio promissor da empresa, em 2017 iniciamos o plano de expansĂŁo da marca e hoje marcamos presenĂ§a em 3 estados (SĂŁo Paulo, ParanĂĄ e Santa Catariana).', NULL, 'PARANĂ', 1, NULL, 19, NULL, NULL, '2026-03-08 20:55:55.253', 'https://franquias.portaldofranchising.com.br/franquia-mr-cheff-gastronomia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
