INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zo0090eh0s7jsu98ga', 'BRCONDOS', 'brcondos', NULL, 'Casa e ConstruĂ§ĂŁo', 'ServiĂ§os e ImobiliĂĄrias', 'AdministraĂ§ĂŁo de condomĂ­nios, cobranĂ§a extrajudicial, seguranĂ§a eletrĂŽnica, automaĂ§ĂŁo predial, seguros.', 2013, 2019, '[\"https://www.youtube.com/watch?v=SLArrkUFobE\"]', '2026-04-01 02:00:04.436', '2025-08-05 22:20:25.860', 361, NULL, 1, 2013, 'A BRCondos Franchising Ă© uma empresa brasileira especializada na administraĂ§ĂŁo de condomĂ­nios, oferecendo soluĂ§Ă”es inovadoras e tecnolĂłgicas para a gestĂŁo condominial. Fundada em 2013, a empresa tem como missĂŁo tornar a vida em condomĂ­nios mais transparente, segura e eficiente, posicionando-se sempre Ă  frente do seu tempo com qualidade e tecnologia. HistĂłrico e ExpansĂŁo Desde sua fundaĂ§ĂŁo, a BRCondos tem se destacado no mercado condominial brasileiro. Com sede em Joinville, Santa Catarina, a empresa expandiu sua atuaĂ§ĂŁo para mais de 150 cidades no Brasil, consolidando-se como a maior rede de administradoras de condomĂ­nios do paĂ­s. Modelo de NegĂłcio A BRCondos opera por meio de um modelo de franquias, permitindo que empreendedores locais se tornem franqueados e ofereĂ§am os serviĂ§os da marca em suas regiĂ”es. Esse modelo de negĂłcio Ă© sustentado por inovaĂ§ĂŁo, integrando central, franqueados, sĂ­ndicos e condĂŽminos, com foco em gerar resultados enquanto a operaĂ§ĂŁo Ă© realizada pela central. ServiĂ§os Oferecidos A BRCondos oferece uma ampla gama de serviĂ§os para a administraĂ§ĂŁo de condomĂ­nios, incluindo: AdministraĂ§ĂŁo Financeira: GestĂŁo de contas a pagar e a receber, prestaĂ§ĂŁo de contas transparente com lanĂ§amentos diĂĄrios e acesso a todos os boletos e comprovantes. Central de Relacionamento: Atendimento aos condĂŽminos via telefone ou web, resoluĂ§ĂŁo de questĂ”es fiscais e tributĂĄrias, e disponibilizaĂ§ĂŁo de informaĂ§Ă”es de forma transparente atravĂ©s do BRCondosOnline. ServiĂ§os de CobranĂ§a: GestĂŁo profissional e eficaz na reduĂ§ĂŁo da inadimplĂȘncia condominial, incluindo conta individual automatizada, previsĂŁo fixa para mais seguranĂ§a orĂ§amentĂĄria e setor exclusivo para negociaĂ§ĂŁo extrajudicial de inadimplentes. BRCondos Online: Sistema e aplicativo que integra o condomĂ­nio, facilitando a comunicaĂ§ĂŁo entre condĂŽminos, sĂ­ndico e administradora, com funcionalidades como abertura de chamados, registro de ocorrĂȘncias, enquetes, comunicados e acesso a documentos e contratos. CalendĂĄrio de Eventos & Reservas: Controle eficiente das reservas de ĂĄreas comuns via sistema, com visualizaĂ§ĂŁo de calendĂĄrio, estipulaĂ§ĂŁo de valores para aluguel e bloqueio de acesso para condĂŽminos inadimplentes. BRCondos AutomaĂ§ĂŁo: SoluĂ§Ă”es para identificaĂ§ĂŁo de pessoas por reconhecimento facial, biometria, chaveiros de proximidade ou QR-Code, acessos de veĂ­culos registrados por adesivos veiculares ou controles remotos, seguranĂ§a no recebimento de visitantes e prestadores de serviĂ§o, e monitoramento completo do condomĂ­nio atravĂ©s de gestĂŁo em tempo real das informaĂ§Ă”es do controle de acesso. Departamento Pessoal: ServiĂ§o especializado de Recursos Humanos para contrataĂ§ĂŁo, controle e relatĂłrios, admissĂŁo e registro, processamento de ponto, processamento de folha, gestĂŁo de benefĂ­cios, recolhimento de impostos e encargos sociais, controle e emissĂŁo de fĂ©rias, rescisĂŁo e outros, gerenciando o quadro de funcionĂĄrios da unidade e dos condomĂ­nios da rede de forma profissional.', NULL, 'SANTA CATARINA', 1, NULL, 85, NULL, NULL, '2026-03-08 20:56:46.451', 'https://franquias.portaldofranchising.com.br/franquia-brcondos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
