INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza74zz0092eh0swi0rvfrk', 'AĂAĂ BEAT', 'acai-beat', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Especializado em creme de aĂ§ai com acompanhamentos', 2011, 2013, '[\"https://www.youtube.com/watch?v=tu-8doxItVM\",\"https://www.youtube.com/watch?v=oZAipflOG4M\",\"https://www.youtube.com/watch?v=BWfhmUYpRUg\"]', '2026-04-01 02:00:04.457', '2025-08-05 22:20:25.871', 363, NULL, 1, 2011, 'A Marca O mercado de aĂ§aĂ­ vem crescendo no Brasil e no mundo, e a rede de Franquia AĂ§aĂ­ Beat acompanha esta tendĂȘncia graĂ§as Ă  qualidade de seus produtos, somada a um projeto arquitetĂŽnico prĂĄtico e inovador de suas unidades e a uma comunicaĂ§ĂŁo interativa com o seu pĂșblico. Uma marca diferenciada, antenada ao seu pĂșblico, que foge da mesmice e cai no gosto das pessoas. Traz o que Ă© bom, saudĂĄvel, gostoso e o melhor âdo seu jeitoâ. Esse Ă© o AĂ§aĂ­ Beat, a franquia mais gostosa de aĂ§aĂ­ do mundo! A HistĂłria ApĂłs morar alguns anos na Europa, trabalhar nos melhores restaurantes da Espanha e se pĂłs-graduar em GestĂŁo de Alimentos y Bebidas pela Escuela de Hosteleria y Turismo de Valencia, o empresĂĄrio JĂșnior Marques volta ao Brasil com a mente aberta e disposto a encontrar nos alimentos um ramo prĂłspero e lucrativo. Quando conheceu o aĂ§aĂ­, um creme muito encontrado jĂĄ em todas as cidades brasileiras mas pouco explorado de forma profissional viu uma oportunidade e apĂłs muitas pesquisas criou a marca AĂ§aĂ­ Beat. A empresa teve inĂ­cio de suas atividades em julho do ano de 2009 com uma loja na cidade de ViĂ§osa - MG e um ano depois a aquisiĂ§ĂŁo da fĂĄbrica de creme de aĂ§aĂ­ (2010) foi o pontapĂ© inicial para a formataĂ§ĂŁo da franquia. Em 2011 com um pequeno quiosque na cidade de Ipatinga - MG deu-se a abertura de sua segunda unidade e a partir de entĂŁo nĂŁo parou mais de crescer. Ao final de 2013, com apenas 2 anos de existĂȘncia, a rede AĂ§aĂ­ Beat tinha 18 unidades abertas em 5 estados diferentes. Atualmente a rede engloba 01 fĂĄbrica, 02 unidades prĂłprias e 37 franqueadas, estĂĄ presente em 31 cidades em 09 estados brasileiros, incluindo a regiĂŁo nordeste e centro-oeste. Em 2016, a meta Ă© finalizar o ano com 70 unidades em operaĂ§ĂŁo. O produto Com a formaĂ§ĂŁo em gastronomia, a experiĂȘncia internacional adquirida junto a Ferran Adri (um dos chefs mais prestigiados do mundo) e a exigĂȘncia do paladar, JĂșnior liderou o processo de desenvolvimento de um creme de aĂ§aĂ­ de sabor incomparĂĄvel, leve e que mantĂ©m as propriedades naturais da fruta cultivada no ParĂĄ. Ele explica que o creme do AĂ§aĂ­ Beat pode ser consumido puro ou com adicionais da melhor qualidade, jĂĄ que a rede busca sempre as melhores marcas e fornecedores para esses opcionais. âCom essa mistura de produtos de sucesso, o cliente sempre sairĂĄ satisfeito!â - JĂșnior Marques Recentemente foi lanĂ§ado os smoothies AĂ§aĂ­ Beat. SĂŁo trĂȘs opĂ§Ă”es de smoothies, que consistem em aĂ§aĂ­ batido com frutas e sucos, aumentando assim a gama de produtos da rede.', NULL, 'SĂO PAULO', 1, NULL, 31, NULL, NULL, '2025-09-09 09:51:06.000', 'https://franquias.portaldofranchising.com.br/franquia-acai-beat-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75040093eh0s2c86q2gn', 'RISE MARTIAL ARTS CLUB', 'rise-martial-arts-club', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Escola de artes marciais para todas as idades. Fundada em fev/2018 a RISE CLUB possui + 3.000 alunos e seis unidades, tĂȘm como propĂłsito cuidar da saĂșde fĂ­sica, emocional e social de nossos alunos', 2023, 2023, '[\"https://www.youtube.com/watch?v=yBFgx-SAC1I\",\"https://www.youtube.com/watch?v=dpD0WfHywnI\",\"https://www.youtube.com/watch?v=K1cYmNKi4NE\",\"https://www.youtube.com/watch?v=zxjDpPtDnvQ\"]', '2026-04-01 02:00:04.467', '2025-08-05 22:20:25.877', 364, NULL, 1, 2018, 'A Rise Club foi fundada em fevereiro 2018 por dois amigos que se conheceram no tatame e depois de duas dĂ©cadas tendo a arte marcial como uma comunidade perceberam que mesmo atuando em outras ĂĄreas profissionais ao longo de suas vidas, sempre estiveram o tatame como um lugar de pertencimento. Quando se formaram faixas pretas observando o crescimento do pĂșblico que procuravam arte marcial como qualidade de vida, vendo as academia com pouca estrutura e dificuldade de gestĂŁo, enxergaram uma oportunidade de trazer um novo conceito de artes marciais para todas as idades de 3 a 80 anos e NĂO com foco em competiĂ§ĂŁo. Hugo Veras com +30 anos engenharia com a PSA Ă© responsĂĄvel pelo estudo de viabilidade estrutural, implantaĂ§ĂŁo e manutenĂ§ĂŁo das unidades. Carlos Ferraz foi sĂłcio por + 8 anos de um grupo educacional que montou +50 escolas no Brasil sendo responsĂĄvel pela gestĂŁo, expansĂŁo e trouxe o conceito de governanĂ§a para Rise. Fechando o conselho temos hoje Tomaz Alcoforado responsĂĄvel pelo corpo jurĂ­dico e advisor com a SRAB Advogados. AlĂ©m disso, a Rise conta hoje com escritĂłrio da V4 Company na sua estrutura de growth marketing Atualmente com 4 unidades prĂłprias, sendo 1 jĂĄ com modelo franquias + 2.000 alunos ativos a Rise iniciou seu processo expansĂŁo iniciando processo seletivo para franquias. Primeiro semestre 2025 serĂĄ inaugurada a 5 unidade, tambĂ©m no modelo franquia. Com taxa de lucratividade atĂ© 40% , breakeven 6 meses e payback entre 24 a 36 meses a Rise se apresenta como uma excelente oportunidade negĂłcio, oferecendo um mercado promissor saĂșde, negĂłcio sĂłlido e escalĂĄvel com carteira de recebĂ­veis e uma holding que faz toda gestĂŁo e estrutura da unidade', NULL, 'PERNAMBUCO', 1, NULL, 6, NULL, NULL, '2026-03-08 20:58:40.910', 'https://franquias.portaldofranchising.com.br/franquia-rise-martial-arts-club/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
