INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza750v0098eh0sg5648k42', 'IMAGINARIUM', 'imaginarium', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'ARTIGOS PARA PRESENTES E DECORAĂĂO', 1990, 1993, '[\"https://www.youtube.com/watch?v=O6Vf5uWtbXY\",\"https://www.youtube.com/watch?v=ckXCETxHZSc\",\"https://www.youtube.com/watch?v=hGiA6A4Y5iA\",\"https://www.youtube.com/watch?v=0Aemu7--Ffg\",\"https://www.youtube.com/watch?v=Na1CB__ZlbQ\"]', '2026-04-01 02:00:04.523', '2025-08-05 22:20:25.903', 369, NULL, 1, 1987, 'Transformar todo dia pra melhor: essa Ă© a missĂŁo da Imaginarium, empresa brasileira criada em 1991.Â Â  Tudo comeĂ§ou na dĂ©cada de oitenta, quando uma arquiteta e um mĂ©dico decidiram que passariam mais tempo com as duas filhas pequenas, acompanhando de perto seu crescimento: a qualidade de vida da famĂ­lia era prioridade. O casal comeĂ§ou a trabalhar em casa, produzindo artesanalmente enfeites de Natal, que eram vendidos na vizinhanĂ§a. A demanda foi tĂŁo grande que a produĂ§ĂŁo teve que se profissionalizar e, em pouco tempo, os produtos jĂĄ estavam sendo comercializados em grandes lojas de departamento. Sempre em busca de bem-estar e qualidade de vida, a famĂ­lia se mudou para FlorianĂłpolis em 1991, quando nasceu a marca Imaginarium. No inĂ­cio, os produtos tinham muita madeira, itens de cozinha, com temĂĄticas voltadas para o aconchego, sugerindo experiĂȘncias para serem compartilhadas em famĂ­lia, entre amigos ou para a simples celebraĂ§ĂŁo da existĂȘncia. InovaĂ§ĂŁo Ă© a palavra-chave dos produtos da marca, que busca sempre surpreender seus clientes com criaĂ§Ă”es exclusivas e muito bom humor, e que Ă© referĂȘncia em presentes criativos e inovadores no mercado. Atualmente, a rede conta com 220 lojas exclusivas, mais de 600 pontos de lojas licenciadas, e-commerce, marketplace, um escritĂłrio na cidade de SĂŁo Paulo e um escritĂłrio internacional.Â  A marca faz parte do GrupoUni.Co, detentor das marcas Imaginarium, Puket, Mind e Love Brands. Â  UMA DAS MAIORES MARCAS DE PRESENTES E DECORAĂĂO DO BRASIL Hoje, a franquia Imaginarium Ă© reconhecida no mercado brasileiro como uma das maiores marcas de presentes criativos e inovadores, alĂ©m de ser reconhecida nacional e internacionalmente por antecipar conceitos e tendĂȘncias em eletrĂŽnicos, utilitĂĄrios e presentes. As caracterĂ­sticas fundamentais dessa trajetĂłria sĂŁo a inovaĂ§ĂŁo e o desejo de transformar as rotinas dos seus clientes: por ano, estima-se que a marca lance mais de 400 novos itens. A franquia Imaginarium Ă© uma das poucas marcas franqueadoras detentora de 20 Selos de âExcelĂȘncia em Franchisingâ.Â  O selo Ă© concedido pela ABF (AssociaĂ§ĂŁo Brasileira de Franchising), mediante uma rigorosa pesquisa realizada com os franqueados da rede. AlĂ©m disso, a marca franqueadora tambĂ©m possui 11 PrĂȘmios de Franquia 5 Estrelas PEGN (Pequenas Empresas, grandes NegĂłcios) e 3 PrĂȘmios Lojista Alshop.', NULL, 'SĂO PAULO', 1, NULL, 75, NULL, NULL, '2026-03-08 21:01:06.495', 'https://franquias.portaldofranchising.com.br/franquia-imaginarium-decoracao-e-presentes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '95000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
