INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza7549009veh0siyhi5jrg', 'AMISTE CAFĂ', 'amiste-cafe', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Empresa de LocaĂ§ĂŁo e Venda de MĂĄquinas de CafĂ©, Vending Machine, CafĂ©s e Insumos', 2013, 2014, '[\"https://www.youtube.com/watch?v=ozc-efRhJ74\"]', '2026-04-01 02:00:04.743', '2025-08-05 22:20:26.025', 392, NULL, 1, 2001, 'CafĂ© sem abrir cafeteria. ConheĂ§a modelo de negĂłcio de mĂĄquinas de cafĂ© B2B e fature em mĂ©dia R$250.000 por mĂȘs A Amiste CafĂ© Ă© uma empresa que oferece soluĂ§Ă”es completas em cafĂ© para clientes corporativos, e isso abre diversas oportunidades de negĂłcios para nossos franqueados. Ao se juntar Ă  nossa rede, vocĂȘ terĂĄ acesso a uma gama de serviĂ§os e produtos que incluem: LocaĂ§ĂŁo e Venda de MĂĄquinas de CafĂ©: Torne-se um especialista em mĂĄquinas de cafĂ© e atenda Ă s necessidades de empresas de todos os tamanhos, fornecendo soluĂ§Ă”es de cafĂ© sob medida. Vendas de Insumos de Alta Qualidade: Trabalhe com insumos premium, como cafĂ©s especiais, gourmet e superiores, cappuccinos, chocolates, chĂĄs, xaropes e outros. AssistĂȘncia TĂ©cnica Autorizada: Lidere o mercado oferecendo assistĂȘncia tĂ©cnica para as principais marcas de mĂĄquinas de cafĂ©, garantindo a satisfaĂ§ĂŁo de seus clientes. Treinamentos, Cursos e Workshops: OfereĂ§a treinamentos personalizados para quem deseja aprimorar a experiĂȘncia de seus clientes. Nossa empresa atende com excelĂȘncia uma variedade de setores e portes, incluindo indĂșstrias, hotĂ©is, hospitais, laboratĂłrios, clĂ­nicas, escritĂłrios, cafeterias, restaurantes e muito mais. A Amiste CafĂ© Ă© sinĂŽnimo de qualidade e excelĂȘncia no mundo do cafĂ©, e vocĂȘ pode fazer parte dessa histĂłria de sucesso. Margem de lucro de 25% Payback de 24 meses NegĂłcio de cafĂ© que nĂŁo Ă© cafeteria Receita recorrente e escalĂĄvel Baixa concorrĂȘncia B2B. Atenda todo tipo de empresa como indĂșstrias, escritĂłrios, clĂ­nicas, cafeterias, hotĂ©is, restaurantes e muitos outros. Â  A primeira franquia de Office Coffee Service do Brasil \nNossa primeira unidade surgiu em 2001, na cidade de Londrina-PR, sendo umas das primeiras do Brasil no ramo de Office Coffee Service (OCS), fornecendo serviĂ§os de locaĂ§ĂŁo e manutenĂ§ĂŁo de mĂĄquinas de cafĂ© para empresas. \nLogo nossa empresa passou a oferecer alĂ©m de mĂĄquinas, produtos como cafĂ©s especiais de alto padrĂŁo, cappuccinos, chocolates e outros insumos para elaboraĂ§ĂŁo de bebidas, expandindo o comĂ©rcio para atender bares, restaurantes e cafeterias. \nApĂłs 10 anos de crescimento, nos tornamos lĂ­der no segmento em Londrina-PR e MaringĂĄ-PR e, em 2012, convertemos o nosso negĂłcio para rede de franquias levando nosso padrĂŁo de qualidade para outras cidades e estados. \nAtualmente estamos presente em 12 cidades do Brasil. \nHoje oferecemos soluĂ§Ă”es completas em cafĂ©s para todo tipo e tamanho de empresa. \nSomos autorizados e homologados dos principais fabricantes de mĂĄquinas de cafĂ©, temos nossas prĂłprias marcas de cafĂ©s, chocolates e cappuccinos e somos distribuidores oficiais dos principais fabricantes de insumos para preparaĂ§ĂŁo de bebidas quentes e geladas. Â  Porque investir na Amiste CafĂ©: Know-how de mais de 20 anos. \nAĂ§Ă”es de marketing e vendas. Contamos com um time dedicado para trazer leads para as equipes comerciais dos nossos franqueados e acelerar o crescimento. \nTreinamento contĂ­nuo. A franqueadora capacita a equipe dos franqueados periodicamente. \nReceita recorrente. Nossa principal fonte de receita vem de contratos de locaĂ§ĂŁo e fornecimento de insumos, o que garante previsibilidade na receita conforme a carteira de clientes vai sendo construĂ­da. \nBaixa concorrĂȘncia. Nesse mercado existem poucos operadores. Somos a Ășnica franquia de OCS do Brasil. \nInvestimento modular. A maior parte do investimento conforme o franqueado vai conquistando seus clientes.', NULL, 'PARANĂ', 1, NULL, 20, NULL, NULL, '2026-03-08 21:11:05.091', 'https://franquias.portaldofranchising.com.br/franquia-amiste-cafe-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
