INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza755o009xeh0s6hiqrq13', 'SUPER OTICA SĂO JOSĂ', 'super-otica-sao-jose', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'Ătica voltada para a SaĂșde dos Olhos', 2010, 2010, '[\"https://www.youtube.com/watch?v=pcb9wFk1f9g\",\"https://www.youtube.com/watch?v=tiWzEu7CUec\",\"https://www.youtube.com/watch?v=TfIzEPUQiyE\",\"https://www.youtube.com/watch?v=e8ILD9MGW8A\"]', '2026-04-01 02:00:04.762', '2025-08-05 22:20:26.076', 394, NULL, 1, 1969, 'VOCĂ QUE DESEJA SER UM EMPREENDEDOR / FRANQUEADO TER SEU PRĂPRIO NEGĂCIO 1- ConheĂ§a caracterĂ­sticas importantes para o comportamento empreendedor / franqueado 2- Confira a seguir algumas caracterĂ­sticas bĂĄsicas de um empreendedor de sucesso.  Iniciativa e coragem Empreender consiste basicamente em colocar ideias em prĂĄtica. \nUm empreendedor sabe que uma boa ideia Ă© aquela que pode ser executada. \nPara isso, traĂ§a um plano de aĂ§ĂŁo. Ele sabe o que quer fazer e como fazer. O empreendedor Ă© alguĂ©m que aceita correr riscos. \nPara implementar suas ideias, ousa de maneira consciente, seja para colocar um novo produto no mercado ou com o objetivo de expandir seu negĂłcio. TambĂ©m Ă© alguĂ©m que planeja e realiza seus projetos, mudando de estratĂ©gia caso seja necessĂĄrio.  VisĂŁo estratĂ©gica  LideranĂ§a  Perceber quais as demandas do mercado, entender o perfil do cliente, saber qual o posicionamento da empresa, avaliar vantagens e riscos. Essas sĂŁo algumas caracterĂ­sticas que compĂ”em a visĂŁo estratĂ©gica dos bons empreendedores. Eles sĂŁo capazes de compreender como as diversas instĂąncias da organizaĂ§ĂŁo estĂŁo articuladas, estabelecendo planos de aĂ§ĂŁo tanto para o ambiente interno como para o externo. Faz parte da visĂŁo estratĂ©gica a capacidade de aproveitar oportunidades e de inovar, e essas aĂ§Ă”es sĂŁo fundamentais para manutenĂ§ĂŁo e crescimento de uma empresa.  LideranĂ§a  VisĂŁo estratĂ©gica  CapacitaĂ§ĂŁo  Por compreender todos os processos de funcionamento da organizaĂ§ĂŁo, o empreendedor Ă© alguĂ©m que sabe liderar. Distribui tarefas e funĂ§Ă”es para os funcionĂĄrios mais aptos a desempenhĂĄ-las. Ao aplicar tĂĄticas de lideranĂ§a, a equipe torna-se autogerenciĂĄvel, passa a conhecer a ordem organizacional, identifica-se com os valores da empresa e age em prol da conquista dos objetivos. A gestĂŁo de talentos Ă© tambĂ©m uma aĂ§ĂŁo essencial para o gerenciamento produtivo, inclusive com melhoria na lucratividade. Ao saber quais as aptidĂ”es de um funcionĂĄrio, o lĂ­der pode remanejĂĄ-lo para outra funĂ§ĂŁo que possa exercer com mais destreza.  CapacitaĂ§ĂŁo  LideranĂ§a  As discussĂ”es mais recentes tĂȘm abandonado a antiga visĂŁo do empreendedorismo como uma caracterĂ­stica inata. Os teĂłricos da administraĂ§ĂŁo e da gestĂŁo de empresas tĂȘm defendido a capacidade empreendedora como um aperfeiĂ§oamento de competĂȘncias. Por isso, investir na capacitaĂ§ĂŁo e no aprendizado tem sido uma caracterĂ­stica bastante incentivada em quem deseja empreender ou ampliar seu negĂłcio. E isso nĂŁo se restringe apenas ao gestor, mas Ă  equipe de funcionĂĄrios, seja com a capacitaĂ§ĂŁo da equipe de vendas ou a organizaĂ§ĂŁo de um curso para implementar novas rotinas produtivas na empresa.', NULL, 'SANTA CATARINA', 1, NULL, 45, NULL, NULL, '2026-03-08 21:13:14.197', 'https://franquias.portaldofranchising.com.br/franquia-super-otica-sao-jose-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '271000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
