INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza756j00a3eh0snfpiyj83', 'ARRANJOS EXPRESS', 'arranjos-express', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'A marca diversifica os serviĂ§os e acompanha as tendĂȘncias do mercado da moda, consolidando-se como referĂȘncia em alinhavar a personalidade Ășnica dos clientes por meio de ajustes e customizaĂ§Ă”es.', 2003, 2012, '[\"https://www.youtube.com/watch?v=ZA3gbpVc7nY\",\"https://www.youtube.com/watch?v=TuMIK43nzLU\",\"https://www.youtube.com/watch?v=mgFtcEQaGgk\",\"https://www.youtube.com/watch?v=0m8DHFTpg4Q\"]', '2026-04-01 02:00:04.818', '2025-08-05 22:20:26.107', 400, NULL, 1, 2003, 'A Arranjos Express foi fundada em 2003, originalmente em Portugal. Chegou ao Brasil em 2012 e em sua trajetĂłria, consolidou-se estando hoje com mais de 120 lojas e com potencial crescimento em toda a AmĂ©rica. \nMais que uma rede de costura, a Arranjos Express atua com excelĂȘncia e com um conceito criativo, criamos junto ao mercado um novo hĂĄbito de consumo, onde o cliente pode consertar, transformar, adequar e reaproveitar suas peĂ§as. \nPara a praticidade do pĂșblico e a rentabilidade dos franqueados, a Arranjos Express busca sempre ser uma aliada e parceira das lojas locais. \nE para equivaler ao ambiente instalado, contamos com lojas modernas, prĂĄticas, maquinĂĄrios inovadores, profissionais bem treinados e serviĂ§os com qualidade alĂ©m de um operacional bastante simplificado e sem estoque.', NULL, 'SĂO PAULO', 1, NULL, 134, NULL, NULL, '2026-03-08 21:16:38.693', 'https://franquias.portaldofranchising.com.br/franquia-arranjos-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza756p00a4eh0swukou9qt', 'OJO', 'ojo', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'Somos uma Ăłtica conceito especializada em Ray Ban principal marca de Ăłculos do mundo.', 2015, 2019, NULL, '2026-04-01 02:00:04.827', '2025-08-05 22:20:26.113', 401, NULL, 1, 2012, 'A OJO nasceu com o desejo de revolucionar aquilo que vocĂȘ conhece como Ăłtica. Tudo Ă© uma questĂŁo de escolhas e praticidade. Por isso reunimos o que existe de melhor em um mesmo lugar: os melhores laboratĂłrios e lentes, os Ășltimos lanĂ§amentos das marcas mais consagradas do mundo, um atendimento personalizado (sem ser chato), a maior variedade de tamanhos, formatos e modelos â tudo, tudinho mesmo, num ambiente mais descontraĂ­do e contemporĂąneo. \nOs modelos ficam a sua disposiĂ§ĂŁo para experimentar, os equipamentos tiram qualquer dĂșvida e o capuccino estĂĄ sempre quentinho esperando vocĂȘ. Tudo foi pensado para fazer vocĂȘ se sentir bem, e sair ainda mais satisfeito e seguro com aquilo que escolheu. E se vocĂȘ nĂŁo gostar, nĂŁo tem problema: a gente troca. \nNĂŁo somos uma loja, somos uma tendĂȘncia. Somos a evoluĂ§ĂŁo daquilo que vocĂȘ conhece como Ăłtica. Somos a OJO by Mr. Ray.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 9, NULL, NULL, '2026-03-08 21:17:19.429', 'https://franquias.portaldofranchising.com.br/franquia-ojo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
