INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza757v00a9eh0se40hamik', 'INTIMISSIMI UOMO', 'intimissimi-uomo', NULL, 'Moda', 'VestuĂĄrios', 'Trata-se de operaĂ§ĂŁo e gestĂŁo de comĂ©rcio de meias, leggings e beachwear feminino, masculino e infantil', 1987, 2024, NULL, '2026-04-01 02:00:04.878', '2025-08-05 22:20:26.156', 406, NULL, 1, 1986, '', NULL, 'SĂO PAULO', 1, NULL, NULL, NULL, NULL, '2026-03-08 21:24:44.295', 'https://franquias.portaldofranchising.com.br/franquia-intimissimi-uomo-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '595000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758600aaeh0s50q9rnlo', 'RESTAURA JEANS', 'restaura-jeans', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Reparos', 'Lavanderia de alta Tecnologia, ServiĂ§os para Costura, CustomizaĂ§ĂŁo e Tingimento Profissional, RestauraĂ§ĂŁo de Roupas e AssessĂłrios em Couro e Venda de Produtos. Uma Franquia completa.', 1994, 2001, '[\"https://www.youtube.com/watch?v=KUS21-NFzu0\",\"https://www.youtube.com/watch?v=3_GQd1WyBMg\"]', '2026-04-01 02:00:04.888', '2025-08-05 22:20:26.166', 407, NULL, 1, 1991, 'A rede jĂĄ passou de 170 unidades em todo o Brasil com um faturamento superior a 100 milhĂ”es de reais no Ășltimo ano, sendo lĂ­der no segmento de limpeza e conservaĂ§ĂŁo de roupas e acessĂłrios. \nHoje a Restaura Jeans Ă© a marca mais valorizada e reconhecida pela qualidade dos serviĂ§os e credibilidade da rede. \nCom mais de 500.000 mil consumidores ativos no Brasil temos um Ă­ndice de satisfaĂ§ĂŁo dos nossos serviĂ§os acima de 94% com base em quem jĂĄ utilizou. \nA mais de 31 anos no mercado de franchising a Restaura Jeans oferece a nossos franqueados 5 fontes de renda em um Ășnico negĂłcio. \nLavanderia completa, tingimento profissional, costura e customizaĂ§ĂŁo, renovaĂ§ĂŁo de couro e venda de mais de 100 produtos inovadores. \nÂ  \nÂ  Com serviĂ§os que vĂŁo muito alĂ©m do jeans, e um modelo de negĂłcio enxuto, a Restaura Jeans traz seguranĂ§a e solidez para seu investimento.Â    Na Restaura Jeans temos um Suporte 360, ou seja, um suporte completo. \nComo franqueado vocĂȘ contarĂĄ com uma equipe especialista nas mais diversas ĂĄreas de negĂłcio para dar seguranĂ§a em todas as fases, da implantaĂ§ĂŁo Ă  operaĂ§ĂŁo da sua franquia.', NULL, 'SANTA CATARINA', 1, NULL, 134, NULL, NULL, '2026-03-08 21:25:07.012', 'https://franquias.portaldofranchising.com.br/franquia-restaura-jeans-conservacao-e-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758e00abeh0sx9po3x9x', 'INSTITUTO ANA HICKMANN', 'instituto-ana-hickmann', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'A Escola Profissionalizante Ana Hickmann Ă© referĂȘncia em cursos de beleza, tecnologia e inglĂȘs, unindo ensino de alta qualidade, inovaĂ§ĂŁo pedagĂłgica e a transformaĂ§ĂŁo de vidas por meio da educaĂ§ĂŁo.', 2018, 2019, '[\"https://www.youtube.com/watch?v=Mds2GbOBFho\"]', '2026-04-01 02:00:04.898', '2025-08-05 22:20:26.175', 408, NULL, 1, 2018, 'Escola Profissionalizante Ana Hickmann: transformando vidas atravĂ©s da educaĂ§ĂŁo e da beleza! A Escola Profissionalizante Ana Hickmann Ă© uma rede de ensino inovadora que atua nas ĂĄreas de beleza, tecnologia e inglĂȘs, com uma proposta pedagĂłgica moderna e acessĂ­vel. Nosso compromisso Ă© oferecer capacitaĂ§ĂŁo profissional de alta qualidade, permitindo que nossos alunos adquiram uma profissĂŁo e gerem renda para suas famĂ­lias, independentemente de gĂȘnero, idade, classe social ou formaĂ§ĂŁo acadĂȘmica. Um modelo de negĂłcio completo: 3 em 1 AlĂ©m de oferecer cursos profissionalizantes, nossas unidades contam com um SalĂŁo Profissional, onde os alunos aplicam seus conhecimentos na prĂĄtica, proporcionando uma experiĂȘncia real e, ao mesmo tempo, gerando uma nova fonte de receita para os franqueados. Escola Profissionalizante na ĂĄrea da tecnologia â Mais de 50 cursos com uma plataforma interativa. Escola Profissionalizante na ĂĄrea da beleza â FormaĂ§ĂŁo em diversas profissĂ”es do setor. SalĂŁo Profissional â Um dos poucos modelos de escola no Brasil que forma e emprega profissionais no mesmo local. Suporte de excelĂȘncia para os Franqueados A franqueadora disponibiliza um Centro de ExcelĂȘncia em Treinamentos, garantindo suporte completo aos franqueados e suas equipes por meio de duas plataformas estratĂ©gicas: Universidade Corporativa Presencial Infraestrutura de alto nĂ­vel para treinamentos e palestras, com um auditĂłrio moderno e climatizado para 150 pessoas, equipado com: Poltronas confortĂĄveis Flipchart e laser point Microfone e sonorizaĂ§ĂŁo profissional Projetor HD Wide e Wi-Fi Salas de reuniĂ”es equipadas EspaĂ§o exclusivo para franqueados Ărea para coffee break/almoĂ§o Estacionamento prĂłprio e localizaĂ§ĂŁo privilegiada Universidade Corporativa EAD Uma plataforma online completa, com materiais estratĂ©gicos para a operaĂ§ĂŁo da franquia, incluindo: Manuais de franquia PeĂ§as personalizĂĄveis para aĂ§Ă”es comerciais Campanhas de marketing VĂ­deos de treinamentos Fotos e documentos essenciais ComunicaĂ§ĂŁo visual e muito mais! LideranĂ§a e Credibilidade A Escola Profissionalizante Ana Hickmann Ă© liderada por grandes nomes do mercado: Sidney Kalaes â Presidente do Grupo Kalaes, uma holding multissetorial de franquias.Â Administrador de empresas, com mais de 30 anos de experiĂȘncia no setor, sendo lĂ­der, master e fundador de diversas franqueadoras de sucesso. Ana Hickmann â Apresentadora e empresĂĄria de renome, trazendo credibilidade, exposiĂ§ĂŁo e diferenciais estratĂ©gicos ao negĂłcio.Â Seu engajamento na educaĂ§ĂŁo profissional tem impactado a vida de milhares de alunos, capacitando-os para o mercado de trabalho. Seja parte dessa transformaĂ§ĂŁo! Invista em um modelo de negĂłcio inovador, sĂłlido e altamente rentĂĄvel.', NULL, 'SĂO PAULO', 1, NULL, 48, NULL, NULL, '2026-03-08 21:25:51.802', 'https://franquias.portaldofranchising.com.br/franquia-instituto-ana-hickmann/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '197000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza758l00aceh0sz5zfxzut', 'LE BISCUIT', 'le-biscuit', NULL, 'Casa e ConstruĂ§ĂŁo', 'ARTIGOS PARA O LAR', 'A Le biscuit Ă© um varejo que oferece soluĂ§Ă”es com sortimento completo para seus clientes em todos os eventos promocionais do ano, alĂ©m das campanhas exclusivas.', 2018, 2018, NULL, '2026-04-01 02:00:04.908', '2025-08-05 22:20:26.181', 409, NULL, 1, 1968, 'A Le biscuit foi criada em 1968, em Feira de Santana, sendo a primeira rede de variedades da Bahia. A partir de 2012, com o apoio do fundo de investimento Vinci Partners, a rede investiu na expansĂŁo e iniciou o ano de 2018, quando comemorou 50 anos de existĂȘncia com mais de 100 lojas prĂłprias em operaĂ§ĂŁo e presente em 14 estados brasileiros nas regiĂ”es Norte, Nordeste, Sudeste e Centro Oeste. Atualmente a companhia passa a contar com 144 estabelecimentos comerciais, sendo 137 lojas prĂłprias e 07 franquias. A Le Biscuit foi reconhecida diversas vezes ao longo dos seus 50 anos de existĂȘncia em decorrĂȘncia do seu compromisso em servir os seus clientes. O Ășltimo reconhecimento aconteceu no ano de 2018, quando a marca foi novamente vencedora do trofĂ©u TOP OF MIND na categoria de Produtos para o Lar. A Le biscuit comercializa mais de 20 mil itens, divididos em diversas categorias: Utilidades domĂ©sticas, brinquedos, papelaria, eletroportĂĄteis, bomboniere, festa, Cama, mesa e banho, Higiene, beleza e moda, lazer, armarinho e artesanato, decoraĂ§ĂŁo, bebĂȘ e telefonia. Para o modelo de franquia foi elaborado um mix otimizado de produtos, mais adequado ao formato destas lojas. Este sortimento oferece soluĂ§Ă”es completas para os clientes em todos os eventos promocionais do ano, alĂ©m das campanhas exclusivas. A Le Biscuit tem como missĂŁo encantar os clientes atravĂ©s de uma experiĂȘncia de compra diferenciada, em um ambiente agradĂĄvel, com maior variedade de produtos, qualidade, inovaĂ§ĂŁo e economia, gerando alegria para todos e crescimento para o nosso time. Atualmente sĂŁo mais de 2.400 colaboradores divididos em nossa matriz que fica na cidade de Salvador/BA, em nosso centro de distribuiĂ§ĂŁo que fica na cidade de CamaĂ§ari/BA, e em nossa rede de lojas prĂłprias. Em 2018 consolidamos o projeto Le franchise, em consonĂąncia com a crescente evoluĂ§ĂŁo do sistema de franquias no Brasil, com o objetivo de criar uma rede padronizada, de forma profissional e organizada, transferindo o know-how a seus Franqueados. Iniciamos o ano de 2020 com 04 franquias em operaĂ§ĂŁo (IrecĂȘ, IpirĂĄ, Santo Amaro e Cruz das Almas) todas no estado da Bahia. No segundo semestre levamos a nossa franquia para outros estados da regiĂŁo NE. A primeira unidade a inaugurar nesse ano foi na cidade de Serra Talhada em seguida em Carpina e breve em Santa Cruz do Capibaribe, ambas no estado de Pernambuco.', NULL, 'BAHIA', 1, NULL, 140, NULL, NULL, '2025-04-15 17:03:31.000', 'https://franquias.portaldofranchising.com.br/franquia-le-biscuit/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
