INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759100afeh0sn3b1pabt', 'GIGATRON', 'gigatron', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'INFORMĂTICA', 'Softwares de gestĂŁo, SaaS, PDV, forĂ§a de venda, Business Intelligence, ERP, soluĂ§Ă”es ĂĄgeis para empresas.', 2011, 2012, NULL, '2026-04-01 02:00:04.937', '2025-08-05 22:20:26.197', 412, NULL, 1, 1999, 'Somos uma empresa de tecnologia que se baseia nas necessidades de nossos clientes e franqueados, seguindo a tendĂȘncia em demandas de produtos em tecnologia. A Gigatron Tecnologia iniciou suas atividades no desenvolvimento de sistemas de gerenciamento no mĂȘs de Maio do ano de 1998, na cidade de Birigui, interior de SĂŁo Paulo, tendo como patrono, o Sr. Marcelo SalomĂŁo GuimarĂŁes. Ă Ă©poca, a empresa tinha como escopo o desenvolvimento de sistemas comerciais para atender as exigĂȘncias fiscais que encontravam-se em grande transformaĂ§ĂŁo. Em detrimento da carĂȘncia de mercado ou pelo alto custo de seus concorrentes, muitas indĂșstrias calĂ§adistas da cidade de Birigui comeĂ§aram a solicitar sistemas Ă  Gigatron. Somente a partir do ano de 2002 que a Gigatron se consolidou no mercado. ApĂłs a construĂ§ĂŁo de seu prĂ©dio prĂłprio e contando com equipe estruturada, a empresa passou a traĂ§ar sua forma. Apenas a partir de 2012 que a empresa decidiu entrar no mercado do franchising, sendo inclusive referĂȘncia por trĂȘs anos seguidos no ramo de tecnologia e serviĂ§os. Modalidades de NegĂłcio Especializada em softwares e prestaĂ§ĂŁo de serviĂ§os para empresas, a rede de franquias apresenta cinco modalidades de negĂłcios. Formato de trabalho Nossa rede trabalha de forma descentralizada, permitindo um modelo de negĂłcio diferenciado. Guarda Chuva = Foco no produto Franqueador = Foco no negĂłcio Master Franquia = Foco na expansĂŁo Franquia ou Micro = Foco no cliente NĂșcleo = Foco em atendimento', NULL, 'SĂO PAULO', 1, NULL, 49, NULL, NULL, '2025-09-09 09:18:22.000', 'https://franquias.portaldofranchising.com.br/franquia-gigatron-comunicacao-informatica-e-eletronicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759600ageh0srm9905a8', 'SIDE WALK', 'side-walk', NULL, 'Moda', 'CalĂ§ados', 'CalĂ§ados, vestuĂĄrio e acessĂłrios para o pĂșblico masculino e feminino.', 2013, 2014, NULL, '2026-04-01 02:00:04.946', '2025-08-05 22:20:26.202', 413, NULL, 1, 1982, 'TrĂȘs amigos, muita coisa em comum e uma vontade. Foi com esse espĂ­rito que, em 1982, Luis Gelpi, Eduardo Rizk e Tinho Azambuja resolveram fundar a Sidewalk, uma marca que cresceu com o DNA repleto de originalidade e irreverĂȘncia. O homem e a mulher Side vivem uma rotina urbana e moderna, mas nĂŁo perdem a chance de sair da cidade para dias mais tranquilos em contato com a natureza. Para isso, alĂ©m de peĂ§as perfeitas para o dia a dia, o conforto Ă©indispensĂĄvel para a marca.   \nMuitas vezes inspirados por experiĂȘncias de suas viagens ao exterior e decididos a mesclar inovaĂ§ĂŁo a um jeito autĂȘntico de se fazer moda, Luis, Eduardo e Tinho abriram a primeira lojaÂ da marca na Rua Melo Alves, nos Jardins, em SĂŁo Paulo. Em pouco tempo, os calĂ§ados da Side, que vinham embalados em saquinhos flanelados, foram sucesso absoluto entre os clientes. Logo depois, a cartela de cores das pĂłlos e das meias, os Topsiders, os sapatos de bolinha, entre muitos outros, jĂĄ estavam nas wish list de gente cheia de estilo no paĂ­s inteiro. \nAtualmente, sĂŁo 26 lojas em todo o Brasil, sendo 13 em SĂŁo Paulo. ApĂłs completar 30 anos, a Sidewalk continua imprimindo seu estilo criativo e descontraĂ­do ao mercado de moda brasileiro.', NULL, 'SĂO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-08 21:28:13.240', 'https://franquias.portaldofranchising.com.br/franquia-side-walk-acessorios-pessoais-e-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '420000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759c00aheh0spjoeoxaz', 'INVEST4U', 'invest4u', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'A Invest4U entrega direĂ§ĂŁo financeira com base cristĂŁ, ajudando famĂ­lias a proteger o presente e construir um plano claro para multiplicar seu patrimĂŽnio com propĂłsito e paz.', 2023, 2024, NULL, '2026-04-01 02:00:04.956', '2025-08-05 22:20:26.208', 414, NULL, 1, 2018, '', NULL, 'PARANĂ', 1, NULL, 8, NULL, NULL, '2026-03-08 21:29:00.699', 'https://franquias.portaldofranchising.com.br/franquia-invest4u-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '33000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759h00aieh0s4beq7ruy', 'POPDENTS', 'popdents', NULL, 'SaĂșde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Ărea da saĂșde', 2017, 2018, '[\"https://www.youtube.com/watch?v=JnQytcdzkME\",\"https://www.youtube.com/watch?v=GPCuYPdmuv4\",\"https://www.youtube.com/watch?v=hxvk2v2n3bY\"]', '2026-04-01 02:00:04.966', '2025-08-05 22:20:26.213', 415, NULL, 1, 2000, 'O propĂłsito do negĂłcio Ă© impactar positivamente a vida das pessoas, fornecendo atenĂ§ĂŁo e cuidado Ă queles que mais necessitam, alĂ©m de capacitar o dentista a se tornar um empreendedor. As operaĂ§Ă”es da POPdents sĂŁo focadas em alto giro e demanda, com desempenho detalhado. Priorizamos a experiĂȘncia individual de cada paciente e cada atendimento de forma personalizada. O caminho para o sucesso estĂĄ em um ciclo diĂĄrio de atendimento imediato, construĂ§ĂŁo de relacionamento com nossa base de clientes, estĂ­mulo ao fluxo de indicaĂ§Ă”es e encorajamento Ă  recompra de novos tratamentos. Nosso CEO e fundador - Marcelo Buriti Ainda na faculdade de odontologia, tinha certeza que nĂŁo pensava como seus colegas e enxergava o dia a dia da profissĂŁo de forma diferente. JĂĄ sentia que seu trabalho nĂŁo se resumiria aos atendimentos no consultĂłrio. O que mais lhe chamava atenĂ§ĂŁo durante este perĂ­odo (alĂ©m das necessidades e dores dos pacientes) era a certeza da capacidade que tinha de transformar a vida dessas pessoas. Depois de formado, decidiu que esse era seu objetivo, e assim comeĂ§ou o projeto. Apostou tudo que tinha nesse sonho e montou seu primeiro consultĂłrio. Depois do sucesso do empreendimento, abriu o segundo, o terceiro e assim 26 anos depois, ao alcanĂ§ar a marca de 80 operaĂ§Ă”es de varejo e tornar o atendimento odontolĂłgico de qualidade mais acessĂ­vel a todos, passou a se concentrar em governanĂ§a, padrĂ”es e processos, inteligĂȘncia corporativa, maximizar a margem de lucro das operaĂ§Ă”es, simplificando o modelo de gestĂŁo e melhorando o posicionamento das marcas. Como empreendedor e empresĂĄrio que Ă©, decidiu abrir sua primeira marca, a POPdents, para o mercado de franquias, dando a oportunidade de empreendedores e investidores entrarem nos segmentos de beleza, bem estar e saĂșde, de forma segura e assertiva.', NULL, 'CEARĂ', 1, NULL, 41, NULL, NULL, '2025-10-13 09:04:17.000', 'https://franquias.portaldofranchising.com.br/franquia-popdents/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza759m00ajeh0sg8ilflzd', 'ĂTICAS BRASIL', 'oticas-brasil', NULL, 'SaĂșde, Beleza e Bem Estar', 'ĂTICAS', 'ComĂ©rcio varejista de Ăłculos, lentes oftĂĄlmicas e acessĂłrios.', 2018, 2021, '[\"https://www.youtube.com/watch?v=un7m6FDTTCc\"]', '2026-04-01 02:00:04.977', '2025-08-05 22:20:26.219', 416, NULL, 1, 1964, 'ĂTICAS BRASIL: UMA FRANQUIA COM PROPĂSITO Com mais de 58 anos de histĂłria, a Ăticas Brasil tem como propĂłsito proporcionar Ă s pessoas uma visĂŁo perfeita e personalizada para ampliar a visĂŁo de si e do mundo Fundada hĂĄ 58 anos por JerĂŽnimo Motta, um dos pioneiros no segmento Ăłptico em GoiĂĄs, a tradicional Ăticas Brasil, nasceu do amor pela visĂŁo, onde Sr. JerĂŽnimo nĂŁo media esforĂ§os para fazer as pessoas enxergarem melhor. JerĂŽnimo era um autodidata criativo, amante da literatura e mĂșsico nas horas vagas. Foi um visionĂĄrio no mercado de lentes Ăłpticas e inaugurou a Ăticas Brasil pelo amor ao ofĂ­cio. AlĂ©m de criar diversos equipamentos para a produĂ§ĂŁo de lentes no seu laboratĂłrio, ainda publicou o livro âElementos de Ăptica Para Balconistasâ e fundou a ASCOEG â AssociaĂ§ĂŁo do ComĂ©rcio de Ăptica do Estado de GoiĂĄs, que, posteriormente se transformou no SINDIĂPTICA â GO, contribuindo para o desenvolvimento do setor. Hoje, Ăticas Brasil se consolidou como uma marca de confianĂ§a junto ao mercado, transmitindo o conhecimento e a experiĂȘncia acumulados como atributos determinantes do binĂŽmio atendimento/fidelidade. Tal experiĂȘncia estende-se tambĂ©m nas melhores negociaĂ§Ă”es com fornecedores, incluindo mix de produtos completo (Ăculos solares, ArmaĂ§Ă”es, Tratamentos antirreflexos, lentes Ăłpticas e acessĂłrios), as melhores Grifes e marcas revendidas do mercado e tambĂ©m marcas prĂłprias, que estĂŁo em franco crescimento, garantindo alta rentabilidade e preĂ§os ainda mais competitivos. Dentro de todas as Lojas Ăticas Brasil, o cliente tem a experiĂȘncia Ășnica de Consultoria Ăptica especializada, que inclui a modernizaĂ§ĂŁo de todo processo de atendimento e confecĂ§ĂŁo dos Ăłculos atravĂ©s do que hĂĄ de mais moderno em termos de soluĂ§ĂŁo digital Ăłptica. Com o aparelho i. Terminal go, os parĂąmetros de mediĂ§ĂŁo ocular sĂŁo capturados digitalmente, resultando em personalizaĂ§ĂŁo avanĂ§ada das lentes. SĂŁo medidas oculares perfeitas, obtendo parĂąmetros individuais com tecnologia de alta precisĂŁo. O processo digital evita possĂ­veis erros de ajuste da mediĂ§ĂŁo manual, que podem resultar em perda de atĂ© 40% do desempenho das lentes. Essa e outras aĂ§Ă”es traduzem o investimento e compromisso da Ăticas Brasil em oferecer ao cliente atendimento de qualidade e soluĂ§Ă”es visuais completas e tecnolĂłgicas. O Grupo Ăticas Brasil conta tambĂ©m com LaboratĂłrio Ătico PrĂłprio, a Unilentes. Com mais de 15 anos de mercado e capacidade produtiva de mais de 1600 serviĂ§os-dia, a Unilentes Ă© atualmente um dos maiores e mais bem estruturados LaboratĂłrios Ăticos da regiĂŁo centro-oeste do paĂ­s, e, um dos Ășnicos do Brasil que recebeu a certificaĂ§ĂŁo internacional ZEISS (Empresa AlemĂŁ lĂ­der mundial na fabricaĂ§ĂŁo de lentes). Para receber esta homologaĂ§ĂŁo, foram realizados altos investimentos em maquinĂĄrio e tecnologia, adequaĂ§ĂŁo de todos os processos produtivos e garantia dos mais exigentes protocolos de qualidade, o que garante ao cliente final lentes de alta performance. Para a Ăticas Brasil, a qualidade do serviĂ§o, inovaĂ§ĂŁo e excelĂȘncia no atendimento sĂŁo os requisitos mais considerados nos seus programas de desenvolvimento. Provas disso sĂŁo as premiaĂ§Ă”es e certificados recebidos ao longo dos anos. Os Ășltimos foram o PrĂȘmio TOP OF MIND GoiĂąnia â A marca de Ăticas Mais lembrada pelos Goianos (PopList GoiĂąnia 2021) e tambĂ©m o certificado de excelĂȘncia em NPS (Net Promoter Score), metodologia internacional que certifica grandes multinacionais e nos pontua como uma das poucas empresas onde mais de 90% dos clientes avaliam nosso atendimento como bom ou Ăłtimo. AndrĂ© Silva, Gestor de Atendimento e Qualidade Ăticas Brasil, trabalha no negĂłcio hĂĄ mais de 40 anos e afirma com confianĂ§a: âMesmo apĂłs 58 anos da fundaĂ§ĂŁo, a Ăticas Brasil segue o legado do Sr JerĂŽnimo, trabalhando na mesma metodologia humanizada, mantendo uma relaĂ§ĂŁo prĂłxima com o cliente e com total garantia de adaptaĂ§ĂŁo. Caso nĂŁo haja satisfaĂ§ĂŁo, os Ăłculos sĂŁo trocados e se por acaso nĂŁo houver soluĂ§ĂŁo o dinheiro Ă© devolvido. Com metodologia disruptiva no mercado, a empresa traz soluĂ§Ă”es Ăłticas por meio de sua inovaĂ§ĂŁo, tecnologia e humanizaĂ§ĂŁo. Seu pioneirismo agrega valor e qualidade no produto. Hoje a Ăticas Brasil conta com um modelo de franquia com payback em 20 meses e investimento inicial de R$238.000,00. AlĂ©m de nĂșmeros expressivos de lucratividade, o franqueado recebe tambĂ©m total acompanhamento, incluindo suporte para ImplantaĂ§ĂŁo do NegĂłcio, suporte Ă  NegociaĂ§ĂŁo de Produtos e Equipamentos, programas de CaptaĂ§ĂŁo Inicial e Continuada, Treinamento TĂ©cnico em Ăptica para Franqueado e Equipe, apoio Ă s AĂ§Ă”es de Marketing Local, software de GestĂŁo, Consultoria de Campo e NegĂłcio e Programas de ExcelĂȘncia.', NULL, 'GOIĂS', 1, NULL, 40, NULL, NULL, '2025-04-16 17:13:04.000', 'https://franquias.portaldofranchising.com.br/franquia-oticas-brasil/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
