INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ao00aqeh0s4ht7u29v', 'LUG\'S', 'lug-s', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O carro chefe da marca: frango no balde e batata belga no cone. Os clientes tambĂ©m encontram opĂ§Ă”es de pratos executivos gourmet e premium, chopp artesanal produzido pela marca, bebidas e sobremesa.', 2014, 2014, '[\"https://www.youtube.com/watch?v=fTt-Zu6tMb4\"]', '2026-04-01 02:00:05.071', '2025-08-05 22:20:26.257', 423, NULL, 1, 2009, 'Ănica no segmento. O que jĂĄ Ă© sucesso na Europa hĂĄ dĂ©cadas, esta fazendo o maior sucesso no Brasil. \nAs Batatas Belgas da Lug\'s, produzidas com batatas Premium importadas da BĂ©lgica, sĂŁo crocantes por fora e macias por dentro, servida no Cone com molhos exclusivos ficam especiais. \nO clima frio e o mĂ©todo de cultivo fazem das Batatas Belgas da Lug\'s Ășnicas em sabor e textura. Venha experimentar este negocio altamente lucrativo e seja mais um louco por batatas!!!  BenefĂ­cios da Franquia LUG\'S \n- Conceito inovador, diferente de tudo que existe no ramo de Fast Food;\n- Produto Ănico e exclusivo no Mercado;\n- OperaĂ§ĂŁo padronizada e manualizada;\n- Uma das maiores rentabilidades do segmento;\n- Baixo custo de implantaĂ§ĂŁo tendo em vista a rentabilidade.  Sistema Lug\'s \nA LUGÂŽS concebeu um Sistema de Franchising bastante simples e objetivo, onde o Franqueado Ă© tratado como um verdadeiro parceiro. \nA principal preocupaĂ§ĂŁo da Franqueadora Ă© oferecer aos Franqueados qualidade nos produtos e condiĂ§Ă”es de lucratividade cada vez mais atraentes, repassando conhecimentos estratĂ©gicos, mĂ©todos de implantaĂ§ĂŁo e operaĂ§ĂŁo de unidades.  Assessoria oferecida \n- Fornecimento de toda matĂ©ria prima necessĂĄria;\n- Assessoria e apoio na escolha localizaĂ§ĂŁo do ponto comercial adequaĂ§Ă”es e layouts de obras a serem executadas no imĂłvel escolhido para a unidade;\n- Suporte na seleĂ§ĂŁo e treinamento de colaboradores, divulgadores e demais funcionĂĄrios;\n- Treinamento e reciclagem para o pessoal operacional e conceitual para os profissionais recĂ©m contratados, na sede da franqueadora ou em locais designadas por ela, visando minimizar os custos do franqueado.\n- Layout interno e externo, e identidade visual do imĂłvel escolhido e/ou aprovado pela LUGÂŽS FRANCHISING.\n- Auditoria Preventiva e Instrutiva;\n- Marketing de inauguraĂ§ĂŁo, manuais da franquia, perspectivas de gastos antecipados e previsĂ­veis, PĂłs-inauguraĂ§ĂŁo;\n- Desenvolvimento de novos produtos', NULL, 'SĂO PAULO', 1, NULL, 3, NULL, NULL, '2026-03-08 21:32:35.026', 'https://franquias.portaldofranchising.com.br/franquia-lugs-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75au00areh0s0jx3klqc', 'LOS CREPES', 'los-crepes', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO COMPLETO', 'Restaurante especialista em Crepes. Servimos mais de 90 sabores de crepe, saladas com crepes, shakes, sucos naturais e aĂ§aĂ­. TambĂ©m temos o formato fast food.', 2023, 2023, NULL, '2026-04-01 02:00:05.083', '2025-08-05 22:20:26.262', 424, NULL, 1, 2020, '', NULL, 'RIO DE JANEIRO', 1, NULL, NULL, NULL, NULL, '2025-04-17 16:24:11.000', 'https://franquias.portaldofranchising.com.br/franquia-los-crepes-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75az00aseh0sq3yzdszb', 'IGA', 'iga', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Com mais de 160 escolas e presente em 5 paĂ­ses, o IGA hoje Ă© a Maior Rede de Escolas de Gastronomia das AmĂ©ricas. Ănica 3 vezes a conquistar o Selo de ExcelĂȘncia em Franquias - 2018/2019/2020.', 2003, 2010, '[\"https://www.youtube.com/watch?v=qVeX8YTA_bw\",\"https://www.youtube.com/watch?v=rhFMI17VjhA\"]', '2026-04-01 02:00:05.095', '2025-08-05 22:20:26.267', 425, NULL, 1, 2001, 'Fundado em 2001, na Argentina, o IGA â Instituto GastronĂŽmico das AmĂ©ricas eÂŽ uma Rede de Escolas de Gastronomia, capacitando cursos de gastronomia e alta cozinha, alĂ©m de confeitaria profissional e avanĂ§ada. \nPrecursora no ensino profissionalizante de gastronomia, assim que ingressou no mercado, a empresa se posicionou entre as melhores no segmento, conquistando sua forĂ§a e presenĂ§a atravĂ©s de sua metodologia exclusiva. \nSua entrada em paĂ­ses da AmĂ©rica do Sul, sendo eles, Argentina, Paraguai, Uruguai, BolĂ­via e Brasil fortaleceu e potencializou o ensino gastronĂŽmico. \nTeve sua consolidaĂ§ĂŁo no mercado com uma chancela Internacional com mais de 500.000 alunos certificados nestes mais de 20 anos de existĂȘncia. \nSendo uma rede sustentĂĄvel, de grande expansĂŁo internacional e excelĂȘncia no Sistema de Franquias, alcanĂ§amos mais de 160 unidades sendo atualmente a maior rede de escolas de gastronomia da AmĂ©rica Latina.Â  \nCom investimento seguro e sĂłlido, o IGA eÂŽ uma rede com multifranqueados, tendo hoje pouco mais de 70 franqueados/investidores em toda a rede.Â  \nTendo no cenĂĄrio atual, franqueados com mais de 20 anos de participaĂ§ĂŁo, inicia-se na rede o processo de transiĂ§ĂŁo para a segunda geraĂ§ĂŁo das unidades. \nQuanto ao segmento, representado por um mercado altamente competitivo, o IGA, estaÂŽ pronto para o desafio de inovar constantemente e melhorar a qualidade e o prestĂ­gio dos seus cursos. \nNo Brasil, desde 2008, hoje conta com mais de 85 unidades em 20 Estados da FederaĂ§ĂŁo. \nA rede possui mais de 30 mil alunos ativos em todo Brasil, e com potencial para dobrar este nĂșmero nos prĂłximos 3 anos. \nCom um crescimento sustentĂĄvel e efetivo, o planejamento de expansĂŁo estaÂŽ em sua quarta fase no Brasil, e, estaÂŽ apontando para Europa, Ăfrica e Asia nos prĂłximos 10 anos. \nEstes sĂŁo dados que o IGA apresenta, para que vocĂȘ^ investidor/franqueado tenha seu capital aplicado em um modelo de negĂłcios que perpetua a mais de 20 anos!', NULL, 'SĂO PAULO', 1, NULL, 76, NULL, NULL, '2026-03-08 21:33:51.761', 'https://franquias.portaldofranchising.com.br/franquia-iga/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
