INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bb00aueh0sokc3aeae', 'POSTNET', 'postnet', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'ServiĂ§os GrĂĄficos e ImpressĂŁo', 'CĂłpias, ImpressĂ”es, Remessas nacionais e internacionais, Internet, GrĂĄfica rĂĄpida.', 2004, 1992, NULL, '2026-04-01 02:00:05.118', '2025-08-05 22:20:26.280', 427, NULL, 1, 1980, 'A PostNet Ă© um centro de conveniĂȘncia de Office Services, que atende pequenas e mĂ©dias empresas, profissionais liberais, estudantes e pessoas fĂ­sicas em geral. Fundada em 1980, nos Estados Unidos, a PostNet iniciou sua expansĂŁo internacional em 1993 e atingiu mais de 1000 lojas em operaĂ§ĂŁo no mundo, distribuĂ­das em 10 paĂ­ses, todas no modelo de franquia. A PostNet chegou ao Brasil em 2003 e operou apenas com a loja Piloto nos padrĂ”es do mercado nacional atĂ© 2006, quando deu inĂ­cio Ă  expansĂŁo de franquias. Atualmente a PostNet Brasil conta com mais de 40 unidades em operaĂ§ĂŁo e uma unidade Piloto para treinamento de novos franqueados. A franquia PostNet estĂĄ presente no Brasil em 19 cidades, distribuĂ­das por 9 estados. O principal objetivo da PostNet Ă© a qualidade no atendimento, oferecendo diversos serviĂ§os em um Ășnico local.', NULL, 'SĂO PAULO', 1, NULL, 55, NULL, NULL, '2026-03-08 21:35:17.390', 'https://franquias.portaldofranchising.com.br/franquia-postnet-grafica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bh00aveh0s85ggvsjz', 'HAPPY&CO.Âźïž', 'happy-co', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'A Happy Ă© uma experiĂȘncia Ășnica e definitiva no ensino do inglĂȘs. Nosso curso Ă© fast mas nĂŁo Ă© food. O sucesso da nossa metodologia Ă© ensinar os alunos de forma consistente, divertida e feliz.', 2021, 2021, NULL, '2026-04-01 02:00:05.130', '2025-08-05 22:20:26.285', 428, NULL, 1, 2020, 'Somos uma Academia de InglĂȘs. Ensinamos o idioma mais falado no mundo em apenas 15 meses (60 semanas), atravĂ©s de uma metodologia diferenciada e focada no sentimento de nossos alunos, por meio de avaliaĂ§Ă”es de satisfaĂ§ĂŁo sistemĂĄticas e acompanhamento pedagĂłgico eficiente, ĂĄgil e, acima de tudo, personalizado. A Happy&CoÂź possui um corpo diretivo com vasta experiĂȘncia em escolas de inglĂȘs. PorĂ©m, todo o desenvolvimento da empresa foi baseado em \"Marketing de DiferenciaĂ§ĂŁo\". Isto nos torna Ășnicos no mercado. A Happy&CoÂź surge em meio Ă  ausĂȘncia do sentimento de bem-estar e pertencer, na falta do reconhecimento e na luta por um propĂłsito. Desde a fundaĂ§ĂŁo da JG ENSINO DE IDIOMAS LTDA EPP (2007) este sentimento foi abalado e petrificado, atĂ© que tudo mudou na presenĂ§a do propĂłsito de Deus em levar aos alunos o compromisso pela satisfaĂ§ĂŁo, pois este sentimento \"trocado\" de um filho por uma empresa, fez com que a HAPPY nascesse 14 anos apĂłs, madura, robusta e com o espĂ­rito de fazer um sentimento mais forte aflorar em seus alunos: FELICIDADE! Assim nasceu na leitura nua e crua de \"FELIZ E CIA\" nosso desejo em sermos nĂŁo apenas uma empresa ou marca, mas um estilo de vida. Como citada antes, nossa metodologia de ensino Ă© focada no entretenimento, imersĂŁo e muita doaĂ§ĂŁo do \"eu\".Â Â Â  Viver este sentimento merece uma celebraĂ§ĂŁo. AliĂĄs, ensinar/aprender inglĂȘs nunca mais serĂĄ da mesma maneira.', NULL, 'SĂO PAULO', 1, NULL, 3, NULL, NULL, '2026-03-08 21:35:57.556', 'https://franquias.portaldofranchising.com.br/franquia-happy-co/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75bn00aweh0sm9rybwph', 'SUBURBANOS', 'suburbanos', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Delivery e balcĂŁo. A suburbanos nasceu com o propĂłsito de trazer uma pizza de qualidade e preĂ§o justo para seus clientes, junto com uma identidade visual alegre, inovadora e fora do padrĂŁo.', 2020, 2022, '[\"https://www.youtube.com/watch?v=37pTzBPPAoU\",\"https://www.youtube.com/watch?v=IrkhT-6xAA0\"]', '2026-04-01 02:00:05.141', '2025-08-05 22:20:26.291', 429, NULL, 1, 2018, 'A Suburbanos surgiu a partir da ideia de 2 primos que nasceram no subĂșrbio da Zona Oeste e queriam empreender, um deles tinha uma pizzaria, enquanto o outro empreendia com outros negĂłcios, entĂŁo em um bate papo descontraĂ­do pensaram em unir seus conhecimentos. \nCarregando as origens de onde nasceram para montar um negĂłcio que remetesse as cores, o carinho e o gosto do lugar onde nasceram. \nEntĂŁo surgiu a marca Suburbanos no dia 5 de novembro de 2019 com uma pegada jovem e um nome ousado.', NULL, 'RIO DE JANEIRO', 1, NULL, 40, NULL, NULL, '2026-03-08 21:36:53.052', 'https://franquias.portaldofranchising.com.br/franquia-suburbanos/', NULL, NULL, NULL, 1, NULL, 0, 0,