INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75dc00b7eh0smiz59nu3', 'EMPĂRIO MINEIRO CHEIRIN BĂO', 'emporio-mineiro-cheirin-bao', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'EmpĂłrio de produtos tipicamente Mineiros e Cafeteria com cafĂ©s especiais do Sul de Minas!', 2016, 2018, '[\"https://www.youtube.com/watch?v=5ADd5sH3Bac\",\"https://www.youtube.com/watch?v=95aw762gVJg\",\"https://www.youtube.com/watch?v=QzQLTO5iAnQ\"]', '2026-04-01 02:00:05.247', '2025-08-05 22:20:26.352', 440, NULL, 1, 2013, 'Empreenda com a maior rede de cafeterias do Brasil! Com mais de 800 franquias espalhadas em todo o Brasil, nos tornamos a maior rede de cafeterias no mercado nacional! Muito mais do que cafeteria de cafĂ©s especiais nos tornamos especialistas em proporcionar momentos Ășnicos e criar boas memĂłrias atravĂ©s de sensaĂ§Ă”es e aromas que remetem as melhores lembranĂ§as da nossa vida. Nos conectamos com nossos clientes atravĂ©s do famoso âjeitin mineiroâ, o cheirin de cafĂ© passado na hora, o bolo quentinho que lembra a casa da vĂł e delĂ­cias mineiras recheadas de tradiĂ§ĂŁo, originalidade e muito afeto! Cheirin BĂŁo recebe trĂȘs dos prĂȘmios mais importantes do franchising em evento promovido pela ABF em 2022! No maior evento do Franchising brasileiro, promovido pela AssociaĂ§ĂŁo Brasileira de Franchising (ABF), fomos reconhecidos com trĂȘs prĂȘmios: Selo de ExcelĂȘncia em Franchising 2022 PrĂȘmio Destaque Franchising ABF na categoria Franqueado por InovaĂ§ĂŁo PrĂȘmio Destaque Franchising ABF na categoria Sustentabilidade Ă motivo de muito orgulho e comemoraĂ§ĂŁo ter tido o reconhecimento do ĂłrgĂŁo que auxilia o mercado de franquias a crescer e se desenvolver. Com a Cheirin BĂŁo vocĂȘ encontra um negĂłcio validado, marca consolidada, a seguranĂ§a e rentabilidade que vocĂȘ precisa! Fature atĂ© R$104 Mil por mĂȘs com a sua Cheirin BĂŁo GraĂ§as a um modelo de negĂłcio sĂłlido com estratĂ©gias validadas, com a sua Cheirin BĂŁo vocĂȘ pode obter atĂ© R$104 Mil de faturamento por mĂȘs! Esses sĂŁo resultados potenciais para o nosso modelo de negĂłcio, que podem variar de acordo com a gestĂŁo do franqueado. Na Cheirin BĂŁo vocĂȘ tem a seguranĂ§a e rentabilidade que vocĂȘ precisa!', NULL, 'MINAS GERAIS', 1, NULL, 588, NULL, NULL, '2026-03-08 21:46:37.822', 'https://franquias.portaldofranchising.com.br/franquia-emporio-mineiro-cheirin-bao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '332900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
