INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ed00beeh0szib7jf6e', 'UZA', 'uza', NULL, 'Moda', 'CalĂ§ados', 'CALĂADOS E ACESSĂRIOS DE MODA FEMININA', 2016, 2021, '[\"https://www.youtube.com/watch?v=Pp264Af2Oyk\"]', '2026-04-01 02:00:05.314', '2025-08-05 22:20:26.390', 447, NULL, 1, 2001, 'Em 2001 a UZA emergia com o propĂłsito de trazer ao mercado, calĂ§ados femininos que estivessem em sintonia com o lifestyle da mulher contemporĂąnea por meio de um design sofisticado e singular. Inicialmente instalada em um pequeno pĂĄtio fabril atendendo ao mercado de multimarcas, a organizaĂ§ĂŁo desenvolveu sua trajetĂłria construindo uma identidade autoral em consonĂąncia com as necessidades do mercado. Sete anos mais tarde, alinhada Ă  crescente demanda por seus produtos, a marca passou a ocupar novas instalaĂ§Ă”es e projetar ampliaĂ§Ă”es focadas em novos mercados, onde em dezembro de 2013 estendeu-se ao varejo online. Em 2016, um novo marco para expansĂŁo da marca Ă© delineado atravĂ©s da inauguraĂ§ĂŁo da sua flagship store no Shopping Cidade Jardim, em SĂŁo Paulo, iniciando assim o projeto de sistema de franquias. Atualmente, alĂ©m da sua contĂ­nua e crescente atuaĂ§ĂŁo por meio das franquias implementadas pelo paĂ­s, atende tambĂ©m a demanda de mais de 800 lojas multimarcas distribuĂ­das no Brasil e no exterior e, empreende de maneira ascendente no varejo online. Todas as lojas da rede trazem a identidade da marca apresentada por meio das instalaĂ§Ă”es que compreendem um projeto arquitetĂŽnico que expĂ”e os produtos de forma a gerar o desejo de experimentaĂ§ĂŁo e compra. O sapato Ă© um Ă­cone apaixonante e difusor de poder para as mulheres, por isso, esse cenĂĄrio representa a figura de um closet, feito com materiais que refletem autoridade e atualidade.', NULL, 'SĂO PAULO', 1, NULL, 49, NULL, NULL, '2026-03-08 21:53:28.732', 'https://franquias.portaldofranchising.com.br/franquia-uza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
