INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ez00bieh0s5c8ak181', 'CASA PILĂO', 'casa-pilao', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Coffee Shops. Rede de cafeterias da marca lĂ­der no mercado de cafĂ©s no Brasil, a Casa PilĂŁo foca em qualidade com cafĂ©s espressos e coados, alĂ©m de cappuccinos, bebidas geladas, doces e salgados.', 2013, 2013, '[\"https://www.youtube.com/watch?v=Q7CK9h2ml6g\"]', '2026-04-01 02:00:05.355', '2025-08-05 22:20:26.411', 451, NULL, 1, 2010, 'A Casa PilĂŁo Ă© uma marca tradicional e lĂ­der de mercado. \nCom um conceito de brasilidade, ambiente aconchegante e atrativo, a Casa PilĂŁo possui um mix variado de produtos de qualidade, produzido por fornecedores homologados. LĂ­der em vendas, seu objetivo Ă© deixar os clientes Ă  vontade dentro do espaĂ§o e, para isso, a Casa PilĂŁo oferece diversas opĂ§Ă”es de cafĂ© espresso, cappuccinos e bebidas frias e aquecimento quente Ă  base de cafĂ©, alĂ©m dos seus processos de cafĂ©s coados na hora. Na cafeteria, alĂ©m do cafĂ© em si, que pode ser servido de diversas formas atrativas, tambĂ©m hĂĄ comercializaĂ§ĂŁo de outros alimentos como salgados, biscoitos ou doces. Permitindo uma experiĂȘncia deliciosa como acompanhamento e agregam no faturamento da unidade.', NULL, 'SĂO PAULO', 1, NULL, 15, NULL, NULL, '2026-03-09 15:16:00.102', 'https://franquias.portaldofranchising.com.br/franquia-casa-pilao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '240000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75f500bjeh0sbzza6ig5', 'ANIMALIAFARMA', 'animaliafarma', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'FarmĂĄcia de ManipulaĂ§ĂŁo VeterinĂĄria', 2016, 2017, NULL, '2026-04-01 02:00:05.365', '2025-08-05 22:20:26.417', 452, NULL, 1, 2011, 'A Animalia Farma Ă© uma farmĂĄcia de manipulaĂ§ĂŁo veterinĂĄria, pioneira em seu segmento na cidade de Araraquara e regiĂŁo. Conta com um corpo profissional altamente especializado, as proprietĂĄrias sĂŁo farmacĂȘuticas que possuem pĂłs-graduaĂ§ĂŁo na ĂĄrea de FĂĄrmacos e Medicamentos (Mestrado e Doutorado na Faculdade de CiĂȘncias FarmacĂȘuticas â Unesp e PĂłs Doutorado na Universidade Estadual Paulista - USP) e ampla experiĂȘncia no setores de pesquisa e desenvolvimento de produtos na indĂșstria veterinĂĄria. \nNosso projeto de expansĂŁo comeĂ§ou com o aperfeiĂ§oamento dos nossos serviĂ§os nos primeiros trĂȘs anos, nĂŁo sĂł na forma de gerenciar e aprimorar nosso negĂłcio, mas no desenvolvimento de formas farmacĂȘuticas e fĂłrmulas exclusivas de diversos formatos e sabores a fim de facilitar a administraĂ§ĂŁo aos pets e a adesĂŁo dos mesmos ao tratamento. \nAs formulaĂ§Ă”es de nossa pasta oral e biscoitos sĂŁo Ășnicas, o que nos torna diferenciados das demais empresas do ramo. Investimos constantemente em pesquisa, tecnologia e conhecimento nosso e de nossos colaboradores, realizando melhorias contĂ­nuas em processos e produtos. Nossa sede foi inaugurada em Araraquara em 2011. Em 2014 inauguramos uma filial em RibeirĂŁo Preto , depois vieram as unidades nas cidades de Piracicaba em 2017, em 2018 SĂŁo Carlos e Campinas, e em 2019 SĂŁo Paulo e Bebedouro', NULL, 'SĂO PAULO', 1, NULL, 15, NULL, NULL, '2026-03-08 21:55:54.729', 'https://franquias.portaldofranchising.com.br/franquia-animaliafarma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
