INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fl00bmeh0sm597hc5f', 'BELLA GULA', 'bella-gula', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Tortaria e CafĂ©', 1999, 1993, NULL, '2026-04-01 02:00:05.393', '2025-08-05 22:20:26.433', 455, NULL, 1, 1993, 'A Bella Gula Ă© uma rede de franquias gaĂșcha de Tortaria e CafĂ©,Â com forte atuaĂ§ĂŁo no mercado local desde 1993 e foi concebida pelo entĂŁo jovem casal Bernardo e Daniella Thomaz unindo a paixĂŁo e o super talento dela em criar delĂ­cias fantĂĄsticas com a grande expertise administrativa dele. \nEles escolheram Porto Alegre para iniciar este sonho e a data de aniversĂĄrio dele, 21 de maio, para ser o primeiro dia, de sua primeira loja. \nDepois desta, vieram muitas outras num processo formatado de franquias. Atualmente a Bella Gula estĂĄ rompendo os limites geogrĂĄficos do Brasil e levando suas delĂ­cias para os Estados Unidos, dando inĂ­cio a sua internacionalizaĂ§ĂŁo. O sonho cresceu! Todo o mix da marca tem como caracterĂ­stica fundamental ser natural e nĂŁo utilizar aditivos quĂ­micos e conservantes em sua formulaĂ§ĂŁo. \nEm sua fĂĄbrica prĂłpria, apesar de serem produzidas toneladas de produtos, a Bella Gula faz questĂŁo de manter a artesanalidade no processo de produĂ§ĂŁo das tortas e doces que sĂŁo feitos Ă  mĂŁo, com muito amor, cuidado e carinho por confeiteiras que estĂŁo na empresa desde o seu inĂ­cio, garantindo assim o sabor incrĂ­vel e qualidade impecĂĄvel em todos os produtos. A Bella Gula proporciona uma experiĂȘncia Ășnica e se consolidou no mercado com mais de 30 lojas espalhadas no Rio Grande do Sul, ParanĂĄ e SĂŁo Paulo. \nAlĂ©m de ser uma das franquias de alimentaĂ§ĂŁo mais premiadas do Sul do Brasil, com 10 selos de ExcelĂȘncia em Franchising da ABF. \nAlĂ©m deste, estĂĄ hĂĄ 15 anos consecutivos entre as 10 melhores franquias do paĂ­s, nomeadas pela Revista Pequenas Empresas, Grandes NegĂłcios. O faturamento mĂ©dio anual de uma franquia Ă© de R$1.200.000,00, com uma lucratividade entre 10 e 20%, payback de 24 a 36 meses e investimento mĂ©dio entre R$350.000,00 e R$450.000,00 (incluindo a taxa de franquia).', NULL, 'RIO GRANDE DO SUL', 1, NULL, 26, NULL, NULL, '2026-03-09 17:20:13.748', 'https://franquias.portaldofranchising.com.br/franquia-bella-gula-docerias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '350000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75fq00bneh0s7uqftb6q', 'FARMĂCIA ROVAL', 'farmacia-roval', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'FarmĂĄcia de ManipulaĂ§ĂŁo', 2009, 2009, '[\"https://www.youtube.com/watch?v=-YRsv4CxjmA\",\"https://www.youtube.com/watch?v=VJf2R9mSwsE\",\"https://www.youtube.com/watch?v=MBbwNGmCckQ\",\"https://www.youtube.com/watch?v=yEr6JCZ9zqw\"]', '2026-04-01 02:00:05.402', '2025-08-05 22:20:26.438', 456, NULL, 1, 1988, 'A FARMĂCIA ROVAL DE MANIPULAĂĂO foi fundada em 1988, no Recife, com a proposta de âmanipular medicamentos para todas as especialidades mĂ©dicasâ e com o firme propĂłsito de criar o intercĂąmbio MĂ©dico-FarmacĂȘutico, tĂŁo importantes para a melhoria da qualidade do tratamento dispensado ao cliente. Em 2010, optou-se por expandir o negĂłcio, atravĂ©s da ROVAL FRANCHISING LTDA e da criaĂ§ĂŁo de um sistema Ășnico de franquia que refletisse a sua expertise no segmento, a credibilidade da sua marca e a sua bem-sucedida atuaĂ§ĂŁo, nos moldes da Lei 13966/19; e tambĂ©m se associou Ă  ABF â AssociaĂ§ĂŁo Brasileira de Franquias, de quem recebeu um selo de excelĂȘncia apĂłs pesquisa junto aos seus franqueados, e atualmente conta com 80 unidades pelo Brasil. A FARMĂCIA ROVAL DE MANIPULAĂĂO Ă© uma empresa inovadora que tem como diferencial oferecer alternativas farmacĂȘuticas que viabilizem a manipulaĂ§ĂŁo de medicamentos personalizados e adaptados Ă s necessidades especiais de pacientes e prescritores. A empresa oferece tratamento adequado, com eficĂĄcia e seguranĂ§a, garantindo a manutenĂ§ĂŁo da saĂșde e qualidade de vida. NOSSO PROPĂSITO: Transformar a saĂșde e a vida das pessoas e dos animais.', NULL, 'PERNAMBUCO', 1, NULL, 62, NULL, NULL, '2026-03-08 21:58:43.963', 'https://franquias.portaldofranchising.com.br/franquia-farmacia-roval-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
