21:59:52.221', 'https://franquias.portaldofranchising.com.br/franquia-smart-fit-valor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '3530000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
