INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ge00breh0sfzkupl7k', 'START ANGLO BILINGUAL SCHOOL', 'start-anglo-bilingual-school', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Franquia de escolas bilĂ­ngues', 2023, 2024, '[\"https://www.youtube.com/watch?v=-3-XtI3IP9U\",\"https://www.youtube.com/watch?v=XkR6o2EDdkk\"]', '2026-04-01 02:00:05.441', '2025-08-05 22:20:26.463', 460, NULL, 1, 1960, 'A Start Anglo Bilingual School Ă© uma das franquias de EducaĂ§ĂŁo BĂĄsica mais inovadoras do paĂ­s. A rede Ă© a Ășnica que oferece excelĂȘncia em bilinguismo e em alta performance acadĂȘmica na mesma proporĂ§ĂŁo, como uma resposta aos desejos e necessidades de famĂ­lias e alunos do sĂ©culo XXI. Com menos de um ano de operaĂ§ĂŁo, a Start Anglo jĂĄ conta com duas flagships [SĂŁo JosĂ© do Rio Preto e Vila Mariana (SP), uma parceria com Liceu Pasteur, a partir de 2025]; uma unidade pronta em Alphaville (SP), inaugurada em janeiro; alĂ©m de 12 contratos assinados para 2025 e 2026. A rede nasceu fundamentada em dĂ©cadas de experiĂȘncia de renomados especialistas que se dedicaram em estudos e anĂĄlises da realidade das escolas privadas do Brasil. O modelo de negĂłcio Start Anglo foi elaborado com o respaldo de uma reconhecida consultoria de franchising da AmĂ©rica Latina, a Cherto. O plano de negĂłcios das escolas se fundamenta em anĂĄlises aprofundadas do mercado, criando um formato de franquia eficiente e saudĂĄvel, com resultados reais para os investidores. Dentre as variĂĄveis de sucesso da Start Anglo estĂŁo a oportunidade de adesĂŁo ao modelo de escola premium, a metodologia exclusiva pautada na excelĂȘncia, as jornadas de formaĂ§ĂŁo e certificaĂ§ĂŁo dos educadores, as ferramentas pioneiras de gestĂŁo escolar, a cultura de anĂĄlise de dados, relatĂłrios e aprendizado constante. Tudo isso permite que a Start Anglo se posicione no topo das melhores franquias de escolas bilĂ­ngues do Brasil, com projeĂ§Ă”es favorĂĄveis de rentabilidade e potencial de crescimento financeiro.', NULL, 'SĂO PAULO', 1, NULL, 2, NULL, NULL, '2026-03-08 22:00:35.523', 'https://franquias.portaldofranchising.com.br/franquia-start-anglo-bilingual-school/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '2550000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
