INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hd00bveh0s6ikpr0p4', 'MAG PAPELARIA', 'mag-papelaria', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Franquia de papelaria e presentes voltado para produtos que estimulam a organizaĂ§ĂŁo e produtividade, desde a escola atĂ© o mercado de trabalho.', 2018, 2019, '[\"https://www.youtube.com/watch?v=CO79VUNAnOE\",\"https://www.youtube.com/watch?v=z8hwqjTwMdA\"]', '2026-04-01 02:00:05.480', '2025-08-05 22:20:26.497', 464, NULL, 1, 2018, 'Somos uma marca que estimula a organizaĂ§ĂŁo e consequentemente a produtividade de jovens e adultos, desde a escola atĂ© o mercado de trabalho, e que usam o papel em paralelo ao digital para otimizar as multitarefas do dia a dia. \nO projeto da MagnĂłlia surgiu lĂĄ no inĂ­cio de 2018, quando 4 casais de amigos se juntaram e tiraram do papel o sonho de abrir um quiosque de papelaria focado em organizaĂ§ĂŁo, planejamento e produtividade.', NULL, 'DISTRITO FEDERAL', 1, NULL, 60, NULL, NULL, '2026-03-08 22:02:33.011', 'https://franquias.portaldofranchising.com.br/franquia-mag-papelaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '134900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75hj00bweh0stf0tyo33', 'SOBRANCELHAS DESIGN', 'sobrancelhas-design', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Unidades especializadas em Tratamentos para Sobrancelhas, CĂ­lios e Maquiagem de alto padrĂŁo', 2012, 2013, NULL, '2026-04-01 02:00:05.491', '2025-08-05 22:20:26.504', 465, NULL, 1, 2012, 'Marca forte e referĂȘncia para o mercado, o Grupo Sobrancelhas Design despertou o mundo para a importĂąncia das sobrancelhas dentro do nicho de beleza e bem-estar. Consolidado como lĂ­der absoluto do segmento com mais de 400 lojas distribuĂ­das pelo Brasil, Estados Unidos e AmĂ©rica Central, Ă© a primeira rede de lojas dedicada exclusivamente ao design de sobrancelhas no mundo e realiza, em mĂ©dia, mais de 3 milhĂ”es de atendimentos por ano. A Sobrancelhas Design possui a mais renomada tĂ©cnica do mercado, que considera diversos aspectos como: formato do rosto, linhas de expressĂŁo, quantidade, tipo e cor dos fios, alĂ©m, Ă© claro, da simetria facial e identidade, bem como o gosto pessoal da cliente. Analisando todos esses pontos Ă© possĂ­vel encontrar o formato ideal de sobrancelha para cada rosto, realĂ§ando a beleza natural e proporcionando uma expressĂŁo mais bonita. As unidades da SD contam com instalaĂ§Ă”es inteligentes que proporcionam conforto e bem-estar Ă s clientes que as frequentam, alĂ©m do Kit Individual de Atendimento SD com o nosso incrĂ­vel gel tonalizante, especialmente desenvolvido por IndĂșstria prĂłpria. Nossas profissionais sĂŁo capacitadas e treinadas pelo prĂłprio Grupo, que conta com dois Centros de Treinamentos e formaĂ§ĂŁo onde as profissionais contratadas aprendem a nossa tĂ©cnica exclusiva e os franqueados sĂŁo orientados sobre a gestĂŁo do negĂłcio. Profissionais com vasta experiĂȘncia em franchising auxiliam diariamente toda a rede de franqueados. O atendimento ao franqueado Ă© prestado de forma local, em sua prĂłpria regiĂŁo, atravĂ©s de gerentes operacionais que acompanham integralmente cada novo franqueado. Os masters franqueados orientam o franqueado durante todo o processo de implantaĂ§ĂŁo e operaĂ§ĂŁo da nova unidade. AlĂ©m do design, a franquia Sobrancelhas Design oferece tambĂ©m depilaĂ§ĂŁo facial com linhas orgĂąnicas e antibacterianas, exclusivas da marca. A tĂ©cnica utilizada Ă© a egĂ­pcia, que permite uma depilaĂ§ĂŁo melhor com menos irritaĂ§Ă”es e desconfortos. E tambĂ©m o SD Relax, um serviĂ§o de massagens relaxantes nos pĂ©s.Â  De tanto vivenciar o universo feminino e todas as suas nuances e necessidades, o Grupo Sobrancelhas Design desenvolveu tambĂ©m uma linha de maquiagem e acessĂłrios para make. JĂĄ consolidada como referĂȘncia no cuidado com as sobrancelhas, a SD MAKEâąUP expandiu a sua linha de produtos exclusivos para olhos, boca e rosto, mantendo o mesmo padrĂŁo de qualidade e alta tecnologia, jĂĄ reconhecidos, com ajuda dos principais profissionais e especialistas do segmento, como o conceituado hair stylist e maquiador Duda Molinos. A linha de maquiagem jĂĄ possui mais de 30 produtos de altĂ­ssimo padrĂŁo. Dentre os principais produtos da SD MAKEâąUP, vale o destaque para a Linha de Tratamento para TransformaĂ§ĂŁo das Sobrancelhas, que recupera as sobrancelhas falhadas, regenerando os folĂ­culos capilares e estimulando o crescimento de novos fios.', NULL, 'CEARĂ', 1, NULL, 125, NULL, NULL, '2026-03-08 22:03:09.019', 'https://franquias.portaldofranchising.com.br/franquia-sobrancelhas-design-estetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
