INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ij00c2eh0sw88h0cxi', 'LAVO', 'lavo', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Lavanderia', 'Lavanderia de autoatendimento', 2019, 2020, '[\"https://www.youtube.com/watch?v=cxCxisc4c88\",\"https://www.youtube.com/watch?v=WRxdV4brFsc\"]', '2026-04-01 02:00:05.554', '2025-08-05 22:20:26.539', 471, NULL, 1, 2019, 'Em 2018 depois de ter experimentado o autosserviĂ§o em uma viagem aos EUA, pude notar que essa soluĂ§ĂŁo vem de encontro ao mercado brasileiro, em especial para cidades que tem altos Ă­ndices de umidade e a dificuldade de secar roupas, aliado ao fato de que o consumidor nĂŁo deseja mais investir grandes valores em mĂĄquinas de lavar e secar onde o espaĂ§o para acomoda-las nos apartamentos estĂĄ cada vez menor. No mesmo ano, o empresĂĄrio â que antes da LavĂŽ trabalhouÂ 25 anos na ĂĄrea comercial â comeĂ§ou a pesquisar sobre esse modelo de negĂłcio e resolveu abrir uma unidade de testes em BalneĂĄrioÂ CamboriĂș. âApesar de morar em SĂŁo Paulo, eu sabia que a concorrĂȘncia na cidade era muito maiorâ, explica. âO fato deÂ BalneĂĄrio CamboriĂșÂ ser uma cidade litorĂąnea, onde as pessoas sujam muito as roupas, tambĂ©m influenciou na escolhaâ. Formado emÂ Marketing pela Faculdade Anhanguera,Â com pĂłs-graduaĂ§ĂŁo emÂ GestĂŁo de ProjetosÂ (Senac) e especializaĂ§ĂŁo em EnergiaÂ Solar (Unicamp), Donaton criou a LavĂŽ como um modelo de negĂłcio com baixo investimento, retorno rĂĄpido e que dispensa contrataĂ§ĂŁo de funcionĂĄrios. O projeto foi um grande sucesso e inspirou a abertura da primeira unidade em outubro de 2019. Nas unidades da marca, o tempo total de utilizaĂ§ĂŁoÂ doÂ serviĂ§o Ă© de aproximadamente uma hora entre lavagem e secagem. Em um ciclo completo, o usuĂĄrio pode lavar atĂ© 10 quilos de roupas (25 peĂ§as, em mĂ©dia). O modelo de negĂłcios permite a adoĂ§ĂŁo de um horĂĄrioÂ de funcionamento flexĂ­vel â as lojas podem operar 24 horas por dia, sete dias por semana.Â O pĂșblico que consome o serviĂ§o Ă© variado, incluindo desde jovens solteiros e donas de casa e aposentados. Em julho, a LavĂŽ passou a ser uma das marcas aceleradas pela 300 Franchising, empreendimento liderado pelos irmĂŁos empresĂĄrios Leandro e Leonardo Castelo, fundadores da Ecoville, a maior rede de produtos de limpeza do paĂ­s. Com o suporte da 300 Franchising no processo de expansĂŁo, a LavĂŽ projeta encerrar o ano com 35 unidades e um faturamento de R$ 700 mil. Para 2021, a projeĂ§ĂŁo Ă© de um total de 120 lojas, com faturamento de R$ 2 milhĂ”es. Segundo Donaton, a crise gerada pela pandemia nĂŁo teve impacto significativo nos negĂłcios da marca. âCom a crise, mudamos alguns planos de inauguraĂ§Ă”es de unidades, mas esse momento nosÂ fez sairÂ do lugar comumÂ e encontrarÂ outras formas de expandir oÂ negĂłcio. Foi assim que comeĂ§amos o projeto de expansĂŁo e conhecemos a 300 Franchisingâ, conta o empresĂĄrio. âEmÂ agosto, a 300 Franchising comeĂ§ouÂ a operar a vendaÂ deÂ franquias.â', NULL, 'SĂO PAULO', 1, NULL, 663, NULL, NULL, '2026-03-08 22:06:13.920', 'https://franquias.portaldofranchising.com.br/franquia-lavo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '211000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
