xclusivos.', NULL, 'SĂO PAULO', 1, NULL, 119, NULL, NULL, '2026-03-08 22:07:34.139', 'https://franquias.portaldofranchising.com.br/franquia-sleep-house/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '60000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
