INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ja00c7eh0soivxjwsi', 'HSH - HOME SUSHI HOME', 'hsh-home-sushi-home', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Empresa especializada em delivery de comida japonesa.', 2018, 2019, '[\"https://www.youtube.com/watch?v=T1N81kq_-HA\",\"https://www.youtube.com/watch?v=04WQBH6r9Lc\",\"https://www.youtube.com/watch?v=mE7Bg10trZo\",\"https://www.youtube.com/watch?v=cnTTAySrD_M\"]', '2026-04-01 02:00:05.606', '2025-08-05 22:20:26.567', 476, NULL, 1, 2016, 'A Rede de Franquias HSH, com origem em JoĂŁo Pessoa, Ă© uma empresa que nasceu atravĂ©s da marca HOME SUSHI HOME em 2016, com o objetivo de proporcionar aos clientes a experiĂȘncia de saborear um sushi de qualidade no conforto de suas casas. Desde o inĂ­cio, a Franquia HSH se destacou por oferecer um cardĂĄpio diversificado de sushi, combinando ingredientes frescos e tĂ©cnicas tradicionais da culinĂĄria japonesa. Com um modelo de negĂłcio enxuto e focado no mercado de delivery, a empresa expandiu sua presenĂ§a para outras regiĂ”es do paĂ­s e hoje atua em 25 cidades (de Norte a Sul). Ao longo dos anos, a Franquia HSH ampliou seu leque de produtos/marcas dentro da mesma estrutura (Poke, Comida asiĂĄtica quente e Pizza), consolidando uma base fiel de clientes e se tornando referĂȘncia nacional no segmento de delivery. Agora, busca expandir para outras cidades atravĂ©s de um modelo de Franquia em que o Franqueado opera atĂ© 4 marcas com um investimento inicial atrativo (abaixo da mĂ©dia de mercado), custo operacional baixo e diluĂ­do e uma equipe multidisciplinar. Isso tudo atravĂ©s de uma logĂ­stica operacional simples, onde os pedidos de todas as marcas sĂŁo centralizados em Ășnico computador.', NULL, 'PARAĂBA', 1, NULL, 20, NULL, NULL, '2026-03-08 22:09:14.857', 'https://franquias.portaldofranchising.com.br/franquia-hsh-home-sushi-home/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
