INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75jr00caeh0synkz74uh', 'PEIXINHO FELIZ', 'peixinho-feliz', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escola de EducaĂ§ĂŁo Infantil para crianĂ§as a partir de 4 meses de idade. Metodologia exclusiva e inovadora. Investimentos flexĂ­veis. Suporte permanente. Garantia de resultados.', 2011, 2022, '[\"https://www.youtube.com/watch?v=NxmSSGVphxk\"]', '2026-04-01 02:00:05.634', '2025-08-05 22:20:26.583', 479, NULL, 1, 2002, 'A Escola de EducaĂ§ĂŁo Infantil Peixinho Feliz nasceu do desejo da sua idealizadora, Damir Forner, de promover mudanĂ§as na prĂĄtica pedagĂłgica da educaĂ§ĂŁo infantil e contribuir para a sua melhoria. A finalidade primordial da escola Ă© oferecer Ă s crianĂ§as amor e seguranĂ§a e aos pais a tranquilidade necessĂĄria para desempenhar suas atividades profissionais, sabendo que seus filhos estĂŁo recebendo cuidados, educaĂ§ĂŁo e acompanhamento personalizado do seu aprendizado e desenvolvimento. A FranquiaÂ Peixinho Feliz nasceu em 2004, apĂłs intensos e consistentes estudos desenvolvidos na ĂĄrea da Pedagogia, Psicopedagogia, da LinguĂ­stica e da NeurociĂȘncia. A metodologia Peixinho Feliz Ă© decorrĂȘncia de estudos teĂłricos e prĂĄticos realizadas no Brasil e no Exterior, principalmente nos Estados Unidos. Desde os seus primeiros passos, a Peixinho Feliz tem obtido um grande sucesso no planejamento, execuĂ§ĂŁo e formataĂ§ĂŁo da Franquia com sistemas didĂĄticos, pedagĂłgicos, operacionais, administrativos e financeiros, testados e em permanente evoluĂ§ĂŁo. A Franquia Peixinho Feliz Ă© ideal para empresĂĄrios, empreendedores e novos investidores, que nĂŁo precisam ser da ĂĄrea da educaĂ§ĂŁo, e que buscam uma opĂ§ĂŁo de negĂłcio seguro e rentĂĄvel em um dos segmentos que mais cresce no Brasil. Tudo com o respaldo de uma marca que Ă© referĂȘncia em EducaĂ§ĂŁo Infantil de qualidade.', NULL, 'SANTA CATARINA', 1, NULL, 8, NULL, NULL, '2026-03-08 22:10:38.092', 'https://franquias.portaldofranchising.com.br/franquia-peixinho-feliz/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '340000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
