INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75kw00ceeh0sjpyo37z6', 'INSTITUTO GOURMET FORMAĂĂO PROFISSIONAL', 'instituto-gourmet-formacao-profissional', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'O Instituto Gourmet Ă© a maior rede nacional de franquia em cursos profissionalizantes em gastronomia criado para quem deseja ingressar no mercado gastronĂŽmico, empreender e obter formaĂ§ĂŁo profissional', 2016, 2017, '[\"https://www.youtube.com/watch?v=5xqFvnRuon4\",\"https://www.youtube.com/watch?v=1jV4RsbMyf0\",\"https://www.youtube.com/watch?v=rDqNqP3kdQY\",\"https://www.youtube.com/watch?v=4wuPjmtt9Ms\"]', '2026-04-01 02:00:05.670', '2025-08-05 22:20:26.624', 483, NULL, 1, 2014, 'Instituto Gourmet - A RevoluĂ§ĂŁo do Empreendedorismo GastronĂŽmico no Brasil Em 2014, na cidade de Serra, EspĂ­rito Santo, nasceu um sonho: transformar vidas atravĂ©s da gastronomia. Assim surgiu o Instituto Gourmet Brasil, uma marca que ensina tĂ©cnicas gastronĂŽmicas de forma prĂĄtica, presencial, empodera pessoas a mudarem suas histĂłrias e trilharem um caminho de sucesso dentro desse segmento. Fundado com a visĂŁo de democratizar o acesso ao conhecimento gastronĂŽmico de alta qualidade, o Instituto Gourmet rapidamente ganhou destaque. Seu impacto foi tĂŁo significativo que, apenas dois anos depois da inauguraĂ§ĂŁo e inĂ­cio da operaĂ§ĂŁo no EspĂ­rito Santo, a marca expandiu para o estado do Rio de Janeiro, iniciando sua operaĂ§ĂŁo em Duque de Caxias. O sucesso foi instantĂąneo. As salas de aula lotadas e as histĂłrias de transformaĂ§ĂŁo pessoal e profissional tornaram-se a marca registrada da operaĂ§ĂŁo. Em 2016, impulsionado pelo impacto gerado e pela alta demanda, o Instituto Gourmet deu um passo ousado: adotou o modelo de franquias. Sob a lideranĂ§a visionĂĄria doÂ CEOÂ Glaucio Paiva Athayde, o crescimento foi meteĂłrico. Hoje, com mais de 110 escolas espalhadas por todo o Brasil, a marca Ă© referĂȘncia no segmento de educaĂ§ĂŁo gastronĂŽmica, formando empreendedores, entusiastas e profissionais do setor. Ao longo de sua trajetĂłria, mais deÂ 100 mil alunosÂ jĂĄ passaram pelo Instituto Gourmet. Muitos deles buscam aprimorar tĂ©cnicas, conquistar uma nova profissĂŁo, aprender por hobby e saem com suas vidas transformadas. Relatos de empreendedorismo bem-sucedido, superaĂ§ĂŁo, e reconhecimento profissional estĂŁo no DNA da marca em todas as regiĂ”es do paĂ­s. âHoje, nosso franqueado tem o poder de transformaĂ§ĂŁo social no territĂłrio que estĂĄ inserido, levando aos alunos atravĂ©s da gastronomia e do empreendedorismo, uma mudanĂ§a de vidaâ, reforĂ§a Glaucio Athayde, CEO. O Instituto Gourmet nĂŁo Ă© apenas uma escola de gastronomia, Ă© um movimento. Um movimento que conecta propĂłsito, tĂ©cnica e empreendedorismo. Liderado por um time que acredita na forĂ§a do conhecimento, a marca continua a inspirar milhares de brasileiros a saĂ­rem da zona de conforto e construĂ­rem um futuro mais saboroso e promissor. E a histĂłria continua. O prĂłximo capĂ­tulo? Ser escrito pelas mĂŁos daqueles que ousam sonhar. Uma marca com essĂȘncia e propĂłsito. Afinal, no Instituto Gourmet,Â cozinhar Ă© transformar vidas.', NULL, 'RIO DE JANEIRO', 1, NULL, 102, NULL, NULL, '2026-03-08 22:12:31.491', 'https://franquias.portaldofranchising.com.br/franquia-instituto-gourmet-formacao-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '294000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
