INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75lq00cieh0spbeuiz1m', 'OPT ĂCULOS', 'opt-oculos', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Ăticas', 'ComĂ©rcio varejista de armaĂ§Ă”es de Ăłculos, lentes de grau e acessĂłrios para Ăłculos', 2018, 2019, '[\"https://www.youtube.com/watch?v=E5oW5qTEP9M\"]', '2026-04-01 02:00:05.706', '2025-08-05 22:20:26.655', 487, NULL, 1, 2018, 'Fundada em 2018, a Opt Ăculos nasceu do desejo do seu fundador que, apĂłs 20 anos de experiĂȘncia no segmento Ăłptico, acreditava que a compra dos Ăłculos poderia ser uma experiĂȘncia mais agradĂĄvel e descomplicada. \nPara criar essa experiĂȘncia, a rede investe em tecnologia e pessoas, oferecendo vĂĄrios canais de contato integrados, sem abrir mĂŁo do atendimento humanizado. \nAtuando inicialmente no interior de SĂŁo Paulo, a partir de 2019 a rede iniciou o processo de expansĂŁo atravĂ©s do modelo de franquias com a missĂŁo de levar o conceito Opt Ăculos a um nĂșmero cada vez maior de brasileiros. \nAtualmente, a rede possui 34 lojas nos estados de SĂŁo Paulo, ParanĂĄ, Santa Catarina e Rio Grande do Sul, e a perspectiva Ă© de chegar a 300 lojas em atĂ© 2 anos atravĂ©s de 3 formatos de loja diferentes: Standard: Lojas de rua com atĂ© 40mÂČ. Full: Lojas de rua com aproximadamente 70mÂČ. Shopping: Lojas com aproximadamente 50mÂČ. Ser franqueado Opt Ăculos traz uma sĂ©rie de vantagens como: Modelo de negĂłcio Omnichannel com crescimento sustentĂĄvel e e-commerce compartilhado com os franqueados.\n\tÂ  Ătimo relacionamento e negociaĂ§ĂŁo com os principais fornecedores do segmento.\n\tÂ  Constante investimento em tecnologia para oferecer as melhores ferramentas de gestĂŁo e vendas aos franqueados.\n\tÂ  Plataforma EAD para capacitaĂ§ĂŁo e treinamento de toda equipe tĂ©cnica e vendas.\n\tÂ  Alto investimento em publicidade local e regional em mĂ­dias online e offline.\n\tÂ  LaboratĂłrio prĂłprio com equipamentos digitais de Ășltima geraĂ§ĂŁo.\n\tÂ  AĂ§Ă”es sociais para promover impactos positivos junto Ă s vizinhanĂ§as das franquias. A Opt Ăculos oferece suporte completo aos seus franqueados, permitindo que estes se concentrem exclusivamente na ĂĄrea comercial, enquanto toda a gestĂŁo da loja Ă© feita pela Central de GestĂŁo Opt.', NULL, 'SĂO PAULO', 1, NULL, 42, NULL, NULL, '2026-03-08 22:14:50.249', 'https://franquias.portaldofranchising.com.br/franquia-opt-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '195000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
