INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75m500ckeh0svd17zooa', 'VICOFLORA', 'vicoflora', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'Farmacia de manipulaĂ§ĂŁo de formulas, cosmĂ©ticos e produtos naturais. Linha completa suplementos alimentares para atletas e geriatria.', 1994, 2013, NULL, '2026-04-01 02:00:05.725', '2025-08-05 22:20:26.669', 489, NULL, 1, 1986, 'Com 27 anos de experiĂȘncia no mercado magistral, a qualidade de nossos produtos e serviĂ§os tem sido a receita do sucesso de nossa franquia. \nCom credibilidade no mercado, inovamos na criaĂ§ĂŁo do Centro TĂ©cnico e CientĂ­fico, onde a realizaĂ§ĂŁo de pesquisas e desenvolvimento de novos produtos sĂŁo prioridades. Criamos uma farmĂĄcia de manipulaĂ§ĂŁo moderna, onde o principal objetivo Ă© a excelĂȘncia da qualidade.\nÂ Â \nTransferimos aos nossos franqueados, todo o know-how necessĂĄrio para administraĂ§ĂŁo do negocio, desde a gestĂŁo administrativa, ĂĄrea tĂ©cnica, atendimento atĂ© o marketing mĂ©dico e tĂ©cnico. Nossos treinamentos sĂŁo realizados de forma contĂ­nua, em sintonia com o mercado e a legislaĂ§ĂŁo em vigor.Â Â Â  Manipulamos todas as substĂąncias permitidas no Brasil, em todas as especialidades, com todos os prescritores autorizados.Â  \nNosso suporte oferece a seguranĂ§a para os que estĂŁo entrando no segmento, jĂĄ que nossa equipe Ă© responsĂĄvel pela aprovaĂ§ĂŁo de projetos sanitĂĄrios, licenĂ§as e documentaĂ§ĂŁo junto Ă  ANVISA.Â  Â  \nSomos referĂȘncia no segmento, nĂŁo somente pela qualidade de nossos produtos, mas tambĂ©m, pela qualidade de nosso suporte tĂ©cnico, avaliado pela Revista Pequenas Empresas & Grandes negĂłcios, como a melhor da categoria. Por tudo isso, somos a Franquia de farmĂĄcia de manipulaĂ§ĂŁo mais premiada em 2013 e 2014.Â   VANTAGENS DO NEGĂCIO: TRANSFERĂNCIA DO KNOW-HOW \nâą GestĂŁo do NegĂłcio\nâą Projeto ArquitetĂŽnico e DocumentaĂ§ĂŁo SanitĂĄria\nâą ManipulaĂ§ĂŁo de todas as substĂąncias permitidas no Brasil\nâą Franqueadora certificada pela ISO 9000.\nâą Equipe formada por profissionais habilitados, com experiĂȘncia no mercado magistral. \nNossa equipe de suporte tĂ©cnico oferece seguranĂ§a aos franqueados, pois acompanham o mercado e a legislaĂ§ĂŁo sanitĂĄria. \nNossos treinamentos e reciclagem profissional sĂŁo contĂ­nuos, tanto aos franqueados, quanto aos seus funcionĂĄrios. Â  Ser um franqueadoÂ Vicoflora Ă© ter uma receita de sucesso!', NULL, 'SĂO PAULO', 1, NULL, 9, NULL, NULL, '2026-03-08 22:16:14.312', 'https://franquias.portaldofranchising.com.br/franquia-vicoflora-farmacias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
