INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75n800creh0sx7rjs0bu', 'ECOPOWER ENERGIA SOLAR', 'ecopower-energia-solar', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'SoluĂ§Ă”es em Energia Energia Solar, Energia Fotovoltaica, Integradora De Energia, Sustentabilidade, Energia RenovĂĄvel.', 2019, 2021, '[\"https://www.youtube.com/watch?v=A0sUnxDDq-c\",\"https://www.youtube.com/watch?v=So7R4KiO8E0\",\"https://www.youtube.com/watch?v=S_qj_dQoxTI\",\"https://www.youtube.com/watch?v=DdqlDT5Hq0M\"]', '2026-04-01 02:00:05.790', '2025-08-05 22:20:26.708', 496, NULL, 1, 2013, 'A EcoPower Ă© a lĂ­der brasileira em integraĂ§ĂŁo de energia solar nos sistemas fotovoltaicos. Desde nossa fundaĂ§ĂŁo em 2013, em Barretos, SP, pelos visionĂĄrios Anderson e NĂĄchila Oliveira, crescemos de forma impressionante. Com 38 mil projetos homologados pela ANEEL e mais de 350 franquias em todo o Brasil, nossa equipe de mais de 500 colaboradores se dedica a oferecer soluĂ§Ă”es energĂ©ticas de alta qualidade. Nossa operaĂ§ĂŁo presente nas 27 unidades federativas do Brasil. Orgulhamo-nos de ser uma das poucas empresas do setor com frota prĂłpria, percorrendo centenas de milhares de quilĂŽmetros mensais para atender nossos clientes com rapidez e eficiĂȘncia. Nossa trajetĂłria Ă© marcada por dois pilares fundamentais: Eco, que reflete nosso compromisso com a sustentabilidade, e Power, que demonstra nossa expertise em energia. Nossas soluĂ§Ă”es personalizadas e integradas atendem Ă s diversas necessidades dos clientes, garantindo qualidade e inovaĂ§ĂŁo. Somos Eco, Somos Power, Somos a energia que move o futuro.', NULL, 'SĂO PAULO', 1, NULL, 340, NULL, NULL, '2026-03-08 22:19:09.275', 'https://franquias.portaldofranchising.com.br/franquia-ecopower-energia-solar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '17500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ni00cseh0s6jr7mq5k', 'KOPENHAGEN', 'kopenhagen', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'BOMBONIĂRE E CAFETERIA - CHOCOLATERIA.', 1992, 1991, '[\"https://www.youtube.com/watch?v=dcGAaEfnS-k\",\"https://www.youtube.com/watch?v=aWd0rsFoPFs\"]', '2026-04-01 02:00:05.799', '2025-08-05 22:20:26.718', 497, NULL, 1, 1928, 'SĂŁo mais de 95 anos de histĂłria e experiĂȘncia consolidada como franqueadora, superando 570 pontos de venda em 27 estados do Brasil nos modelos de lojas e quiosques. \nQuem conhece a Kopenhagen garante sabores irresistĂ­veis que transcendem geraĂ§Ă”es e acompanham a vida de muitas pessoas. Somos 100% digitais, atuamos nos principais canais de venda online e possuĂ­mos uma base de CRM forte e estruturada com mais de 3MM de clientes.Â  Ser parte do time Kopenhagen Ă© pertencer a uma marca protagonista e desbravadora, que Ă© reconhecida e celebrada pelos clientes e pelo mercado de atuaĂ§ĂŁo.\nÂ   Â  Venha fazer parte dessa histĂłria de sucesso!', NULL, 'MINAS GERAIS', 1, NULL, 780, NULL, NULL, '2026-03-08 22:19:53.946', 'https://franquias.portaldofranchising.com.br/franquia-kopenhagen-bebidas-cafe-doces-e-salgados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '280000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75nn00cteh0s2f48f2ah', 'R-CRIO CĂLULAS-TRONCO', 'r-crio-celulas-tronco', NULL, 'SaĂșde, Beleza e Bem Estar', 'SERVIĂOS MĂDICOS', 'Produtos e serviĂ§os tĂ©cnicos especializados de coleta de cĂ©lulas-tronco mesenquimais provenientes do dente decĂ­duo (dente de leite), terceiro molar (dente do siso), periĂłsteo do palato, tecido adiposo', 2020, 2022, '[\"https://www.youtube.com/watch?v=ccTxKr8HZos\",\"https://www.youtube.com/watch?v=Mez4Pk9ec7I\"]', '2026-04-01 02:00:05.809', '2025-08-05 22:20:26.724', 498, NULL, 1, 2014, 'A R-Crio CĂ©lulas-tronco nasceu com o propĂłsito de garantir para a populaĂ§ĂŁo brasileira mais qualidade de vida associada Ă  jĂĄ conquistada longevidade. Desde 2014, ano de inĂ­cio das operaĂ§Ă”es comerciais, a empresa busca promover soluĂ§Ă”es para a populaĂ§ĂŁo ter acesso Ă  medicina regenerativa, uma nova forma de medicina que busca regenerar cĂ©lulas para tratar doenĂ§as comuns do envelhecimento. Nessa Ă©poca, o laboratĂłrio iniciou suas coletas por meio da polpa dentĂĄria de dentes de leite e dentes do siso, o que fez se tornar conhecida de dentistas do Brasil inteiro. Em 2020 passou a coletar cĂ©lulas-tronco de adultos e idosos por meio do CĂ©u da Boca (periĂłsteo do palato) e tambĂ©m do tecido adiposo. Esse Ășltimo com profissionais mĂ©dicos como coletores. O processo de coleta da R-Crio Ă© prĂĄtico e intuitivo para os profissionais coletores e tambĂ©m para as famĂ­lias. A coleta da R-Crio pouco incide na rotina da clĂ­nica ou do consultĂłrio, mas permite trazer uma nova forma de faturamento e fidelizaĂ§ĂŁo por meio do serviĂ§o inovador e Ășnico oferecido. Durante esses anos, a R-Crio desenvolveu mais de 50 artigos cientĂ­ficos, 12 patentes com depĂłsitos nacionais e internacionais, 8 livros dedicados a inovaĂ§ĂŁo em Medicina e Odontologia Regenerativas, projetos de pesquisa, participaĂ§ĂŁo em bancas de especializaĂ§ĂŁo, mestrado e doutorado com entidades de renome e referĂȘncia, alĂ©m de possuir hoje, em sua sede em Campinas/SP, um laboratĂłrio de pesquisa e desenvolvimento de biomateriais para serem associados Ă s cĂ©lulas armazenadas para oferecer uma soluĂ§ĂŁo completa para a saĂșde dos clientes. Hoje, a empresa conta tambĂ©m com iniciativas internacionais, possuindo uma cadeira tĂ©cnico-cientĂ­fica na Universidade de Laval, em QuebĂ©c, no CanadĂĄ, e um escritĂłrio dentro do LaboratĂłrio de CiĂȘncias da Vida, localizado na ĂĄrea do Kennedy Space Center, local de treinamento da NASA, na FlĂłrida. Por conta de tanta atuaĂ§ĂŁo em pesquisa cientĂ­fica comprometida com entrega de soluĂ§Ă”es para a saĂșde, a R-Crio se tornou referĂȘncia em criopreservaĂ§ĂŁo e processamento de cĂ©lulas-tronco no Brasil, oferecendo diferentes vantagens e diferenciais para seus clientes, como: Qualidade tĂ©cnica: cultivar cĂ©lulas em meio de cultura de soro humano, garantindo mais estabilidade genĂ©tica, e realizar treinamento com todo profissional coletor, exigindo tambĂ©m o envio de alvarĂĄ sanitĂĄrio vigente anualmente; TransparĂȘncia: notificar o cliente sobre os estĂĄgios do processo laboratorial em tempo real, e emitir um Certificado de CriopreservaĂ§ĂŁo impresso em papel moeda ao cliente no final do processo; InformaĂ§ĂŁo: enviar frequentemente notificaĂ§Ă”es aos clientes atualizaĂ§Ă”es da ĂĄrea da medicina regenerativa, bem como realizar consultorias com mĂ©dicos no caso de solicitaĂ§ĂŁo do produto para uso. RazĂ”es para se tornar um Franqueado R-Crio CĂ©lulas-tronco O serviĂ§o da R-Crio se torna cada vez mais contemporĂąneo, uma vez que os desafios da medicina se tornam maiores com o aumento da expectativa de vida e, consequentemente, das doenĂ§as crĂŽnicas-degenerativas, as quais nĂŁo possuem cura e muitas consistem no envelhecimento - ou mal funcionamento - das cĂ©lulas do organismo por conta do avanĂ§o da idade. A R-Crio estĂĄ levando Ă  investidores do Brasil todo a possibilidade de oferecer essa forma de prevenĂ§ĂŁo e acesso Ă  saĂșde por meio de uma rede franqueada suportada por diferentes iniciativas com foco no sucesso da operaĂ§ĂŁo do franqueado, sendo elas: FidelizaĂ§ĂŁo de pacientes e inovaĂ§ĂŁo: franqueados poderĂŁo levar para suas regiĂ”es um serviĂ§o garantido por exclusividade territorial, se destacando ainda mais em um mercado denso de profissionais de saĂșde e clĂ­nicas especializadas. Rapidez no retorno do investimento: a franquia R-Crio pode ser alocada dentro de uma clĂ­nica jĂĄ estabelecida, significando mais agilidade para inĂ­cio das operaĂ§Ă”es. AssistĂȘncia de marketing, vendas, recursos humanos e processos: todo know-how do laboratĂłrio Ă© repassado ao franqueado, bem como realizadas assistĂȘncias continuadas, treinamentos e consultoria de seleĂ§ĂŁo de ponto comercial; Portal de Relacionamento com Franqueado: intranet para gestĂŁo de vendas, notificaĂ§Ă”es, recebimento de materiais de marketing digital e gestĂŁo de pĂłs-vendas de serviĂ§os de clientes. TIPOLOGIAS DE UNIDADES FRANQUEADAS O Sistema de Franquia R-Crio CĂ©lulas-tronco prevĂȘ a utilizaĂ§ĂŁo de espaĂ§os fĂ­sicos em 3 modelos operacionais: âą TIPO 1 ClĂ­nicas ou consultĂłrios mĂ©dicos ou odontolĂłgicos, localizadas em estruturas de Shopping Centers, Centros ou Galerias MĂ©dicas e OdontolĂłgicas, Avenidas, RegiĂ”es Metropolitanas de Capitais de Estados e MunicĂ­pios polo acima de 100.000 mil habitantes, com metragem mĂ­nima a partir de 20mÂČ. âą TIPO 2 ClĂ­nicas ou consultĂłrios mĂ©dicos ou odontolĂłgicos que operam no modelo de negĂłcio Franquia Empresarial (franchising), localizadas em estruturas de Shopping Centers, Centros ou Galerias MĂ©dicas e OdontolĂłgicas, Avenidas, RegiĂ”es Metropolitanas de Capitais de Estados e MunicĂ­pios-polo acima de 100.000 mil habitantes, com metragem mĂ­nima a partir de 20mÂČ. âą TIPO 3 Estruturas mĂ©dicas e odontolĂłgicas que realizam atividades comercial e operacional de saĂșde em escala de rede hospitalar ou laboratorial privada, localizadas em Parques TecnolĂłgicos, Shopping Centers, Centros ou Galerias MĂ©dicas e OdontolĂłgicas, Avenidas, RegiĂ”es Metropolitanas de Capitais de Estados e MunicĂ­pios polo acima de 100.000 mil habitantes, com metragem mĂ­nima a partir de 40mÂČ', NULL, 'SĂO PAULO', 1, NULL, 5, NULL, NULL, '2025-09-09 16:06:11.000', 'https://franquias.portaldofranchising.com.br/franquia-r-crio-celulas-tronco/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
