INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ob00cxeh0sbl1qsa9f', 'GRUPO ACOLHER & CUIDAR', 'grupo-acolher-cuidar', NULL, 'SaĂșde, Beleza e Bem Estar', 'SERVIĂOS MĂDICOS', 'Atuamos no paciente com necessidades de atenĂ§ĂŁo de pequena a alta complexidade, com ĂȘnfase na recuperaĂ§ĂŁo e qualidade de vida em Ăąmbito domiciliar, hospitalar e em viagens.', 2021, 2022, '[\"https://www.youtube.com/watch?v=rX6q8xTQaqY\"]', '2026-04-01 02:00:05.847', '2025-08-05 22:20:26.748', 502, NULL, 1, 2016, 'O Grupo Acolher e Cuidar Franchising nasceu em 2016 em BrasĂ­lia-DF, com foco na realizaĂ§ĂŁo da prestaĂ§ĂŁo de serviĂ§os domiciliares em saĂșde atravĂ©s do atendimento de cuidador de idosos. A rede atua no ramo de home care em atendimento de pacientes com necessidades de cuidados de baixa, mĂ©dia e alta complexidade, com destaque para os serviĂ§os na ĂĄrea de reabilitaĂ§ĂŁo e qualidade de vida, prezando acima de tudo pelo conforto e seguranĂ§a. O franqueado precisa de um ponto fĂ­sico para operar e sĂŁo disponibilizados trĂȘs modelos de franquias: unidade fit, premium e home care, com investimento a partir de R$ 67 mil e prazo de retorno previsto em 16 meses. Nos diferenciamos das demais franquias atravĂ©s da operaĂ§ĂŁo validada, conte com quem jĂĄ chegou lĂĄ e conhece o caminho do sucesso, uma estrutura simplificada com o sistema de locaĂ§ĂŁo de aparelhos tendo um investimento mĂ­nimo em estrutura. AlĂ©m disso, dispomos de um modelo padronizado, pronto para comeĂ§ar a faturar, oferecemos manuais operacionais de apoio para a implantaĂ§ĂŁo e gestĂŁo da sua unidade. Contamos com um suporte tĂ©cnico, nossa equipe especializada irĂĄ auxiliĂĄ-lo no dia a dia de sua unidade e possuĂ­mos um sistema personalizado, um software desenvolvido especialmente para a Franquia Grupo Acolher & Cuidar.', NULL, 'DISTRITO FEDERAL', 1, NULL, 14, NULL, NULL, '2025-09-01 12:17:11.000', 'https://franquias.portaldofranchising.com.br/franquia-grupo-acolher-cuidar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
