INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75ou00d0eh0s9okaw4hc', 'L`ENTRECĂTE DE PARIS', 'l-entrecote-de-paris', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Restaurante de prato Ășnico, leva a uma experiĂȘncia sensorial em uma autĂȘntica brasserie parisiense. Prato principal Ă© o famoso entrecĂŽte, servido com molho secreto e batatas fritas Ă  vontade.', 2012, 2012, NULL, '2026-04-01 02:00:05.875', '2025-08-05 22:20:26.766', 505, NULL, 1, 2008, 'O clĂĄssico agora nas casas dos brasileiros \nAlto valor agregado, alta rentabilidade e agora com modelo enxuto com novas ĂĄreas de expansĂŁo. O LâEntrecĂŽte de Paris Ă© uma rede de restaurantes com prato Ășnico, com uma marca lĂ­der e reconhecida hĂĄ mais de 10 anos no mercado. \nO suculento entrecĂŽte fatiado recoberto pelo molho secreto Ă© oferecido pelo conceituado restaurante LâEntrecĂŽte de Paris por todo o paĂ­s desde 2009, agora traz a mesma sofisticaĂ§ĂŁo e qualidade para a casa dos seus clientes atravĂ©s do Delivery.  A receita: Foram necessĂĄrios dez anos de pesquisas para recriar o molho servido na capital francesa. \nDesde novembro de 2009, quando o LâEntrecĂŽte de Paris abriu as portas, a clientela pode saborear o contrafilĂ© banhado na consistente combinaĂ§ĂŁo de 21 ingredientes, que leva 36 horas para ficar pronta. \nPara garantir um padrĂŁo de excelĂȘncia em todas as franquias, os restaurantes seguem rigorosamente o mesmo padrĂŁo da unidade fundada em 2009 e, claro, o famoso molho secreto, que Ă© enviado para todas as unidades diretamente da fĂĄbrica. E estratĂ©gias de comunicaĂ§ĂŁo, comercializaĂ§ĂŁo e de gestĂŁo de relacionamento com o cliente tambĂ©m sĂŁo transferidas da matriz para as franquias.  Novo modelo: ApĂłs mais de 10 anos de sucesso no mercado, com unidades espalhadas pelas principais capitais do paĂ­s, e contabilizando mais de 500 mil pratos servidos, o LâEntrecĂŽte de Paris iniciou em 2020 o modelo de negĂłcio exclusivo para o delivery. Franquia de Delivery:Â A rede estĂĄ em expansĂŁo para todo o Brasil com um modelo de franquia dark-kitchen, ou seja, 100% focada para o delivery. Com a franquia delivery LâEntrecĂŽte de Paris vocĂȘ tem baixo investimento inicial, facilidade no dia a dia da operaĂ§ĂŁo e uma maior margem de lucro. \nDiferenciais de ter uma franquia LâEntrecĂŽte de Paris Delivery: \n* NĂŁo requer fachada nem estrutura de salĂŁo;\n* Economia com operacional de atendimento;\n* AluguĂ©is mais baratos do que em pontos como ruas de comĂ©rcio e shoppings.\n* Parceria exclusiva com o aplicativo iFoodÂ \n* Nossos franqueados tĂȘm acesso a taxas diferenciadas, significativamente menores;\n* Temos posicionamento destacado no app.', NULL, 'SĂO PAULO', 1, NULL, 28, NULL, NULL, '2026-03-08 22:22:57.119', 'https://franquias.portaldofranchising.com.br/franquia-lentrecote-de-paris-restaurantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '700000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
