INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75p500d2eh0scn8yjenp', 'HAVANNA', 'havanna', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'CAFETERIA ARGENTINA', 1998, 2015, NULL, '2026-04-01 02:00:05.894', '2025-08-05 22:20:26.777', 507, NULL, 1, 1939, 'COMO SURGIU A HAVANNA! \nA histĂłria da Havanna comeĂ§ou a ser escrita em 1939, quando o entusiasmo de dois jovens amigos e empreendedores falou mais alto, se expandiu e transformou-se em um dos maiores Ă­cones da Argentina! Os Alfajores Santa Monica, como eram comercializados no inicio de sua histĂłria, eram produzidos em uma pequena fĂĄbrica em Buenos Aires, tendo como um de seus principais clientes uma bomboniere de Mar Del Plata. \nA partir de uma relaĂ§ĂŁo comercial muito boa, nasceu uma grande amizade que fortaleceu a oportunidade de expansĂŁo da empresa, desafiando os dois amigos. \nLogo, a marca Havanna se tornou sinĂŽnimo de Alfajor e sĂ­mbolo de prazer, jĂĄ que naquela Ă©poca os argentinos e turistas passavam as fĂ©rias no balneĂĄrio e compravam os doces para presentear amigos e familiares. Possuem a mesma receita desde 1947, que foi aprimorada pelas mĂŁos do pasteleiro Toribio GonzĂĄles; Hoje na Argentina sĂŁo 202 lojas, sendo 59 prĂłprias e 141 franqueadas. \nNo exterior sĂŁo 92 pontos de venda, alĂ©m dos pontos de distribuiĂ§ĂŁo em todo o mundo. \nA Chegada da Havanna no Brasil foi em 2006. O sucesso foi instantĂąneo e nĂŁo demorou muito para que outras lojas e quiosques fossem inaugurados pelo paĂ­s. A partir de 2014, com a adoĂ§ĂŁo do sistema de franquia, a expansĂŁo nacional foi acelerada. \nA marca trabalha com dois modelos de negĂłcio: CafĂ© Quiosque e Cafeteria. Hoje sĂŁo mais de 50 pontos de venda espalhados por 18 estados brasileiros. \nÂ  MISSĂO, VISĂO E VALORES!\nÂ  Quem nĂŁo gosta de ter uma experiĂȘncia de consumo Ășnica? Fundamentada em conforto, acessibilidade, inovaĂ§ĂŁo e sabores que sejam ligados e fiĂ©is aos valores, a verdade da marca Havanna sĂŁo os seus principais pilares: Alfajor, Doce de Leite, Argentina. O modelo de negĂłcios Havanna Ă© baseado em excelĂȘncia, Ă©tica, melhoria contĂ­nua, superaĂ§ĂŁo de resultados, comprometimento, valorizaĂ§ĂŁo humana, experiĂȘncia de qualidade, inovaĂ§ĂŁo, respeito aos valores e Ă  verdade\nda marca e seus produtos, estabelecendo relaĂ§Ă”es de transparĂȘncia, integridade e respeito com fornecedores, colaboradores, clientes! Â  LOCALIZAĂĂO HAVANNA\nÂ  SĂŁo indicadas para shoppings, prĂ©dios comerciais, universidades, galerias, terminais rodoviĂĄrios, aeroportos, enfim, locais que tenham um grande fluxo de pessoas.\nÂ  Â  MODELOS DE NEGĂCIO HAVANNA\nÂ    CafĂ© Quiosque   \nÂ  Metragem: 18MÂČ de ĂĄrea operacional + ĂĄrea de mesas. Mix de Produtos: linha Havanna, produtos sazonais e produtos cafeterias.\n(sanduĂ­ches; tortas; cafĂ©s; drinks, salgados e crepe). Investimento: A partir de R$350.000,00 Taxa de franquia: R$65.000,00 (jĂĄ inclusa no investimento) Lucratividade: 12% ĂĄ 15% Capital de Giro: 3x o estoque inicial. Royalties: 5%* Taxa de Marketing: 2%* *Sobre o faturamento mensal bruto. Â    Cafeteria   \nMetragem: A Partir de 35MÂČ de ĂĄrea operacional + ĂĄrea de mesas. Mix de Produtos: linha Havanna, produtos sazonais e produtos cafeterias.Â \n(sanduĂ­ches; tortas; cafĂ©s; drinks, salgados e crepe). Investimento: A partir de R$520.000,00 Taxa de franquia: R$65.000,00 (jĂĄ inclusa no investimento) Lucratividade: 15% ĂĄ 18% Capital de Giro: 3x o estoque inicial. Royalties: 5%* Taxa de Marketing: 2%* *Sobre o faturamento mensal bruto.', NULL, 'SĂO PAULO', 1, NULL, 134, NULL, NULL, '2026-03-08 22:24:14.414', 'https://franquias.portaldofranchising.com.br/franquia-havanna/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '331000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pa00d3eh0s2kb70atq', 'OFICIAL MED', 'oficial-med', NULL, 'SaĂșde, Beleza e Bem Estar', 'FARMĂCIAS', 'Rede de farmĂĄcias de manipulaĂ§ĂŁo e suplementaĂ§ĂŁo personalizada', 2024, 2025, NULL, '2026-04-01 02:00:05.906', '2025-08-05 22:20:26.783', 508, NULL, 1, 2022, '', NULL, 'PARANĂ', 1, NULL, 3, NULL, NULL, '2025-05-09 14:21:18.000', 'https://franquias.portaldofranchising.com.br/franquia-oficial-med-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75pf00d4eh0sqwwvnnvj', 'LOCARX FRANCHISING', 'locarx-franchising', NULL, 'ServiĂ§os Automotivos', 'LocaĂ§ĂŁo de veĂ­culos', 'LocaĂ§ĂŁo de Veiculos', 2009, 2022, NULL, '2026-04-01 02:00:05.916', '2025-08-05 22:20:26.787', 509, NULL, 1, 2009, 'A LOCARX surgiu em 2009, quando cinco diferentes empresas de aluguel de veĂ­culos automotivos ex-franqueadas de uma das maiores redes de locadora do paĂ­s a Ă©poca, se uniram para partilhar conhecimento do mercado de locaĂ§ĂŁo de veĂ­culos e utilizar a marca, de maneira nacional, criando uma rede com uma frota de aproximadamente 500 veĂ­culos. Em 2010 a LOCARX estabeleceu a cidade de Salvador como sua sede, oportunidade em que a empreendedora Livia Villar passou a ser a sua administradora e principal executiva. Com o crescimento exponencial do mercado de franquias, no inĂ­cio de 2020, a LOCARX vislumbrou nesse forte segmento uma forma de expandir suas operaĂ§Ă”es. \nNesse sentido, e contando com a expertise de Luiz Villar, presente na LOCARX desde o inĂ­cio do projeto, foram iniciados os estudos mercadolĂłgicos para o lanĂ§amento da franquia LOCARX no final do ano de 2021. Em novembro de 2021 a LOCARX assina um acordo operacional com a 300 Franchising, maior aceleradora de franquias do Brasil. Â  MissĂŁo:Â Â  Proporcionar mobilidade e liberdade aos nossos clientes com excelĂȘncia e eficiĂȘncia no atendimento. Â  VisĂŁo:Â Â  Ser uma empresa lucrativa, eficiente e respeitada no mercado de locaĂ§ĂŁo de veĂ­culos, oferecendo serviĂ§os com qualidade e acessibilidade aos clientes, fornecedores e funcionĂĄrios. Â  Valores:Â  Respeito a relaĂ§Ă”es humanas; Comprometimento com a satisfaĂ§ĂŁo do cliente; Busca constante pela excelĂȘncia, Ă©tica e transparĂȘncia; ValorizaĂ§ĂŁo do trabalho em equipe; Respeito ao meio ambiente.\n\tÂ  Sistema de Franquia: A franquia LOCARX Ă© um mĂ©todo de se fazer negĂłcios em que a FRANQUEADORA concede ao(Ă ) FRANQUEADO(A), durante a vigĂȘncia do Contrato, o direito de instalar e operar uma Unidade Franqueada em determinada Ărea de AtuaĂ§ĂŁo, mediante a utilizaĂ§ĂŁo de know-how prĂłprio, para o desenvolvimento e operacionalizaĂ§ĂŁo do negĂłcio de locaĂ§ĂŁo de veĂ­culos automotivos, aplicaĂ§ĂŁo das tĂ©cnicas e metodologia operacional, administrativa e mercadolĂłgica desenvolvida pela FRANQUEADORA. A franquia LOCARX oferece Ă  sua rede diversas ferramentas que automatiza as rotinas operacionais, contribuindo para um melhor gerenciamento do negĂłcio, por meio da padronizaĂ§ĂŁo de informaĂ§Ă”es e visualizaĂ§ĂŁo de modo seguro, do desempenho e da lucratividade da unidade. O franchising proporciona a expansĂŁo de um conceito comprovado na operaĂ§ĂŁo da Unidade Franqueada, publicidade ampla e de alto impacto, marcas registradas reconhecidas, assistĂȘncia tĂ©cnica e gerencial contĂ­nua. Â  Por que fazer parte da rede de franquias LOCARX e quais as vantagens? Ao fazer parte da rede de franquias LOCARX o(a) FRANQUEADO(A) passa a integrar uma rede nacional de atendimento, podendo contar com as seguintes vantagens: UtilizaĂ§ĂŁo de software de gestĂŁo. Central de atendimento ao cliente 24 horas. GeraĂ§ĂŁo de negĂłcios â a rede trabalhando para a rede. TerceirizaĂ§ĂŁo da frota â Know How e tradiĂ§ĂŁo. 9/78 ForĂ§a de vendas. Descontos e condiĂ§Ă”es competitivas junto Ă s montadoras de veĂ­culos. Central de reservas. Site LOCARX. Treinamento â relaĂ§ĂŁo contĂ­nua. Sites nacionais de reservas online Site internacional de reserva online para as Unidades Franqueadas Aeroporto. Ferramentas digitais e sistemas auxiliares, os quais sĂŁo indispensĂĄveis para a operaĂ§ĂŁo da franquia LOCARX, cujo uso, e o respectivo custo, a ser pago pelo(a) FRANQUEADO(A), estĂĄ definido no Manual de OperaĂ§Ă”es. Â  Perfil do Franqueado LocarX Para ser um(a) Franqueado(a)da LOCARX, o(a) CANDIDATO(A) deve se enquadrar no perfil que, em linhas gerais, tenhas as seguintes caracterĂ­sticas: Empreendedor, organizado, comprometido, honesto e com noĂ§ĂŁo em administraĂ§ĂŁo geral. Preferivelmente com experiĂȘncia no ramo de automĂłveis, mas se nĂŁo tiver, que possua interesse em aprender as nuances de um negĂłcio que envolve alĂ©m da venda de serviĂ§os a comercializaĂ§ĂŁo dos veĂ­culos. Possuir disponibilidade financeira; Disponibilidade de tempo; Ă imprescindĂ­vel que o mesmo tenha residĂȘncia ou grande conhecimento da praĂ§a onde deseje instalar a unidade. IdentificaĂ§ĂŁo com a marca e a polĂ­tica da mesma, cumprindo as especificaĂ§Ă”es de identidade visual e metodologia de trabalho desenvolvidas pela Franqueadora.', NULL, 'BAHIA', 1, NULL, 26, NULL, NULL, '2026-03-08 22:25:59.551', 'https://franquias.portaldofranchising.com.br/franquia-locarx-franchising/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
