INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rb00dgeh0s8jgr1o4o', 'DINIZ LASER', 'diniz-laser', NULL, 'SaĂșde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'ClĂ­nica especializada em tratamentos estĂ©ticos a laser. A Diniz Laser conta com uma equipe de especialistas da ĂĄrea da saĂșde, com atendimento personalizado e focado na necessidade de cada cliente.', 2019, 2023, '[\"https://www.youtube.com/watch?v=cOHVrcf2Jqs\",\"https://www.youtube.com/watch?v=ivn2F-v6P6U\"]', '2026-04-01 02:00:06.030', '2025-08-05 22:20:26.855', 521, NULL, 1, 2019, 'Com mais de 15 anos de experiĂȘncia na ĂĄrea, em 2019, a empresĂĄria Ali Diniz trouxe aos clientes uma nova proposta de clĂ­nica especializada em tratamentos estĂ©ticos a laser. A Diniz Laser passa a ser a PRIMEIRA ESTĂTICA A LASER DO BRASIL. A Diniz Laser Ă© uma franqueadora de clĂ­nicas especializadas em tratamentos estĂ©ticos a laser. A marca possui um portfĂłlio completo envolvendo diversos tratamentos faciais e corporais a laser, todos eles de alta tecnologia e contando com os melhores equipamentos do mundo. A expansĂŁo estĂĄ em ritmo acelerado e nossa projeĂ§ĂŁo Ă© de 50 franquias para os prĂłximos meses, sendo que 90% dos nossos franqueados sĂŁo MULTIFRANQUEADOS, possuindo mais de uma unidade. O grande diferencial Ă© o baixo investimento e alta rentabilidade, que se caracteriza pela operaĂ§ĂŁo enxuta e ausĂȘncia de estoque de produtos para gerenciar. O plano de negĂłcio tem payback (retorno do investimento) entre 8 e 18 meses, lucro lĂ­quido mĂ©dio de 40% e faturamento anual estimado em 1,5 milhĂŁo de reais. Invista na Diniz Laser e seja dono de uma franquia da PRIMEIRA ESTĂTICA A LASER DO BRASIL.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 10, NULL, NULL, '2025-09-17 10:17:22.000', 'https://franquias.portaldofranchising.com.br/franquia-diniz-laser/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
