INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75rr00djeh0se3plulze', 'COLCCI', 'colcci', NULL, 'Moda', 'VestuĂĄrios', 'Desde 86 carregando a essĂȘncia jeanswear no seu DNA, a Colcci Ă© uma das mais renomadas marcas de moda brasileira. Disruptiva e vanguardista, a marca Ă© reconhecida por sua inovaĂ§ĂŁo, estilo e qualidade.', 1986, 2013, NULL, '2026-04-01 02:00:06.058', '2025-08-05 22:20:26.871', 524, NULL, 1, 1986, 'FRANQUIA COLCCI â A MAIOR MARCA DE JEANSWEAR DO BRASIL \nA Colcci Ă© considerada a maior marca de jeanswear nacional, presente em 130 lojas e mais de 2000 multimarcas, alĂ©m de contar com a presenĂ§a de distribuidores em todos os continentes.Â  \nA marca carrega em seu DNA a essĂȘncia do denim, se conectando com o pĂșblico jovem e urbano, atingindo o pĂșblico A e B da faixa etĂĄria dos 18 a 35 anos. \nSinĂŽnimo de moda, a Colcci traz sempre o melhor produto para nossos clientes. ReforĂ§ada atravĂ©s da poderosa imagem da uber model Gisele Bundchen e de grandes eventos como o SPFW. O mix amplo e diversificado que conta com itens de confecĂ§ĂŁo, sapatos e acessĂłrios , tanto para o pĂșblico feminino como para o pĂșblico masculino, impacta diversos estilos.  \nÂ  Vantagens em ser um franqueado COLCCI:\nÂ \n- Principal marca de jeanswear nacional\nÂ \n- ExperiĂȘncia de 30 anos de mercado\nÂ \n- Projeto arquitetĂŽnico padronizado\nÂ \n- AnĂĄlise e consultoria para a definiĂ§ĂŁo do ponto comercial\nÂ \n- Moderno software de gestĂŁo\nÂ \n- Acompanhamento prĂłximo do Consultor de Franquias\nÂ \n- Treinamentos de vendas e produtos, para a capacitaĂ§ĂŁo de equipe\nÂ \n- Acesso ao Guia Visual da marca e Visual Merchandising\nÂ \n- Apoio Ă  materiais de marketing e aĂ§Ă”es de varejo\nÂ \n- Amplo material estratĂ©gico para fomentar as vendas\nÂ \n- CondiĂ§Ă”es comerciais mais favorĂĄveis\nÂ \n- Suporte nos pedidos de compra\nÂ \n- Variado mix de produtos com mais de 1800 itens por coleĂ§ĂŁo\nÂ \n- Trabalhar com uma marca de reconhecimento internacional\nÂ \n- Suporte do Grupo AMC TĂȘxtil: Â proprietĂĄria da marca, o maior gestor de marcas da AmĂ©rica Latina', NULL, 'SANTA CATARINA', 1, NULL, 155, NULL, NULL, '2026-03-08 22:33:59.075', 'https://franquias.portaldofranchising.com.br/franquia-colcci-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
