INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75s500dmeh0sgb6p6zcn', 'LEZ A LEZ', 'lez-a-lez', NULL, 'Moda', 'VestuĂĄrios', 'Loja de vestuĂĄrio feminino. Somos moda, somos praia dentro da cidade, uma marca urbana com os pĂ©s na areia & cultura Urban Beach. Acreditamos que o equilĂ­brio entre a leveza da praia e a modernidade', 2008, 2016, '[\"https://www.youtube.com/watch?v=Kpcsh03Uy7Y\",\"https://www.youtube.com/watch?v=SgSS85szLF4\",\"https://www.youtube.com/watch?v=_yeifX8fDX8\"]', '2026-04-01 02:00:06.086', '2025-08-05 22:20:26.885', 527, NULL, 1, 1981, 'A Lez a Lez nasceu em 2006 e pertence a Lunelli, umas das principais indĂșstrias tĂȘxteis do Brasil que faz moda com significado hĂĄ mais de 40 anos. Atualmente, com 16 fĂĄbricas e 165.000mÂČ de ĂĄrea construĂ­da, a Lunelli tem um parque fabril com tecnologia de ponta, conta com mais de 4.800 colaboradores e produz 26 milhĂ”es de peĂ§as por ano. Dentre as premiaĂ§Ă”es e conquistas que a Lez a Lez recebeu, destacamos os 4 Ășltimos selos de ExcelĂȘncia em Franchising da ABF, os 3 selos de Franquia Internacional da ABF e tambĂ©m a pontuaĂ§ĂŁo que nos classificou como a Melhor Marca de Moda Feminina do Brasil, pelo Pequenas Empresas e Grandes NegĂłcios. A Lez a Lez estĂĄ presente em todos estados brasileiros, em mais de 2 mil pontos de vendas e contamos com 37 lojas no Brasil e tambĂ©m no exterior. Nossas lojas conceito estĂŁo localizadas na Oscar Freire e na praia de JurerĂȘ Internacional. Somos moda, somos praia dentro da cidade, uma marca urbana com os pĂ©s na areia & cultura Urban Beach. Acreditamos que o equilĂ­brio entre a leveza da praia e a modernidade da cidade faz o sol da gente brilhar bem mais bonito.', NULL, 'SANTA CATARINA', 1, NULL, 43, NULL, NULL, '2026-03-08 22:35:43.774', 'https://franquias.portaldofranchising.com.br/franquia-lez-a-lez/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
