INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75tp00dueh0sj01cndf9', 'SHOPMASP', 'shopmasp', NULL, 'Moda', 'CalĂ§ados', 'Franquia de Varejo Esportivo, focada nas maiores marcas mundiais, levando o que hĂĄ de melhor no ramo de calĂ§ados, confecĂ§Ă”es, acessĂłrios para nossas lojas, tornando-as referĂȘncia na regiĂŁo onde atuam', 2014, 2020, '[\"https://www.youtube.com/watch?v=2onl-ZleHYA\"]', '2026-04-01 02:00:06.163', '2025-08-05 22:20:26.940', 535, NULL, 1, 1979, 'A maior franquia de artigos esportivos da regiĂŁo Sul A Shopmasp, uma das 10 maiores redes de lojas de artigos esportivos do sul do Brasil, Ă© sinĂŽnimo de inovaĂ§ĂŁo e qualidade no setor. Atualmente, a rede conta com quase 50 lojas fĂ­sicas estrategicamente localizadas no sul do paĂ­s. HistĂłria da Shopmasp Fundada em 1979 pelos pais do atual proprietĂĄrio Marcelo Luis Vieira. A ideia de criar a loja surgiu do pai de Marcelo, um professor de educaĂ§ĂŁo fĂ­sica apaixonado por esportes. Ele decidiu transformar sua paixĂŁo em um negĂłcio. A primeira loja foi batizada de Marcelo Sports, em homenagem ao ?lho. Em 1993, Marcelo Luis Vieira assumiu a gestĂŁo do negĂłcio, trazendo uma visĂŁo estratĂ©gica e transformadora. Ele reposicionou a marca para atender ao segmento de estilo casual e elevou o padrĂŁo de qualidade da loja. O crescimento contĂ­nuo da loja culminou na decisĂŁo de expandir o negĂłcio por meio de franquias. Esse marco trouxe tambĂ©m uma nova identidade: o nome foi alterado de Marcelo Sports para Shopmasp. Hoje, a Shopmasp Ă© reconhecida por sua inovaĂ§ĂŁo, qualidade e lideranĂ§a no setor esportivo, focada em comercializar produtos das principais marcas esportivas do mercado, como Nike, Adidas, Asics e Mizuno.', NULL, 'SANTA CATARINA', 1, NULL, 22, NULL, NULL, '2026-03-08 22:38:30.388', 'https://franquias.portaldofranchising.com.br/franquia-shopmasp/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '209400', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
