INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75v800e0eh0sxoi02wbw', 'HARO SUSHI', 'haro-sushi', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Somos uma rede de restaurantes delivery com foco na culinĂĄria japonesa e chinesa.', 2019, 2022, '[\"https://www.youtube.com/watch?v=fH1bsh1wfTY\"]', '2026-04-01 02:00:06.220', '2025-08-05 22:20:26.997', 541, NULL, 1, 2017, 'Imagine uma jornada culinĂĄria que comeĂ§ou em 2017 e desde entĂŁo tem transformado o mercado do delivery no Brasil. ? Bem-vindo ao Grupo HarĂŽ, onde a inovaĂ§ĂŁo e a paixĂŁo pela gastronomia se unem para criar uma experiĂȘncia Ășnica. Somos mais do que uma simples franquia, somos a personificaĂ§ĂŁo do sucesso em seis segmentos diferentes? Sempre buscando estar a frente, construĂ­mos uma verdadeira miscelĂąnea de sabores, oferecendo nĂŁo apenas comida, mas uma experiĂȘncia gastronĂŽmica de tirar o fĂŽlego. Nosso segredo? Uma cozinha otimizada, estrategicamente projetada para reduzir os custos operacionais dos nossos parceiros e garantir que cada prato seja uma obra de arte ? Ao unir forĂ§as conosco, vocĂȘ nĂŁo apenas ingressa em uma franquia, mas sim em uma rede de empreendedores apaixonados, prontos para conquistar o paladar de milhares de clientes em todo o Brasil. Junte-se a nĂłs e embarque nessa jornada rumo ao sucesso, onde cada entrega Ă© mais do que um simples embalagem, Ă© uma promessa de excelĂȘncia e satisfaĂ§ĂŁo.? Venha fazer parte do Grupo HarĂŽ e descubra como podemos transformar seus sonhos em uma realidade altamente lucrativa. O futuro estĂĄ Ă  mesa e vocĂȘ estĂĄ convidado a saboreĂĄ-lo conosco.', NULL, 'PERNAMBUCO', 1, NULL, 40, NULL, NULL, '2026-03-08 22:46:27.056', 'https://franquias.portaldofranchising.com.br/franquia-haro-sushi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
