INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xa00efeh0snlqto3uh', 'MR. BLACK CAFĂ GOURMET', 'mr-black-cafe-gourmet', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO RĂPIDO', 'O Mr. Black Ă© uma rede de cafeterias focada na qualidade dos seus produtos e na excelĂȘncia no atendimento ao cliente.', 2012, 2012, '[\"https://www.youtube.com/watch?v=NqnhPN8EzKM\",\"https://www.youtube.com/watch?v=Kw-WpNTwlcA\",\"https://www.youtube.com/watch?v=cw0SdaMwl6s\"]', '2026-04-01 02:00:06.375', '2025-08-05 22:20:27.070', 556, NULL, 1, 2006, 'Fundada em 2006 na cidade de Belo Horizonte, o Mr. Black CafĂ© rapidamente se consolidou no mercado de cafeterias atravĂ©s de trĂȘs pilares essenciais: alta qualidade dos produtos, preĂ§o justo e atendimento diferenciado. Buscando sempre a excelĂȘncia, o Mr. Black CafĂ© se tornou sinĂŽnimo de qualidade e estamos sempre em busca das melhores prĂĄticas de gestĂŁo, desenvolvimento da marca e aperfeiĂ§oamento da experiĂȘncia do cliente. Acreditamos que a melhor forma de atrair e manter clientes satisfeitos Ă© sempre trabalhar de forma justa e sincera. Nos posicionamos como uma cafeteria de cafĂ©s especiais, ou seja, os cafĂ©s que utilizamos sĂŁo cafĂ©s que foram cultivados observando as melhores prĂĄticas, gerando grĂŁos de alta qualidade, tal que, atravĂ©s de teste de prova, sĂŁo classificados por especialistas com notas entre 84 e 86 pontos. Estes cafĂ©s tem caracterĂ­sticas sensoriais diferenciadas, promovendo aos nossos clientes uma experiĂȘncia diferenciada. Em 2012, apĂłs 6 anos de muito trabalho e grande sucesso na capital mineira, os nossos gestores, atravĂ©s de um plano estratĂ©gico de longo prazo, disponibilizaram a marca para expansĂŁo atravĂ©s do sistema de franquias. Associada a ABF (AssociaĂ§ĂŁo Brasileira de Franchising), o Mr. Black CafĂ© conta com 25 unidades franqueadas em 7 estados brasileiros. Desde o ano de 2016, decidimos por fabricar os nossos prĂłprios produtos da linha de salgados e doces. Essa estratĂ©gia nos proporcionou um grande ganho de qualidade, exclusividade, controle de custos e consequente diferencial competitivo frente aos nossos concorrentes. Como uma franquia Mineira e de Belo Horizonte, que recebeu o tĂ­tulo de Cidade Criativa da Gastronomia pela UNESCO no ano de 2019, buscamos sempre a excelĂȘncia na qualidade dos nossos produtos, a melhoria continua na experiĂȘncia do nosso cliente e a adequaĂ§ĂŁo do modelo de negĂłcio Ă s tendĂȘncias internacionais de arquitetura, tecnologia no preparo dos alimentos e inovaĂ§Ă”es nas nossas estratĂ©gias de marketing. Modelos de Franquia Express Ideal para locais de grande fluxo como supermercados, faculdades, call centers, estaĂ§Ă”es de metrĂŽ, hospitais e store in store. Â» EspaĂ§o: 6mÂČ a 9mÂČ Â» Taxa de Franquia: R$30.000,00 Â» Capital para InstalaĂ§ĂŁo: entre R$90.000,00 e R$110.000,00 Â» Capital de Giro: R$10.000,00 Â» Investimento total: entre R$130.000,00 e R$150.000,00 Â» Faturamento mĂ©dio estimado: R$30.000,00 Â» Lucro estimado: 15% do faturamento Â» Royalties fixo: R$1.100,00 (reajustĂĄvel anualmente pelo IGPM) Â» Taxa de publicidade fixa: R$200,00 (reajustĂĄvel anualmente de acordo com plano de marketing) Quiosque Modelo que pode ser instalado em: shopping center, prĂ©dios comerciais, supermercados, hospitais, faculdades e estaĂ§Ă”es. Â» EspaĂ§o para shopping: 15 mÂČ mais ĂĄrea para mesas e cadeiras Â» Taxa de franquia: R$ 40 mil Â» MaquinĂĄrio e mobiliĂĄrio: em torno de R$ 80 mil Â» Obra civil: entre R$ 50 mil e R$ 80 mil Â» UtensĂ­lios: em torno de R$ 15 mil Â» Capital de giro: R$ 15 mil Â» Investimento total estimado: entre R$ 200 mil e R$ 230 mil Â» Royalty: 5% do faturamento bruto Â» Taxa de publicidade: rateio (nĂŁo cobramos % fixo) Loja de Shopping ou Rua Ideal para shoppings ou pontos de rua com grande fluxo de pessoas. Â» EspaĂ§o para shopping: 20 mÂČ e 45 mÂČ Â» EspaĂ§o para rua: 60 mÂČ e 100 mÂČ Â» Taxa de franquia: R$ 40 mil Â» MaquinĂĄrio e mobiliĂĄrio: em torno de R$ 80 mil Â» Obra civil: entre R$ 90 mil e R$ 130 mil Â» UtensĂ­lios: em torno de R$ 15 mil Â» Capital de giro: R$ 15 mil Â» Investimento total estimado: entre R$ 240 mil e R$ 280 mil Â» Royalty: 5% do faturamento bruto Â» Taxa de publicidade: rateio (nĂŁo cobramos % fixo)', NULL, 'MINAS GERAIS', 1, NULL, 23, NULL, NULL, '2025-09-11 17:20:01.000', 'https://franquias.portaldofranchising.com.br/franquia-mr-black-cafe-gourmet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza75xf00egeh0sf98n7obo', 'PRIORIDADE 10', 'prioridade-10', NULL, 'Moda', 'VestuĂĄrios', 'Loja de departamento, especializado em vestuĂĄrio e utilidades. Loja de presentes com preĂ§o popular.', 2021, 2022, '[\"https://www.youtube.com/watch?v=yGRVCSwrKP4\",\"https://www.youtube.com/watch?v=mx2Ut-ozSs0\",\"https://www.youtube.com/watch?v=Mx0N6VrqiIA\"]', '2026-04-01 02:00:06.384', '2025-08-05 22:20:27.075', 557, NULL, 1, 2014, 'Tudo por atĂ© R$ 20. Essa Ă© a proposta da Prioridade 10, uma loja de departamentos criada em Cunha PorĂŁ (SC), uma cidade com pouco mais de 11 mil habitantes, em 2014. A parceria com fornecedores estratĂ©gicos foi a chave para conseguir produtos de qualidade por um preĂ§o baixo, tornando o negĂłcio um verdadeiro sucesso, que em pouco tempo comeĂ§ou a expandir para cidades vizinhas. Com a preocupaĂ§ĂŁo de manter a qualidade e o padrĂŁo dos itens vendidos, resolveram buscar informaĂ§Ă”es sobre o sistema de franquias e migraram para o modelo em 2022. Hoje a Prioridade 10 conta com mais de 2 mil fornecedores homologados e 10 mil itens cadastrados no Portal de Compras exclusivo da rede. AlĂ©m disso, Ă© possĂ­vel contar com o software ERP para gestĂŁo de estoque, equipe de marketing dedicada e mais de 09 anos de experiĂȘncia no setor. Atualmente somos a maior rede de loja de departamento de preĂ§o popular do Brasil, com unidades em Santa Catarina, ParanĂĄ, Rio Grande do Sul e Distrito Federal.', NULL, 'SANTA CATARINA', 1, NULL, 45, NULL, NULL, '2026-03-08 22:52:06.921', 'https://franquias.portaldofranchising.com.br/franquia-prioridade-10/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
