INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761000f1eh0szkz47jy2', 'HIGH TORQUE CAR SERVICE', 'high-torque-car-service', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'Oficina de manutenĂ§ĂŁo e reparaĂ§ĂŁo automotiva.', 2016, 2020, '[\"https://www.youtube.com/watch?v=UDcvUsNLnko\",\"https://www.youtube.com/watch?v=Q-AhpzyX_H0\",\"https://www.youtube.com/watch?v=azs492xmsfI\",\"https://www.youtube.com/watch?v=IkSsak8N91M\"]', '2026-04-01 02:00:06.573', '2025-08-05 22:20:27.204', 578, NULL, 1, 2016, 'VocĂȘ possivelmente conheceu a High Torque pelos nossos vĂ­deos no Youtube. Mas, sabe como isso comeĂ§ou? Sabe como uma pequena oficina se transformou em uma franquia de sucesso? Para entender a nossa histĂłria Ă© preciso voltar ao ano de 2005, quando o fundador da empresa, Alexandre Dias Generoso (ADG), que trabalhava como taxista durante o dia e em uma oficina na parte da noite, decidiu abrir o prĂłprio negĂłcio. No dia 15 de setembro de 2005 nasce a High Torque, fundada com base em uma sĂłlida experiĂȘncia no mercado de manutenĂ§ĂŁo automotiva. ADG sempre foi um entusiasta do mundo automotivo, buscando se aperfeiĂ§oar cada vez mais na ĂĄrea e decidiu, entĂŁo, compartilhar o que sabia em um programa chamado PDO - Por Dentro da Oficina, transmitido pelo canal High Torque no Youtube, alcanĂ§ando milhares de seguidores. Desenvolvemos o modelo de franquia High Torque Car Service para que vocĂȘ tenha negĂłcio rentĂĄvel, de gestĂŁo descomplicada e prazerosa, que preste serviĂ§os confiĂĄveis e de qualidade com preĂ§os competitivos. Atuamos em um nicho de serviĂ§os automotivos de alto padrĂŁo, sendo capazes de atender Ă s demandas de multimarcas em um modelo de negĂłcio honesto e acessĂ­vel. A High Torque Car Service chegou chegando, com forte presenĂ§a e diferencial competitivo. Assim, alĂ©m da excelĂȘncia em seus processos, a rede preza por oferecer serviĂ§os com qualidade aos clientes. MissĂŁo Promover o crescimento da marca e a realizaĂ§ĂŁo pessoal de todos os envolvidos atravĂ©s dos serviĂ§os automotivos. Promover mais que manutenĂ§ĂŁo, uma nova experiĂȘncia em serviĂ§os automotivos. VisĂŁo Ser a marca de referĂȘncia nacional em manutenĂ§ĂŁo automotiva de alta qualidade a um preĂ§o justo. Valores ConfianĂ§a Honestidade Qualidade ValorizaĂ§ĂŁo e respeito aos clientes e colaboradores; Comportamento Ă©tico Zelo pela imagem da empresa e honra Ă  marca. Se fossemos resumir a essĂȘncia do nosso negĂłcio em uma frase, poderĂ­amos dizer que: A High Torque busca promover a satisfaĂ§ĂŁo de franqueados, colaboradores e clientes na prestaĂ§ĂŁo de serviĂ§os automotivos. Somos mais do que uma oficina mecĂąnica, mais que uma marca de sucesso, somos pessoas que buscam se realizar profissionalmente ao atender com qualidade e honestidade nossos clientes.', NULL, 'SĂO PAULO', 1, NULL, 10, NULL, NULL, '2026-03-08 23:00:53.498', 'https://franquias.portaldofranchising.com.br/franquia-high-torque-car-service/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '472000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
