INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761p00f6eh0sjtvwvhmu', 'CADE', 'cade', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'Trabalhos para dar mais qualidade de vida para os nossos pacientes com dor.', 2024, 2024, NULL, '2026-04-01 02:00:06.619', '2025-08-05 22:20:27.229', 583, NULL, 1, 2019, 'O Centro AvanĂ§ado da Dor e Especialidades surge a partir de um momento de muita dedicaĂ§ĂŁo para com a minha famĂ­lia. \nO meu avĂŽ paterno, que enfrentava entĂŁo fortes dores crĂŽnicas, me levou a um estudo e especializaĂ§ĂŁo profundo na busca por aliviar e proporcionar qualidade de vida em um momento tĂŁo delicado para todos nĂłs.Â \nÂ \nE a partir dessa busca, identifiquei uma importante lacuna no mercado de cuidados com a saĂșde, e somado a isso, uma grande determinaĂ§ĂŁo e vontade de implantar em cada ponto deste PaĂ­s um centro especializado com atendimentos multidisciplinares com foco em melhora e alĂ­vio de dores crĂŽnicas. \nNeste momento divido o meu objetivo e apresento uma excelente oportunidade de negĂłcio a cada um de vocĂȘs: levar o mesmo conforto que proporcionei a minha famĂ­lia para os lares de todos que precisem do mesmo acolhimento e atuaĂ§ĂŁo. \nSeja Bem-vindo a CADE, sua Rede AvanĂ§ada de tratamento de Dor e Especialidades. \nDr. LĂșcio GusmĂŁo Rocha', NULL, 'DISTRITO FEDERAL', 1, NULL, 2, NULL, NULL, '2026-03-08 23:11:43.304', 'https://franquias.portaldofranchising.com.br/franquia-cade/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
