INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza761y00f8eh0snto3x79b', 'PARIS SAINT-GERMAIN ACADEMY', 'paris-saint-germain-academy', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Escola de Futebol Premium no Brasil; LĂ­der em Faturamento Nacional no Segmento; Marca Consolidada Mundialmente; Metodologia de Treino do Paris Saint-Germain; Rede em ExpansĂŁo.', 2005, 2022, NULL, '2026-04-01 02:00:06.638', '2025-08-05 22:20:27.238', 585, NULL, 1, 2005, 'A histĂłria da empresa comeĂ§ou com 3 franceses fundadores que se encontraram jogando futebol no Rio de Janeiro em 2010 quando surgiu o projeto de abrir um complexo de futebol inovador baseado no modelo europeu de Fut5 e de campeonatos corporativos. \nO mesmo abriu em 2013 no bairro de Botafogo no coraĂ§ĂŁo da Zona Sul carioca depois de mais de 1 ano de obra. \nDurante o processo e com a observaĂ§ĂŁo do mercado se destacou a oportunidade de abrir uma escola oficial do clube Paris Saint-Germain. Assim foi feito e em janeiro 2014 foi inaugurada a 1a unidade PSG Academy fora da FranĂ§a. \nLogo percebemos o potencial do negĂłcio e comeĂ§amos a concentrar nossos esforĂ§os no desenvolvimento da operaĂ§ĂŁo de escolas de futebol. \nEm um primeiro tempo foi em prĂłprio e apenas no RJ e a partir de 2017 assinamos a master franquia nacional da PSG Academy e comeĂ§amos a desenvolver Brasil afora tanto com unidades prĂłprias como em franquias. 8 anos depois contamos com 36 unidades - com 7 prĂłprias entre SP, BH e RJ; e 29 franquias de Manaus a Porto Alegre.Â  \nNelas treinam 9.000 alunos semanalmente com a camisa e dentro da metodologia PARIS SAINT-GERMAIN graĂ§as aos mais de 300 treinadores capacitados e constantemente treinados e atualizados.', NULL, 'RIO DE JANEIRO', 1, NULL, 42, NULL, NULL, '2026-03-08 23:12:57.091', 'https://franquias.portaldofranchising.com.br/franquia-paris-saint-germain-academy/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762300f9eh0slic1p3hk', 'SANTO SANTO SANTO', 'santo-santo-santo', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'Loja de Presentes CatĂłlicos - AcessĂłrios femininos, masculinos e infantil. Itens de decoraĂ§ĂŁo para o lar. Imagens. Todos os produtos catĂłlicos. Presentes com FĂ©', 2022, 2025, NULL, '2026-04-01 02:00:06.648', '2025-08-05 22:20:27.243', 586, NULL, 1, 2016, '', NULL, 'SĂO PAULO', 1, NULL, 15, NULL, NULL, '2025-09-18 09:54:23.000', 'https://franquias.portaldofranchising.com.br/franquia-santo-santo-santo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '311000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762800faeh0sdwr9rj36', 'ALERGOSHOP', 'alergoshop', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Alergoshop, desde 1993 desenvolvendo produtos de forma criteriosa para o seu bem-estar e prevenĂ§ĂŁo das alergias. (cosmĂ©ticos, saneantes, produtos anti-ĂĄcaros, semi-jĂłias, repelentes etc.)', 2012, 2011, NULL, '2026-04-01 02:00:06.659', '2025-08-05 22:20:27.248', 587, NULL, 1, 1993, 'Desde 1993 a Alergoshop trabalha focada no bem-estar das pessoas.Â \nÂ  E esta histĂłria jĂĄ comeĂ§ou com um propĂłsito, em um tempo quando ainda nĂŁo haviam muitas alternativas para alĂ©rgicos no Brasil, a Alergoshop chegou e mudou esse cenĂĄrio. Â  De lĂĄ pra cĂĄ investimos muitos em pesquisa e desenvolvimento, ampliamos nossa distribuiĂ§ĂŁo com canais fĂ­sicos e digitais, principalmente com a nossa rede de franquias.Â  Â  Conquistamos reconhecimento e recomendaĂ§Ă”es dos melhores profissionais da saĂșde e inĂșmeros clientes pelo cuidado dos nossos produtos para toda a famĂ­lia, inclusive os pets.Â Â  Somos referĂȘncia em produtos hipoalergĂȘnicos de alta qualidade e eficiĂȘncia, sendo grande parte com selo Cruelty Free e Vegano. Â  Os nĂșmeros do cenĂĄrio global confirmam o quanto a nossa presenĂ§a se faz revelante. SĂł para se ter uma ideia, segundo a organizaĂ§ĂŁo mundial da saĂșde, atualmente:\nÂ  30% da populaĂ§ĂŁo mundial Ă© alĂ©rgica, podendo chegar a 50% atĂ© 2040. O Brasil estĂĄ entre os paĂ­ses que mais consomem cosmĂ©ticos no mundo. 21,8% das dermatites de contato sĂŁo desencadeadas por maquiagens e cosmĂ©ticos. 80% das alergias respiratĂłrias sĂŁo causadas por fungos e ĂĄcaros presentes na poeira domĂ©stica. Passamos 3/4 da vida em ambientes fechados. Â  Invista em uma franquia da empresa pioneira no Brasil, especializada em produtos para alĂ©rgicos e para quem nĂŁo quer ter alergias ou outros prejuĂ­zos Ă  saĂșde.Â  Â  FaĂ§a parte desse movimento,Â   Seja um franqueado ALERGOSHOP!', NULL, 'SĂO PAULO', 1, NULL, 10, NULL, NULL, '2026-03-08 23:14:04.594', 'https://franquias.portaldofranchising.com.br/franquia-alergoshop-beleza-e-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762e00fbeh0s8zl7nudj', 'PROHOUSE', 'prohouse', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Loja de colchĂ”es', 2010, 2023, '[\"https://www.youtube.com/watch?v=aX3LJDweJeY\",\"https://www.youtube.com/watch?v=vvP-Ay7BEzw\",\"https://www.youtube.com/watch?v=K72CpGZLCFE\",\"https://www.youtube.com/watch?v=jzfa0qkpQk0\"]', '2026-04-01 02:00:06.668', '2025-08-05 22:20:27.254', 588, NULL, 1, 1979, 'A franquiaÂ Prohouse ColchĂ”esÂ Ă© a rede de lojas do grupo MGA Moveleira com nome e reputaĂ§ĂŁo constituĂ­dos hĂĄ mais de 45 anos. LĂ­der de mercado na fabricaĂ§ĂŁo de Camas Box e ColchĂ”es de grandes redes varejistas, contamos atualmente com mais de 60 lojas Prohouse distribuĂ­das nos estados de SĂŁo Paulo, Rio de Janeiro e Minas Gerais. A expertise da MGA na fabricaĂ§ĂŁo e montagem de colchĂ”es e o conhecimento de mercado da Prohouse, se evidenciam nos produtos inovadores e no atendimento personalizado para todas as necessidades e gostos. Foi com base nestes princĂ­pios que se criou o modelo de loja de fĂĄbrica Prohouse, que reĂșne em um sĂł espaĂ§o, ampla variedade de produtos e complementos para o dormitĂłrio em um ambiente agradĂĄvel, aconchegante e confortĂĄvel. Produtos exclusivos e inovadores: A gama de diferenciais sĂł Ă© encontrada em um modelo de negĂłcio como o da PROHOUSE ColchĂ”es. A expertise da rede PROHOUSE advĂ©m da MGA Moveleira na fabricaĂ§ĂŁo e montagem de colchĂ”es e camas box desde 1979. Marketplace Franqueado: Os produtos vendidos no site Prohouse dentro da regiĂŁo do franqueado sĂŁo direcionados 100% para o franqueado. Ter uma loja de fĂĄbrica possibilita acesso rĂĄpido as melhores tecnologias em conforto e relaxamento que o mercado pode oferecer. Estilo moderno de loja especializada de colchĂ”es, as lojas PROHOUSE criam um ambiente que traduz aconchego e conforto, alĂ©m de produtos que facilitam e agregam valor a experiĂȘncia de compra.', NULL, 'SĂO PAULO', 1, NULL, 64, NULL, NULL, '2026-03-08 23:15:01.338', 'https://franquias.portaldofranchising.com.br/franquia-prohouse/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
