INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza762x00feeh0sxjkcc0zm', 'GREEN STATION', 'green-station', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Somos um Fast Food de comida saudĂĄvel. Com saladas, wraps, sucos, etc.', 2016, 2018, NULL, '2026-04-01 02:00:06.697', '2025-08-05 22:20:27.273', 591, NULL, 1, 2015, '', NULL, 'ESPĂRITO SANTO', 1, NULL, 42, NULL, NULL, '2026-03-08 23:16:30.753', 'https://franquias.portaldofranchising.com.br/franquia-green-station/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza763500ffeh0so1g8s6wf', 'CASA PRADO', 'casa-prado', NULL, 'Moda', 'VestuĂĄrios', 'Moda masculina', 2018, 2021, NULL, '2026-04-01 02:00:06.707', '2025-08-05 22:20:27.282', 592, NULL, 1, 1955, 'A Casa Prado foi fundada em 11 de Fevereiro 1955 e desde o seu inĂ­cio, traz como principal caracterĂ­stica do negĂłcio, seu DNA futurista e contemporĂąneo ( Ă  frente do seu tempo ). \nNa Ă©poca, o seu fundador: Sr. JosĂ©Â Rodrigues do Prado segmentou o mercado da regiĂŁo, criando uma loja exclusiva de artigos para cavalheiros. \nUma atitude arrojada e inovadora para a Ă©poca, pois a grande maioria das lojas vendia vĂĄrios produtos femininos, infantis e masculinos no mesmo espaĂ§o fĂ­sico. \nDurante toda a sua trajetĂłria, a Casa Pardo sempre prezou pelo atendimento de qualidade e exclusivo aos homens de bom gosto, caracterĂ­stica marcante e reconhecida por nossos clientes que garantem a perenidade do nosso negĂłcio em nossos 66 anos de existĂȘncia. \nDesenvolvemos nossa marca prĂłpria em 2010 e hoje se tornou o principal produto das nossas lojas, graĂ§as Ă  qualidade apresentada de nossos artigos. \nTemos um trabalho forte e consistente de gestĂŁo de produtos, conectado com as principais tendĂȘncias de moda masculina e uma parceria prĂłspera que mantemos com nossos parceiros comerciais em todo Brasil que nos permitem um ganho de eficiĂȘncia na logĂ­stica de entrega de nossas mercadorias em nossas unidades prĂłprias e franqueadas e um portfĂłlio que atende as principais exigĂȘncias de um pĂșblico seleto e de alto poder econĂŽmico. \nA franquia nasceu de um sonho de levar o conceito da Casa Prado para todo Brasil, com a certeza de que possuĂ­mos a vocaĂ§ĂŁo e interesse genuĂ­no para realizar uma gestĂŁo da rede de franqueados de forma prĂłxima, eficaz, com total parceria entre as partes e ancorada na tradiĂ§ĂŁo da nossa marca. \nFato este que jĂĄ acontece com nossos franqueados de SINOP-MT e SORRISO-MT. \nApostamos muito nesse conceito de uma marca que se relaciona com os clientes ao longo de mais de seis dĂ©cadas, colhemos frutos dessas relaĂ§Ă”es atĂ© hoje, fato que tornou a marca sĂłlida, garantindo produtos de alta qualidade e com forte gestĂŁo profissional.', NULL, 'MATO GROSSO', 1, NULL, 12, NULL, NULL, '2026-03-08 23:16:54.401', 'https://franquias.portaldofranchising.com.br/franquia-casa-prado/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
