INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765900fteh0sbn08kxic', 'SUCĂO', 'sucao', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O SucĂŁo estĂĄ inserido no segmento de \"healthy fast food\", proporcionando, de forma Ășnica, alimentaĂ§ĂŁo saudĂĄvel e saborosa de maneira rĂĄpida e acessĂ­vel.', 2014, 2016, '[\"https://www.youtube.com/watch?v=MEIyAC0AWLk\"]', '2026-04-01 02:00:06.834', '2025-08-05 22:20:27.357', 606, NULL, 1, 1975, 'Reconhecimento â A mais premiada do PaĂ­s 5x Selo de excelĂȘncia em franchising; 2019 â 2020 â 2021 â 2022 â 2023 4x Nota mĂĄxima (5 estrelas) no Guia de Franquias da PEGN; 2020 â 2021 â 2022 â 2023 PrĂȘmio Retail Design Institute 2022: 1Âș Lugar mĂ©dios formatos e 2Â° Lugar pequenos formatos; PrĂȘmio ABF + Retail Design Institute : 1Âș lugar na categoria âEmbalagensâ e 2Â° lugar na categoria âProjetos de Quiosqueâ; 7x eleito o melhor âSuco da Cidadeâ pela revista Veja;Â  Fast and Healthy Food De olho na expansĂŁo de centros comerciais de pequeno, mĂ©dio e grande porte e nas oportunidades identificadas no mercado de alimentaĂ§ĂŁo saudĂĄvel, o SucĂŁo desenvolveu um projeto sĂłlido e sustentĂĄvel com um completo e exclusivo portfĂłlio de produtos, baixo custo operacional e margens de contribuiĂ§ĂŁo acima da mĂ©dia do mercado de alimentaĂ§ĂŁo, inaugurando um novo segmento neste ramo: alimentaĂ§ĂŁo saudĂĄvel e saborosa, com preĂ§os competitivos e rapidez na entrega dos produtos: este Ă© o conceito âFast and Healthy Foodâ. Para conhecer mais sobre a nossa histĂłria, acesse nosso site: www.sucao.com.br Tudo prĂłprio: marketing, indĂșstria e logĂ­stica Isso Ă© essencial para o dinamismo que o mercado exige: Pesquisa de mercado e desenvolvimento de produtos sempre, alinhados a comunicaĂ§ĂŁo de marca; Cozinha central com profissionais especializados, com altĂ­ssimo rigor de qualidade e seguranĂ§a alimentar, sempre atentos Ă s tendĂȘncias e diretamente ligados ao time de marketing; LogĂ­stica prĂłpria para que tudo isso chegue atĂ© a ponta com qualidade, padrĂŁo e sob responsabilidade da rede, sem intermediĂĄrios e elevaĂ§ĂŁo de custo para nossos parceiros.', NULL, 'SĂO PAULO', 1, NULL, 62, NULL, NULL, '2026-03-08 23:21:56.187', 'https://franquias.portaldofranchising.com.br/franquia-sucao-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '295000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
