INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765t00fxeh0s8ag44rs2', 'ZĂ COXINHA', 'ze-coxinha', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Lanches rĂĄpidos e casuais, rĂĄpida implementaĂ§ĂŁo, espaĂ§os reduzidos, atendimento rĂĄpido com salgados fritos e assados, preĂ§os acessĂ­veis e baixo custo de implantaĂ§ĂŁo.', 2011, 2022, '[\"https://www.youtube.com/watch?v=dsovxnrlNbI\",\"https://www.youtube.com/watch?v=jS5ekEbAmm4\",\"https://www.youtube.com/watch?v=X8xWxmsUaO8\",\"https://www.youtube.com/watch?v=5CjRQM6Q8a0\"]', '2026-04-01 02:00:06.872', '2025-08-05 22:20:27.377', 610, NULL, 1, 2011, 'Fundado em 2011 no municĂ­pio de Vila Velha, EspĂ­rito Santo, o ZĂ© Coxinha Ă© a marca pioneira em venda de salgados na caixa. Seu grande diferencial Ă© ter produtos de ALTA QUALIDADE, PREĂO ACESSĂVEL E MUITO SABOROSOS! Em 2019, o Grupo VĂł Alimentos, empresa especializada na produĂ§ĂŁo e comercializaĂ§ĂŁo de salgados fritos, assados e pĂŁes de queijo juntou-se Ă  NAZCA Co, especialista em estruturaĂ§ĂŁo empresarial, inteligĂȘncia, desenvolvimento e gestĂŁo de negĂłcios. ApĂłs o feito, a franquia ZĂ© Coxinha entrou para a famĂ­lia com intuito de evoluir e proporcionar uma experiĂȘncia ainda melhor. Em conjunto, nossa missĂŁo e propĂłsito Ă© levar muito sabor de forma acolhedora para vocĂȘ se sentir em casa, por meio de nossa rede de distribuiĂ§ĂŁo e lojas franqueadas. Hoje contamos com mais de 40 lojas nos estados do ES, MG e RJ. A proposta para os prĂłximos anos Ă© consolidarmos todas as unidades existentes e avanĂ§ar com novas inauguraĂ§Ă”es, tendo como objetivo alcanĂ§ar 400 lojas. O ZĂ© Coxinha possui uma ĂĄrea de 3.000mÂČ localizada em Serra/ES, onde sĂŁo fabricados todos os salgados chegando a 100mil coxinhas por dia. Com investimento de 2milhĂ”es em melhorias na nossa planta fabril, o ZĂ© Coxinha faz a entrega em todas as lojas, com carros e caminhĂ”es refrigerados e equipados para o transporte adequado de produtos congelados. O investimento inicial de R$90mil inclui todos os equipamentos, taxa de franquia, reforma e obras, contrataĂ§ĂŁo de mĂŁo de obra, sistema, estoque inicial, capital de giro e abertura da empresa. As vantagens em ser um franqueado ZĂ© Coxinha: fĂĄbrica prĂłpria, baixo investimento, baixo custo operacional, implementaĂ§ĂŁo ĂĄgil, operaĂ§ĂŁo simples, mix de produtos, suporte antes e depois da inauguraĂ§ĂŁo. Invista em um negĂłcio prĂĄtico, gestĂŁo simples, Ăłtimos resultados e baixo custo de investimento. VocĂȘ pode lucrar atĂ© 1 milhĂŁo por ano com uma opĂ§ĂŁo rĂĄpida e simples para vocĂȘ comeĂ§ar a funcionar em 30 dias.', NULL, 'ESPĂRITO SANTO', 1, NULL, 24, NULL, NULL, '2026-03-08 23:23:53.026', 'https://franquias.portaldofranchising.com.br/franquia-ze-coxinha/', NULL, NULL, NULL, 1, 5, 10, 2, 'MAINTAIN', 0, 0, '[]', '140000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza765y00fyeh0sych2qd3a', 'NAĂĂO VERDE', 'nacao-verde', NULL, 'AlimentaĂ§ĂŁo', 'EMPĂRIOS, MERCADOS E LOJAS DE CONVENIĂNCIA', 'Primeira franquia de produtos naturais do Brasil com 3 linhas de produtos e 3 canais de venda: varejo, venda direta em atacado, e e-commerce em um mesmo local e integrado com tecnologia prĂłpria.', 2012, 2018, '[\"https://www.youtube.com/watch?v=A9Nw24d_M8g\",\"https://www.youtube.com/watch?v=pqwGzMrBFf8\"]', '2026-04-01 02:00:06.881', '2025-08-05 22:20:27.382', 611, NULL, 1, 2010, 'A franquia NaĂ§ĂŁo Verde Ă© para vocĂȘ que busca muito mais do que lucratividade, Ă© para vocĂȘ que busca um propĂłsito! Com a franquia NaĂ§ĂŁo Verde vocĂȘ vai impactar a vida de milhares de pessoas na sua regiĂŁo, vai levar mais saĂșde, mais alegria, vai se tornar referĂȘncia local para quem busca uma vida melhor. Nunca empreendeu? NĂłs temos uma equipe de profissionais altamente capacitados para te acompanhar nessa sua jornada empreendedora e te ajudar a conquistar os seus sonhos. Motivos para investir no mercado de alimentaĂ§ĂŁo saudĂĄvel: Venda de alimento saudĂĄvel bate R$ 100 bilhĂ”es em 2020, em meio Ă  pandemia. Foi a maior cifra para essa categoria de alimentos desde 2006 (Euromonitor). No final de 2020 foi feito um estudo pela Euromonitor para avaliar como estava a alimentaĂ§ĂŁo do brasileiro na pandemia e descobriu que 78% delas comeĂ§aram a ficar mais atentas Ă  alimentaĂ§ĂŁo e Ă  saĂșde, e que 53% estavam buscando informaĂ§ĂŁo sobre a funĂ§ĂŁo dos alimentos. Outra pesquisa feita pela FederaĂ§ĂŁo das IndĂșstrias do Estado de SĂŁo Paulo (Fiesp) com trĂȘs mil pessoas maiores de 16 anos, em 12 regiĂ”es metropolitanas do Brasil, aponta que 80% dos brasileiros buscam por uma alimentaĂ§ĂŁo saudĂĄvel. SĂŁo mais de 300 produtos prĂłprios que chegam atĂ© todas as franquias atravĂ©s de uma central prĂłpria de distribuiĂ§ĂŁo. - 3 Linhas exclusivas de fabricaĂ§ĂŁo prĂłpria - Equipe dedicada a criaĂ§ĂŁo de novos produtos Hoje somos mais de 100 franqueados! Perfil do franqueado NAĂĂO VERDE ConheĂ§a abaixo o perfil que a franquia NaĂ§ĂŁo Verde busca para selecionar franqueados: - PaixĂŁo por pessoas e pela atividade de participar de um negĂłcio em rede; - Bom relacionamento interpessoal; - Capacidade de relacionar pessoas para comunicaĂ§ĂŁo do negĂłcio; - Capacidade de criaĂ§ĂŁo, uso e expansĂŁo de network; - Senso de valorizaĂ§ĂŁo do sucesso da marca e sua importĂąncia; - Foco comercial; - Identidade com o propĂłsito da marca, - Disponibilidade e dedicaĂ§ĂŁo. Processo de seleĂ§ĂŁo da franquia NAĂĂO VERDE ConheĂ§a abaixo quais sĂŁo as etapas do processo de seleĂ§ĂŁo da franquia NaĂ§ĂŁo Verde: Primeiro contato para verificaĂ§ĂŁo de disponibilidade de licenĂ§a AvaliaĂ§ĂŁo de perfil AnĂĄlise de documentos (COF/CONTRATO) Esclarecimento de dĂșvidas Contrato e Pagamento Primeira mentoria â Boas vindas e ponto comercial AprovaĂ§ĂŁo de ponto Projeto ImplantaĂ§ĂŁo Incubadora â treinamento presencial para lojas fĂ­sicas InauguraĂ§ĂŁo JĂĄ consegue se imaginar sendo dono de sua loja NaĂ§ĂŁo Verde? Envie seus dados e receba informaĂ§Ă”es exclusivas sobre como abrir sua prĂłpria Franquia NaĂ§ĂŁo Verde.', NULL, 'SĂO PAULO', 1, NULL, 99, NULL, NULL, '2025-05-29 00:00:26.000', 'https://franquias.portaldofranchising.com.br/franquia-nacao-verde/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
