INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766l00g2eh0sy794qzws', 'PERSONAL CLEAN PROFESSIONAL', 'personal-clean-professional', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'ServiĂ§os de Limpeza', 'Modelo de franquia que especializa o franqueado em produtos e processos inovadores para limpeza e desinfecĂ§ĂŁo em ambientes que requeiram cuidados especiais como alimentaĂ§ĂŁo, saude, lazer e industrias.', 2015, 2019, '[\"https://www.youtube.com/watch?v=p8gqHFK8ILo\",\"https://www.youtube.com/watch?v=TwrW7ftO9jQ\",\"https://www.youtube.com/watch?v=wvXCsbF0HRQ\"]', '2026-04-01 02:00:06.918', '2025-08-05 22:20:27.406', 615, NULL, 1, 2015, 'PERSONAL CLâEAN especialistas em soluĂ§Ă”es sustentĂĄveis para higienizaĂ§ĂŁo. Nossa histĂłria decorre da soma de esforĂ§os de empreendedores visionĂĄrios que atravĂ©s de um grupo de empresas sustentĂĄveis que em homologaĂ§ĂŁo recĂ­proca atua no mercado de higienizaĂ§ĂŁo profissional com ĂȘxito e crescimento continuo possibilitando que empreendedores integrem neste grupo e difundam a marca em todo territĂłrio nacional. Iniciamos em 1986 com a exploraĂ§ĂŁo do comercio de produtos para limpeza institucional, basicamente nas regiĂ”es prĂłximas Ă  sede na cidade de Itatiba, estado de SĂŁo Paulo. Em 1993, atuando com sucesso em grande parte do estado e sul do estado de Minas Gerais, atravĂ©s de planta moderna e totalmente estruturada passamos a fabricar especialidades voltadas a higienizaĂ§ĂŁo profissional, com isso conquistando cada vez mais o mercado local e o de outros estados. Uma empresa sĂł Ă© respeitada e se solidifica se agir com idoneidade, responsabilidade, respeito, parceria e profundo conhecimento no que faz, o que lhe assegura operaĂ§Ă”es sadias e confiĂĄvel contabilmente.Â  Esses atributos gerados pelos valores do grupo, polĂ­tica, visĂŁo e empreendedorismo, ampliaram a atuaĂ§ĂŁo e industrializaĂ§ĂŁo dando inĂ­cio em 1999 as operaĂ§Ă”es como franqueadores, expandindo assim a marca nos estados do Rio Grande do Sul, Santa Catarina, EspĂ­rito Santo, Bahia, MaranhĂŁo e SĂŁo Paulo atravĂ©s de Franquias O sistema foi reconhecido no ranking do Guia de Franquia da revista Pequenas Empresas Grandes NegĂłcios, publicado pela Editora Globo, por dois anos consecutivos em satisfaĂ§ĂŁo do franqueado, crescimento, melhor marca para se investir e excelĂȘncia em desempenho. Por esses motivos destacamo-nos dentre inĂșmeras empresas no ramo industrial, em especial o de higienizaĂ§ĂŁoÂ profissional, por nĂŁo nos limitarmos a um segmento apenas, desenvolvemos a quĂ­mica usual, tradicional Ă quela que preserva e mantĂ©mÂ a vida, inovando e agregando diversos segmentos do mercado. Vantagens em optar pela franquia PERSONAL CLâEAN O mercado de higienizaĂ§ĂŁo cresce de forma constante e regular e o Brasil Ă© o quarto maior mercado do mundo em produtos de limpeza. Limpeza e sanitizaĂ§ĂŁo sĂŁo requisitos de saĂșde. HĂĄ carĂȘncia de produtos e soluĂ§Ă”es mais rentĂĄveis e inovadoras. Exclusividade na ĂĄrea de atuaĂ§ĂŁo Mercado seguro Baixo custo operacional Treinamento completo Franquia direto da indĂșstria IndependĂȘncia financeira Pagamento facilitado PreĂ§os competitivos Retorno rĂĄpido do investimento Acompanhamento e capacitaĂ§ĂŁo permanentesÂ  Alta tecnologia e inovaĂ§Ă”es de produtos Excelente margem de lucratividade Ărea planejada para o crescimento da franquia', NULL, 'SĂO PAULO', 1, NULL, 13, NULL, NULL, '2026-03-08 23:26:34.154', 'https://franquias.portaldofranchising.com.br/franquia-personal-clean-professional/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '83000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza766r00g3eh0syqio83e4', 'SOLAR21', 'solar21', NULL, 'ServiĂ§os e Outros NegĂłcios', 'SERVIĂOS ADMINISTRATIVOS', 'Especialista em soluĂ§Ă”es de energia com tecnologia prĂłpria, atuaĂ§ĂŁo nacional e modelo inovador. E foco em relacionamento de longo prazo.', 2023, 2023, '[\"https://www.youtube.com/watch?v=7LESp15AwYc\",\"https://www.youtube.com/watch?v=7h-gAbf7jYY\"]', '2026-04-01 02:00:06.927', '2025-08-05 22:20:27.411', 616, NULL, 1, 2017, 'HistĂłria de sucesso: Temos uma histĂłria sĂłlida de mais de 6 anos. Crescemos 7x em 2022 em nĂșmero de clientes, chegando a mais de 800 projetos em 200 cidades brasileiras, com uma geraĂ§ĂŁo de mais de 3mil cadastros mensais em nossa plataforma. Captamos mais de R$ 20 milhĂ”es nos Ășltimos dois anos, o que nos permitiu crescer rĂĄpido, construir uma marca forte e desenvolver tecnologia de ponta. Time fundador experiente: dois dos nossos fundadores, o Vinicius Ferraz (CEO) e o Rafael Magossi (CTO), sĂŁo engenheiros eletricistas e formados pela Universidade de SĂŁo Paulo (USP), com experiĂȘncia em grandes projetos de Engenharia e Tecnologia. Foco no cliente: NĂłs somos uma empresa âfoco no clienteâ, visĂŁo estratĂ©gica fundamental hoje em dia para que uma empresa tenha sucesso, gerando: mais venda, mais credibilidade, maior satisfaĂ§ĂŁo e fidelizaĂ§ĂŁo do cliente. De acordo com uma pesquisa da consultoria Deloitte, as organizaĂ§Ă”es que aplicam essa estratĂ©gia registram 60% a mais de lucro do que as que nĂŁo tĂȘm o cliente em foco. Gigantes como a Amazon e a Apple sĂŁo excelentes exemplos de marcas que adotaram essa proposta, ressaltando a importĂąncia dessa estratĂ©gia. A Franquia Solar21 Ă© diferente de todas do mercado e vamos te explicar em 3 motivos: MĂĄquina de vendas: Garantimos uma alta geraĂ§ĂŁo de leads para que o franqueado possa vender mais e aumentar a sua receita. Temos uma grande relevĂąncia no digital e o franqueado se beneficia de forma direta. Tecnologia e Plataformas: temos tecnologia de alto nĂ­vel de ponta a ponta, como a Plataforma cliente que permite a contrataĂ§ĂŁo rĂĄpida e segura, o nosso App prĂłprio de monitoramento, para que o cliente acompanhe a sua usina solar em tempo real e a Plataforma franqueado, permitindo que vocĂȘ possa gerir a sua carteira de clientes o tempo inteiro, te dando agilidade para crescer de forma acelerada. Consultoria dedicada ao Franqueado: temos um time operacional experiente que serĂĄ responsĂĄvel pela sua Franquia em diversas frentes: engenharia, comercial, marketing, atendimento ao cliente, planejamento estratĂ©gico etc, tudo para que vocĂȘ tenha o melhor planejamento e consiga executĂĄ-lo da melhor forma possĂ­vel, levando a sua franquia ao sucesso.', NULL, 'SĂO PAULO', 1, NULL, 25, NULL, NULL, '2025-09-09 15:39:16.000', 'https://franquias.portaldofranchising.com.br/franquia-solar21/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
