INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza769a00gieh0swusci90i', 'CLUBE MORENA ROSA', 'clube-morena-rosa', NULL, 'Moda', 'VestuĂĄrios', 'A Clube Morena Rosa Ă© o modelo de franquia do Grupo Morena Rosa, com 30 anos de mercado. ReĂșne o melhor da moda num Ășnico espaĂ§o com as grifes IĂłdice, LebĂŽh, Maria Valentina, Morena Rosa, e Zinco.', 2014, 2018, '[\"https://www.youtube.com/watch?v=xiU7fPPGt7U\"]', '2026-04-01 02:00:07.075', '2025-08-05 22:20:27.503', 631, NULL, 1, 1993, 'Com o objetivo de ser um ponto de encontro entre os diferentes estilos da mulher brasileira, a Clube Morena Rosa se destaca pelo atendimento multicanais, uma equipe dedicada Ă  inovaĂ§ĂŁo e pela experiĂȘncia presente em cada detalhe, que trazem significado e vĂŁo muito alĂ©m do consumo. Entre as marcas, a Morena Rosa evidencia o protagonismo feminino e aposta em criaĂ§Ă”es que aliam design, conforto e sensualidade. O lado sofisticado e prĂĄtico da mulher contemporĂąnea aparece na Maria Valentina que traduz versatilidade em peĂ§as essenciais para a rotina cosmopolita. A Zinco traz o estilo jovem e descontraĂ­do de quem sabe aproveitar o melhor da vida. A LebĂŽh, por sua vez, se destaca pelo design urbano, que revela a personalidade Ășnica de cada consumidora. JĂĄ a IĂłdice apresenta uma moda exclusiva e atemporal, que veste uma mulher confiante e autĂȘntica. Fundador da rede de franquias, o Grupo Morena Rosa, holding paranaense, consolidada, com 30 anos de histĂłria no mercado da moda, conta com mais de 1500 colaboradores e um parque fabril de 24.000 m2 em Cianorte-PR. AlĂ©m da capacidade produtiva, a empresa Ă© parceira do meio ambiente com soluĂ§Ă”es para o descarte adequado de resĂ­duos e atua com programas de bem-estar junto aos colaboradores atravĂ©s do Instituto Morena Rosa. Criada em 2014, a ClubeMR conta com uma flagship na Oscar Freire, que ocupa 654m2 no famoso endereĂ§o paulistano. Com fachadas padronizadas e um rĂłtulo exclusivo de espumante, a franquia surpreende clientes em todo o Brasil. Comprometida com o propĂłsito de oferecer uma moda Ășnica, versĂĄtil e apaixonante, tem a meta de alcanĂ§ar 100 franquias atĂ© 2024.', NULL, 'PARANĂ', 1, NULL, 38, NULL, NULL, '2026-03-08 23:33:41.414', 'https://franquias.portaldofranchising.com.br/franquia-morena-rosa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '450000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
