INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76an00greh0sgvivktl8', 'AĂAĂ NO KILO', 'acai-no-kilo', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Empresa do segmento de gelados, com lojas de AĂ§aĂ­ no sistema Self-Service. Estrutura completa de suporte ao Franqueado em todas as fases do negĂłcio. OperaĂ§ĂŁo inovadora e agrada todo tipo de pĂșblico.', 2018, 2020, '[\"https://www.youtube.com/watch?v=v2pYI5U1QZ8\"]', '2026-04-01 02:00:07.162', '2025-08-05 22:20:27.552', 640, NULL, 1, 2017, 'Com a primeira loja inaugurada em 7 de outubro de 2017, em Euclides da Cunha, Bahia, a marca AĂ§aĂ­ NoKilo se tornou a franquia de aĂ§aĂ­ com maior crescimento no estado. \nA rede que nasceu do sonho da empresĂĄria ElisĂąngela Lavina Siqueira, em proporcionar uma experiĂȘncia de consumo personalizada e acessĂ­vel, Ă© formada por uma equipe com mais de 10 anos de expertise no ramo de gelados comestĂ­veis. \nCom a crescente demanda no consumo de aĂ§aĂ­ no paĂ­s e a percepĂ§ĂŁo da empresĂĄria sobre a praticidade do sistema self service, um modelo de negĂłcio foi criado com o objetivo de inovar o formato jĂĄ existente no mercado. Diferenciado nĂŁo apenas pela qualidade dos seus produtos mas, pela variedade e preĂ§os competitivos, associados a um ambiente bonito, agradĂĄvel, o formato oferece praticidade aos consumidores. Nas lojas, cada mobiliĂĄrio e produto Ă© posicionado estrategicamente, para garantir uma experiĂȘncia de consumo agradĂĄvel e exclusiva. \nA rede que jĂĄ conta mais de 45 lojas em toda a Bahia, alĂ©m de unidades em processo de instalaĂ§ĂŁo em outros estados, Ă© a prĂłpria fabricante dos aĂ§aĂ­s e cremes comercializados, garantindo melhores margens, autonomia e ainda, o lanĂ§amento de novos sabores durante todo ano. Outro diferencial da franquia AĂ§aĂ­ NoKilo estĂĄ no sistema logĂ­stico da rede que Ă© prĂłprio, garantindo a entrega no tempo e quantidade ideais para o bom funcionamento do negĂłcio. \nCom a comercializaĂ§ĂŁo de produtos exclusivos, o AĂ§aĂ­ NoKilo tem como objetivo oferecer ao mercado de franchising um negĂłcio de baixo investimento e Ăłtima lucratividade, formando uma rede de parceiros com capacidade para crescer, conquistando o setor com produtos e atendimento de qualidade.Â  \nO AĂ§aĂ­ NoKilo conta com cinco formatos de operaĂ§ĂŁo, que possibilitam aos diversos perfis de investidores a realizaĂ§ĂŁo do sonho de empreender:Â  \n- Quiosque NoKilo;\n- Loja Container;\n- Mini Loja NoKilo;\n- Loja padrĂŁo, e;\n- Loja Premium. \nDiferentes entre si, os formatos de operaĂ§ĂŁo sĂŁo alicerĂ§ados no mesmo propĂłsito: NUTRIR A VIDA COM EMOĂĂES POSITIVAS.Â  \nProporcionando bons momentos Ă s famĂ­lias e consumidores de aĂ§aĂ­, hoje o AĂ§aĂ­ NoKilo Ă© sinĂŽnimo de praticidade, entretenimento, sucesso de expansĂŁo e lucratividade. FaĂ§a parte dessa famĂ­lia que nĂŁo para de crescer!', NULL, 'BAHIA', 1, NULL, 57, NULL, NULL, '2026-03-08 23:36:59.787', 'https://franquias.portaldofranchising.com.br/franquia-acai-no-kilo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '160000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
