INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76bi00gveh0snrmncibd', 'REDEVERDE JARDINS E ECONEGOCIOS', 'redeverde-jardins-e-econegocios', NULL, 'Casa e ConstruĂ§ĂŁo', 'MANUTENĂĂO', 'Jardinagem e paisagismo, jardins, manejo ambiental, rec. de ĂĄrea degradada, mitigaĂ§ĂŁo ambiental, neutralizaĂ§ĂŁo de carbono, horta urbana, parede e telhado verde, transplante de arvores, arborizaĂ§ĂŁo,', 2017, 2017, NULL, '2026-04-01 02:00:07.199', '2025-08-05 22:20:27.583', 644, NULL, 1, 2001, '', NULL, 'SANTA CATARINA', 1, NULL, 2, NULL, NULL, '2025-09-09 13:48:37.000', 'https://franquias.portaldofranchising.com.br/franquia-redeverde-jardins-e-econegocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76bq00gweh0scjk3aymo', 'MAIS NATURAL', 'mais-natural', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Invista em saĂșde e qualidade de vida! O seu prĂłximo negĂłcio Ă© Mais Natural, franquia com 10 anos de experiĂȘncia e mais de 40 lojas por todo paĂ­s! Vem ser Mais Natural vocĂȘ tambĂ©m!', 2012, 2021, '[\"https://www.youtube.com/watch?v=M606eCgudBU\",\"https://www.youtube.com/watch?v=LDAv0R74Q2A\"]', '2026-04-01 02:00:07.209', '2025-08-05 22:20:27.590', 645, NULL, 1, 2008, 'A necessidade da populaĂ§ĂŁo em procurar alimentos saudĂĄveis e a preocupaĂ§ĂŁo com a qualidade de vida faz do investimento em produtos naturais um negĂłcio certo e lucrativo. Pensando em cada um desses detalhes Ă© que nasceu a Mais Natural, a primeira franquia gaĂșcha de lojas de produtos naturais. A proprietĂĄria Sandra Marasca Martini, na condiĂ§ĂŁo de farmacĂȘutica e de produtora rural, percebeu a necessidade de agregar valor Ă  produĂ§ĂŁo de grĂŁos, desde seu cultivo, processamento atĂ© o seu consumo. Por isso, o diferencial da Mais Natural Ă© levar produtos direto do campo atĂ© a mesa do consumidor. Cada grĂŁo Ă© cultivado e processado com acompanhamento especial em lavouras cultivadas pela prĂłpria empresa, o que garante procedĂȘncia e qualidade nos produtos. Oferece tambĂ©m produtos provenientes da agricultura orgĂąnica, cultivados sem agrotĂłxicos ou fertilizantes quĂ­micos. A franquia que foi fundada em 2012, completa 10 anos em 2022, e estĂĄ presente em diversos Estados do Brasil nĂŁo para de crescer, pelo profissionalismo e experiĂȘncia em sua administraĂ§ĂŁo, impulsionada pela crescente demanda por alimentos naturais diferenciados e de valor nutricional melhorado. TENHA SUA FRANQUIA MAIS NATURAL! E agora vocĂȘ pode realizar seu sonho de empreender em um dos setores (alimentaĂ§ĂŁo saudĂĄvel) que mais cresce no Brasil e no mundo. A Mais Natural proporciona a vocĂȘ a oportunidade de trabalhar para vocĂȘ e nĂŁo para os outros. Na Mais Natural, vocĂȘ tem a oportunidade de trabalhar e administrar o seu prĂłprio negĂłcio: a sua Franquia Mais Natural. E nĂŁo Ă© sĂł isso, vocĂȘ vai gerir uma loja para ter SUA INDEPENDĂNCIA FINANCEIRA com um GRANDE PROPĂSITO: melhorar a vida e a saĂșde das pessoas na sua cidade ou regiĂŁo. INVISTA COM TOTAL SEGURANĂA! Empreender Ă© um sonho da maioria das pessoas, mas muitos fracassam, porque nĂŁo tem o conhecimento especĂ­fico do ramo em que vĂŁo atuar e o tempo que levam para aprender acaba consumindo todo o capital existente. NA MAIS NATURAL VOCĂ NĂO VAI ESTAR SOZINHO, nĂłs temos uma super equipe para ajudar vocĂȘ em todos os momentos. Conte conosco para: Apoiar vocĂȘ a encontrar o melhor ponto comercial e criar sua estrutura de gestĂŁo; Ter um software com tudo que vocĂȘ precisa para administrar sua empresa; Ter os melhores fornecedores do mercado e uma LINHA EXCLUSIVA com marca prĂłpria; Melhorar sua rentabilidade com nossa INDĂSTRIA E DISTRIBUIDORA prĂłprias; Treinar os seus colaboradores com um sistema de EAD que farĂĄ sua loja vender mais e ter clientes encantados; Melhorar sua capacidade de gestĂŁo com palestras, mentorias e encontros mensais; Ter uma LOJA ONLINE e poder vender tanto presencial quanto pela internet; Ajudar a âbombarâ suas redes sociais com treinamentos na ĂĄrea do marketing digital.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 37, NULL, NULL, '2026-03-08 23:43:26.301', 'https://franquias.portaldofranchising.com.br/franquia-mais-natural/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
