L, NULL, '2026-03-08 23:46:52.264', 'https://franquias.portaldofranchising.com.br/franquia-super-pizza-pan/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
