INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76dx00haeh0sqzh3qvnj', 'SOLĂRIO PISCINA', 'solario-piscina', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Empresa do ramo de piscinas de fibra.', 2010, 2020, '[\"https://www.youtube.com/watch?v=imhMwDNuMTo\",\"https://www.youtube.com/watch?v=l4qBEq-o8X8\"]', '2026-04-01 02:00:07.343', '2025-08-05 22:20:27.670', 659, NULL, 1, 1990, 'A SolĂĄrio Piscinas Ă© o resultado da iniciativa de empreendedores que, desde 1990, conquistaram um extenso âKnow-howâ e experiĂȘncia na ĂĄrea de piscinas. ApĂłs anĂĄlise das tendĂȘncias do mercado, trouxeram soluĂ§Ă”es para atender a forte demanda no segmento de lazer, oferecendo uma gama de opĂ§Ă”es em piscinas de fibra instaladas, spas, conjuntos filtrantes, aquecedores solares, produtos quĂ­micos e acessĂłrios em geral. A SolĂĄrio desenvolveu com base em sua experiĂȘncia no varejo uma linha de piscinas exclusivas e inovadoras, as quais sĂŁo fabricadas respeitando os mais altos padrĂ”es de qualidade. Atualmente, ocupa lugar de destaque e lideranĂ§a no cenĂĄrio nacional, por seus diferenciais de qualidade na fabricaĂ§ĂŁo e pĂłs venda de seus produtos. Com sua loja matriz localizada na cidade de SĂŁo JosĂ© do Rio Preto â SP, a rede expandiu-se vertiginosamente, tendo em vista a demanda expressiva pelas piscinas em toda regiĂŁo.Â  Hoje, com 3 parques industriais no Brasil e mais de 45 lojas, a SolĂĄrio estĂĄ em plena expansĂŁo, aumentando o nĂșmero de seus franqueados de forma exponencial em todo territĂłrio brasileiro', NULL, 'SĂO PAULO', 1, NULL, 44, NULL, NULL, '2026-03-08 23:52:54.255', 'https://franquias.portaldofranchising.com.br/franquia-solario-piscina/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
