INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ea00hdeh0sg98ioelp', 'PETLOVE', 'petlove', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'A Petlove Ă© a maior plataforma pet do Brasil. Nossas franquias unem tecnologia, experiĂȘncia e amor pelos pets, oferecendo tudo em um sĂł lugar: loja, banho e tosa, saĂșde e conveniĂȘncia.', 2023, 2024, NULL, '2026-04-01 02:00:07.372', '2025-08-05 22:20:27.682', 662, NULL, 1, 1999, '', NULL, 'SĂO PAULO', 1, NULL, 10, NULL, NULL, '2025-11-04 08:09:09.000', 'https://franquias.portaldofranchising.com.br/franquia-petlove-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '1460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76eg00heeh0szxtw6291', 'MORANA', 'morana', NULL, 'Moda', 'AcessĂłrios Pessoais', 'AcessĂłrios (bijuterias, bolsas, lenĂ§os e afins)', 2002, 2001, '[\"https://www.youtube.com/watch?v=5pqgWFKAOdY\",\"https://www.youtube.com/watch?v=-ixxJkCr9kY\"]', '2026-04-01 02:00:07.383', '2025-08-05 22:20:27.689', 663, NULL, 1, 2001, 'A Franquia Morana Ă© uma das maiores redes de acessĂłrios femininos do Brasil com presenĂ§a em todas as capitais brasileiras, alĂ©m dos Estados Unidos. Criada pelo Grupo Ornatus, empresa com mais de 30 anos de experiĂȘncia em varejo e especialista em gestĂŁo de franquias, a Morana estĂĄ no mercado hĂĄ 16 anos e soma cerca de 300 operaĂ§Ă”es. Qualidade no design, acessĂłrios que se destacam pela qualidade e versatilidade em coleĂ§Ă”es exclusivas e renovadas constantemente. Essas sĂŁo as caracterĂ­sticas que fazem da Morana uma marca que cresce exponencialmente e se torna cada vez mais desejada por consumidoras seletivas e exigentes, que estĂŁo antenadas com a moda, mas nĂŁo abrem mĂŁo da beleza clĂĄssica e do acabamento impecĂĄvel. As campanhas transitam entre temas atuais a debates que valorizam e respeitam as mulheres, tendo Ă  frente o peso de celebridades ou embaixadoras que compartilham dos mesmos valores da marca. As aĂ§Ă”es de marketing sĂŁo criadas de maneira estratĂ©gica com foco na comunicaĂ§ĂŁo 360Âș que atua em todos os pontos de contato da marca com o cliente. Assim, Ă© possĂ­vel estar presente nos canais onde o consumidor Morana estĂĄ. Hoje, o sucesso das grandes cidades estĂĄ pronto para ser lucrativo em todo o restante do PaĂ­s. Para isso ocorrer em municĂ­pios com populaĂ§ĂŁo entre 70 mil e 200 mil habitantes, a marca criou a Morana Light. Pequenas mudanĂ§as no formato do projeto arquitetĂŽnico e, principalmente, no estoque da loja, permitem que o investidor tenha uma franquia de acessĂłrios femininos em cidades menores, mas de grande poder aquisitivo.', NULL, 'SĂO PAULO', 1, NULL, 310, NULL, NULL, '2026-03-08 23:54:38.409', 'https://franquias.portaldofranchising.com.br/franquia-morana-bijuterias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '163000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76em00hfeh0sdn5q7ksi', 'LOUCOS POR COXINHA', 'loucos-por-coxinha', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Loucos por Coxinha Ă© uma rede de franquia consolidada e sustentĂĄvel. Modelo testado e aprovado por 95% dos franqueados. SĂŁo mais de 100 Unidades nos melhores shopping e regiĂ”es do Brasil.', 2014, 2016, '[\"https://www.youtube.com/watch?v=6nSAU9XlL4o\"]', '2026-04-01 02:00:07.393', '2025-08-05 22:20:27.694', 664, NULL, 1, 2014, 'Loucos por Coxinha: Nossa HistĂłria e ExpansĂŁo A Loucos por Coxinha nasceu em 2014, na cidade de Natal, Rio Grande do Norte, da visĂŁo empreendedora de Pablo Farias e Vitor Azevedo. Amigos de infĂąncia unidos pelo sonho de transformar a paixĂŁo nacional â a coxinha â em uma experiĂȘncia de consumo e um negĂłcio de sucesso no mercado de franchising. Crescimento Estruturado e InovaĂ§ĂŁo em Formatos Em 2015, consolidamos o nosso modelo de quiosque em shopping centers, que rapidamente se estabeleceu como um formato testado e altamente aprovado tanto pelos clientes quanto pelos nossos franqueados. Hoje, a Loucos por Coxinha oferece formatos de franquia adaptĂĄveis a diferentes mercados e pontos comerciais, incluindo: Quiosque Container Pocket (Formato compacto) LideranĂ§a Ampla Atualmente, somos uma franquia com estrutura verticalizada, contando com produĂ§ĂŁo e logĂ­stica prĂłpria. Temos, tambĂ©m, uma base sĂłlida com mais de 100 operaĂ§Ă”es ativas. AlĂ©m do modelo de franquias, fortalecemos nossa presenĂ§a no mercado de varejo com a marca Loucos por Coxinha Varejo, que atende a mais de 6 mil pontos de venda em supermercados.Â  Nossa atuaĂ§ĂŁo abrange 13 estados das regiĂ”es Norte, Nordeste, Sul e Sudeste do Brasil, demonstrando a capilaridade e o sucesso da nossa marca. VisĂŁo de Futuro e ExpansĂŁo Para os PrĂłximos Anos O plano de expansĂŁo para 2026 foca na consolidaĂ§ĂŁo regional por meio da interiorizaĂ§ĂŁo nos estados onde jĂĄ estamos presentes. Adicionalmente, buscaremos ampliar o alcance da marca para novas regiĂ”es estratĂ©gicas, incluindo a entrada nos estados de Tocantins e PiauĂ­.', NULL, 'RIO GRANDE DO NORTE', 1, NULL, 102, NULL, NULL, '2026-03-08 23:55:32.783', 'https://franquias.portaldofranchising.com.br/franquia-loucos-por-coxinha/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '117759.57', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76eq00hgeh0s4tqp95p0', 'FOLKS FRANQUEADORA', 'folks-franqueadora', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'AgroBar Ă© um bar temĂĄtico sertanejo para todos os dias e todos os pĂșblicos. Uma marca da FOLKS FRANQUIAS que jĂĄ possui outros modelos de sucesso, como o Folks Pub.', 2019, 2022, NULL, '2026-04-01 02:00:07.404', '2025-08-05 22:20:27.698', 665, NULL, 1, 2014, '', NULL, 'PARANĂ', 1, NULL, 13, NULL, NULL, '2026-03-08 23:56:25.762', 'https://franquias.portaldofranchising.com.br/franquia-folks-franqueadora/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '349000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ev00hheh0s5yys0xy7', 'GET IT', 'get-it', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'A Get it Ă© uma empresa jovem e inovadora que nasceu com o objetivo de quebrar barreiras e conectar as pessoas com o mundo. Uma metodologia forte, uma empresa humanizada, com foco nos resultados.', 2016, 2019, NULL, '2026-04-01 02:00:07.415', '2025-08-05 22:20:27.703', 666, NULL, 1, 2007, 'A Ășnica franqueadora de idiomas com o trabalho de GovernanĂ§a Corporativa.\n\nTodos os nossos franqueados recebem um suporte conferido pelo CEO da Get it, Thiago Sanches, que faz um acompanhamento detalhado e realiza um trabalho de consultoria mensal. \nEle participa diretamente de todos os processos com os novos integrantes da rede, deixando o lado humano sobressair ao que poderia ser uma simples negociaĂ§ĂŁo. Isso jĂĄ demonstra o quanto a Get it estĂĄ posicionada na contramĂŁo dos grandes âplayersâ do mercado. \nNossa proposta Ă© trazer facilidades e diferenciaĂ§Ă”es no investimento inicial, alĂ©m de fazer um planejamento de execuĂ§ĂŁo compatĂ­vel com a realidade dos franqueados, dando-lhes total autonomia nas decisĂ”es das escolas. A forma como a Get it trabalha estĂĄ relacionada com a experiĂȘncia real do mundo moderno, respeitando as opiniĂ”es, absorvendo ideias dos franqueados, os impulsionando, dando forĂ§a e voz aos mesmos, que contam com a possibilidade de trocar informaĂ§Ă”es relevantes e experiĂȘncias. Um lugar onde todos sĂŁo ouvidos e atendidos durante o processo completo de desenvolvimento empresarial. Uma marca projetada para promover experiĂȘncias. Uma empresa jovem, inovadora, eficaz, que estĂĄ adaptada ao universo digital, visa a evoluĂ§ĂŁo e executa prĂĄticas conscientes da velocidade com que as coisas acontecem. A Get it nasceu com o principal objetivo de quebrar barreiras e conectar as pessoas com o mundo. Por isso nĂŁo oferece somente cursos de idiomas, mas possibilita conquistas, experiĂȘncias sem limite de fronteiras e a realizaĂ§ĂŁo de sonhos. Atualmente, estamos presentes em diversos estados do territĂłrio nacional, e Ă© com muito otimismo e fidelidade aos nossos valores que projetamos nossa expansĂŁo para os prĂłximos anos. \nNossa prioridade Ă© sempre manter uma metodologia forte, ser uma empresa humanizada, e oferecer um ensino de qualidade, possibilitando resultados rĂĄpidos e durĂĄveis. A Get it confia na concretizaĂ§ĂŁo dos objetivos maiores, e busca contribuir de forma direta com o sucesso de nossos alunos, parceiros e franqueados. FaĂ§a parte dessa famĂ­lia!', NULL, 'SANTA CATARINA', 1, NULL, 14, NULL, NULL, '2026-03-08 23:56:49.027', 'https://franquias.portaldofranchising.com.br/franquia-get-it/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76f100hieh0szb889o2s', 'DUGAS PIZZA DELIVERY', 'dugas-pizza-delivery', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Modelo de Pizzaria Delivery formatado para alto volume de vendas com processos bem delineados visando a entrega de pizzas de alta qualidade para pĂșblico A, B e C+.', 2021, 2023, '[\"https://www.youtube.com/watch?v=BPFp3tSbZAE\",\"https://www.youtube.com/watch?v=As1YDPOAEw0\",\"https://www.youtube.com/watch?v=Q2LFIgvixEk\",\"https://www.youtube.com/watch?v=c4KmH8PNado\"]', '2026-04-01 02:00:07.425', '2025-08-05 22:20:27.709', 667, NULL, 1, 2016, 'ApĂłs conquistar o mercado regional e se tornar referĂȘncia de pizzas de qualidade na regiĂŁo sul de Santa Catarina, a Dugas Pizza Delivery, juntamente com dois empresĂĄrios locais com ampla experiĂȘncia em Franquias e apaixonados pela pizza da Dugas, iniciaram a formataĂ§ĂŁo da empresa para a expansĂŁo atravĂ©s do franchising - e o resultado nĂŁo poderia ser diferente: em 01 ano de expansĂŁo a Rede jĂĄ conta com 16 unidades espalhadas pelo Brasil, com presenĂ§a em todos os Estados do Sul e Sudeste e mais de 85 mil pizzas entregues. Sabendo que o Brasil Ă© o segundo maior consumidor de pizzas do Mundo, atrĂĄs apenas dos Estados Unidos, bem como do exponencial crescimento e consolidaĂ§ĂŁo do delivery nos Ășltimos anos, a Dugas aposta na qualidade de seus produtos, elaborados somente com ingredientes de mĂĄxima qualidade, para navegar nesse verdadeiro oceano azul de oportunidades em um mercado concorrido, porĂ©m, onde a maior parte da concorrĂȘncia briga por preĂ§o. Um dos grandes diferenciais, alĂ©m da altĂ­ssima qualidade da pizza, Ă© o valor de investimento abaixo do mercado, pois a Dugas Pizza Delivery nĂŁo necessita de pizzaiolo nem de mĂŁo de obra especializada. Todos os processos sĂŁo padronizados e o Franqueado recebe todo o suporte necessĂĄrio, o treinamento inicial Ă© realizado pela franqueadora presencialmente na unidade Franqueada, e apĂłs esse treinamento a equipe ja se encontra apta a produzir e fornecer a pizza de qualidade com o selo da Dugas Pizza Delivery. âEssa combinaĂ§ĂŁo resulta em um processo ĂĄgil e muito rĂĄpido na entrega para fidelizar cada vez mais os clientesâ, explica Marcus Mendes, Diretor de ExpansĂŁo da marca.', NULL, 'SANTA CATARINA', 1, NULL, 13, NULL, NULL, '2026-03-08 23:57:57.480', 'https://franquias.portaldofranchising.com.br/franquia-dugas-pizza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
