ionar uma incrĂ­vel experiĂȘncia de sabor aos nossos clientes. Fazendo isso com o compromisso de incorporar ingredientes naturais e saudĂĄveis. Assegurando sempre as boa prĂĄticas e o respeito pelo planeta e ambiente. \nFaĂ§a parte desta famĂ­lia #viciadosemaĂ§ai', NULL, 'PERNAMBUCO', 1, NULL, 378, NULL, NULL, '2026-03-08 23:59:06.254', 'https://franquias.portaldofranchising.com.br/franquia-acai-concept/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
