anquia-ragazzo-valor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '320000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
