INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gm00hteh0swuzt1t0l', 'AMBEV - CHOPP BRAHMA EXPRESS', 'ambev-chopp-brahma-express', NULL, 'AlimentaĂ§ĂŁo', 'DISTRIBUIĂĂO E PRODUĂĂO', 'Delivery de chopp para eventos, com foco no atendimento apenas de Pessoa FĂ­sica.', 2005, 2008, NULL, '2026-04-01 02:00:07.532', '2025-08-05 22:20:27.766', 678, NULL, 1, 1999, 'CHOPP BRAHMA EXPRESS O Chopp Brahma Express, no mercado desde 2005, inovou e se transformou num modelo mais convergente Ă s tendĂȘncias e comportamentos dos nossos consumidores. A proposta de valor da Franqueadora Ă© ser a principal soluĂ§ĂŁo de consumo de chopp em casa, garantindo uma experiĂȘncia ainda mais completa e sinĂ©rgica entre todos os nossos canais, em especial as lojas fĂ­sicas. Em seus dois tamanhos e formatos distintos de unidades fĂ­sicas, Light Store e Compact, o CBE tĂȘm a definiĂ§ĂŁo pelo tamanho ideal para cada tipo de cidade, territĂłrio de atendimento, sendo baseado em diretrizes geogrĂĄficas, quantidade habitantes e potencial de consumo, alĂ©m de levar em consideraĂ§ĂŁo raios de deslocamento logĂ­stico. O formato ideal apontado, visa o encaixe assertivo considerando fatores de investimento, rentabilidade e payback, mantendo os pilares de entrega do CBE: as principais soluĂ§Ă”es de consumo e experiĂȘncia de chopp em casa, somado com a disponibilidade de todo portfĂłlio Ambev, seja via visitaĂ§ĂŁo nas lojas fĂ­sicas, ou pelos nossos demais canais (online/digitais ou offline), proporcionando uma verdadeira experiĂȘncia âOmnichannelâ. Chopp Brahma Express Ă© uma franquia oficial Ambev! Qual Ă© o momento do mercado e segmento? A Ambev Ă© lĂ­der no segmento em que atua. Nossas franquias tĂȘm relevante peso no mercado de chopp nacional e cada vez mais Ă© percebida como uma soluĂ§ĂŁo completa na experiĂȘncia de todos os demais lĂ­quidos do nosso portfĂłlio. Entretanto, diante do enorme potencial de crescimento do setor e surgimento de novos entrantes nesse mercado, nosso dever Ă© inovar e evoluir para mantermos a solidez dos nossos parceiros e expandirmos constantemente o business como um todo. Quais os produtos e serviĂ§os disponĂ­veis? O CBE Ă© uma franquia de sortimento e uma soluĂ§ĂŁo completa desde grandes eventos a pequenos encontros. Todo o portfĂłlio Ambev estĂĄ disponĂ­vel para compra e consumo nas nossas lojas fĂ­sicas, via delivery, ou atravĂ©s do nosso e-commerce oficial (a disponibilidade de skuâs pode variar de acordo com cada regiĂŁo). Qual o territĂłrio de atuaĂ§ĂŁo e as principais rotinas operacionais? Estamos presentes em aproximadamente 60% do territĂłrio do Brasil e em plena expansĂŁo. Com isso, a Franqueadora determina o raio de atuaĂ§ĂŁo da sua unidade baseado de um estudo de potencial e de deslocamento logĂ­stico e aponta quais os bairros ou atĂ© mesmo cidades que sua loja poderĂĄ atender. O CBE tem como foco o atendimento ao consumidor final, festas e eventos particulares e, por regra, nĂŁo estĂĄ autorizado a atender pontos de vendas e estabelecimentos comerciais, salvo em exceĂ§Ă”es concedidas pela prĂłpria Ambev. As vendas sĂŁo realizadas nas 207* lojas fĂ­sicas CBE, no 0800 888 1021, atravĂ©s da plataforma e-commerce no site choppbrahmaexpress.com.br e de appâs de entrega (parceiros), como o ZĂ© Delivery. O projeto e design da loja, em seus dois diferentes modelos, foi desenvolvido a fim de criar um ambiente baseado em curadoria, experiĂȘncia, relacionamento e especialmente excelĂȘncia operacional. (*Jan/2024). O CEP de onde cada compra se origina, seja atravĂ©s do e-commerce, seja atravĂ©s do telefone oficial sĂŁo direcionados Ă  sua unidade respeitando o territĂłrio de atendimento e polĂ­gono concedido e/ou presente em seu contrato de franquia. Vale ressaltar que nĂŁo hĂĄ interseĂ§ĂŁo de raios, ou seja, o cliente sempre serĂĄ direcionado Ă  unidade do territĂłrio que ele se encontra. O contrato de franquia tem vigĂȘncia de 5 anos e o tempo mĂ©dio entre a formalizaĂ§ĂŁo e a inauguraĂ§ĂŁo da unidade fĂ­sica varia entre 60 e 90 dias, de acordo com o modelo. A rentabilidade mĂ©dia mensal varia entre 10% e 13%. O payback mĂ©dio Ă© entre 40 e 48 meses. Sendo o ponto de equilĂ­brio de venda do chopp de 8000 litros/mĂȘs. Sobre o Franqueado: A Franqueadora possui um criterioso processo de seleĂ§ĂŁo e uma das caracterĂ­sticas essenciais Ă© que o franqueado esteja Ă  frente do negĂłcio com dedicaĂ§ĂŁo exclusiva, preferencialmente, e com disponibilidade para gerir sua franquia inclusive aos finais de semana e feriados. A Ambev garante o treinamento inicial, transferĂȘncia de know-how e consultoria de campo para a conduĂ§ĂŁo do negĂłcio. PorĂ©m, Ă© de extrema importĂąncia que o candidato se identifique com o produto e com a oportunidade. Sociedades sĂŁo permitidas, mas sempre deverĂĄ existir a figura do sĂłcio operador, aquele que terĂĄ a interface diĂĄria com a Franqueadora sobre novas campanhas, alĂ©m de questĂ”es administrativas, financeiras, legais, tĂ©cnicas e operacionais. O franqueado deverĂĄ ter as seguintes caracterĂ­sticas: Ter ciĂȘncia de que estĂĄ se propondo a ter um negĂłcio prĂłprio e com riscos inerentes Ă  implantaĂ§ĂŁo de quaisquer atividades empresariais; Compreender premissas, estimativas de investimento e payback, inteirar-se do conteĂșdo, deveres e obrigaĂ§Ă”es presentes na COF â Circular de Oferta de Franquia; EspĂ­rito empreendedor, dinĂąmico e com forte desejo de ser bem-sucedido; Dedicar-se ao perfeito andamento da operaĂ§ĂŁo e performance financeira; Zelar por produtos e equipamentos concedidos sob regime de comodato pela Ambev; Respeitar as iniciativas, programas e utilizaĂ§ĂŁo de serviĂ§os e assets de fornecedores e parceiros homologados pela Franqueadora; Gostar de trabalhar em Rede, atendendo a diretrizes do contrato de franquia. Quais as caracterĂ­sticas de cada modelo e seus investimentos? A Ambev auxilia na escolha do ponto comercial, premissas de locaĂ§ĂŁo (contrato mĂ­nimo de locaĂ§ĂŁo de cinco anos) e projeto arquitetĂŽnico. A adequaĂ§ĂŁo civil, aquisiĂ§ĂŁo e instalaĂ§ĂŁo do enxoval geral adquirido junto a fornecedores homologados: mobiliĂĄrios, cĂąmara fria, utensĂ­lios e uniformes, cilindros e ferramentaria sĂŁo responsabilidade do franqueado e jĂĄ previstos no investimento inicial. Quais sĂŁo os gastos apĂłs a compra da franquia? Todo o investimento citado anteriormente Ă© para a implantaĂ§ĂŁo fĂ­sica da loja. PorĂ©m, o franqueado terĂĄ alguns outros custos corriqueiros e operacionais. Royalties (10%) e Fundo de Propaganda (4%) incidem sobre a compra de produtos Ambev. Marketing local: a Franqueadora realiza aĂ§Ă”es de propaganda em seus canais oficiais, mas cabe ao franqueado impulsionar as vendas localmente com as mĂ­dias que melhor se adequam Ă  regiĂŁo. Mensalidade sistema de gestĂŁo homologado (Linx): o valor da mensalidade para administraĂ§ĂŁo do sistema Ă© de responsabilidade do franqueado. RenovaĂ§ĂŁo de contrato: caso seja de interesse do franqueado e da Franqueadora, apĂłs o perĂ­odo de 5 anos de contrato, Ă© feita a renovaĂ§ĂŁo. Nesse momento, serĂĄ cobrado o valor de 75% do valor da taxa de franquia (TIF) vigente do ano de renovaĂ§ĂŁo. ManutenĂ§ĂŁo: cabe ao franqueado manter a loja e os equipamentos em perfeito funcionamento. Para isso, devem manter uma manutenĂ§ĂŁo periĂłdica por meio de serviĂ§os especializados. Reforma: de tempos em tempos, serĂĄ necessĂĄria a reforma e adequaĂ§ĂŁo ao padrĂŁo mais atual da franquia.', NULL, 'SĂO PAULO', 1, NULL, 205, NULL, NULL, '2025-08-07 11:09:22.000', 'https://franquias.portaldofranchising.com.br/franquia-ambev-chopp-brahma-express-conveniencia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gt00hueh0sllaqonzg', 'CEC', 'cec', NULL, 'EducaĂ§ĂŁo', 'EDUCAĂĂO', 'ColĂ©gio', 2024, 2025, NULL, '2026-04-01 02:00:07.543', '2025-08-05 22:20:27.773', 679, NULL, 1, 2021, '', NULL, 'SĂO PAULO', 1, NULL, 1, NULL, NULL, '2025-10-13 14:55:24.000', 'https://franquias.portaldofranchising.com.br/franquia-cec-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76gy00hveh0sua89rboz', 'MINI KALZONE', 'mini-kalzone', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Primeira e maior rede de mini calzones com a concepĂ§ĂŁo fast-food no mundo, a Mini Kalzone reĂșne produtos de alta qualidade com resultados comprovados nas mais de 145 lojas de sucesso pelo Brasil.', 2001, 2002, '[\"https://www.youtube.com/watch?v=N5FrBsQQGD8\",\"https://www.youtube.com/watch?v=KjetihEybls\",\"https://www.youtube.com/watch?v=2wxCmCEo68k\"]', '2026-04-01 02:00:07.552', '2025-08-05 22:20:27.778', 680, NULL, 1, 1993, 'A Mini Kalzone foi fundada em setembro de 1993 com a abertura de sua primeira loja na rua Anita Garibaldi, onde funciona atĂ© hoje, no Centro de FlorianĂłpolis/SC. \nA grande sacada do fundador e atual sĂłcio da empresa, JoĂŁo Batista Cardoso, foi transformar um prato tĂ­pico italiano, que lembra uma pizza dobrada ao meio, recheada e assada (o calzone), em uma porĂ§ĂŁo individual prĂĄtica, bem recheada e com preĂ§o acessĂ­vel. \nAssim, nasceu a primeira rede de calzones com a concepĂ§ĂŁo de fast-food no mundo. \nLogo em 1994, para aumentar a capacidade produtiva e atender a demanda crescente, JoĂŁo Batista Cardoso associou-se a Murilo de Souza Naspolini e Luciano JosĂ© Fadel, iniciando o processo de multiplicaĂ§ĂŁo deste bem sucedido modelo de negĂłcio. \nA partir de 2001, foi criada a MK Marketing e Franchising Ltda, com o objetivo de replicar em todo o Brasil o sucesso jĂĄ consagrado em FlorianĂłpolis, expandindo como formato de franquia. \nAssim, a Mini Kalzone se consolidou como uma empresa verticalizada e completa, atuando na indĂșstria alimentĂ­cia (indĂșstrias), no transporte das mercadorias com logĂ­stica prĂłpria, no comĂ©rcio varejista (lojas) e na prestaĂ§ĂŁo de serviĂ§os de Marketing e Franchising (expansĂŁo) \nDessa forma, alĂ©m de excelentes produtos, a Mini Kalzone oferece tambĂ©m um Ăłtimo modelo de negĂłcio para investidores, uma franquia verdadeira, com resultados comprovados e reconhecimento no mercado. \nCom uma marca forte, produtos de alta qualidade e proporcionando experiĂȘncias de sabores Ășnicos, a Mini Kalzone cresceu de forma orgĂąnica e sustentĂĄvel, chegando em 2018 ao marco de 100 lojas, entregando qualidade e amor em cada produto. \nHoje a rede estĂĄ presente em quase todo o Brasil, do Sul ao Nordeste, com mais de 125 lojas ativas em 12 estados + Distrito Federal e 55Â cidades. \nSeguindo um contĂ­nuo processo de expansĂŁo sustentĂĄvel e responsĂĄvel, a Mini Kalzone Ă© altamente comprometida com o sucesso de seus franqueados e com a qualidade dos produtos servidos para cada cliente em todas as lojas..', NULL, 'SANTA CATARINA', 1, NULL, 152, NULL, NULL, '2026-03-09 00:03:58.733', 'https://franquias.portaldofranchising.com.br/franquia-mini-kalzone/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
