INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76h900hxeh0sqp6c8uh7', 'ECODECOR', 'ecodecor', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'Venda de revestimentos para paredes internas e externas jĂĄ aplicados, (mÂČ), por profissionais especializados, treinados pela franquia. Agregamos valor ao trabalho com a venda de produtos e serviĂ§os.', 2014, 2021, NULL, '2026-04-01 02:00:07.573', '2025-08-05 22:20:27.790', 682, NULL, 1, 2011, '', NULL, 'SĂO PAULO', 1, NULL, 109, NULL, NULL, '2025-10-27 15:37:50.000', 'https://franquias.portaldofranchising.com.br/franquia-ecodecor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76hf00hyeh0skgy5lalf', 'VINHO & PONTO', 'vinho-ponto', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Loja especializada em vinhos, trabalha c/ marcas exclusivas nacionais e importadas das melhores regiĂ”es, alĂ©m da operaĂ§ĂŁo da loja o franqueado tambĂ©m atua como distribuidor, venha ser nosso sĂłcio .', 2014, 2015, '[\"https://www.youtube.com/watch?v=LkWnTcv0940\"]', '2026-04-01 02:00:07.583', '2025-08-05 22:20:27.795', 683, NULL, 1, 2010, 'Como na maioria das vezes grandes ideias surgem da necessidade de seus idealizadores, e no caso da franquia Vinho & Ponto Franchising nĂŁo foi diferente. Em nossa famĂ­lia desde sempre cultivamos o hĂĄbito de consumir e conhecer vinhos, tendo o mesmo como parte de nossa alimentaĂ§ĂŁo e dos melhores momentos de nosso dia a dia. Projeto diferenciado e Ășnico para este produto, dedicado a atender bairros de grandes cidades e ou cidades de pequeno porte, de maneira a aproximar-se do novo consumidor e superar expectativas dos velhos amantes do vinho, apresentando o vinho como produto acessĂ­Â­vel a todos, a fim de criar a referĂȘncia de vinhos no mercado brasileiro e aproveitar todo o potencial deste merc