INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76j100i8eh0s8seizbr1', 'HINODE', 'hinode', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'ComercializaĂ§ĂŁo de cosmĂ©ticos', 2012, 2015, NULL, '2026-04-01 02:00:07.691', '2025-08-05 22:20:27.853', 693, NULL, 1, 1988, 'O Grupo Hinode possui duas marcas consolidadas no mercado com cerca de 600 produtos, dentre eles perfumaria, bem-estar, higiene pessoal, maquiagem e cosmĂ©ticos. Â  TEMOSÂ FRANQUIAS EMÂ TODO BRASIL AsÂ franquias Hinode, hoje conhecidas como Hinode Center, foram criadas com o objetivo de facilitar a logĂ­stica e a distribuiĂ§ĂŁo de produtos para os consultores da empresa. Com estruturas modernas que contam com sala para treinamento e reuniĂŁo, as franquias da Hinode sĂŁo uma verdadeira âmĂŁo na rodaâ para os consultores, os quais podemÂ retirar seus produtos na hora, garantindo que seus clientes sejam atendidos com agilidade. Muito mais que um local para experimentarÂ e adquirir produtos, o Hinode Center eÂŽ umaÂ extensĂŁo da nossa marca para todo oÂ Brasil.  AlĂ©m de ser um ponto de retirada de produtos, as franquias Hinode servem como ponto de apoio para o consultor, o qual pode fazer reuniĂ”es e agendar apresentaĂ§ĂŁo do plano de negĂłcios. Muitas franquias tambĂ©m oferecem treinamento sobre produtos e sobreÂ os 10 passos para o sucesso. O Hinode Center Ă© o lugar ideal para levar os prospectos que estĂŁo em fase de acompanhamento, para que eles possam conhecer a estrutura da empresa. Atualmente,Â a empresa conta com mais de 440 franquias, espalhadas pelos quatro cantos do Brasil.Â  Â  PASSADAÂ DE GERAĂĂOÂ A GERAĂĂO Com muito trabalho e determinaĂ§ĂŁo, SrÂ Francisco e Dona Adelaide Rodrigues fundaramÂ a Hinode em 1988 com uma missĂŁo: oferecer Ă sÂ pessoas a oportunidade para mudarem de vida. Hoje, seu filho Sandro Rodrigues Ă© o presidente do Grupo Hinode e vencedor do trofĂ©u empresĂĄrio do ano, conquistando uma gestĂŁo de sucesso junto aos seus irmĂŁos Alessandro Rodrigues, Crisciane Rodrigues e Leandro Rodrigues e toda a equipe. Â  NOSSA MISSĂO OFERECER ĂS PESSOAS A OPORTUNIDADE PARA MUDAREM DE VIDA Acreditamos que temos um papel maior na sociedade - ser um agente transformador na vida de milhĂ”es de pessoas, proporcionando uma oportunidade Ășnica de mudar de vida. Enxergamos em cada pessoa um empreendedor em potencial e, por isso, oferecemos todas as ferramentas para que possam se desenvolver profissionalmente. Para que consigam atingir suas metas pessoais, realizar seus sonhos e construir um novo futuro para sua famĂ­lia. Ă essa crenĂ§a que nos move e nossa verdadeira razĂŁo de existir. Â  SEM ESFORĂOÂ NĂO HĂÂ RESULTADO NĂŁo tem milagre. Com honestidade, fĂ© e muito trabalho, construĂ­mos uma trajetĂłria de superaĂ§ĂŁo e atingimos um crescimento exponencial. Â  VERDADEIROSÂ LĂDERES INSPIRAMÂ O CRESCIMENTO A lideranĂ§a faz parte do nosso DNA. Acreditamos que sĂŁo os lĂ­deres que movimentam o mundo, por isso, decidimos desenvolvĂȘ-los. Buscamos revelar talentos, motivar e inspirar nĂŁo sĂł os nossos parceiros, mas a sociedade. Â  MAIS QUEÂ UM TIME,Â UMA FAMĂLIA Acolhemos a todos de braĂ§os abertos, criamos relaĂ§Ă”es verdadeiras, compartilhamos ideais e objetivos, comemoramos lado a lado o nosso sucesso. Porque ninguĂ©m conquista nada sozinho. Juntos, somos mais fortes. Â  ISSO Ă SĂÂ O COMEĂO.Â TEMOS O MUNDOÂ PELA FRENTE Compartilhamos o desejo por algo mais, a vontade de ir alĂ©m. Temos o espĂ­rito empreendedor, a inquietude e o entusiasmo de quem ainda tem muito a conquistar. Para nĂłs, tudo isso Ă© apenas o comeĂ§o. Â  FRANQUIA HINODE  Adotamos o modelo de franchising em 2012.Â  Nelas, nosso consultores, tem um local para adquirir seus produtos, fazer seus treinamento e reuniĂ”es.', NULL, 'SĂO PAULO', 1, NULL, 253, NULL, NULL, '2026-03-09 00:09:14.125', 'https://franquias.portaldofranchising.com.br/franquia-hinode-cosmeticos-e-perfumaria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
