INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76jn00iceh0srt20otm2', 'PELLO MENOS DEPILAĂĂO', 'pello-menos-depilacao', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'DepilaĂ§ĂŁo a Cera, Linha e Laser', 2007, 2009, '[\"https://www.youtube.com/watch?v=6WwUfofmf_Y\",\"https://www.youtube.com/watch?v=oO5rONRr2mQ\",\"https://www.youtube.com/watch?v=jKtm3ssQ124\"]', '2026-04-01 02:00:07.729', '2025-08-05 22:20:27.875', 697, NULL, 1, 1996, 'Pode ser mĂŁe, esposa, filha, irmĂŁ. Pode ser empresĂĄria, executiva. NĂŁo importa o cargo que ocupa ou o estado civil; o que vale mesmo Ă© que todas, embora tĂŁo diferentes, tĂȘm trĂȘs caracterĂ­sticas em comum: o passo acelerado, a vida corrida e uma agenda atribulada. Foi pensando nelas e, principalmente, por ser uma delas, que a Regina JordĂŁo, visualizou e estruturou um negĂłcio de sucesso num nicho de mercado pouco explorado atĂ© entĂŁo. \nO Pello Menos, hoje uma rede de franquias com 46 unidades, nasceu no ano de 1996 em Copacabana e se tornou pioneiro na idealizaĂ§ĂŁo de um instituto de depilaĂ§ĂŁo, exclusivamente feminino. \nO que as mulheres querem quando pensam em depilaĂ§ĂŁo? Uma pele lisinha e macia Ă© certamente a resposta correta, mas um procedimento seguro e sem sofrimento tambĂ©m sĂŁo requisitos muito importantes. Para obter esses resultados a depilaĂ§ĂŁo Ă  cera Ă© a mais indicado e engana-se quem pensa que esse mĂ©todo Ă© sinĂŽnimo de dor. O segredo para esse momento se tornar apenas mais um ritual de beleza tranquilo Ă©, justamente, o material utilizado. \nOs benefĂ­cios da utilizaĂ§ĂŁo da cera sĂŁo muitos. Ela deixa a pele mais lisa, ajuda a retirar cĂ©lulas mortas, retira os pelos pela raiz, alĂ©m de fazĂȘ-los crescerem mais finos. Foi pensando em todos esses benefĂ­cios proporcionados pelo mĂ©todo que a fundadora e CEO da rede Pello Menos, Regina JordĂŁo, criou uma cera com fĂłrmula exclusiva e que causa menos dor na depilaĂ§ĂŁo. \nCom uma fĂłrmula Ă  base de mel e especiarias naturais, a cera tem uma textura elĂĄstica que garante maior aproveitamento e aderĂȘncia ao pelo, o que resulta em uma depilaĂ§ĂŁo mais prĂĄtica e, o melhor, menos dolorosa. \nMantida em uma temperatura ideal e agradĂĄvel para a pele, a cera pode ser utilizada em todas as ĂĄreas do corpo e por mulheres de todas as idades, incluindo as adolescentes. O mĂ©todo Ă  cera Ă© o mais indicado para todas as mulheres, explica Regina JordĂŁo. Isso porque nĂŁo hĂĄ destruiĂ§ĂŁo dos tecidos celulares do organismo, como outros mĂ©todos fazem. Afinal, cuidar da pele Ă© prezar pela saĂșde e nĂŁo devemos maltratĂĄ-la. \nEm 1997 foi inaugurado o Centro de OrientaĂ§ĂŁo Profissional (COP), localizado em Copacabana, no Rio. O Cop Ă© considerado a Universidade do Pello. O objetivo Ă© oferecer conhecimento teĂłrico e prĂĄtico para suas profissionais, possibilitando-as a exercerem o trabalho da melhor forma possĂ­vel. \nEntendemos que a depilaĂ§ĂŁo feminina possui muitas dificuldades. Por isso, nossas profissionais recebem um treinamento tĂ©cnico intenso e constantes avaliaĂ§Ă”es para realizarem uma depilaĂ§ĂŁo sem hora marcada, rĂĄpida, com menos dor e mais conforto para todas as nossas clientes em qualquer uma de nossas unidades. \nToda nova colaboradora tem um perĂ­odo de quatro meses de formaĂ§ĂŁo, sendo 360 horas de aulas teĂłricas e 600 horas de aulas prĂĄticas. O treinamento oferecido capacita a profissional para o atendimento, atravĂ©s de conhecimento teĂłrico da histologia da pele e o treinamento prĂĄtico em grande escala para total capacitaĂ§ĂŁo da profissional, o que garante que nossas clientes serĂŁo atendidas por equipe altamente qualificada. \nAlĂ©m disso, o Pello Menos trabalha com a famosa cera exclusiva, Ășnica no Brasil: âA depilaĂ§ĂŁo faz parte da rotina das mulheres e nĂŁo precisa ser um momento de sofrimento. Por isso criamos uma cera exclusiva, registrada pelo MinistĂ©rio da SaĂșde e aprovada dermatologicamente, para proporcionar praticidade, liberdade e seguranĂ§aâ, ressalta Regina.', NULL, 'RIO DE JANEIRO', 1, NULL, 35, NULL, NULL, '2026-03-09 00:12:06.237', 'https://franquias.portaldofranchising.com.br/franquia-pello-menos-depilacao-estetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '355000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
