INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76l000ikeh0sj26z3txr', 'EURO COLCHĂES', 'euro-colchoes', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'ComĂ©rcio de colchĂ”es, boxes, cabeceiras, poltronas e acessĂłrios.', 2008, 2017, '[\"https://www.youtube.com/watch?v=4XBl0DKTwaE\",\"https://www.youtube.com/watch?v=W94UfIC3jBc\",\"https://www.youtube.com/watch?v=A2dahC9pb5M\"]', '2026-04-01 02:00:07.806', '2025-08-05 22:20:27.924', 705, NULL, 1, 2005, 'A Euro ColchĂ”es nasceu para entregar uma experiĂȘncia Ășnica no mercado de colchĂ”es. NĂłs somos apaixonados pelo o que fazemos. E usamos nossa expertise e inovaĂ§ĂŁo tecnolĂłgica para cuidar dos nossos clientes. Nossa primeira loja foi inaugurada em 2005. Desde o inĂ­cio, nosso objetivo Ă© oferecer produtos da mais alta qualidade, bem como um atendimento especializado e cuidadoso. \nAlcanĂ§ar a excelĂȘncia estĂĄ em nosso DNA. \nTemos como foco principal o desenvolvimento de novas tecnologias para colchĂ”es, em 2011 inauguramos a nossa fĂĄbrica na cidade de TrĂȘs Rio. Firmamos parceria de desenvolvimento, transferĂȘncia de tecnologia, possuindo exclusividade de fabricaĂ§ĂŁo e comercializaĂ§ĂŁo dos colchĂ”es KINGSDOWNÂź no Brasil. AlĂ©m disso, em parceria com a Unifi, maior fabricante de fios reciclados do mundo, desenvolvemos a linha EcoMind. \nNossa marca desperta interesse, devido a diferenciais como: baixo investimento, rentabilidade rĂĄpida, marcas exclusivas, fĂĄbrica prĂłpria e ausĂȘncia de estoque. Essas sĂŁo algumas das vantagens que um franqueado da Euro tem, alĂ©m da certeza de comercializar produtos de alta qualidade. \nDisponibilizamos suporte ao franqueado, atravĂ©s de sistema de informĂĄtica TOTVS, manuais operacionais, programa de treinamento e capacitaĂ§ĂŁo, consultoria de campo, marketing e publicidade. No ano de 2020, recebemos o prĂȘmio ExcelĂȘncia em Franchising da ABF. \nA Euro ColchĂ”es se posiciona como uma marca de prestĂ­gio. Um local onde o cliente Ă© atendido de forma diferenciada. Nos preocupamos em oferecer uma grande experiĂȘncia de compra e nossos vendedores sĂŁo altamente capacitados para ajudar o cliente a escolher o produto ideal.', NULL, 'RIO DE JANEIRO', 1, NULL, 72, NULL, NULL, '2026-03-09 00:17:48.591', 'https://franquias.portaldofranchising.com.br/franquia-euro-colchoes-artigos-para-o-lar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '278000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76l500ileh0s6l8r3yoe', 'VIASOFT', 'viasoft', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'SoluĂ§Ă”es/Softwares de gestĂŁo empresarial', 1995, 2023, NULL, '2026-04-01 02:00:07.815', '2025-08-05 22:20:27.930', 706, NULL, 1, 1990, '', NULL, 'PARANĂ', 1, NULL, 12, NULL, NULL, '2026-02-23 17:16:14.000', 'https://franquias.portaldofranchising.com.br/franquia-viasoft/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '36900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lb00imeh0sa0l4v3nx', 'CASA DO CONSTRUTOR', 'casa-do-construtor', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Aluguel de equipamentos para construĂ§ĂŁo civil, pintura, jardinagem e limpeza.', 1998, 1998, '[\"https://www.youtube.com/watch?v=jVA9BBF9znA\"]', '2026-04-01 02:00:07.824', '2025-08-05 22:20:27.935', 707, NULL, 1, 1993, 'Nossa histĂłria agrega, de fato, muitos desses valores. \nEscrita com Ă©tica, com responsabilidade social, contaminada pela paixĂŁo ao trabalho, devotada Ă  sustentabilidade, Ă  inovaĂ§ĂŁo, Ă s melhores prĂĄticas de gestĂŁo, manifestada na excelĂȘncia do atendimento ao cliente, no respeito humano. \nHistĂłria que, desde sua origem, inspirou-se na amizade entre dois universitĂĄrios, os engenheiros civis Altino Cristofoletti Junior e Expedito Eloel Arena. Partiu deles a iniciativa de materializar esse projeto. No inĂ­cio, em 1993, uma modesta loja de materiais de construĂ§ĂŁo fundada em Rio Claro, regiĂŁo de Campinas, no interior paulista. \nDepois, nos trĂȘs anos seguintes, desenvolveu-se o roteiro para a criaĂ§ĂŁo da primeira franquia brasileira especializada na locaĂ§ĂŁo de mĂĄquinas e equipamentos de pequeno porte para a construĂ§ĂŁo civil. \nA Unidade Piloto da Rede surgiu em 1998, jĂĄ com o registro da marca CASA DO CONSTRUTOR no INPI â Instituto Nacional de Propriedade Industrial. Naquele mesmo ano era inaugurada a primeira loja da franquia, em Americana. Consolidada, hoje, em todas as regiĂ”es do Brasil, num contĂ­nuo movimento de expansĂŁo pelo territĂłrio nacional, Ă© uma das marcas mais laureadas dos Ășltimos anos. \nMelhor Franquia em 2010, pela Revista Pequenas Empresas & Grandes NegĂłcios e tambĂ©m a Melhor do Brasil em 2012, prĂȘmio da AssociaĂ§ĂŁo Brasileira de Franchising (ABF), a qual a empresa Ă© associada desde sua fundaĂ§ĂŁo. Em 2011, a CASA DO CONSTRUTOR tornava-se Empreendedor do Ano, pela Consultoria Ernst & Young, passando ainda a figurar como Empreendedor Endeavor. \nTodas as premiaĂ§Ă”es â e sĂŁo inĂșmeras â alĂ©m de selos de certificaĂ§ĂŁo consecutivos obtidos tĂȘm o respaldo dos mais conceituados institutos. Com a responsabilidade de ser referĂȘncia no mercado, a Rede se permite ter ao seu lado parceiros que tambĂ©m advogam os mesmos princĂ­pios. \nĂ este o perfil dos nossos franqueados, dos nossos fornecedores, todos consagrados em seus segmentos, dos nossos colaboradores, dos nossos amigos e clientes. \nNegĂłcios sĂŁo negĂłcios, mas aqui as amizades nunca ficam Ă  parte. O sucesso de um Ă© o sucesso do coletivo.', NULL, 'SĂO PAULO', 1, NULL, 808, NULL, NULL, '2026-03-09 00:18:53.464', 'https://franquias.portaldofranchising.com.br/franquia-casa-do-construtor-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '529000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
