INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76lv00iqeh0sqk0ns8y0', 'DOUTOR RESOLVE', 'doutor-resolve', NULL, 'Casa e ConstruĂ§ĂŁo', 'CONSTRUĂĂO', 'Doutor Resolve oferece serviĂ§os que atende tanto residĂȘncias com pequenos reparos, reformas, projetos, construĂ§Ă”es e paisagismo, quanto empresas com soluĂ§Ă”es corporativas.', 2010, 2018, '[\"https://www.youtube.com/watch?v=euj4R9GYqDk\"]', '2026-04-01 02:00:07.863', '2025-08-05 22:20:27.956', 711, NULL, 1, 2010, 'Fundada em agosto de 2010, a Doutor Resolve nasceu com o objetivo de profissionalizar o setor de serviĂ§os da construĂ§ĂŁo civil. Em um cenĂĄrio de alta demanda e carente por profissionais qualificados e compromissados, rapidamente a Doutor Resolve conquistou milhares de clientes por todo o Brasil atendendo-os de maneira inovadora e altamente eficiente. Hoje a Doutor oferece serviĂ§os que atende tanto residĂȘncias com pequenos reparos, reformas, projetos, construĂ§Ă”es e paisagismo, quanto empresas com soluĂ§Ă”es corporativas. A marca passou a fazer parte do portfĂłlio de franquias da EFFE Franchising em Julho de 2016. A EFFE Franchising Ă© uma Holding de Franquias, de SĂŁo JosĂ© do Rio Preto, interior de SĂŁo Paulo. AlĂ©m das marcas Doutor Resolve a EFFE tambĂ©m possui a marca Dona Resolve, focada em limpeza e facilidades para o lar e soluĂ§Ă”es para empresas. No ano de 2020 a Doutor Resolve alcanĂ§a 5 Estrelas no anuĂĄrio da revista da Pequenas Empresas e Grandes Negocios e neste mesmo ano conquista seu primeiro Sele de ExcelĂȘncia em Franchising, comprovando a qualidade da marca e eficiĂȘncia do suporte ao franqueado. Nos anos seguintes a marca conquista o Selo de ExcelĂȘncia em Franchising, somando trĂȘs conquistas consecutivas, consolidando sua presenĂ§a de destaque no franchising brasileiro.', NULL, 'SĂO PAULO', 1, NULL, 25, NULL, NULL, '2025-08-22 18:40:20.000', 'https://franquias.portaldofranchising.com.br/franquia-doutor-resolve/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
