INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ml00iveh0si9wr90ns', 'CHURRAS EXPRESS', 'churras-express', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'LOJA OU QUIOSQUE DE VENDA DE ESPETOS ASSADOS OU IN NATURA, COM UM MIX VARIADO DE PRODUTOS COMPLEMENTARES', 2018, 2021, '[\"https://www.youtube.com/watch?v=QpHr31r3pfA\",\"https://www.youtube.com/watch?v=l13E9tMA2wA\"]', '2026-04-01 02:00:07.914', '2025-08-05 22:20:27.981', 716, NULL, 1, 2018, 'CHURRAS EXPRESS â desde 2019 A ideia do Churras Express, surgiu apĂłs 18 meses de experiĂȘncia em nossa outra franquia, no mesmo mercado mas com outro produto.Â  \nDetectamos na Ă©poca quais eram os desejos e necessidades do pĂșblico, quais os diferenciais deveriam ser criados e o que definitivamente atenderia essa necessidade independente de clima, local, fluxo entre outros quesitos.Â  \nO desafio seria criar algo que o brasileiro consome diariamente, de uma forma rĂĄpida, higiĂȘnica, com qualidade e baixo custo, surgindo assim o Churras Express Brasil.', NULL, 'SĂO PAULO', 1, NULL, 57, NULL, NULL, '2026-03-09 00:22:33.407', 'https://franquias.portaldofranchising.com.br/franquia-churras-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '164000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76mq00iweh0sgq6wmz97', 'PEGGĂ MARKET', 'peggo-market', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'Mercados autĂŽnomos para condominios e empresas', 2022, 2023, '[\"https://www.youtube.com/watch?v=dXom-1_NzBM\",\"https://www.youtube.com/watch?v=D-d_5VDYxP0\"]', '2026-04-01 02:00:07.924', '2025-08-05 22:20:27.986', 717, NULL, 1, 2021, 'Empresa formada por Empreendedores, que identificaram as oportunidades de mercado em meio Ă  alta demanda proporcionada pelo advento da pandemia. \nDecidiram focar seus esforĂ§os em desenvolver um modelo de negĂłcios que unisse tecnologia e praticidade para o ramo de minimercados, trazendo comodidade e praticidade aos clientes. Com muito estudo e pesquisas de mercado, quisemos ser ĂĄgeis na aplicaĂ§ĂŁo do modelo estudado, e jĂĄ nos primeiros meses de operaĂ§ĂŁo o negĂłcio foi replicado em novas unidades prĂłprias. \nEm cada uma das unidades pudemos comprovar a viabilidade do modelo de negĂłcios, nos deixando seguros de que poderĂ­amos entrar para o sistema de franchising, permitindo a formaĂ§ĂŁo de uma rede de sucesso. Com isso, em 2022 o PeggĂŽ Market desenvolveu o modelo com o maior mix de produtos do seguimento, a Ășnica empresa a fazer abastecimentos diĂĄrios, hoje estĂĄ presente em varios estados Brasil, dentro dos principais condomĂ­nios. Mas nĂŁo Ă© sĂł isso! Com toda a estrutura e suporte que nossa equipe fornece somos a Ășnica empresa que em toda nossa trajetĂłria mantemos uma taxa de churn em 0%, isso temos 100% de satisfaĂ§ĂŁo em todos os condominios atendidos. O que vocĂȘ estĂĄ esperando se juntar ao segmento que mais cresce no Brasil? Torne-se um franqueado do PeggĂŽ Market!', NULL, 'RIO DE JANEIRO', 1, NULL, 33, NULL, NULL, '2026-03-09 00:23:11.744', 'https://franquias.portaldofranchising.com.br/franquia-peggo-market/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
