INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76nm00j2eh0s9j6uco1d', 'MARY HELP', 'mary-help', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'ServiĂ§os de Limpeza', 'Agenciamento de diaristas, seleĂ§ĂŁo de mensalistas, terceirizaĂ§ĂŁo de mĂŁo de obra.', 2011, 2011, '[\"https://www.youtube.com/watch?v=4P6ObWojPps\"]', '2026-04-01 02:00:07.983', '2025-08-05 22:20:28.018', 723, NULL, 1, 2011, 'Como comeĂ§ou \nA Mary Help Ă© uma franquia que foi concebida em abril de 2011, idealizada por JosĂ© Roberto Campanelli e sua mulher. \nA motivaĂ§ĂŁo nasceu da constataĂ§ĂŁo da dificuldade de se conseguir contratar uma profissional diarista para trabalhar em sua residĂȘncia, Iogo apĂłs retornarem de uma viagem de fĂ©rias. EntĂŁo viu da dificuldade uma grande oportunidade de negĂłcio. A franquia iniciou suas atividades com uma unidade prĂłpria em 2011 no municĂ­pio de SĂŁo JosĂ© do Rio Preto, jĂĄ tendo sido concedida com a estratĂ©gia de se tornar, em pouco tempo, uma franquia nacional. \nA concepĂ§ĂŁo do negĂłcio foi baseada na constataĂ§ĂŁo da forte demanda atual no Brasil por serviĂ§os prestados em domicĂ­lios em todas as ĂĄreas, notadamente para os serviĂ§os ligados Ă Â  organizaĂ§ĂŁo, conservaĂ§ĂŁo e limpeza diĂĄria das residĂȘncias e pequenas empresas (escritĂłrios, clĂ­nicas, salĂ”es, lojas comerciais, etc).  Mary Help Pioneira no Brasil no seu modelo de negĂłcio \nA Mary Help inovou em 2011 ao agenciar uma equipe de diaristas preparadas em sua escola de capacitaĂ§ĂŁo para realizaĂ§ĂŁo de serviĂ§os de limpeza, faxina, lavar e passar roupas. Foi, portanto, uma proposta de negĂłcio inĂ©dita no Brasil, operando na forma de uma rede de empresas pelo sistema de franchising. O conceito inicial foi estendido e hoje a Mary Help atua desde o agenciamento de diaristas para diversas funĂ§Ă”es, recrutamento e seleĂ§ĂŁo de profissionais mensalistas (empregadas domĂ©sticas, babĂĄs, cuidadores de idosos, etc) e terceirizaĂ§ĂŁo de mĂŁo de obras em residĂȘncias e empresas.  MĂŁo de obra altamente qualificada \nA mĂŁo de obra selecionada e treinada para realizaĂ§ĂŁo de serviĂ§os representa um diferencial competitivo da Mary Help sobre as demais profissionais existentes no mercado. Isto Ă©, hĂĄ muito tempo ansiado pelas donas de casa que enfrentam a cada dia, com maior frequĂȘncia, a escassez no nĂșmero de empregadas domĂ©sticas mensalistas e sofrem com o despreparo das diaristas. A praticidade na contrataĂ§ĂŁo e a confianĂ§a percebida e valorizada pelos clientes Ă© a chave para o sucesso da franquia.  Mais 5 bons motivos para vocĂȘ fazer parte da Mary Help \n1 - Vasta gama de serviĂ§os. Nossos principais serviĂ§os sĂŁo: faxineira, lavadeira, passadeira, cozinheira, copeira, churrasqueiro, garĂ§om, babĂĄ, cuidador de idosos, processos seletivos, terceirizaĂ§ĂŁo de mĂŁo de obra, personal organizer, jardineiro, piscineiro, sanitizaĂ§ĂŁo de ambientes, limpeza e higienizaĂ§ĂŁo de estofados e tapetes. \n2 - Somos a rede do setor mais informatizada no momento. \n3 - Conquistamos pelo terceiroÂ ano consecutivo o seloÂ da ABF (AssociaĂ§ĂŁo Brasileira de Franchising) de excelĂȘncia em Franchising. \n4 -Â Em constante crescimento. JĂĄ somos mais de 160Â franquias pelo Brasil. \n5 - O modelo de negĂłcio Mary Help possui Ă­ndice de satisfaĂ§ĂŁo entre 9 e 10 dos nossos clientes. \nEntre em contato e saiba como para fazer parte do time de franqueados Mary Help. Bem-vindo (a)! \nMais informaĂ§Ă”es: www.maryhelp.com.br', NULL, 'SĂO PAULO', 1, NULL, 177, NULL, NULL, '2026-03-09 00:26:05.845', 'https://franquias.portaldofranchising.com.br/franquia-mary-help/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '40000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
