INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76oj00j8eh0sbaltvnlw', 'DOUTOR SOFĂ', 'doutor-sofa', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'ServiĂ§os de Limpeza', 'Limpeza e proteĂ§ĂŁo de estofados.', 2015, 2020, '[\"https://www.youtube.com/watch?v=MFaa8Pc-tRE\",\"https://www.youtube.com/watch?v=VPNzlcjvhkE\"]', '2026-04-01 02:00:08.046', '2025-08-05 22:20:28.051', 729, NULL, 1, 2014, 'Com presenĂ§a em mais de 1600 cidades em trĂȘs continentes, a Doutor SofĂĄ Ă© a maior rede de franquias de limpeza especializada de estofados do Mundo! A franquia, com sede em Joinville-SC, Ă© a Ășnica empresa do segmento Ă  receber os dois maiores reconhecimentos do franchising nacional, o Selo de ExcelĂȘncia em Franchising (ABF) e o PrĂȘmio 5 Estrelas da revista Pequenas Empresas Grandes NegĂłcios, sendo uma das franquias com maior satisfaĂ§ĂŁo de franqueados de todo Brasil! Atualmente a Marca estĂĄ presente em 25 estados brasileiros, com mais de 1 milhĂŁo de clientes atendidos! Com sistema prĂłprio de gestĂŁo, a Doutor SofĂĄ se destaca pela qualidade de seus serviĂ§os e pelo amplo suporte oferecido ao franqueado, que engloba todos os aspectos da gestĂŁo da franquia, desde a precificaĂ§ĂŁo dos serviĂ§os atĂ© o pĂłs-venda ao cliente, passando pelo marketing para prospecĂ§ĂŁo de clientes, que Ă© um grande diferencial da marca. AlĂ©m disso, os franqueados desfrutam de produtos exclusivos com marca prĂłpria, suporte completo na operaĂ§ĂŁo, forte presenĂ§a de Marketing Digital para prospecĂ§ĂŁo de seus clientes, e muito mais! A franquia tambĂ©m Ă© pioneira em oferecer uma plataforma de streaming prĂłpria aos seus franqueados, o SOFĂFLIX, possibilitando ao franqueado se capacitar com centenas de treinamentos em vĂ­deo para aprimoramento das operaĂ§Ă”es. Com baixo investimento inicial e baixo custo operacional (por nĂŁo exigir ponto comercial), a Doutor SofĂĄ se destaca como uma franquia com rĂĄpido retorno do investimento, em mĂ©dia de 06 a 12 meses!', NULL, 'SANTA CATARINA', 1, NULL, 164, NULL, NULL, '2026-03-09 00:29:26.683', 'https://franquias.portaldofranchising.com.br/franquia-doutor-sofa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '35000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76oo00j9eh0s5si6eq80', 'MINDS ENGLISH SCHOOL', 'minds-english-school', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Ensino de InglĂȘs com duraĂ§ĂŁo de apenas 18 meses. AlĂ©m do intensivo, com duraĂ§ĂŁo de um mĂȘs, no perĂ­odo de fĂ©rias', 2008, 2009, '[\"https://www.youtube.com/watch?v=C-0o_Ct8ctk\"]', '2026-04-01 02:00:08.056', '2025-08-05 22:20:28.056', 730, NULL, 1, 2007, 'Em 2007, a marca Minds English School que remete a mente/inteligĂȘncia Ă© criada. \nLeiza Oliveira e Augusto Jimenez inauguram a sua primeira unidade e com o lado humano, em cada etapa do aprendizado, atinge a marca de 1.000 alunos em menos de um ano. \nPor isso, em 2008, os sĂłcios enxergam que podem expandir a escola no sistema de franchising levando tecnologia em sinergiaÂ  com o processo de aprendizado de cada estudante. \nImplantaram as primeira lousas touch-screen, incluĂ­ram o conteĂșdo dos livros no tablet e uso dos board games (Jogos de tabuleiro) dentro e fora das salas de aula. \nTudo para tornar a fluĂȘncia do inglĂȘs mais orgĂąnico. \nA uniĂŁo entre a inovaĂ§ĂŁo e \"o olho no olho\" de cada estudante gerou uma expansĂŁo consciente e contĂ­nua em todo o paĂ­s. \nCom o curso regular flex, em que o aluno fica fluente no idioma em 18 meses e pode agendar as suas aulas, a marca atingiu mais de 50 unidades em 2016. \nEm 2017, a rede coloca em prĂĄtica o curso misto (50% online e 50% presencial) otimizando o tempo do estudante e possibilitando a inauguraĂ§ĂŁo de novas escolas em uma metragem mais compactaÂ  e em municĂ­pios menores. \nIndo alĂ©m dos grandes centros. Com essa nova aĂ§ĂŁo saltamos para mais de 70 escolas.Â  \nDe Junho a Dezembro de 2019, mais trĂȘs escolas foram inauguradas e o uso de gameficaĂ§ĂŁo fortaleceu. \nA Minds Idiomas Ă© a Ășnica rede de inglĂȘs com expansĂŁo consciente de atĂ© 10 unidades por ano. \nEm que hĂĄ o estudo para as novas franquiasÂ  a fim deÂ  alcanĂ§ar o pĂșblico correto para esse novo franqueado(a), gerar lucro e entregar realmente o aprendizado do inglĂȘs para os seus estudantes.', NULL, 'PARANĂ', 1, NULL, 52, NULL, NULL, '2026-03-09 00:30:20.862', 'https://franquias.portaldofranchising.com.br/franquia-minds-english-school-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
