INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76q600jgeh0sglhy5e00', 'TRADICIONAL BOLOS & TORTAS', 'tradicional-bolos-tortas', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Confeitaria especializada em produĂ§ĂŁo diĂĄria de bolos caseiros, sobremesas, pudins e bolos confeitados para festa e tortas salgadas.', 2012, 2015, NULL, '2026-04-01 02:00:08.117', '2025-08-05 22:20:28.110', 737, NULL, 1, 2011, 'A TRADICIONAL BOLOS E TORTAS surgiu no ano de 2011 como uma das pioneiras na Capital do Estado de SĂŁo Paulo. \nSua trajetĂłria vem seguido sempre do fator inovador de produtos aliado Ă  alta qualidade dos insumos, o que vem trazendo destaque em outras regiĂ”es do PaĂ­s tambĂ©m, tanto em cidades de interior como capitais, na qual o negĂłcio se torta muito bem quisto pela sociedade por onde se instala, com um prestĂ­gio inigualĂĄvel ao ponto de empresas de grande porte buscarem se aliar Ă  TRADICIONAL BOLOS E TORTAS com parcerias igualmente vencedoras.Â  Venha tambĂ©m fazer parte deste negĂłcio que nĂŁo Ă© comum de se encontrar e muito prazeroso para trazer resultados.', NULL, 'SĂO PAULO', 1, NULL, 38, NULL, NULL, '2026-03-09 00:33:49.142', 'https://franquias.portaldofranchising.com.br/franquia-tradicional-bolos-e-tortas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '240000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76qg00jheh0s90odr9jh', 'JAN-PRO', 'jan-pro', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'SERVIĂOS DE LIMPEZA', 'Franquia de serviĂ§os de limpeza e manutenĂ§ĂŁo de imĂłveis.', 1991, 2012, '[\"https://www.youtube.com/watch?v=dIUZDGuI2g4\",\"https://www.youtube.com/watch?v=USvAp1d2BoY\",\"https://www.youtube.com/watch?v=RIHv0p-nc6U\",\"https://www.youtube.com/watch?v=7IBHX1EJnlQ\"]', '2026-04-01 02:00:08.127', '2025-08-05 22:20:28.121', 738, NULL, 1, 1991, 'A franquia JAN-PRO foi criada em 1991, nos Estados Unidos. Hoje, atua em 15 paĂ­ses do mundo, com mais de 9.000 franqueados atendendo mais de 60.000 clientes. No Brasil desde 2011, atualmente tem 14 Franquias Regionais, que atuam como escritĂłrio de suporte e vendas de franquias nas cidades de SĂŁo Paulo, Rio de Janeiro, NiterĂłi, VitĂłria, Salvador, Recife, BelĂ©m, Manaus, Porto Velho, Belo Horizonte, TriĂąngulo Mineiro, Campinas, FlorianĂłpolis e Porto Alegre. Que atendem a mais de 300 Franqueados locais, que por sua vez atendem a mais de 1.000 clientes de manutenĂ§ĂŁo mensal. Sua equipe de gestĂŁo Ă© composta por profissionais com mais de 25 anos de experiĂȘncia no mercado de franquia e de limpeza, tendo participado da diretoria da ABF nos anos 90, bem como da fundaĂ§ĂŁo de outras entidades do segmento com ABRALIMP (AssociaĂ§ĂŁo Brasileira de Limpeza), ABRAFAC (AssociaĂ§ĂŁo Brasileira de Facilities), da FundaĂ§ĂŁo Lidio Nobuo que foi a primeira escola profissionalizante de faxineiros do Brasil. O Jeito JAN-PRO A JAN-PRO Ă© a maior franquia de limpeza comercial do mundo, e estĂĄ classificada como a dĂ©cima maior franquia americana. Presente no Brasil desde 2011 hoje Ă© uma das cinquenta maiores franquias brasileiras. E jĂĄ recebeu diversos prĂȘmios que comprovam sua formataĂ§ĂŁo, como os de excelĂȘncia da ABF, de Melhor Microfranquia e Melhor Franquia de Limpeza da PEGN, nos Ășltimos dois anos foi considerada uma das 25 melhores franquias brasileiras pela consultoria da Bittencourt, alĂ©m de estar em primeiro lugar entre as franquias Top10 do segmento de limpeza. Este sucesso todo ocorre pelo contĂ­nuo aperfeiĂ§oamento do modelo de franquia chamado de âDuas Camadasâ ou de Franquias Regionais. As franquias de limpeza sĂŁo consideradas no mundo todo como as precursoras do modelo de franquia de baixo investimento, que com sucesso em todos os paĂ­ses que Ă© implantado acaba fomentando quase todos os outros modelos de franquia. A JAN-PRO conseguiu unir o modelo de baixo investimento com o de alto investimento, promovendo a oportunidade de todos os tipos de investidores virem a ser seu franqueado. Assim, um investidor com experiĂȘncia empresarial e capital disponĂ­vel poderĂĄ comprar um territĂłrio para implementar a franquia JAN-PRO. Desenvolvendo todo o marketing necessĂĄrio para atrair novos clientes de serviĂ§os de limpeza, e ao mesmo tempo montando uma central de serviĂ§os para dar suporte aos futuros Franqueados Locais que passarĂŁo a aderir Ă  franquia nesta regiĂŁo. Estes Franqueados Locais irĂŁo comprar do Franqueado Regional o direito de operar a franquia de limpeza JAN-PRO e receberĂŁo como seguranĂ§a para seu sucesso um cliente realmente garantido atĂ© quatro meses depois de treinado, num valor proporcional ao investimento inicial feito de acordo a um dos 19 planos de franquia que existem disponĂ­veis no Brasil, o que lhe darĂĄ um retorno em menos de 18 meses. Franquia Locais Os franqueados Locais foram divididos em 3 categorias de acordo o grau de envolvimento com a operaĂ§ĂŁo dos serviĂ§os prestados. Microfranqueadores: os que vĂŁo executar os serviĂ§os por conta prĂłpria, que vĂŁo por a mĂŁo na massa. Eles fazem o menor investimento que existe hoje no mercado brasileiro de franquia. Franqueados Gerenciais: os que vĂŁo executar os serviĂ§os junto a uma equipe de atĂ© 10 auxiliares de serviĂ§os gerais. Realizam um investimento maior que o anterior, mas ainda assim menor que a mĂ©dia das franquias brasileiras. Franqueados Empresariais: a Ășltima categoria foi criada para atender Ă quela pessoa que irĂĄ coordenar duas ou mais equipes de limpeza em clientes diferentes, transformando-se no que hoje em dia se chama Multifranqueados. O investimento Ă© equivalente Ă  mĂ©dia do mercado brasileiro. Estes quatro formatos de franquia possibilitam que qualquer pessoa possa vir a ser franqueado da JAN-PRO, gerando uma flexibilidade enorme que gera tambĂ©m crescimento para a rede. Desta forma, o Franqueado Regional fica focado na obtenĂ§ĂŁo de novos contratos de limpeza (gerando demanda) e os Franqueados Locais ficam focados na prestaĂ§ĂŁo dos serviĂ§os de limpeza (atendendo a demanda). Existem dezenas de casos de franqueados que iniciaram com contratos garantidos entre R$ 3.500,0 e R$ 9.000,00 e que depois de trĂȘs anos faturam mais de R$ 100.000,00 mensais. Valores de investimento das franquias Master Franquia Taxa Inicial: R$ 240.000,00 Montagem EscritĂłrio: R$ 40.000,00 Capital de Giro: R$ 120.000,00 Faturamento MĂ©dio: R$ 1 milhĂŁo Microfranquia Taxa Inicial: R$ 20.500 (podendo ser financiada em atĂ© 36 meses) Montagem EscritĂłrio: 0 (porque Ă© Home-Based) Capital de Giro: R$ 2.500,00 Faturamento Garantido inicial: R$ 36.000,00 Faturamento MĂ©dio: R$ 120.000,00 Franquia Gerencial Taxa Inicial: R$ 49.950,00 (podendo ser financiada em atĂ© 36 meses) Montagem EscritĂłrio: 0 (porque Ă© Home-Based) Capital de Giro: R$ 5.500,00 Faturamento Garantido Inicial: R$ 144.000,00 Faturamento MĂ©dio: R$ 250.000,00 Franquia Empresarial Taxa Inicial: R$ 92.000,00 (podendo ser financiada em atĂ© 36 meses) Montagem EscritĂłrio: 0 (porque Ă© Home-Based) Capital de Giro: R$ 12.500,00 Faturamento Garantido Inicial: R$ 360.000 Faturamento MĂ©dio: R$ 1.000.000,00 Agora o mais importante Ă© saber que vocĂȘ pode comeĂ§ar no primeiro modelo e com o tempo ir avanĂ§ando para os outros. JĂĄ temos casos, atĂ© no Brasil, de franqueados que comeĂ§aram como Microfranqueados e que hoje sĂŁo Franqueados Regionais.', NULL, 'SĂO PAULO', 1, NULL, 175, NULL, NULL, '2025-09-03 09:21:08.000', 'https://franquias.portaldofranchising.com.br/franquia-jan-pro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76qv00jjeh0s7j27g898', 'ACADEMIA DE INGLĂS WASHINGTON', 'academia-de-ingles-washington', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escolas de Ensino Especializadas em InglĂȘs.', 2015, 2016, '[\"https://www.youtube.com/watch?v=s3dqz7rPX9o\"]', '2026-04-01 02:00:08.137', '2025-08-05 22:20:28.135', 740, '88b24c4c-9be7-41a4-a01c-02f7e7ac9801', 1, 2008, 'A Academia de InglĂȘs Washington nasce em 1963 quando o professor Luis OctĂĄvio da Costa chega ao Brasil vindo da Ăndia. \nO sonho de disseminar educaĂ§ĂŁo e cultura para alunos em todo o paĂ­s tornou-se realidade com a fundaĂ§ĂŁo da primeira Academia de InglĂȘs Washington na cidade de Arapongas-PR. \nA rede foi conquistando seu espaĂ§o, priorizando relaĂ§Ă”es duradouras e pautadas no respeito com seus parceiros. \nHoje conta com unidades espalhadas por todo o Brasil que utilizam sua metodologia, os materiais didĂĄticos e os processos de gestĂŁo. \nA rede segue em plena expansĂŁo, focada em oferecer um modelo de negĂłcio que combina qualidade de ensino com especializaĂ§ĂŁo na lĂ­ngua inglesa, custos enxutos e alta rentabilidade. Em 2008, Siddhartha Octavio da Costa, filho do fundador, iniciou a expansĂŁo da marca atravĂ©s do modelo de licenciamento, onde a metodologia e material didĂĄtico eram ofertados fundamentalmente para professores que tinham o sonho de empreender. \nEm 2015, a expansĂŁo passa a acontecer atravĂ©s do sistema defranchising, oferecendo aos seus parceiros um suporte completo para a gestĂŁo das unidades da rede. AlĂ©m da metodologia de ensino e materiais didĂĄticos exclusivos, o franqueado conta com um amparo que incluisoftwareÂ de gestĂŁo especializado, treinamentos presenciais e EAD. \nTambĂ©m sĂŁo oferecidas aĂ§Ă”es comerciais e campanhas deÂ marketingÂ exclusivas, totalmente direcionadas para a comunidade onde a escola estĂĄ inserida. Ao mesmo tempo em que valoriza e preza pela tradiĂ§ĂŁo de 55 anos dando novas oportunidades para as pessoas atravĂ©s do ensino da lĂ­ngua inglesa, a Academia de InglĂȘs Washington sabe que Ă© necessĂĄrio renovar-se constantemente para acompanhar as tendĂȘncias do mercado. \nĂ por isto que o material didĂĄtico conta com tecnologias de realidade aumentada e virtual para proporcionar aos seus alunos a melhor experiĂȘncia possĂ­vel de aprendizado, alĂ©m da plataforma interativa Washington Web, que permite complementar o que Ă© visto na sala de aula atravĂ©s da tela do celular. \nTradiĂ§ĂŁo e modernidade andando juntas Ă© uma prioridade da instituiĂ§ĂŁo. Â  As franquias da Academia de InglĂȘs Washington representam uma opĂ§ĂŁo com baixo investimento, rĂĄpido retorno e lucratividade lĂ­quida de 40%, sem restriĂ§Ă”es geogrĂĄficas de mercado. \nO modelo se adapta a cidades de pequeno, mĂ©dio e grande porte, tornando-se uma Ăłtima opĂ§ĂŁo nĂŁo apenas para professores, mas tambĂ©m para qualquer empreendedor que procura uma boa opĂ§ĂŁo de investimento. \nEm sua primeira participaĂ§ĂŁo no ranking Guia de Franquias da revista Pequenas Empresas Grandes NegĂłcios obteve o 8Â° lugar no segmento Ensino de Idiomas, ficando a frente de grandes nomes deste mercado. Entre em contato com nossa equipe de expansĂŁo para iniciarmos uma parceria de sucesso!', NULL, 'PARANĂ', 1, NULL, 53, NULL, NULL, '2026-03-09 00:40:14.409', 'https://franquias.portaldofranchising.com.br/franquia-academia-de-ingles-washington-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76r400jkeh0sa6garcbu', 'TUTORES', 'tutores', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Transforme vidas atravĂ©s da educaĂ§ĂŁo: reforĂ§o escolar, aulas particulares, tutorias, apoio escolar, preparaĂ§ĂŁo para Enem e vestibulares.', 2008, 2008, '[\"https://www.youtube.com/watch?v=pMSU2m4T9zI\",\"https://www.youtube.com/watch?v=f4Ec2kd-A5c\",\"https://www.youtube.com/watch?v=YmwHDFGKa1Y\"]', '2026-04-01 02:00:08.146', '2025-08-05 22:20:28.144', 741, NULL, 1, 2007, 'ServiĂ§os oferecidos Acompanhamento escolar ReforĂ§o Escolar Acompanhamento da liĂ§ĂŁo de casa PreparaĂ§ĂŁo para avaliaĂ§Ă”es escolares Acompanhamento do dever de casaÂ  Aula particular PreparaĂ§ĂŁo para prestar vestibulares PreparaĂ§ĂŁo para as provas do Enem Cursos para Acelerar a Aprendizagem Programa de EstimulaĂ§ĂŁo Cognitiva Quem sĂŁo nossos clientes Alunos da EducaĂ§ĂŁo infantil Alunos do Ensino fundamental: 1Âș ao 9Âș ano Alunos do Ensino mĂ©dio: 1Âș ao 3Âș ano MĂ©todo Mais que um mĂ©todo, a Tutores Ă© uma filosofia de educaĂ§ĂŁo que proporciona benefĂ­cios reais para os alunos. Nossa abordagem pedagĂłgica enfatiza ensinar a aprender, fortalecendo o potencial de aprendizado de cada aluno e os incentivando Ă  independĂȘncia nos estudos.Â  Modalidades de Franquia Na Tutores, vocĂȘ pode escolher a modalidades de negĂłcio que melhor se encaixa na sua realidade: Home Based: a operaĂ§ĂŁo da franquia Ă© realizada no conforto de seu lar, sem necessidade de locaĂ§ĂŁo de um ponto comercial. Os alunos sĂŁo atendidos pelos tutores em suas residĂȘncias e em clubes, condomĂ­nios, escolas etc. Ponto Comercial: com uma unidade fĂ­sica, vocĂȘ terĂĄ a possibilidade de atuar nĂŁo sĂł nas residĂȘncias dos alunos, mas tambĂ©m em seu ponto comercial, o que pode permite atender maior nĂșmero de alunos e, consequentemente, obter maiores rendimentos. Os alunos podem ser atendidos nas seguintes modalidades: VIP: aulas individuais Flex: aulas em gruposÂ  Os Fundadores Nossa experiĂȘncia de 16 anos de franquia Ă© respaldada pela visĂŁo empreendedora dos sĂłcios-fundadores da Tutores.Â  Artur HipĂłlito Ă© fundador da rede Home Angels, a maior franquia de cuidadores de pessoas da AmĂ©rica Latina, pioneira no ramo, com mais de 170 unidades e 110.000 clientes atendidos no paĂ­s. Sua expertise como gestor garante suporte sĂłlido e eficaz para os franqueados da Tutores. LĂ©a Bueno criou e desenvolveu sistemas educacionais de ensino de idiomas e produziu material didĂĄtico para o Ensino Fundamental e Cursos Profissionalizantes. Suas pesquisas e visitas Ă s principais empresas do setor de franquias de tutoria nos Estados Unidos a posicionam como uma fonte de conhecimento valioso, trazendo as melhores prĂĄticas internacionais para a rede.', NULL, 'SĂO PAULO', 1, NULL, 20, NULL, NULL, '2026-03-09 00:41:42.151', 'https://franquias.portaldofranchising.com.br/franquia-tutores-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76r900jleh0scd129chz', 'HYPERLOCAL', 'hyperlocal', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'Franquia de tecnologia, com produtos de alto valor agregado para todo o varejo local. Pense grande: Aja local, seja Hyperlocal.', 2018, 2019, '[\"https://www.youtube.com/watch?v=s31gRb-l6wk\",\"https://www.youtube.com/watch?v=d1rmF1KbLRo\",\"https://www.youtube.com/watch?v=yVM-noW8EzU\"]', '2026-04-01 02:00:08.157', '2025-08-05 22:20:28.150', 742, NULL, 1, 2013, 'A franquia Hyperlocal nasceu em 2018 quando ainda era Avec e os seus franqueados comercializavam apenas essa soluĂ§ĂŁo focada em beleza e bem estar. Em 2021, a partir de investimentos de fundos internacionais, a Avec adquiriu outros produtos, possibilitando aos franqueados aumentar seu leque de soluĂ§Ă”es para o comĂ©rcio local. Assim nos tornamos Hyperlocal Franquias. Nosso franqueado pode atuar em todo o ecossistema de estabelecimentos locais, o que possibilita e facilita a geraĂ§ĂŁo de networking, gerando valor para todo esse ecossistema. Nossos principais diferenciais: Software de gestĂŁo com alto valor agregado e preĂ§o acessĂ­vel; possibilidade de investimento baixo custo, receita recorrente, franquia home based e tecnologia de gestĂŁo totalmente integrada com meio de pagamento.', NULL, 'SANTA CATARINA', 1, NULL, 32, NULL, NULL, '2025-09-01 16:43:18.000', 'https://franquias.portaldofranchising.com.br/franquia-hyperlocal/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
