 NULL, NULL, '2026-03-09 00:44:06.276', 'https://franquias.portaldofranchising.com.br/franquia-rede-autoriza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '14490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
