INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76sj00jueh0sprkyrnyr', 'DROGARIAS MAX', 'drogarias-max', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'FarmĂĄcias e Drogarias', 1989, 2000, '[\"https://www.youtube.com/watch?v=ianBqNcQkkM\"]', '2026-04-01 02:00:08.245', '2025-08-05 22:20:28.196', 751, NULL, 1, 1983, 'Fundada em 1980, a rede Drogarias Max Ă© a primeira franquia de farmĂĄcias do Brasil associada Ă  AssociaĂ§ĂŁo Brasileira de Franchising (ABF). Atualmente, sĂŁo 128 lojas franqueadas em todo o Estado do Rio de Janeiro, que juntas faturam, em mĂ©dia, R$ 29 milhĂ”es por mĂȘs.Â  \nA Drogarias Max atua no mercado varejista farmacĂȘutico como franquia de conversĂŁo para empresĂĄrios independentes que buscam apoio para uma gestĂŁo estruturada e uma estratĂ©gia comercial eficaz de rentabilidade. \nHĂĄ duas formas de adesĂŁo: Selo Max e Bandeira Max.Â  \nPrincipais serviĂ§os oferecidos aos franqueados:Â  \n- CondiĂ§Ă”es comerciais negociadas pela franqueadora;\n- Material de marketing;\n- Central de compras com aplicativo prĂłprio;\n- NegociaĂ§ĂŁo centralizada de taxas de cartĂŁo de crĂ©dito e dĂ©bito;\n- Indicadores de gestĂŁo e performance da drogaria;\n- 30mil clientes ativos pelo ConvĂȘnio Empresas com desconto em folha;\n- Simulador para definiĂ§ĂŁo de metas;\n- Apoio nas polĂ­ticas de precificaĂ§ĂŁo;\n- Acesso a linhas de crĂ©dito;\n- Assessoria jurĂ­dica;\n- CaptaĂ§ĂŁo de pedidos para a loja por meio do NĂșmero Ănico;\n- Manual de operaĂ§ĂŁo de loja. A rede Drogarias Max Ă© a Ășnica franquia do setor no Estado do Rio de Janeiro a fazer parte do ranking das dez marcas de farmĂĄcia mais lembradas pelos cariocas em 2020, de acordo com ranking do jornal O Globo. Desde 2014, conquista consecutivamente o PrĂȘmio ExcelĂȘncia em Franchising, concedido pela ABF.', NULL, 'RIO DE JANEIRO', 1, NULL, 138, NULL, NULL, '2026-03-09 00:45:48.619', 'https://franquias.portaldofranchising.com.br/franquia-drogarias-max/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
