INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76su00jweh0s21ek4wnw', 'MORMAII FITNESS', 'mormaii-fitness', NULL, 'SaĂșde, Beleza e Bem Estar', 'ESPORTE E RECREAĂĂO', 'Franquia Studio Mormaii, com metodologia prĂłpria e exclusiva de treinamento fĂ­sico.', 2015, 1990, '[\"https://www.youtube.com/watch?v=gPz1i6bxKFg\",\"https://www.youtube.com/watch?v=6Y66LjFJXFQ\",\"https://www.youtube.com/watch?v=JF2_mkfP12I\"]', '2026-04-01 02:00:08.266', '2025-08-05 22:20:28.206', 753, NULL, 1, 2013, 'A Mormaii Ă© uma empresa originalmente brasileira e democrĂĄtica que, acaba de completar 40 anos de histĂłria, tem como principal premissa proporcionar qualidade de vida Ă s pessoas. Com raĂ­zes no mundo do surf e pioneirismo na fabricaĂ§ĂŁo das reconhecidas roupas de neoprene, hoje a marca transcende esse universo e se insere nas mais diversas categorias esportivas. NĂŁo seria por acaso que a Mormaii Ă© considerada a maior e mais querida marca de esportes livres do Brasil, entregando aos seus consumidores e fĂŁs mais de 5 mil itens que tangibilizam a promessa da marca. Seguindo por esse caminho e ampliando ainda a sua participaĂ§ĂŁo no mercado, a empresa desenvolveu o projeto Mormaii Fitness em 2012. O objetivo: melhorar o desempenho esportivo e a capacidade fĂ­sica das pessoas e proporcionar a melhor experiĂȘncia, sejam elas atletas profissionais ou iniciantes, que estĂŁo Ă  procura de opĂ§Ă”es diferenciadas e dinĂąmicas de exercĂ­cios fĂ­sicos. Para isso, lanĂ§ou uma metodologia exclusiva de treinamento, o MĂ©todo Integrado Mormaii Fitness, que consiste em quatro pilares reunindo os movimentos do pilates, treinamento funcional e cardio, associados ao Five Konzept, uma tĂ©cnica alemĂŁ trazida exclusivamente pela Mormaii para o Brasil. AtravĂ©s de nosso treinamento fĂ­sico, ajudamos na melhora da performance de atletas, nĂŁo atletas e de todos que desejam alcanĂ§ar seus objetivos com mais saĂșde. JĂĄ sĂŁo mais de 40 franquias espalhadas pelo Brasil. Invista agora em um negĂłcio com propĂłsito. Queremos levar para sua vida o estilo de vida que transpiramos dentro do Studio Mormaii.', NULL, 'SANTA CATARINA', 1, NULL, 52, NULL, NULL, '2025-08-07 11:33:56.000', 'https://franquias.portaldofranchising.com.br/franquia-mormaii-fitness/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
