INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76t900jzeh0shqmfkmcn', 'LOFT', 'loft', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'Tecnologia e EletrĂŽnicos', 'A Loft Ă© uma marca onde o conceito de design Ă© uma paixĂŁo! SĂŁo mais de 1.000 produtos desenvolvidos internamente, e de forma exclusiva com a marca LOFT, a partir do estudo de tendĂȘncias mundiais.', 2013, 2015, NULL, '2026-04-01 02:00:08.299', '2025-08-05 22:20:28.222', 756, NULL, 1, 2010, 'A marca Loft foi criada para atender a um pĂșblico exigente e ligado em Design. A Loft acredita que o Design e a inovaĂ§ĂŁo fazem toda diferenĂ§a na vida das pessoas e refletem um comportamento, um jeito de ser, de agir e de pensar. Por isso, a marca desenvolveu mais de 1500 itens com design exclusivo, alĂ©m de ter foco na inovaĂ§ĂŁo e em produtos eletrĂŽnicos e acessĂłrios para smartphones e informĂĄtica. Com a abertura de sua primeira unidade em 2013, a franquia LOFT se faz presente em 9 estados brasileiros, com 48 pontos de vendas localizados em shoppings, ruas de referĂȘncia e aeroportos.  Posicionamento da marca: \nA empresa carrega o slogan âI Loft Designâ, que reforĂ§a a importĂąncia do conceito de design dos seus produtos e o desejo de ser uma marca que agrega conceito e estilo de vida. A marca preza por produtos de qualidade e sempre estĂĄ atenta a novas oportunidades, a busca incessante por novidades passa por um time de desenvolvimento de produtos que participa das principais feiras de tecnologia do mundo buscando as principais tendĂȘncias de mercado no segmento de design e tecnologia.  REGIĂES DE INTERESSE \nVeja abaixo as regiĂ”es que possuem oportunidades para a abertura de novos pontos de venda e entre em contato conosco para maiores informaĂ§Ă”es.\nÂ \nâą Sudeste: SP, RJ, MG, ES\nâą Centro - Oeste: GO, DF, MT, MS\nâą Nordeste: AL, BA, MA, CE, PB, PE, PI, RN, SE\nâą AC, AM, AP, PA, RO, RR, TO\nâą Sul: PR, RS, SC', NULL, 'SANTA CATARINA', 1, NULL, 39, NULL, NULL, '2026-03-09 00:57:38.748', 'https://franquias.portaldofranchising.com.br/franquia-loft-comunicacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '195000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
