INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76tj00k1eh0sp5pqn2eu', 'MIKRO MARKET', 'mikro-market', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Rede de mercados autĂŽnomos em condomĂ­nios residenciais e empresariais.', 2023, 2023, NULL, '2026-04-01 02:00:08.320', '2025-08-05 22:20:28.231', 758, NULL, 1, 2021, 'Por que a Mikro Market Ă© a Escolha Certa para VocĂȘ? A Mikro Market nĂŁo Ă© apenas um minimercado; Ă© uma revoluĂ§ĂŁo em conveniĂȘncia autĂŽnoma, operando 24 horas por dia, 7 dias por semana. Com tecnologia de ponta, levamos a praticidade diretamente para a vida das pessoas em: CondomĂ­nios residenciais e comerciais; Empresas; HotĂ©is; EstaĂ§Ă”es de metrĂŽ; Shoppings; E qualquer outro local estratĂ©gico onde a conveniĂȘncia faz a diferenĂ§a! Eliminamos filas e a necessidade de atendentes, construindo um modelo baseado em confianĂ§a mĂștua e agilidade. Nossa plataforma estĂĄ em constante evoluĂ§ĂŁo, oferecendo nĂŁo apenas produtos essenciais, mas tambĂ©m serviĂ§os e funcionalidades que simplificam o dia a dia de milhares de clientes. BenefĂ­cios IrresistĂ­veis de Ser um Franqueado Mikro Market: Modelo de NegĂłcio Inovador: Opere minimercados autĂŽnomos com alta demanda e baixos custos operacionais. O Maior Faturamento do Segmento: Invista com quem sabe e tenha o maior faturamento do segmento em sua unidade Tecnologia de Ponta: Tenha acesso a soluĂ§Ă”es robustas para gestĂŁo, estoque e experiĂȘncia do cliente. Mercado em ExpansĂŁo Acelerada: Posicione-se em um segmento em franco crescimento, impulsionado pela busca por praticidade. Retorno Comprovado: Veja seu investimento gerar frutos em tempo recorde, a partir de apenas 6 meses. Suporte 360Âș: Receba assessoria completa, desde a escolha do ponto atĂ© a gestĂŁo diĂĄria da sua operaĂ§ĂŁo. Nossa Jornada de Sucesso: Crescimento e InovaĂ§ĂŁo A Mikro Market nĂŁo para de crescer e inovar. Veja nossa trajetĂłria: 2021: O InĂ­cio da RevoluĂ§ĂŁo: LanĂ§amos nossa primeira operaĂ§ĂŁo prĂłpria no Rio de Janeiro, pavimentando o caminho para a inovaĂ§ĂŁo no varejo autĂŽnomo. 2022: Franquia de Sucesso: ApĂłs mais de um ano de intenso trabalho, formatamos nosso modelo de franquia, garantindo seguranĂ§a e mĂĄxima rentabilidade para nossos parceiros. 2023: Reconhecimento da ABF: Orgulhosamente nos tornamos associados da ABF (AssociaĂ§ĂŁo Brasileira de Franchising), confirmando nosso compromisso com prĂĄticas de gestĂŁo rigorosas, inovaĂ§ĂŁo contĂ­nua e a excelĂȘncia da nossa rede. 2024: LideranĂ§a no Rio de Janeiro: Conquistamos a lideranĂ§a estadual como a marca com maior nĂșmeros de operaĂ§ĂŁo somente no Rio de Janeiro, consolidando-nos como referĂȘncia absoluta no segmento. 2025: ExpansĂŁo Nacional e Novas Fronteiras: Nosso foco agora Ă© a expansĂŁo por todo o Brasil e o lanĂ§amento de novidades que impulsionam ainda mais o sucesso do franqueado:Â \n\tMikro Academy: Uma plataforma de ensino completa, guiando vocĂȘ da prospecĂ§ĂŁo de pontos atĂ© a gestĂŁo diĂĄria da sua operaĂ§ĂŁo. Mikro Media: Uma inovadora vertical de retail media para ativaĂ§Ă”es no ponto de venda, gerando mais rentabilidade para vocĂȘ e benefĂ­cios exclusivos para seus clientes.', NULL, 'RIO DE JANEIRO', 1, NULL, 90, NULL, NULL, '2026-03-09 00:58:58.094', 'https://franquias.portaldofranchising.com.br/franquia-mikro-market-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76to00k2eh0su25rxqn7', 'REPINTE', 'repinte', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'Empresa prestadora de serviĂ§os, especializada em RestauraĂ§ĂŁo Predial, que tĂȘm como propĂłsito elevar o patamar dessa prestaĂ§ĂŁo de serviĂ§os em todo paĂ­s. Os Pilares sĂŁo TransparĂȘncia, Ătica e ExcelĂȘncia', 2021, 2023, '[\"https://www.youtube.com/watch?v=G1VACFAyLzQ\"]', '2026-04-01 02:00:08.331', '2025-08-05 22:20:28.236', 759, NULL, 1, 2001, 'Fundada em 2001 pelo Eng. Paulo SĂ©rgio Ramalho (profissional atuante no segmento desde 1991), a Repinte Ă© uma referĂȘncia no mercado de restauraĂ§ĂŁo predial. Com mais de 20 anos de atuaĂ§ĂŁo, mais de 2000 obras executadas, diversas certificaĂ§Ă”es, premiaĂ§Ă”es e cursos, conta hoje com mais de 100 colaboradores na sua estrutura. E assim, uma vez testado e consolidado o negĂłcio, a REPINTE resolveu, nos primeiros meses de 2022, iniciar seu projeto de expansĂŁo por meio de franquias. Dessa forma a REPINTE se traduz em um excelente negĂłcio de investimento, pautada na boa fĂ©, Ă©tica e na prestaĂ§ĂŁo de serviĂ§os com elevada qualidade. Ingressando na Rede de Franquias REPINTE, que jĂĄ Ă© uma marca com excelente reputaĂ§ĂŁo e projeĂ§ĂŁo nas mĂ­dias sociais, alĂ©m de um negĂłcio com excelentes perspectivas, vocĂȘ tambĂ©m pode fazer parte dessa histĂłria de sucesso, pois a Franqueadora, com seu plano de expansĂŁo por meio de franquias, abre oportunidades para quem deseja crescer junto com a empresa.', NULL, 'SĂO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-09 01:00:35.516', 'https://franquias.portaldofranchising.com.br/franquia-repinte-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
