INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ty00k4eh0srredwoke', 'ORALJET', 'oraljet', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'Irrigadores Orais e Higiene Oral', 2019, 2019, NULL, '2026-04-01 02:00:08.352', '2025-08-05 22:20:28.246', 761, NULL, 1, 2015, '', NULL, 'SĂO PAULO', 1, NULL, 3, NULL, NULL, '2026-03-09 01:01:48.268', 'https://franquias.portaldofranchising.com.br/franquia-oraljet-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76u300k5eh0sttpj8610', 'HERING STORE', 'hering-store', NULL, 'Moda', 'VestuĂĄrios', 'VESTUĂRIO E ACESSĂRIOS', 1993, 1992, '[\"https://www.youtube.com/watch?v=wyYyfF-GBjA\"]', '2026-04-01 02:00:08.362', '2025-08-05 22:20:28.251', 762, NULL, 1, 1880, 'Fundada hĂĄ quase 140 anos, nossa histĂłria teve inĂ­cio a partir da determinaĂ§ĂŁo de dois irmĂŁos alemĂŁes que decidiram encarar o desafio de empreender no Brasil. Instalados em Blumenau/SC, eles vivenciaram as dificuldades de quem deseja empreender em um local de condiĂ§Ă”es precĂĄrias, em que faltava quase tudo, a comeĂ§ar pela matĂ©ria-prima. \nMas nada foi motivo ou entrave para demovĂȘ-los de seu projeto. A ousadia e o espĂ­rito empreendedor tambĂ©m tĂȘm caracterizado todas as geraĂ§Ă”es e todos os colaboradores que, ao longo dos anos vem transformando a Cia. Hering em uma das maiores empresas de design de vestuĂĄrio do Brasil. A Hering, uma das marcas da Cia., tornou-se uma das mais queridas e conhecidas marcas dos brasileiros, que atĂ© hoje Ă© simbolizada pelos \"peixinhos\". \nJĂĄ largamente reconhecida por nossa atuaĂ§ĂŁo na indĂșstria, em 1993 iniciamos a nossa operaĂ§ĂŁo no varejo com a primeira loja prĂłpria, encontrando assim, uma forma de entender melhor e mais rapidamente os anseios de nossos consumidores. LanĂ§amos logo em seguida a primeira loja no modelo de franquia e tambĂ©m as marcas PUC e Hering Kids e com isso, iniciamos nossa trajetĂłria de expansĂŁo, ampliando a atuaĂ§ĂŁo no mercado nacional e internacional.Â  \nHoje somos a maior rede de franquias de vestuĂĄrio do Brasil, reconhecida por mais de 90% dos brasileiros. ConstruĂ­mos hĂĄ mais de 25 anos um modelo bem-sucedido de franquias e estamos presentes em todo o Brasil, alĂ©m da atuaĂ§ĂŁo internacional com mais de 20 franquias na AmĂ©rica Latina.  Diferenciais \n- Marca com tradiĂ§ĂŁo e qualidade reconhecidas\n- Forte know-how no desenvolvimento de franquias\n- Credibilidade transmitida ao pĂșblico consumidor\n- Desenvolvimento de franquias com abordagem sĂ©ria, apoiada numa estrutura sĂłlida e com comprovada presenĂ§a no mercado\n- Grande estrutura de suporte ao franqueado\n- Marca internacionalmente reconhecida\n- Qualidade premium  CIA. HERING \nTemos orgulho em dizer que estamos em constante inovaĂ§ĂŁo e evoluĂ§ĂŁo hĂĄ mais de 135 anos.Â  \nSomos uma organizaĂ§ĂŁo multimarca no lifestyle casual com forte diferencial de produto. Nossa estrutura garante velocidade na produĂ§ĂŁo e distribuiĂ§ĂŁo das nossas coleĂ§Ă”es. \nFazemos gestĂŁo marcas, sabemos o que produzir e entregar, porque conhecemos nossos consumidores. \nPossuĂ­mos um modelo hĂ­brido de produĂ§ĂŁo. Contamos com fabricaĂ§ĂŁo prĂłpria, terceirizaĂ§ĂŁo de etapas produtivas e outsourcing.Â  \nHoje, somos quem somos porque atuamos em uma grande rede. Estamos em todo o Brasil e levamos nosso DNA casual tambĂ©m para a AmĂ©rica Latina. Vivemos o presente com a leveza de saber quem somos e comprometidos com tudo o que acreditamos.  Vem empreender com a gente!', NULL, 'SĂO PAULO', 1, NULL, 687, NULL, NULL, '2026-03-09 01:02:11.441', 'https://franquias.portaldofranchising.com.br/franquia-hering-store-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '260000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76u800k6eh0s217cp899', 'DERMAGE', 'dermage', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'DermocosmĂ©ticos', 1995, 1995, '[\"https://www.youtube.com/watch?v=l60FKogvTMw\"]', '2026-04-01 02:00:08.371', '2025-08-05 22:20:28.256', 763, NULL, 1, 1990, 'DERMAGE: UM SONHO DE MĂE PARA FILHA Duas jovens de espĂ­rito empreendedor. Duas histĂłrias que se misturam: mĂŁe e filha. Uma farmĂĄcia e uma crianĂ§a que nasceram juntas, cresceram e se transformaram. Uma marca brasileira feita por mulheres fortes com histĂłrias de sucesso para contar. Esta Ă© a Dermage. Lisabeth Braun era funcionĂĄria pĂșblica no fim dos anos 1970. Tinha uma vida estĂĄvel pela frente, mas o espĂ­rito empreendedor de Lisa e uma visita a uma farmĂĄcia de manipulaĂ§ĂŁo em Buenos Aires deram o clique para mudar sua perspectiva. Aos 30 anos ela percebeu ali uma oportunidade. Largou o emprego e vendeu seu Fusca para investir em um tipo de negĂłcio que atĂ© entĂŁo nĂŁo existia no Rio de Janeiro. âQuem Ă© o homem por trĂĄs da empresa?â era a pergunta que costumava ouvir. Com filhos pequenos e todas as incertezas de um novo business, Lisa trocou o certo pelo duvidoso e sabia que era preciso forĂ§a e coragem para seguir seu sonho num universo predominantemente masculino. Assumia todas as funĂ§Ă”es: das fĂłrmulas e do financeiro aos pedidos no balcĂŁo da lojinha que montou em Copacabana. Ganhou a confianĂ§a da classe mĂ©dica com seus produtos de excelĂȘncia. A demanda era tanta que, em 1990, Lisa percebeu uma nova oportunidade: por que nĂŁo industrializar as fĂłrmulas mais pedidas? Um novo comeĂ§o, novos desafios. Assim surgiu a Dermage, marca de dermocosmĂ©ticos, dando um passo alĂ©m da manipulaĂ§ĂŁo de fĂłrmulas. Enquanto tudo isto acontecia, Ilana Braun, sua filha, seguia por caminhos diferentes. AtĂ© que um dia, trabalhando no mercado financeiro, decidiu usar suas fĂ©rias para uma imersĂŁo na empresa da mĂŁe. Depois de dez dias e muitas memĂłrias afetivas da infĂąncia reativadas, ela decidiu largar tudo para embarcar no negĂłcio familiar. Era o que faltava. A uniĂŁo das forĂ§as de mĂŁe e filha se juntou Ă  experiĂȘncia em produtos com a perspicĂĄcia para o business, tĂ­pica dos jovens empreendedores. E assim veio a expansĂŁo a passos largos. Todos os produtos sĂŁo desenvolvidos com ativos de alta eficĂĄcia, sem testes em animais, resultado de extensas pesquisas, com eficĂĄcia comprovada para a pele brasileira e fĂłrmulas premiadas. O know-how daquela jovem que conquistou cada indicaĂ§ĂŁo dos mĂ©dicos no Rio de Janeiro nos anos 1980 se transformou em algo maior, e as indicaĂ§Ă”es profissionais se espalharam por todo o Brasil. De uma pequena sala em Copacabana para 60 lojas no paĂ­s, entre prĂłprias e franquias, alĂ©m da distribuiĂ§ĂŁo em farmĂĄcias e na gigante multimarcas Sephora. Mais que um case de sucesso, a franquia Dermage Ă© a demonstraĂ§ĂŁo do poder do empreendedorismo feminino. Ă o sonho de Lisa, que encontrou o sonho da filha, Ilana, com a certeza de quem acredita no que faz.', NULL, 'RIO DE JANEIRO', 1, NULL, 74, NULL, NULL, '2026-03-09 01:03:30.010', 'https://franquias.portaldofranchising.com.br/franquia-dermage-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
