INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76uu00kaeh0sxitt260i', 'AMĂVIA COSMĂTICOS', 'amavia-cosmeticos', NULL, 'SaĂșde, Beleza e Bem Estar', 'COSMĂTICOS E PERFUMARIA', 'Franquia de CosmĂ©ticos especialmente Capilar comprometida em oferecer produtos de alta qualidade.', 2017, 2018, '[\"https://www.youtube.com/watch?v=-G5pur0OoMg\",\"https://www.youtube.com/watch?v=PRB_gjoOXWk\",\"https://www.youtube.com/watch?v=CPN3dP9eUEw\"]', '2026-04-01 02:00:08.412', '2025-08-05 22:20:28.278', 767, NULL, 1, 2011, 'AmĂĄvia foi fundada em 2011, com o objetivo de provocar uma revoluĂ§ĂŁo na ĂĄrea de estĂ©tica capilar, com inovaĂ§Ă”es e soluĂ§Ă”es para o mercado de cosmĂ©ticos. Como novo conceito de marca, a empresa estĂĄ sustentada pelos pilares do Amor e Viabilidade, sempre em busca da satisfaĂ§ĂŁo do cliente. Recebemos o PrĂȘmio de Melhor Produto Capilar da AmĂ©rica Latina, em 2019 com o produto NĂ©voa Micelar Vegan Coconut e em 2021 com a linha Keraplex. O prĂȘmio de Atualidade CosmĂ©tica celebra a inovaĂ§ĂŁo e o talento de profissionais e empresas que movimentam o mercado de beleza na AmĂ©rica Latina. Ă reconhecidamente, o \"Oscar\" do mercado de beleza no Brasil. A expansĂŁo com franquias iniciou hĂĄ cinco anos, e hoje a franqueadora soma mais de 80 operaĂ§Ă”es, dentre quiosques e lojas, estrategicamente posicionados em 13 estados e Distrito Federal. Na contramĂŁo do mercado brasileiro, nossa empresa ampliou os resultados de faturamento durante a pandemia, e para 2024 projetamos um crescimento de 80% em nossa rede de franquias. Embora o nĂșmero pareĂ§a audacioso, a sustentabilidade de um negĂłcio de 12 anos, jĂĄ se mostrou viĂĄvel.', NULL, 'BAHIA', 1, NULL, 59, NULL, NULL, '2025-07-01 13:12:45.000', 'https://franquias.portaldofranchising.com.br/franquia-amavia-cosmeticos-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
