INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vf00keeh0sywfh1fy6', 'PRA COMER', 'pra-comer', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Lanchonete, Cafeteria, SuplementaĂ§ĂŁo,', 2023, 2023, '[\"https://www.youtube.com/watch?v=N-GjLN66cDk\"]', '2026-04-01 02:00:08.453', '2025-08-05 22:20:28.299', 771, NULL, 1, 2016, 'Fundada em 2016, a Pra Comer nasceu a partir da vontade de ter mais tempo de qualidade com os filhos, desejo de maior autonomia para cuidar de projetos pessoais e da necessidade de uma renda maior.Â  Ă Ă©poca era funcionĂĄrio pĂșblico do Governo de Minas Gerais, gastava muito tempo em deslocamento de casa/trabalho/casa e nĂŁo me sobrava tempo nem disposiĂ§ĂŁo. \nComo funcionĂĄrio pĂșblico estadual nĂŁo via possibilidade de aumentar renda, tĂŁo pouco de crescimento pessoal/profissional. \nEstava estagnado em um patamar financeiro que nĂŁo me permitia projetar uma vida melhor para mim e meus filhos. Era preciso tomar o risco e empreender! Inicialmente montei o primeiro BOX da Pra Comer e toquei a empresa e meu trabalho no Governo do Estado paralelamente. \nApĂłs 10 meses de operaĂ§ĂŁo da lanchonete, jĂĄ ganhava o dobro do que ganhava como funcionĂĄrio pĂșblico! EntĂŁo pedi exoneraĂ§ĂŁo do cargo pĂșblico. O Box Pra Comer Ă© uma lanchonete completa! Ocupa apenas 3m2, ideal para locais como hospitais, clĂ­nicas, shoppings, galerias, prĂ©dios comerciais, rodoviĂĄrias, aeroportos, etc. A Pra comer Ă© uma Ăłtima opĂ§ĂŁo para empreender e prosperar em famĂ­lia. Aconteceu comigo, experiĂȘncia prĂłpria!  Charleston Souza\nIdealizador da Franquia Pra Comer', NULL, 'MINAS GERAIS', 1, NULL, 1, NULL, NULL, '2026-03-09 01:12:48.149', 'https://franquias.portaldofranchising.com.br/franquia-pra-comer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '74970', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vk00kfeh0sor09uijm', 'MUNIZ AUTOCENTER', 'muniz-autocenter', NULL, 'ServiĂ§os Automotivos', 'LocaĂ§ĂŁo de veĂ­culos', 'Auto Center, especialistas em serviĂ§os automotivo, corretivos e preventivos, troca de pneus, cambagem, alinhamento e balanceamento, sistema de ar cond., manutenĂ§ĂŁo de freios, suspensĂŁo, troca de oleo.', 2016, 2020, '[\"https://www.youtube.com/watch?v=Gji_FzmfTZQ\",\"https://www.youtube.com/watch?v=qxxODQCN3YU\"]', '2026-04-01 02:00:08.464', '2025-08-05 22:20:28.304', 772, NULL, 1, 2009, 'Muito Prazer; somos a Rede Muniz Auto Center Â  Tudo comeĂ§ou com Maedson Muniz, um jovem que veio de uma famĂ­lia muito humilde e diversas vezes passou por muitas dificuldades, atĂ© mesmo privaĂ§Ă”es extremas, porĂ©m Maedson sempre foi um jovem cheio de esperanĂ§a e com um sonho a ser conquistado, ele comeĂ§ou a investir no seu futuro com apenas 11 anos de idade, para ajudar nas despesas em casa comeĂ§ou a trabalhar na oficina do seu tio, foi nesta fase que ele descobriu o sonho de ter seu prĂłprio negĂłcio, uma oficina, inspirado no seu pai que tambĂ©m era mecĂąnico. \nInvestindo neste sonho, com 18 anos de idade, Muniz percebeu que precisava de uma renda extra, foi ai que ele comeĂ§ou a fazer bicos como office boy a noite e lavando carros aos sĂĄbados e domingos, ele mal descansava, mas seu desejo por crescer o impulsionava e dava forĂ§as para nĂŁo desistir. \nAos 23 anos, foi quando ele decidiu que era a hora de comeĂ§ar o seu empreendimento! Fez um emprĂ©stimo de 6 mil reais e abriu a primeira Muniz Auto Center, o sonho, finalmente, havia comeĂ§ado. No comeĂ§o era muito difĂ­cil, pois, Muniz nĂŁo tinha ajuda, entĂŁo era ele quem cuidava de tudo e todos os detalhes da tĂŁo sonhada empresa. \nMaedson Muniz sempre teve seu prĂłprio objetivo e sempre soube o porque era tĂŁo importante alcanĂ§ar seus sonhos e pela primeira vez em sua vida este sonho estava em prĂĄtica, finalmente ele podia ajudar outras famĂ­lias a nĂŁo sofrerem o que ele sofreu, podia dar uma chance a todos aqueles que quisessem crescer e alcanĂ§ar seus prĂłprios sonhos! \nSeu negĂłcio foi crescendo cada vez mais, contratando funcionĂĄrios, conquistando mais clientes e, apĂłs 5 anos da primeira loja localizada em ParanavaĂ­, foi inaugurada em MaringĂĄ â PR, a segunda unidade da Muniz Auto Center, em pouco tempo, foi inaugurada a terceira loja, desta forma, sendo comprovado que o negĂłcio, era sem dĂșvidas, um excelente empreendimento! \nCerto dia, conversando com um grande amigo que tambĂ©m tinha o sonho de ter seu prĂłprio negĂłcio e trazer estabilidade e conforto a sua famĂ­lia, Muniz pensando em formas de ajudar teve um estalo em sua mente, por que nĂŁo transformar a Muniz Auto Center em uma franquia? Dessa forma, ajudaria nĂŁo somente seu amigo, mas muitas outras pessoas, que assim como ele, sonhavam alto! Seu amigo aceitou comprar a primeira franquia na hora! EntĂŁo em apenas 30 dias, tudo estava pronto e assim, foi inaugurada em Londrina a primeira franquia! \nCom um grande crescimento, atualmente, Muniz Auto Center conta com 30 franquias, em apenas 4 anos apĂłs a venda da primeira, um negĂłcio comprovado e sĂłlido no mercado. Muniz realizou seu sonho e o sonho de 30 famĂ­lias que, assim como ele, almejavam uma mudanĂ§a de vida! \nE vocĂȘ quer mudar a sua vida? Temos a oportunidade certa para vocĂȘ que Ă© apaixonado por carros, deseja uma mudanĂ§a de vida e finalmente conquistar a tĂŁo sonhada liberdade financeira adquirindo o seu prĂłprio negĂłcio! Com nossa ajuda na gestĂŁo do seu novo empreendimento, sem dĂșvidas vocĂȘ vai longe, nĂŁo perca esta grande oportunidade.', NULL, 'PARANĂ', 1, NULL, 59, NULL, NULL, '2026-03-09 01:13:35.226', 'https://franquias.portaldofranchising.com.br/franquia-muniz-autocenter/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vp00kgeh0s9en99u0r', 'SEU VIDAL', 'seu-vidal', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'A franquia de sanduicheria Seu Vidal apresenta um modelo de negĂłcio sĂłlido e lucrativo, que tem atraĂ­do empreendedores em busca de oportunidades no ramo da alimentaĂ§ĂŁo.', 2022, 2023, NULL, '2026-04-01 02:00:08.474', '2025-08-05 22:20:28.310', 773, NULL, 1, 2016, '', NULL, 'RIO DE JANEIRO', 1, NULL, 38, NULL, NULL, '2026-03-09 01:14:55.769', 'https://franquias.portaldofranchising.com.br/franquia-seu-vidal-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vu00kheh0ssqxku4tt', 'ARAMIS', 'aramis', NULL, 'Moda', 'VestuĂĄrios', 'VestuĂĄrio masculino, calĂ§ados e acessĂłrios', 2003, 2019, '[\"https://www.youtube.com/watch?v=Ub-289B0IEE\",\"https://www.youtube.com/watch?v=Q5YX3z-lqV8\",\"https://www.youtube.com/watch?v=mEAylUih7wQ\",\"https://www.youtube.com/watch?v=DUiZrNkboTM\"]', '2026-04-01 02:00:08.484', '2025-08-05 22:20:28.314', 774, NULL, 1, 1994, 'A Aramis atua no mercado de moda masculina hĂĄ mais de 25 anos, com excelĂȘncia em qualidade, alinhada ao que hĂĄ de novo em menswear pelo mundo. Inovamos constantemente, e nos mantemos conectados Ă s tendĂȘncias e demandas da moda masculina contemporĂąnea. \nA Aramis foi criada em 1995 por Henri Stad, empresĂĄrio francĂȘs com 45 anos de experiĂȘncia no setor tĂȘxtil. \nA proposta da grife sempre se baseou em uma moda masculina moderna e sofisticada, com poder de inovaĂ§ĂŁo e tino comercial. \nFoi a primeira a trazer para o mercado brasileiro a camisaria de fio egĂ­pcio. Inspirado nas aventuras de âOs TrĂȘs Mosqueteiros\", Henri batizou aÂ marca em homenagem ao seu personagem preferido do romance histĂłrico de Alexandre Dumas. \nA primeira loja foi inaugurada no Shopping Iguatemi, em SĂŁo Paulo, em um dos mais concorridos espaĂ§os de moda do paĂ­s. \nCom o tempo, aprimorou o estilo de suas peĂ§as, unindo conceito de moda, conforto, qualidade e evoluiu dividindo-se em quatro linhas: Menswear, Jeanswear, Night e Social, que juntas atendem o homem em todas as ocasiĂ”es. Atualmente, conta com uma equipe de estilo que acompanha as tendĂȘncias mundiais e realiza pesquisas internacionais constantes sobre consumo.Â  \nCom um mix de produtos de qualidade indiscutĂ­vel, Ă© referĂȘncia no lifestyle masculino, com alfaiataria de corte e caimento impecĂĄveis em peĂ§as que vĂŁo do clĂĄssico ao moderno.  ExpansĂŁo da marca Em fevereiro de 2014, o filho de Henri Stad, Richard Stad, assume a presidĂȘncia, se tornando CEO, aos 29 anos de idade, apĂłs dez anos trabalhando na marca. \nDepois de um crescimento focado entre 2015 e 2016, a Aramis partiu para seu projeto de expansĂŁo, liderado por Richard, abrindo mais de 40 lojas, entre prĂłprias e franquias, por todo o territĂłrio nacional. \nâCom a abertura de novas lojas, o objetivo Ă© oferecer ao cliente uma experiĂȘncia de compra Ășnica. \nPara isso, implementamos um novo projeto de lojas - que segmenta a coleĂ§ĂŁo em linhas para cada ocasiĂŁo e valoriza ainda mais o produto. \nAlĂ©m do investimento no ponto de venda, tambĂ©m iniciamos um plano de marketing agressivo que atua com diferentes pontos de contato com o nosso consumidor.', NULL, 'SĂO PAULO', 1, NULL, 138, NULL, NULL, '2026-03-09 01:15:16.148', 'https://franquias.portaldofranchising.com.br/franquia-aramis-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '1050000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76vz00kieh0seqq9w8oh', 'ESPETINHOS MIMI', 'espetinhos-mimi', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'ComĂ©rcio de Espetinhos Assados, Congelados, Desenvolvimento e ComercializaĂ§ĂŁo de Outros Produtos e OrganizaĂ§ĂŁo de Festas e Eventos.', 1988, 1992, NULL, '2026-04-01 02:00:08.494', '2025-08-05 22:20:28.320', 775, NULL, 1, 1967, 'Mais de 50 anos de histĂłria \nCom DNA industrial, no comeĂ§o de sua trajetĂłria, a Espetinhos Mimi reinventou o jeito de fazer churrasco para facilitar a logĂ­stica dos eventos â seja uma pequena festa familiar ou a confraternizaĂ§ĂŁo de uma empresa para centenas de funcionĂĄrios. Com o passar do tempo, alĂ©m de fabricar os espetinhos e fornecĂȘ-los para eventos, a Espetinhos Mimi passou a produzir tambĂ©m para o segmento de marca prĂłpria, e hoje Ă© responsĂĄvel pelos espetinhos de grandes redes varejistas. Depois, em 1988, veio a presenĂ§a no varejo, com lojas prĂłprias e franqueadas. Hoje, a Espetinhos Mimi tem mais de 20 pontos de venda.Â  A fĂĄbrica, uma planta industrial de 1200 metros quadrados, estĂĄ localizada em Indaiatuba/SP. O mais novo passo da marca, alĂ©m dos novos modelos de franquia, e a construĂ§ĂŁo de seu e-commerce. A nova loja virtual conta com uma plataforma robusta desenvolvida pela Vtex (R$ 500 mil de investimento), que estĂĄ por trĂĄs de mais de 2,5 mil sites de comĂ©rcio eletrĂŽnico, e inclui a rede de franquias na operaĂ§ĂŁo. AlĂ©m da parceria inĂ©dita com o iFood para alavancar as vendas de suas lojas prĂłprias e franqueadas.', NULL, 'SĂO PAULO', 1, NULL, 22, NULL, NULL, '2026-03-09 01:16:18.063', 'https://franquias.portaldofranchising.com.br/franquia-espetinhos-mimi/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
