INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76ww00koeh0sjgc3epry', 'EX-TOURO', 'ex-touro', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Hamburgueria no modelo Delivery', 2020, 2021, '[\"https://www.youtube.com/watch?v=dGstIo4K3JU\",\"https://www.youtube.com/watch?v=RrS0c7hKdM0\"]', '2026-04-01 02:00:08.553', '2025-08-05 22:20:28.352', 781, NULL, 1, 2015, 'O negĂłcio comeĂ§ou por acaso. Quando abriu as portas em 2015, na pequena loja no Cadeg, Yasser Regis tinha como ideia ser apenas um aĂ§ougue de carnes nobres. Por pressĂŁo dos amigos (que adoravam seus hambĂșrgueres) comeĂ§ou a criar seus blends com cortes de angus e wagyu. A brincadeira se tornou sonho, o sonho se tornou realidade e a Ex-Touro foi premiada dois anos depois pelo prĂȘmio da Veja Rio COMER & BEBER. O sucesso e a vontade de levar essa maravilha gastronĂŽmica para um maior nĂșmero de pessoas fez a hamburgueria premium investir na sua expansĂŁo e se tornar uma franquia.', NULL, 'RIO DE JANEIRO', 1, NULL, 42, NULL, NULL, '2026-03-09 01:18:40.734', 'https://franquias.portaldofranchising.com.br/franquia-ex-touro/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '420000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76x100kpeh0s1qmj7aq1', 'WISEHOME', 'wisehome', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'SoluĂ§ĂŁo inovadora para AutomaĂ§ĂŁo Residencial sem quebra-quebra com tecnologia campeĂŁ dos desafios brasileiro e internacional de internet das coisas.', 2021, 2023, '[\"https://www.youtube.com/watch?v=fL2eYAEYdWI\"]', '2026-04-01 02:00:08.563', '2025-08-05 22:20:28.357', 782, NULL, 1, 2017, 'A WISEHOME Ă AUTORIDADE NO ASSUNTO A WiseHome foi criada com atenĂ§ĂŁo aos detalhes, usando o que hĂĄ de melhor na indĂșstria mundial de hardware e software. Nossa patente requerida permite a automaĂ§ĂŁo residencial ou empresarial com facilidade de instalaĂ§ĂŁo, seja numa construĂ§ĂŁo nova ou antiga, a instalaĂ§ĂŁo Ă© feita de maneira prĂĄtica e rĂĄpida. A nossa marca Ă© referĂȘncia no mercado devido Ă  qualidade dos serviĂ§os prestados, tanto pelo atendimento pessoal quanto por equipamentos exclusivos que possuem excelente desempenho. Ă uma soluĂ§ĂŁo campeĂŁ do Desafio Brasileiro e Mundial de Internet das Coisas, nossa experiĂȘncia agrega valor e reconhecimento. Possibilita uma instalaĂ§ĂŁo limpa e rĂĄpida, sem precisar de infraestrutura prĂ©via. AlĂ©m de ser a mais segura do mercado, com criptografia BLOCKCHAIN.Â  Seu cliente conseguirĂĄ controlar a iluminaĂ§ĂŁo, cascata da piscina, aparelhos de ar condicionado, TVs, persianas eÂ  eletrodomĂ©sticos de onde estiver, com a velocidade de um clique e a seguranĂ§a que sĂł a WiseHome entrega!', NULL, 'SĂO PAULO', 1, NULL, 47, NULL, NULL, '2026-03-09 01:19:16.711', 'https://franquias.portaldofranchising.com.br/franquia-wisehome/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
