INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xl00kteh0sdnd2erso', 'DIA%', 'dia', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Supermercado Varejista', 1989, 2011, NULL, '2026-04-01 02:00:08.606', '2025-08-05 22:20:28.378', 786, NULL, 1, 1979, 'Cada dia mais pertoÂ  Somos a loja do bairro, aquela que proporciona uma experiĂȘncia de compra fĂĄcil, rĂĄpida e completa, perto de casa e com produtos fresquinhos a um preĂ§o acessĂ­vel. Chegamos ao Brasil em 2001, como parte do Grupo Dia, um dos maiores varejistas alimentares do mundo, atualmente com lojas na Espanha, onde nasceu em 1979, e na Argentina. Hoje, nĂŁo fazemos mais parte do Grupo Dia, mas seguimos no Brasil, oferecendo qualidade e preĂ§o justo em 244 unidades prĂłprias e franqueadas, distribuĂ­das pelo estado de SĂŁo Paulo. Juntos, somos mais de 2.300 colaboradoras e colaboradores. Contamos ainda com a Marca PrĂłpria Melhor a Cada Dia, que contempla desde alimentos, itens congelados e bebidas atĂ© produtos de limpeza, higiene e beleza â sendo a linha prĂłpria mais consumida no paĂ­s, segundo a Nielsen IBOPE.', NULL, 'SĂO PAULO', 1, NULL, 240, NULL, NULL, '2026-03-09 01:20:42.489', 'https://franquias.portaldofranchising.com.br/franquia-dia-servicos-e-conveniencia/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '1515000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xq00kueh0sb0jshabf', 'MANIA DE CHURRASCO! PRIME STEAK & BURGER', 'mania-de-churrasco-prime-steak-burger', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Steakhouse - (Churrasco, Lanches, Acompanhamentos, Saladas, Bebidas)', 2013, 2013, '[\"https://www.youtube.com/watch?v=DQEbdkbCzNk\",\"https://www.youtube.com/watch?v=e6Uz2xXp_Dg\",\"https://www.youtube.com/watch?v=M4BnTZ4IEd4\"]', '2026-04-01 02:00:08.616', '2025-08-05 22:20:28.383', 787, NULL, 1, 2001, 'Em agosto de 2001 nasce a Mania de Churrasco! Buffet Express com o autĂȘntico churrasco gaĂșcho no shopping Ibirapuera. Em 2012, depois de muito aprendizado, persistĂȘncia, diversos estudos e pesquisas, os fundadores do Mania de Churrasco! â comeĂ§aram a pensar em um novo modelo de negĂłcio, que pudesse ser replicado de maneira consistente e, entĂŁo, nasceu o Mania de Churrasco ! PRIME STEAK HOUSE, cujo objetivo Ă© oferecer, tambĂ©m em praĂ§a de alimentaĂ§ĂŁo, os melhores cortes de carnes nobres, normalmente encontrados apenas em churrascarias de luxo, restaurantes e butiques de carnes. \nO novo modelo de negĂłcio foi concebido dentro do modelo de franquias. Isso, porque era crescente o nĂșmero de pessoas interessadas em investir em um negĂłcio semelhante ao Mania de Churrasco!, mas que envolvesse investimento um pouco mais baixo do que as unidades no modelo Buffet. Com investimento na casa a partir de R$ 2.5Â milhĂŁo, o conceito â que une praticidade e qualidade â logo se revelou um sucesso. Durante este perĂ­odo, o nĂșmero de candidatos a franqueados sĂł cresce e a rede jĂĄ contabiliza mais 90 unidades em operaĂ§ĂŁo nas regiĂ”es Sudeste, Sul, Centro â Oeste e tambĂ©m no Distrito Federal, Â com um time com muita gente boa e que faz a marca crescer de forma saudĂĄvel;', NULL, 'SĂO PAULO', 1, NULL, 106, NULL, NULL, '2026-03-09 01:21:22.854', 'https://franquias.portaldofranchising.com.br/franquia-mania-de-churrasco-prime-steak-burger-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '1500000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76xv00kveh0s4e72i9mn', 'SCADA', 'scada', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO RĂPIDO', 'Cafeteria com foco no bem estar, muitos cafĂ©s especiais e um cardĂĄpio diversificado com produtos premium, pois acreditamos que toda pausa precisa ser especial.', 2007, 2022, '[\"https://www.youtube.com/watch?v=FhviVdzeTQs\",\"https://www.youtube.com/watch?v=3LvJMjEUzz0\",\"https://www.youtube.com/watch?v=LTQTNUBKtVg\",\"https://www.youtube.com/watch?v=SIsFAaWCA5o\"]', '2026-04-01 02:00:08.626', '2025-08-05 22:20:28.388', 788, NULL, 1, 2004, 'Acreditamos que toda pausa merece um cafĂ© especial. A marca nasceu com esse espĂ­rito e seu nome foi inspirado nas caracterĂ­sticas sensoriais dos melhores cafĂ©s: Sabor, Corpo, Acidez, DoĂ§ura e Aroma.. Somos uma marca contemporĂąnea que acompanha as grandes tendĂȘncias mundiais, sempre com foco no bem-estar dos nossos clientes, entregando o mĂĄximo de qualidade nos nossos produtos e serviĂ§os. A primeira unidade foi instalada em 2004 na cidade de Presidente Prudente, Estado de SĂŁo Paulo, no modelo de quiosque. Em pouco tempo, a marca SCADA CAFĂ tornou-se referĂȘncia na cidade e regiĂŁo. O principal diferencial da rede SCADA CAFĂ Ă© a sua preocupaĂ§ĂŁo em oferecer um serviĂ§o e um cafĂ© de excelĂȘncia. O cafĂ© comercializado na rede SCADA CAFĂ Ă© produzido com grĂŁos 100% arĂĄbica, cuidadosamente selecionados e torrados de forma artesanal, garantindo um toque pessoal Ă  bebida. Cultivado na Serra da Mantiqueira, nas montanhas de Carmo de Minas, nossos cafĂ©s reĂșnem caracterĂ­sticas raras, que fazem dele um produto altamente diferenciado e premiado como um dos melhores do mundo. O desejo de continuar crescendo, ganhando o mercado e novos consumidores, foi o fator preponderante para a marca entrar no sistema de franquia. Hoje a marca estĂĄ presente nas principais capitais do Brasil, atendendo mais de 100 mil consumidores por mĂȘs. Temos trĂȘs formatos de negĂłcios, um cardĂĄpio democrĂĄtico e inclusivo para atender os clientes a qualquer horĂĄrio do dia e tornar o modelo de negĂłcio mais atraente e lucrativo aos franqueados. VANTAGENS AOS FRANQUEADOS: Suporte inicial para escolha do ponto; Treinamento inicial e contĂ­nuo; Produtos para qualquer hora do dia; Consumidores de todas as idades; Fornecedores homologados hĂĄ mais de 15 anos; Acompanhamento de resultados online; Ătima rentabilidade; Campanhas de markenting anual; Desenvolvimento de novos produtos; Consultoria de campo.', NULL, 'SĂO PAULO', 1, NULL, 7, NULL, NULL, '2025-09-12 14:13:31.000', 'https://franquias.portaldofranchising.com.br/franquia-scada/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
