INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76y500kxeh0sorzeg6by', 'SONHO DOS PĂS', 'sonho-dos-pes', NULL, 'Moda', 'CalĂ§ados', 'ComĂ©rcio Varejista de CalĂ§ados e AcessĂłrios femininos.', 2004, 2018, '[\"https://www.youtube.com/watch?v=c8VzgshIo1I\",\"https://www.youtube.com/watch?v=cINuRWwKelM\",\"https://www.youtube.com/watch?v=G7EfbhjVBfw\"]', '2026-04-01 02:00:08.646', '2025-08-05 22:20:28.398', 790, NULL, 1, 1978, 'VocĂȘ sabe qual segredo da Sonho dos PĂ©s para os negĂłcios? Nosso sonho comeĂ§ou em 1978, com a abertura de uma loja de bolsas e acessĂłrios no Rio de Janeiro. \nMovidos pelo imenso desejo de conectar nossas clientes Ă s principais tendĂȘncias de moda, atravĂ©s do melhor custo-benefĂ­cio, consolidamos a marca no mercado varejista como uma das mais presentes no dia a dia da mulher brasileira. HĂĄ 35 anos no mercado de calĂ§ados e acessĂłrios e hĂĄ mais de 20 anos franqueando, chegamos a mais de 200 lojas distribuĂ­das pelos principais estados do Brasil, conseguindo atender a todos os estilos, por meio de um leque altamente variado de opĂ§Ă”es. \nSempre atentos aos detalhes que envolvem acabamento e durabilidade, oferecemos produtos que reĂșnem qualidade Ășnica, design e conforto: tudo isso aliado a uma experiĂȘncia de compra encantadora! \nQueremos conquistar as mulheres da vida real e incentivĂĄ-las a serem o seu melhor, em qualquer momento ou humor. \nEntregando sempre brasilidade, proximidade e moda acessĂ­vel. Faz parte dos nossos valores acreditar na arte dos encontros sinceros e genuĂ­nos e sabemos que juntos somos mais fortes, afinal amamos gente! A Sonho dos PĂ©s cresceu sabendo que fazer junto faz toda a diferenĂ§a, faz parte da nossa missĂŁo propiciar um ambiente de negĂłcios seguro e rentĂĄvel, por isso trabalhamos para oferecer aos nossos franqueados a melhor margem do mercado, um payback de atĂ© 36 meses e um lucro mensal de 10% a 15%. Sabemos da importĂąncia de um negĂłcio sĂłlido e de confianĂ§a, e temos total expertise nesse assunto, por 3 anos chancelados pela ABF com o selo de excelĂȘncia em franchising. \nSomos uma marca com mais 3 milhĂ”es de pares de calĂ§ados vendidos no ano, com uma famĂ­lia de 49 franqueados. Venha fazer parte da famĂ­lia Sonho dos PĂ©s!\nÂ  A nossa marca estĂĄ hĂĄ 35 anos no mercado. NĂłs temos em nosso DNA: - Margem de 3,0;\n- Auxilio na escolha do ponto;\n- Lojas com uma Ăłtima estrutura;\n- Suporte integral ao franqueado;\n- Marketing 360;\n- PreĂ§o acessĂ­vel;\n- Qualidade e coleĂ§Ă”es que encantam;\n- Conforto e variedade;Â \n- CartĂŁo Private Label exclusivo da loja.', NULL, 'RIO DE JANEIRO', 1, NULL, 199, NULL, NULL, '2026-03-09 01:22:46.447', 'https://franquias.portaldofranchising.com.br/franquia-sonho-dos-pes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '330000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
