INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yl00l0eh0snylm0wvq', 'PURE PILATES', 'pure-pilates', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Esportes e Vida Ativa', 'Studio de Pilates', 2015, 2020, '[\"https://www.youtube.com/watch?v=oeQNU-sejPc\",\"https://www.youtube.com/watch?v=BSvpP0Hi3lQ\",\"https://www.youtube.com/watch?v=InFx8RTlbpM\",\"https://www.youtube.com/watch?v=XTdyHdR5iNE\"]', '2026-04-01 02:00:08.678', '2025-08-05 22:20:28.413', 793, NULL, 1, 2009, 'NĂłs da Pure Pilates nascemos com o intuito de oferecer para a comunidade o melhor em qualidade de vida. Desde 2009, atuamos em busca deste objetivo e somos uma empresa jovem e moderna, onde o atendimento diferenciado nos torna referĂȘncia nacional no mĂ©todo Pilates. Sempre pensando em estar alinhados com o que hĂĄ de novo no mercado, nĂŁo nos acomodamos e investimos muito tempo e dedicaĂ§ĂŁo em pesquisa, treinamento e inovaĂ§ĂŁo. Nossos franqueados passam por um longo treinamento de capacitaĂ§ĂŁo para garantir que um excelente desempenho tanto nos negĂłcios quanto na entrega de serviĂ§os aos seus alunos.', NULL, 'SĂO PAULO', 1, NULL, 275, NULL, NULL, '2026-03-09 01:24:23.829', 'https://franquias.portaldofranchising.com.br/franquia-pure-pilates/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yq00l1eh0sirevxmbs', 'BRITISH AND AMERICAN', 'british-and-american', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Ensino do idioma inglĂȘs focado em uma metodologia rĂĄpida com ĂȘnfase na conversaĂ§ĂŁo. Gama de produtos que atendem todas as faixas etĂĄrias.', 2015, 2017, '[\"https://www.youtube.com/watch?v=M1seCK8zBhA\",\"https://www.youtube.com/watch?v=yvDcIYAeD2M\",\"https://www.youtube.com/watch?v=akjsrP0DgmI\"]', '2026-04-01 02:00:08.688', '2025-08-05 22:20:28.418', 794, NULL, 1, 1996, 'Com o respaldo do know-how adquirido ao longo de mais de 22Â anos de experiĂȘncia no mercado de ensino do idioma inglĂȘs, a franquiaÂ British and American tem um imenso orgulho em poder aproximar pessoas de seus sonhos. O segredo do nosso sucesso estĂĄ na alegria do nosso aluno em frequentar aulas, e a nossa maior satisfaĂ§ĂŁo Ă© perceber sua rĂĄpida evoluĂ§ĂŁo no nĂ­vel de aprendizagem e aquisiĂ§ĂŁo da lĂ­ngua, dia apĂłs dia.\nÂ  Por que escolher a BRITISH AND AMERICAN? âą Software de gestĂŁo desenvolvido exclusivamente para a Rede, suprindo todas as necessidades e com constantes upgrades (atualizaĂ§Ă”es); âą Material didĂĄtico prĂłprio, moderno e registrado na Biblioteca Nacional; âą Total suporte aos trĂȘs departamentos: Comercial, PedagĂłgico e Administrativo; âą Baixos custos fixos; âą Desenvolvimento Profissional e Pessoal; âą GestĂŁo flexĂ­vel do seu horĂĄrio.\nÂ  CURSOS OFERECIDOS Atualmente, a Rede BRITISH AND AMERICAN oferece aos franqueados 3 tipos de produtos distintos, mas conectados entre si.\nÂ  CURSO TEENS Voltado ao mundo adolescente, o curso Teens absorve alunos a partir dos 09 anos de idade. O curso Teens tem duraĂ§ĂŁo de 04 anos e contempla 8 books, utilizando uma abordagem que fala a lĂ­ngua dos nossos alunos, os teachers promovem uma maior proximidade e interatividade em sala de aula. Tendo Ă  disposiĂ§ĂŁo salas de aula com kits multimĂ­dia e com possibilidade de reforĂ§o semanal gratuito, o curso Teens torna-se um excelente investimento no futuro de nossos jovens. Â  CURSO ADULTS Curso dirigido a adultos e jovens a partir dos 15 anos de idade. O curso tem duraĂ§ĂŁo de 12 meses (3 books), com ĂȘnfase total na conversaĂ§ĂŁo, aulas ministradas 100% em inglĂȘs e horĂĄrios semi-flexĂ­veis, assim, o aluno marca sua aula conforme sua disponibilidade de tempo, podendo assistir atĂ© 05 aulas semanais. As turmas reduzidas (limite mĂĄximo de 05 alunos por turma), tornam o ensino muito mais personalizado. E tem mais, as matrĂ­culas ficam abertas o ano todo, com inĂ­cio imediato. Â  CURSO HYPER Seguindo a premissa de 12 meses de duraĂ§ĂŁo, e com um Ășnico book, o Curso Hyper Ă© destinado a pessoas que jĂĄ dominam o idioma inglĂȘs, mas que buscam proficiĂȘncia. O curso potencializa todas as habilidades dos alunos, que ao final do curso, terĂŁo a oportunidade de fazer O teste de proficiĂȘncia TOIEC, gratuitamente. A British and American Ă© centro aplicador homologado deste teste.\nÂ  CURSO START: Agora, pessoas que tiveram pouco contato com a lĂ­ngua inglesa, terĂŁo seu, \"Start\" na busca da fluĂȘncia. The Start Book Ă© divertido, atual e, acima de tudo, inclusivo. Ele foi criado com base em feedback direto tanto dos alunos como dos professores. Ele tem a duraĂ§ĂŁo 3 meses totalizando 12 aulas. No aprendizado da lĂ­ngua inglesa, confianĂ§a na sua capacidade Ă© fundamental e o Start Book promove exatamente isso aos alunos, ao mesmo tempo que os prepara para o curso de 12 meses. Â  APOIO AO FRANQUEADO âą OrientaĂ§ĂŁo para localizaĂ§ĂŁo e aprovaĂ§ĂŁo do ponto comercial; âą Fornecimento do Manual do Franqueado, explicitando o know-how de instalaĂ§ĂŁo, operaĂ§ĂŁo e gestĂŁo da British and American; âą OrientaĂ§ĂŁo e manual do projeto arquitetĂŽnico e comunicaĂ§ĂŁo visual; âą IndicaĂ§ĂŁo de fornecedores e prestadores de serviĂ§os homologados. Â  Â SERVIĂOS CONTĂNUOS âą CapacitaĂ§ĂŁo contĂ­nua para o FRANQUEADO OPERADOR e sua equipe de trabalho; âą OrientaĂ§ĂŁo nas aĂ§Ă”es de captaĂ§ĂŁo de alunos, coordenaĂ§ĂŁo dos planos de comunicaĂ§ĂŁo, bem como a criaĂ§ĂŁo e arte-final das peĂ§as de comunicaĂ§ĂŁo para veiculaĂ§ĂŁo pelos FRANQUEADOS no mercado; âą SupervisĂŁo periĂłdica do padrĂŁo de qualidade dos serviĂ§os prestados; âą Desenvolvimento e busca constante de melhorias do Sistema de Franquia British and American, objetivando o crescimento e sucesso das unidades FRANQUEADAS; âą RealizaĂ§ĂŁo de encontros periĂłdicos, para exposiĂ§ĂŁo de ideias, crĂ­ticas, sugestĂ”es, bem como realizaĂ§ĂŁo de workshops, convenĂ§Ă”es, seminĂĄrios, palestras e treinamentos; Programa BFF. AĂ§Ă”es de relacionamento com clientes internos e alunos. Â  Mais informaĂ§Ă”es Contato: expansao@britishandamerican.com.br', NULL, 'PARANĂ', 1, NULL, 14, NULL, NULL, '2026-03-09 01:24:56.321', 'https://franquias.portaldofranchising.com.br/franquia-british-and-american-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76yw00l2eh0sfrryqnwe', 'BALANCEADO', 'balanceado', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Balanceado Ă© uma rede de alimentaĂ§ĂŁo saudĂĄvel ancorada na megatendĂȘncia mundial da saudabilidade e sustentabilidade, oferece uma alimentaĂ§ĂŁo muito colorida e nutricionalmente correta.', 2013, 2018, NULL, '2026-04-01 02:00:08.698', '2025-08-05 22:20:28.425', 795, NULL, 1, 2013, 'O Balanceado Ă© uma rede de franquias gaĂșcha com foco em alimentaĂ§ĂŁo saudĂĄvel, equilibrada e nĂŁo radical, o que se traduz no seu nome e faz parte da megatendĂȘncia mundial de saudabilidade. Seu mix de produtos Ă© muito colorido, cheio de texturas e muito sabor,Â  o que proporciona combinaĂ§Ă”es incrivelmente equilibradas e deliciosas. Apesar de seu carro chefe serem saladas personalizadas montadas pelo clientes, a marca possui pratos quentes, sanduiches, wraps, sucos, sobremesas e bebidas geladas saudĂĄveis. \nTodo o cardĂĄpio Ă© concebido por uma equipe de nutricionistas, engenheiro de alimentos e chefes especializados. \nPara aqueles que buscam por uma alimentaĂ§ĂŁo natural e saudĂĄvel, as receitas contam com insumos frescos e de muita qualidade. A marca surgiu em 2010 de um projeto de vida do empresĂĄrio carioca, Bernardo Thomaz, que sempre idealizou ter um negĂłcio de alimentaĂ§ĂŁo saudĂĄvel e sustentĂĄvel que fizesse bem as pessoas e ao planeta e que pudesse crescer mundo afora. \nUsando sua experiĂȘncia de mais de 20 anos como franqueador de alimentaĂ§ĂŁo de outro segmento, ele conseguiu concretizar seu projeto com muito sucesso. Com 12 lojas espalhadas pelo Sul do Brasil, o Balanceado Ă© uma marca que estĂĄ sempre atenta as novas tendĂȘncias de saudabilidade e necessidades de sustentabilidade, com inovaĂ§Ă”es constantes no seu mix de produtos, buscando sempre o melhor para os seus clientes, para o planeta e Ă© claro, para os seus franqueados. O faturamento mĂ©dio anual de uma franquia Balanceado Ă© de R$1.000.000,00, com uma lucratividade de atĂ© 25%, payback de 24 a 36 meses e investimento mĂ©dio de 450mil (incluindo a taxa de franquia).', NULL, 'RIO GRANDE DO SUL', 1, NULL, 7, NULL, NULL, '2026-03-09 01:26:46.393', 'https://franquias.portaldofranchising.com.br/franquia-balanceado/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
