INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76z900l4eh0sglgepcyd', 'ORTOESTĂTICA', 'ortoestetica', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'ClĂ­nica OdontolĂłgica', 2011, 2015, NULL, '2026-04-01 02:00:08.719', '2025-08-05 22:20:28.438', 797, NULL, 1, 2005, 'OrtoestĂ©tica Ă© a maior rede orofacial do Brasil que tem como embaixadora da marca a artista Claudia Leitte, alĂ©m de parceria com os maiores fornecedores do segmento. A ortoestĂ©tica possui royalties fixo, sem cobranĂ§a sobre o percentual do faturamento e com taxa de aquisiĂ§ĂŁo justa, acessĂ­vel e facilitada. \nA marca oferece modelo 2 em 1: saĂșde e estĂ©tica, nos formatos express, standard e premium. Segundo a revista de empreendedorismo, Pequenas Empresas & Grande NegĂłcios, a franquia estĂĄ entre as melhores para se investir em 2021. Aproveite!', NULL, 'PERNAMBUCO', 1, NULL, 85, NULL, NULL, '2026-03-09 01:28:08.500', 'https://franquias.portaldofranchising.com.br/franquia-ortoestetica/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76zg00l5eh0sq111300n', 'JUMPER PROFISSĂES E IDIOMAS LTDA', 'jumper-profissoes-e-idiomas-ltda', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Um modelo de negĂłcio completo e lucrativo! Com a Jumper, vocĂȘ tem a chance de abrir uma escola com cursos na ĂĄrea de idiomas, tecnologia, administraĂ§ĂŁo, industrial, saĂșde e beleza em um sĂł lugar.', 2009, 2018, '[\"https://www.youtube.com/watch?v=121_3fxTujQ\"]', '2026-04-01 02:00:08.729', '2025-08-05 22:20:28.445', 798, NULL, 1, 2003, 'A Jumper ProfissĂ”es e Idiomas Ă© uma Franquia com 18 anos de histĂłria, mais de 150 franquias pelo Brasil, conta com os melhores cursos do mercado, atende todas as idades e gĂȘneros com um portifĂłlio completo, opĂ§Ă”es das formaĂ§Ă”es na ĂĄrea de Beleza, Idiomas, Industriais, SaĂșde, NegĂłcios & Business e Idiomas. As Escolas da rede tĂȘm como os principais diferenciais, serem centros aplicadores do teste do TOEIC (Test Of English for International Communication) e a FormaĂ§ĂŁo do Executivo JR (Curso voltado para formaĂ§ĂŁo de executivos e empreendedores, sendo a pioneira no Brasil. Modelo de franquia A Jumper! trabalha com um modelo inovador de negĂłcio, com valores de investimento que partem de R$ 129 mil. SĂŁo trĂȘs modelos de franquias: Express, Standard e Premium. O modelo Express Ă© voltado para cidades acima de 20 mil habitantes, enquanto o modelo Standard Ă© indicado para cidades acima de 40 mil habitantes. JĂĄ a franquia Premium deve ser instalada, preferencialmente, em cidades acima de 100 mil habitantes. A proposta de retorno Ă© atrativa: com taxa de lucro entre 30% e 40%, o payback parte de seis meses. O faturamento mĂ©dio Ă© de R$ 50 mil. Suporte e treinamento A Jumper Escolas oferece suporte completo desde a compra da franquia, disponibilizamos Setor jurĂ­dico para orientaĂ§Ă”es sobre todos os aspectos legais. Desenvolvimento de Franquias, auxilia desde a busca do imĂłvel, contrataĂ§ĂŁo e treinamento de toda a equipe e Franqueado, check list, prĂ© e pĂłs inauguraĂ§ĂŁo e todas as aĂ§Ă”es do zero ao 100% da Franquia. AgĂȘncia prĂłpria de Marketing, terĂĄ uma agencia exclusiva da marca, fazendo campanhas ilimitadas, personalizadas para a regiĂŁo do franqueado. Setor pedagĂłgico irĂĄ acompanhar todo o desenvolvimento da escola, Ă© responsĂĄvel pela busca incansĂĄvel por inovaĂ§Ă”es nas ĂĄreas de cursos, metodologias e as tendĂȘncias do mercado. AlĂ©m de disponibilizar um consultor por 30 dias imerso na unidade sem custo nenhum ao franqueado.', NULL, 'PARANĂ', 1, NULL, 29, NULL, NULL, '2026-03-09 01:28:47.123', 'https://franquias.portaldofranchising.com.br/franquia-jumper-profissoes-e-idiomas-ltda-servicos-educacionais/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '186999.71', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza76zm00l6eh0sf1b8cx0u', 'JORGE BISCHOFF', 'jorge-bischoff', NULL, 'Moda', 'CalĂ§ados', 'CONSULTORIA EM GESTAO EMPRESARIAL, COMERCIO VAREJISTA DE CALĂADOS E ACESSĂRIOS', 2008, 2010, '[\"https://www.youtube.com/watch?v=Xd7B9xGNPHs\",\"https://www.youtube.com/watch?v=qZGhHY_0Skc\",\"https://www.youtube.com/watch?v=vHVe8E5WANs\",\"https://www.youtube.com/watch?v=zhzODbdsa4Q\"]', '2026-04-01 02:00:08.739', '2025-08-05 22:20:28.450', 799, NULL, 1, 2003, 'HĂĄ 16 anos no mercado de franchising, a JORGE BISCHOFF conta com uma consolidada rede, com mais de 120 lojas exclusivas em operaĂ§ĂŁo, em todas as regiĂ”es do Brasil. Duas lojas-conceito sĂŁo as grandes vitrines da marca. Elas estĂŁo localizadas na Rua Oscar Freire, nos Jardins, em SĂŁo Paulo/SP e na cidade turĂ­stica de Gramado, na Serra GaĂșcha, entregando toda experiĂȘncia de lifestyle da grife aos seus visitantes. As demais lojas da rede apresentam layout estratĂ©gico com foco em vendas, produtos em evidĂȘncia e experiĂȘncia sensorial e de consumo, que conquista e fideliza clientes. Entre os diferenciais competitivos da franquia JORGE BISCHOFF destacam-se: o maior markup de preĂ§os do segmento, o alto poder de fidelizaĂ§ĂŁo dos clientes e a ausĂȘncia de cobranĂ§a da taxa de propaganda. A JORGE BISCHOFF tambĂ©m investe na implementaĂ§ĂŁo de estratĂ©gias omnichannel, proporcionando praticidade na jornada de compra do cliente e experiĂȘncias personalizadas, alĂ©m de oferecer vantagem competitiva significativa para a loja. Como marca de lifestyle, a JORGE BISCHOFF tem uma linha ampla de produtos, que vai alĂ©m do mix de sapatos, bolsas e acessĂłrios â femininos e masculinos â com lanĂ§amentos e novidades chegando nas lojas constantemente. Nas coleĂ§Ă”es especiais o destaque vai para: SAY YES (noivas); LUXO LEGĂTIMO (pele original de python); VIAGENS (malas e mochilas); MONOGRAMA (itens com a exclusiva estampa Monograma JB); ESSĂNCIAS (aromatizadores de ambiente com o perfume da loja); BISCHOFF WINES (espumantes exclusivos da marca). AlĂ©m da rede de lojas de franchising, a JORGE BISCHOFF tambĂ©m tem atuaĂ§ĂŁo global, estando presente em mais de 60 paĂ­ses nos cinco continentes, somando cerca de 600 pontos de venda em todo o mundo.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 130, NULL, NULL, '2026-03-09 01:29:51.848', 'https://franquias.portaldofranchising.com.br/franquia-jorge-bischoff-acessorios-pessoais-e-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '600000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
