INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770j00lceh0saf3r2z4n', 'ESPAĂO FACIAL', 'espaco-facial', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Franquia de HarmonizaĂ§ĂŁo facial e corporal, como aplicaĂ§ĂŁo de botox, preenchimento, bioestimuladores de colĂĄgeno e etc.', 2019, 2023, NULL, '2026-04-01 02:00:08.790', '2025-08-05 22:20:28.483', 805, NULL, 1, 2019, '', NULL, 'RIO DE JANEIRO', 1, NULL, 20, NULL, NULL, '2026-03-09 01:38:57.770', 'https://franquias.portaldofranchising.com.br/franquia-espaco-facial/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '270000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770o00ldeh0solzoid7m', 'O BOTICĂRIO', 'o-boticario', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'COMĂRCIO DE COSMĂTICOS E PERFUMARIA', 1980, 1992, NULL, '2026-04-02 13:13:57.947', '2025-08-05 22:20:28.489', 806, NULL, 1, 1977, 'A Franquia O BoticĂĄrio estĂĄ hĂĄ mais de 35 anos no sistema de Franchising. Hoje somos a maior rede de franquias do Brasil e a maior do mundo em perfumaria e cosmĂ©ticos.Â  Para conseguir este marco, a parceria com nossos franqueados Ă© fundamental.Â  Esse Ă© um dos motivos pelos quais eles tĂȘm a preferĂȘncia na abertura de novas lojas.Â \nÂ  NOSSA HISTĂRIA Somos otimistas, alquimistas e apaixonados Acreditamos que a beleza tem o poder de transformar acontecimentos simples em momentos mĂĄgicos.Â  Afinal, de que outra forma conseguirĂ­amos transformar uma batedeira em uma fĂĄbrica que espalha beleza por todo o Brasil e vĂĄrios paĂ­ses pelo mundo? Para explicar esta histĂłria, temos que voltar ao inĂ­cio.Â  Tudo comeĂ§ou em 1977, quando o recĂ©m-formado bioquĂ­mico Miguel Krigsner resolveu abrir sua prĂłpria farmĂĄcia de manipulaĂ§ĂŁo na rua Saldanha Marinho, centro de Curitiba. O nome do negĂłcio foi uma homenagem aos antigos farmacĂȘuticos, que manipulavam medicamentos de forma artesanal.Â  Assim nasceu O BoticĂĄrio.  Ao perceber que a maioria dos clientes eram mulheres, Miguel colocou seu lado alquimista em aĂ§ĂŁo e criou cremes faciais Ă  base de algas marinhas e colĂĄgeno, que misturava em uma batedeira de bolos nos fundos de sua botica.Â  O sucesso das fĂłrmulas se espalhou pela cidade e mudou para sempre os rumos do negĂłcio. Em 1979, a trajetĂłria de Miguel Krigsner se cruza com a de outro empreendedor.Â  Ao ouvir falar que Silvio Santos havia desistido de abrir uma marca de perfumaria no Brasil e possuĂ­a 60 mil frascos em forma de Ăąnfora, mas que a oferta era tudo ou nada, apostou no otimismo: mesmo sem ter o dinheiro ou espaĂ§o para armazenĂĄ-las, fez uma oferta para levar todas sob a condiĂ§ĂŁo de devolvĂȘ-las se nĂŁo conseguisse pagĂĄ-las.', NULL, 'PARANĂ', 1, NULL, 4051, NULL, NULL, '2026-03-09 01:39:23.573', 'https://franquias.portaldofranchising.com.br/franquia-boticario-valor/', NULL, NULL, NULL, 1, 3, 3, 1, 'MAINTAIN', 1, 1, '[\"RANKING_CATEGORIA\"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza770u00leeh0s4glhgujk', 'ASTRAL', 'astral', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'DesinsetizaĂ§ĂŁo, DesratizaĂ§ĂŁo, DescupinizaĂ§ĂŁo, Controle de mosquitos, Antimofo, Limpeza e DesinfecĂ§ĂŁo de caixas dâĂĄgua, Saneamento vegetal, Manejo de fauna silvestre SanitizaĂ§ĂŁo de Ambientes.', 1996, 1997, '[\"https://www.youtube.com/watch?v=bHRtKf4rt5g\"]', '2026-04-01 02:00:08.811', '2025-08-05 22:20:28.494', 807, NULL, 1, 1983, 'A Astral atua hĂĄ mais de 40 anos no mercado de controle de pragas e vetores urbanos e Ă© LĂDER na AmĂ©rica Latina.\nÂ \nDurante a sua trajetĂłria, se multiplicou em tamanho, investiu em tecnologia avanĂ§ada, mas manteve a mesma qualidade no serviĂ§o e no atendimento que fez da empresa a lĂ­der do setor em toda a AmĂ©rica Latina, especializada em contratos de mĂ©dio e de grande porte.\nÂ \nNossa trajetĂłria de sucesso teve inĂ­cio em 1983, na cidade mineira de UberlĂąndia. Hoje, a Rede Astral estĂĄ distribuĂ­da em 20 estados brasileiros, localizados em cidades do norte ao sul do paĂ­s, ultrapassando a marca das 43Â unidades fraqueadas.\nÂ \nAlĂ©m disso, possui mais de 10.000 pontos atingidos em contratos, 21Â Selos de ExcelĂȘncia em Franchising e lucro lĂ­quido mĂ©dio de 30%.\nÂ \nSeu processo de ExpansĂŁo vai Brasil a fora, a marca Ă© licenciada para atuar na Europa e estĂĄ em processo de licenciamento para atuar nos EUA.\nÂ \nA franquia Astral Ă© uma empresa que se reinventa e oferece aos clientes novas soluĂ§Ă”es para atender as exigĂȘncias do mercado.', NULL, 'RIO DE JANEIRO', 1, NULL, 38, NULL, NULL, '2026-03-09 01:40:24.153', 'https://franquias.portaldofranchising.com.br/franquia-astral-limpeza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '237000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771000lfeh0soi7gv38c', 'CADILE\'S ESPORTES', 'cadile-s-esportes', NULL, 'Moda', 'CalĂ§ados', 'A Cadile\'s Esportes atua no segmento de varejo esportivo, com foco em experiĂȘncia e nas melhores marcas de esporte do mundo, com Nike, Adidas, Puma, Vans e muito outras marcas desejo! Um show de loja!', 2023, 2023, '[\"https://www.youtube.com/watch?v=vZMNmDGtSlc\",\"https://www.youtube.com/watch?v=8921L9DCc-4\"]', '2026-04-01 02:00:08.824', '2025-08-05 22:20:28.500', 808, NULL, 1, 1996, 'A Cadile\'s Ă© uma empresa fundada em 1996 na cidade de IjuĂ­ - RS, especializada na venda de calĂ§ados e artigos esportivos, inicialmente suas operaĂ§Ă”es eram todas dedicadas Ă  sapataria, onde vendia-se calĂ§ados fashion, social e esportes. Entretanto, desde sua criaĂ§ĂŁo, a empresa tem se dedicado a oferecer produtos de qualidade e um atendimento diferenciado aos seus clientes. PorĂ©m, apĂłs uma viagem para a NRF em 2018, a maior feira de varejo do mundo em Nova York (EUA), foi criado um novo formato de loja, a Cadileâs Esportes, inovadora e disruptiva, eficiente e rentĂĄvel, no modelo ideal de arquitetura, design, combinaĂ§Ă”es, marcas e espaĂ§os fĂ­sicos. Em novembro do mesmo ano Ă© inaugurada um show de loja, com slogan Movimento Ă© Vida. ApĂłs um ano de testes e projeto piloto, houve uma boa resposta do mercado e da metodologia aplicada ao negĂłcio, fazendo com que todas lojas Cadileâs mudassem de perfil Cadileâs CalĂ§ados (Sapatarias - PrĂłprias) para Cadileâs Esportes, uma transformaĂ§ĂŁo empresarial completa. Â  A trajetĂłria ascendente, com a inauguraĂ§ĂŁo contĂ­nua de lojas, levou a Cadileâs a mudar seu modelo de expansĂŁo, optando em 2023 pelo franchising. Com o apoio das maiores marcas do mundo do esporte, como Nike, Adidas, Puma, Vans, Asics, Fila, New Balance e outras, todas sĂŁo homologadas para que os franqueados possam oferecer produtos de desejo e com alto ticket mĂ©dio. PRINCIPAIS VANTAGENS COMPETITIVAS Atende todas idades e classes sociais, praticantes de esporte, pessoas que gostam de usar as melhores marcas do mundo e que valorizam a qualidade dos produtos. Mix completo com calĂ§ados, vestuĂĄrio e acessĂłrios para as categorias: Corrida, Casual, Treino, Futebol, Basquete, Volei e outras! As melhores negociaĂ§Ă”es do mercado com as marcas (Markup elevado) e acesso Ă  segmentaĂ§ĂŁo de produtos especiais. Prateleira Infinita com estoque de todas lojas integrados e tambĂ©m estoque de algumas marcas. Os melhores sistemas da atualidade. Hoje, a Cadileâs Esportes Ă© reconhecida como uma das melhores lojas de esporte do Sul do Brasil, com pontos de vendas diferenciados que dĂŁo visibilidade aos produtos mais desejados pelos clientes.  Uma marca em crescimento e que estĂĄ inovando o segmento de esportes, o modelo Cadileâs Esportes Ă© projetado para cidades acima de 60 mil habitantes. Possuindo hoje lojas de rua e Shopping Center. Contando com lojas de 150 mÂČ a 250 mÂČ, o modelo envolve muita inovaĂ§ĂŁo e tecnologia, tendo como principais objetivos a maximizaĂ§ĂŁo das vendas, rentabilidade da operaĂ§ĂŁo e a experiĂȘncia do cliente. O segmento de esportes apresenta diversos desafios e a Cadileâs Esportes foi projetada para solucionar, sĂŁo eles: Acesso Ă s melhores marcas e segmentaĂ§Ă”es de produtos Alto ticket mĂ©dio + produto de desejo = OtimizaĂ§ĂŁo da equipe Maior rentabilidade para o franqueado Encantamento: Atendimento ĂĄgil e personalizado para o cliente', NULL, 'RIO GRANDE DO SUL', 1, NULL, 13, NULL, NULL, '2026-03-09 01:41:08.482', 'https://franquias.portaldofranchising.com.br/franquia-cadiles-esportes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '569000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771500lgeh0s0zkz01qw', 'CHOCOLATE LUGANO', 'chocolate-lugano', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Contempla um mix de negĂłcios, associando a tradicional loja de chocolates artesanais Ă  uma cafeteria e espaĂ§o para a venda de presentes e souvenirs, proporcionando estĂ­mulo ao aumento do ticket mĂ©dio.', 2018, 2019, NULL, '2026-04-01 02:00:08.834', '2025-08-05 22:20:28.505', 809, NULL, 1, 1976, 'Desde 1976, transformamos qualidade e carinho na mais deliciosa experiĂȘncia dos chocolates de Gramado. Com mais de 150 franquias, a Lugano estĂĄ presente em todos os estados do Brasil, sendo assim reconhecida pela sua excelĂȘncia em chocolates finos. Produzimos mensalmente mais de 100 toneladas de chocolate, com uma enorme variedade de barras de chocolate, trufas, bombons, kits para presente e uma linha completa de chocolates zero aĂ§Ășcar e sem lactose. Nossos modelos de franquias, alĂ©m da clĂĄssica e completa linha de chocolates, tambĂ©m oferece um completo cardĂĄpio de cafeteria, com: cafĂ©s clĂĄssicos e autoriais, chocolates quentes, lanches salgados e sobremesas com muito chocolate.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 133, NULL, NULL, '2025-07-10 11:39:41.000', 'https://franquias.portaldofranchising.com.br/franquia-chocolate-lugano-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza771a00lheh0s8i0ymns9', 'BILLY THE GRILL', 'billy-the-grill', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Billy Ă© a marca que conquista as praĂ§as de alimentaĂ§ĂŁo com o cheirinho de churrasco. O Churrasco na Pedra Ă© o carro-chefe do cardĂĄpio, que traz tambĂ©m opĂ§Ă”es variadas de pratos e acompanhamentos.', 2010, 2012, NULL, '2026-04-01 02:00:08.846', '2025-08-05 22:20:28.511', 810, NULL, 1, 2010, 'O Xerife da PraĂ§a de AlimentaĂ§ĂŁo \nUma histĂłria digna de herĂłis do velho oeste \nO churrasco na pedra logo fez sucesso em 2010, quando nasceu a primeira loja Billy The Grill em SĂŁo GonĂ§alo, segundo municĂ­pio mais populoso do Estado do Rio de Janeiro. Mas bem antes disso, iniciamos nossa trajetĂłria empreendedora atravĂ©s de uma rede de franquias no segmento de alimentaĂ§ĂŁo. Esta experiĂȘncia foi o alicerce para nossa histĂłria de sucesso e de superaĂ§ĂŁo.Â  \nEngenheiros de formaĂ§ĂŁo, Luiz Felipe Costa e Luiz Sergio Costa, irmĂŁos empreendedores, viram na franquia a oportunidade de construir a prĂłpria trajetĂłria e desenvolver suas carreiras com sucesso. Buscaram no franchising o suporte necessĂĄrio que compensaria sua pouca experiĂȘncia no segmento. Infelizmente nĂŁo fizeram uma escolha acertada em seu parceiro de negĂłcio. NĂŁo houve suporte ou treinamento e, depois de longos meses sem apoio, quase viram todo o investimento da famĂ­lia se perder. \nNo entanto, herdaram do pai, Seu SĂ©rgio, a garra e a coragem de seguir em seu propĂłsito e decidiram criar seu prĂłprio plano de negĂłcio e marca. ArregaĂ§aram as mangas, foram para a cozinha, buscaram as melhores receitas da famĂ­lia, conversaram com clientes da praĂ§a de alimentaĂ§ĂŁo, voltaram para a sala de aula e pediram muita ajuda a quem surgia. Tudo para fazer o negĂłcio gerar resultado. O plano de crescimento desenhado em um guardanapo depois de quase 10 anos parece uma trajetĂłria Ă©pica.Â  \nCom um tempero Ășnico e refeiĂ§Ă”es completas, o Billy The Grill Ă© a pedida ideal para se sentir mais prĂłximo de casa. Nossa comida Ă© fresca e de verdade e, nossa apresentaĂ§ĂŁo e serviĂ§o sĂŁo dignos dos herĂłis do faroeste. Nossos pratos sĂŁo preparados diariamente por cozinheiros, com carinho e dedicaĂ§ĂŁo. E nosso churrasco na pedra faz a diferenĂ§a no dia a dia, levando uma pitada de emoĂ§ĂŁo na correria da semana. Ă uma experiĂȘncia para nossos clientes diariamente carregar suas pedras cobertas com belos cortes de carne, fritas e outros complementos. Ă incrĂ­vel sentir aquele cheirinho de churrasco no meio da praĂ§a de alimentaĂ§ĂŁo! \nO Billy Ă© para aqueles que querem se conectar com um lugar de cuidado, com sabores Ășnicos e ao mesmo tempo familiares. Seja um amigo, um familiar ou um desconhecido: nĂłs pensamos que todos ao nosso redor merece respeito e carinho. Acreditamos que ao ajudar, somos tambĂ©m ajudados e, por isso, damos sempre o nosso melhor. \nSomos uma famĂ­lia. Fazemos parte de um time que acredita em relaĂ§Ă”es verdadeiras e estamos juntos no desenvolvimento e aprendizado de cada um. Queremos que as pessoas se sintam bem quando provam da nossa comida caseira, que os sabores e temperos os levem para um lugar de afeto e memĂłria.  Por isso, bem-vindo Ă  Casa do Churrasco na Pedra. Bem-vindo ao Billy The Grill.', NULL, 'RIO DE JANEIRO', 1, NULL, 52, NULL, NULL, '2026-03-09 01:42:54.038', 'https://franquias.portaldofranchising.com.br/franquia-billy-the-grill-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '750000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
