INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza772600lneh0syq1ajbel', 'GRID TIE SOLAR', 'grid-tie-solar', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'Na Grid Tie Solar nĂłs ajudamos os clientes a produzir uma energia limpa e sustentĂĄvel a um custo inferior ao que pagariam a distribuidora por uma energia poluente.', 2021, 2022, '[\"https://www.youtube.com/watch?v=sG8pTlXnUOc\",\"https://www.youtube.com/watch?v=iJH_RdhWuSg\",\"https://www.youtube.com/watch?v=gxg2094e6p4\",\"https://www.youtube.com/watch?v=Fgy6rVOTYAg\"]', '2026-04-01 02:00:08.925', '2025-08-05 22:20:28.543', 816, NULL, 1, 2016, 'A Grid Tie Solar, Ă© um modelo de negĂłcio no ramo de energia fotovoltaica, criado nos mais altos padrĂ”es, que oferece aos seus clientes serviĂ§os de alta qualidade com preĂ§os acessĂ­veis, empregando atĂ© entĂŁo as melhores tecnologias disponĂ­veis no mercado. \nO objetivo Ă© contribuir na produĂ§ĂŁo de energia limpa para estabelecimentos comerciais, industriais e residĂȘncias a um custo inferior ao que pagariam Ă  concessionĂĄria por uma energia poluente. \nForam desenvolvidos protocolos de atendimento e realizaĂ§ĂŁo de procedimentos para que o cliente tenha a melhor e mais agradĂĄvel experiĂȘncia, com seguranĂ§a, conforto e bem-estar. \nNosso compromisso Ă© com a excelĂȘncia no desenvolvimento e instalaĂ§ĂŁo de projetos para captaĂ§ĂŁo de energia solar, assegurando qualidade em todas as unidades, de maneira uniforme. \nChegamos para deixar nossa marca no mercado de energia solar fotovoltaica, pois somos diferentes, Ășnicos: ConstruĂ­mos relaĂ§Ă”es de confianĂ§a; Entregamos alto valor com preĂ§os competitivos; Promovemos qualidade de vida e bem-estar. Operando desde 2016 com unidade prĂłpria, a partir de 2021 a Grid Tie Solar adotou o modelo de franquia empresarial como estratĂ©gia de expansĂŁo do negĂłcio.', NULL, 'RIO DE JANEIRO', 1, NULL, 12, NULL, NULL, '2026-03-09 01:46:13.721', 'https://franquias.portaldofranchising.com.br/franquia-grid-tie-solar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
