sĂŁo em ritmo acelerado para todo o Brasil.', NULL, 'SĂO PAULO', 1, NULL, 28, NULL, NULL, '2026-03-09 01:53:54.410', 'https://franquias.portaldofranchising.com.br/franquia-codigo-girls-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '370000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
