INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza775c00m1eh0ss88syvuu', 'CLUBE 04', 'clube-04', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'O Clube04 Pet Store revolucionou a maneira de cuidar dos pets, tornando-se referĂȘncia nacional em bem-estar, carinho e qualidade. Centro de estĂ©tica, produtos diferenciados e cuidados veterinĂĄrios.', 2020, 2023, '[\"https://www.youtube.com/watch?v=PvwipJ4JOIg\"]', '2026-04-01 02:00:09.098', '2025-08-05 22:20:28.656', 830, NULL, 1, 2017, 'Clube04 Pet Store: Transformando a RelaĂ§ĂŁo entre Humanos e seus Pets No Clube04 Pet Store, acreditamos que a relaĂ§ĂŁo entre os humanos e seus doguinhos pode ser transformada atravĂ©s de uma comunicaĂ§ĂŁo excelente e muito carinho. Nosso objetivo nĂŁo Ă© ser apenas mais um pet shop, mas sim criar experiĂȘncias Ășnicas que faĂ§am com que cada pet se sinta amado e compreendido por todos os membros do Clube04. Seja durante o banho ou ao experimentar nossos produtos cuidadosamente selecionados, buscamos proporcionar momentos e lembranĂ§as positivas para os nossos doguinhos. Orgulhamo-nos de ser a faĂ­sca que acende um movimento em todo o Brasil, inspirando pet shops e pais de pets a trilhar uma jornada de amor e cuidado. Clube04 Pet Store: Uma RevoluĂ§ĂŁo no Cuidado com os Pets Somos uma referĂȘncia nacional no mercado pet e estamos revolucionando a maneira de cuidar dos nossos companheiros de quatro patas. Oferecemos um serviĂ§o diferenciado para garantir o bem-estar dos pets, incluindo: O Melhor Banho do Mundo com cromoterapia, feromonioterapia, mĂșsica relaxante, secagem no colo, massagem relaxante e sem o uso de gaiolas. Centro de estĂ©tica pet com produtos exclusivos e cuidados veterinĂĄrios de alta qualidade. NĂșmeros que Refletem Nosso Sucesso: Faturamento mĂ©dio anual da franquia: R$ 1,2 milhĂŁo. Rentabilidade: superior a 20%. O mercado pet Ă© um dos setores que mais cresce no Brasil, e o Clube04 Pet Store representa uma excelente oportunidade para quem deseja investir nesse segmento em plena ascensĂŁo. Suporte de ExcelĂȘncia para os Franqueados A franqueadora oferece suporte total para os franqueados, garantindo o sucesso da operaĂ§ĂŁo atravĂ©s de duas plataformas estratĂ©gicas: Universidade Corporativa Presencial: Um centro de treinamento de alto nĂ­vel, com um auditĂłrio moderno e climatizado para atĂ© 150 pessoas, oferecendo uma infraestrutura completa, incluindo salas de reuniĂŁo, espaĂ§o exclusivo para franqueados e estacionamento prĂłprio. Universidade Corporativa EAD: Plataforma online com materiais estratĂ©gicos essenciais para a operaĂ§ĂŁo da franquia, como manuais, peĂ§as personalizĂĄveis para aĂ§Ă”es comerciais, campanhas de marketing, vĂ­deos de treinamentos e muito mais! LideranĂ§a e Credibilidade O Clube04 Pet Store Ă© conduzido por grandes nomes do mercado: Sidney Kalaes â Presidente do Grupo Kalaes, holding multissetorial de franquias, com mais de 31 anos de experiĂȘncia no setor. LĂ­der e fundador de diversas franqueadoras de sucesso. Ana Paula Shinzaki â Idealizadora e fundadora do Clube04, com formaĂ§ĂŁo em Marketing pela USP e mais de 8 anos de experiĂȘncia em marketing criativo e inteligĂȘncia de mercado. FĂĄbio Aydar â Fundador do Clube04, formado em Marketing pela USP, com experiĂȘncia em empresas como Natura e Hypera, atuando em planejamento estratĂ©gico e demanda. Venha fazer parte dessa rede de sucesso!', NULL, 'SĂO PAULO', 1, NULL, 27, NULL, NULL, '2026-03-09 01:54:56.558', 'https://franquias.portaldofranchising.com.br/franquia-clube-04/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '282291', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
