INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza775s00m4eh0smiftdhg1', 'DISAPAR', 'disapar', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'ComĂ©rcio varejista e atacadista de Ferramentas, Equipamentos, Soldas, Abrasivos, EPIs, Parafusos, Tintas Automotivas e Industriais, Utilidades e ElĂ©trica.', 2020, 2020, '[\"https://www.youtube.com/watch?v=7sdVB9_zADQ\",\"https://www.youtube.com/watch?v=azg6QLMRAXc\",\"https://www.youtube.com/watch?v=CmVJRFZ0lD4\",\"https://www.youtube.com/watch?v=_d7P694ULBo\",\"https://www.youtube.com/watch?v=lxc8HORUDAo\"]', '2026-04-01 02:00:09.127', '2025-08-05 22:20:28.672', 833, NULL, 1, 1990, 'Uma empresa fundada em 1990, no Oeste de Santa Catarina! Surgiu com a necessidade regional em produtos de alta qualidade linha de tintas automotivas, equipamentos de proteĂ§ĂŁo individual (EPIs), ferramentas e parafusos. Ao longo dos anos, fomos ampliando nossa linha de produtos e hoje fornecemos, tambĂ©m, mĂĄquinas e equipamentos, soldas e abrasivos, produtos elĂ©tricos e uma linha de bazar. Ao todo, sĂŁo mais de 40 mil itens oferecidos em nossas lojas e site, que sĂŁo constantemente atualizados.\nÂ  Nossa equipe hoje conta com 60 colaboradores diretos, nas cidades ChapecĂł-SC e JoaĂ§aba-SC e mais de 20 representantes que atuam nos trĂȘs estados do sul. Todos alinhados com a nossa proposta de distribuir tecnologia em suprimentos industriais, no comĂ©rcio atacadista e varejista, com mercadorias nacionais e importadas.\nÂ  Pensando no compromisso que temos em distribuir produtos de qualidade para nossa cidade e regiĂŁo, buscamos sempre os melhores fornecedores. Prezamos por manter produtos de qualidade, que atendam Ă s necessidades dos clientes, com preĂ§os justos.Â  Temos uma equipe preparada sempre participando de treinamentos tĂ©cnicos sobre os produtos, para que possam oferecer, alĂ©m de informaĂ§Ă”es primĂĄrias, recomendaĂ§Ă”es sobre o uso correto dos produtos, para que o cliente possa ter mais produtividade e seguranĂ§a.\nÂ  Â A assistĂȘncia tĂ©cnica especializada tambĂ©m Ă© um diferencial da Disapar, e temos uma equipe de tĂ©cnicos nas linhas de EPIs, tintas automotivas, abrasivos e mĂĄquinas de solda preparada para ir atĂ© o cliente e orientar o melhor uso do produto. O ponto comercial da Disapar Ă© outro diferencial, porque Ă© de fĂĄcil localizaĂ§ĂŁo, pensado estrategicamente para facilitar a vida do cliente que vem atĂ© a loja. A logĂ­stica de transportadoras tambĂ©m Ă© facilitada por conta desse fator, e podemos enviar nossos produtos para todo o Brasil.', NULL, 'SANTA CATARINA', 1, NULL, 7, NULL, NULL, '2026-03-09 01:57:01.708', 'https://franquias.portaldofranchising.com.br/franquia-disapar-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '589212', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
