INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777m00mfeh0sy68lx7qm', 'FASTFRAME - MOLDURA NA HORA', 'fastframe-moldura-na-hora', NULL, 'Casa e ConstruĂ§ĂŁo', 'ARTIGOS PARA O LAR', 'ServiĂ§os e produtos de molduraria caracterizado pela busca constante de inovaĂ§ĂŁo e tecnologia.', 1995, 1997, '[\"https://www.youtube.com/watch?v=YvRgvdoIZSk\",\"https://www.youtube.com/watch?v=5AO6Tw5JU_I\"]', '2026-04-01 02:00:09.234', '2025-08-05 22:20:28.738', 844, NULL, 1, 1983, 'FastFrame / Moldura na Hora A maior rede de molduraria rĂĄpida do mundo A FastFrame / Moldura na Hora Ă© uma rede americana lĂ­der mundial em molduras, pĂŽsteres e espelhos, com mais de 100 lojas no mundo todo. Chegou ao Brasil em 1996 com um sistema especializado em prestaĂ§Ă”es de serviĂ§os de emolduraĂ§ĂŁo em apenas uma hora. Trouxe tambĂ©m produtos inovadores de alta qualidade, que estabelecem um forte diferencial competitivo atravĂ©s da utilizaĂ§ĂŁo de sofisticados equipamentos e materiais. Este ano a rede recebeu pela 14ÂȘ vez a chancela do Selo de ExcelĂȘncia em Franchising, que Ă© fornecido para franquias aprovadas em pesquisas e anĂĄlises de satisfaĂ§ĂŁo dos franqueados em relaĂ§ĂŁo Ă  franqueadora, tudo averiguado pela ComissĂŁo de Ătica da ABF (AssociaĂ§ĂŁo Brasileira de Franchising). Obteve a aceitaĂ§ĂŁo de mais de 90% dos franqueados. No ano de 2016, 2017, 2020 e 2021 a FastFrame | Moldura na Hora recebeu o prĂȘmio Pequenas Empresas Grandes NegĂłcios a cotaĂ§ĂŁo 5 estrelas no ranking das melhores franquia do Brasil, da Editora Globo. Hoje, o crescimento Ă© visĂ­vel, com o aumento expressivo do nĂșmero de lojas que atingem as principais cidades e capitais do paĂ­s. A FastFrame / Moldura na Hora Ă© lĂ­der por ser especialista no que faz, e tambĂ©m por oferecer um atendimento impecĂĄvel a seus clientes, atravĂ©s de funcionĂĄrios especialmente treinados e matĂ©ria prima de primeira linha. TambĂ©m se destaca por trabalhar com produtos inovadores e sempre divulgar novas tendĂȘncias e artistas. A partir de produtos customizados, oferece a soluĂ§ĂŁo adequada para projetos de decoraĂ§ĂŁo corporativos (hotĂ©is e empresas) e residĂȘncias. A rede Ă© a primeira do ramo a oferecer o serviĂ§o `Museum Quality`, que estĂĄ dentro dos padrĂ”es internacionais de conservaĂ§ĂŁo para total proteĂ§ĂŁo dos trabalhos emoldurados. Todos os produtos utilizados seguem um exemplo mundial de qualidade e que evitam o aparecimento de fungos, cupins e o amarelamento das obras. Possui ainda uma enorme variedade de produtos e itens exclusivos, que vocĂȘ sĂł encontra na FastFrame / Moldura na Hora. A rede oferece um serviĂ§o inĂ©dito no paĂ­s: a FastFrame Digital, que consiste em um banco de dados com mais de 20 mil imagens com temas variados. Utiliza moderna tecnologia para impressĂŁo de pĂŽsteres, escaneamento e tratamento de imagens, duplicaĂ§ĂŁo e ampliaĂ§ĂŁo em variados formatos, cores e mĂ­dias e estĂĄ sempre antenada nas tendĂȘncias. Ao realizar um serviĂ§o, alia Ăłtimos produtos com qualidade e agilidade. Os clientes podem retirar o pedido em uma hora ou entĂŁo contar com a comodidade do serviĂ§o de entrega. As lojas possuem um ar jovial e um ambiente convidativo que remetem a uma galeria de arte, devido aos quadros originais e Ă s obras em sĂ©rie nas versĂ”es gravuras e pĂŽsteres. Oferece produtos e serviĂ§os da mais alta qualidade, pois busca sempre oferecer o melhor para os clientes. Com um rigoroso critĂ©rio de seleĂ§ĂŁo, homologa somente fornecedores que atendam aos mais exigentes padrĂ”es de qualidade. Busca empresas que, assim como a FastFrame / Moldura na Hora, tenham por objetivo a excelĂȘncia em seus produtos e serviĂ§os. Os funcionĂĄrios sĂŁo treinados e supervisionados de perto por profissionais experientes, garantindo um serviĂ§o Ă  altura da rede.', NULL, 'SĂO PAULO', 1, NULL, 49, NULL, NULL, '2025-08-29 11:28:05.000', 'https://franquias.portaldofranchising.com.br/franquia-fastframe-decoracao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777s00mgeh0sdn4dnv66', 'FORUM', 'forum', NULL, 'Moda', 'VestuĂĄrios', 'ReferĂȘncia no mercado de jeanswear com peĂ§as originais e criativas, a Forum apresenta um momento fresh, moderno e com lifestyle urbano, alĂ©m de uma rica curadoria em clĂĄssicas alfaiatarias.', 1985, 2012, NULL, '2026-04-01 02:00:09.243', '2025-08-05 22:20:28.744', 845, NULL, 1, 1981, 'âFRANQUIA FORUM â A MARCA PIONEIRA DE JEANSWEAR NACIONAL \nÂ A Forum traz em seu DNA jeanswear, coleĂ§Ă”es com pegada contemporĂąnea, sofisticada e cool, apresentando a cada temporada looks cheios de personalidade. \nĂ referĂȘncia em estilo e comportamento, sendo a marca de vestuĂĄrio mais citada em pesquisas de opiniĂŁo no Brasil e vencedora por anos do prĂȘmio de empresa mais admirada do segmento. \nUma marca para homens e mulheres urbanos com um lifestyle jovem, bem informados e que usam a moda como forma de expressĂŁo. \nPertencentes as classes A e B, sĂŁo referĂȘncia de estilo em seu cĂ­rculo de relacionamento.   Vantagens em ser um franqueado FORUM: \n- Marca de moda mais lembrada pelo pĂșblico\n- ExperiĂȘncia de 35 anos de mercado\n- Projeto arquitetĂŽnico padronizado\n- AnĂĄlise e consultoria para a definiĂ§ĂŁo do ponto comercial\n- Moderno software de gestĂŁo\n- Expertise dos melhores Consultores de Franquias do mercado\n- Treinamentos de vendas e produtos, para a capacitaĂ§ĂŁo de equipe\n- Acesso ao Guia Visual da marca e Visual Merchandising\n- Apoio a materiais de marketing e aĂ§Ă”es de varejo\n- Amplo material estratĂ©gico para fomentar as vendas\n- CondiĂ§Ă”es comerciais mais favorĂĄveis\n- Suporte nos pedidos de compra\n- Diversificado mix de produtos, com mais de 800 itens por coleĂ§ĂŁo\n- Suporte do Grupo AMC TĂȘxtil, proprietĂĄria da marca, o maior gestor de marcas da AmĂ©rica Latinaâ', NULL, 'SANTA CATARINA', 1, NULL, 11, NULL, NULL, '2026-03-09 02:01:57.336', 'https://franquias.portaldofranchising.com.br/franquia-forum-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza777x00mheh0s49kitb3d', 'MILON', 'milon', NULL, 'Moda', 'VestuĂĄrios', 'Milon pertence ao Grupo Kyly, uma das indĂșstrias de vestuĂĄrio mais importantes do paĂ­s, e oferece agora ao mercado a oportunidade de parceria atravĂ©s do modelo de franquias em vestuĂĄrio infantil.', 2016, 2017, '[\"https://www.youtube.com/watch?v=Un7FEGQWews\",\"https://www.youtube.com/watch?v=1GpyzC5WyKE\"]', '2026-04-01 02:00:09.252', '2025-08-05 22:20:28.749', 846, NULL, 1, 1985, 'GRUPO KYLY Presente no mercado desde 1985, produz confecĂ§Ă”es de alto valor agregado para os mais exigentes mercados. Atualmente, o Grupo Kyly conta com mais de 1.500 funcionĂĄrios diretos e estĂĄ entre as empresas de maior representatividade no vestuĂĄrio infantil. Integridade, qualidade e sustentabilidade sĂŁo os valores do Grupo, que busca colocĂĄ-los em prĂĄtica atravĂ©s de aĂ§Ă”es de respeito e valorizaĂ§ĂŁo das pessoas. Toda a experiĂȘncia e competĂȘncia de uma indĂșstria sĂłlida foram absorvidas pela Milon, que assim desenvolve confecĂ§Ă”es com leitura atual de moda e excelĂȘncia em qualidade. O Grupo Kyly apresenta as franquias Milon. No mercado desde 2006, a Franquia Milon iniciou a abertura de suas lojas em 2010 para aproximar-se do consumidor e levar a experiĂȘncia da marca para o ponto de venda. SOBRE A MILON A origem no nome da marca Milon foi inspirada em um vilarejo na regiĂŁo de Bordeaux, na FranĂ§a. A marca Ă© conhecida pela inspiraĂ§ĂŁo europeia, estilo clĂĄssico e detalhes exclusivos. Veste desde recĂ©m-nascidos atĂ© o tamanho 14, alĂ©m de uma linha completa de enxoval. LOJA A primeira loja da Milon foi aberta em 2010. Fundamentado em estudos de mercado e direcionado ao pĂșblico da marca, o plano de expansĂŁo prevĂȘ para os prĂłximos anos a abertura de franquias distribuĂ­das nas principais cidades brasileiras. PRODUTO Em cada estaĂ§ĂŁo, peĂ§as sĂŁo desenvolvidas especialmente para as lojas Milon, inspirados nas principais tendĂȘncias de moda e em equilĂ­brio com as caracterĂ­sticas da marca: clĂĄssico e encanto. Sempre atentos as necessidades do mercado alĂ©m do estilo identificamos necessidades e trabalhamos com outras marcas que compĂ”em nosso mix em formato de collab. Parceria como com a marca de calĂ§ados infantis Tip Toey Joey, marca que compĂ”e nossos looks e permitem uma experiĂȘncia de compra completa. Linhas especiais voltadas para ocasiĂ”es de uso e novidades das modelagens e tamanhos tambĂ©m estĂŁo em constante evoluĂ§ĂŁo. A Milon Ă© uma das poucas marcas no Brasil a possuir o tamanho 5 dentro de sua grade de peĂ§as. COLEĂĂES Produtos exclusivos e repletos de detalhes diferenciados fazem da marca uma referĂȘncia no mercado infantil. A Milon mescla com perfeiĂ§ĂŁo o moderno e o clĂĄssico, o bĂĄsico e o sofisticado. VISUAL MERCHANDISING A Milon apresenta um modelo de loja que atende Ă s necessidades e expectativas de seus consumidores, oferecendo excelente exposiĂ§ĂŁo dos produtos, atendimento especializado e completo material de apoio Ă s vendas. DIFERENCIAIS A franqueadora tem como objetivo garantir o suporte e todas as ferramentas para o sucesso de todos os franqueados. Marca nacionalmente conhecida; Ampla variedade de produtos, com lanĂ§amentos constantes; Estilo, instalaĂ§Ă”es e visual merchandising exclusivos; Equipe exclusiva de gerenciamento de marketing para franquias; Assessoria de comunicaĂ§ĂŁo especializada no segmento; Rede testada em operaĂ§Ă”es prĂłprias.', NULL, 'SANTA CATARINA', 1, NULL, 120, NULL, NULL, '2026-03-09 02:02:46.138', 'https://franquias.portaldofranchising.com.br/franquia-milon-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '300000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
