INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778j00mleh0sh6nip0v0', 'HOT N\' TENDER', 'hot-n-tender', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Fast Food Especializado Em Frango Crocante. Hub de marcas, com varias cozinhas coletivas, entre elas frango crocante, mexicano, hamburguer, comida brasileira, comida saĂșdavel, entre outras.', 2015, 2015, '[\"https://www.youtube.com/watch?v=gTjTtt5tMME\",\"https://www.youtube.com/watch?v=Dq2acond_Rc\",\"https://www.youtube.com/watch?v=spEOFjHwzSg\"]', '2026-04-01 02:00:09.292', '2025-08-05 22:20:28.771', 850, NULL, 1, 1995, 'A Hot nÂŽTenderÂ  foi fundada em 1995, nos adaptamos a cultura brasileira e o nosso tempero Ă© um sucesso!! Iniciamos a expansĂŁo da marca em 2015 e atualmente estamos com mais 50 lojas em 8 estados brasileiros, sendo eles: Rio de Janeiro, SĂŁo Paulo, Minas Gerais, EspĂ­rito Santo Sergipe, CearĂĄ, Pernambuco, Bahia e Rio Grande do Norte. TambĂ©m contamos com 2Â unidades nos EUA. Os nossosÂ  deliciosos frangos crocantes sĂŁo preparados com a nossa receita secreta! no melhor estilo americano e os baldes arrebatam multidĂ”es. Trabalhamos com um mix diversificado de produtos como: sanduĂ­ches, tĂĄbuas de petiscos, pratos prontos e porĂ§Ă”es de batata frita, mandioca e anĂ©is de cebola. A HNT trabalha com umaÂ  estratĂ©gia diversificada que permite aos nossos franqueados manter o faturamento ao longo de todo o dia, garantindo a mĂĄxima rentabilidade.', NULL, 'RIO DE JANEIRO', 1, NULL, 49, NULL, NULL, '2026-03-09 02:07:56.772', 'https://franquias.portaldofranchising.com.br/franquia-hotntender/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '250000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza778r00mmeh0sxwxpmb66', 'I\'M INSTITUTO MIX DE PROFISSĂES', 'i-m-instituto-mix-de-profissoes', NULL, 'EducaĂ§ĂŁo', 'Treinamento Profissional e CapacitaĂ§ĂŁo', 'Cursos profissionalizantes, GraduaĂ§ĂŁo e Cursos na ĂĄrea de trĂąnsito', 2012, 2023, '[\"https://www.youtube.com/watch?v=VaYAteftr4M\",\"https://www.youtube.com/watch?v=A6qgWo4hXGM\",\"https://www.youtube.com/watch?v=2Zv8VcY5cf8\"]', '2026-04-01 02:00:09.302', '2025-08-05 22:20:28.779', 851, NULL, 1, 2012, 'HistĂłria da franquia Instituto Mix de ProfissĂ”es O Instituto Mix de ProfissĂ”es foi fundado com o intuito de formar profissionais altamente qualificados que possam atuar em diversas ĂĄreas do mercado, tais como: saĂșde, beleza, tecnologia, idiomas, administraĂ§ĂŁo, construĂ§ĂŁo civil, gastronomia, moda, indĂșstria e mecĂąnica, hotelaria e turismo. O IM traz uma grande variedade de cursos e assim consegue estar presente em um vasto nĂșmero de nichos do mercado, envolvendo vĂĄrios perfis de clientes de diferentes classes sociais, faixa etĂĄrias, sexo e estado civil. \nOpĂ§Ă”es de cursos nĂŁo faltam! SĂŁo mais de 200 Ă  disposiĂ§ĂŁo do aluno! Isso porque o Instituto Mix estĂĄ sempre buscando a excelĂȘncia dos serviĂ§os prestados e o sucesso dos seus franqueados. \nHoje a marca estĂĄ presente em todo territĂłrio nacional e alcanĂ§a a fantĂĄstica marca 600 unidades comercializadas no Brasil! A marca IM, que faz parte do mercado de franchising hĂĄ mais de dez anos, tem acumulado conquistas! Em 2014 ganhou seu primeiro selo das melhores franquias da revista âPequenas Empresas, Grandes NegĂłciosâ, e se manteve na lideranĂ§a, tendo recebido o prĂȘmio por dez anos consecutivos! Em 2015, 2016, 2017 e tambĂ©m em 2018, a marca tambĂ©m conquistou o Selo de ExcelĂȘncia da ABF. \nPorĂ©m em 2018 a comemoraĂ§ĂŁo foi ainda mais especial! O IM foi o grande destaque em sua categoria, sendo reconhecida como a melhor Franquia do Brasil.Â  Todos estes prĂȘmios sĂŁo resultados de muito trabalho que possibilitaram um crescimento vitorioso mesmo diante do cenĂĄrio desafiador do paĂ­s, com altĂ­ssimo nĂ­vel de satisfaĂ§ĂŁo de seus franqueados. Esta satisfaĂ§ĂŁo vem do mĂ©todo testado e de suporte constante. O Instituto Mix de ProfissĂ”es se difere de outras marcas quando o assunto Ă© capacitaĂ§ĂŁo e qualificaĂ§ĂŁo dos seus franqueados e colaboradores, sendo uma das franquias destaque em suporte. \nContamos com a UCIM, a Universidade Corporativa Instituto Mix, local para a troca de experiĂȘncias entre os profissionais e muitas formaĂ§Ă”es para quem jĂĄ estĂĄ na rede e quem estĂĄ chegando no IM. O Instituto Mix conta ainda com uma TV prĂłpria, a IMTV. Por meio dela franqueados e colaboradores recebem informaĂ§Ă”es especĂ­ficas sobre os setores da escola, como o setor pedagĂłgico, comercial, gestĂŁo, marketing, mĂ­dias e tambĂ©m conteĂșdo jornalĂ­stico. Contamos ainda com nossa prĂłpria grĂĄfica, a Editora IM, que imprime todas os nossos livros didĂĄticos e muitos outros materiais. Com um baixo investimento podemos atingir tanto as pequenas cidades quanto grandes metrĂłpoles. Para a franquia Instituto Mix o investimento Ă© baixo, o suporte Ă© constante e a rentabilidade Ă© muito grande! E vocĂȘ? Quer se tornar um franqueado de sucesso tambĂ©m? NĂŁo perca tempo! Venha fazer parte desta rede de conquistas!', NULL, 'SANTA CATARINA', 1, NULL, 284, NULL, NULL, '2026-03-09 02:08:39.338', 'https://franquias.portaldofranchising.com.br/franquia-instituto-mix-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '85327', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
