INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779n00mqeh0st3a3xn8e', 'FRANGO NO POTE', 'frango-no-pote', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Frango No Pote atua no segmento de alimentaĂ§ĂŁo desde 2012 com mais de 70 lojas em todas as regiĂ”es do Brasil, sendo considerada uma das maiores redes de franquia de frango frito do Brasil.', 2014, 2017, '[\"https://www.youtube.com/watch?v=-jjvNxcmfTM\"]', '2026-04-01 02:00:09.343', '2025-08-05 22:20:28.812', 855, NULL, 1, 2012, 'Em 2012, Carlos Augusto inicia a histĂłria da marca Frango no Pote. NinguĂ©m imaginaria que um delivery na churrasqueira da casa do CarlĂŁo, como Ă© conhecido, produziria uma poderosa rede de frango frito. No primeiro dia dessa inusitada trajetĂłria o telefone tocou 5 vezes, uma surpresa total. O tempo foi passando, as vendas aumentando. Carlos Augusto pega suas economias e inaugura a 1a loja fĂ­sica no dia 16 de junho de 2012 em Arniqueiras, com padrĂŁo digno de franquia, no qual tornou-se mania entre os brasilienses. O sucesso foi tĂŁo certeiro que desde 2014 o Frango no Pote tornou-se a maior franquia de frango frito do Centro-Oeste, com mais de 20 lojas a pleno vapor (e sabor!). Ciente do potencial da marca e de toda sua imensa equipe, a rede caminha focada em atingir nĂ­veis nacionais. Em 2012, Carlos Augusto inicia a histĂłria da marca Frango no Pote. NinguĂ©m imaginaria que um delivery na churrasqueira da casa do CarlĂŁo, como Ă© conhecido, produziria um poderosa rede de frango frango frito. No primeiro dia dessa inusitada trajetĂłria o telefone tocou 5 vezes, uma surpresa total. O tempo foi passando, as vendas aumentando. Carlos Augusto pega suas economias e inaugura a 1a loja fĂ­sica no dia 16 de junho de 2012 em Arniqueiras, com padrĂŁo digno de franquia, no qual tornou-se mania entre os brasilienses. O sucesso foi tĂŁo certeiro que desde 2014 o Frango no Pote tornou-se a maior franquia de frango frito do Centro-Oeste, com mais de 20 lojas a pleno vapor (e sabor!). Ciente do potencial da marca e de toda sua imensa equipe, a rede caminha focada em atingir nĂ­veis nacionais. O irresistĂ­vel vai aterrissar em todo o Brasil e vocĂȘ pode fazer parte dessa histĂłria.', NULL, 'DISTRITO FEDERAL', 1, NULL, 58, NULL, NULL, '2026-03-09 02:11:27.310', 'https://franquias.portaldofranchising.com.br/franquia-frango-no-pote/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza779u00mreh0s8gu6pnz4', 'PLANETA IMAGINĂRIO', 'planeta-imaginario', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e RecreaĂ§ĂŁo', 'A MELHOR REDE DE ESPAĂO INFANTIL DO BRASIL EM SHOPPING CENTER. ENQUANTO AS CRIANĂAS BRINCAM E SE DIVERTEM, OS PAIS USUFRUEM DE MOMENTOS PESSOAIS.', 2011, 2015, '[\"https://www.youtube.com/watch?v=aQqDGq1Fdeo\"]', '2026-04-01 02:00:09.355', '2025-08-05 22:20:28.818', 856, NULL, 1, 2007, 'ConheĂ§a a histĂłria de 3 irmĂŁs que com muito amor e empenho, alcanĂ§aram o sucesso! Desde sua chegada a RibeirĂŁo Preto, uma das irmĂŁs sentiu a necessidade de algo que a apoiasse no desenvolvimento dos seus filhos Nasceu assim, em 2007, um novo conceito em serviĂ§o de recreaĂ§ĂŁo infantil, o PLANETA IMAGINĂRIO, no RibeirĂŁo Shopping. Aos poucos o cenĂĄrio promissor proporcionou a abertura de novas unidades e iniciou a parceria entre as 3 irmĂŁs.Â  Em 2010 foi inaugurada a unidade de BrasĂ­lia-DF. A partir desta uniĂŁo a empresa alcanĂ§ou Ăłtimos resultados em um mercado carente de recreaĂ§ĂŁo e espaĂ§os infantis dentro de shoppings. O novo conceito permitia que os centros comerciais apostassem na marca e o PLANETA IMAGINĂRIO tornou-se alvo das REDES DE SHOPPINGS de todo o paĂ­s. A ampliaĂ§ĂŁo da rede foi tĂŁo grande que se tornou inevitĂĄvel a expansĂŁo da marca. Atualmente, o Planeta ImaginĂĄrio tem 10 unidades espalhadas pelo Brasil e diversas oportunidades abertas em grandes shoppings. MISSĂO Encantar as crianĂ§as e proporcionar momentos de alegria e boas recordaĂ§Ă”es, atravĂ©s de um mundo lĂșdico, enquanto os pais ou responsĂĄveis desfrutam de tempo para assuntos pessoais. Ser um espaĂ§o de liberdade e expressĂŁo infantil. VISĂO Compromisso com o coraĂ§ĂŁo e a mente. AtenĂ§ĂŁo, carinho e respeito com as crianĂ§as.Â DiversĂŁo com seguranĂ§a. Beneficiar todos atravĂ©s de parcerias. Por que investir em uma franquiaÂ Planeta ImaginĂĄrio? ExperiĂȘncia de sucesso de mais de 9 anos Excelente relacionamento com as administradoras de Shopping Center Vai participar de uma marca e de um sistema de gestĂŁo consolidado, de prestĂ­gio e de sucesso. IniciarĂĄ a operaĂ§ĂŁo com mĂ©todos profissionais de gestĂŁo e com acompanhamento. ContarĂĄ com a experiĂȘncia e apoio da Rede Planeta ImaginĂĄrio para minimizar riscos. Porque vocĂȘ irĂĄ unir sonho, realizaĂ§ĂŁo pessoal, profissional e financeira Vantagens de fazer parte da RedeÂ Planeta ImaginĂĄrioÂ de Franquias? Conceito de vanguarda e prestaĂ§ĂŁo de serviĂ§o inovador. Marca respeitada e consolidada. Projeto de arquitetura inovador e seguro. Auxilio na negociaĂ§ĂŁo de ponto em shopping. Treinamento completo, padronizaĂ§ĂŁo, metodologia, estratĂ©gia e gestĂŁo. Marketing ativo e inovador. RĂĄpido retorno de investimento.', NULL, 'SĂO PAULO', 1, NULL, 13, NULL, NULL, '2026-03-09 02:12:26.775', 'https://franquias.portaldofranchising.com.br/franquia-planeta-imaginario-entretenimento-brinquedos-e-lazer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '355000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
