INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bm00n3eh0smpo7uop9', 'ODONTOTOP HOSPITAL DO DENTE', 'odontotop-hospital-do-dente', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'Muito mais que clĂ­nica, um Hospital do Dente. Vamos alĂ©m da odontologia para ser a maior e mais premiada rede de hospitais odontolĂłgicos do Brasil em 2026.', 2020, 2021, '[\"https://www.youtube.com/watch?v=cKzAaDXkNIY\",\"https://www.youtube.com/watch?v=4lAx3D9iUJo\",\"https://www.youtube.com/watch?v=ScXKq_dIPbU\",\"https://www.youtube.com/watch?v=zYhX9YcQrAM\"]', '2026-04-01 02:00:09.472', '2025-08-05 22:20:28.882', 868, NULL, 1, 2012, 'A OdontoTop Ă© uma franquia de odontologia criada por dentistas, para dentistas. Nossos profissionais viveram e trabalharam em unidades prĂłprias, testando, validando e estruturando um modelo de sucesso. Agora, compartilhamos toda essa experiĂȘncia para que novos franqueados possam iniciar seus negĂłcios com seguranĂ§a, em uma rede grande, sĂłlida e autossustentĂĄvel. A OdontoTop oferece uma fĂłrmula vencedora, que combina uma metodologia prĂłpria de atuaĂ§ĂŁo com um software de gestĂŁo exclusivo. Esse modelo comprovadamente funciona em qualquer localidade do Brasil, com todas as unidades inauguradas em plena atividade. Por que limitar-se a uma clĂ­nica odontolĂłgica quando vocĂȘ pode ter seu prĂłprio Hospital do Dente? Oferecemos modelos de negĂłcios para cidades a partir de 8 mil habitantes. A OdontoTop Ă© a rede odontolĂłgica mais premiada do Brasil em 2024, ao receber o selo de ExcelĂȘncia em Franchising, concedido pela ABF, o selo de Melhores Franquias do Brasil, concedido pelo programa Pequenas Empresas & Grandes NegĂłcios e o selo de Great Place to Work. Tenha seu prĂłprio Hospital do Dente A estrutura Ă© um grande diferencial, voltado para o conforto e comodidade dos pacientes, desde a recepĂ§ĂŁo atĂ© as salas de atendimento. Cada projeto Ă© cuidadosamente planejado para atender a demanda de tratamentos odontolĂłgicos de toda a regiĂŁo. Agora pense como um paciente: vocĂȘ faria uma cirurgia complexa em uma clĂ­nica simples ou em um hospital especializado? Contamos com um centro cirĂșrgico completo, equipado com monitor cardĂ­aco hospitalar, oxigĂȘnio e raio-x panorĂąmico, ideal para procedimentos de grande complexidade, e ambientes prĂ© e pĂłs-operatĂłrios. Nossos consultĂłrios sĂŁo padronizados para garantir excelĂȘncia em todos os procedimentos realizados. Todo o Hospital do Dente Ă© planejado e estruturado para atender Ă s exigĂȘncias de um negĂłcio sustentĂĄvel ao longo prazo, mantendo-se sempre atualizado e em conformidade com as normas da vigilĂąncia sanitĂĄria federal.', NULL, 'SANTA CATARINA', 1, NULL, 76, NULL, NULL, '2026-03-09 02:18:06.708', 'https://franquias.portaldofranchising.com.br/franquia-odontotop-hospital-do-dente/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '1001553.95', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
