INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77bw00n5eh0sdyd9etv9', 'PITICAS FRANQUEADORA', 'piticas-franqueadora', NULL, 'Moda', 'VestuĂĄrios', 'Camisetas e acessĂłrios oficiais e licenciados do universo geek, super herĂłis, sĂ©ries, personagens e bandas de rock.', 2011, 2013, '[\"https://www.youtube.com/watch?v=PNpQLQA2kSs\",\"https://www.youtube.com/watch?v=fu6cEA_n4kw\"]', '2026-04-01 02:00:09.492', '2025-08-05 22:20:28.892', 870, NULL, 1, 2010, 'AÂ PiticasÂ iniciou suas atividades em 2010, a partir da ideia dos irmĂŁos Rossetti.Â  O objetivo inicial era oferecer ao consumidor final peĂ§as de moda criativa que brincava com marcas famosas. Com a consolidaĂ§ĂŁo no mercado, veio o licenciamento com os maiores players de entretenimento do mundo e, com isso, nos tornamos a maior referĂȘncia em moda GEEK no Brasil.Â  Hoje, mais de 10 anos depois, a Piticas conta com mais de 400 pontos de vendas espalhados por todo o paĂ­s. Oferecemos todo mĂȘs, novas estampas exclusivas e uma linha completa de mix de produtos para vestir seu lado fĂŁ! A Franquia Piticas ocupa o 43Âș lugar no ranking das maiores franquias do Brasil, com mais de 400 unidades franqueadas (ABF), e estĂĄ entre as 5 mais amadas pelos Brasileiros (Revista exame). A franquia se destaca pela inovaĂ§ĂŁo em tecnologia, produĂ§ĂŁo ĂĄgil com reposiĂ§ĂŁo semanal, e uma estrutura de franquia 100% focada no resultado dos nossos franqueados. Uma das grandes vantagens da franquia Piticas Ă© sua produĂ§ĂŁo 100% verticalizada, que garante a qualidade dos produtos, independĂȘncia deÂ fornecedores terceirizados, e dinamismo na produĂ§ĂŁo de lanĂ§amentos.  HISTĂRIA DA MARCA A Piticas nasceu da ideia de dois irmĂŁos, Vinicius e Felipe Rossetti, que apĂłs morarem por mais de uma dĂ©cada nos Estados Unidos, retornaram ao Brasil em busca de uma oportunidade empreendedora.  Os irmĂŁos, que sempre foram fĂŁs de cultura pop, em especial pelos filmes de super-herĂłis, sĂ©ries e games, apĂłs analisar vĂĄrios mercados, tiveram a visĂŁo de um negĂłcio que ainda nĂŁo era explorado no Brasil: o mercado de vestuĂĄrio de peĂ§as licenciadas, inicialmente, camisetas. A marca que incialmente se consolidou atravĂ©s de pontos de quiosques, hoje jĂĄ conta com + 03 modelos de negĂłcio: store, XP e multimarcas. Com uma produĂ§ĂŁo 100% verticalizada, e o foco no desenvolvimento da criatividade e atentos a cada detalhe, os irmĂŁos fundaram a primeira loja em 2010, e desde entĂŁo acompanham todas as etapas de produĂ§ĂŁo, treinamento de funcionĂĄrios e satisfaĂ§ĂŁo dos clientes, prezando por qualidade e criatividade em seus produtos.', NULL, 'SĂO PAULO', 1, NULL, 220, NULL, NULL, '2026-03-09 02:19:36.180', 'https://franquias.portaldofranchising.com.br/franquia-piticas-franqueadora-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '75000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
