INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cg00n9eh0sprialfwe', 'TODOMODA', 'todomoda', NULL, 'Moda', 'AcessĂłrios Pessoais', 'LĂ­der no segmento de AcessĂłrios de Moda e Lifestyle na AmĂ©rica Latina, com mais de 800 lojas na regiĂŁo. ApĂłs excelente entrada no Brasil, lanĂ§a seu modelo de franquias com lojas entre 35 e 45m2.', 2002, 2023, '[\"https://www.youtube.com/watch?v=DE-zDfrkv5k\"]', '2026-04-01 02:00:09.530', '2025-08-05 22:20:28.912', 874, NULL, 1, 1995, 'Aterrizamos no Brasil em 2019 e com o objetivo de construir tambĂ©m no paĂ­s a sua lideranĂ§a no segmento, a qual Ă© mais do que comprovada na maioria dos paĂ­ses da AmĂ©rica Latina. As nossas coleĂ§Ă”es sĂŁo desenvolvidas de ponta a ponta com base em pesquisas de moda globais e adaptadas ao DNA da marca e de sua comunidade de clientes, os produtos sĂŁo projetados contando com processos de sustentabilidade e âcruelty freeâ, a qual possui certificaĂ§ĂŁo, inspirando as novas geraĂ§Ă”es a escolherem produtos de forma mais consciente e responsĂĄvel, com o objetivo de gerar um impacto positivo para o planeta. O objetivo da expansĂŁo de franquias da TODOMODA, assim como nos demais paĂ­ses onde a marca estĂĄ presente, Ă© de democratizar o acesso aos seus produtos e gerar conexĂŁo emocional com a sua comunidade de clientes, fazendo com que se sintam Ă  vontade para expressar sua personalidade atravĂ©s dos acessĂłrios, com inovaĂ§ĂŁo, tecnologia na personalizaĂ§ĂŁo da experiĂȘncia, muito cuidado e carinho no desenvolvimento dos produtos Ășnicos e tudo dentro de um modelo de negĂłcios inteligente, saudĂĄvel e com muito suporte aos seus Franqueados. RAZĂES PARA SER UM FRANQUEADO TODOMODA Modelo de negĂłcio inovador Tomada de decisĂŁo com dados real-time Planejamento de demanda com suporte de ferramentas de InteligĂȘncia Artificial Total suporte estratĂ©gico e operacional Customer Experience e integraĂ§ĂŁo de canais Retorno rĂĄpido do investimento Lucro entre 10% e 18% Custo-benefĂ­cio Empresa sĂłlida com know-how de mercado Omnicanalidade Modelo de inteligĂȘncia baseado em Machine Learning Mais de 10 bilhĂ”es de dados combinados semanalmente para identificaĂ§ĂŁo de oportunidades em loja', NULL, 'SANTA CATARINA', 1, NULL, 21, NULL, NULL, '2026-03-09 02:21:41.361', 'https://franquias.portaldofranchising.com.br/franquia-todomoda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '510000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cm00naeh0sh777zspt', 'GOLDKO', 'goldko', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Chocolateria e cafeteria premium com um mix exclusivo de produtos 100% sem aĂ§Ășcar.', 2023, 2022, '[\"https://www.youtube.com/watch?v=RtMT8wU-3bM\",\"https://www.youtube.com/watch?v=S5x9BVL98y4\",\"https://www.youtube.com/watch?v=zE2_rNWPZAg\",\"https://www.youtube.com/watch?v=ciMMsyRZ5bQ\"]', '2026-04-01 02:00:09.540', '2025-08-05 22:20:28.918', 875, NULL, 1, 2017, 'A franquiaÂ GoldKo nasceu em 2017 com o propĂłsito de transformar a relaĂ§ĂŁo do brasileiro com o chocolate. Criada por uma famĂ­lia empreendedora com mais de 100 anos de experiĂȘncia no setor â fundadora de uma das marcas de chocolate mais tradicionais do paĂ­s â a GoldKo une sabor, saĂșde e sofisticaĂ§ĂŁo em um portfĂłlio completo de chocolates zero adiĂ§ĂŁo de aĂ§Ășcares, com apelo premium e alto valor percebido. Com fĂĄbrica prĂłpria, controle total de produĂ§ĂŁo e presenĂ§a consolidada em grandes redes varejistas, a marca iniciou seu projeto de franquias em 2023, apĂłs validar com sucesso o modelo de operaĂ§ĂŁo com sua loja prĂłpria no Shopping Eldorado - aberta em 2021. O mercado de chocolates premium e saudĂĄveis cresce acima da mĂ©dia do setor, impulsionado por um consumidor mais consciente, exigente e aberto a novas experiĂȘncias. A GoldKo estĂĄ perfeitamente posicionada nesse cenĂĄrio, oferecendo um produto inovador e Ășnico, com forte poder de encantamento e recompra. Entre os principais diferenciais da franquia estĂŁo: Omnicanalidade real: cada unidade conta com loja fĂ­sica e e-commerce regional integrado, sem conflito de canal â todas as vendas online da regiĂŁo sĂŁo faturadas pelo franqueado. Modelo de operaĂ§ĂŁo enxuto e escalĂĄvel, ideal para shopping centers. PortfĂłlio premiado, com produtos que unem prazer e saudabilidade. FĂĄbrica prĂłpria, garantindo qualidade, abastecimento e inovaĂ§ĂŁo constante. Marca com propĂłsito, forte conexĂŁo emocional com o consumidor e enorme potencial de expansĂŁo nacional. A franquia GoldKo Ă© mais do que uma loja de chocolates â Ă© um negĂłcio de impacto, alinhado Ă s novas demandas do consumidor e com estrutura sĂłlida para crescer de forma acelerada.', NULL, 'SĂO PAULO', 1, NULL, 16, NULL, NULL, '2026-03-09 02:22:35.937', 'https://franquias.portaldofranchising.com.br/franquia-goldko/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '340000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cr00nbeh0sf36lwb8v', 'SCHUTZ', 'schutz', NULL, 'Moda', 'CALĂADOS', 'A marca investe significativamente em pesquisas de tendĂȘncias, desenvolvimento de material e tecnologia para a criaĂ§ĂŁo do seu portfĂłlio. Sua missĂŁo Ă© oferecer ao seu pĂșblico um conceito de produtos.', 2010, 2015, NULL, '2026-04-01 02:00:09.549', '2025-08-05 22:20:28.923', 876, NULL, 1, 1995, '', NULL, 'SĂO PAULO', 1, NULL, 68, NULL, NULL, '2025-10-27 17:44:40.000', 'https://franquias.portaldofranchising.com.br/franquia-schutz-acessorios-pessoais-e-calcados/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '760000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77cx00nceh0s25f76uf3', 'V4 COMPANY', 'v4-company', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Modelo prestaĂ§ĂŁo de serviĂ§os de marketing digital atravĂ©s de escritĂłrios independentes espalhados em todo Brasil.', 2017, 2019, '[\"https://www.youtube.com/watch?v=mTyZLCFxA_Q\",\"https://www.youtube.com/watch?v=QMQz2qXZUt8\"]', '2026-04-01 02:00:09.558', '2025-08-05 22:20:28.929', 877, NULL, 1, 2012, 'Junte-se ao melhor time de profissionais de marketing do Brasil. Trabalhe de qualquer lugar: nosso projeto foi construĂ­do para atuar a distĂąncia. Trabalhe de qualquer lugar do Brasil ou do mundo com a sua unidade. Fature com a V4: AtĂ© 50 clientes atribuĂ­dos em um prazo de 12 meses com ticket mĂ©dio de R$3.500,00. Suporte nos projetos: Conte com a colaboraĂ§ĂŁo do time de Customer SuccessÂ  em seus projetos no dia a dia. Nossa equipe presta o suporte necessĂĄrio. Apoio administrativo: Suporte consultivo nos aspectos administrativos gerais do negĂłcio e suporte ativo na cobranĂ§a e negociaĂ§ĂŁo de inadimplĂȘncia. NegĂłcio Inovador: A Franquia V4 Ă© um modelo de negĂłcio inovador, Ășnico, escalĂĄvel que estĂĄ revolucionando o mercado de marketing no paĂ­s. AcessĂ­vel: Com um custo de operaĂ§ĂŁo muito baixo, vocĂȘ pode comeĂ§ar o seu negĂłcio com um escritĂłrio enxuto. Lucrativo: Um franqueado disciplinado pode ter um lucro de atĂ© 30% sobre o faturamento, jĂĄ nos primeiros meses de atuaĂ§ĂŁo com os clientes. EscalĂĄvel: A V4 oferece um plano de crescimento robusto, com um planejamento detalhado, que possibilita a escala do negĂłcio. Â  VANTAGENS DE SER UM FRANQUEADO V4: Know How Compartilhado: VocĂȘ ganharĂĄ uma formaĂ§ĂŁo completa Cientista do Marketing Digital, para aprender as tĂ©cnicas e conceitos que jĂĄ foram testadas e consolidadas na V4 Company. \nEsses ensinamentos sĂŁo aplicados diariamente em nossos mais de 172 escritĂłrios. Plano de crescimento agressivo: A V4 planeja crescer muito nos prĂłximos anos, para se tornar uma das maiores franqueadoras do Brasil e vocĂȘ terĂĄ a oportunidade de crescer sua unidade junto com a gente. \nEm 2 anos, o nosso crescimento se mostra rĂĄpido e consistente e a tendĂȘncia Ă© continuarmos fortemente em ascensĂŁo, atingindo cada vez mais clientes e unidades. AtĂ© 20k de MRR (receita recorrente mensal): ApĂłs adquirir a Franquia, vocĂȘÂ  tem seus primeiros clientes garantidos pela V4 com um valor mĂ©dio de serviĂ§o de R$ 4.000 por cliente. ApĂłs vocĂȘÂ  seguir o processo de prestaĂ§ĂŁo de serviĂ§o com excelĂȘncia para esses primeiros clientes, poderemos continuar delegando clientes para sua unidade atĂ© alcanĂ§ar seus objetivos de faturamento. IPO em 2030: O grande objetivo da V4 Company Ă© chegar Ă  marca de 100 mil clientes juntamente com a abertura de capital na bolsa de valores atravĂ©s de um IPO. Sem barreiras geogrĂĄficas: Todo nosso sistema de prestaĂ§ĂŁo de serviĂ§o foi desenvolvido para ser realizado Ă Â  distĂąncia. \nSendo assim, vocĂȘÂ  pode atuar em qualquer lugar do Brasil. JĂĄ contamos com franqueados em todas as regiĂ”es do paĂ­s. \nIndependente de quantas franquias jĂĄ existirem na sua cidade, vocĂȘ pode fazer parte da V4 atendendo clientes de qualquer lugar. AuxĂ­lio total da matriz: Todas as unidades franqueadas tĂȘm livre acesso Ă  toda equipe V4 matriz, bem como todas unidades franqueadas. \nTemos um canal de comunicaĂ§ĂŁo onde Ă© possĂ­vel solicitar apoio com os projetos, dĂșvidas sobre contrataĂ§ĂŁo de pessoas, cases de clientes, etc. \nA V4 Matriz acompanha o andamento dos projetos, os resultados dos mesmos, o desempenho do franqueado, acompanhamento dos processos e gestĂŁo da unidade. Torne-se um Equity Partner da V4 Company: O plano Ă© anualmente premiar os melhores franqueados com participaĂ§ĂŁo em todo o negĂłcio . Assim, alĂ©m dos ganhos do negĂłcio, vocĂȘ conquista um patrimĂŽnio de alto valor.\nÂ  TEMPO PARA PAYBACK (retorno do investimento): FRANQUIA V4\n8 a 18 meses\nEm atĂ© 60 dias vocĂȘ recebe seus primeiros clientes, e somente com eles em 9 meses vocĂȘ jĂĄ pode faturar \"de volta\" todo seu investimento. \nEm 12 meses de retenĂ§ĂŁo do cliente, o payback Ă© garantido dentro deste perĂ­odo citado acima.  OUTRAS FRANQUIAS\n36 a 48 meses Outras franquias do mercado apresentam um risco muito maior pois nĂŁo existe nenhuma garantia de retorno, alĂ©m de exigirem capital inicial muito maior.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 273, NULL, NULL, '2026-03-09 02:23:53.499', 'https://franquias.portaldofranchising.com.br/franquia-v4-company/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 1, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77d300ndeh0sok8ovub4', 'ORAL CENTTER CLĂNICAS ODONTOLĂGICAS', 'oral-centter-clinicas-odontologicas', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'CLINICA ODONTOLOGICAS', 2022, 2023, '[\"https://www.youtube.com/watch?v=gTkSHWD5IT4\"]', '2026-04-01 02:00:09.568', '2025-08-05 22:20:28.935', 878, NULL, 1, 2020, 'SOBRE A ORAL CENTTER  CONEXĂO QUE NOS LEVA ALĂM! Â  Por que investir em odontologia? Fundada em 2020 pela dentista e empresĂĄria Priscila GusmĂŁo, a Oral Centter nasceu da necessidade de criar um modelo de negĂłcio responsĂĄvel, que oferece suporte integral e auxilia os dentistas a conquistarem sua prĂłpria clĂ­nica. A experiĂȘncia de Priscila como ex-franqueada de uma rede falida foi o ponto de partida para desenvolver uma proposta inovadora e sĂłlida. Com foco nas classes C e D, a rede se destaca por validar unidades em cidades a partir de 15 mil habitantes, oferecendo soluĂ§Ă”es acessĂ­veis e de qualidade em regiĂ”es pouco exploradas por grandes redes. Â  ExpansĂŁo planejada e resultados sĂłlidos A Oral Centter jĂĄ possui 81 unidades, sendo 39 em operaĂ§ĂŁo, e segue um plano de expansĂŁo nos estados de Minas Gerais, GoiĂĄs e Nordeste. O objetivo Ă© crescer com responsabilidade e garantir suporte completo ao franqueado, desde a assinatura do contrato atĂ© o dia a dia da operaĂ§ĂŁo. Â  Diferenciais que fazem a diferenĂ§a Treinamentos semanais e mensais nas ĂĄreas comercial, clĂ­nica, gestĂŁo e finanĂ§as. Marketing completo e padronizado, gerenciado pela prĂłpria rede, sem necessidade de terceirizaĂ§ĂŁo. ClĂ­nicas com faturamento mĂ©dio de R$120.000,00 a R$140.000,00, oferecendo atendimento humanizado e uma experiĂȘncia comparĂĄvel ao pĂșblico A. Â  Mais do que expandir, a Oral Centter tem como missĂŁo realizar sonhos: Dos dentistas que abrem suas clĂ­nicas prĂłprias. Dos pacientes que encontram um atendimento acessĂ­vel e de qualidade.', NULL, 'MINAS GERAIS', 1, NULL, 59, NULL, NULL, '2026-03-09 02:25:45.869', 'https://franquias.portaldofranchising.com.br/franquia-oral-centter-clinicas-odontologicas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '235000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77db00neeh0s03kzu6ko', 'CASTILLA IDIOMAS', 'castilla-idiomas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escola de idiomas com desenvolvimento linguĂ­stico e cultural.', 2021, 2022, '[\"https://www.youtube.com/watch?v=9PmDKMr3whg\",\"https://www.youtube.com/watch?v=q4a8pCejlYA\",\"https://www.youtube.com/watch?v=YnOVshepw5c\",\"https://www.youtube.com/watch?v=w9awREMTpYU\"]', '2026-04-01 02:00:09.578', '2025-08-05 22:20:28.943', 879, NULL, 1, 1996, 'HĂĄ 27 anos, o Castilla IdiomasÂ tem sido a escola de idiomas que tem transformado muitas histĂłrias atravĂ©s de um aprendizado rĂĄpido, melhor e completo. Todos os 7 idiomas sĂŁo ensinados por meio de uma metodologia comunicativa, pois nossa principal meta Ă© promover a aprendizagem da lĂ­ngua estrangeira com atividades que priorizem a comunicaĂ§ĂŁo que envolvem quatro competĂȘncias: auditiva, oral, leitura e escrita. Atualmente temos 16 unidades no estado do ParĂĄ e duas unidades em Fortaleza, mais para nĂłs o cĂ©u Ă© o limite, o nosso objetivo Ă© ter um Castilla Idiomas nos 4 cantos deste paĂ­s. Nossos diferenciais: Metodologia de ensino de idiomas para Brasileiros.\n\tAs metodologias de ensino de InglĂȘs, Espanhol e FrancĂȘs sĂŁo prĂłprias do Castilla, contendo livros, ĂĄudios e vĂ­deos animados.\n\tEsse material foi desenvolvido para o aprendizado de idiomas por Brasileiros.\n\tÂ  Segundo idioma em 18 meses.\n\tNossa metodologia oferece cursos completos de idiomas em 18 meses.\n\tÂ  MatrĂ­culas 365 dias por ano.\n\tO Castilla oferece os cursos Regulares e Flex (InglĂȘs, FrancĂȘs e Espanhol) o que proporciona matrĂ­culas 365 dias por ano.\n\tÂ  Sistema Castillaflex de aulas on-line.\n\tO Castilla desenvolveu um sistema de marcaĂ§ĂŁo e acesso a aulas on-line para seus cursos Flex, o que possibilita aos alunos marcarem suas aulas e assistirem de qualquer lugar.\n\tAs unidades franqueadas compartilham as aulas e formam uma imensa estrutura de oferta diĂĄria de aulas.', NULL, 'PARĂ', 1, NULL, 15, NULL, NULL, '2026-03-09 02:26:40.373', 'https://franquias.portaldofranchising.com.br/franquia-castilla-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '62500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
