INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77do00ngeh0sxmukzl98', 'BENGĂ', 'bengo', NULL, 'AlimentaĂ§ĂŁo', 'Docerias, Padarias e CafĂ©s', 'A BengĂŽ AĂ§aĂ­ se estabeleceu como lĂ­der no MaranhĂŁo e, agora, estamos expandindo para mais 6 estados. Recorde de Vendas de Franquias, contabilizamos mais de 20 lojas vendidas em menos de um ano', 2023, 2023, NULL, '2026-04-01 02:00:09.596', '2025-08-05 22:20:28.956', 881, NULL, 1, 2015, '', NULL, 'MARANHĂO', 1, NULL, 77, NULL, NULL, '2026-03-09 02:27:53.982', 'https://franquias.portaldofranchising.com.br/franquia-bengo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77dv00nheh0sl8qcpa7z', 'USINA DE MASSAS', 'usina-de-massas', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Restaurante especializado em massas e molhos.', 2012, 2012, NULL, '2026-04-01 02:00:09.606', '2025-08-05 22:20:28.963', 882, NULL, 1, 2002, 'A Usina de Massas foi inaugurada em 2002 com o objetivo de ser referĂȘncia em massas e molhos na cidade de Porto Alegre. \nO projeto originou-se da necessidade percebida pelos dois sĂłcios fundadores de ter um restaurante que reunisse Ăłtima comida, excelente atendimento agregados a uma arquitetura acolhedora. Partindo desta percepĂ§ĂŁo escolheu-se o segmento de massas e molhos pelo grande nĂșmero de apreciadores dessa combinaĂ§ĂŁo e por entender que havia uma carĂȘncia de propostas deste tipo no mercado de Porto Alegre. \nEssas premissas levaram Ă  escolha de uma bela casa da dĂ©cada de 50, no charmoso bairro Moinhos de Vento, onde foi construĂ­da a Usina de Massas. A busca por encantar o cliente Ă© alcanĂ§ada atravĂ©s da Ăłtima comida, atendimento profissionalizado e ambiente acolhedor. \nO restaurante possui sistema de delivery, loja com massas frescas, molhos congelados e take away. A Usina de Massas disponibiliza em seu websiteÂ diversas informaĂ§Ă”es como cardĂĄpio, carta de vinhos, produtos do ArmazĂ©m da Usina, promoĂ§Ă”es e diversas informaĂ§Ă”es Ășteis para seus clientes.\"', NULL, 'RIO GRANDE DO SUL', 1, NULL, 21, NULL, NULL, '2026-03-09 02:28:13.803', 'https://franquias.portaldofranchising.com.br/franquia-usina-de-massas-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77e000nieh0shsrhpjgz', 'POPCORN GOURMET', 'popcorn-gourmet', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'SeleĂ§ĂŁo de matĂ©ria-prima de altĂ­ssima qualidade que garantem cobertura generosa, crocĂąncia e textura aveludada. OperaĂ§ĂŁo enxuta e produto pronto e As melhores Pipocas da vida.', 2016, 2022, '[\"https://www.youtube.com/watch?v=uoEsO6k3DI8\",\"https://www.youtube.com/watch?v=lXTTplTF3jY\",\"https://www.youtube.com/watch?v=1KDKpZxnOQw\",\"https://www.youtube.com/watch?v=cDz1uw-XN-s\"]', '2026-04-01 02:00:09.616', '2025-08-05 22:20:28.968', 883, NULL, 1, 2015, 'Mais que uma Pipoca, UMA EXPERIĂNCIA!Â  Aqui, somos viciados em qualidade, portanto, todo processo de fabricaĂ§ĂŁo das Pipocas passa por rĂ­gido controle de qualidade. Utilizamos as melhores matĂ©rias-primas no mercado, a fim de oferecer ao cliente a melhor experiĂȘncia. Hoje, sĂŁo 15 sabores das melhores Pipocas, sendo trĂȘs deles homologados e licenciados pela NestlĂ©: Feito com Alpino, Feito com SensaĂ§ĂŁo e Melhor com Ninho Trufado, o recordista de vendas.Â  Preocupada com sustentabilidade, nossa CEO e Chef Elaine Moura, criou vĂĄrias outras receitas a partir de sobras de insumos deliciosos da fabricaĂ§ĂŁo de pipocas: Cappuccinos, FrapĂȘs, Chocolates, CafĂ©s gelados, sĂŁo algumas das receitas que deram inĂ­cio a nova rede da franquia de cafeterias, Pop Coffee.  DiferencialÂ \nOs produtos sĂŁo feitos a partir de tĂ©cnicas diferenciadas, que garantem alta crocĂąncia. AlĂ©m disso, sĂŁo utilizadas matĂ©rias-primas de altĂ­ssima qualidade e tĂ©cnica. E sĂŁo feitos sem o uso de conservantes artificiais. Um produto completamente distintivo e superior Ă  concorrĂȘncia!Â  Â  Sobre nĂłs Ao falar da histĂłria da PopCorn Gourmet, nĂŁo podemos deixar de mencionar a responsĂĄvel pelo sucesso da marca: Chef Elaine Moura! AlĂ©m de Chef de cozinha, Elaine Ă© jornalista, mĂŁe, empresĂĄria e fundadora da PopCorn Gourmet. Durante 19 anos ficou Ă  frente de um dos mais luxuosos buffets de GoiĂąnia, e em 2014 sentiu a necessidade de criar uma receita autoral que servisse de presente a seus clientes. \nSendo apaixonada por doces e pipocas, focou em pesquisas por mais de um ano atĂ© acertar a receita perfeita. Assim surgiu a PopCorn Gourmet, que em 2015, foi lanĂ§ada pela Chef na CASACOR. O sucesso foi instantĂąneo, garantindo capa no principal jornal da cidade.Â  A PopCorn GourmetÂ  Devido ao grande sucesso na CASACOR, a Chef Elaine, em 2015, instalou quiosques de pipocas nos principais shoppings de GoiĂąnia. Ao perceber que ganhou o pĂșblico da cidade, decidiu em 2016, conquistar novos negĂłcios inaugurando sua primeira unidade franqueada em RibeirĂŁo Preto, de lĂĄ pra cĂĄ, somamos mais de 50 unidades no Brasil, fĂĄbrica e quiosque recĂ©m inaugurados em Miami e em breve fĂĄbrica em Portugal. AlĂ©m do mercado de franquias, a marca agora comercializa seus produtos em embalagens Stand Up Pouch, que ocupam as gĂŽndolas dos melhores supermercados e empĂłrios do Brasil. \nTendo como principal ponto de venda a rede de supermercados Carrefour.', NULL, 'GOIĂS', 1, NULL, 46, NULL, NULL, '2026-03-09 02:28:57.259', 'https://franquias.portaldofranchising.com.br/franquia-popcorn-gourmet/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '48000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
