LO', 1, NULL, 564, NULL, NULL, '2026-03-09 02:30:59.787', 'https://franquias.portaldofranchising.com.br/franquia-splash/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77el00nmeh0sm9uelt8o', 'BASICOISAS EXPRESS', 'basicoisas-express', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Mercado autĂŽnomo para condomĂ­nios e empresas, aberto 24 hrs. Home market para comodidade de moradores e funcionĂĄrios. Mini mercado inteligente automatizado. Mercado sem funcionĂĄrios, tendĂȘncia mundial', 2022, 2023, NULL, '2026-04-01 02:00:09.654', '2025-08-05 22:20:28.989', 887, NULL, 1, 2018, '', NULL, 'SANTA CATARINA', 1, NULL, 82, NULL, NULL, '2026-03-09 02:31:37.810', 'https://franquias.portaldofranchising.com.br/franquia-basicoisas-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '10100', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ep00nneh0sjo40pxw0', 'BURGER KING BRASIL', 'burger-king-brasil', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Uma empresa inovadora, conduzida por pessoas experientes que tĂȘm na qualidade dos produtos, na excelĂȘncia do atendimento e na busca incessante por vantagens competitivas.', 2011, 2018, NULL, '2026-04-01 02:00:09.663', '2025-08-05 22:20:28.994', 888, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1953, 'Essa Ă© a hora de se juntar a franquia Burger King Brasil. Fundado em 1954, o BURGER KINGÂźÂ Ă© a segunda maior rede de hambĂșrgueres do mundo. Lar original do WHOPPERÂź, possui mais de 15 mil lojas, servindo mais de 11 milhĂ”es de consumidores por dia em mais de 100 paĂ­ses ao redor do mundo.  Aproximadamente 90% dos restaurantes BURGER KINGÂźÂ pertencem e sĂŁo operados por franquias independentes, muitas delasÂ administradasÂ por empresas familiares que estĂŁo no ramo hĂĄ dĂ©cadas. A franquia Burger King do Brasil Ă© um master franqueado doÂ Burger King CorporationÂ no paĂ­s. Nossa marca estĂĄ aqui desde 2004, quando inauguramos nosso primeiro restaurante no Shopping Ibirapuera, mas foi em 2011, apĂłs o Burger King Corporation ser adquirido pelo grupo 3G capital, que iniciamos a nossa operaĂ§ĂŁo prĂłpria aqui no paĂ­s, atravĂ©s de uma joint venture entre Vinci Partners e 3G Capital. De 2011 para cĂĄ jĂĄ crescemos muito, e nossos nĂșmeros comprovam isso. Somos uma empresa que em meados de 2011 possuĂ­a alguns colaboradores em SĂŁo Paulo distribuĂ­dos entre 17 pontos de venda. Hoje, jĂĄ somamos mais de 11 mil colaboradores e estamos presentes em todos os estados brasileiros, com mais de 600 pontos de venda. Acreditamos que o nosso bem mais valioso Ă© a nossa Gente. Por isso, apostamos na carreira de nossos colaboradores, com o objetivo de impulsionar a visĂŁo de dono daqueles que, junto com a gente, acreditam em um Sonho Grande: ser a mais prazerosa experiĂȘncia de alimentaĂ§ĂŁo. Para sustentar esse sonho, nos focamos em quatro pilares: sermos a marca de fast food preferida, mais rentĂĄvel, com pessoas talentosas e com forte presenĂ§a nacional.', 'What is Lorem Ipsum?\r\nLorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry\'s standard dummy text ever since the 1500s, when an unknown printer took a galley of type and scrambled it to make a type specimen book. It has survived not only five centuries, but also the leap into electronic typesetting, remaining essentially unchanged. It was popularised in the 1960s with the release of Letraset sheets containing Lorem Ipsum passages, and more recently with desktop publishing software like Aldus PageMaker including versions of Lorem Ipsum.\r\n\r\nWhy do we use it?\r\nIt is a long established fact that a reader will be distracted by the readable content of a page when looking at its layout. The point of using Lorem Ipsum is that it has a more-or-less normal distribution of letters, as opposed to using \'Content here, content here\', making it look like readable English. Many desktop publishing packages and web page editors now use Lorem Ipsum as their default model text, and a search for \'lorem ipsum\' will uncover many web sites still in their infancy. Various versions have evolved over the years, sometimes by accident, sometimes on purpose (injected humour and the like).\r\n\r\n\r\nWhere does it come from?\r\nContrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of \"de Finibus Bonorum et Malorum\" (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, \"Lorem ipsum dolor sit amet..\", comes from a line in section 1.10.32.\r\n\r\nThe standard chunk of Lorem Ipsum used since the 1500s is reproduced below for those interested. Sections 1.10.32 and 1.10.33 from \"de Finibus Bonorum et Malorum\" by Cicero are also reproduced in their exact original form, accompanied by English versions from the 1914 translation by H. Rackham.\r\n\r\nWhere can I get some?\r\nThere are many variations of passages of Lorem Ipsum available, but the majority have suffered alteration in some form, by injected humour, or randomised words which don\'t look even slightly believable. If you are going to use a passage of Lorem Ipsum, you need to be sure there isn\'t anything embarrassing hidden in the middle of text. All the Lorem Ipsum generators on the Internet tend to repeat predefined chunks as necessary, making this the first true generator on the Internet. It uses a dictionary of over 200 Latin words, combined with a handful of model sentence structures, to generate Lorem Ipsum which looks reasonable. The generated Lorem Ipsum is therefore always free from repetition, injected humour, or non-characteristic words etc.\r\n\r\n5\r\n\tparagraphs\r\n\twords\r\n\tbytes\r\n\tlists\r\n\tStart with \'Lorem\r\nipsum dolor sit amet...\'\r\n', 'SĂO PAULO', 1, NULL, 1238, NULL, NULL, '2026-03-09 02:31:56.924', 'https://franquias.portaldofranchising.com.br/franquia-burger-king-valor/', NULL, NULL, NULL, 1, 5, 5, 1, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77eu00noeh0sauosdbze', 'EXPERIMENTO', 'experimento', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'EducaĂ§ĂŁo Internacional e programas de intercĂąmbio cultural no mundo inteiro', 1998, 2004, NULL, '2026-04-01 02:00:09.672', '2025-08-05 22:20:28.998', 889, NULL, 1, 1964, 'A Experimento Ă© a maior rede especializada exclusivamente em intercĂąmbio cultural. Desde 1964 atuando no paĂ­s, Ă© a pioneira no Brasil e, portanto, quem mais entende do assunto. Somos Experts em intercĂąmbio, com muito orgulho e paixĂŁo pelo o que fazemos. Atualmente contamos com mais 60Â lojas, sendo 5Â prĂłprias. AlĂ©m de ser membro das mais importantes federaĂ§Ă”es internacionais, aÂ ExperimentoÂ Ă© membro exclusivo da FEIL (Federation of the Experiment in International Living), primeira do mundo a promover vivĂȘncia intercultural no mundo, em 1932. TambĂ©m vem conquistando desde 2011 o Selo de ExcelĂȘncia em Franchising pela ABF e eleita a melhor Franquia de Cultura e Lazer do Brasil em 2015 e 2017, pelo Guia de Franquias Pequenas Empresas, Grandes NegĂłcios. A franquia Experimento foi eleita por 5 anos consecutivos (2010 | 2011 | 2012 | 2013 e 2014), a melhor agĂȘncia de intercĂąmbio da AmĂ©rica Latina atravĂ©s do Star Awards for International Education, um prĂȘmio internacional promovido pela Language Travel Magazine, em Londres. A votaĂ§ĂŁo Ă© realizada pelas organizaĂ§Ă”es educacionais internacionais, que elegem as melhores escolas e agĂȘncias do mundo inteiro. Com a 5ÂȘ premiaĂ§ĂŁo, a Experimento se torna membro do seleto grupo STM Super Star Hall of Fame, honrada com o tĂ­tulo perpetuamente.\nÂ \nTambĂ©m vem conquistando desde 2011 o Selo de ExcelĂȘncia em Franchising pela ABF, incluindo o de 2016, o que certifica importĂąncia e satisfaĂ§ĂŁo dentre seus franqueados. Eleita a melhor Franquia de Cultura e Lazer do Brasil em 2015 e 2017, pelo Guia de Franquias Pequenas Empresas, Grandes NegĂłcios.\nÂ \nPara pessoas com perfil comercial e espĂ­rito empreendedor, a rede traz a grande chance de investir em um negĂłcio em constante expansĂŁo. O mercado de educaĂ§ĂŁo internacional cresce em mĂ©dia 20% ao ano no Brasil e movimentou mais de US$ 1 bilhĂŁo no paĂ­s em 2012, o que representa uma excelente oportunidade de negĂłcio. O franqueado Experimento conta com completa estrutura Ă  disposiĂ§ĂŁo para implantaĂ§ĂŁo e acompanhamento do novo negĂłcio.\nÂ \nA rede oferece programas que atendem aos mais altos padrĂ”es de qualidade. Isto significa programas de intercĂąmbio com as melhores instituiĂ§Ă”es do mundo, atendimento realizado por profissionais qualificados no Brasil e no exterior, rede com mais de 50 lojas em todo o paĂ­s e uma linha completa de produtos e serviĂ§os para que a viagem seja tranquila e segura.', NULL, 'SĂO PAULO', 1, NULL, 54, NULL, NULL, '2026-03-09 02:32:54.881', 'https://franquias.portaldofranchising.com.br/franquia-experimento-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
