INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77f900nreh0sve79hh48', 'MUNDO TERRA', 'mundo-terra', NULL, 'Moda', 'VestuĂĄrios', 'Desde 1999 proporcionando conexĂ”es reais e verdadeiras experiĂȘncias equipando nossos clientes para suas viagens e aventuras com mais conforto e seguranĂ§a pelo nosso planeta, nosso Mundo Terra!', 2014, 2020, '[\"https://www.youtube.com/watch?v=gx5nSMNhbxo\"]', '2026-04-01 02:00:09.698', '2025-08-05 22:20:29.014', 892, NULL, 1, 1999, 'A MUNDO TERRA trouxe um pouco do mundo outdoor e do estilo de vida ao ar livre para cidade quando abriu sua primeira unidade em 1999 na Pedroso de Morais 1085 no coraĂ§ĂŁo de Pinheiros em Sampa! Produtos como acessĂłrios calĂ§ados, equipamentos e vestuĂĄrio para atividades e viagens de lazer e aventura estavam disponĂ­veis aos entusiastas desse mercado que tinham dificuldade em encontrar esses produtos no Brasil.Â  Iniciamos milhares de clientes ao longo dos anos com informaĂ§ĂŁo, conforto e seguranĂ§a em suas atividades que muitas vezes sĂŁo verdadeiros projetos de vida, sonhos que se materializam. Somos especialistas, verdadeiramente, apaixonados pelo nosso mercado, a inovaĂ§ĂŁo estĂĄ muito presente em nosso dia a dia. Curiosos! Estamos sempre procurando evoluir pensando com muito carinho nas pessoas que envolvem todo nosso ecossistema para que tenham uma experiĂȘncia inesquecĂ­vel, desde o nosso time, no carinho e cuidado dentro de casa nas informaĂ§Ă”es que transmitimos consultoria dos produtos, serviĂ§o que entregamos para aliados ao planejamento e a preparaĂ§ĂŁo dos nossos clientes sejam fatores determinantes em suas conquistas! Juntos vamos engajar mais pessoas no estilo de vida ao ar livre e disseminar essa Cultura, impactando a vida das pessoas para que criem mais conexĂ”es, e que estas possam ser seu o âcombustĂ­velâ para que melhorem sua qualidade de vida, tragam mais saĂșde e bem-estar no longo prazo! ConstruĂ­mos assim uma sociedade mais humana, lindas histĂłrias, contada por cada uma dessas pessoas, a cada momento mĂĄgico vivido, a cada novo suspiro pelo fato de ter feito algo novo pela primeira vez, e queremos que vocĂȘ venha participar dessa jornada conosco! Venha para o nosso Mundo!', NULL, 'SĂO PAULO', 1, NULL, 6, NULL, NULL, '2026-03-09 02:35:11.891', 'https://franquias.portaldofranchising.com.br/franquia-mundo-terra/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '349000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
