INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77fk00nteh0sap5ilbr4', 'SUPERRICO', 'superrico', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'A SuperRico Ă© uma Plataforma de SaĂșde Financeira que conecta pessoas e planejadores financeiros. AtravĂ©s dos nossos serviĂ§os ajudamos os brasileiros a manterem uma boa saĂșde financeira.', 2021, 2022, '[\"https://www.youtube.com/watch?v=8f63aaDU-ZU\",\"https://www.youtube.com/watch?v=xumSh18DkqY\",\"https://www.youtube.com/watch?v=px9MuqjZUlQ\",\"https://www.youtube.com/watch?v=Gh6NLAt0Sp8\"]', '2026-04-01 02:00:09.716', '2025-08-05 22:20:29.024', 894, NULL, 1, 2017, 'A SuperRico nasceu em 2014 como um blog de conteĂșdo de educaĂ§ĂŁo financeira. Em 2016 se tornou uma empresa de prestaĂ§ĂŁo de serviĂ§os de planejamento financeiro para pessoas e famĂ­lias. A empresa tem a missĂŁo de tornar possĂ­vel a todos os seres humanos a conquista e a manutenĂ§ĂŁo do bem-estar financeiro. Nossa meta Ă© democratizar o acesso Ă  educaĂ§ĂŁo financeira e ao planejamento financeiro para que toda a sociedade brasileira conquiste e mantenha uma vida financeira saudĂĄvel. Criamos uma plataforma de educaĂ§ĂŁo financeira e planejamento financeiro e desenvolvemos mecanismos que a tornasse disponĂ­vel Ă  sociedade de tal forma que todo cidadĂŁo possa ter acesso e se sinta motivado a utilizĂĄ-la para atingir um bom nĂ­vel de bem-estar financeiro. Disseminamos nossa metodologia âCurva de Vitalidade FinanceiraÂźâ por meio de ferramentas que possam ser utilizadas por todas as pessoas, fazendo parcerias com as mais variadas instituiĂ§Ă”es e empresas, formando uma grande rede nacional onde todos serĂŁo beneficiados. A SuperRico sempre oferecerĂĄ aos seus clientes, aos planejadores financeiros e a sociedade em geral, soluĂ§Ă”es que melhor atendam Ă s necessidades dessas pessoas, sem obter favorecimentos ou benefĂ­cios das empresas envolvidas no fornecimento desses produtos e serviĂ§os. Nossos valores: Pessoas comprometidas e engajadas IndependĂȘncia para alinhar interesses dos clientes e planejadores financeiros TransparĂȘncia em tudo que fazemos Compromisso com a diversidade, equidade e inclusĂŁoÂ  Cumprimento do cĂłdigo de Ă©tica Crescimento com responsabilidade social e sustentabilidade', NULL, 'SĂO PAULO', 1, NULL, 67, NULL, NULL, '2026-03-09 02:36:19.863', 'https://franquias.portaldofranchising.com.br/franquia-superrico/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '12500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
