stram e comprovamÂ suaÂ excelĂȘncia.', NULL, 'SĂO PAULO', 1, NULL, 389, NULL, NULL, '2026-03-09 18:01:14.237', 'https://franquias.portaldofranchising.com.br/franquia-igui-lazer/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '2150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
