INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ip00o7eh0s8ja640r7', 'MAISLASER DEPILAĂĂO', 'maislaser-depilacao', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'A Maislaser by Ana Hickmann Ă© uma franquia lucrativa e consolidada em depilaĂ§ĂŁo e estĂ©tica a laser, com operaĂ§ĂŁo simplificada, tecnologia exclusiva e rentabilidade acima de 30%, a maior do mercado!', 2018, 2019, '[\"https://www.youtube.com/watch?v=3-PcvjQYweY\"]', '2026-04-01 02:00:09.860', '2025-08-05 22:20:29.138', 908, NULL, 1, 2018, 'A Maislaser by Ana Hickmann Ă© uma rede de clĂ­nicas reconhecida pela excelĂȘncia em depilaĂ§ĂŁo e estĂ©tica a laser, combinando tecnologia exclusiva e resultados comprovados. Nossos tratamentos sĂŁo seguros, confortĂĄveis e eficazes para todos os tons de pele, inclusive as bronzeadas. DepilaĂ§ĂŁo a laser: O equipamento exclusivo da Maislaser (Maistech) reĂșne as trĂȘs principais tecnologias do mercado com trĂȘs comprimentos de ondas que entregam melhor resultado e produtividade. MAIS seguro e confortĂĄvelÂ  MAIS eficaz / 1800W MAIS econĂŽmico MAIS rapidez na aplicaĂ§ĂŁoÂ  MAIS autoestima e bem-estar Tratamentos dermato estĂ©ticos: A Maislaser tambĂ©m realiza mais de 22 protocolos para tratamentos dermato estĂ©ticos em todo o corpo. O equipamento exclusivo utiliza o laser Ndyag e atende os procedimentos mais procurados, como remoĂ§ĂŁo de tatuagem e micropigmentaĂ§ĂŁo, clareamento Ă­ntimo e de manchas, tratamento para acne, melasma, rosĂĄcea, estrias, olheiras, cicatrizes, Peeling de Hollywood e muito mais. Os sĂłcios: *Sidney Kalaes:Â presidente do Grupo Kalaes (Holding Multissetorial de Franquias), tem formaĂ§ĂŁo em administraĂ§ĂŁo de empresas e mais de 31 anos de experiĂȘncia como lĂ­der, master e fundador de vĂĄrias marcas de sucesso no mercado.Â  *Ana Hickmann:Â apresentadora e empresĂĄria de sucesso que traz para a Maislaser muita credibilidade, forĂ§a, conhecimento, valor e exposiĂ§ĂŁo, proporcionando diferenciais e crescimento aos envolvidos no negĂłcio.Â  *Wlamir Bello:Â fundador da rede Maislaser, empresĂĄrio especialista em gestĂŁo empresarial, estratĂ©gia de negĂłcios e marketing. Tem MBA em gestĂŁo empresarial e graduaĂ§ĂŁo em publicidade e propaganda.', NULL, 'SĂO PAULO', 1, NULL, 190, NULL, NULL, '2026-03-09 03:09:09.513', 'https://franquias.portaldofranchising.com.br/franquia-maislaser-depilacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
