INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77j900obeh0svve9utcq', 'ERA', 'era', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Consultoria em eficiĂȘncia operacional, otimizaĂ§ĂŁo de custos, soluĂ§Ă”es inovadoras em estratĂ©gia de negĂłcios, gestĂŁo empresarial, otimizaĂ§ĂŁo de processos e reduĂ§ĂŁo de custos', 1992, 2005, '[\"https://www.youtube.com/watch?v=4pmTpi9rM7M\",\"https://www.youtube.com/watch?v=Zz60nYjeSNU\"]', '2026-04-01 02:00:09.897', '2025-08-05 22:20:29.157', 912, NULL, 1, 1992, 'FAĂA PARTE DA REDE LĂDER EM CONSULTORIA EMPRESARIAL Expense Reduction Analysts (ERA) Ă© uma das maioresÂ  franquiasÂ  em Business Strategy, EficiĂȘncia OperacionalÂ  eÂ  GestĂŁo Empresarial, com mais de 700 consultores, presentes em mais de 35 paĂ­ses. Em 2019, 2020 e 2021 ERA foi ganhadora do âSelo de ExcelĂȘncia em Franchising â ABFâ. Foi nomeada \" World-Class Franchiseâ \" pelo Franchise Research Institute em 2015, 2016 e 2017. Em 2018 & 2019, a ERA foi premiada como âBest White-Collar Franchiseâ pela Global Franchise Magazine. PrĂȘmios esses que atestam a seriedade e comprometimento da ERA com seus franqueados ao redor do mundo. Ao longo desses 30 anos, atendemos mais de 5.000 clientes,Â  entregamosÂ  mais de 30.000 projetos, dos mais diversos segmentos,Â  como por exemplo logĂ­stica integrada, matriz energĂ©tica, seguranĂ§a patrimonial e muito mais. Essa diversificada atuaĂ§ĂŁoÂ  faz daÂ  ERAÂ  a maior e mais experiente consultoria em gestĂŁo empresarial do mundo. Noss@Â  Consultor IdealÂ âÂ Na Expense Reduction Analysts (ERA)Â  noss@ candidat@ ideal Ă© inteligente, motivad@ e tem a disposiĂ§ĂŁo de seguir uma comprovada metodologia de 30 anos de mercado. Sente-se confortĂĄvel quer seja com donos de empresas ouÂ  executiv@s C-level. Ă abert@Â  aÂ  trabalhar em parceria com outr@s franquead@s ERA, utilizando sua expertise amparad@ por nossa dinĂąmica de negĂłcios.Â  Junte-se a nĂłs paraÂ  o prĂłximo passo em sua carreira, onde vocĂȘ serĂĄ SENHOR DO SEU TEMPO e utilizarĂĄ todo o conhecimento adquirido em sua carreira profissional. VocĂȘ temÂ  desejo de assumir o controle do seu futuro?Â â Nossa rede global de mais de 700 consultores vem de muitas indĂșstrias diferentes. O que tod@s tĂȘm em comum Ă© o desejo de assumir o controle de suas vidas, ganhar o que merecem e alavancarÂ  de forma significativa sua experiĂȘncia profissional . AprimoreÂ  suas habilidades com nosso conhecimento âÂ NĂłs ajudamos a aprimorarÂ  suas habilidades e potencializar seu conhecimentoÂ  para que vocĂȘ possa operar seu prĂłprio negĂłcio de consultoria ERA. Combinar sua ambiĂ§ĂŁo e expertise com nossa rede de Franquead@s, nossosÂ  processos eÂ  ferramentas Ă© uma maneira comprovada de acelerar o seu caminho para o sucesso. Treinamento constanteÂ âÂ ERA conta com uma exclusiva academia de treinamento de nĂ­vel internacional (ERA Training Academy), que @ ajudarĂĄ aÂ  iniciar sua jornada de ĂȘxito como consultor@ de alto desempenho. VocĂȘ trabalharĂĄ em estreita colaboraĂ§ĂŁo com nossas equipes de apoioÂ  para desde o inĂ­cio empreender amparado por nossa experiencia.Â  Â E mais:Â  em nossa plataforma digital LearnUpon vocĂȘ terĂĄ acesso ilimitadoÂ  a conteĂșdo de melhores prĂĄticas, aprimoramento tĂ©cnico e reciclagem constante para impulsionar seu negĂłcio.', NULL, 'SĂO PAULO', 1, NULL, 11, NULL, NULL, '2026-03-09 18:10:20.423', 'https://franquias.portaldofranchising.com.br/franquia-era-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '316925', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77je00oceh0s5itttr4p', 'LOPES', 'lopes', NULL, 'Casa e ConstruĂ§ĂŁo', 'ServiĂ§os e ImobiliĂĄrias', 'IntermediaĂ§ĂŁo imobiliĂĄria de venda e locaĂ§ĂŁo.', 2014, 2019, '[\"https://www.youtube.com/watch?v=7n1qRniB9-w\",\"https://www.youtube.com/watch?v=rz_h6XBCG7U\"]', '2026-04-01 02:00:09.906', '2025-08-05 22:20:29.162', 913, NULL, 1, 1935, 'Somos a maior franquia de imĂłveis da AmĂ©rica Latina e oferecemos aos nossos franqueados oportunidades de negĂłcios Ășnicas, com a maior atratividade e capilaridade no mercado imobiliĂĄrio. \nCom mais de 88Â anos de histĂłria, somos referĂȘncia no setor e especialistas em soluĂ§Ă”es em todos os segmentos, prestando assessoria a incorporadores, corretores, compradores e vendedores de lanĂ§amentos e imĂłveis prontos. \nDesde a abertura de capital, em 2006, jĂĄ ajudamos mais de 500 mil famĂ­lias a encontrarem um lar, intermediando aproximadamente 493 mil unidades, que ultrapassam R$176 bilhĂ”es de VGV, nos mantendo como a lĂ­der de mercado.Â  \nE hoje, o site da Lopes Ă© uma das maiores plataformas imobiliĂĄrias do Brasil, gerando mais de 15,5 mil leads por mĂȘs.Â  \nAlĂ©m de ser o maior portfĂłlio da AmĂ©rica Latina, com 250 mil imĂłveis prontos e lanĂ§amentos. \nAqui na Lopes 1 imĂłvel Ă© vendido ou alugado a cada 3 horas! \nGraĂ§as a isso, temos sido a vencedora do TOP ImobiliĂĄrio, na categoria de VGV, como a rede que mais realiza lanĂ§amentos, desde 1993. \nE tudo, porque nĂŁo paramos no tempo. \nEstamos sempre investindo em tecnologias e inovando em ferramentas modernas que reforĂ§am o papel da Lopes como referĂȘncia no segmento. \nAcreditamos que dividir Ă© multiplicar. \nE por isso, queremos dividir com vocĂȘ toda a nossa capacidade de se adaptar, nosso conhecimento e ferramentas exclusivas para corretores e imobiliĂĄrias. \nAjudar as pessoas a conquistarem o seu lugar Ă© o que nos move em busca de soluĂ§Ă”es completas para criar experiĂȘncias encantadoras. Â  Â  Motivos para escolher a Rede Lopes: A marca mais reconhecida no mercado imobiliĂĄrio; + de 88Â anos de tradiĂ§ĂŁo em intermediaĂ§Ă”es imobiliĂĄrias; + de 250Â mil imĂłveis prontos e lanĂ§amentos; + de 14Â mil corretores associados; Parceira dos maiores portais imobiliĂĄrios; Parceira do ItaĂș, para financiamentos via CrediPronto. Â  Motivos para se tornar um franqueado da Rede Lopes: Ferramentas exclusivas que te ajudam a gerir o seu negĂłcio; O maior potencial de Leads qualificados direcionados Ă s franquias; Suporte completo para o Marketing da sua unidade; CapacitaĂ§ĂŁo do seu time de corretores e suporte contĂ­nuo; Workshops periĂłdicos sobre diferentes assuntos; Know-How no mercado primĂĄrio. Â  Principais dores do setor imobiliĂĄrio: NĂŁo sei como me posicionar no ambiente digital imobiliĂĄrio; NĂŁo consigo aumentar minha equipe de corretores; Tenho dificuldade em fazer a gestĂŁo da imobiliĂĄria e analisar meu desempenho; Preciso gerar mais leads e melhorar minha conversĂŁo de vendas; Gostaria de captar mais imĂłveis; Tenho dificuldade em participar e ter acesso aos lanĂ§amentos; Gostaria de compartilhar boas prĂĄticas com outros empresĂĄrios do setor. Â  O que muda sendo franqueado da Rede Lopes: Resultados e lucratividade crescente; DiminuiĂ§ĂŁo no risco de investimento; Facilidade na gestĂŁo do negĂłcio; Vantagem competitiva no mercado imobiliĂĄrio.', NULL, 'SĂO PAULO', 1, NULL, 147, NULL, NULL, '2026-03-09 18:11:36.917', 'https://franquias.portaldofranchising.com.br/franquia-lopes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
