INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jo00oeeh0sn2o3h8pa', 'ATMO MĂDIA DIGITAL CORPORATIVA', 'atmo-midia-digital-corporativa', NULL, 'ComunicaĂ§ĂŁo, InformĂĄtica e EletrĂŽnicos', 'ComunicaĂ§ĂŁo e MĂ­dia', 'Primeiramente somos apaixonados pelo que fazemos! Presente no mercado hĂĄ mais de 30 anos oferecendo soluĂ§Ă”es em Eventos, TV Corporativa e Digital Signage. Amplo portifĂłlio e cases de sucesso!', 2019, 2019, '[\"https://www.youtube.com/watch?v=Uj73LS76PGk\",\"https://www.youtube.com/watch?v=Zyg-3HtpaOo\",\"https://www.youtube.com/watch?v=58L0azvlU-o\"]', '2026-04-01 02:00:09.925', '2025-08-05 22:20:29.172', 915, NULL, 1, 1990, 'O modelo de franquia ATMO DIGITAL surgiu da ideia de favorecer e difundir serviĂ§os de alta qualidade, de forma regional, na ĂĄrea de ComunicaĂ§ĂŁo Corporativa com SoluĂ§Ă”es Ăudio Visuais, TV Corporativa e Digital Signage.Â  \nNo mercado desde o ano de 1990, com mais de 2000 cidades atendidas em todo territĂłrio nacional e mais de 10.000 eventos realizados, A ATMO DIGITAL alcanĂ§ou amplo reconhecimento em comunicaĂ§ĂŁo dentro do universo corporativo. \nSer Franqueado ATMO Ă© fazer parte de uma empresa que estĂĄ no mercado hĂĄ mais de 29 anos, sendo pioneira em SoluĂ§Ă”es para ComunicaĂ§ĂŁo Corporativa, sempre atuando com criatividade, inovaĂ§ĂŁo e qualidade na entrega final. \nSomos apaixonados pelo que fazemos.', NULL, 'SĂO PAULO', 1, NULL, 2, NULL, NULL, '2026-03-09 18:13:26.444', 'https://franquias.portaldofranchising.com.br/franquia-atmo-digital-corporativa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77jt00ofeh0s1ss6um2x', 'INSTITUTO EMBELLEZE', 'instituto-embelleze', NULL, 'EducaĂ§ĂŁo', 'EDUCAĂĂO', 'FormaĂ§ĂŁo profissional na ĂĄrea de beleza', 2003, 1993, '[\"https://www.youtube.com/watch?v=fEyXlvkSgXg\"]', '2026-04-01 02:00:09.934', '2025-08-05 22:20:29.177', 916, NULL, 1, 2003, 'HĂĄ mais de duas dĂ©cadas, o Instituto Embelleze tem sido um pilar fundamental na capacitaĂ§ĂŁo de profissionais da beleza no Brasil. Com 22 anos de existĂȘncia e uma histĂłria marcada pela excelĂȘncia no ensino, o Instituto jĂĄ formou mais de 2,5 milhĂ”es de alunos, oferecendo a eles as ferramentas e conhecimentos necessĂĄrios para transformar suas vidas e as de outros. Presente em mais de 150 unidades espalhadas por 21 estados brasileiros e no exterior - 1 nos Estados Unidos e 1 na Costa Rica -, o Instituto Embelleze oferece uma vasta gama de cursos que atendem Ă s demandas do mercado de beleza. SĂŁo mais de 25 opĂ§Ă”es de formaĂ§ĂŁo, incluindo cursos profissionalizantes, especializaĂ§Ă”es, cursos express e workshops. Entre os cursos mais procurados, estĂŁo os de cabelo e barbearia, manicure e pedicure e embelezamento do olhar (sobrancelhas e cĂ­lios). Ao longo dos anos, a instituiĂ§ĂŁo tem se consolidado como uma referĂȘncia no mercado de beleza, tanto pela qualidade de seu ensino quanto pelo impacto social que promove. Ao formar profissionais altamente qualificados e comprometidos, o Instituto Embelleze contribui para o desenvolvimento do setor e para a realizaĂ§ĂŁo dos sonhos de milhares de pessoas.', NULL, 'SĂO PAULO', 1, NULL, 232, NULL, NULL, '2025-07-18 09:54:10.000', 'https://franquias.portaldofranchising.com.br/franquia-instituto-embelleze-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
