te.', NULL, 'SĂO PAULO', 1, NULL, 23, NULL, NULL, '2026-03-09 18:14:11.513', 'https://franquias.portaldofranchising.com.br/franquia-ginastica-do-cerebro-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '90000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
