INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77kv00omeh0si00yqbf1', 'LET\'S FRITAS', 'let-s-fritas', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Invista na Letâs Fritas, franquia de fast food com produtos de alta aceitaĂ§ĂŁo, sem sazonalidade, operaĂ§ĂŁo simples e alta lucratividade. Vamos juntos, do primeiro pedido ao sucesso!', 2025, 2025, NULL, '2026-04-01 02:00:09.999', '2025-08-05 22:20:29.215', 923, NULL, 1, 2021, '', NULL, 'MINAS GERAIS', 1, NULL, 4, NULL, NULL, '2026-03-09 18:16:52.759', 'https://franquias.portaldofranchising.com.br/franquia-lets-fritas-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '129119', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77l000oneh0st46uwwx0', 'ALPHABETO', 'alphabeto', NULL, 'Moda', 'VestuĂĄrios', 'A Alphabeto veste crianĂ§a como crianĂ§a de 0 a 12 anos hĂĄ mais de 20 anos por todo o Brasil com peĂ§as confortĂĄveis, estilosas, a preĂ§o acessĂ­vel e com a essĂȘncia sempre lĂșdica e infantil.', 2008, 2012, NULL, '2026-04-01 02:00:10.009', '2025-08-05 22:20:29.220', 924, NULL, 1, 1978, 'A Alphabeto acredita na alegria e na delicadeza da infĂąncia, por isso a marca assume a missĂŁo de vestir crianĂ§a como crianĂ§a. \nA linha de produtos desenvolvida para meninos e meninas de 0 a 14 anos reflete estilo, conforto, preĂ§o acessĂ­vel, essĂȘncia infantil e o investimento em beneficiamentos: bordados Ă  mĂŁo, âsilksâ diferenciados e estampas exclusivas sĂŁo os hits da marca. \nTodas as peĂ§as sĂŁo desenvolvidas de acordo com as tendĂȘncias em voga na Moda nacional e internacional. \nCom uma coleĂ§ĂŁo totalmente coordenĂĄvel, Ă© possĂ­vel criar âlooksâ divertidos, nos quais todos os detalhes se combinam, sem perder o foco no desenvolvimento de peĂ§as confortĂĄveis e resistentes que acompanham o ritmo das crianĂ§as. \nO produto Alphabeto Ă© sinĂŽnimo de qualidade e vem conquistando cada vez mais clientes em todo o territĂłrio nacional. \nA empresa foi fundada no ano de 1978, na cidade de SĂŁo JoĂŁo Nepomuceno, em Minas Gerais, com o nome de Children. \nContava inicialmente com apenas 9 colaboradores, fornecendo para pequenos varejistas locais. \nCom a aceitaĂ§ĂŁo do produto, o crescimento foi rĂĄpido e em pouco tempo jĂĄ fornecia peĂ§as para as grandes lojas de departamento brasileiras, como a C&A e a antiga Mesbla. Em 1996, foi inaugurada a 1ÂȘ loja exclusiva no Shopping Nova AmĂ©rica, no Rio de Janeiro. \nA Alphabeto conta com parque fabril prĂłprio e com o que hĂĄ de maquinĂĄrio mais avanĂ§ado em termos de tecnologia no mundo. \nEm 2014, a fĂĄbrica produz mais de 90% de seus produtos internamente e possui em torno de 800 colaboradores, que sĂŁo constantemente treinados para que todas as etapas do processo de produĂ§ĂŁo sejam cumpridas com qualidade e rapidez. \nO processo de produĂ§ĂŁo inclui tecelagem, onde Ă© produzida a malha, lavanderia industrial, mĂĄquinas de bordado a laser e mĂĄquinas eletrĂŽnicas de estamparia. \nA Alphabeto consegue oferecer ao consumidor final ampla variedade de produtos a um preĂ§o final bastante acessĂ­vel.', NULL, 'MINAS GERAIS', 1, NULL, 72, NULL, NULL, '2026-03-09 18:17:15.207', 'https://franquias.portaldofranchising.com.br/franquia-alphabeto/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
