INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77no00p1eh0skunjrdnv', 'TURQUESA ESMALTERIA', 'turquesa-esmalteria', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'A Turquesa Beleza & Bem-Estar oferece a melhor experiĂȘncia ao cliente que procura serviĂ§os diferenciados para unhas, como tambĂ©m serviĂ§os complementares: depilaĂ§ĂŁo, sobrancelhas, cabelo e estĂ©tica.', 2015, 2018, NULL, '2026-04-01 02:00:10.152', '2025-08-05 22:20:29.316', 938, NULL, 1, 2014, 'Lutamos pela democratizaĂ§ĂŁo da beleza proporcionando um ambiente diferenciado, acolhedor e acessĂ­vel Ă  todos. \nUm salĂŁo de beleza completo onde a cliente desfruta momentos de relaxamento e descontraĂ§ĂŁo, enquanto cuida de toda sua beleza. \nE para quem quer empreender no promissor segmento da beleza, a Turquesa oferece vĂĄrios modelos de composiĂ§ĂŁo de serviĂ§os que vai desde manicure tradicional e unhas especiais, nosso carro chefe, bem como serviĂ§os de cabelo, embelezamento de olhar, depilaĂ§ĂŁo e estĂ©tica. \nNossas referĂȘncias sĂŁo sempre ligadas Ă  beleza e ao bem-estar por isso a corÂ  Turquesa que alĂ©m de ser a cor preferida mundialmente, relaxa todo o sistema nervoso e acalma a mente. Com uma equipe especializada oferecemos um suporte integral para o franqueado gerir a sua loja, desde o atendimento atĂ© as suas redes sociais. \nIsso porque a Turquesa Ă© gerida pelas suas prĂłprias fundadoras que atuam hĂĄ quase dez anos no negĂłcio administrando uma rede de mais de 100 unidades espalhadas em todo o Brasil, gerando emprego para mais de mil profissionais da ĂĄrea de beleza. A equipe da franqueadora que assessora os franqueados sĂŁo profissionais do franchising responsĂĄveis pelo: Apoio na expertise pela busca de um bom ponto comercial; Projeto visual da loja feito por excelentes profissionais; Plano de negĂłcio customizado para o contexto do mercado de atuaĂ§ĂŁo de cada franqueado, garantindo uma atuaĂ§ĂŁo mais sĂłlida, mais assertiva, em busca da rentabilidade desejada; Uma equipe de gerenciamento de projeto que o ajudarĂĄ na fase de implantaĂ§ĂŁo da sua unidade garantindo melhor ĂȘxito em todas as etapas atĂ© a inauguraĂ§ĂŁo; Treinamento gerencial intensivo aos franqueados recĂ©m-chegados Ă  rede, ministrado presencialmente pelos prĂłprios fundadores e parceiros na sede da franquedora. Ainda que o franqueado nĂŁo tenha experiĂȘncia no setor, ele sairĂĄ apto Ă  gerir a sua prĂłpria loja com excelĂȘncia; Â Plataforma de treinamento on-line para reciclagem; Treinamento tĂ©cnico intensivo para os profissionais de beleza selecionados, que acontece por trĂȘs dias integrais e ministrado por treinadora exclusiva da rede Turquesa; Equipe interna de marketing de comunicaĂ§ĂŁo provendo aos franqueados todas artes, todo o material de comunicaĂ§ĂŁo online e offline para campanhas institucionais, varejo nacional com as suas datas comemorativas e campanhas e aĂ§Ă”es regionais; Consultor de operaĂ§ĂŁo responsĂĄvel por acompanhar a performance das unidades e disseminar as boas prĂĄticas da rede. Estamos tambĂ©m com os melhores fornecedores homologados do segmento, com taxas exclusivas e preĂ§os mais acessĂ­veis. \nPara vocĂȘ, futuro empreendedor que deseja atuar neste crescente e promissor segmento, a marca Turquesa Esmalteria & Beleza oferece um modelo de negĂłcios sĂłlido e validado, com todo apoio e proximidade da franqueadora. \nEmpreenda no segmento que mais cresce no Brasil! Seja um franqueado Turquesa.', NULL, 'SĂO PAULO', 1, NULL, 76, NULL, NULL, '2026-03-09 18:23:55.552', 'https://franquias.portaldofranchising.com.br/franquia-turquesa-esmalteria/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '69000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
