INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77nz00p3eh0s7ywbw2pu', 'KUMON', 'kumon', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'MĂ©todo de estudo nas disciplinas: matemĂĄtica, portuguĂȘs, inglĂȘs e japonĂȘs', 1958, 2003, '[\"https://www.youtube.com/watch?v=to3DeCKixOs\",\"https://www.youtube.com/watch?v=nlpznBpjNWQ\"]', '2026-04-01 02:00:10.171', '2025-08-05 22:20:29.327', 940, NULL, 1, 1958, 'O Kumon Ă© uma empresa que, por meio da educaĂ§ĂŁo, contribui para o desenvolvimento de milhĂ”es de crianĂ§as em todo o mundo. Ă a maior franquia de educaĂ§ĂŁo do paĂ­s*, uma marca sĂłlida e rentĂĄvel que proporciona ao franqueado um retorno valioso: realizaĂ§ĂŁo pessoal, profissional e financeira. O mĂ©todo Kumon foi idealizado em 1954, quando o Prof. Toru Kumon, professor de MatemĂĄtica, criou um material didĂĄtico com o intuito de desenvolver o seu filho, Takeshi, pela autoinstruĂ§ĂŁo. Percebendo os resultados de Takeshi na escola, os pais dos outros alunos passaram a se interessar pelo mĂ©todo. Com o objetivo de proporcionar o melhor aprendizado para o prĂłprio filho e para todas as crianĂ§as de todo o mundo, foi fundado o Kumon. Diferenciais da franquia Kumon: Presente em mais de 60 paĂ­ses; Marca consolidada hĂĄ mais de 45 anos na AmĂ©rica do Sul; Mais de 1500 unidades no Brasil; Mais de 175 mil alunos no paĂ­s; *Maior franquia de educaĂ§ĂŁo do paĂ­s (dados ABF/2024); Investimento inicial a partir de 50 mil; Diferenciais do mĂ©todo: Estudo individualizado O Kumon nĂŁo se prende a idade ou serie escolar, mas sim, a capacidade individual do aluno, que comeĂ§a no seu ponto ideal de conhecimento. Autodidatismo O mĂ©todo desenvolve a autonomia nos estudos, ou seja, a capacidade de o aluno prender por si. Material didĂĄtico exclusivo Nosso material didĂĄtico e estruturado para que o aluno inicie os conteĂșdos de um nĂ­vel fĂĄcil e avance de forma gradativa, sem sobrecargas de acordo com a evoluĂ§ĂŁo do aluno. Orientadores/Franqueados O papel do franqueado Kumon que Ă© o orientador da unidade, Ă© fundamental, pois cabe a ele observar as habilidades individuais do aluno e ajudar a desenvolvĂȘ-las ao mĂĄximo. Gosto pelo aprendizado O aluno Kumon alcanĂ§a a autoconfianĂ§a e o interesse em estudar e aprender, desenvolvendo considerĂĄveis habilidades acadĂȘmicas e pessoais.', NULL, 'SĂO PAULO', 1, NULL, 1972, NULL, NULL, '2026-03-09 18:25:37.707', 'https://franquias.portaldofranchising.com.br/franquia-kumon-educacao-e-treinamento/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '50000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ob00p5eh0shlthl57p', 'MCDONALDÂŽS', 'mcdonald-s', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'McDonald\'s Ă© a maior e mais conhecida empresa de serviĂ§o rĂĄpido de alimentaĂ§ĂŁo do mundo. No Brasil, a rede Ă© operada desde 2007 pela Arcos Dourados, franqueada da marca em toda AmĂ©rica Latina.', 1955, 1992, NULL, '2026-04-01 02:00:10.181', '2025-08-05 22:20:29.339', 942, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1955, 'FRANQUIA McDONALD\'S BRASIL \nLĂ­der no segmento de serviĂ§o rĂĄpido de alimentaĂ§ĂŁo, o McDonald\'s se destaca pela qualidade dos produtos e do atendimento. O McDonald\'s Ă© a maior e mais conhecida empresa de serviĂ§o rĂĄpido de alimentaĂ§ĂŁo do mundo. Presente em 119 paĂ­ses, a rede possui mais de 36 mil restaurantes, onde trabalham 2 milhĂ”es de funcionĂĄrios que alimentam diariamente mais de 70 milhĂ”es de clientes. No Brasil, a rede Ă© operada desde 2007 pela Arcos Dourados, mĂĄster franqueada da marca McDonald\'s em toda a AmĂ©rica Latina. O primeiro restaurante do Brasil foi inaugurado em 1979, em Copacabana, Rio de Janeiro. Uma das melhores empresas para trabalhar no Brasil e um dos maiores empregadores de jovens do paĂ­s, o McDonaldâs reforĂ§a seu compromisso com a seguranĂ§a e a saĂșde do trabalhador e anuncia o apoio ao movimento Abril Verde, iniciativa que ressalta a discussĂŁo sobre a seguranĂ§a e a saĂșde no ambiente de trabalho. \nLĂ­der absoluto no segmento de restaurantes fast food, com produtos de qualidade reconhecida, o Mcdonaldâs Ă© hoje uma das melhores empresas para se trabalhar e uma das melhores franquias para administrar. De fato, foi o sistema de franquias que permitiu o McDonaldâs a se tornar a rede de restaurantes de mais sucesso do planeta, com mais de 33.000 restaurantes e presenĂ§a em 119 paĂ­ses.', NULL, 'SĂO PAULO', 1, NULL, 2779, NULL, NULL, '2026-03-09 18:28:05.677', 'https://franquias.portaldofranchising.com.br/franquia-mcdonalds-valor/', NULL, NULL, NULL, 1, 5, 5, 1, 'MAINTAIN', 0, 0, '[]', '2670000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77oh00p6eh0s8qmuaxtz', 'ACCORHOTELS', 'accorhotels', NULL, 'Hotelaria e Turismo', 'HOSPEDAGEM', 'Impulsionamos o mercado hoteleiro nas AmĂ©ricas, desenvolvendo hotĂ©is Premium, Midscale e Economy de sucesso. Acesse nosso site, e conheĂ§a nossas marcas: https://all.accor.com/a/pt-br/brands.html', 1971, 2006, NULL, '2026-04-01 02:00:10.191', '2025-08-05 22:20:29.345', 943, NULL, 1, 1971, '', NULL, 'SĂO PAULO', 1, NULL, 183, NULL, NULL, '2026-01-16 10:30:49.000', 'https://franquias.portaldofranchising.com.br/franquia-accor-hospitality-hotelaria-e-turismo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '8320000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77on00p7eh0sam4xd64r', 'PURIFIC', 'purific', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Purificadores de Ăgua PortĂĄteis, Residencial, Corporativo, Industrial.', 2003, 2006, NULL, '2026-04-01 02:00:10.200', '2025-08-05 22:20:29.351', 944, NULL, 1, 1998, 'Fundada em 1998, a sede da Purific estĂĄ localizada na cidade de MaringĂĄ (PR). A empresa trabalha com o objetivo de produzir purificadores de alta tecnologia com valores acessĂ­veis. \nConta com equipe altamente capacitada, formada por engenheiros quĂ­micos, alĂ©m de convĂȘnio com a Universidade Estadual de MaringĂĄ (UEM). Juntos, eles desenvolvem a melhor tecnologia de purificadores e elementos filtrantes. \nA Purific do Brasil desponta com moderna tecnologia e grande variedade de produtos, realizando o lanĂ§amento de um produto por ano, a fim de atender Ă s necessidades e exigĂȘncias do mercado. \nCom tanto crescimento e evoluĂ§ĂŁo, para melhorar a demanda e transporte, a Purific do Brasil inaugurou um centro de distribuiĂ§ĂŁo e montagem na cidade de Balbinos (SP), com o objetivo de facilitar as entregas diretamente aos operadores logĂ­sticos, fazendo com que os produtos cheguem mais rĂĄpido a qualquer ponto do PaĂ­s. \nO centro de distribuiĂ§ĂŁo e montagem de Balbinos representa de forma significativa o crescimento de 50% no seu parque de mĂĄquinas, proporcionando aumento na fabricaĂ§ĂŁo dos produtos Purific e gerando empregos. \nAlĂ©m de oferecer completa linha de purificadores de alta tecnologia, a Purific estĂĄ sempre acompanhando as tendĂȘncias de mercado e preocupada com o meio ambiente, desenvolvendo produtos de qualidade com alta tecnologia e design moderno para atender e satisfazer nossos consumidores.', NULL, 'PARANĂ', 1, NULL, 151, NULL, NULL, '2026-03-09 18:28:52.821', 'https://franquias.portaldofranchising.com.br/franquia-purific-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
