026-01-16 10:35:42.000', 'https://franquias.portaldofranchising.com.br/franquia-new-era-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
