C, e oferecem ensino de excelĂȘncia a 25 mil estudantes em todas as regiĂ”es do PaĂ­s', NULL, 'SĂO PAULO', 1, NULL, 489, NULL, NULL, '2026-03-09 18:30:32.138', 'https://franquias.portaldofranchising.com.br/franquia-maple-bear/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '2612350', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
