 forĂ§a e rapidez. Venha ganhar este mercado conosco!', NULL, 'ESPĂRITO SANTO', 1, NULL, 16, NULL, NULL, '2026-03-09 18:31:11.428', 'https://franquias.portaldofranchising.com.br/franquia-super-aprendiz/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
