INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77pj00pdeh0sk5tbc8xj', 'REMAX', 'remax', NULL, 'Casa e ConstruĂ§ĂŁo', 'ServiĂ§os e ImobiliĂĄrias', 'FRANQUIA IMOBILIĂRIA', 1973, 2010, '[\"https://www.youtube.com/watch?v=H4i1igfgruc\"]', '2026-04-01 02:00:10.256', '2025-08-05 22:20:29.383', 950, NULL, 1, 1973, 'AÂ RE/MAX, lĂ­der do franchising imobiliĂĄrio mundial, foi fundada em Denver, no Estado do Colorado (USA). Hoje a RE/MAX Ă© a maior rede de franquias imobiliĂĄrias em nĂșmeros de transaĂ§Ă”es no mundo, com mais de 9.000 franquias e 144.000 corretores a sua disposiĂ§ĂŁo. No Brasil, a RE/MAX atua desde 2009, com mais de 630Â Franquias por todo o paĂ­s. O diferencial da rede Ă© bastante conhecido: âNinguĂ©m vende mais imĂłveis no mundo do que aÂ RE/MAXâ. A franquiaÂ RE/MAXÂ baseia-se em trĂȘs fundamentos: mĂĄximo serviĂ§o para o cliente, mĂĄxima comissĂŁo para o corretor e mĂĄxima rentabilidade para o franqueado, numa atuaĂ§ĂŁo Ășnica onde âtodos ganhamâ. Para ser um franqueadoÂ RE/MAX, o empresĂĄrio nĂŁo precisa ter conhecimento prĂ©vio do mercado imobiliĂĄrio. AÂ RE/MAXÂ oferece: REDE MUNDIALÂ presente em mais de 110Â paĂ­ses, mais de 144Â mil corretores, o que permite um leque vasto de opĂ§Ă”es para compra ou venda de imĂłveis em qualquer lugar do Brasil e do mundo. TREINAMENTOÂ constante dos brokers e corretores associados. UNIVERSIDADE RE/MAX, Ășnica no gĂȘnero em operaĂ§ĂŁo no mundo, o franqueado aprende e se mantem sempre atualizado nos procedimentos para de venda e captaĂ§ĂŁo de imĂłveis. PAR:Â Suporte ao franqueado por meio da transferĂȘncia de Know-How. MARCAÂ fortemente reconhecida no mundo. MAXPRO, um software que proporciona em tempo real todas as informaĂ§Ă”es do negĂłcio para o franqueado. CULTURA:Â InovaĂ§ĂŁo na prestaĂ§ĂŁo de serviĂ§o por meio das melhores prĂĄticas mundiais, com foco no desenvolvimento e qualidade de vida. E mais:Â TAXA DE FRANQUIAÂ a partir de $20 mil dĂłlares. A operaĂ§ĂŁo nacional conta com 16 Masters Regionais distribuĂ­das por todo o Brasil, oferecendo total suporte para sua operaĂ§ĂŁo. Se vocĂȘ procura um negĂłcio que pode mudar o futuro da sua imobiliĂĄria ou uma ĂĄrea rentĂĄvel em potencial, entre em contato conosco. Â  Processo de seleĂ§ĂŁo da franquia REMAX ConheĂ§a abaixo quais sĂŁo as etapas do processo de seleĂ§ĂŁo da franquiaÂ RE/MAX: Contato Inicial ApresentaĂ§ĂŁo de venda de franquia Visita a um franqueado Planilha de viabilidade Envio da Circular de Oferta de Franquia (COF) Esclarecimento da COF AprovaĂ§ĂŁo do Franqueado Assinatura do Contrato Perfil do franqueado REMAX ConheĂ§a abaixo o perfil que a franquiaÂ RE/MAXÂ procura para seus franqueados: a) Saber delegar\nb) GestĂŁo de talentos\nc) Bom relacionamento\nd) ValorizaĂ§ĂŁo do compartilhamento\ne) CooperaĂ§ĂŁo\nf) Empreendedor\ng) DedicaĂ§ĂŁo e disponibilidade\nh) Autonomia\ni) OrganizaĂ§ĂŁo e responsabilidade\nj) IdentificaĂ§ĂŁo com o modelo de negĂłcio\nk) Flexibilidade para o aprendizado\nl) Possui recursos financeiros', NULL, 'SĂO PAULO', 1, NULL, 623, NULL, NULL, '2026-03-09 18:32:09.167', 'https://franquias.portaldofranchising.com.br/franquia-remax-imobiliarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77po00peeh0sumobv5u3', 'PETLAND', 'petland', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'A maior rede de Franquias de petshop do Brasil, com mais de 50 anos de histĂłria, presente em 19 paĂ­ses.', 1970, 2014, '[\"https://www.youtube.com/watch?v=jB02ZtqASm4\"]', '2026-04-01 02:00:10.266', '2025-08-05 22:20:29.389', 951, NULL, 1, 1967, 'A Petland Ă© uma rede de franquias que nasceu nos EUA em 1967 com uma visĂŁo inspirada na magia da Disneyland. Fundada por Ed Kunzelman em Ohio, a Petland rapidamente se expandiu internacionalmente e hoje estĂĄ presente em 19 paĂ­ses ao redor do mundo. Com quase 60 anos de experiĂȘncia, nossa missĂŁo Ă© proporcionar experiĂȘncias memorĂĄveis aos clientes que visitam nossas lojas, focando em transmissĂŁo de informaĂ§ĂŁo, uma experiĂȘncia de compra Ășnica, responsabilidade social e preĂ§os justos. Somos uma empresa moderna e inovadora, comprometida em oferecer um ambiente seguro e confiĂĄvel para nossos franqueados e clientes. Aterrissamos no Brasil em 2014 e jĂĄ temos histĂłrias incrĂ­veis para compartilhar! Somos a maior rede de pet shops do Brasil, com mais de 170 lojas espalhadas por 21 estados. AlĂ©m de toda a experiĂȘncia adquirida e transmitida por uma rede de quase 60 anos de histĂłria, o sucesso da Petland tambĂ©m Ă© impulsionado pelo fato de o Brasil ser o 2Âș maior mercado consumidor de produtos para pets no mundo. O mercado pet tambĂ©m tem resistido Ă s recentes crises econĂŽmicas, registrando um crescimento de mais de dois dĂ­gitos todos os anos. A tendĂȘncia de humanizaĂ§ĂŁo dos animais de estimaĂ§ĂŁo, tratados cada vez mais como membros da famĂ­lia, Ă© um dos motores desse crescimento, mantendo o mercado sempre em busca de novos produtos e experiĂȘncias para oferecer aos seus pets e tutores. Com um faturamento anual ultrapassando os R$ 35 bilhĂ”es, o mercado de Pet Shop se revela uma oportunidade incrĂ­vel de investimento, atendendo a todas as classes sociais e a um pĂșblico de todas as idades. A Petland se destaca no universo das franquias oferecendo uma variedade de formatos de lojas, desde unidades compactas atĂ© mega lojas, para atender Ă s diferentes demandas e localidades. Na Petland, o bem-estar e a saĂșde dos pets sempre tĂȘm prioridade mĂĄxima. Em nossas franquias, nossa equipe Ă© treinada para fornecer um atendimento centrado na educaĂ§ĂŁo, orientando os tutores sobre as 4 Necessidades BĂĄsicas de todo animal: nutriĂ§ĂŁo, ambiente, comportamento e manutenĂ§ĂŁo. Nossos colaboradores, os âPetlandersâ, estĂŁo empenhados em fazer a combinaĂ§ĂŁo perfeita entre o animal e sua nova famĂ­lia, garantindo a satisfaĂ§ĂŁo de ambas as partes. Para aqueles que jĂĄ possuem um pet, estamos comprometidos em expandir seu conhecimento e aprimorar esse relacionamento. No pilar responsabilidade social, mantemos parcerias com mais de 40 ONGs no Brasil. Todos os fins de semana, diversas lojas de nossa rede promovem eventos de adoĂ§ĂŁo por todo o paĂ­s. AlĂ©m disso, anualmente realizamos o SRDay, um dia especial em que todas as 170 lojas da Petland promovem eventos de adoĂ§ĂŁo simultaneamente. Essas aĂ§Ă”es refletem nosso compromisso com o bem-estar animal e a promoĂ§ĂŁo da adoĂ§ĂŁo responsĂĄvel. Venha fazer parte da maior rede de Pet Shops do Brasil e nos ajude a transformar a vida de pets e pessoas!', NULL, 'SĂO PAULO', 1, NULL, 168, NULL, NULL, '2026-03-09 18:33:33.400', 'https://franquias.portaldofranchising.com.br/franquia-petland-negocios-e-servicos/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '135000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77pu00pfeh0srdmb4a6s', 'MAIS1', 'mais1', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Rede de cafeterias de cafĂ©s especiais e alimentos de alta qualidade. GestĂŁo simplificada com a necessidade de apenas 3 colaboradores. Suporte total ao franqueado', 2019, 2020, '[\"https://www.youtube.com/watch?v=Q26g28o6kX4\",\"https://www.youtube.com/watch?v=96sQu13hbKE\",\"https://www.youtube.com/watch?v=a7OxXLtZozM\",\"https://www.youtube.com/watch?v=-IcNYgGsde8\"]', '2026-04-01 02:00:10.276', '2025-08-05 22:20:29.394', 952, NULL, 1, 2019, 'A REDE DE FRANQUIAS QUE MAIS CRESCEU NO BRASIL EM 2022 Com mais de 500 unidades jĂĄ confirmadas no Brasil, a Mais 1 CafĂ© Ă© uma rede de franquias que chegou ao mercado em 2019 e de lĂĄ pra cĂĄ tem se expandido e criado grandes parcerias, se tornando uma das principais redes de cafeterias e se consolidando como a marca mais jovem a entrar no ranking das 50 maiores franquias do paĂ­s, tudo isto graĂ§as ao planejamento e plano de negĂłcios bem estruturado. SĂł trabalhamos com produtos de altĂ­ssima qualidade, importados de diversos lugares do mundo, o cafĂ© utilizado Ă© da categoria especial, 100% arĂĄbica produzido nas melhores fazendas do paĂ­s. Nos orgulhamos de parcerias oficiais de produtos com as principais marcas mundiais como NestlĂ©, Nutella, Ovomaltine e Forno de Minas, e de parcerias de marketing com Universal Studios, Gol Linhas aĂ©reas entre outras. Dentro de todo esse cenĂĄrio, a Mais1 se destaca pelo seu baixo valor de investimento inicial, alta rentabilidade, espaĂ§os compactos, nĂșmero reduzido de funcionĂĄrios e ainda todo o suporte oferecido pela rede franqueadora. JĂĄ somos mais de 500 unidades confirmadas no Brasil e continuamos crescendo de forma acelerada. Venha fazer parte desta histĂłria. Esperamos seu contato!', NULL, 'PARANĂ', 1, NULL, 502, NULL, NULL, '2026-03-09 18:35:06.185', 'https://franquias.portaldofranchising.com.br/franquia-mais1/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '290000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
