INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77r400pneh0s2s4y22we', 'STALKER', 'stalker', NULL, 'Moda', 'VestuĂĄrios', 'VestuĂĄrio', 2000, 1998, NULL, '2026-04-01 02:00:10.349', '2025-08-05 22:20:29.441', 960, NULL, 1, 1998, 'A STALKER chegou ao mercado brasileiro em julho de 1998. No seu dĂ©cimo nono ano de existĂȘncia, conta com 30 operaĂ§Ă”es. A marca procura criar uma identidade para o pĂșblico-alvo: o homem com espĂ­rito livre e jovem sem faixa etĂĄria dominante. A âEstrelaâ associa-se Ă  posiĂ§ĂŁo, objetivos, traz alusĂŁo Ă  liberdade de escolha, Ă  aventura, traduz-se em bĂșssola, horizonte. A palavra âSTALKERâ do inglĂȘsÂ to stalk, que significa caĂ§ar, dĂĄ um carĂĄter universal ao homem perseverante e atual, que âpersegueâ seus objetivos, caĂ§ador, homem moderno e livre. \nAtualmente faz parte do grupo Sand Beach, empresa com 31 anos de mercado. O grupo iniciou seu trabalho com uma fĂĄbrica de garagem, em Fortaleza (CE), voltada para a produĂ§ĂŁo de bermudas (boardshorts) para os amigos e criou a marca MARESIA. A Sand Beach se tornou um dos maiores parques industriais do segmento, que atualmente consta com 20.000mÂČ, sendo 85% automatizados.Â SĂŁo mais de 500 colaboradores diretos que respondem por uma produĂ§ĂŁo que, somente na estamparia Ă© de aproximadamente 10 mil peĂ§as completas por dia, podendo funcionar 24 horas durante os sete dias da semana.Â Um crescimento que tambĂ©m se expandiu em segmentos, trazendo para o grupo as marcas MARESIA Future, criada para levar toda a qualidade da MARESIA para as crianĂ§as, e a Black Box, que Ă© mais voltada para a moda casual jovem e urbana.', NULL, 'CEARĂ', 1, NULL, 20, NULL, NULL, '2026-03-09 18:42:47.813', 'https://franquias.portaldofranchising.com.br/franquia-stalker-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
