INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77rl00pqeh0sw317jd73', '10 PASTĂIS', '10-pasteis', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Fast Food', 1996, 1998, NULL, '2026-04-01 02:00:10.378', '2025-08-05 22:20:29.457', 963, 'df170f80-7453-425d-9613-b55ed556e14e', 1, 1961, 'O empreendedor Marcos Nagano conta a histĂłria de sucesso, que tornou a 10 pastĂ©is a maior rede de pastĂ©is do Brasil Por trĂĄs de um grande empreendimento, hĂĄ sempre mentes visionĂĄrias, e principalmente, empreendedoras. E com a franquia â10 PastĂ©isâ nĂŁo foi diferente. AtĂ© se consolidar como a maior rede de pastĂ©is do Brasil, a empresa teve muita estratĂ©gia, planejamento e momentos de readequaĂ§ĂŁo para hoje em dia, continuar seu processo de expansĂŁo. E uma das mentes por trĂĄs do sucesso da marca Ă©Â Marcos Nagano, 53 anos. Em sua vida pessoal, Nagano, que Ă© natural de Presidente Prudente, em SĂŁo Paulo, se mudou ainda adolescente para Curitiba, cidade que reside atualmente. Engenheiro MecĂąnico, ele jĂĄ foi atleta, bancĂĄrio, tĂ©cnico das categorias de base da seleĂ§ĂŁo brasileira de beisebol, trabalhou com sistemas e quando estava com a vida tranquila, sendo funcionĂĄrio pĂșblico, decidiu ser empreendedor. âEm 1993, a famĂ­lia do Rui Sasazawa, meu sĂłcio na Ă©poca, tinha uma pastelaria na rodoviĂĄria de MaringĂĄ. Ele se mudou para Curitiba e abriu a 10 PastĂ©is. Eu recebi o convite dele, e entrei no negĂłcio para liderar a franqueadoraâ, relembra. Com a experiĂȘncia de engenheiro, Nagano contratou uma consultoria, e desde o inĂ­cio, investiu em capacitaĂ§ĂŁo. âQuerĂ­amos que tudo acontecesse dentro de um padrĂŁoâ, disse. E esta era justamente uma das caracterĂ­sticas da 10 PastĂ©is, que mais tarde veio a ter na culinĂĄria, qualidades que diferenciasse dos concorrentes, como a massa de chocolate, de pimenta, pastel com bordas, etc. A vida nĂŁo Ă© uma constante Para Nagano, a vida funciona como uma linha inconstante, com variaĂ§Ă”es tanto para cima, quanto para baixo. E a primeira variaĂ§ĂŁo negativa da empresa foi em 1996 quando o fundador da 10 PastĂ©is saiu do negĂłcio. âDepois de 5 anos, o Rui saiu. Mas seguimos nosso planejamento, com o objetivo de dar sustentabilidade para a marca. Afinal, o segredo de uma franquia Ă© fazer os franqueados ganharem dinheiroâ, destacou. As armadilhas pelo caminho Ao estudar a histĂłria de empresas da menor para as grandes companhias, Ă© comum haver tempos de prosperidade e crescimento mĂștuo, alternando com perĂ­odos de crise. ApĂłs um perĂ­odo de crescimento, em que chegou a mais de 60 lojas, a 10 PastĂ©is viu seuÂ market shareÂ cair no mercado entre 2015 e 2016. Nagano lembra que o motivo foi a crise, mas ele deixa aquele momento de susto, como um grande aprendizado. âQuando tudo comeĂ§a a dar certo no negĂłcio, Ă© quando vocĂȘ precisa tomar cuidado com cada passo que vai darâ. Pois nossa grande armadilha foi justamente essa, lembra. Hoje com 40 lojas abertas em nove estados do Brasil, a empresa jĂĄ tem mais sete franquias em processo de abertura e projeto de expansĂŁo para 70 lojas. âO nosso objetivo Ă© em trĂȘs anos chegar a 100ÂȘ lojaâ, revelou. A experiĂȘncia de quem deu certo Marcos Nagano nunca se contentou, sempre correndo atrĂĄs de seus sonhos. E para quem pretende empreender, ele deixa um conselho. âPrimeiro acredite do sonho. Quem quer empreender, realmente tem que acreditar no sonho. Segundo, tem que ter um planejamento. NĂŁo sĂł ter o sonho, mas saber fazer. E ter resiliĂȘncia. Tendo tudo isso: objetivo e planejamento, nĂŁo tem porque nĂŁo tentar. O dar certo Ă© uma consequĂȘnciaâ, concluiu.', NULL, 'PARANĂ', 1, NULL, 64, NULL, NULL, '2026-03-09 18:44:18.596', 'https://franquias.portaldofranchising.com.br/franquia-10-pasteis-salgados/', NULL, NULL, NULL, 1, 3.666666666666667, 11, 3, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
