INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77sc00pveh0smotsj632', 'T-DONUTS', 't-donuts', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Franqueamento de unidades de comercializaĂ§ĂŁo de doces', 2021, 2022, '[\"https://www.youtube.com/watch?v=CLfHrTC_zu8\",\"https://www.youtube.com/watch?v=IFJQvFy47kE\"]', '2026-04-01 02:00:10.428', '2025-08-05 22:20:29.484', 968, NULL, 1, 2021, 'Empreendedor de sucesso, Tiago Fernandes, o Tcar, Ă© proprietĂĄrio da loja de carros mais famosa do Brasil com +4 milhĂ”es de seguidores nas redes sociais, e emÂ 2021Â em meio Ă  pandemia, decidiu diversificar seus investimentos e apostar no ramo alimentĂ­cio. Foi entĂŁo que a tdonuts nasceu e foi uma explosĂŁo de vendas na Ă©poca. A esse sucesso associou-se Tiago Carvalho, empreendedor jovem e dinĂąmico, dono de uma rede de franquias odontolĂłgicas com mais de 30 unidades e faturamento anual que jĂĄ supera a marca dos 30 milhĂ”es de reais. ApĂłs encontros de negĂłcios, Tiago Carvalho e Tiago Fernandes, decidiram se tornar sĂłcios da maior e melhor franquia de donuts do Brasil, a tdonuts. Ănica franquia 6 em 1 do Brasil, aÂ  t.donuts Ă© uma rede de lojas especializada em donuts, a nova âfebre do brasileiroâ! SĂŁo diversos sabores, de rings clĂĄssicos aos recheados, ou melhor, muitooooo recheados, que encantam e deixam o cliente com gostinho deÂ  âquero maisâ. AlĂ©m deles, a loja oferece em seu cardĂĄpio donuts salgados, donuts com sorvete, cafĂ©s, milkshakes e deliciosas sodas italianas. Perfeita para todas as horas do dia, e todos os gostos.', NULL, 'SĂO PAULO', 1, NULL, 8, NULL, NULL, '2026-03-09 18:47:08.605', 'https://franquias.portaldofranchising.com.br/franquia-t-donuts/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '80000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77sm00pxeh0shy1mv528', 'ORTHOCRIN', 'orthocrin', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'O Sistema de Franquias da ORTHOCRIN baseia- se no licenciamento aos franqueados do direito de uso da marca, que Ă© conhecida, consolidada e com prestĂ­gio em todo o territĂłrio nacional, associado ao uso de uma Metodologia de Trabalho padronizada para instalaĂ§ĂŁo, montagem, administraĂ§ĂŁo e operaĂ§ĂŁo de uma loja especializada na venda dos produtos da marca.', 2013, 2014, '[\"https://www.youtube.com/watch?v=8MJRgJFWuKc\",\"https://www.youtube.com/watch?v=Xmh2JiRiZBU\",\"https://www.youtube.com/watch?v=bWbe5jC_2v4\"]', '2026-04-01 02:00:10.437', '2025-08-05 22:20:29.494', 970, NULL, 1, 2013, 'Uma equilibrada mistura entre tradiĂ§ĂŁo e inovaĂ§ĂŁo, gestĂŁo familiar com renovaĂ§ĂŁo do mercado, tecnologia criada dentro da empresa com mĂ©todos internacionais. Assim podemos resumir a forma como a Orthocrin, uma das maiores empresas de colchĂ”es do Brasil, se posiciona no mercado. Com mais de 50 anos de atuaĂ§ĂŁo, a fĂĄbrica mineira se orgulha de sua histĂłria e mantĂ©m sempre o foco na qualidade e excelĂȘncia de seus produtos. Todo esse cuidado e dedicaĂ§ĂŁo, contribuĂ­ram para a conquista de importantes certificaĂ§Ă”es, como: Empresa Top Of Mind, Selo de Qualidade e Controle de ProduĂ§ĂŁo do Inmetro e Certificado PrĂł-Espuma. Hoje, a marca estĂĄ presente nos Estados de Minas Gerais, Bahia, EspĂ­rito Santo, GoiĂĄs, ParaĂ­ba, Rio de Janeiro, Rio Grande do Norte, Sergipe e SĂŁo Paulo, com mais de trĂȘs mil pontos de vendas da marca, incluindo lojas credenciadas, multimarcas e franquias. Ao escolher uma franquia COLCHĂES ORTHOCRIN, o empreendedor passa a contar com uma metodologia de trabalho padronizada, preĂ§os competitivos e o fornecimento assegurado por uma das maiores indĂșstrias de colchĂ”es do Brasil. Diferenciais que propiciam ao franqueado iniciar a gestĂŁo de sua loja com maiores chances de sucesso.', NULL, 'MINAS GERAIS', 1, NULL, 93, NULL, NULL, '2026-03-09 18:59:48.387', 'https://franquias.portaldofranchising.com.br/franquia-orthocrin/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
