INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77u500q4eh0sn4iny7b3', 'JAH', 'jah', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'O JAH AĂ§aĂ­, Sorvetes e PicolĂ©s conta com mais de 180 unidades pelo Brasil, e uma oferta exclusiva em produtos atravĂ©s de um modelo self-service de negĂłcio, Ă  justo custo benefĂ­cio aos nossos clientes.', 2016, 2018, '[\"https://www.youtube.com/watch?v=mHY4avCoiQc\",\"https://www.youtube.com/watch?v=K-aVOzoXda4\"]', '2026-04-01 02:00:10.506', '2025-08-05 22:20:29.549', 977, NULL, 1, 2009, 'Uma empresa que conduz o futuro com qualidade, sabores, pessoas e ideias. \nDe Conselheiro Lafaiete, interior de Minas Gerais, o JAH Ă© uma rede de franquias de aĂ§aĂ­, sorvetes e picolĂ©s que inovou ao desenvolver um negĂłcio sob medida, que conversa com as necessidades do seu pĂșblico-alvo.Â  O modelo self-service abriu portas para a expansĂŁo da rede que, hoje, estĂĄ em 14 estados no paĂ­s, compondo uma rede de mais de 150 unidades. \nO nosso diferencial conversa com diversos pĂșblicos e abraĂ§a dores de mercado, que enfrenta escassez de produtos de qualidade, feitos exclusivamente para os #JAHLovers - uma comunidade de cerca de dois milhĂ”es de pessoas alcanĂ§adas mensalmente atravĂ©s dos nossos canais digitais.Â  OpĂ§Ă”es veganas, sem lactose e sem adiĂ§ĂŁo de conservantes sĂŁo alguns dos diferenciais do nosso negĂłcio. \nSomos uma marca sĂłlida, transparente em todos os processos que acredita que o sucesso individual de cada franqueado Ă© um esforĂ§o diĂĄrio.', NULL, 'SĂO PAULO', 1, NULL, 152, NULL, NULL, '2026-03-09 19:10:13.439', 'https://franquias.portaldofranchising.com.br/franquia-jah/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '299000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77uk00q6eh0sbd8x8lxl', 'CREDFĂCIL', 'credfacil', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'PromoĂ§ĂŁo e intermediaĂ§ĂŁo de crĂ©ditos e financiamentos junto Ă s instituiĂ§Ă”es financeiras; IntermediaĂ§ĂŁo de consĂłrcios.', 2009, 2022, NULL, '2026-04-01 02:00:10.516', '2025-08-05 22:20:29.564', 979, NULL, 1, 2004, 'A CredfĂĄcil se destaca como uma franquia de serviĂ§os financeiros, estabelecendo parcerias sĂłlidas com os principais bancos e promotoras regulamentadas do Brasil. Em um mercado competitivo, oferecemos diversas modalidades de crĂ©dito altamente procuradas por milhĂ”es de brasileiros. O nosso diferencial reside no extenso know-how de 20 anos de mercado, uma experiĂȘncia que compartilhamos com nossos franqueados para assegurar o ĂȘxito de seus empreendimentos. Valorizamos o crescimento conjunto, e para isso, proporcionamos produtos com excelentes comissĂ”es e grande demanda no mercado. Na CredfĂĄcil, acreditamos no seu sucesso, e por isso, adotamos o sistema de royalties. Este Ă© um valor mensal que vocĂȘ paga para a franqueadora, e este investimento Ă© integralmente revertido na disponibilizaĂ§ĂŁo de ferramentas e recursos essenciais para fortalecer ainda mais a sua atuaĂ§ĂŁo. O lucro gerado Ă© integralmente seu, permitindo que vocĂȘ se torne um empreendedor de sucesso. Nosso comprometimento vai alĂ©m do inĂ­cio da sua franquia. Oferecemos treinamento e suporte especializado, mesmo para aqueles que nĂŁo possuem conhecimento prĂ©vio no universo financeiro. Investir em uma franquia CredfĂĄcil proporciona diversas vantagens, tais como: Baixo custo operacional e ausĂȘncia de capital de giro. ComissĂ”es pagas diariamente. Retorno rĂĄpido do investimento. Acesso a plataforma de marketing completa. Suporte operacional. Treinamentos na Universidade EAD. Equipe Comercial e Consultoria de campo. CRM para gestĂŁo e vendas. Ao escolher a Franquia CREDFĂCIL, vocĂȘ nĂŁo apenas ingressa em um negĂłcio promissor, mas tambĂ©m se une a uma rede comprometida com o seu crescimento e sucesso. Estamos aqui para guiĂĄ-lo em cada passo do caminho.', NULL, 'PARANĂ', 1, NULL, 1027, NULL, NULL, '2026-03-09 19:15:06.757', 'https://franquias.portaldofranchising.com.br/franquia-credfacil/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
