INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77ve00qaeh0srmrjuzbm', 'STERNA CAFĂ', 'sterna-cafe', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Cafeteria especializada em cafĂ©s especiais cultivados no Brasil e nos principais paĂ­ses produtores. A experiĂȘncia comeĂ§a com um espresso, passando pelos principais mĂ©todos de extraĂ§ĂŁo internacionais.', 2015, 2016, '[\"https://www.youtube.com/watch?v=tEyLDngnTKc\"]', '2026-04-01 02:00:10.535', '2025-08-05 22:20:29.594', 983, NULL, 1, 2015, 'O mundo das viagens e novas experiĂȘncias a partir de grĂŁos selecionados de cafĂ©, sĂŁo a base do conceito da Sterna. Seus fundadores viajaram o mundo por mais de 60 paĂ­ses, vivenciando diferentes culturas e experimentando novos e inovadores sabores, principalmente por meio do cafĂ©, bebida que Ă© sinĂŽnimo de receptividade e acolhimento ao redor do globo. O nome Sterna Ă© inspirado por uma ave de mesmo nome que ao longo de sua vida, percorre o equivalente a 60 voltas na Terra. Inspirados por isso, a Sterna CafĂ© nasceu em 2015 com a missĂŁo de levar todas essas experiĂȘncias cafeinadas atĂ© o cliente. Uma cafeteria Sterna CafĂ© une a oferta de grĂŁos de cafĂ©s especiais de vĂĄrias regiĂ”es do Brasil e do mundo, com a extraĂ§ĂŁo por mĂ©todos internacionalmente conhecidos, sempre em um ambiente pensado para que o cliente tenha uma nova experiĂȘncia a cada xĂ­cara de cafĂ©. Assim como trabalhamos com os melhores cafĂ©s, oferecemos um cardĂĄpio variado e adaptĂĄvel, elaborado para todos os momentos de venda, atendendo diferentes perfis de clientes e de acordo com o local de instalaĂ§ĂŁo da cafeteria. A franquia foi concebida com padrĂ”es arquitetĂŽnicos flexĂ­veis para que possa ser facilmente implantada em diferentes locais como lojas de rua, edifĂ­cios comerciais, hospitais, galerias comerciais, residenciais short stay, universidades, aeroportos, rodoviĂĄrias, shopping centers, estaĂ§Ă”es de metrĂŽ, strip malls, etc. Um formato que vem ganhando forĂ§a dentro da rede Ă© o modelo store in store, onde implantamos as nossas unidades em empresas que possuem sinergia com o nosso negĂłcio, como salĂ”es de cabelereiro, escritĂłrios comerciais, etc. VocĂȘ pode ter uma cafeteria premium da Sterna CafĂ© nos formatos Loja e Quiosque, com as opĂ§Ă”es de modelo convencional e container. Atualmente a rede conta com mais de 50 unidades em funcionamento em SP (capital e interior), RJ (capital e NiterĂłi), MG, DF, TO e PR (capital e Londrina). E seguimos crescendo! Vantagens de ser um franqueado Sterna: Apoio na localizaĂ§ĂŁo e negociaĂ§ĂŁo do ponto comercial; IndicaĂ§ĂŁo de arquiteto homologado; Suporte completo na implantaĂ§ĂŁo da unidade; Treinamento completo para o franqueado; Treinamento operacional para toda a equipe; Apoio total na inauguraĂ§ĂŁo da loja; Manuais operacionais completos; Universidade Sterna CafĂ©; FĂĄbrica de alimentos prĂłpria; Fornecedores homologados; Barista e nutricionista profissionais; Desenvolvimento de novos produtos; Consultoria de campo contĂ­nua; AgĂȘncia de publicidade; CalendĂĄrio anual de marketing Assessoria de imprensa; Marketing digital: DivulgaĂ§ĂŁo nas redes sociais; ConvĂȘnios com instituiĂ§Ă”es financeiras para financiamento; Associada Ă  ABF', NULL, 'SĂO PAULO', 1, NULL, 90, NULL, NULL, '2026-03-09 19:21:37.192', 'https://franquias.portaldofranchising.com.br/franquia-sterna-cafe-cafeterias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '389000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vk00qbeh0saoijahzs', 'DENTELAR FRANCHISING', 'dentelar-franchising', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'Rede de ClĂ­nicas OdontolĂłgicas com lucratividade acima da mĂ©dia. Fature R$ 100.000,00 no mĂȘs da sua inauguraĂ§ĂŁo. Seja Franqueado Dentelar e tenha uma clĂ­nica de Sucesso!', 2024, 2024, '[\"https://www.youtube.com/watch?v=Xy5KvtEN5C4\"]', '2026-04-01 02:00:10.545', '2025-08-05 22:20:29.600', 984, NULL, 1, 2012, 'HistĂłria Dentelar: Dra. Elaine, nordestina e baiana, da cidade de CaetitĂ©, sempre sonhou em ser odontĂłloga. ApĂłs concluir o ensino mĂ©dio, prestou vestibular em duas universidades, sendo aprovada em Belo Horizonte-MG e em ItaĂșna-MG. Optou por estudar em ItaĂșna devido Ă s caracterĂ­sticas de uma cidade do interior. Ao concluir a graduaĂ§ĂŁo, ela decidiu permanecer em ItaĂșna, onde iniciou sua carreira profissional em uma clĂ­nica local. O destino trouxe o mineiro Edgard para sua vida, e juntos decidiram viver em ItaĂșna. Posteriormente, decidiram empreender e abriram uma clĂ­nica prĂłpria. Edgard e Elaine se tornaram referĂȘncia na cidade, onde se formavam longas filas na porta aguardando atendimento. O sucesso logo resultou na abertura da segunda unidade em Mateus Leme-MG. Nascia assim um modelo de negĂłcio sĂłlido, lucrativo, sustentĂĄvel e replĂ­cavel! O crescimento continuou dando resultados excepcionais, e abriram mais trĂȘs unidades, em Itaguara, ClĂĄudio e Arcos. Agora a rede conta com cinco unidades prĂłprias e se prepara para levar a Dentelar para todos os cantos do Brasil. A expansĂŁo por franquias busca entregar aos novos franqueados um know-how de sucesso desenvolvido, testado e validado ao longo de 12 anos. Como estratĂ©gia temos cidades de 30 a 100 mil habitantes para melhor performance das unidades. A Dentelar tem uma lucratividade acima da mĂ©dia, cerca de 30%. AlĂ©m de faturar logo no primeiro mĂȘs R$ 100.000,00. Buscamos dentistas que busquem trocar os seus consultĂłrios para clĂ­nicas lucrativas ou empresĂĄrios que desejam investir em um dos setores que mais lucrativos do Brasil. Â  Perfil do Franqueado: Dentistas ou investidores que possuem interesse em investir como sĂłcio operador ou sĂłcio investidor em uma clĂ­nica Dentelar. O perfil ideal do franqueado para a Dentelar Franchising, preferencialmente, seja um dentista que demonstre habilidades clĂ­nica, juntamente com uma paixĂŁo pelo setor odontolĂłgico e um compromisso com a excelĂȘncia no atendimento ao paciente. AlĂ©m disso, Ă© fundamental que o dentista possua um perfil de lideranĂ§a e habilidades interpessoais para liderar e motivar a equipe, garantindo um ambiente de trabalho positivo e produtivo. O perfil gestor ou administrador deve ser um profissional com perfil executor, organizado e orientado para resultados. Deve possuir noĂ§Ă”es de gestĂŁo e administraĂ§ĂŁo, incluindo capacidade de planejamento, controle financeiro e estratĂ©gico. Â  Suporte: Suporte aos nossos franqueados Ă© a nossa prioridade. Queremos construir uma rede com uma cultura forte, padrĂŁo e qualidade nos atendimentos. Nosso know-how conta com 12 anos de mercado e processos realmente testados e validados. Â AlĂ©m de manuais oferecemos assistĂȘncia completa e treinamentos para vocĂȘ franqueado e sua equipe, alĂ©m de suporte no processo de planejamento, execuĂ§ĂŁo e curadoria dos custos da implantaĂ§ĂŁo. Temos um time inteiramente capacitado para te auxiliar nessa nova jornada. Nossa equipe te acompanharĂĄ desde as escolha do ponto ao dia a dia da gestĂŁo de agendas, campanhas de marketing estruturadas e estrtĂ©gias para captaĂ§ĂŁo de pacientes, um suporte dedicado para melhor performance da sua unidade. Â  PadrĂŁo Dentelar: Nossa estrutura caracterizam-se pelos espaĂ§os aconchegantes, qualidade superior dos equipamentos e insumos, alĂ©m do bom atendimento.', NULL, 'MINAS GERAIS', 1, NULL, 5, NULL, NULL, '2026-03-09 19:23:04.233', 'https://franquias.portaldofranchising.com.br/franquia-dentelar-franchising-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '302000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vp00qceh0sfexhlgds', 'ODONTO SPECIAL', 'odonto-special', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'Rede de clĂ­nicas odontolĂłgicas com atendimento completo, personalizado e de excelĂȘncia, unindo tecnologia avanĂ§ada a cuidados humanizados para transformar sorrisos.', 2018, 2019, '[\"https://www.youtube.com/watch?v=EJCqJu94oTk\"]', '2026-04-01 02:00:10.555', '2025-08-05 22:20:29.606', 985, NULL, 1, 2018, 'A Odonto Special by Sabrina Sato Ă© uma rede de clĂ­nicas que oferece o que hĂĄ de mais moderno em odontologia e estĂ©tica facial. Contamos com uma equipe altamente qualificada e tecnologia de ponta para oferecer tratamentos completos: limpeza, clareamento, lentes de contato dental, aparelhos ortodĂŽnticos, implantes, prĂłteses, tratamentos de canal, cirurgias, alĂ©m de procedimentos de harmonizaĂ§ĂŁo orofacial. Nosso compromisso Ă© cuidar da saĂșde bucal e realĂ§ar a beleza do sorriso com conforto, seguranĂ§a e excelĂȘncia no atendimento. Com a Odonto Special, vocĂȘ terĂĄ a oportunidade de transformar sua clĂ­nica atual em uma marca estruturada ou abrir uma nova unidade, com suporte 360Â°. NĂșmeros que refletem nosso sucesso: Faturamento mĂ©dio anual da franquia: R$ 1.8 milhĂŁo. Rentabilidade: entre 20% e 30%. Diferencial exclusivo: VocĂȘ nĂŁo precisa ser dentista para investir na Odonto Special. A franqueadora oferece um modelo testado e comprovado, com apoio total, transferĂȘncia de know-how e treinamentos que garantem o sucesso do franqueado. Invista em um dos setores que mais crescem no Brasil: o mercado odontolĂłgico â onde saĂșde, estĂ©tica e alto potencial de lucro caminham juntos. Suporte de ExcelĂȘncia para os Franqueados: A franqueadora oferece suporte total para os franqueados, garantindo o sucesso da operaĂ§ĂŁo atravĂ©s de duas plataformas estratĂ©gicas: Universidade Corporativa Presencial: Um centro de treinamento de alto nĂ­vel, com um auditĂłrio moderno e climatizado para atĂ© 150 pessoas, oferecendo uma infraestrutura completa, incluindo salas de reuniĂŁo, espaĂ§o exclusivo para franqueados e estacionamento prĂłprio. Universidade Corporativa EAD: Plataforma online com materiais estratĂ©gicos essenciais para a operaĂ§ĂŁo da franquia, como manuais, peĂ§as personalizĂĄveis para aĂ§Ă”es comerciais, campanhas de marketing, vĂ­deos de treinamentos e muito mais! LideranĂ§a e Credibilidade: A Odonto Special by Sabrina Sato Ă© conduzida por grandes nomes do mercado: Sidney Kalaes â Presidente do Grupo Kalaes, holding multissetorial de franquias, com mais de 31 anos de experiĂȘncia no setor. LĂ­der e fundador de diversas franqueadoras de sucesso. Sabrina Sato â Com seu carisma inconfundĂ­vel, a apresentadora e empresĂĄria transmite autenticidade e confianĂ§a, fortalecendo a credibilidade da marca junto ao pĂșblico. Sua presenĂ§a inspira autoestima e bem-estar, promovendo uma conexĂŁo genuĂ­na com os consumidores. Dr. Felipe Abreu â SĂłcio Fundador, Mestre e Especialista em odontologia (CRO/SP 110.635). Ă embaixador da Oral-B e tem mais de 19 anos de experiĂȘncia na ĂĄrea. Venha fazer parte dessa rede de sucesso!', NULL, 'SĂO PAULO', 1, NULL, 67, NULL, NULL, '2026-03-09 19:24:55.028', 'https://franquias.portaldofranchising.com.br/franquia-odonto-special/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '171300', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77vv00qdeh0sthmri8oe', 'ORAL UNIC IMPLANTES', 'oral-unic-implantes', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'ClĂ­nica OdontolĂłgica Premium, com foco em implantes e experiĂȘncia do paciente.', 2016, 2019, '[\"https://www.youtube.com/watch?v=TDAA-r8we0M\",\"https://www.youtube.com/watch?v=YB-CE7KIn90\"]', '2026-04-01 02:00:10.565', '2025-08-05 22:20:29.611', 986, NULL, 1, 2016, 'A Oral Unic nasceu em 2016, em ItajaĂ­ (SC), com o propĂłsito de transformar vidas por meio de sorrisos e uma gestĂŁo de excelĂȘncia. Em menos de 10 anos, nos consolidamos como a maior franquia de odontologia premium do Brasil, com mais de 300 clĂ­nicas em operaĂ§ĂŁo, faturamento superior a R$ 1 bilhĂŁo pelo segundo ano consecutivo e quatro conquistas do Selo de ExcelĂȘncia em Franchising da ABF. Oferecemos um modelo de negĂłcio sĂłlido, validado e de alta rentabilidade, com uma operaĂ§ĂŁo eficiente em um dos setores mais promissores do paĂ­s. Nosso propĂłsito nĂŁo Ă© ser apenas a maior, mas sim a melhor franquia odontolĂłgica do Brasil. E isso significa entregar o melhor suporte, a melhor implantaĂ§ĂŁo, os melhores treinamentos no maior centro de treinamento do franchising e as melhores ferramentas para que nossos franqueados cresĂ§am com consistĂȘncia e resultado.', NULL, 'SANTA CATARINA', 1, NULL, 213, NULL, NULL, '2026-03-09 19:26:24.427', 'https://franquias.portaldofranchising.com.br/franquia-oral-unic-implantes/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '614900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
