INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77wx00qkeh0sxjf1cxu6', 'LISĂ LASER', 'liso-laser', NULL, 'SaĂșde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'ClĂ­nica de DepilaĂ§ĂŁo a Laser.', 2022, 2023, '[\"https://www.youtube.com/watch?v=TgmUcj7_2ek\",\"https://www.youtube.com/watch?v=ZU-OrTalgSM\"]', '2026-04-01 02:00:10.630', '2025-08-05 22:20:29.649', 993, NULL, 1, 2021, 'A LisĂŽ Laser Ă© a franquia de depilaĂ§ĂŁo a laser que mais cresce no Brasil. Faz parte da We Scale, o maior ecossistema de franquias da AmĂ©rica Latina, responsĂĄvel por marcas como Oral Unic. Com tecnologia 4D exclusiva, operaĂ§ĂŁo simplificada e suporte completo, a LisĂŽ oferece um modelo atrativo, escalĂĄvel e com alto potencial de faturamento.', NULL, 'SANTA CATARINA', 1, NULL, 30, NULL, NULL, '2025-10-22 10:36:40.000', 'https://franquias.portaldofranchising.com.br/franquia-liso-laser/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77x200qleh0sjfmyynqp', 'DROGARIAS ĂTIMA FARMA', 'drogarias-otima-farma', NULL, 'SaĂșde, Beleza e Bem-Estar', 'FarmĂĄcias e ManipulaĂ§ĂŁo', 'Uma Rede de Franquias de Drogarias pautada na transparĂȘncia, profissionalismo e tecnologia, para o crescimento e desenvolvimento de empresĂĄrios que jĂĄ atuam no ramo farma e novos empresĂĄrios.', 2016, 2019, '[\"https://www.youtube.com/watch?v=zkyHsH6Uc-4\",\"https://www.youtube.com/watch?v=gz0BOZM459E\",\"https://www.youtube.com/watch?v=FQnXn73Vtfw\"]', '2026-04-01 02:00:10.640', '2025-08-05 22:20:29.654', 994, NULL, 1, 2016, 'Em dezembro de 2015, Marcelo Ferreira e Juarez Ricardo de Souza, dois empresĂĄrios com vasta experiĂȘncia no mercado farmacĂȘutico, com vivĂȘncia em consultoria empresarial e know-how no sistema de franquias, idealizaram a Rede de Franquias Ătima Farma. No final de 2016, foi inaugurada a Central de GestĂŁo Ătima Farma (sede da franqueadora) e vĂȘm expandindo sua atuaĂ§ĂŁo em nĂșmero de unidades. Atualmente, a franquia possui lojas ativas em sua capital mineira Belo Horizonte, grande BH, SĂŁo Paulo, Rio de Janeiro, dentre outras cidades. Tendo atuado nos Ășltimos 30 anos no mercado farmacĂȘutico, nossos gestores conhecem a fundo todo o trabalho de expansĂŁo e gestĂŁo de drogarias. Dessa forma, nosso maior diferencial Ă© poder oferecer aos nossos franqueados todo o suporte necessĂĄrio para que sua drogaria/farmĂĄcia opere de forma competitiva frente a concorrĂȘncia. Em 2019 passou a integrar o seletivo grupo de associados da ABF (AssociaĂ§ĂŁo Brasileira de Franchising). No inĂ­cio de 2022, a Ătima Farma foi chancelada pela AssociaĂ§ĂŁo Brasileira de Franchising (ABF) com o Selo de ExcelĂȘncia que se trata da maior honraria do mercado de franquias Brasileiro. Esta certificaĂ§ĂŁo carrega uma histĂłria de trĂȘs dĂ©cadas e desde entĂŁo, reconhece o quanto as Franquias tĂȘm se destacado e se desenvolvido no paĂ­s. O Selo de ExcelĂȘncia contribui de maneira Ă­mpar para a Rede Ătima Farma se destacar no meio farmacĂȘutico e continuar sendo referĂȘncia de qualidade, eficiĂȘncia do setor e sobretudo alcanĂ§ar novos territĂłrios. Em 2023 no mĂȘs de abril passa a integrar maior federaĂ§ĂŁo de farmĂĄcia do Brasil, Ă  Febrafar. A FederaĂ§ĂŁo Brasileira das Redes Associativas e Independentes de FarmĂĄcias, Febrafar, Ă© uma sociedade civil sem fins lucrativos criada em fevereiro de 2000, tendo seu DNA formado por premissas fundamentadas em trĂȘs fortes pilares: A cultura empreendedora; O relacionamento colaborativo; AtuaĂ§ĂŁo visionĂĄria. A grandeza em nĂșmeros da Febrafar impressiona: 66 redes de farmĂĄcias, com lojas em 26 estados e no Distrito Federal. As mais de 17 mil lojas integradas Ă s redes associadas Ă  Febrafar, em 26 estados + DF, atendem clientes em mais de 3.000 municĂ­pios. Em julho de 2023 inicia uma parceria (fusĂŁo) com o Grupo Farma. Um grupo com 23 anos no mercado Farma, se uni a Ătima Farma, passando a ser chamada de Grupo Ătima. O Grupo Ătima no mĂȘs de setembro/23, jĂĄ conta com 301 operaĂ§Ă”es em 10 Estados.', NULL, 'MINAS GERAIS', 1, NULL, 31, NULL, NULL, '2026-03-09 19:33:48.864', 'https://franquias.portaldofranchising.com.br/franquia-drogarias-otima-farma/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
