INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xi00qoeh0s9446z3ld', 'QUALITĂ ODONTOLOGIA', 'qualite-odontologia', NULL, 'SaĂșde, Beleza e Bem Estar', 'ODONTOLOGIA', 'ClĂ­nicas OdontolĂłgicas', 2022, 2023, NULL, '2026-04-01 02:00:10.667', '2025-08-05 22:20:29.670', 997, NULL, 1, 2016, '', NULL, 'SĂO PAULO', 1, NULL, 4, NULL, NULL, '2025-07-24 13:27:35.000', 'https://franquias.portaldofranchising.com.br/franquia-qualite-odontologia-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xn00qpeh0s8wqw2yma', 'QG JEITINHO CASEIRO', 'qg-jeitinho-caseiro', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Rede de restaurantes especializada no preparo de pastĂ©is, grelhados, frango frito, sanduĂ­ches, petiscos com sabor e temperos caseiros.', 2009, 2010, NULL, '2026-04-01 02:00:10.677', '2025-08-05 22:20:29.675', 998, NULL, 1, 1981, 'Somos apaixonados pela arte de cozinhar com temperos frescos, e por cuidar, promover o bem-estar e prolongar a vida das pessoas! \nTemos orgulho em seguir receitas caseiras, testadas pelo tempo e por cozinheiros de mĂŁo cheia. Com uma jĂĄ consolidada experiĂȘncia em rede de Fast Food, o Grupo QG vem investindo estrategicamente na expansĂŁo de suas marcas com foco em inovaĂ§ĂŁo e excelĂȘncia no fornecimento de produtos e atendimento aos seus clientes. \nA franquia QG JEITINHO CASEIRO Ă© desenvolvida atravĂ©s da operaĂ§ĂŁo de um estabelecimento comercial no segmento de comida caseira de rĂĄpido atendimento, que comercializa alimentos e bebidas em geral, tendo como diferencial a qualidade superior de seus serviĂ§os e produtos. \nContamos com 6 modelos de negĂłcios, sendo eles: Container, Shopping e Hipermecado, Loja de Rua, Dark Kitchen (Somente delivery), Double (Cozinha dupla) e Carrinho. Nossos modelos de negĂłcio possibilitam integrar em ambientes de grande fluxo de pessoas como: Shoppings, Hipermercados, Lojas de Rua, Centros Comerciais, Open Mall e outros.\nÂ  10 diferenciais da nossa franquia: Â TradiĂ§ĂŁo, com mais de 40 anos no ramo alimentĂ­cio;\n\tÂ  Â Somos 3 em 1: QG Jeitinho Caseiro, Chicken Lovers e BupaqĂȘ! 3 cozinhas que atendem a todos os pĂșblicos. Menus que contam com pastĂ©is, grelhados, saladas, frango no balde, petiscos, sanduĂ­ches gourmets, x-tudo, bebidas e muito mais.\n\tÂ  Â Qualidade reconhecida pelos consumidores;\n\tÂ  Â PreĂ§os competitivos para uma alimentaĂ§ĂŁo no dia-a-dia;\n\tÂ  Â Vencedora do Selo de ExcelĂȘncia em Franchising pela ABF em 2013, 2014, 2015, 2016, 2017, 2019, 2020 e tambĂ©m vencedora do prĂȘmio âMelhores Franquias do Brasilâ pela Pequenas Empresas & Grandes negĂłcios em 2013, 2018, 2019, 2020, 2021 e 2022.\n\tÂ  Oportunidade do franqueado expandir em conjunto com a marca;\n\tÂ  Marca associada Ă  ABF;\n\tÂ  Lucratividade de atĂ© 25%;\n\tÂ  Suporte total ao franqueado por Whatsapp, telefone, e-mail e extranet. AlĂ©m de consultorias presenciais para aprimorar a operaĂ§ĂŁo e os resultados da unidade franqueada;\n\tÂ  Possui fĂĄbrica prĂłpria para garantir sabor exclusivo das marcas.', NULL, 'GOIĂS', 1, NULL, 52, NULL, NULL, '2026-03-09 19:35:54.255', 'https://franquias.portaldofranchising.com.br/franquia-qg-jeitinho-caseiro-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77xs00qqeh0sjp3c8tr2', 'AMAZON SPA', 'amazon-spa', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Revenda de banheiras e SPAS de hidromassagem', 2017, 2019, '[\"https://www.youtube.com/watch?v=1r7mqoXEyWI\"]', '2026-04-01 02:00:10.686', '2025-08-05 22:20:29.681', 999, NULL, 1, 2001, 'A IndĂșstria Ăgua Nativa, fundadora da rede de franquias Amazon Spa, nasceu em 2001 em Curitiba no PR, fundada por Edson Schneider. \nAtĂ© 2001, Edson trabalhava com piscinas, porĂ©m sua inquietaĂ§ĂŁo e visĂŁo de futuro lhe levou a construir de forma artesanal o primeiro OfurĂŽ da Ăgua Nativa. \nO sucesso de vendas foi imediato, a produĂ§ĂŁo foi crescendo e houve a necessidade de mais espaĂ§o fĂ­sico. \nEm 2003 a Ăgua Nativa foi levada para uma sede definitiva em Campina Grande do Sul/PR, onde contou com mais espaĂ§o para ampliaĂ§ĂŁo da fĂĄbrica. \nTrata-se de 10.000 mÂČ onde se preserva parte da ĂĄrea como reserva ambiental, traduzindo uma preocupaĂ§ĂŁo da Ăgua Nativa com o crescimento sustentĂĄvel. \nEm 2004 banheiras e SPAs entraram na linha de produĂ§ĂŁo. Em 2010, os produtos atĂ© entĂŁo fabricados somente em Gel Coat, passaram a ser fabricados tambĂ©m em acrĂ­lico, uma tecnologia mais moderna.Â  \nA primeira loja Amazon SPA, que foi uma loja piloto, inaugurada em 2008 e administrada pela FĂĄbrica Ăgua Nativa atĂ© 2018. \nA segunda loja foi criada em 2013 e foi administrada pela FĂĄbrica Ăgua Nativa atĂ© 2016 com o objetivo de conhecer as necessidades do varejo.Â  \nA IndĂșstria Ăgua Nativa operou duas lojas prĂłprias no varejo com o objetivo de conhecer o varejo, as necessidades do consumidor final e adequar as lojas ao sistema de Franquias. \nAtualmente ambas as lojas sĂŁo Franquias operadas por Franqueados. \nEm 2020, a Ăgua Nativa - usando a marca Amazon SPA, estava definitivamente preparada para dar inĂ­cio a abertura de mercado com franquias. \nAtualmente a marca possui 4 lojas Amazon SPA franqueadas.', NULL, 'PARANĂ', 1, NULL, 9, NULL, NULL, '2026-03-09 19:37:16.437', 'https://franquias.portaldofranchising.com.br/franquia-amazon-spa/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '67700', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
