INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77y300qseh0sbr6fe45f', 'FOR RENTAL', 'for-rental', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Somos uma empresa especializada em aluguel de equipamentos para construĂ§ĂŁo civil, limpeza e jardinagem um dos principais pilares do PIB Nacional', 2015, 2016, '[\"https://www.youtube.com/watch?v=ZiFOVU4f76I\",\"https://www.youtube.com/watch?v=yMsywvJtOlU\"]', '2026-04-01 02:00:10.705', '2025-08-05 22:20:29.691', 1001, NULL, 1, 2015, 'Obrigado pelo seu interesse em conhecer a For Rental. Nossa Empresa foi criada com muito amor e dedicaĂ§ĂŁo. Nossa histĂłria foi escrita com Ă©tica, com responsabilidade social, pela paixĂŁo ao trabalho, devotada Ă  sustentabilidade, Ă  inovaĂ§ĂŁo, manifestada na excelĂȘncia do atendimento ao cliente, no respeito humano.  HistĂłria escrita por Daniel Rodrigues de Souza com expertise de 30 anos no segmento de Franchising, desde sua constituiĂ§ĂŁo foi planejada para fazer parte do seguimento de Franchising no Brasil no segmento de Aluguel de Equipamentos para ConstruĂ§ĂŁo, Limpeza e jardinagem um dos setores que mais cresce no mundo. \nUma Empresa Genuinamente Brasileira, que tem em sua MissĂŁo, VisĂŁo e Valores zelar por um Brasil melhor, com mais condiĂ§Ă”es de igualdade para todos, viabilizando para empreendedores e investidores de ter seu prĂłprio negĂłcio com maiores chances de sucesso em um mercado duro em uma relaĂ§ĂŁo âganha & ganhaâ e duradora.Â  NegĂłcio Aluguel de equipamentos para: ConstruĂ§ĂŁo; Limpeza; Jardinagem.\n\tÂ  ExperiĂȘncia dos proprietĂĄrios da For Rental: 30 anos de experiĂȘncia no Franchising;Â \n\tÂ  Diferencias For Rental: Todos modelos comeĂ§am com o mesmo investimento âStartâ de negĂłcio, facilitando o inĂ­cio do negĂłcio com investimentos reduzidos projetando investimentos gradativos; Quadro de funcionĂĄrios baixo. Taxa de Retorno sobre o investimento total de 6%; Investimento totalmente customizado por mercado; Margem acima do mercado de 20 a 40% ou de R$ 16.000,00 a R$ 32.000,00 por mĂȘs; Suporte presencial PrĂ© e PĂłs- inauguraĂ§ĂŁo; Os primeiros seis meses de atividade da unidade, nĂłs nĂŁo cobramos Royalties*; NĂŁo cobramos fundo de propaganda; O Royalty Ă© cobrado somente sobre Faturamento de LocaĂ§ĂŁo os outros faturamentos, Frete, ServiĂ§os e ManutenĂ§ĂŁo de Equipamentos nĂŁo sĂŁo cobrados Royalties, sendo totalmente livre para o Franqueado; Garantia de proposta de recompra de sua unidade apĂłs o perĂ­odo mĂ­nimo de dois anos de atividade caso nĂŁo tenha atingindo a margem lĂ­quida proposta mĂ­nima de 20%, com base na avaliaĂ§ĂŁo feita pela Franqueadora de uma proposta utilizando dados do Software de GestĂŁo For Rental caso a unidade nĂŁo esteja atingido o payback proposto pela Franqueadora em contrato 24 a 36 meses; Plano de expansĂŁo interna: Queremos que nossos franqueados tenham amplitude em sua regiĂŁo com a preferĂȘncia de territĂłrios prĂłximos aumentando seu raio de atuaĂ§ĂŁo e de maneira que tenhamos menos franqueados com mais franquias;Â  Ponto de equilĂ­brio em aproximadamente nove meses; Payback de equipamentos aproximadamente em 12 meses; SĂĄbado e Domingo estarĂĄ em sua casa cuidando de seu maior bem, sua FamĂ­lia. Â Â   *Com o pagamento integral da Taxa de Franquia Â  NĂŁo seja mais um Franqueado, seja âO Franqueadoâ For Rental Â  âDĂȘ uma Oportunidade ao seu Sucessoâ', NULL, 'SĂO PAULO', 1, NULL, 19, NULL, NULL, '2026-03-09 19:38:42.762', 'https://franquias.portaldofranchising.com.br/franquia-for-rental/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '190000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77y900qteh0s1pvz5pou', 'HAVAIANAS', 'havaianas', NULL, 'Moda', 'CALĂADOS', 'Loja exclusiva de produtos Havaianas, coleĂ§ĂŁo de sandĂĄlias, chinelos e acessĂłrios.', 2008, 2009, NULL, '2026-04-01 02:00:10.714', '2025-08-05 22:20:29.698', 1002, NULL, 1, 1962, 'SOBRE A FRANQUIA HAVAIANAS Simples, cool, intensa e democrĂĄtica, assim Ă© Havaianas, a sandĂĄlia mais famosa do mundo que desde 1962 faz parte da vida dos brasileiros. Atualmente nossas sandĂĄlias sĂŁo exportadas para mais de 120 paĂ­ses. SĂŁo cerca de 200 modelos, que somados as cores e estilos, chegam a mais de 1.200 sandĂĄlias diferentes. NĂŁo importa a classe social, o estilo, o sexo ou a idade, vocĂȘ sempre encontrarĂĄ uma Havaianas para fazer a sua cabeĂ§a. INFORMAĂĂES DA FRANQUIA As lojas Havaianas foram idealizadas para oferecer aos consumidores uma experiĂȘncia completa com a marca. O modelo de franquia foi adotado porque acreditamos que empresĂĄrios locais que se identifiquem com a marca e com nosso negĂłcio podem agregar conhecimento e experiĂȘncia regional, fundamental para o sucesso das lojas. INVESTIMENTO: Taxa de Franquia = R$ 45.000,00 (quarenta e cinco mil reais); InstalaĂ§ĂŁo da Loja: De 255.000,00 a 800.000,00 (Duzentos e cinquenta e cinco mil reais a Oitocentos mil reais). INVESTIMENTO TOTAL: (incluindo taxa de franquia + instalaĂ§ĂŁo + estoque) De R$ 300.000,00 a R$ 845.000,00 (mĂ©dia) NĂŁo cobramos royalties; O franqueado destinarĂĄ 2% de seu faturamento bruto mensal para investimento em MKT local para divulgaĂ§ĂŁo de sua loja ( A franqueadora nĂŁo recolherĂĄ esse valor); Pay Back estimando: de 12 a 36 meses; Custo do ponto comercial (luvas) nĂŁo estĂĄ incluĂ­do no investimento e no cĂĄlculo de pay back (retorno).', NULL, 'SĂO PAULO', 1, NULL, 712, NULL, NULL, '2026-02-05 15:48:53.000', 'https://franquias.portaldofranchising.com.br/franquia-havaianas-valor/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '235000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
