INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77yv00qxeh0s1jke0r6u', 'O BURGUĂS', 'o-burgues', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O BurguĂȘs iniciou sua operaĂ§ĂŁo com uma loja em 2017. Com produtos de alta qualidade e um modelo de negĂłcio de administraĂ§ĂŁo simples. Hoje se consolida como a maior hamburgueria delivery do Brasil.', 2018, 2019, NULL, '2026-04-01 02:00:10.754', '2025-08-05 22:20:29.719', 1006, NULL, 1, 2017, 'Criado com o intuito de inovar no serviĂ§o delivery do mercado de hambĂșrgueres no Rio de Janeiro, O BurguĂȘs iniciou sua operaĂ§ĂŁo com uma loja em fevereiro de 2017. \nProdutos de alta qualidade aliados a um modelo de negĂłcio de administraĂ§ĂŁo simples e de baixo risco fizeram a marca superar as expectativas do segmento, e alcanĂ§ar, em 3 anos, um crescimento meteĂłrico em nĂșmero de lojas. \nEm 2020 passamos a operar com 21 lojas, sendo 6 fora do Rio (3 em SĂŁo Paulo, 1 em BrasĂ­lia/DF, 1 em VitĂłria/ES e 1 em Belo Horizonte/MG). \nHoje nos consolidamos como a maior hamburgueria delivery do Brasil, inseridos de acordo com a ABRASEL (AssociaĂ§ĂŁo de Bares e Restaurentes) em um mercado que sĂł vem crescendo, o de conveniĂȘncia (delivery), com um faturamento estimado em R$ 20 milhĂ”es em 2020. \nSomos Key account de um dos principais aplicativos delivery da atualidade, tendo promoĂ§Ă”es personalizadas entre outras vantagens.', NULL, 'RIO DE JANEIRO', 1, NULL, 59, NULL, NULL, '2026-03-09 19:42:14.001', 'https://franquias.portaldofranchising.com.br/franquia-o-burgues/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '450000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77z100qyeh0s1irb5njw', 'GOLLOG', 'gollog', NULL, 'ServiĂ§os e Outros NegĂłcios', 'LogĂ­stica e OperaĂ§Ă”es', 'Transporte de cargas', 2005, 2011, NULL, '2026-04-01 02:00:10.764', '2025-08-05 22:20:29.725', 1007, NULL, 1, 2001, 'SĂł a Gollog, serviĂ§o de cargas da GOL, conta com a infraestrutura de uma das maiores companhias aĂ©reas do paĂ­s em seu negĂłcio. \nSĂŁo mais de 100 unidades que atendem cerca de 3.500 cidades em todo o Brasil.  Marca Conhecida \nCrescimento 2 vezes maior que a dos principais concorrentes Mais de 1 milhĂŁo de encomendas emitidas anualmente Sete bases internacionais: Buenos Aires, RosĂĄrio e CĂłrdoba (Argentina), AssunĂ§ĂŁo (Paraguai), Santa Cruz de la Sierra (BolĂ­via), Santiago (Chile) e MontevidĂ©u (Uruguai). \nE as vantagens nĂŁo param por aĂ­, como franqueado Gollog vocĂȘ ainda conta com benefĂ­cios de orientaĂ§ĂŁo e assessoria, antes e apĂłs a inauguraĂ§ĂŁo da sua franquia.  Antes da Abertura \nÂ - Uso da marca Gollog;\nÂ - Treinamento de prĂ©-inauguraĂ§ĂŁo;\nÂ - OrientaĂ§ĂŁo e suporte na aquisiĂ§ĂŁo de todos os equipamentos e materiais padronizados, junto a fornecedores licenciados;\nÂ - Fornecimento dos Manuais de identidade visual (papelaria/veĂ­culos/uniformes);\nÂ - OrientaĂ§ĂŁo ao Franqueado na reforma, construĂ§ĂŁo ou adaptaĂ§ĂŁo do imĂłvel onde serĂĄ instalada sua Franquia, garantindo que o mesmo esteja conforme os padrĂ”es da rede Gollog;\nÂ - ApĂłs a InauguraĂ§ĂŁo Consultoria de campo com visitas periĂłdicas de acompanhamento e assessoria, para garantir a padronizaĂ§ĂŁo da rede e o desenvolvimento da Franquia;\nÂ - Apoio atravĂ©s de treinamentos e reciclagens; Assessoria, desenvolvimento, aperfeiĂ§oamento e fornecimento do software utilizado pelo Sistema Gollog e outros instrumentos necessĂĄrios Ă  administraĂ§ĂŁo da Franquia;\nÂ - CoordenaĂ§ĂŁo de toda propaganda e promoĂ§ĂŁo da marca e da rede Gollog;\nÂ - Desenvolvimento constante de novas tĂ©cnicas de gestĂŁo e de atuaĂ§ĂŁo, para manter a rede atualizada Ă s necessidades dos clientes;  Escolha entre 4 modalidades de franquia: \nCentro Operacional \nÂ - Venda de carga expressa e convencional;\nÂ - Coletas domiciliares;\nÂ - Triagem, manuseio de cargas fracionadas e outros objetos;\nÂ - Entrega domiciliar, ao cliente destinatĂĄrio, de cargas ;  Loja \nÂ - Venda de carga expressa e convencional;\nÂ - Coletas domiciliares;\nÂ - Remessa de volumes para os Terminais Operacionais Comerciais;\nÂ - InformatizaĂ§ĂŁo das operaĂ§Ă”es;  QuiosqueÂ Gollog \nSĂł a Gollog, serviĂ§o de cargas da GOL, conta com a infraestrutura de uma das maiores companhias aĂ©reas do paĂ­s em seu negĂłcio. \nSĂŁo mais de 100 unidades que atendem cerca de 3.500 cidades em todo o Brasil.  Marca Conhecida \nCrescimento 2 vezes maior que a dos principais concorrentes Mais de 1 milhĂŁo de encomendas emitidas anualmente Sete bases internacionais: Buenos Aires, RosĂĄrio e CĂłrdoba (Argentina), AssunĂ§ĂŁo (Paraguai), Santa Cruz de la Sierra (BolĂ­via), Santiago (Chile) e MontevidĂ©u (Uruguai). \nE as vantagens nĂŁo param por aĂ­, como franqueado Gollog vocĂȘ ainda conta com benefĂ­cios de orientaĂ§ĂŁo e assessoria, antes e apĂłs a inauguraĂ§ĂŁo da sua franquia.  Antes da Abertura \nÂ - Uso da marca Gollog;\nÂ - Treinamento de prĂ©-inauguraĂ§ĂŁo;\nÂ - OrientaĂ§ĂŁo e suporte na aquisiĂ§ĂŁo de todos os equipamentos e materiais padronizados, junto a fornecedores licenciados;\nÂ - Fornecimento dos Manuais de identidade visual (papelaria/veĂ­culos/uniformes);\nÂ - OrientaĂ§ĂŁo ao Franqueado na reforma, construĂ§ĂŁo ou adaptaĂ§ĂŁo do imĂłvel onde serĂĄ instalada sua Franquia, garantindo que o mesmo esteja conforme os padrĂ”es da rede Gollog;\nÂ - ApĂłs a InauguraĂ§ĂŁo Consultoria de campo com visitas periĂłdicas de acompanhamento e assessoria, para garantir a padronizaĂ§ĂŁo da rede e o desenvolvimento da Franquia;\nÂ - Apoio atravĂ©s de treinamentos e reciclagens; Assessoria, desenvolvimento, aperfeiĂ§oamento e fornecimento do software utilizado pelo Sistema Gollog e outros instrumentos necessĂĄrios Ă  administraĂ§ĂŁo da Franquia;\nÂ - CoordenaĂ§ĂŁo de toda propaganda e promoĂ§ĂŁo da marca e da rede Gollog;\nÂ - Desenvolvimento constante de novas tĂ©cnicas de gestĂŁo e de atuaĂ§ĂŁo, para manter a rede atualizada Ă s necessidades dos clientes;  Escolha entre 4 modalidades de franquia: \nCentro Operacional \nÂ - Venda de carga expressa e convencional;\nÂ - Coletas domiciliares;\nÂ - Triagem, manuseio de cargas fracionadas e outros objetos;\nÂ - Entrega domiciliar, ao cliente destinatĂĄrio, de cargas ;  Loja \nÂ - Venda de carga expressa e convencional;\nÂ - Coletas domiciliares;\nÂ - Remessa de volumes para os Terminais Operacionais Comerciais;\nÂ - InformatizaĂ§ĂŁo das operaĂ§Ă”es;  Quiosque \nÂ - Venda  Container \nÂ - Venda  Container \nÂ - Venda', NULL, 'SĂO PAULO', 1, NULL, 130, NULL, NULL, '2026-03-09 19:42:54.633', 'https://franquias.portaldofranchising.com.br/franquia-gollog/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '139312.5', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77z600qzeh0s6mr8324j', 'MONSTER DOG', 'monster-dog', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Ramo alimentĂ­cio de comida rĂĄpida vendendo hot-dog, hambĂșrgueres, salgados, pĂŁo de queijo, refrigerantes e sucos. Pontos entre 2,5mÂČ e 100mÂČ, segmentado Ă  classe B, C e D, ao pĂșblico em geral.', 2016, 2018, NULL, '2026-04-01 02:00:10.775', '2025-08-05 22:20:29.730', 1008, NULL, 1, 2002, 'A marca Monster Dog foi criada em 2007 com sua primeira loja no terminal rodoviĂĄrio urbano Vila Nova Cachoeirinha, atualmente alĂ©m dessa contamos com mais duas unidades da marca no mesmo local. O Monster Dog surgiu com a idĂ©ia de unificar a comida rĂĄpida de rua com a qualidade e garantia de marcas reconhecidas no mercado. Sempre servindo os melhores lanches com qualidade, agilidade, simpatia e o diferencial de ter preĂ§os acessĂ­veis.', NULL, 'SĂO PAULO', 1, NULL, 60, NULL, NULL, '2026-03-09 19:45:06.045', 'https://franquias.portaldofranchising.com.br/franquia-monster-dog/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zb00r0eh0sxp8j6nl4', 'BISCOITĂ', 'biscoite', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'Biscoitos especiais para presentes e cafeteria.', 2018, 2021, NULL, '2026-04-01 02:00:10.785', '2025-08-05 22:20:29.735', 1009, NULL, 1, 2012, 'A BiscoitĂȘ Ă© uma boutique de biscoitos finos. Das receitas Ă s embalagens, tudo Ă© criado com tempo, cuidado e dedicaĂ§ĂŁo. \nAs receitas sĂŁo inspiradas em diferentes culturas e preparadas com ingredientes da melhor qualidade. \nCriada desde 2012 com outro nome, a BiscoitĂȘ transformou-se em um case de sucesso a partir de 2016. \nSendo a Ășnica franquia do Brasil a atuar no mercado de biscoitos, mercado este, maior que o de chocolate, chegando a ter mais de R$20 bilhĂ”es vendidos todos os anos no mundo. \nCom o propĂłsito de transformar a vida das pessoas atravĂ©s de momentos, biscoitos e presentes feitos com amor e unindo-se a uma identidade consolidada, um forte marketing, fidelizaĂ§ĂŁo de produtos e lanĂ§amentos, seu ticket mĂ©dio de faturamento Ă© 3x maior que o de uma cafeteria.Â  \nPreocupada em atender todos os pĂșblicos, a BiscoitĂȘ se diferencia pela grande quantidade de tipos de biscoitos. \nAlĂ©m dos tradicionais, existe a linha kids, a zero (glutĂ©n e lactose) e salgados e muito mais. \nA BiscoitĂȘ nĂŁo vende sĂł produtos, vende momentos e, pensando nisso, a linha de biscoitos sazonais proporciona experiĂȘncias incrĂ­veis nas datas comemorativas mais marcantes do ano, como Natal, PĂĄscoa, Dia das MĂŁes, Dia dos Pais, Dia dos Professores, entre outros.Â  \nCom a BiscoitĂȘ, a oportunidade de faturamento pode acontecer de diversas maneiras: vendas por delivery, parceria com lojistas, vendas corporativas, alĂ©m da presenĂ§a em eventos. \nO franqueado da BiscoitĂȘ conta com todo o suporte e treinamento para que sua loja tenha o mais excelente serviĂ§o que a boutique tem a oferecer.', NULL, 'SĂO PAULO', 1, NULL, 63, NULL, NULL, '2026-03-09 19:45:37.372', 'https://franquias.portaldofranchising.com.br/franquia-biscoite/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zg00r1eh0smiu6yd5i', 'BIO MUNDO', 'bio-mundo', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'suplementos, produtos naturais e a granel.', 2017, 2018, '[\"https://www.youtube.com/watch?v=NrOFA7TdEBk\"]', '2026-04-01 02:00:10.795', '2025-08-05 22:20:29.741', 1010, NULL, 1, 2015, 'Nascida em 2015, a Bio Mundo jĂĄ nasceu sendo um tremendo sucesso: somente no primeiro ano como franquia jĂĄ foram mais de 23 operaĂ§Ă”es ativas, representando um recorde do perĂ­odo quando se fala em franquias de alimentaĂ§ĂŁo saudĂĄvel. Atualmente, jĂĄ sĂŁo mais de 150 franquias franqueados na rede, presentes em mais de 17 estados do paĂ­s.Â  \nAlĂ©m disso, a franquia jĂĄ foi premiada com o Selo de ExcelĂȘncia em Franchising dado pela AssociaĂ§ĂŁo Brasileira de Franquias (ABF).Â  Isso porque a Bio Mundo Ă© a loja de produtos naturais mais completa do mercado. \nO seu mix de produtos consiste em mais de 10 mil itens entre 3 principais categorias: a linha a granel, a linha de nutriĂ§ĂŁo espotiva esportiva e os produtos naturais.Â  \nEssa diversificaĂ§ĂŁo permite atrair mais clientes em suas lojas e, consequentemente, garante um maior faturamento para os seus franqueados. Sendo uma rede especialista em pontos de loja fĂ­sica, a franquia trabalha com lojasÂ  entre 45mÂČ a 100mÂČ, adaptados de acordo com a realidade do local, seja na rua, shopping, aeroporto, centros comerciais, galerias e hipermercados. Ter uma franquia Bio Mundo Ă© ter nas mĂŁos a oportunidade de trabalhar com produtos de alta qualidade, recebendo suporte completo da franqueadora.', NULL, 'DISTRITO FEDERAL', 1, NULL, 151, NULL, NULL, '2026-03-09 19:46:33.264', 'https://franquias.portaldofranchising.com.br/franquia-bio-mundo/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '285000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zl00r2eh0sxk2yky32', 'MEGA VISAO FRANQUIAS LTDA', 'mega-visao-franquias-ltda', NULL, 'SaĂșde, Beleza e Bem Estar', 'ĂTICAS', 'saude visual', 2023, 2025, NULL, '2026-04-01 02:00:10.806', '2025-08-05 22:20:29.745', 1011, NULL, 1, 2008, '', NULL, 'PARANĂ', 1, NULL, 3, NULL, NULL, '2025-07-28 08:28:17.000', 'https://franquias.portaldofranchising.com.br/franquia-mega-visao-franquias-ltda-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza77zr00r3eh0sge8bqk5l', 'BOALI', 'boali', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Segmento de \"healthy fast food\" com cardĂĄpio completo que abrange saladas, wraps, bowls, crepes, burritos, sucos e sobremesas com foco na saudabilidade, sustentabilidade e praticidade.', 2007, 2016, '[\"https://www.youtube.com/watch?v=pQ_BcarSQJk\",\"https://www.youtube.com/watch?v=bAEwka1Qd_Q\",\"https://www.youtube.com/watch?v=DQhq-xw_QMc\"]', '2026-04-01 02:00:10.816', '2025-08-05 22:20:29.752', 1012, NULL, 1, 2007, 'Nossa histĂłria comeĂ§a em 2006 quando 4 amigos se unem com um objetivo em comum que Ă© transformar os hĂĄbitos alimentares da populaĂ§ĂŁo, e trouxeram para o Brasil a primeira rede de alimentaĂ§ĂŁo saudĂĄvel do mundo, a Marca AmericanaÂ Salad Creations. Em 2007 foi inaugurada a primeira loja conceito em um Shopping Center localizado na zona oeste da capital paulistana. ApĂłs uma grande experiĂȘncia em gestĂŁo de rede de alimentaĂ§ĂŁo saudĂĄvel e varejo, em 2015 os sĂłcios fundam a BOALI com o propĂłsito de universalizar o acesso a alimentaĂ§ĂŁo saudĂĄvel e transformar hĂĄbitos e fazer o bem por meio da comida. A Marca BOALI Ă© derivada da uniĂŁo das palavras âboaâ e âalimentaĂ§ĂŁoâ, foi criada para ser um sinĂŽnimo de comida gostosa, saudĂĄvel, prĂĄtica e acessĂ­vel.Â Â Â  Nascida com o intuito de oferecer uma relaĂ§ĂŁo sustentĂĄvel e saudĂĄvel Ă  sociedade e Ă  natureza, a Franqueadora busca constantemente, por meio da criatividade e inovaĂ§ĂŁo no desenvolvimento dos produtos comercializados, contribuir com a possibilidade de implantar um novo mundo, em que o respeito ao meio ambiente e Ă s pessoas, reflitam Ă  comercializaĂ§ĂŁo de uma alimentaĂ§ĂŁo saborosa e saudĂĄvel. Nosso cardĂĄpio Ă©, portanto, composto por ingredientes nobres e de alta qualidade, e nossos pratos sĂŁo elaborados com o objetivo de atender ao pĂșblico de maneira geral. Por esta razĂŁo, a BOALI considera-se uma Marca democrĂĄtica, abrangente e plural. Somos feitos de pessoas e focados em transformar a vida das pessoas. Vamos juntos inspirar mudanĂ§as e promover o bem com otimismo e vitalidade. BOALI Uma marca 100% brasileira Gente de verdade, fazendo COMIDA DE VERDADE e com um propĂłsito de verdade', NULL, 'SĂO PAULO', 1, NULL, 97, NULL, NULL, '2026-03-09 19:47:40.905', 'https://franquias.portaldofranchising.com.br/franquia-boali-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '264000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
