INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza780700r6eh0sg38i8dno', 'BONAPARTE', 'bonaparte', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O requinte e a criatividade de suas receitas inovaram o conceito de refeiĂ§Ă”es rĂĄpidas. Utilizando ingredientes nobres com rigor e padronizaĂ§ĂŁo no preparo dos pratos de alto padrĂŁo.', 1998, 1995, NULL, '2026-04-01 02:00:10.844', '2025-08-05 22:20:29.767', 1015, NULL, 1, 1998, 'O Restaurante Bonaparte surgiu em marĂ§o de 1998, com a certeza de que fast-food nĂŁo precisava ser sinĂŽnimo de pratos mal apresentados, falta de requinte e criatividade. \nO propĂłsito do restaurante Ă© atender Ă s necessidades do consumidor de fast-food, preenchendo uma lacuna existente. \nSeu maior trunfo estĂĄ na racionalizaĂ§ĂŁo do cardĂĄpio e na otimizaĂ§ĂŁo do espaĂ§o fĂ­sico. \nAs cozinhas dos restaurantes Bonaparte foram planejadas para dar ao cliente total visibilidade do que se passa no seu interior. \nSeu projeto arquitetĂŽnico Ă© limpo e moderno, priorizando materiais como aĂ§o inoxidĂĄvel, vidro e cerĂąmica, para facilitar a limpeza. \nA qualidade do atendimento tambĂ©m Ă© prioridade no Bonaparte. Seus funcionĂĄrios sĂŁo bem treinados e tĂȘm total compromisso com a satisfaĂ§ĂŁo do cliente. \nTudo para oferecer o melhor serviĂ§o e as melhores refeiĂ§Ă”es. \nJunte sabor e praticidade, acrescente qualidade em tudo e ponha uma grande porĂ§ĂŁo de clientes satisfeitos. \nEssa Ă© a receita de sucesso do Bonaparte. \nSeu cardĂĄpio variado, que vai de carnes, risotos, saladas e frutos do mar, Ă© a melhor pedida para quem quer fazer um bom negĂłcio.', NULL, 'PERNAMBUCO', 1, NULL, 13, NULL, NULL, '2026-03-09 19:49:24.794', 'https://franquias.portaldofranchising.com.br/franquia-bonaparte-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
