INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781500rdeh0sfa93o2kk', 'BRASTEMP', 'brastemp', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'LocaĂ§ĂŁo de Purificadores e PrestaĂ§ĂŁo de ServiĂ§o', 2014, 2017, NULL, '2026-04-01 02:00:10.913', '2025-08-05 22:20:29.802', 1022, NULL, 1, 1954, 'A Brastemp Ă© uma das marcas mais fortes, conhecidas e respeitadas do Brasil, e lĂ­der absoluta em preferĂȘncia na categoria de eletrodomĂ©sticos.1 Ao perceber uma crescente procura por Purificadores de Ăgua no Brasil, a Brastemp realizou uma anĂĄlise criteriosa deste mercado no paĂ­s, identificando uma grande oportunidade de negĂłcio: levar ĂĄgua pura de verdade aos seus consumidores por meio de assinatura mensal.Â  A ideia foi um grande sucesso. O que levou a Brastemp aderir ao sistema de franquia para melhor administrar e atender a demanda de expansĂŁo deste serviĂ§o e modelo de negĂłcio pioneiro para todo o Brasil. Â 1Fonte: pesquisa da revista Forbes.', NULL, 'SĂO PAULO', 1, NULL, 18, NULL, NULL, '2026-03-09 19:55:27.815', 'https://franquias.portaldofranchising.com.br/franquia-brastemp-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '180000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781b00reeh0spp6dpsox', 'APOLAR IMĂVEIS', 'apolar-imoveis', NULL, 'Casa e ConstruĂ§ĂŁo', 'ServiĂ§os e ImobiliĂĄrias', 'Franquia ImobiliĂĄria', 1995, 2011, '[\"https://www.youtube.com/watch?v=9Or4cOlvgSw\",\"https://www.youtube.com/watch?v=aPWtMK7N_d0\",\"https://www.youtube.com/watch?v=CfW0-eElJyE\",\"https://www.youtube.com/watch?v=hmdJHWmmcV8\"]', '2026-04-01 02:00:10.923', '2025-08-05 22:20:29.807', 1023, NULL, 1, 1969, 'Com mais de meio sĂ©culo de atuaĂ§ĂŁo no mercado imobiliĂĄrio, 68 franquias e mais 20 pontos de atendimento, somos a Apolar ImĂłveis. \nPioneira no Brasil na ĂĄrea de franquias, sendo uma das lĂ­deres do setor imobiliĂĄrio no sul do paĂ­s. \nNascemos de um sonho, aparentemente distante de ser alcanĂ§ado, mas possĂ­vel de ser realizado. \nCom persistĂȘncia e dignidade, chegamos aonde querĂ­amos, somos sinĂŽnimo de felicidade. \nNosso modelo rentĂĄvel de negĂłcio, proporciona aos nossos parceiros o sucesso que eles almejam. \nSomos uma rede de imobiliĂĄrias organizadas em forma de franquias, tendo por objetivo o sucesso de todo o ecossistema, buscando permanentemente a complementaridade, o aumento da produtividade e velocidade dos negĂłcios atravĂ©s da uniĂŁo com parceiros e entre parceiros. \nSomos a rede com maior nĂșmero de vendas compartilhadas, afinal, nossa missĂŁo Ă© proporcionar a melhor experiĂȘncia para nossos clientes e o trabalho em rede possibilita que nosso pĂșblico tenha acesso a mais de 5 mil imĂłveis com gestĂŁo exclusiva e que ele possa negociar em qualquer localidade onde hĂĄ uma loja Apolar, independente de cidade ou estado. \nInvestimos em tecnologia, usabilidade e inovaĂ§ĂŁo, pois o futuro Ă© agora e o sucesso nĂŁo espera. Nossos parceiros contam com o apoio de um departamento especializado e um software diferenciado, criado e desenvolvido pela Apolar, onde o usuĂĄrio tem acesso a todas as ferramentas imobiliĂĄrias em um sĂł lugar. \nNossa variedade de serviĂ§os, torna a Apolar uma referĂȘncia no segmento. \nAtuamos no setor de Venda, LocaĂ§ĂŁo, ConsĂłrcio, Short Stay, Real Estate Triple A, Built For Business, LanĂ§amentos, FeirĂŁo Apolar e Apolar Procura. \nTudo idealizado para auxiliar no ĂȘxito nas negociaĂ§Ă”es de nossos parceiros. \nO trabalho da diretoria da Apolar Ă© fortalecer o mercado imobiliĂĄrio, onde atuamos em todos os ĂłrgĂŁos do setor, buscando e apoiando os avanĂ§os do segmento. \nSomos uma marca de sucesso, somos a Apolar ImĂłveis.', NULL, 'PARANĂ', 1, NULL, 78, NULL, NULL, '2026-03-09 19:56:02.714', 'https://franquias.portaldofranchising.com.br/franquia-apolar-imoveis-imobiliarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '99000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781g00rfeh0sz4706juu', 'CAPITANO', 'capitano', NULL, 'AlimentaĂ§ĂŁo', 'Mercados e DistribuiĂ§ĂŁo', 'Franquias de Peixarias e Distribuidoras de Pescados - Lojas para atender Varejo e Atacado da sua cidade com os melhores peixes e frutos do mar do Brasil! Produtos jĂĄ limpos e embalados', 2021, 2022, '[\"https://www.youtube.com/watch?v=vMyc_s3V57o\",\"https://www.youtube.com/watch?v=U4s3l1txCP4\",\"https://www.youtube.com/watch?v=kFchjXOWYbo\"]', '2026-04-01 02:00:10.932', '2025-08-05 22:20:29.812', 1024, NULL, 1, 2003, 'A CAPITANO Ă© uma distribuidora de pescados que atua hĂĄ mais de 40 anos nos mercados brasileiro e internacional, fornecendo cortes de peixes e frutos do mar em geral de alta qualidade, atendendo desde consumidores residenciais e varejistas, atĂ© grandes redes de mercados e outros atacadistas. Nossa sede Ă© localizada em Cabo Frio (RJ), onde recebemos boa parte dos pescados que comercializamos e cuidadmos de todas as etapas de produĂ§ĂŁo. Desde a descarga dos pescados frescos dos barcos, passando pelas etapas de seleĂ§ĂŁo de qualidade e processamento da proteĂ­na, atĂ© a distribuiĂ§ĂŁo e venda direta nos PDVs da marca. Os modelos de loja da Capitano contĂ©m produtos 100% limpos e embalados, que entregam uma qualidade idĂȘntica ao peixe fresco, recĂ©m saĂ­do do mar. Com tĂ©cnicas prĂłprias e uma metodologia desenvolvida hĂĄ dĂ©cadas, somos reconhecidos pela excelĂȘncia dos cortes que preparamos e pela eficiĂȘncia no atendimento a diversos segmentos de food service distintos: bares, restaurantes, hoteis, pousadas, quiosques, mercados e mais. Polvo, Lagosta, Vieiras, SalmĂŁo, CamarĂŁo, TilĂĄpia e tudo o que vocĂȘ precisa do mar, vocĂȘ encontra na Capitano!', NULL, 'RIO DE JANEIRO', 1, NULL, 9, NULL, NULL, '2026-03-09 19:57:10.755', 'https://franquias.portaldofranchising.com.br/franquia-capitano/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '92500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781l00rgeh0sexevad0g', 'NOCTA', 'nocta', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'A Nocta atua no mercado hĂĄ 20 anos com abrangĂȘncia nacional, comercializando planos de saĂșde, odontolĂłgico, seguros e outros ramos, oferecendo as melhores soluĂ§Ă”es a todos perfis de clientes.', 2023, 2024, NULL, '2026-04-01 02:00:10.941', '2025-08-05 22:20:29.817', 1025, NULL, 1, 2005, '', NULL, 'SĂO PAULO', 1, NULL, 12, NULL, NULL, '2025-08-20 22:38:21.000', 'https://franquias.portaldofranchising.com.br/franquia-nocta-servicos-e-outros-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '9990', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza781q00rheh0saeuhnjj7', 'DEPYL ACTION', 'depyl-action', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Cuidados com pele, pelo e embelezamento do olhar', 1996, 2005, '[\"https://www.youtube.com/watch?v=bne3Mci-w_s\",\"https://www.youtube.com/watch?v=qEGc19Kzxys\",\"https://www.youtube.com/watch?v=a2ugsaV2DL8\",\"https://www.youtube.com/watch?v=uGPkeHrcwvg\",\"https://www.youtube.com/watch?v=OJ6dGxGrHCc\"]', '2026-04-01 02:00:10.951', '2025-08-05 22:20:29.823', 1026, NULL, 1, 1983, 'Nossa histĂłria comeĂ§a em 1983, na cidade de BalneĂĄrio CamboriĂș (SC), com a Arcangel, uma fĂĄbrica de cera depilatĂłria nascida do sonho de Dona Glaci Van Straten de mudar a experiĂȘncia de depilaĂ§ĂŁo, considerada por ela, naquela Ă©poca, um verdadeiro sofrimento. TĂ­nhamos um produto tĂŁo bom (cera morna) e fazĂ­amos isso com tanto amor, que mudamos esse paradigma da depilaĂ§ĂŁo, antes percebida como um momento âdolorosoâ, para ser considerada uma experiĂȘncia de bem-estar, conforto e autoestima. A partir disso, em 1996, comeĂ§a a trajetĂłria da rede Depyl Action Franchising, no segmento de saĂșde, beleza e bem-estar.  Hoje, apĂłs mais de 25 anos de caminhada, comemoramos o reconhecimento pĂșblico de seguir atuando no mercado como a Mais Completa Franquia de DepilaĂ§ĂŁo do Brasil. Oferecemos 3 segmentos de serviĂ§os: clĂĄssicos, artĂ­sticos e tecnolĂłgicos, que englobam e 11 especialidades focadas em atender demandas de cuidados com o pelo e a pele de mulheres e homens, da adolescĂȘncia Ă  melhor idade, de maneira Ășnica, diversa e plural. Somos uma empresa pioneira, mas que nĂŁo para de evoluir. Inovamos no relacionamento com franqueados, oferecendo consultoria contĂ­nua sobre o negĂłcio, treinamentos para equipes de colaboradores (cursos e atualizaĂ§ĂŁo), alĂ©m de oferecer todo o suporte necessĂĄrio para quem entra para o nosso time. SĂŁo mais de 3 mil clientes atendidos por dia, em 103 lojas espalhadas pelo Brasil e fora dele (Venezuela), com 77 franqueados apaixonados. Â   A 115Â° unidade da Depyl Action abriu suas portas em julho de 2020, no tradicional bairroÂ Jardim Paulista, capital de SĂŁo Paulo. A franqueada Manuela Penna segue Ă  frente doÂ negĂłcio, ao lado da sĂłcia Jaqueline Paiva, fortalecendo ainda mais a rede no estado, que jĂĄÂ conta com outras unidades localizadas em Campinas, TatuapĂ©, Itaim Bibi, RibeirĂŁo Preto,Â Araraquara, Santos, SĂŁo Caetano do Sul, SĂŁo JosĂ© dos Campos, SĂŁo Paulo e Sorocaba).Â  SaĂșde, beleza e bem-estar: serviĂ§os e produtos em um segmento promissor  A Depyl Action Ă© mais que depilaĂ§ĂŁo, oferecemos soluĂ§Ă”es personalizadas para o cuidado com o pelo e a pele. AlĂ©m de um atendimento de excelĂȘncia, focado na experiĂȘncia do cliente, trabalhamos com um vasto portfĂłlio de serviĂ§os clĂĄssicos (epilaĂ§ĂŁo com cera morna - fĂłrmula exclusiva e pioneira no paĂ­s, epilaĂ§ĂŁo com linha, aparo de pelos e esfoliaĂ§ĂŁo corporal), tecnolĂłgicos (laser, luz pulsada, clareamento e rejuvenescimento) e artĂ­sticos (embelezamentoÂ  das sobrancelhas, embelezamento dos cĂ­lios e coloraĂ§ĂŁo dos pelos). Os serviĂ§os sĂŁo realizados em cabines exclusivas e climatizadas, com toda a seguranĂ§a, discriĂ§ĂŁo, assepsia e higiene necessĂĄrias para que as pessoas tenham a chance de conhecer o que Ă© bem-estar de verdade!  ExcelĂȘncia em Franchising SĂŁo 21 prĂȘmios da ABF, colecionados com muito orgulho desde o ano de 2004. Em 2015, tambĂ©m recebemos umÂ reconhecimento muito importante: 10 anos consecutivos com o Selo de ExcelĂȘncia em Franchising, uma verdadeira honra, resultado de um trabalho realizado com muito empenho e transparĂȘncia.  Onde estamos? Estamos em 24 estados brasileiros e no Distrito Federal.Â  Nossa sede fica em Belo Horizonte (Minas Gerais): Rua Sergipe, 1430, 17Âș andar. Telefone: (31) 3222-7701', NULL, 'MINAS GERAIS', 1, NULL, 90, NULL, NULL, '2026-03-09 19:58:24.431', 'https://franquias.portaldofranchising.com.br/franquia-depyl-action-beleza/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
