'2026-03-09 20:07:34.817', 'https://franquias.portaldofranchising.com.br/franquia-auxiliadora-predial-imobiliarias/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '130000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
