INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza782x00rpeh0sci3uichc', 'RED BALLOON', 'red-balloon', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escola BilĂ­ngue para crianĂ§as de 2 a 5 anos e escola de inglĂȘs para crianĂ§a de 3 a 17 anos', 1999, 2000, NULL, '2026-04-01 02:00:11.029', '2025-08-05 22:20:29.865', 1034, NULL, 1, 1969, 'A Red Balloon oferece no mesmo espaĂ§o fĂ­sico, dois modelos de negĂłcio distintos e complementares: o curso livre de inglĂȘs e a escola bilingue Escola BilĂ­ngue (turno): A Bilingual School Ă© destinada ao ensino infantil para crianĂ§as de 2 a 5 anos e oferece currĂ­culo bilingue de verdade com 50% em inglĂȘs e 50% em portuguĂȘs. Aliada a metodologia que consolidou a Red Balloon como referĂȘncia no ensino de inglĂȘs para este pĂșblico, a escola infantil bilĂ­ngue permite imersĂŁo ainda maior no idioma e passa a ser a primeira escola do paĂ­s a utilizar o currĂ­culo internacional de Oxford. English Program (contraturno): O English Program da Red Balloon corresponde a modalidade de curso livre, mas Ă© muito mais do que um curso tradicional. Isso porque, alĂ©m de utilizar uma metodologia lĂșdica Ășnica. O English Program permite mais flexibilidade as famĂ­lias com cargas horarias que vĂŁo de 3 atĂ© 20 horas semanais, elas podem escolher a opĂ§ĂŁo que mais se enquadra nas suas necessidades. NĂșmeros que provam que nosso modelo de negĂłcio: NPS das famĂ­lias de +80, hĂĄ mais de 6 anos seguidos LTV (life time value) de 5,5 anos, muito superior a outros cursos de inglĂȘs Taxa de retenĂ§ĂŁo de 85%, sendo taxa de retenĂ§ĂŁo similar a escola regular + de 90% de aprovaĂ§ĂŁo nos exames de Cambridge, maior que a mĂ©dia nacional de aprovaĂ§ĂŁo. Lucro lĂ­quido em torno dos 35% do faturamento Modelo de negĂłcio estĂĄvel, seguro e duradouro', NULL, 'SĂO PAULO', 1, NULL, 73, NULL, NULL, '2026-03-09 20:08:33.434', 'https://franquias.portaldofranchising.com.br/franquia-red-balloon-educacao/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '700000.01', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783300rqeh0sqsig0617', 'SANTA LOLLA', 'santa-lolla', NULL, 'Moda', 'CALĂADOS', 'CalĂ§ados e AcessĂłrios Femininos', 2004, 2007, '[\"https://www.youtube.com/watch?v=KcOiPgfvOdM\"]', '2026-04-01 02:00:11.039', '2025-08-05 22:20:29.872', 1035, NULL, 1, 2002, 'SĂłcios da Franquia Santa Lolla, os irmĂŁos Rubens, Vanessa e FĂĄbio Martinez comeĂ§aram a trilhar sua trajetĂłria no varejo na dĂ©cada de 90, quando abriram sua primeira loja multimarcas de sapatos, motivados pelo interesse comum pelo universo dos calĂ§ados. A vontade de criar suas prĂłprias coleĂ§Ă”es, impulsionou o surgimento da marca Santa Lolla, em 2002. Dois anos depois, apĂłs com ainda mais know how, inauguraram a primeira franquia Santa Lolla. Crescendo de forma sustentĂĄvel com 140 lojas atĂ© agosto desse ano, e uma expansĂŁo programada de mais 15 lojas para 2017. Com 15 anos no mercado, a Santa Lolla firmou-se como uma das principais referĂȘncias de moda no Brasil, antecipando e criando tendĂȘncias com um time afiado que cria cinco coleĂ§Ă”es por ano, cerca de sete mil novos itens que abastecem constantemente as lojas, para atender o pĂșblico cada vez mais informado e ĂĄvido por novidades. A empresa nasceu e segue com a missĂŁo de aliar conforto e moda para uma mulher sexy, segura, independente e poderosa. Marketing e Visual Merchandising A Santa Lolla conta com uma equipe especializada na criaĂ§ĂŁo e desenvolvimento das estratĂ©gias de comunicaĂ§ĂŁo e marketing para a marca. âą Marketing forte e inovador âą Plano de comunicaĂ§ĂŁo nacional e multicanal âą Suporte ao franqueado para aĂ§Ă”es personalizadas âą Materiais de apoio para franqueados e equipe âą Visual Merchandising com vitrines especiais âą Visual Merchandising com exposiĂ§ĂŁo de produto dinĂąmico Seja um franqueado: (11) 3046-3301 | franquia@santalolla.com.br', NULL, 'SĂO PAULO', 1, NULL, 315, NULL, NULL, '2026-01-20 11:44:20.000', 'https://franquias.portaldofranchising.com.br/franquia-santa-lolla-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '540000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783900rreh0sbpejyvvf', 'SPA EXPRESS', 'spa-express', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os EstĂ©ticos e Bem-Estar', 'Microfranquia modelo homeoffice que presta serviĂ§os de estĂ©tica e bem-estar em domicĂ­lio.', 2014, 2019, '[\"https://www.youtube.com/watch?v=Ap0rB7FCV2k\",\"https://www.youtube.com/watch?v=vE1K4geRrt8\"]', '2026-04-01 02:00:11.049', '2025-08-05 22:20:29.877', 1036, NULL, 1, 2011, 'Desde 2011 atuando no mercado de JoĂŁo Pessoa - PB, o SPA Express nasceu com o propĂłsito de levar bem-estar aos seus clientes.Â  Numa sala de consultĂłrio mĂ©dico, a ideia surgiu enquanto Luciana esperava sua hora de atendimento. Ela pensou em como seria interessante ter ali mesmo um serviĂ§o de manicure express. \nE, logo, a ideia saiu do papel! Firmando parcerias com clĂ­nicas mĂ©dicas, os serviĂ§os de manicure chegaram nestes centros para otimizar o tempo das mulheres. A inovaĂ§ĂŁo do serviĂ§o alinhada ao bom atendimento resultou no reconhecimento e sucesso da marca SPA Express e, logo, a empresa estendeu os serviĂ§os para o atendimento domiciliar. Assim, o SPA Express passou a levar nĂŁo sĂł os serviĂ§os de manicure como tambĂ©m procedimentos estĂ©ticos corporais, faciais, serviĂ§os exclusivos de Dia de Noiva, SPA Day, entre outros, para a casa/hotel/trabalho dos clientes. Com o passar do tempo, os tratamentos estĂ©ticos corporais e faciais assumiram uma fatia majoritĂĄria no faturamento do negĂłcio e o foco do SPA Express acompanhou esta tendĂȘncia. Hoje em dia, a Franquia se especializou neste segmento especĂ­fico e eliminou o atendimento de manicure do seu mix de serviĂ§os. Em razĂŁo de toda a experiĂȘncia acumulada nos serviĂ§os prestados em domicĂ­lio durante esse tempo e objetivando a expansĂŁo da sua marca, em 2014 o SPA Express aderiu ao Sistema de Franchising e jĂĄ conta com mais de 44 franquias espalhadas pelo Brasil oferecendo uma proposta home office inovadora com pequeno investimento inicial e baixo custo fixo mensal. Hoje somos a MAIOR franquia de SPA em domicĂ­lio do Brasil! \nVem fazer parte dessa histĂłria de sucesso que ainda estĂĄ sĂł comeĂ§ando!', NULL, 'PARAĂBA', 1, NULL, 20, NULL, NULL, '2026-03-09 20:09:34.805', 'https://franquias.portaldofranchising.com.br/franquia-spa-express/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', '29640', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783f00rseh0saim4s773', 'VIDA CARD', 'vida-card', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'CARTĂO DE SAĂDE ASSOCIADO A CLĂNICA MĂDICA E ODONTOLĂGICA', 2019, 2021, '[\"https://www.youtube.com/watch?v=lnuyU1mGZuM\",\"https://www.youtube.com/watch?v=7pRIgAGEFhQ\"]', '2026-04-01 02:00:11.061', '2025-08-05 22:20:29.883', 1037, NULL, 1, 2008, 'OLĂ INVESTIDOR(A)! \nSEJA MUITO BEM VINDO AO SEU NOVO NEGĂCIO, O VIDA CARD! \nA REDE DE FRANQUIAS DA ĂREA DA SAĂDE QUE MAIS CRESCE NO BRASIL. \nSurgia hĂĄ mais de 11 anos o embriĂŁo do negĂłcio que se tornaria o Vida Card. \nUm grupo de religiosos, unidos a profissionais de saĂșde e membros da comunidade, iniciaram um pequeno projeto social oferecendo as pessoas serviĂ§os de saĂșde com preĂ§os acessĂ­veis. \nO marco inicial ocorreu com um grupo de mĂ©dicos e uma mĂĄquina de ultrassom, oferecendo atendimento Ă  populaĂ§ĂŁo de baixa renda. Logo o projeto foi ganhando proporĂ§ĂŁo, unindo cada vez mais profissionais de saĂșde e clientes.Â  \nEm outubro de 2015, com uma estrutura fĂ­sica que jĂĄ nĂŁo comportava o seu tamanho, o projeto ganhou uma casa nova, um Centro de SaĂșde de 700 mÂČ, com uma estrutura moderna e equipada para melhor atender a populaĂ§ĂŁo.Â  \nA reestruturaĂ§ĂŁo do pequeno projeto social o qual era conhecido inicialmente, foi coordenado pelos sĂłcios fundadores da franqueadora Vida Card, Anna Kuerten, Eduardo Saibt, Luciano de Medeiros e Luiz Felipe Durand. \nNeste processo, o projeto nĂŁo sĂł ganhou uma nova estrutura fĂ­sica, como tambĂ©m uma gestĂŁo profissional e o seu nome: Vida Card. \nApĂłs dois anos de validaĂ§ĂŁo do novo formato de negĂłcio na unidade Vida Card de Santa Maria/RS, nasceu a Franqueadora Vida Card, com a sua primeira unidade franqueada na cidade de Alegrete/RS, que no mĂȘs de junho/22 completou 3 anos de atividades atingindo o nĂșmero expressivo de associados.Â  \nNestes trĂȘs anos sĂŁo 30 unidades Vida Card em funcionamento no Rio Grande do Sul, Santa Catarina, ParanĂĄ, com mais 22 unidades em implantaĂ§ĂŁo. \nJunte-se a nĂłs e venha fazer parte desta histĂłria de sucesso e crescimento.  - Estrutura\nCom unidades que podem variar entre 120mÂČ a 400mÂČ, com destaque para ĂĄrea comercial e o centro de saĂșde totalmente padronizadas, a rede busca proporcionar um atendimento de excelĂȘncia em todas as suas Unidades. \nA equipe de implantaĂ§ĂŁo da franqueadora acompanha o novo franqueado em todos as etapas de construĂ§ĂŁo da sua unidade, desde o seu projeto de arquitetura, elaboraĂ§ĂŁo de estratĂ©gias operacionais e comerciais atĂ© o evento de inauguraĂ§ĂŁo.Â  \nDepois o suporte da Franqueadora Vida Card continua com a consultoria de gestĂŁo, time de marketing, comercial e rede de atendimento.  - Tecnologia\nO franqueado faz a gestĂŁo da sua Unidade atravĂ©s de um software de gestĂŁo integral (comercial, financeiro e Centro de saĂșde), que tambĂ©m disponibiliza um acompanhamento da performance da unidade atravĂ©s de um painel de indicadores.\nÂ  - ServiĂ§osÂ \nOs Clientes das franquias Vida Card encontram todas as especialidades em um sĂł lugar, uma ampla rede interna e externa contendo diversas especialidades mĂ©dicas, odontolĂłgicas e de serviĂ§os, alĂ©m de encontrar saĂșde de qualidade por um preĂ§o acessĂ­vel, usufruem de uma estrutura moderna e muito bem equipada para recebe-los, com centro de SaĂșde prĂłprio, agilidade no agendamento de consultas e exames, e valores de planos assistenciais familiares que cabem no bolso.Â  ConheĂ§a a franquia VIDA CARD e seja Franqueado de um NegĂłcio SĂłlido, RentĂĄvel e Recorrente!', NULL, 'RIO GRANDE DO SUL', 1, NULL, 33, NULL, NULL, '2026-03-09 20:10:47.662', 'https://franquias.portaldofranchising.com.br/franquia-vida-card/', NULL, NULL, NULL, 1, NULL, 0, 0, 'MAINTAIN', 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
