INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783p00rueh0sppsszuu5', 'L\'OCCITANE', 'l-occitane', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'Perfumaria e CosmĂ©ticos com alma francesa e coraĂ§ĂŁo brasileiro, marca celebra as diversas belezas do Brasil em todos os seus produtos.', 1976, 2022, '[\"https://www.youtube.com/watch?v=RlwemzLwY9w\"]', '2026-04-01 02:00:11.084', '2025-08-05 22:20:29.894', 1039, NULL, 1, 1976, 'L\'Occitane au BrĂ©sil: a FranĂ§a na essĂȘncia, Brasil por natureza. A histĂłria do Grupo LâOccitane teve inĂ­cio em 1967 com a criaĂ§ĂŁo da LâOccitane en Provence, fundada por Olivier Baussen. A marca se expandiu por meio da produĂ§ĂŁo de sabonetes em barra e cremes corporais, tudo inspirado na natureza, segredo de todos os nossos produtos. HĂĄ mais de 40 anos vivemos este sonho, compartilhado com o mundo todo. O Grupo atualmente Ă© composto por oito marcas. AlĂ©m da LâOccitane en Provence, a outra Ășnica marca fundada pelo grupo foi a LâOccitane au BrĂ©sil. A LâOccitane au BrĂ©sil, com alma francesa e coraĂ§ĂŁo brasileiro, celebra as diversas belezas do Brasil em todos os seus produtos. A marca nasceu em 2013 com o propĂłsito de celebrar as diversas belezas do Brasil por meio de uma perspectiva Ășnica: o olhar do francĂȘs com o sorriso do olhar brasileiro, enaltecendo a alegria, tradiĂ§Ă”es, cores, ingredientes, cheiros, texturas e pessoas que fazem do Brasil uma naĂ§ĂŁo querida em todos os cantos do mundo â uma celebraĂ§ĂŁo do Brasil aos olhos da FranĂ§a. Com valores de autenticidade, sensorialidade e respeito, a marca conta com comunidades produtoras parceiras espalhadas ao redor do paĂ­s em cadeias sustentĂĄveis, trazendo ingredientes de origem nacional para todos os mais de 200 produtos do portfĂłlio, e artistas que celebram a franco-brasilidade com ilustraĂ§Ă”es exclusivas.Â  Nossos compromissos Ă© surpreender os nossos clientes com uma experiĂȘncia autĂȘntica, levar alegria & diversĂŁo e envolver os clientes com nossas texturas, sensorialidade e histĂłrias verdadeiras UM NOME FORTE A L\'Occitane au BrĂ©sil tem um nome altamente reconhecĂ­vel para clientes brasileiros e estrangeiros, aliada Ă  heranĂ§a do Grupo L\'OCCITANE UM GRUPO CONDUZIDO PELO CRESCIMENTO O Grupo L\'OCCITANE teve um crescimento de 15% no Brasil em seu Ășltimo ano fiscal (2021), reforĂ§ando a influĂȘncia de suas marcas entre os clientes brasileiros. Filosofia de NegĂłcio Parceria; TransparĂȘncia; ComunicaĂ§ĂŁo frequente e permanente; Comprometimento com o negĂłcio Suporte da Franqueadora Oferecemos suporte contĂ­nuo ao franqueado, auxiliando em diferentes etapas do processo: PrĂ© InauguraĂ§ĂŁo Direito de uso da marca e adesĂŁo ao sistema de franquias; Todo know-how; Assessoria e apoio na escolha do ponto; Projeto arquitetĂŽnico; Treinamento inicial do franqueado e da primeira equipe; Manual de operaĂ§ĂŁo e gestĂŁo da loja; Apoio na montagem e inauguraĂ§ĂŁo da loja. PĂłs InauguraĂ§ĂŁo Acompanhamento e suporte operacional por meio de consultoria de campo; Treinamento de reciclagem e para lanĂ§amento de novos produtos; Portal de pedidosÂ  Portal do franqueadoÂ  SAF (sistema de atendimento ao franqueado) ConvenĂ§ĂŁo de franqueados;', NULL, 'SĂO PAULO', 1, NULL, 291, NULL, NULL, '2026-03-09 20:12:59.315', 'https://franquias.portaldofranchising.com.br/franquia-loccitane/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '150000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza783w00rveh0sszmw973e', 'DENTAL ARTE', 'dental-arte', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ServiĂ§os MĂ©dicos e ClĂ­nicas', 'ClĂ­nicas OdontolĂłgicas', 2016, 2015, '[\"https://www.youtube.com/watch?v=UlOwG5kOP6U\"]', '2026-04-01 02:00:11.096', '2025-08-05 22:20:29.900', 1040, NULL, 1, 2002, 'A Dental Arte Ă© uma das marcas de clĂ­nicas odontolĂłgicas mais conhecidas do Rio Grande do Sul. A rede nasceu em Alvorada, no ano de 2002, com o propĂłsito de tornar acessĂ­vel a todos uma odontologia de excelente qualidade, com atendimento acolhedor e humanizado. O trabalho ĂĄrduo e dedicado das Dras. Alessandra Batista e Adriane Afonso logo gerou reconhecimento e o âjeito Dental Arte de atenderâ conquistou a regiĂŁo metropolitana de Porto Alegre. Em menos de dois anos, a marca cresceu e chegou ao centro histĂłrico da capital com a jĂĄ consagrada unidade da Andradas. Nos anos seguintes foram abertas mais duas clĂ­nicas prĂłprias, em Cachoeirinha e Novo Hamburgo. ApĂłs 13 anos de muito sucesso e reconhecimento no coraĂ§ĂŁo dos gaĂșchos, as diretoras da Rede perceberam que estava no momento de compartilhar seu know-how e expertise no segmento odontolĂłgico. As primeiras franquias foram vendidas muito rapidamente para dentistas que jĂĄ atendiam na Dental Arte e constataram o potencial da marca e sua credibilidade por um serviĂ§o odontolĂłgico de qualidade e referĂȘncia. Em 8 anos como rede de franquias odontolĂłgicas, a Dental Arte obteve um crescimento acentuado em nĂșmero de clĂ­nicas abertas, inclusive mantendo constĂąncia de crescimento durante a pandemia da Covid-19. Com 21 anos de mercado e mais de 2 milhĂ”es de sorrisos transformados, a Rede Dental Arte conta com mais de 40 unidades espalhadas em 4 estados brasileiros, sendo eles: Rio Grande do Sul, Santa Catarina, Bahia e SĂŁo Paulo.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 36, NULL, NULL, '2026-03-09 20:14:41.618', 'https://franquias.portaldofranchising.com.br/franquia-dental-arte-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
