INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785d00s5eh0s707w4n77', 'YES! COSMETICS', 'yes-cosmetics', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'CosmĂ©ticos e perfumaria.', 2015, 2016, '[\"https://www.youtube.com/watch?v=tF2dBIKhWKA\",\"https://www.youtube.com/watch?v=cagc8onT_GQ\",\"https://www.youtube.com/watch?v=fIRvrEKxh4s\"]', '2026-04-01 02:00:11.216', '2025-08-05 22:20:29.953', 1050, NULL, 1, 2000, 'Da maquiagem ao skincare, da perfumaria ao autocuidado. Somos uma marca brasileira, de cosmĂ©ticos 100% veganos e cruelty-free, que leva beleza e bem-estar de um jeito acessĂ­vel e democrĂĄtico a todas as regiĂ”es do Brasil. Somos uma rede de franquias que acredita no poder da diversidade e no empreendedorismo que prospera. Nossa histĂłria comeĂ§ou em 2000, na Venda Direta. Em pouco tempo, investimos em operaĂ§Ă”es prĂłprias e, em 2016, apĂłs um perĂ­odo de aprendizado e amadurecimento, demos um passo decisivo rumo ao franchising. Com mais de 20 anos de trajetĂłria no cenĂĄrio nacional, seguimos conquistando novos pĂșblicos com produtos de qualidade, o melhor custo-benefĂ­cio, e um modelo de negĂłcio rentĂĄvel, estruturado e sustentĂĄvel. Com dois formatos de investimento, quiosque e loja, aqui vocĂȘ encontra oportunidades a partir de R$109 mil para empreender em um dos mercados que mais crescem no mundo!  Nosso modelo de franquia foi pensado para oferecer seguranĂ§a e suporte a quem deseja ingressar no setor de Higiene Pessoal, Perfumaria e CosmĂ©ticos (HPPC): um segmento em constante crescimento, que se mantĂ©m aquecido o ano todo, com produtos nĂŁo perecĂ­veis e que fazem parte do dia a dia de todo mundo. Ao lado da Yes! Cosmetics vocĂȘ ainda garante outras vantagens! Â  Junto com vocĂȘ em cada etapa Nossa equipe acompanha cada fase do seu negĂłcio, desde a implantaĂ§ĂŁo atĂ© o dia a dia da operaĂ§ĂŁo. Nos primeiros meses, vocĂȘ conta com o Suporte BerĂ§ĂĄrio e, depois, seguimos com consultoria de campo regional, consultoria de estoque e abastecimento, agĂȘncia interna de marketing, alĂ©m de um software dedicado Ă  gestĂŁo de materiais de divulgaĂ§ĂŁo, que traz mais agilidade e autonomia a cada franqueado. Â  Treinamento e CapacitaĂ§ĂŁo Oferecemos uma trilha de aprendizado que comeĂ§a jĂĄ nas primeiras reuniĂ”es atĂ© a imersĂŁo no Treinamento para Novos Franqueados (TFY). Acesso a manuais e materiais de apoio, lives estratĂ©gicas, orientaĂ§ĂŁo sobre produtos, tĂ©cnicas de venda e gestĂŁo operacional, alĂ©m da plataforma exclusiva Yes! Academy, para capacitar vocĂȘ e sua equipe ao longo de toda a jornada. Â  Nosso jeito de empreender Buscamos empreendedores que digam sim ao propĂłsito da marca e percebam na Yes! Cosmetics uma oportunidade real de crescimento. Entre os principais atributos que valorizamos estĂŁo: Mentalidade empreendedora e de parceria Disponibilidade e energia pra fazer acontecer Respeito, disciplina e senso de responsabilidade Habilidade em se relacionar e liderar equipes Engajamento e foco na gestĂŁo do negĂłcio OrganizaĂ§ĂŁo e capacidade de adaptaĂ§ĂŁo Diga sim a novas possibilidades com a Yes! Cosmetics Confira a seguir as etapas do nosso processo de seleĂ§ĂŁo:', NULL, 'PERNAMBUCO', 1, NULL, 1, NULL, NULL, '2026-03-09 20:28:18.676', 'https://franquias.portaldofranchising.com.br/franquia-yes-cosmetics-cosmeticos-e-perfumaria/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '155000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
