INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza785s00s8eh0svhwt1iy0', 'CENTER PANOS', 'center-panos', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Supermercado do Artesanato - Oferecendo mix de produtos para criaĂ§ĂŁo de peĂ§as de todas as tĂ©cnicas artesanais, alĂ©m de cursos para capacitaĂ§ĂŁo e arte terapia. AlĂ©m de artigos de decoraĂ§ĂŁo.', 2012, 2014, '[\"https://www.youtube.com/watch?v=J0b-V6qhylE\"]', '2026-04-01 02:00:11.247', '2025-08-05 22:20:29.969', 1053, NULL, 1, 2005, 'Fundada em 2003 pelo empresĂĄrio Ronaldo Aparecido CordĂŁo, a Center Panos nasceu alinhada Ă  sustentabilidade tendo por objetivo a inserĂ§ĂŁo econĂŽmica, social e a terapia ocupacional por meio da comercializaĂ§ĂŁo de seus produtos, se tornando em curto prazo a franquia pioneira em distribuiĂ§ĂŁo de produtos para artesanato no Brasil. ApĂłs estudos, anĂĄlises e pesquisas de mercado, a Center Panos criou um sistema que apresenta soluĂ§Ă”es para o desenvolvimento de artesanato e decoraĂ§ĂŁo baseados nas mais recentes tendĂȘncias mundiais voltadas ao segmento de artesanato, contando com uma gama aproximadamente de 15.000 itens, divididos em: a) Tecidos e armarinho;\nb) Cama, mesa e banho;\nc) Pintura e apliques;\nd) MDF;\ne) Produtos para decoraĂ§ĂŁo em geral. Em 2013, com a uniĂŁo do empresĂĄrio fundador Ronaldo Aparecido CordĂŁo e uma indĂșstria tĂȘxtil, a Center Panos iniciou sua expansĂŁo via franchising, contabilizando, atualmente, 22 unidades em funcionamento no Brasil.', NULL, 'SĂO PAULO', 1, NULL, 50, NULL, NULL, '2026-03-09 20:30:09.349', 'https://franquias.portaldofranchising.com.br/franquia-center-panos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
