INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786h00sdeh0scph20ixt', 'RAHRA SEMIJOIAS', 'rahra-semijoias', NULL, 'Moda', 'ACESSĂRIOS PESSOAIS', 'ComĂ©rcio de Semijoias com qualidade e garantia em todas as peĂ§as de atĂ© 10 anos. Uma marca que enaltece a forĂ§a e a beleza das mulheres, elevando autoestima e individualidade de cada uma.', 2018, 2023, '[\"https://www.youtube.com/watch?v=uGJ72COmh6g\",\"https://www.youtube.com/watch?v=WIpeD22SRoE\",\"https://www.youtube.com/watch?v=Jrn8K3IF8qo\",\"https://www.youtube.com/watch?v=yMnORiI0lUs\"]', '2026-04-01 02:00:11.301', '2025-08-05 22:20:29.994', 1058, NULL, 1, 1988, 'Fundada hĂĄ 35 anos por Solange Coelho, a RAHRA Semijoias nasceu com uma missĂŁo clara: inspirar mulheres a se expressarem plenamente, despertando sua autenticidade e confianĂ§a interior. Unimos moda, beleza, arte e lifestyle em peĂ§as exclusivas, projetadas para realĂ§ar e acompanhar cada momento especial na vida de nossas clientes. Com o passar dos anos, a RAHRA consolidou-se como uma das principais referĂȘncias em semijoias no Brasil, ganhando a confianĂ§a e o carinho de suas clientes e revendedoras autĂŽnomas. Contamos com mais de 55 franquias em todo o paĂ­s e um modelo de loja inovador, que se destaca pela arquitetura Ășnica no segmento. Nossas coleĂ§Ă”es sĂŁo desenvolvidas com base em pesquisas globais de moda, adaptadas ao DNA da marca e Ă s necessidades da nossa comunidade de clientes. Na RAHRA, ultrapassamos limites para alcanĂ§ar nossos objetivos. Movidos pela paixĂŁo, continuamos a crescer e inovar, investindo em tecnologia para personalizar a experiĂȘncia, cuidando do desenvolvimento de produtos Ășnicos e oferecendo um modelo de negĂłcios inteligente e saudĂĄvel, com suporte integral aos nossos franqueados. RAZĂES PARA SER UM FRANQUEADO RAHRA - Royalties Free: NĂŁo cobramos royalties sobre faturamento da unidade. Uma oportunidade incrĂ­vel para crescer e prosperar sem se preocupar com taxas extras. - Estoque inicial consignado: Rahra disponibiliza 100% do estoque inicial com carĂȘncia de 12 meses. Ao final desse perĂ­odo vocĂȘ pode devolver tudo o que nĂŁo vender. - Garantia e Qualidade: Oferecemos atĂ© 10 anos de garantia e realizamos atualizaĂ§Ă”es constantes no processo produtivo, evoluindo diariamente a qualidade de nossos produtos. - Tratamento Especial: Nossas peĂ§as sĂŁo livres de nĂ­quel e possuem 3 camadas de ouro com verniz protetor. Utilizamos uma tecnologia exclusiva de tratamento antialĂ©rgico, com 99% de aprovaĂ§ĂŁo. - Sempre na Moda: Realizamos lanĂ§amentos de novas coleĂ§Ă”es todos os meses e apresentamos novos modelos a cada 15 dias, garantindo que vocĂȘ esteja sempre na moda. RAHRA Ă© mais do que uma marca de semijoias; Ă© um movimento que celebra a individualidade e a diversidade feminina. Junte-se a nĂłs nessa jornada.', NULL, 'MINAS GERAIS', 1, NULL, 64, NULL, NULL, '2025-09-18 10:14:27.000', 'https://franquias.portaldofranchising.com.br/franquia-rahra-semijoias-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '143490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza786o00seeh0sx6mbogtb', 'MAMMA MIA EXPRESS', 'mamma-mia-express', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'OperaĂ§ĂŁo Fast Food de Galeto e Massas tĂ­picas do sul do Brasil', 2012, 2013, NULL, '2026-04-01 02:00:11.310', '2025-08-05 22:20:30.001', 1059, NULL, 1, 1985, 'Sabor, o segredo do Mamma Mia No Galeto Mamma Mia, todos acreditam que as fartas refeiĂ§Ă”es em famĂ­lia, com a culinĂĄria tĂ­pica dos imigrantes italianos, podem e devem ser desfrutadas por todos. E que suas receitas tradicionais sĂŁo a melhor razĂŁo para alegres encontros, brindes e sorrisos de satisfaĂ§ĂŁo. Â  O clima de suas casas Ă© sempre acolhedor e conquista as pessoas que apreciam o comer e viver bem. O segredo desde o inĂ­cio estĂĄ no sabor e no atendimento. Servir o cliente o mais rapidamente possĂ­vel para que ele tenha tempo para degustar o sabor Ășnico dos pratos do Mamma Mia.\nÂ  O sonho de um menino, o comeĂ§oÂ  Mamma Mia! Esta expressĂŁo italiana que demonstra admiraĂ§ĂŁo e encantamento trouxe nome e inspiraĂ§ĂŁo para o sonho de um menino que aos 11 anos jĂĄ queria tocar seu prĂłprio negĂłcio. Julinho Cavichioni primeiro cuidou de uma lanchonete. Aos 16 anos foi emancipado pelos pais, para realizar o sonho de abrir o restaurante Mamma Mia. Com o grande movimento do restaurante, quis conhecer de onde vinham seus clientes. Para isto, o jovem corria atĂ© o estacionamento e olhava os carros. As placas de Porto Alegre indicavam que a expansĂŁo de seu restaurante deveria comeĂ§ar por lĂĄ. Assim, em 1986, abriu mais um Mamma Mia, desta vez na capital gaĂșcha. O sonho continua O espĂ­rito empreendedor segue no DNA do Mamma Mia que estĂĄ prestes a abrir a sua sexta operaĂ§ĂŁo. Â  Uma marca altamente conhecida no sul do Brasil, que transpĂ”e barreiras e acessibiliza o verdadeiro sabor da culinĂĄria dos imigrantes italianos presentes na serra gaĂșcha. Franquias do Galeto Mamma Mia: uma histĂłria deÂ 39 anosÂ que estĂĄ sĂł comeĂ§ando.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 29, NULL, NULL, '2026-03-09 20:31:32.969', 'https://franquias.portaldofranchising.com.br/franquia-mamma-mia-express-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
