INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza787600sheh0sfyvyra8o', 'THE KIDS CLUB - INGLĂS SĂ P/ CRIANĂAS', 'the-kids-club-ingles-so-p-criancas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'INGLĂS PARA CRIANĂAS DE 18 MESES A 12 ANOS', 1990, 1995, '[\"https://www.youtube.com/watch?v=B7wW3uEn_po\",\"https://www.youtube.com/watch?v=7vQruW9Wg5U\",\"https://www.youtube.com/watch?v=7HuOodis12c\",\"https://www.youtube.com/watch?v=MATV9J2dN7Y\"]', '2026-04-01 02:00:11.338', '2025-08-05 22:20:30.019', 1062, NULL, 1, 1987, 'SOBRE A FRANQUIA THE KIDS CLUB Investimento inicial acessĂ­vel Microfranquia em formato home-based Cursos anuais com RECEITA MENSAL RECORRENTE Metodologia internacional exclusiva No Brasil desde 1994, o THE KIDS CLUB Ă© uma rede de franquias de origem inglesa, especializada no ensino de inglĂȘs para crianĂ§as de 18 meses a 12 anos de idade, e pioneira no Brasil no formato microfranquia home-based, com atuaĂ§ĂŁo sem ponto comercial e em parceria com Escolas Regulares. Oferecemos dois formatos de atuaĂ§ĂŁo, e o franqueado pode optar por um, ou pelos dois: - FORMATO HOME-BASED â sem necessidade de ponto comercial, podendo o franqueado administrar o negĂłcio de casa. As aulas acontecem dentro de escolas de EducaĂ§ĂŁo Infantil e Ensino Fundamental I, atravĂ©s de parcerias. - FORMATO SEDE PRĂPRIA â modelo tradicional de escola de idiomas em um ponto comercial. Com uma proposta Ășnica e um modelo de negĂłcio inovador, a franquia THE KIDS CLUB forma empreendedores, donos dos seus prĂłprios negĂłcios, com treinamentos, orientaĂ§Ă”es, e sem muita burocracia. Â  INVESTIMENTO INICIAL Taxa de Franquia: R$ 12.500,00 Investimento Inicial total (incluindo a Taxa de Franquia e capital de giro): R$ 23.500,00, no formato home-based. Retorno do Investimento: 18 a 24 meses. Â  Estimativa de faturamento mensal: R$ 12.500,00 (considerando 50 alunos e uma mensalidade de R$ 250,00/aluno) Estimativa de lucratividade: 25% - 30% Possiblidade de receita recorrente â cursos anuais Â  VALORES DO SISTEMA Taxa de Royalties: 9% sobre mensalidades Fundo de Marca: R$ 200,00/mĂȘs Sistema de GestĂŁo: R$ 200,00/mĂȘs Â  NOSSA METODOLOGIA Aulas para crianĂ§as de 18 meses a 12 anos de idade Aulas 100% em inglĂȘs, desde o primeiro dia Manuais do Professor exclusivos, com todas as aulas jĂĄ preparadas Material didĂĄtico de Ășltima geraĂ§ĂŁo, com uso de aplicativo e recursos tecnolĂłgicos Grade completa de cursos, com 11 nĂ­veis anuais Cursos curriculares, extracurriculares, e nosso exclusivo PROGRAMA BILĂNGUE, com aulas todos os dias, escolhidos de acordo com a necessidade de cada cliente CertificaĂ§ĂŁo Internacional para crianĂ§as Nossa metodologia prioriza a comunicaĂ§ĂŁo em inglĂȘs desde a primeira aula. AtravĂ©s de jogos, mĂșsicas e muita brincadeira, interagimos com o universo infantil, contextualizando o novo idioma, e criando uma aula divertida onde os alunos aprendem sem perceber. Com aulas 100% em inglĂȘs, nossos professores fluentes e treinados estimulam a participaĂ§ĂŁo dos alunos, criando um ambiente acolhedor, onde o uso do novo idioma se torna fĂĄcil e prazeroso. Nosso Material DidĂĄtico foi desenvolvido em parceria com as melhores editoras internacionais, e Ă© atualizado anualmente. Todos os professores e alunos tĂȘm acesso a plataformas digitais para realizarem atividades online. E somos hoje um Centro Autorizado para aplicaĂ§ĂŁo das CertificaĂ§Ă”es Internacionais especializadas em crianĂ§as: PEIC YL â Pearson English International Certificate for Young Learners TOEFL Primary TOEFL Junior Â  EXCELĂNCIA EM FRANCHISING Em 2024, a rede THE KIDS CLUB completou 30 anos no Brasil, e foi chancelada com o 20Âș SELO DE EXCELĂNCIA EM FRANCHISING DA ABF, que atesta a satisfaĂ§ĂŁo dos franqueados com a marca e com a franqueadora.', NULL, 'SĂO PAULO', 1, NULL, 39, NULL, NULL, '2026-03-09 20:41:30.004', 'https://franquias.portaldofranchising.com.br/franquia-the-kids-club-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '13500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
