INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789300speh0sdtdctgfy', 'PARK EDUCATION', 'park-education', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'EducaĂ§ĂŁo', 2000, 2008, '[\"https://www.youtube.com/watch?v=Py3kasswNRU\",\"https://www.youtube.com/watch?v=yi7cJuIHdD4\",\"https://www.youtube.com/watch?v=uCH_gsm4y4c\"]', '2026-04-01 02:00:11.421', '2025-08-05 22:20:30.087', 1070, NULL, 1, 1996, 'Park | Escola do Futuro: Invista em Sucesso e PropĂłsito na EducaĂ§ĂŁo A Park Education nasceu da visĂŁo inovadora de Eduardo Pacheco, que, ao retornar dos Estados Unidos, identificou a necessidade de transformar o ensino de idiomas no Brasil. Em 1996, ao ministrar aulas de inglĂȘs, Pacheco constatou que a abordagem tradicional deixava 95% dos alunos inseguros para se comunicarem, percebendo, assim, uma grande oportunidade de revolucionar o aprendizado. Junto com o experiente executivo Paulo Arruda, fundou e desenvolveu o MĂ©todo Park â inspirado no processo natural de aquisiĂ§ĂŁo da lĂ­ngua materna â que coloca o aluno para falar antes de aprender as regras gramaticais. Com mais de 29 anos de histĂłria e uma trajetĂłria marcada por resultados expressivos, a Park Education se consolidou como referĂȘncia no setor educacional, impactando mais de 100.000 alunos e atingindo Ă­ndices de aprovaĂ§ĂŁo de 98% e uma taxa de retenĂ§ĂŁo de 95%. A partir de 2000, optamos pelo sistema de franquias para acelerar nossa expansĂŁo e levar nosso mĂ©todo inovador a diferentes regiĂ”es do Brasil. Hoje, a Park Education apresenta aÂ Escola do FuturoÂ â um modelo que une sucesso financeiro e impacto social, oferecendo: EducaĂ§ĂŁo Inovadora:Â IntegraĂ§ĂŁo de tecnologia, ensino bilĂ­ngue, criatividade e habilidades socioemocionais para preparar os alunos para os desafios do mundo real. Impacto Social Positivo:Â ContribuiĂ§ĂŁo direta para a formaĂ§ĂŁo de lĂ­deres do amanhĂŁ, criando uma sociedade mais preparada e igualitĂĄria. Sucesso Financeiro:Â Modelo de negĂłcio sĂłlido, com investimento a partir de R$299K, retorno rĂĄpido, suporte operacional completo e estratĂ©gias de marketing inovadoras. Mercado em Crescimento:Â Aproveite a crescente demanda por educaĂ§ĂŁo de qualidade adaptada Ă s novas realidades e posicione-se como lĂ­der no setor. Ao se tornar um franqueado da Park Education | Escola do Futuro, vocĂȘ investe em um negĂłcio que vai alĂ©m do lucro, deixando um legado transformador na educaĂ§ĂŁo e contribuindo para o desenvolvimento das prĂłximas geraĂ§Ă”es. Junte-se a nĂłs nessa revoluĂ§ĂŁo educacional e comece sua jornada de sucesso com propĂłsito hoje.', NULL, 'MINAS GERAIS', 1, NULL, 47, NULL, NULL, '2026-03-09 20:47:16.664', 'https://franquias.portaldofranchising.com.br/franquia-park-education/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
