 de negĂłcio te ajuda a conquistar os resultados que vocĂȘ procura.', NULL, 'PARANĂ', 1, NULL, 58, NULL, NULL, '2026-03-09 20:48:31.952', 'https://franquias.portaldofranchising.com.br/franquia-help-multas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '124900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
