INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789m00sseh0scxuv9e62', 'ODONTOCOMPANY', 'odontocompany', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'Franquia de ClĂ­nica OdontolĂłgica', 2008, 2011, '[\"https://www.youtube.com/watch?v=gqA9E_jak6w\"]', '2026-04-01 02:00:11.451', '2025-08-05 22:20:30.106', 1073, NULL, 1, 1990, 'A OdontoCompany Ă© lĂ­der absoluta no segmento de franquias odontolĂłgicas e uma das marcas mais reconhecidas da franchising brasileira, sendo referĂȘncia em escala, rentabilidade e suporte ao franqueado. Para conhecer mais sobre o modelo de negĂłcio e as oportunidades de expansĂŁo, a franqueadora disponibiliza informaĂ§Ă”es completas em seu site oficial.  Com mais de 35 anos de histĂłria, a OdontoCompany nasceu em SĂŁo JosĂ© do Rio Preto (SP), idealizada pelo Dr. Paulo Zahr, e evoluiu para um modelo de franchising sĂłlido, validado e altamente escalĂĄvel, acompanhando a profissionalizaĂ§ĂŁo e o crescimento do setor no Brasil. Com clĂ­nicas em operaĂ§ĂŁo em todo o Brasil, a rede conta com unidades estruturadas, profissionais experientes, infraestrutura moderna e alto padrĂŁo de biosseguranĂ§a. O portfĂłlio de serviĂ§os Ă© completo e abrange desde a odontologia bĂĄsica atĂ© as soluĂ§Ă”es estĂ©ticas mais avanĂ§adas, atendendo diferentes perfis de pĂșblico com qualidade e padronizaĂ§ĂŁo. Atualmente, a rede integra o Grupo SMZTO, fundado pelo empresĂĄrio JosĂ© Carlos Semenzato, jurado do Shark Tank Brasil e uma das principais referĂȘncias do franchising nacional. A OdontoCompany tambĂ©m conta com o respaldo do Fundo L Catterton, o maior private equity do mundo focado em negĂłcios de consumo, reforĂ§ando a governanĂ§a, a solidez financeira e a visĂŁo de longo prazo da marca. Modelo de negĂłcio e resultados O modelo de negĂłcio da OdontoCompany se reflete diretamente em seus resultados. Atualmente, 60% dos franqueados possuem mais de uma unidade, evidenciando a escalabilidade da operaĂ§ĂŁo.  A franqueadora oferece suporte completo ao investidor, desde a implantaĂ§ĂŁo da clĂ­nica atĂ© a gestĂŁo diĂĄria da unidade, incluindo: TransferĂȘncia de know-how validado Apoio na escolha do ponto comercial e montagem da unidade Fornecedores homologados Software de gestĂŁo e controle de indicadores Consultoria contĂ­nua e acompanhamento de performance MĂ©todo prĂłprio de captaĂ§ĂŁo de pacientes, garantindo agenda cheia ao longo do ano AlĂ©m disso, a OdontoCompany Ă© reconhecida como a rede odontolĂłgica que mais investe em mĂ­dia nacional, com campanhas institucionais, marketing digital e aĂ§Ă”es de fortalecimento de marca que impulsionam a geraĂ§ĂŁo de demanda para as unidades franqueadas.  Por que investir na franquia OdontoCompany? Marca premiada: eleita uma das Melhores Franquias do Brasil 2025 pela revista PEGN Baixo risco: modelo testado e validado em todos os estados do Brasil Marketing forte e centralizado NegĂłcio escalĂĄvel, ideal para investidores e profissionais da odontologia Alta rentabilidade, com lucratividade mĂ©dia entre 20% e 25% Retorno estimado em cerca de 18 meses  Como se tornar um franqueado O processo para se tornar franqueado Ă© simples, estruturado e transparente, iniciando com o cadastro para recebimento da apresentaĂ§ĂŁo do negĂłcio, seguido por anĂĄlise de perfil, reuniĂŁo estratĂ©gica, envio da Circular de Oferta de Franquia (COF) e formalizaĂ§ĂŁo contratual. Para conhecer todos os detalhes sobre o modelo de franquia, formatos disponĂ­veis e prĂłximos passos, acesse o site oficial da OdontoCompany.', NULL, 'SĂO PAULO', 1, NULL, 1138, NULL, NULL, '2026-03-09 20:49:34.116', 'https://franquias.portaldofranchising.com.br/franquia-odontocompany-odontologica/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '358000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza789s00steh0seisaug4c', 'LIEN CORRETORA DE SEGUROS', 'lien-corretora-de-seguros', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Corretores e agentes de seguros de autos, imĂłveis residenciais e comerciais, vida e planos de previdĂȘncia complementar e de saĂșde. ConsĂłrcios e Financiamentos.', 2016, 2016, NULL, '2026-04-01 02:00:11.460', '2025-08-05 22:20:30.113', 1074, NULL, 1, 2010, 'Saber que seus bens estĂŁo seguros Ă© viver com mais tranquilidade, podendo dedicar seu tempo no que mais importa para vocĂȘ. Pensando nisso a LIEN Corretora de Seguros trabalha oferecendo facilidade e transparĂȘncia. Uma corretora atual que busca a melhoria contĂ­nua em seus processos e serviĂ§os. Nosso objetivo Ă© proporcionar seguranĂ§a e despreocupaĂ§ĂŁo, por isso contamos com uma consultoria especializada que visa orientar e apresentar a proposta de seguro mais adequada Ă s suas necessidades, atravĂ©s de uma anĂĄlise minuciosa para oferecer o melhor custo-benefĂ­cio com a certeza de uma apĂłlice bem elaborada. ConheĂ§a nossos serviĂ§os, faĂ§a um seguro com a LIEN. Trabalhamos com mais de 30 companhias de seguros, temos conhecimento em vĂĄrios ramos do seguro, como automĂłvel, vida, empresas de pequeno, mĂ©dio e grande risco, transporte nacional, transporte internacional, seguros garantia, seguro de responsabilidade civil entre outros.Â  Modelos de Franquias: HOME\nNĂŁo precisa de estrutura fĂ­sica, taxa fixa de R$150,00 no primeiro ano e R$300,00 nos demais, Na modalidade HOME nĂŁo haverĂĄ exclusividade vinculadas Ă  territorialidade sendo suas unidades ilimitadas. Na modalidade HOME, o Treinamento Ă© destinado a 01 (um) usuĂĄrio, podendo ser o prĂłprio FRANQUEADO ou a seu colaborador.  STANDARD\nNecessĂĄrio estrutura fĂ­sica conforme contrato. Cidades acima de 50.000 (cinquenta mil) habitantes poderĂŁo receber mais de uma unidade STANDARD, sempre cabendo Ă  FRANQUEADORA, com base na viabilidade da franquia, a decisĂŁo de permitir ou nĂŁo a implantaĂ§ĂŁo de outra franquia na mesma cidade. Taxa fixa de R$250,00 no primeiro ano e R$500,00 nos demais. Na modalidade STANDARD, o Treinamento Ă© destinado a 02 (dois) usuĂĄrios, podendo ser o prĂłprio FRANQUEADO ou a seus colaboradores.  VANTAGENS\n30 seguradoras parceiras e 95 ramos de seguros, certificada ABF, duas modalidades de negĂłcio, recursos que favorecem o retorno consistente e a lucratividade, suporte na cotaĂ§ĂŁo de seguros e gestĂŁo do negĂłcio.  SUPORTEÂ \nIlimitado, via e-mail, telefone e acesso remoto para ambas as modalidades.  TREINAMENTO Sistema LIEN Â  5:00 (Cinco horas) Sistema das Seguradoras Â 10:00 (Dez horas) \nSistema LIEN e sistema das Seguradoras Ă© feito via telefone, e-mail e acesso remoto. Treinamentos sobre seguro sĂŁo disponibilizados em vĂ­deo das seguradoras e demais treinamentos serĂŁo dados pelas seguradoras que serĂŁo acordados com a LIEN para um grupo mĂ­nimo.', NULL, 'PARANĂ', 1, NULL, 33, NULL, NULL, '2026-03-09 20:51:13.581', 'https://franquias.portaldofranchising.com.br/franquia-lien-negocios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
