INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ad00sweh0s0k9talgx', 'BOBÂŽS', 'bob-s', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'COMĂRCIO DE SANDUĂCHES, SORVETES, REFEIĂĂES RĂPIDAS E OUTROS PRODUTOS ASSEMELHADOS', 1984, 1994, '[\"https://www.youtube.com/watch?v=MZuS3oV7JEU\",\"https://www.youtube.com/watch?v=Z0MOD5ekJcc\"]', '2026-04-01 02:00:11.488', '2025-08-05 22:20:30.133', 1077, '43c1fff6-a024-4336-b5af-4cf21bc8c239', 1, 1952, 'Pioneirismo, criatividade e qualidade sĂŁo as caracterĂ­sticas que marcaram o Bob\'s desde sua fundaĂ§ĂŁo, em 1952, no burburinho de Copacabana, Rio de Janeiro. Rapidamente virou mania entre os cariocas com a sua primeira loja na Rua Domingos Ferreira, lanĂ§ando o hot-dog, o hambĂșrguer, o milkshake e o sundae. De lĂĄ pra cĂĄ, O Bobâs sĂł fez crescer, vendendo o que hĂĄ de mais saboroso em hambĂșgueres e sundaes, alĂ©m do inigualĂĄvel milkshake de ovomaltine. Em 1984, a rede iniciou seu sistema de franquias, com a abertura de duas unidades em VitĂłria (ES). Atualmente, a rede conta com mais de 1.000 pontos de venda em todas as capitais do Brasil. Esse sucesso nĂŁo Ă© por acaso. Afinal, as receitas do Bobâs foram desenvolvidas por dĂ©cadas, procurando atender sempre o paladar dos brasileiros. Por isso, o Bobâs Ă© nacionalmente reconhecido por seus produtos de excelente qualidade e sabor tipicamente brasileiro. O esforĂ§o do Bob`s nos Ășltimos anos tem sido premiado, conquistando pelo 13Âș ano consecutivo o Selo de Qualidade ABF - AssociaĂ§ĂŁo Brasileira de FRANCHISING. Conquistam o referido Selo as empresas franqueadoras que sĂŁo aprovadas por seus franqueados nos mais diversos fatores, averiguados por um instituto de pesquisa independente contratado pela ABF. Esta Ă© a maior prova do sucesso da parceria do Bob`s e seus franqueados. A franquia BOBÂŽs tem modelos de negĂłcio que se adaptam ao potencial de consumo de cada regiĂŁo. A estimativa do investimento vai depender da localizaĂ§ĂŁo do ponto de venda, da ĂĄrea a ser ocupada e do tipo de loja (rua, shopping center, drive thru) sendo o quiosque uma opĂ§ĂŁo disponĂ­vel apenas para franqueados que jĂĄ possuem loja em outro formato. O investimento mĂ­nimo depende do tamanho e necessidade de cada ponto.', 'Esse Ă© um teste de descriĂ§ĂŁo feito pelo QA', 'SĂO PAULO', 1, NULL, 1029, NULL, NULL, '2026-03-09 20:53:27.500', 'https://franquias.portaldofranchising.com.br/franquia-bobs-valor/', NULL, NULL, NULL, 1, 5, 5, 1, NULL, 1, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
