INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78at00szeh0sfjtzeyx8', 'JOHNNY ROCKETS', 'johnny-rockets', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Rede americana de restaurante casual dining, temĂĄtico, especializado em Hamburgueres , Sanduiches e Milk Shakes', 1990, 2017, NULL, '2026-04-01 02:00:11.519', '2025-08-05 22:20:30.149', 1080, NULL, 1, 1986, 'ConheĂ§a o Johnny Rockets â Uma verdadeira viagem no tempo Fundado em 1986, na vibrante cidade de Los Angeles, Estados Unidos, o Johnny Rockets traz um conceito nostĂĄlgico e tradicional dos anos 50. Conhecido por seus pratos icĂŽnicos, garĂ§ons danĂ§antes e hamburgueres exclusivos, o Johnny Rockets vemÂ  encantando geraĂ§Ă”es em mais de 20 paĂ­ses, tendo o Brasil como o maior destaque operacional fora dos Estados Unidos. AlĂ©m de diversas premiaĂ§Ă”es dentro e fora do Brasil, conquistou na dĂ©cada de 90, o prĂȘmio de Melhor HambĂșrguer e o Melhor Shake do Mundo eleito por 5 vezes consecutivas. No Brasil, o Johnny Rockets acumula 3 selos de excelĂȘncia em franchising (2021, 2022 e 2023), concedidos pela ABF - AssociaĂ§ĂŁo Brasileira de Franchising. Focado no conceito de restaurantes fast-casual, o Johnny Rockets Ă© um lugar para aproveitar com a famĂ­lia e amigos, contando com um cardĂĄpio bem variado e adaptado as exigĂȘncias do paladar brasileiro, carne Angus, mĂșsicas tradicionais, ambientes descontraĂ­dos e alegres e muito mais. Nossos franqueados amam o Johnny Rockets! Confira depoimentos de quem tem uma franquia Johnny Rockets e venha fazer parte dessa histĂłria.', NULL, 'SĂO PAULO', 1, NULL, 36, NULL, NULL, '2026-03-09 21:01:55.481', 'https://franquias.portaldofranchising.com.br/franquia-johnny-rockets/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ay00t0eh0sd7939v9r', 'CUORDICREMA', 'cuordicrema', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'A primeira e a maior rede de Franquias de Gelato italiano do Brasil Os principais valores da marca, sĂŁo tradiĂ§ĂŁo, inovaĂ§ĂŁo, gosto e saĂșde, proporcionando as clientes a melhor experiencia de consumo.', 2015, 2017, NULL, '2026-04-01 02:00:11.530', '2025-08-05 22:20:30.154', 1081, NULL, 1, 2012, 'ConheĂ§a a Cuor di Crema â A paixĂŁo em forma de gelato A Cuor di Crema nasceu de um sonho empreendedor de um italiano e uma brasileira, que juntos abriram o mercado de gelateria no Brasil, oferecendo todo o conceito tradicional\nitaliano para o clima tropical do Brasil. Investir na Cuor di Crema Ă© acreditar na verdadeira arte de fazer gelato. Ă oferecer para as pessoas um pedacinho da ItĂĄlia em cada sabor, com autenticidade, eficiĂȘncia e qualidade. Um dos diferenciais da Cuor di Crema Ă© a receita exclusiva feita na prĂłpria loja entre 5 e 7 minutos. Garantindo o frescor e a consistĂȘncia que o verdadeiro gelato italiano deve ter. 100% natural Rico em vitaminas Sem adiĂ§ĂŁo de gordura, aromatizantes e conservantes SaudĂĄvel OpĂ§Ă”es zero aĂ§Ășcar e zero lactose OpĂ§ĂŁo de gelatos para pet. E com um ambiente aconchegante e acolhedor, a Cuor di Crema oferece a verdadeira e autĂȘntica tradiĂ§ĂŁo italiana, que vem conquistando e fidelizando clientes desde 2012. Nossos franqueados amam a Cuor di Crema! Confira depoimentos de quem tem uma franquia Cuor di Crema e venha fazer parte dessa histĂłria.', NULL, 'SĂO PAULO', 1, NULL, 14, NULL, NULL, '2026-03-09 21:02:50.184', 'https://franquias.portaldofranchising.com.br/franquia-cuordicrema-docerias-e-sorveterias/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78b300t1eh0suj0yqx1n', 'OMO LAVANDERIA', 'omo-lavanderia', NULL, 'Limpeza e ConservaĂ§ĂŁo', 'Lavanderia', 'ServiĂ§os de Lavanderia e HigienizaĂ§ĂŁo de Estofados', 2020, 2021, '[\"https://www.youtube.com/watch?v=WlOS6QpxACQ\"]', '2026-04-01 02:00:11.539', '2025-08-05 22:20:30.159', 1082, NULL, 1, 2020, 'OMO Lavanderia Ă© a rede de lavanderias da marca mais amada do Brasil, com mais de 200 lojas espalhadas pelo paĂ­s. Com dois modelos de negĂłcio â Self-Service e Especializada â atende a diferentes perfis de investidores e consumidores, unindo conveniĂȘncia, eficiĂȘncia e cuidado profissional com as roupas. O grande diferencial da franquia estĂĄ no suporte completo ao franqueado: da implantaĂ§ĂŁo ao acompanhamento prĂłximo da operaĂ§ĂŁo. AlĂ©m disso, OMO Lavanderia Ă© a Ășnica rede com um selo de programa exclusivo de lavagem, desenvolvido junto aos fabricantes das mĂĄquinas e testado com rigor tĂ©cnico para garantir performance, cuidado e padronizaĂ§ĂŁo em todas as unidades. Uma franquia sĂłlida, reconhecida e alinhada aos novos hĂĄbitos de consumo â ideal para quem busca empreender com confianĂ§a e o respaldo de uma marca de renome.', NULL, 'SĂO PAULO', 1, NULL, 199, NULL, NULL, '2026-03-09 21:03:34.011', 'https://franquias.portaldofranchising.com.br/franquia-omo-lavanderia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '160000', NULL, NULL, NULL, '25000', NULL, '5', '2', '115000', '20000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78b800t2eh0skoec5uew', 'F.A COLCHĂES', 'f-a-colchoes', NULL, 'Casa e ConstruĂ§ĂŁo', 'MĂłveis e DecoraĂ§ĂŁo', 'Loja de colchoes, produtos para o sono e complementos para o quarto', 2024, 2023, '[\"https://www.youtube.com/watch?v=0i9IQ8Gegw4\",\"https://www.youtube.com/watch?v=gq07M3KNNJU\",\"https://www.youtube.com/watch?v=F94KiUAy2xw\"]', '2026-04-01 02:00:11.549', '2025-08-05 22:20:30.165', 1083, NULL, 1, 1964, 'A F.A. ColchĂ”es nasceu em 1964 com o propĂłsito de transformar o mercado de colchĂ”es, oferecendo qualidade e conforto. Com um parque industrial moderno e mais de 100 lojas, a marca Ă© reconhecida pela inovaĂ§ĂŁo e excelĂȘncia, sendo uma das cinco empresas do setor com o selo PrĂł-Espuma (INER). Com um modelo de vendas hĂ­brido (loja fĂ­sica e online) e forte suporte logĂ­stico, garantimos uma operaĂ§ĂŁo ĂĄgil e eficiente para nossos franqueados.', NULL, 'PARANĂ', 1, NULL, 2, NULL, NULL, '2026-03-09 21:04:10.473', 'https://franquias.portaldofranchising.com.br/franquia-fa-colchoes/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '100000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78be00t3eh0sxi1i4ws6', 'MANA POKE', 'mana-poke', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'POKE', 2020, 2022, '[\"https://www.youtube.com/watch?v=P6m1g75Mv4k\",\"https://www.youtube.com/watch?v=OIea6rKfs6c\"]', '2026-04-01 02:00:11.559', '2025-08-05 22:20:30.170', 1084, NULL, 1, 2018, 'A rede de franquias Mana Poke, especializada em culinĂĄria havaiana completou 4 anos e jĂĄ Ă© considerada a maior do Brasil. \nApĂłs a primeira unidade em Campinas/SP, os sĂłcios decidiram levar a experiĂȘncia da culinĂĄria havaiana como uma opĂ§ĂŁo saudĂĄvel para todo territĂłrio nacional. \nA operaĂ§ĂŁo no modelo de fast casual reduz os custos com mĂŁo de obra e facilita a operaĂ§ĂŁo. \nO ambiente das lojas traz uma atmosfera leve e agradĂĄvel, lembrando o lifestyle havaiano muito presente na marca e contribuindo com o engajamento dos clientes, que se tornam âfansâ da marca ao se identificar de uma forma real. \nHoje, a rede jĂĄ se faz presente em praticamente todos os grandes centros do interior de SĂŁo Paulo, com unidades na capital do estado, Minas Gerais, Rio de Janeiro, GoiĂĄs e ParanĂĄ. \nA maior parte dos franqueados jĂĄ possui mais de uma loja. \nA missĂŁo da Mana Poke Ă© popularizar o acesso Ă  alimentaĂ§ĂŁo saudĂĄvel, oferecendo preĂ§o justo e qualidade aos clientes. \nAlĂ©m disso, quer ser referĂȘncia em poke no Brasil, tendo como valores a experiĂȘncia do cliente, o trabalho em equipe e a valorizaĂ§ĂŁo de todos os parceiros. \nO investimento inicial para quem quer se tornar um franqueado da marca Ă© a partir de R$ 390 mil. \nO valor inclui taxa de franquia e capital de giro. \nO retorno do investimento Ă© previsto em atĂ© 24 meses com faturamento mĂ©dio de R$ 150 a R$ 600 mil por mĂȘs. \nVenha ser um Franqueado da Rede Mana Poke, uma das maiores tendĂȘncias gastronĂŽmicas no Brasil! \nUma Ăłtima opĂ§ĂŁo para quem quer um investimento seguro com uma empresa sĂ©ria e que traz bons resultados!', NULL, 'SĂO PAULO', 1, NULL, 69, NULL, NULL, '2026-03-09 21:04:44.742', 'https://franquias.portaldofranchising.com.br/franquia-mana-poke/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '490000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bk00t4eh0spv3nxr2z', 'GERMAN FINANCIAL', 'german-financial', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Consultoria financeira 360Âș para pessoas fĂ­sicas e jurĂ­dicas.', 2023, 2023, NULL, '2026-04-01 02:00:11.568', '2025-08-05 22:20:30.176', 1085, NULL, 1, 2023, '', NULL, 'PARANĂ', 1, NULL, 123, NULL, NULL, '2026-03-09 21:05:47.272', 'https://franquias.portaldofranchising.com.br/franquia-german-financial/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bp00t5eh0s37tou2ow', 'MUNDO ANIMAL LANCHONETE TEMĂTICA', 'mundo-animal-lanchonete-tematica', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Lanchonete TemĂĄtica', 2018, 2020, '[\"https://www.youtube.com/watch?v=ESlaRUgDUP0\",\"https://www.youtube.com/watch?v=WEj3hV7lYX0\",\"https://www.youtube.com/watch?v=HwkFAr6w4i8\",\"https://www.youtube.com/watch?v=1rHbEFQONlM\"]', '2026-04-01 02:00:11.578', '2025-08-05 22:20:30.182', 1086, NULL, 1, 2011, 'Nascemos para proporcionar uma experiĂȘncia inesquecĂ­vel e repleta de diversĂŁo, em um ambiente temĂĄtico inspirado na selva! Desde a decoraĂ§ĂŁo, feita com mĂłveis desenvolvidos de maneira artesanal, atĂ© o cardĂĄpio com pratos imensamente deliciosos que levam nomes de animais e sĂŁo perfeitos para dividir com quem se ama, tudo na Mundo Animal Ă© pensado para que vocĂȘ viva uma verdadeira imersĂŁo em um mundo de muitas aventuras, alegrias e sabores.\nÂ \nA primeira unidade da nossa selva foi fundada em junho de 2011 com uma equipe muito modesta e espaĂ§o limitado em CapĂŁo da Canoa - RS. O rĂĄpido sucesso permitiu ampliar a estrutura, conquistar novos parceiros e expandir para diferentes regiĂ”es no Brasil. Hoje estamos em 16Â estados do Brasil, nos quatro cantos do paĂ­s. E nĂŁo vamos parar por aĂ­! Queremos ir alĂ©m, sempre oferecendo a pessoas de todas as idades a oportunidade de desbravar uma selva de delĂ­cias, estimulando, fortalecendo e valorizando vĂ­nculos familiares. Afinal, sua famĂ­lia Ă© a nossa famĂ­lia.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 68, NULL, NULL, '2026-03-09 21:06:09.299', 'https://franquias.portaldofranchising.com.br/franquia-mundo-animal-lanchonete-tematica/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '865000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78bv00t6eh0s75g6yatp', 'PORTOBELLO SHOP', 'portobello-shop', NULL, 'Casa e ConstruĂ§ĂŁo', 'ConstruĂ§ĂŁo e Reforma', 'Loja Especializada em Revestimentos CerĂąmicos', 1998, 2004, NULL, '2026-04-01 02:00:11.587', '2025-08-05 22:20:30.187', 1087, NULL, 1, 1979, 'Como parte integrante do grupo Portobello S.A., a Portobello Shop S.A., nasceu em 1.998, trazendo para o mercado um novo conceito: alĂ©m de uma linha exclusiva de produtos de alta qualidade, oferece ao cliente atendimento personalizado e serviĂ§os que auxiliam no momento da decisĂŁo e facilitam o desenvolvimento da obra. \nA busca por tendĂȘncias, novidades, revisĂŁo de conceito, criaĂ§ĂŁo de soluĂ§Ă”es e design inovadores, resultou a criaĂ§ĂŁo da maior e melhor rede de lojas especializadas em revestimentos cerĂąmicos no Brasil, a Portobello Shop. \nHoje, com mais de 110 lojas instaladas em todo o Brasil, operadas por mais de 60 Franqueados, a Portobello Shop tornou-se um sucesso, com a atuaĂ§ĂŁo de suas lojas nos Formatos Compacto, Tradicional e EmpĂłrio. Â  Â   \nAs lojas oferecem um pacote de serviĂ§os de acordo com as necessidades de cada cliente:  Produtos exclusivos\nA rede possui uma linha de produtos exclusiva e extremamente variada, que atravĂ©s de suas infinitas combinaĂ§Ă”es, possibilita ambientes totalmente personalizados.  Atendimento especializado\nPara auxiliar os clientes na concretizaĂ§ĂŁo do projeto de seu sonho, as lojas contam com uma Equipe de Arquitetos e Projetistas.  MediĂ§ĂŁo da obra\nVerificaĂ§ĂŁo das medidas corretas dos ambientes a serem revestidos, garantindo a precisĂŁo na metragem a ser comprada.  OrĂ§amento\nQuantificaĂ§ĂŁo exata do revestimento cerĂąmico a ser utilizado, evitando sobras e transtornos de complementaĂ§ĂŁo, traduzindo no conforto do planejamento financeiro da obra.  Acompanhamento\nProfissionais especializados verificam o desenvolvimento da obra no ato da instalaĂ§ĂŁo do produto, minimizando os erros de aplicaĂ§ĂŁo ou do nĂŁo cumprimento do projeto especificado. Os clientes recebem o manual tĂ©cnico Portobello Shop para facilitar o esclarecimento de dĂșvidas, bem como auxiliar com dicas de manutenĂ§ĂŁo e limpeza.  Assessoria tĂ©cnica\nTodas as lojas possuem um assistente tĂ©cnico especializado, que alĂ©m de tirar dĂșvidas de como proceder quanto Ă  utilizaĂ§ĂŁo do produto, Ă© a interface entre o cliente e a Portobello Shop na resoluĂ§ĂŁo de eventuais problemas relativos ao produto e seu uso.  SimulaĂ§ĂŁo de ambientes por computador - 3D - Promob\nOs projetos de paginaĂ§ĂŁo auxiliam na visualizaĂ§ĂŁo da melhor composiĂ§ĂŁo do revestimento cerĂąmico, maximizando a possibilidade de combinaĂ§ĂŁo nos seus vĂĄrios formatos e peĂ§as especiais, aumentando o grau de certeza no momento da escolha do cliente.  LogĂ­stica de entregas programadas\nAtravĂ©s destes serviĂ§os, o cliente tem a comodidade de programar a data de chegada do material em sua obra, respeitando o seu melhor momento para este recebimento, minimizando as chances de perda ou quebra da mercadoria. Â  Â  Â  Â    HistĂłrico \nDesde entĂŁo a empresa apresentou um crescimento rĂĄpido, sĂłlido e planejado, que pode ser observado no quadro cronolĂłgico:  1977 â InĂ­cio da construĂ§ĂŁo da CerĂąmica Portobello, no municĂ­pio de Tijucas (SC).  1979 â InĂ­cio da produĂ§ĂŁo da CerĂąmica Portobello. 1980 â Equipe: 250 colaboradores.  1981 â InĂ­cio das exportaĂ§Ă”es. Abertura da primeira filial em SĂŁo Paulo.  1982 â SubstituiĂ§ĂŁo do combustĂ­vel GLP (GĂĄs Liquefeito de PetrĂłleo) por GĂĄs Pobre, oriundo de carvĂŁo vegetal / InstalaĂ§ĂŁo do 1Âș computador â Labo 8032 (64kb de memĂłria) / FundaĂ§ĂŁo da Adec.  1983 â Equipe: 624 colaboradores / A empresa participa da 1ÂȘ Feira Internacional, no PanamĂĄ. Descoberta de jazidas na regiĂŁo de Dr. Pedrinho, Campo Alegre e SĂŁo Bento do Sul (SC).  1984 â LanĂ§amento da linha Carga Pesada: intensivo trabalho de marketing / CriaĂ§ĂŁo do CCQ â CĂ­rculos de Controle de Qualidade.  1987 â AmpliaĂ§ĂŁo do parque fabril, aumentando a produĂ§ĂŁo para 1 milhĂŁo de mÂČ/mĂȘs / InĂ­cio da parceria com o Senai: cursos de TĂ©cnicos Ceramistas e Aprendizagem Industrial MecĂąnica.  1988 â Equipe ultrapassa mil funcionĂĄrios / Primeira participaĂ§ĂŁo na Feira de Bologna, ItĂĄlia.  1989 â CriaĂ§ĂŁo do Departamento TĂ©cnico.  1990 â CriaĂ§ĂŁo da Portobello AmĂ©rica / Abertura de 12 filiais, no interior de SP, RJ e na regiĂŁo Nordeste.  2011 â Conquistamos pelo sexto ano consecutivo, do Selo de ExcelĂȘncia em Franchising 2011 pela ABF â AssociaĂ§ĂŁo Brasileira de Franchising, e do PrĂȘmio em 2Âș lugar â no segmento Casa, DecoraĂ§ĂŁo e Presentes, pela Revista PEGN â Pequenas Empresas Grandes NegĂłcios â Editora Globo.  2012 â Selo de ExcelĂȘncia em Franchising â 2012 pela ABF â AssociaĂ§ĂŁo Brasileira de Franchising. E tambĂ©m, o PrĂȘmio de Melhor Franquia (1Âș. Lugar) no segmento Casa, DecoraĂ§ĂŁo e Presentes, pela Revista PEGN â Pequenas Empresas Grandes NegĂłcios â Editora Globo.  2013 â Selo de ExcelĂȘncia em Franchising â 2013 pela ABF â AssociaĂ§ĂŁo Brasileira de Franchising.', NULL, 'SANTA CATARINA', 1, NULL, 161, NULL, NULL, '2026-03-09 21:06:56.428', 'https://franquias.portaldofranchising.com.br/franquia-portobello-shop-construcao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '541000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78c000t7eh0sr0pni9nr', 'PIZZA HUT', 'pizza-hut', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Criada em 1958 nos EUA, a Pizza Hut Ă© a maior rede de pizzaria do mundo com presenĂ§a em 100 paĂ­ses, com mais de 16 mil restaurantes distribuĂ­dos pelos cinco continentes.', 1970, 2021, NULL, '2026-04-01 02:00:11.596', '2025-08-05 22:20:30.193', 1088, NULL, 1, 1958, 'A primeira loja foi inaugurada em maio de 1958, por dois irmĂŁos, lĂĄ no Kansas. Hoje, a rede Ă© uma Ăłtima oportunidade de negĂłcio, fazendo muito sucesso por aqui: Ă a 7ÂȘ marca mais querida pelos brasileiros.* SĂŁo mais de 260 lojas distribuĂ­das por todo o paĂ­s. Faz parte da IMC (International Meal Company), empresa de capital aberto, detentora tambĂ©m das marcas KFC, Frango Assado, Viena, entre outras. E a tendĂȘncia Ă© que a marca cresĂ§a ainda mais: O Brasil Ă© o 4Âș paĂ­s que mais consome fast food.** A expectativa Ă© que o Brasil se torne um dos maiores mercados de Pizza Hut. A melhor fatia de um mercado de milhĂ”es pode ser sua. Fontes: *Segundo o ranking anual Brand Finance Restaurant/2022. ** EAE Bussiness School.', NULL, 'SĂO PAULO', 1, NULL, 269, NULL, NULL, '2026-03-09 21:09:36.865', 'https://franquias.portaldofranchising.com.br/franquia-pizza-hut/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '1185000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78c700t8eh0szheawvbp', 'DF DR. FISCAL', 'df-dr-fiscal', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Franquia de consultoria empresarial com ĂȘnfase em soluĂ§Ă”es tributĂĄrias, estabelecida desde 2017 e com mais de 325 unidades espalhadas pelo Brasil, oferecendo serviĂ§os Ășnicos e inovadores.', 2017, 2018, '[\"https://www.youtube.com/watch?v=8maKZzrwVJA\"]', '2026-04-01 02:00:11.605', '2025-08-05 22:20:30.199', 1089, NULL, 1, 2017, 'A Dr Fiscal surgiu do GFBR - Grupo Fiscal do Brasil, Conglomerado de empresas com mais de 15 anos de experiĂȘncia na ĂĄrea fiscal e tributĂĄria. Luis Wulff, seu fundador, identificou que dos 4 trilhĂ”es de crĂ©ditos a recuperar, boa parte se encontrava nos microempreendedores e pequenas empresas. A partir desse conceito foi fundada a Dr Fiscal, empresa focada em melhorar a saĂșde tributĂĄria e fiscal de empresas que atuam no regime do Simples Nacional. Nossa estrutura de regras fiscais formatadas em uma modelagem de algoritmo possui hoje 5 milhĂ”es de regras fiscais e mais de 32 milhĂ”es de produtos, permitindo aos empresĂĄrios do Simples Nacional a correta emissĂŁo das suas NFes e tambĂ©m a acuracidade no pagamento dos tributos, evitando riscos com a fiscalizaĂ§ĂŁo. Com mais de 7.086.597 de empresas optantes pelo regime, nosso modelo de franquia tem demonstrado exito em todo o mercado brasileiro.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 140, NULL, NULL, '2026-03-09 21:10:18.626', 'https://franquias.portaldofranchising.com.br/franquia-df-dr-fiscal/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '30000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
