INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78dr00theh0swaxbkdoj', 'BIBI', 'bibi', NULL, 'Moda', 'CALĂADOS', 'Loja de CalĂ§ados e AcessĂłrios Infantis.', 2008, 2010, '[\"https://www.youtube.com/watch?v=pLIdARMBfC0\",\"https://www.youtube.com/watch?v=V1OGjmQ_id8\",\"https://www.youtube.com/watch?v=wNFEkl_9fWc\"]', '2026-04-01 02:00:11.690', '2025-08-05 22:20:30.255', 1098, NULL, 1, 1949, 'Fundada em 1949, a Bibi Ă© pioneira na fabricaĂ§ĂŁo de calĂ§ados infantis no Brasil. Com indĂșstria prĂłpria, atua por meio do modelo de franquias hĂĄ mais de 15 anos. Especialista no pĂșblico infantil, a marca desenvolve produtos com tecnologia que visam contribuir para o crescimento saudĂĄvel de crianĂ§as de 0 a 9 anos em diferentes fases do desenvolvimento. AlĂ©m disso, a Bibi tem atuaĂ§ĂŁo global, estĂĄ presente em mais de 60 paĂ­ses nos cinco continentes e soma 152 lojas espalhadas por todo Brasil e em paĂ­ses da AmĂ©rica Latina. Ambientada no universo infantil de Baby, cada loja harmoniza produtos para todas as fases de desenvolvimento da crianĂ§a, seja ela Baby, Mini ou Kids. AlĂ©m de transformar o momento da compra em uma experiĂȘncia sensorial e fluĂ­da de consumo. Para isso, a rede investe em conceitos de transformaĂ§ĂŁo digital para que os consumidores optem pelo fĂ­sico ou digital, proporcionando praticidade na jornada de compra. A Bibi possui um mix de calĂ§ados e acessĂłrios com linhas exclusivas, coleĂ§Ă”es inovadoras e um calendĂĄrio de vitrines e aĂ§Ă”es, criando a sensaĂ§ĂŁo de uma nova loja a cada visita. Mais que uma operaĂ§ĂŁo infantil, a Bibi Ă© um ponto de experiĂȘncia da marca com o seu consumidor. Com o propĂłsito de fazer o bem, um passinho por vez, a empresa visa o incentivo Ă s prĂĄticas sustentĂĄveis, o estĂ­mulo ao desenvolvimento saudĂĄvel das geraĂ§Ă”es futuras, e o cumprimento das suas responsabilidades sociais para a construĂ§ĂŁo de um mundo melhor. HĂĄ mais de 70 anos a bibi decidiu olhar o mundo pela perspectiva da crianĂ§a para fazer o bem para elas, porque fazendo o bem pra elas, elas fazem o bem para o mundo.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 148, NULL, NULL, '2026-01-12 12:27:17.000', 'https://franquias.portaldofranchising.com.br/franquia-bibi/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '380000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
