INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78e100tjeh0szgkmhqye', 'M1 MOTORS', 'm1-motors', NULL, 'ServiĂ§os e Outros NegĂłcios', 'CONSULTORIAS', 'Consultoria Automotiva', 2022, 2022, NULL, '2026-04-01 02:00:11.709', '2025-08-05 22:20:30.266', 1100, NULL, 1, 2020, 'A InovaĂ§ĂŁo do Mercado Automotivo! A primeira loja de carros presente no mundo digital e nos maiores pontos de circulaĂ§ĂŁo da cidade. Oferecemos um modelo inovador para o setor automotivo. Vamos transformar a forma como os brasileiros compram e vendem veĂ­culos, somos uma facilitadora e oferecemos uma experiĂȘncia diferenciada. Com mais de 4 anos de atuaĂ§ĂŁo no mercado automotivo, e 27 anos de experiencia do fundador da marca, o grupo M1 consolidou-se como referĂȘncia ao desenvolver um estoque 100% online que proporciona praticidade na escolha, para comprar ou vender um carro. Nossa equipe Ă© formada por profissionais especializados, focados em maximizar a lucratividade de cada parceiro franqueado. Fazer parte da nossa rede Ă© integrar um modelo de negĂłcio que busca constantemente tecnologia de ponta e se mantĂ©m Ă  frente do mercado, garantindo a satisfaĂ§ĂŁo dos consumidores e o crescimento sustentĂĄvel de franqueados e clientes. Com um know-how de qualidade, inspirado nas tendĂȘncias globais, e utilizando o conceito de Auto Broker, amplamente utilizado nos EUA e em outros paĂ­ses de primeiro mundo, realizamos transaĂ§Ă”es de compra e venda de veĂ­culos de forma rĂĄpida e sem complicaĂ§Ă”es. Nossos franqueados estĂŁo prontos para compreender as expectativas dos clientes e oferecer soluĂ§Ă”es personalizadas para cada necessidade. Esperamos vocĂȘ como um franqueado M1 MOTORS. MissĂŁo: Revolucionar o mercado automotivo brasileiro, e criar um ambiente que preza pelo bem-estar e satisfaĂ§ĂŁo do cliente. VisĂŁo: Ser referĂȘncia no Brasil como a melhor escolha para quem deseja comprar, vender ou trocar de carro, promovendo um crescimento conjunto e sustentĂĄvel. Valores: Respeito, Ă©tica, transparĂȘncia, inovaĂ§ĂŁo e compromisso com a credibilidade e a confianĂ§a.', NULL, 'PARANĂ', 1, NULL, NULL, NULL, NULL, '2025-08-18 13:06:28.000', 'https://franquias.portaldofranchising.com.br/franquia-m1-motors/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78e800tkeh0s3h0vbi4t', 'FOZ SUSTENTĂVEL', 'foz-sustentavel', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'Invista no seu futuro e no futuro do planeta com a Foz. Gere lucro enquanto economiza com o nosso mĂ©todo exclusivo e tecnologias inovadoras. Junte-se a sustentabilidade lucrativa Ă  prova de crises.', 2019, 2024, '[\"https://www.youtube.com/watch?v=EvEcJWGYGmA\",\"https://www.youtube.com/watch?v=jX3ub0HhMJY\",\"https://www.youtube.com/watch?v=LcO31YfMt3o\",\"https://www.youtube.com/watch?v=oDIgdowz5mY\"]', '2026-04-01 02:00:11.719', '2025-08-05 22:20:30.272', 1101, NULL, 1, 2016, 'Transforme desperdĂ­cio de ĂĄgua em lucro. Seja pioneiro com a Foz SustentĂĄvel! VocĂȘ sabia que o Brasil desperdiĂ§a mais de 6 TRILHĂES de litros de ĂĄgua e movimenta mais de R$70 BILHĂES de reais ao ano? Se nĂŁo sabia, vocĂȘ nĂŁo estĂĄ sozinho. Enquanto todos falam de energia solar, poucos percebem que a ĂĄgua tambĂ©m precisa de uma revoluĂ§ĂŁo. A Foz SustentĂĄvel estĂĄ liderando essa mudanĂ§a transformando desperdĂ­cio em lucro, tanto para unidades prĂłprias quanto para unidades franqueadas. Com mais de 9 anos de experiĂȘncia de mercado e mais de 30 milhĂ”es de reais economizados, a Foz desenvolveu um modelo de franquia barata com atuaĂ§ĂŁo exclusiva chamada de âEconomia por Performanceâ, permitindo que os clientes economizem atĂ© 80% de ĂĄgua e 30% na energia de bombeamento sem precisar investir nada. Isso significa que toda a economia gerada Ă© compartilhada entre o cliente e a franquia, garantindo uma receita recorrente e acumulativa, alĂ©m de outras formas de ganhos como por exemplo, a Venda do Projeto e GestĂŁo Foz 4.0. AtravĂ©s de um modelo Robusto e Seguro, as franquias baratas da Foz oferecem: NegĂłcio validado com mĂ©todos exclusivos. Tecnologias inovadoras com produĂ§ĂŁo prĂłpria. Retorno expressivo com margens de lucro de 30% para Venda do Projeto e 75% para Economia por Performance. Mercado pouco explorado com alta demanda e baixa concorrĂȘncia. Equipamentos sem custo para o franqueado. Sem estoque: envio de equipamentos por conta da franqueadora. Franquia Barata com baixo investimento e grande retorno. Sustentabilidade Lucrativa: ganhe dinheiro enquanto ajuda o planeta. âO Nosso modelo exclusivo permite que empresas e condomĂ­nios economizem atĂ© 80% no ponto de ĂĄgua sem precisar investir nem um centavo. Em troca, a economia gerada Ă© dividida entre o cliente e a franquia, gerando uma receita previsĂ­vel, recorrente e cumulativa.â Imagine, por exemplo, um condomĂ­nio ou empresa que paga R$16 mil por mĂȘs na conta de ĂĄgua. Com a Foz, se reduzirmos esse custo em 50%, metade fica com o cliente e metade com a franquia e o franqueado, sem que o cliente precise investir nada em contratos que variam de 3 a 5 anos. Ou seja, um Ășnico cliente que gerar R$2.000 por mĂȘs seguindo o plano de aquisiĂ§ĂŁo de 4 clientes/mĂȘs ou 48 clientes no total, Ă© possĂ­vel atingir R$100.000 por mĂȘs de recorrĂȘncia, R$1.200.000 faturados, com uma estrutura enxuta de uma franquia barata. A franqueadora decidiu em 2024 que abriria novas unidades Brasil afora, o mercado estĂĄ praticamente inexplorado e entrar agora Ă© uma grande oportunidade. As primeiras 20 unidades jĂĄ foram adquiridas, e jĂĄ restam poucas oportunidades para algumas regiĂ”es. Garanta sua franquia antes que sua regiĂŁo seja totalmente ocupada. O que os franqueados estĂŁo dizendo: \"Comecei minha franquia com 2 reais no bolso. 3 meses depois jĂĄ faturei R$12.000, que deu para cobrir investimentos. Tenho muitos prĂ©dios em recorrĂȘncia que me dĂĄ tranquilidade no final do mĂȘs.\" - Markus Lebre, 30 anos. âNesse negĂłcio conseguimos gerar economia para o cliente, recorrĂȘncia para nĂłs e temos um amplo leque de atuaĂ§ĂŁo. NegĂłcios locais, condomĂ­nios, hospitais, hotĂ©is, faculdades, indĂșstrias e mais um monte.â - Victor Melo, 28 anos. Aproveite um oceano azul de oportunidades com um negĂłcio altamente lucrativo, escalĂĄvel e sustentĂĄvel com a franquia barata da Foz: Baixe a apresentaĂ§ĂŁo agora, entenda como a franquia funciona e como vocĂȘ pode lucrar muito enquanto ajuda o planeta.', NULL, 'PERNAMBUCO', 1, NULL, 20, NULL, NULL, '2025-09-06 00:00:12.000', 'https://franquias.portaldofranchising.com.br/franquia-foz-sustentavel/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ee00tleh0socniwt7g', 'SORRIDENTS', 'sorridents', NULL, 'SaĂșde, Beleza e Bem-Estar', 'Odontologia', 'A Sorridents Ă© uma das maiores e mais conceituadas redes de clĂ­nicas odontolĂłgicas do mundo. Fundada em 1995, a Sorridents nasceu com o objetivo de trazer a todos o direito fundamental de sorrir.', 2005, 2008, '[\"https://www.youtube.com/watch?v=-nd899AmhRk\",\"https://www.youtube.com/watch?v=Lje18ToyqI0\",\"https://www.youtube.com/watch?v=6fDTFLYhqDk\"]', '2026-04-01 02:00:11.729', '2025-08-05 22:20:30.278', 1102, NULL, 1, 1995, 'SEJA MUITO BEM VINDO Ă FRANQUIA SORRIDENTS\nÂ  A REDE DE CLĂNICAS ODONTOLĂGICAS MAIS PREMIADA DO BRASIL!  \nÂ  A franquiaÂ Sorridents Ă© a mais premiada rede de clĂ­nicas odontolĂłgicas do Brasil. Â  Fundada em 1995, a rede completou 25Â anos de sucesso e referĂȘncia no segmento odontolĂłgico com mais de 4,5 milhĂ”es de pacientes atendidos!\nÂ  O setor de clĂ­nicas odontolĂłgicas possui uma enorme oportunidade de negĂłcio, existem mais de 20 milhĂ”es de brasileiros que ainda nĂŁo tiveram nenhuma experiĂȘncia com o cirurgiĂŁo dentista e este segmento possui uma das maiores rentabilidades do setor do Franchising.\nÂ  Mas por que Sorridents?\nÂ  A Sorridents em suas duas dĂ©cadas e meia de histĂłria acumulou experiĂȘncia suficiente para ganhar 9Â vezes o prĂȘmio de Melhor Franquia do Brasil, alĂ©m de ter recebido diversos outros destaques como ter por recebido por 10 anos consecutivos o Selo de ExcelĂȘnciaÂ e estar no ranking Top 25 do Franchising Brasileiro. \nIsso significa uma grande engrenagem com um time de especialistas e infraestrutura completa para auxiliar as Unidades da rede e seus franqueados a potencializar a gestĂŁo do seu negĂłcio atravĂ©s do Porque Sorridents!Â  \nA franqueadora trabalha para trazer a rede inovaĂ§ĂŁo e estrutura, sempre com novos projetos, parcerias e ferramentas que agreguem ainda mais valor ao trabalho e serviĂ§o oferecido nas clĂ­nicas, assim oferecemos ao franqueado:  - Marca\nÂ  O apoio de um nome fortalecido hĂĄ 25Â anos sobre os seus sĂłlidos pilares com a missĂŁo de propiciar acesso a uma odontologia moderna com conforto, conveniĂȘncia e qualidade com 95% de pacientes satisfeitos. Â  Reconhecida pelos maiores veĂ­culos de mĂ­dias especializada como a Melhor Franquia do Brasil no segmento de saĂșde e bem-estar, alĂ©m de constante visibilidade e relevĂąncia no dia a dia do consumido em matĂ©rias na Exame, Veja, GloboNews, Portal Terra, e outros importantes veĂ­culos.\nÂ  - Estrutura \nCom clĂ­nicas tĂ©rreas com mais de 180 m2 e padronizadas, a rede busca proporcionar um atendimento de excelĂȘncia em todas as suas Unidades. Â  A equipe de implantaĂ§ĂŁo da franqueadora acompanha o novo franqueado em todos as etapas de construĂ§ĂŁo da sua loja, desde o seu projeto de arquitetura a festa de inauguraĂ§ĂŁo. Depois suporte continuaÂ com consultores de campo, time de marketing, call center, jurĂ­dico e muito mais.  - Tecnologia \nO franqueado faz a gestĂŁo de sua Unidade no Sistema SISO e acompanha sua performance no BI Sorridents. Â  AlĂ©m de rentabilizar o seu negĂłcio com as ferramentas exclusivas da marca como o CartĂŁo de CrĂ©dito Sorridents, onde o paciente pode parcelar seus tratamentos em atĂ© 18 vezes.  - ServiĂ§osÂ  \nO paciente Sorridents encontra todas as especialidades em um sĂł lugar e mais que isso, oferecemos um cuidado especial, tratando-o como Ășnico, ouvindo a sua necessidade, explicando o seu problema e mostrando a melhor soluĂ§ĂŁo e o quando Ă© importante tratar, esse Ă© o jeito de ser Sorridents! \nÂ  Seja um Franqueado Sorridents! \nConheĂ§a mais sobre o negĂłcio Sorridents.', NULL, 'SĂO PAULO', 1, NULL, 391, NULL, NULL, '2026-03-09 21:14:28.560', 'https://franquias.portaldofranchising.com.br/franquia-sorridents-odontologica/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '460000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ek00tmeh0sobea7riz', 'VIVENDA DO CAMARĂO', 'vivenda-do-camarao', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'CulinĂĄria RĂĄpida de Frutos do Mar', 1998, 1996, '[\"https://www.youtube.com/watch?v=o8veMMbic64\"]', '2026-04-01 02:00:11.738', '2025-08-05 22:20:30.284', 1103, NULL, 1, 1984, 'A Vivenda do CamarĂŁo surgiu com o intuito de oferecer a sofisticaĂ§ĂŁo e a qualidade do camarĂŁo a preĂ§os acessĂ­veis. No dia 12 de junho de 1984, no bairro paulistano de Moema, foi inaugurado o primeiro restaurante da rede. Uma simples faixa na rua anunciando `CAMARĂO A PREĂO JUSTO` foi o suficiente para que se formasse uma fila de clientes esperando para conhecer a grande novidade. A partir de entĂŁo, com fila de espera diariamente, fez-se necessĂĄria a abertura de mais um restaurante, dessa vez no bairro dos Jardins, em SĂŁo Paulo. O sucesso se consolidou e apareceu o convite para a PraĂ§a Gourmet do Shopping Morumbi, onde foi criado, entĂŁo, o conceito de Vivenda do CamarĂŁo Express, possibilitando a abertura de novos estabelecimentos e a consolidaĂ§ĂŁo da rede nos principais shoppings. Diante disso, fez-se necessĂĄria a construĂ§ĂŁo da atual CPA - Central Processadora de Alimentos, situada em Cotia, na Grande SĂŁo Paulo, onde sĂŁo processadas cerca de 2000 toneladas de pescados por ano, que se transformar em todos os pratos oferecidos pelas lojas. Dotada de equipamentos exclusivos e de altĂ­ssima tecnologia, permite mais agilidade na produĂ§ĂŁo e garante um excelente controle de qualidade. Oferecendo a mesma qualidade exigida pelos importadores, mas a preĂ§os populares, a Vivenda do CamarĂŁo leva ao alcance de todos o riquĂ­ssimo valor proteico e as baixas calorias do camarĂŁo. Ă muito importante destacar que os camarĂ”es utilizados pela Vivenda sĂŁo cultivados em fazendas especializadas e nĂŁo recebem nenhum tipo de conservante. Trata-se de um alimento altamente saudĂĄvel, sem quĂ­micas e da mais alta qualidade. Oferecendo a mesma qualidade exigida pelos importadores, mas a preĂ§os populares, a franquia Vivenda do CamarĂŁo leva ao alcance de todos o riquĂ­ssimo valor proteico e as baixas calorias do camarĂŁo. Ă muito importante destacar que os camarĂ”es utilizados pela Vivenda sĂŁo cultivados em fazendas especializadas e nĂŁo recebem nenhum tipo de conservante. Trata-se de um alimento altamente saudĂĄvel, sem quĂ­micas e da mais alta qualidade. Tudo isso garantiu a certificaĂ§ĂŁo para exportaĂ§ĂŁo de alimentos prontos para os EUA (FDA) e para a Comunidade Europeia, algo inĂ©dito para frutos do mar em todo o hemisfĂ©rio sul. Mais uma prova de que a Vivenda do CamarĂŁo estĂĄ compromissada com a mĂĄxima qualidade em todos os produtos que oferece. A Vivenda do CamarĂŁo recebeu pelo 10Âș ano consecutivo o Selo de ExcelĂȘncia em Franchising da ABF, o ISO 9000 das franquias. A rede tambĂ©m foi condecorada com o trofĂ©u Hors Concours na categoria Restaurante do PrĂȘmio Alshop, por ganhar trĂȘs vezes consecutivas, pelo voto do consumidor, alĂ©m de ter ficado em 2Âș lugar no prĂȘmio cedido pela PEGN no quesito Melhores Franquias do Brasil. Em 2011 recebeu o tĂ­tulo inĂ©dito de Melhor Franqueadora do Ano, entre todas as categorias, tambĂ©m cedido pela ABF. Em 2017, recebemos mais um reconhecimento, fomos vencedores no PrĂȘmio ABF + RDI Desing, na categoria Ouro, como melhor Visual Merchandising de loja. Com uma marca conhecida e apreciada em todo o paĂ­s, atualmente a rede tem mais de 150 lojas da Vivenda do CamarĂŁo nas principais cidades brasileiras, alĂ©m do Paraguai. Com uma marca conhecida e apreciada em todo o paĂ­s, atualmente a rede tem mais de 150 lojas da Vivenda do CamarĂŁo nas principais cidades brasileiras, alĂ©m do Paraguai e Portugal.', NULL, 'SĂO PAULO', 1, NULL, 158, NULL, NULL, '2026-03-09 21:15:56.721', 'https://franquias.portaldofranchising.com.br/franquia-vivenda-do-camarao-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
