INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78f100tpeh0slr2w5zj8', 'GiO EstĂ©tica AvanĂ§ada', 'gio-estetica-avancada', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'A GiO EstĂ©tica AvanĂ§ada Ă© uma franquia de depilaĂ§ĂŁo a laser, estĂ©tica facial e corporal que une alta tecnologia a baixos custos para o cliente.', 2014, 2014, '[\"https://www.youtube.com/watch?v=N8giRCchC_w\",\"https://www.youtube.com/watch?v=_hWmNxAc0ws\",\"https://www.youtube.com/watch?v=dHdmXEbFyGA\",\"https://www.youtube.com/watch?v=M-NCvmDUr2Y\"]', '2026-04-01 02:00:11.768', '2025-08-05 22:20:30.302', 1106, NULL, 1, 2007, 'SEJAÂ BEM VINDO Ă GiO EstĂ©tica AvanĂ§ada\nTudo em um sĂł lugar\nÂ  Por que estĂ©tica? Nascida do desejo de oferecer a melhor tecnologia em depilaĂ§ĂŁo a laser e estĂ©tica facial e corporal com valores indiscutivelmente acessĂ­veis, a GiO EstĂ©tica AvanĂ§ada iniciou sua trajetĂłria a partir da sociedade entre 2 esteticistas com espĂ­rito empreendedor e a estrela globalÂ Giovanna Antonelli. DesdeÂ 2013, comÂ unidades bem estruturadasÂ em diferentes cidades e estados do territĂłrio nacional, a rede de clĂ­nicas nĂŁo parou de crescer e estĂĄÂ cada vez mais presente em todo o paĂ­s, levando ainda mais bem-estar e autoestima tanto para homens quanto para mulheres com mĂĄximaÂ seguranĂ§a, conforto, eficĂĄcia e acessibilidade. Hoje, a rede de franquias de estĂ©tica e depilaĂ§ĂŁo a laser faz parte do grupo Salus ParticipaĂ§Ă”es, dona tambĂ©m da marca Sorridents e holding de saĂșde consolidada no mercado, o que qualifica ainda mais seu plano de expansĂŁo, multiplicando suas unidades de forma sĂłlida, responsĂĄvel e seletiva. Os brasileiros estĂŁo cada vez mais preocupados com a aparĂȘncia Segundo a ABF (AssociaĂ§ĂŁo Brasileira de Franchising), o setor de beleza e estĂ©tica movimentou mais de 55Â bilhĂ”es de reais no Ășltimo ano*. Â  Franquias de estĂ©tica nunca estiveram tĂŁo em alta! Mesmo em tempos de crise, o mercado de saĂșde, beleza e bem-estar figura entre as maiores ascensĂ”es do segmento de franquias, registrando um crescimento de 17,5% no ano de 2023*. *Fonte: ABF â AssociaĂ§ĂŁo Brasileira de Franchising  POR QUE GiO EstĂ©tica AvanĂ§ada? Suporte completo da implantaĂ§ĂŁo Ă  gestĂŁo diĂĄria da sua clĂ­nica Geomarketing, projeto arquitetĂŽnico, manuais de suporte jurĂ­dico, operacional, comercial, de atendimento e gestĂŁo, modelo de negĂłcio descomplicado. Tudo o que vocĂȘ precisa para se tornar referĂȘncia em sua regiĂŁo Treinamentos para sua equipe, total acesso Ă s aĂ§Ă”es promocionais da rede e consultores de campo sempre Ă  disposiĂ§ĂŁo para sugerir soluĂ§Ă”es e analisar o sucesso do seu negĂłcio.', NULL, 'SĂO PAULO', 1, NULL, 230, NULL, NULL, '2026-03-09 21:22:52.327', 'https://franquias.portaldofranchising.com.br/franquia-gio-estetica-avancada-saude-beleza-e-bem-estar/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '620000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
