INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78ga00tweh0se5o8pdko', 'CASA DE MADRINHA', 'casa-de-madrinha', NULL, 'Entretenimento e Lazer', 'Lazer Infantil e RecreaĂ§ĂŁo', 'A Casa de Madrinha tem compromisso em fazer de cada festa um evento Ășnico, realizando sonhos e proporcionando momentos inesquecĂ­veis aos seus clientes.', 2021, 2023, NULL, '2026-04-01 02:00:11.835', '2025-08-05 22:20:30.346', 1113, NULL, 1, 2017, '', NULL, 'SANTA CATARINA', 1, NULL, 3, NULL, NULL, '2026-03-09 21:26:05.580', 'https://franquias.portaldofranchising.com.br/franquia-casa-de-madrinha/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '767000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmdza78gk00txeh0sbqrgxtcf', 'LIVRARIA E PAPELARIA NOBEL', 'livraria-e-papelaria-nobel', NULL, 'Entretenimento e Lazer', 'BRINQUEDOS E LAZER', 'Livros, Papelaria, Revistas e Presentes', 1992, 1993, NULL, '2026-04-01 02:00:11.844', '2025-08-05 22:20:30.356', 1114, NULL, 1, 1943, 'A Livraria Nobel foi fundada em SĂŁo Paulo no ano de 1943 pelo imigrante italiano ClĂĄudio Milano e logo se especializou na venda e ediĂ§ĂŁo de apostilas escolares. Desde o princĂ­pio se destacou pela qualidade e profissionalismo em suas atividades. Hoje, a empresa Ă© formada pela rede de lojas e pelas editoras Nobel, Marco Zero, Studio Nobel, publicando livros sobre as mais diversas ĂĄreas do conhecimento. Trabalhando com sistemas de franquia desde 1992, a Nobel Ă© hoje a maior rede de livrarias do Brasil com mais de 100 franquias distribuĂ­das pelo paĂ­s. Franquia: Em 1992, a Nobel optou pelo sistema de Franchising para a expansĂŁo de sua rede de livrarias e papelarias, seguindo sua filosofia de contĂ­nua preocupaĂ§ĂŁo com a qualidade dos serviĂ§os prestados aos seus clientes. Essa decisĂŁo foi fruto da constataĂ§ĂŁo de que a presenĂ§a do `dono` franqueado em sua loja aumenta muito a fidelidade da clientela, a produtividade do trabalho dos funcionĂĄrios, a qualidade das compras e, como conseqĂŒĂȘncia, o volume das vendas e dos lucros. O Sistema Nobel de Franchising Ă© baseado nos trĂȘs fatores que realmente importam numa franquia: forĂ§a da marca, know-how e melhores condiĂ§Ă”es de compra em rede. A marca Nobel existe desde 1943 e estĂĄ em permanente evidĂȘncia, seja pelas dezenas de lojas em funcionamento, seja pela propaganda contĂ­nua da Editora Nobel e do rede como um todo. A rede Nobel tem hoje um volume de compras que possibilita descontos melhores junto aos fornecedores do que obteria qualquer loja isoladamente, prazos especiais de pagamento e grande variedade de livros em consignaĂ§ĂŁo - o que diminui o risco e o capital inicial necessĂĄrio para a formaĂ§ĂŁo de estoque. Tudo isso sem qualquer obrigaĂ§ĂŁo para o franqueado de compra mĂ­nima ou de cotas, atuando cada franquia como unidade livre e independente, definindo seu prĂłprio mix de produtos. Nobel Mega Store A partir de 1998, seguindo uma tendĂȘncia mundial, a Nobel comeĂ§ou a ampliar o conceito de seu negĂłcio para um modelo de entretenimento. A loja aumentou sua ĂĄrea fĂ­sica, disponibilizando uma maior variedade e quantidade de estoque, deixando de ser um local apenas para compras e passando a ser uma destinaĂ§ĂŁo importante para famĂ­lias que buscam novas opĂ§Ă”es de lazer e cultura. Assim, alĂ©m de produtos tradicionais, comeĂ§ou a vender em sua rede de lojas produtos culturais complementares aos livros tais como CDs musicais, vĂ­deos, DVDS, revistas, brinquedos educativos e produtos multimĂ­dia, agregando valor Ă s suas lojas e trazendo uma maior satisfaĂ§ĂŁo aos seus clientes. Surgiu assim o conceito da Nobel Mega Store, em que, cada loja adota o sistema de auto-serviĂ§o, onde o cliente dispĂ”e de vĂĄrios espaĂ§os temĂĄticos, tais como ĂĄrea de acesso Ă  lnternet, CafĂ© para momentos agradĂĄveis de leitura, ĂĄrea infantil com atividades educativas, ĂĄrea especial para palestras e noite de autĂłgrafos e muito mais, transformando o ato comprar em um momento de lazer, entretenimento e magia.', NULL, 'SĂO PAULO', 1, NULL, 151, NULL, NULL, '2025-08-05 15:44:50.000', 'https://franquias.portaldofranchising.com.br/franquia-livraria-e-papelaria-nobel-livrarias/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
