INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoql0001eh0sd5rh290z', 'CEOPAG', 'ceopag', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', 'Somos uma Rede de Franquias de Meios de Pagamentos (Fintech). Aplicativo, maquininha, delivery e outros.', 2019, 2019, '[\"https://www.youtube.com/watch?v=F0bzHH-_zQQ\",\"https://www.youtube.com/watch?v=D3a0g5QwT3Q\",\"https://www.youtube.com/watch?v=VpRATwiptr4\"]', '2026-04-01 02:00:11.955', '2025-08-11 01:37:23.325', 1127, NULL, 1, 2019, 'A CEOPAG, Ă© uma fintech (empresa de tecnologia e inovaĂ§ĂŁo aplicadas na soluĂ§ĂŁo de serviĂ§os financeiros), de alta tecnologia criada para revolucionar o mercado de meios de pagamento. Com foco no PMEs e MEIs,Â a CEOPAG, une quatro segmentos que mais crescem no Brasil: a Maquininha, Banco Digital, App Delivery de Tudo e Telemedicina. Presente em 23 estados, mais 250 cidades e mais de 350 franquias; a CEOPAG oferece um atendimento humanizado e presencial atravĂ©s de sua Rede de Franquias, com produtos de alta tecnologia. No modelo de negĂłcios daÂ CEOPAG, o franqueado Ă© responsĂĄvel pela prospecĂ§ĂŁo, cadastramento e o atendimento Ă s empresas que utilizarĂŁo os meios de pagamentos. Nossa ideia Ă© democratizar totalmente o modelo de pagamentos por meios eletrĂŽnicos, e com isso gerar mais oportunidades de negĂłcios para todos. O franqueado alĂ©m de entrar para um time de sucesso com baixo investimento inicial, receberĂĄ treinamento, suporte e consultoria totalmente humanizada. AÂ CeopagÂ tem 2 modalidades de Franquia, de acordo com seu perfil: Franquia Home Nacional:Â Investimento de R$19.990,00. Atua na prospecĂ§ĂŁo de clientes podendo ter somente o titular de contrato como operador da Franquia. Estimativa deÂ Lucro LĂ­quidoÂ deÂ R$5.000,00 Ă  R$7.000,00 mensalÂ a partir do 6Âș mĂȘs, com crescimento recorrente de acordo com trabalho e dedicaĂ§ĂŁo do Franqueado.Â Retorno do Investimento de 3 Ă  6 meses.\n\tÂ  Franquia FDA Nacional:Â Investimento Ă  partir de R$100.000,00. Atua como MĂĄster Franqueado Nacional, vendendo Franquias e gerando receita sobre as vendas e produtividade de todos os franqueados vinculados Ă  sua MĂĄster, alĂ©m de ganhar uma Franquia Full para operar tambĂ©m. Estimativa deÂ Lucro LĂ­quidoÂ deÂ R$20.000,00 Ă  R$25.000,00Â mensal a partir do 6Âș mĂȘs, com crescimento recorrente de acordo com trabalho e dedicaĂ§ĂŁo do FDA MĂĄster.Â Retorno do Investimento de 12 Ă  18 meses.\n\tÂ  Invista em um negĂłcio que realmente funciona. \nCom um pequeno investimento inicial, vocĂȘ tem um retorno real e formas de crescimento recorrente. \nFranquia com baixo investimento e alta lucratividade, sem a necessidade de ponto fixo e funcionĂĄrios. FaĂ§a parte dessa Franquia de sucesso! Preencha o formulĂĄrio e saiba mais sobre este modelo de negĂłcio.', NULL, 'SĂO PAULO', 1, NULL, 717, NULL, NULL, '2026-03-09 21:38:05.626', 'https://franquias.portaldofranchising.com.br/franquia-ceopag/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '21490', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
