INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mforf0003eh0s3ssetfrt', 'SKYONE', 'skyone', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Tecnologia da InformaĂ§ĂŁo', 2024, 2024, '[\"https://www.youtube.com/watch?v=TcjEwws_D_c\",\"https://www.youtube.com/watch?v=ZwZ0ZLiwvx4\"]', '2026-04-01 02:00:11.975', '2025-08-11 01:37:23.355', 1129, NULL, 1, 2013, 'Desde 2013, temos como objetivo simplificar o dia a dia e aumentar a produtividade de nossos clientes. Ao longo desse caminho, nossa missĂŁo se materializou em um ecossistema robusto e inovador. Estamos presentes em mais de 35 paĂ­ses, transformando a realidade de empresas lĂ­deres em seus segmentos. Oferecemos uma plataforma Ășnica e completa que abrange: ComputaĂ§ĂŁo em Nuvem; Dados e InteligĂȘncia Artificial; CiberseguranĂ§a; Marketplace; ServiĂ§os; Por que ser um Franqueado Skyone? Parceria sĂłlida: ConstruĂ­mos relaĂ§Ă”es baseadas em transparĂȘncia, confianĂ§a e suporte contĂ­nuo. Sucesso mĂștuo: Nossa visĂŁo de mĂ©dio e longo prazo visa o sucesso tanto da Skyone quanto de nossos franqueados. Recompensas tangĂ­veis: Oferecemos recompensas palpĂĄveis pelo desempenho e sucesso dos franqueados. Impacto no futuro: Juntos, podemos impactar o amanhĂŁ com uma plataforma Ășnica e infinitas possibilidades. Valor Ășnico: A Skyone oferece uma proposta de valor sĂłlida, criando uma jornada de parceria Ășnica e vantajosa.', NULL, 'SĂO PAULO', 1, NULL, NULL, NULL, NULL, '2026-03-09 21:45:33.953', 'https://franquias.portaldofranchising.com.br/franquia-skyone/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '15000', NULL, NULL, NULL, '40000', NULL, '10', '2', NULL, NULL, 0);
