INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosa0006eh0s5rlgsa9b', 'Casa Do Celular', 'casa-do-celular', NULL, 'Tecnologia', 'Telefonia', 'Franquia', 2009, 2025, '[\"https://www.youtube.com/watch?v=tnTJHHsk4H0\"]', '2026-04-01 02:00:12.007', '2025-08-11 01:37:23.386', 1132, NULL, 1, 2009, 'A Casa do Celular tem uma histĂłria e proposta inovadora de negĂłcio, desenhada com o objetivo de vender nĂŁo somente produtos, mas excelĂȘncia no que faz. \nA Casa do Celular, em atuaĂ§ĂŁo no mercado desde o ano de 2009, foi idealizada e fundada pelo Sr. Darlan Almeida, hoje ainda Presidente atuante na empresa. \nO inĂ­cio das atividades se deu na cidade de SantarĂ©m no estado do ParĂĄ, com um quadro de 03 funcionĂĄrios, tendo a frente seu fundador. \nCom ideias visionarias e pensamento empreendedor, a rede Casa do Celular conseguiu enxergar alĂ©m de seu tempo, apostando em um futuro promissor no meio de telecomunicaĂ§Ă”es, mais especificamente em aparelhos de telefonia celular. \nApĂłs se aprofundar no conhecimento de aparelhos e suas tecnologias, a rede Casa do Celular investiu tempo e dedicaĂ§ĂŁo na busca de conhecimento nĂŁo apenas de tecnologia, como tambĂ©m de mercado.', NULL, 'SĂŁo Paulo', 1, NULL, 170, NULL, NULL, '2026-03-09 21:57:10.563', 'https://franquias.portaldofranchising.com.br/franquia-casa-do-celular/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '150000', NULL, NULL, NULL, '30000', NULL, '3.5', '2', '120000', NULL, 3535);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosj0007eh0sy8tdgyz7', 'TEM JEITO', 'tem-jeito', NULL, 'Moda', 'VESTUĂRIO', 'Consertamos e ajustamos roupas, serviĂ§os como Barra de calĂ§a, troca de zĂ­per, ajustes em vestidos, ternos, todos os tipos de roupas, incluindo serviĂ§os tĂȘxteis para cortinas toalhas, fronhas e outros', 2020, 2025, '[\"https://www.youtube.com/watch?v=Thq3icV1fBk\",\"https://www.youtube.com/watch?v=0XbjcwHPNKc\"]', '2026-04-01 02:00:12.017', '2025-08-11 01:37:23.395', 1133, NULL, 1, 2015, 'A Tem Jeito Ă© uma franquia inovadora no setor de costura e customizaĂ§ĂŁo de roupas, fundada em 2015 em Campina Grande (PB) pelo empresĂĄrio Evandro de Macedo Filho. Ele identificou uma lacuna no mercado para ajustes rĂĄpidos e de qualidade, criando um modelo de negĂłcio que alia eficiĂȘncia e excelĂȘncia no atendimento. Em 2020, a marca ingressou no sistema de franchising, possibilitando a expansĂŁo do negĂłcio. Atualmente, a rede conta com 18 unidades, sendo 6 prĂłprias e 12 franqueadas, consolidando-se como a primeira franquia do Brasil especializada em ajustes e customizaĂ§Ă”es de roupas com um atendimento ĂĄgil e diferenciado.', NULL, 'PARAĂBA', 1, NULL, 15, NULL, NULL, '2025-10-23 12:00:29.000', 'https://franquias.portaldofranchising.com.br/franquia-tem-jeito/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfosw0008eh0szs1miplu', 'INSTITUTO DOS ĂCULOS', 'instituto-dos-oculos', NULL, 'SaĂșde, Beleza e Bem-Estar', 'ĂTICAS', 'ComĂ©rcio varejista de Ăłculos.', 2014, 2018, '[\"https://www.youtube.com/watch?v=xWbDTXBR91I\"]', '2026-04-01 02:00:12.028', '2025-08-11 01:37:23.408', 1134, NULL, 1, 2010, 'Fundada em Curitiba em 2010, a rede Instituto dos Ăculos nasceu com o objetivo de disponibilizar produtos de qualidade com preĂ§o acessĂ­vel e enfoque popular. A empresa trabalha com a venda de Ăłculos de grau, Ăłculos solares e lentes de contato. Em 2014, foi formalizado o processo de Franquias, com o propĂłsito de expandir a marca e angariar empreendedores que buscam negĂłcios lucrativos e que se preocupam com a responsabilidade social. O Instituto dos Ăculos se vĂȘ como sinĂŽnimo de acessibilidade e estilo de vida. Acessibilidade se dĂĄ pela democratizaĂ§ĂŁo de Ăłculos de qualidade a preĂ§os reduzidos. \nO estilo de vida se encontra na cultura da empresa, onde o trabalho Ă© valorizado, mas nĂŁo superestimado. A rede de franquias Instituto dos Ăculos tem uma visĂŁo integral da vida, de modo que em todas as suas operaĂ§Ă”es, Ă© levado em consideraĂ§ĂŁo as famĂ­lias e a saĂșde pessoal de seus colaboradores e parceiros. Atualmente, a empresa conta com 45 unidades franqueadas e 15 unidades da famĂ­lia fundadora, bem como um laboratĂłrio de lentes de tecnologia Freeform alemĂŁ, alĂ©m de produtos homologados e com alto controle de qualidade. Com uma marca de 13 anos de existĂȘncia e uma administraĂ§ĂŁo de 30 anos de experiĂȘncia no ramo Ăłtico, a rede estĂĄ preparada a expandir-se para todos os estados do Brasil e convida vocĂȘ a fazer parte dessa caminhada.', NULL, 'PARANĂ', 1, NULL, 56, NULL, NULL, '2026-03-09 21:59:54.988', 'https://franquias.portaldofranchising.com.br/franquia-instituto-dos-oculos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '165000', NULL, NULL, NULL, '35000', '0', '4', '3', '130000', NULL, 0);
