cro. Venha ser um franqueado de sucesso.', NULL, 'PARAĂBA', 1, NULL, 58, NULL, NULL, '2026-03-09 22:17:47.293', 'https://franquias.portaldofranchising.com.br/franquia-love-gifts/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '19900', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
