franquia + pacote de equipamentos)', NULL, 'SĂŁo Paulo', 1, NULL, 199, NULL, NULL, '2026-03-09 22:18:27.120', 'https://franquias.portaldofranchising.com.br/franquia-dryclean-lavanderia/', 'Faturamento', 'Faturamento', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '260000', NULL, NULL, NULL, '45000', '75000', '5', '2', '175000', '40000', 40);
