-03-09 22:26:48.494', 'https://franquias.portaldofranchising.com.br/franquia-cartao-be-happy-beneficios/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '8000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
