L, NULL, '2026-03-09 22:27:29.363', 'https://franquias.portaldofranchising.com.br/franquia-constance-acessorios-pessoais-e-calcados/', 'Compras', 'Compras', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '320000', NULL, NULL, NULL, '69000', '250000', '14', '3', '201000', '50000', 100);
