INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfovr000leh0spcstv0fs', 'AILINE TELEMEDICINA', 'ailine-telemedicina', NULL, 'SaĂșde, Beleza e Bem Estar', 'SERVIĂOS MĂDICOS', 'Telemedicina Clinica e Especialidades', 2023, 2024, NULL, '2026-04-01 02:00:12.163', '2025-08-11 01:37:23.511', 1147, NULL, 1, 2023, 'A Ailine Telemedicina, fundada em 2019, Ă© uma franquia com sede em SĂŁo JosĂ© do Rio Preto/SP, com mais de 500 unidades em operaĂ§ĂŁo no Brasil. Oferece soluĂ§Ă”es completas em saĂșde digital, permitindo que empresĂĄrios atuem com a marca Ailine, utilizando sua plataforma de telemedicina e corpo clĂ­nico treinado, mantendo sua prĂłpria identidade. O mercado de telemedicina estĂĄ em expansĂŁo acelerada, com uma crescente demanda por serviĂ§os digitais no Brasil e globalmente. A popularizaĂ§ĂŁo da telessaĂșde, impulsionada pela pandemia, resultou em um aumento de 8% no interesse pela modalidade em 2024. De acordo com estimativas, atĂ© 2030, metade dos atendimentos mĂ©dicos poderĂŁo ser feitos remotamente. A Ailine se destaca oferecendo nĂŁo apenas consultas mĂ©dicas 24 horas por dia, 7 dias por semana, mas tambĂ©m uma sĂ©rie de benefĂ­cios para os usuĂĄrios, como programas de saĂșde (suporte psicolĂłgico, nutriĂ§ĂŁo, combate ao tabagismo, entre outros), e um clube de descontos nas maiores marcas do mercado. Isso representa uma excelente oportunidade para empresĂĄrios que buscam entrar no setor de saĂșde digital com uma soluĂ§ĂŁo jĂĄ estruturada, confiĂĄvel e que valoriza o bem-estar do cliente.', NULL, 'SĂO PAULO', 1, NULL, 10, NULL, NULL, '2025-10-27 00:00:26.000', 'https://franquias.portaldofranchising.com.br/franquia-ailine-telemedicina/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfovx000meh0saxffed37', 'Yes!', 'yes', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', '', NULL, 2006, '[\"https://www.youtube.com/watch?v=muzJZ_P2GjU\",\"https://www.youtube.com/watch?v=cfinsJUvLdc\",\"https://www.youtube.com/watch?v=JJvfz1VdnSA\"]', '2026-04-01 02:00:12.173', '2025-08-11 01:37:23.518', 1148, NULL, 1, NULL, 'SĂŁo 53 anos de atuaĂ§ĂŁo, inovaĂ§ĂŁo e compromisso inegociĂĄvel com a qualidade fazem da YES! uma referĂȘncia absoluta no competitivo mercado de ensino de idiomas. Pelo trabalho consistente e Ă©tico desenvolvido, a marca Ă© amplamente reconhecida e sua competĂȘncia Ă© comprovada pelos diversos prĂȘmios conquistados ao longo desta trajetĂłria de sucesso. Associada Ă  ABF (AssociaĂ§ĂŁo Brasileira de Franchising) desde 2006, a YES! Ă© chancelada hĂĄ 19 anos consecutivos com o Selo de ExcelĂȘncia em Franchising, um testemunho da satisfaĂ§ĂŁo de nossa rede. No 30Âș ano da AssociaĂ§ĂŁo, em 2020, fomos pioneiros ao receber o PrĂȘmio EvoluĂ§ĂŁo da Performance, com 100% de aprovaĂ§ĂŁo dos Franqueados na Categoria Master, feito repetido em 2021. HĂĄ 14 anos ininterruptos, a YES! tambĂ©m vem sendo eleita uma das melhores franquias de idiomas do Brasil pela prestigiada revista Pequenas Empresas & Grandes NegĂłcios. Em 2023, alcanĂ§amos o auge do reconhecimento, sendo eleita a Franquia do Ano, a Melhor de todos os segmentos. Em 2024, mantivemos nossa lideranĂ§a, conquistando o tĂ­tulo de Melhor Franquia de Idiomas do Brasil, pela mesma instituiĂ§ĂŁo, e reafirmou sua excelĂȘncia com mais um Selo de ExcelĂȘncia em Franchising e, de forma pioneira, conquistou o selo adicional ESG, refletindo nosso compromisso com prĂĄticas de governanĂ§a e sustentabilidade. 2025 foi o ano de perpetuarmos nossa posiĂ§ĂŁo, nos mantendo entre as melhores Escolas do Brasil. A rede Ă© constituĂ­da por escolas financeiramente fortes, bem conceituadas, rentĂĄveis e que crescem a cada dia. Pautamos nossa atuaĂ§ĂŁo na Ă©tica inegociĂĄvel, no profissionalismo e na parceria transparente, o que garante franqueados satisfeitos e em busca contĂ­nua de uma posiĂ§ĂŁo de lideranĂ§a no paĂ­s. O novo franqueado recebe consultoria 360Âș, desde o inĂ­cio da implantaĂ§ĂŁo da escola atĂ© a contrataĂ§ĂŁo da equipe. Este suporte vitalĂ­cio se mantĂ©m durante toda a operaĂ§ĂŁo, assegurando que o franqueado jamais esteja sozinho em sua jornada de sucesso. . \"Junte-se a nĂłs e faĂ§a parte desta histĂłria de sucesso de mais de 50 anos em ensino de idiomas! Na nossa rede de franquias, nĂŁo apenas prometemos resultados. Nos comprometemos ativamente em proporcionar capacitaĂ§ĂŁo contĂ­nua, impulsionando a performance e a rentabilidade dos nossos alunos e franqueados. Estamos dedicados a investir no crescimento e no sucesso de cada franqueado, capacitando-o para alcanĂ§ar novos patamares de excelĂȘncia e prosperidade. Aqui a tradiĂ§ĂŁo de meio sĂ©culo se une Ă  inovaĂ§ĂŁo para criar experiĂȘncias de aprendizado e investimento incomparĂĄveis.\" (Clodoaldo Nascimento â CEO e Presidente da YES! Idiomas)', NULL, 'Rio de Janeiro', NULL, NULL, 119, NULL, NULL, '2026-03-09 22:43:31.980', 'https://franquias.portaldofranchising.com.br/franquia-yes-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '150000', NULL, NULL, NULL, '20000', '68000', '0', '0', '90000', '40000', 100);
