INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfowk000peh0sa3t6p4x9', 'SPACECLASS', 'spaceclass', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Franquia Especializada em Treinamentos de Idiomas', 2024, 2025, '[\"https://www.youtube.com/watch?v=i9kdbs77ySQ\",\"https://www.youtube.com/watch?v=r29f8MjSjrk\",\"https://www.youtube.com/watch?v=H67WKO1GxmI\"]', '2026-04-01 02:00:12.199', '2025-08-11 01:37:23.540', 1151, NULL, 1, 2022, 'A Spaceclass Ă© uma rede de franquias de ensino de idiomas que vem ressignificando o mercado de educaĂ§ĂŁo de idiomas no Brasil e no mundo. Fundada em 2020, a empresa oferece um modelo de negĂłcio digital e inovador, com aulas 100% online e ao vivo, baseadas em neurociĂȘncia e focadas na conversaĂ§ĂŁo desde a primeira aula. A metodologia elimina a gramĂĄtica tradicional e personaliza o ensino de acordo com os objetivos profissionais dos alunos. A Spaceclass disponibiliza dois modelos de franquia: Executivo de Vendas, ideal para empreendedores com perfil comercial e Executivo de Ensino, voltado para professores ou profissionais bilĂ­ngues que desejam dar aulas. Ambos os modelos oferecem baixo investimento inicial, retorno rĂĄpido (entre 3 e 4 meses) e suporte completo, incluindo treinamento comercial, pedagĂłgico e estratĂ©gico. AlĂ©m disso, os franqueados contam com uma plataforma tecnolĂłgica avanĂ§ada para gerenciar vendas, aulas, recursos didĂĄticos e pagamentos. O mercado de educaĂ§ĂŁo digital e ensino de idiomas estĂĄ em constante crescimento, impulsionado pela demanda por flexibilidade e aprendizado personalizado. A Spaceclass se destaca nesse cenĂĄrio por oferecer uma soluĂ§ĂŁo escalĂĄvel, sem necessidade de estrutura fĂ­sica, permitindo que os franqueados atuem de qualquer lugar do mundo. Com uma abordagem centrada no aluno e foco em resultados reais, a franquia representa uma oportunidade sĂłlida para quem busca empreender com propĂłsito e impacto positivo na vida das pessoas.', NULL, 'SĂO PAULO', 1, NULL, 9, NULL, NULL, '2026-03-09 23:09:17.397', 'https://franquias.portaldofranchising.com.br/franquia-spaceclass/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '5000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfowq000qeh0sh19bqhhx', 'KNN IDIOMAS', 'knn-idiomas', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Rede de idiomas cujo modelo de negĂłcio foi desenvolvido para ser Ășnico, oferecendo ao franqueado oportunidades de crescimento que vĂŁo alĂ©m daquelas encontradas no mercado de idiomas brasileiro.', 2013, 2018, '[\"https://www.youtube.com/watch?v=b8BFbEnAuI4\",\"https://www.youtube.com/watch?v=yDy9Vfg0V4E\",\"https://www.youtube.com/watch?v=Hkk5DlnMj3k\",\"https://www.youtube.com/watch?v=LxNFCtaPtYg\"]', '2026-04-01 02:00:12.209', '2025-08-11 01:37:23.546', 1152, NULL, 1, 2004, 'A KNN Ă© uma empresa jovem, mas isso nĂŁo quer dizer que comeĂ§amos ontem. Nossa histĂłria teve inĂ­cio em 2004, quando partimos de um Ășnico sonho: oferecer ensino de qualidade, de forma rĂĄpida e prĂĄtica e principalmente, respeitando as individualidades de cada aluno. Foi assim que o empresĂĄrio Reginaldo Boeira criou um mĂ©todo inovador e exclusivo, que respeita o modo como nĂłs â falantes da lĂ­ngua portuguesa â assimilamos um novo idioma.Â  Desde 2014, a KNN opera como franquia e hoje Ă© reconhecida como uma das maiores escolas de idiomas da AmĂ©rica Latina. O DIFERENCIAL Em um mercado extremamente competitivo, ser apenas bom nĂŁo Ă© o suficiente. Ă preciso ser diferente e ousado. NinguĂ©m entra num mercado consolidado como este, lotado de marcas que estĂŁo operando hĂĄ dĂ©cadas e ganha dinheiro fazendo o mesmo que elas, nĂŁo Ă© mesmo? Aqui na KNN, o faturamento Ă© todo seu! Isso quer dizer que somos uma franquia que nĂŁo cobra royalties. AlĂ©m disso, quem decide investir em nossa marca, tem apoio incondicional sempre que precisar da maior e melhor equipe de especialistas do ramo. O nosso suporte vitalĂ­cio em todas ĂĄreas da escola faz com que os franqueados nĂŁo se sintam sozinhos no mundo dos negĂłcios. A gente te guia no caminho para o sucesso.Â  PILARES DE SUCESSOÂ  MATRĂCULAS O ANO INTEIRO:Â  A estrutura comercial da KNN Ă© Ășnica e foi criada para quebrar a sazonalidade caracterĂ­stica do mercado de ensino de idiomas, gerando matrĂ­culas o ano todo. O modelo de negĂłcios foi desenvolvido para gerar uma mĂ©dia de 40 a 60 matrĂ­culas por mĂȘs durante todos os meses do ano.Â  Este sistema comercial super ativo permite que os franqueados atinjam seu ponto de equilĂ­brio financeiro em menos de 6 meses.Â  SUCESSO NA MANUTENĂĂO DE ALUNOS:Â  Sim, nĂłs temos uma equipe cuja funĂ§ĂŁo principal Ă© capacitar nossa rede de franqueados para nĂŁo perderem seus clientes. Fazer matrĂ­culas Ă© realmente muito importante, mas saber manter seus alunos Ă© crucial para a saĂșde financeira da sua escola e nĂłs sabemos muito bem disso. A KNN possui um sistema prĂłprio de retenĂ§ĂŁo, o qual proporciona uma permanĂȘncia de seus alunos de aproximadamente 36 meses â simplesmente a maior mĂ©dia do segmento no Brasil.Â  CONTROLE DE INADIMPLĂNCIAÂ  NĂŁo conhecer as ferramentas para reduzir a inadimplĂȘncia pode ser extremamente perigoso para a sua empresa. Em um negĂłcio que lida com pagamentos recorrentes, isso Ă© ainda mais delicado, pois Ă© necessĂĄrio que a organizaĂ§ĂŁo seja hĂĄbil o suficiente para lidar com esta questĂŁo sem perder seus alunos. PossuĂ­mos uma equipe especializada neste assunto, que estarĂĄ pronta para ajudĂĄ-lo a manter as taxas de inadimplĂȘncia em nĂ­veis seguros, entre 6 a 8 % ao mĂȘs.Â Â  INVESTIMENTOS E EXPANSĂO A rede possui modelos de negĂłcios para qualquer tipo de cidade e fornece consultoria em todas as ĂĄreas da empresa. Com unidades sendo abertas de norte a sul do paĂ­s, em breve a franquia irĂĄ inaugurar tambĂ©m suas unidades na AmĂ©rica Latina. Diversos diferenciais competitivos fizeram a marca se tornar atualmente um dos grandes players do mercado do segmento. Como exemplo, destacamos o transporte gratuito oferecido para alunos de atĂ© 14 anos, material didĂĄtico atualizado anualmente, mascotes originais, game exclusivo para smartphones e a parceria com o Rock in Rio Brasil 2022, sendo a escola de idiomas oficial do maior festival de mĂșsica e entretenimento do mundo.Â  De acordo com o setor de expansĂŁo da franchising, a estimativa Ă© fechar o ano de 2022 com mais de 900 escolas negociadas em todo paĂ­s, caminhando rumo Ă  lideranĂ§a no segmento. A empresa projeta se tornar a nĂșmero 1 entre as franquias de idiomas em 2023. AlĂ©m disso, novos projetos e campanhas tambĂ©m sendo criadas constantemente dentro da rede KNN, possibilitando diversas oportunidades de negĂłcio para seus franqueados. Â  SOBRE REGINALDO BOEIRA, CEO E FUNDADOR DA KNN.Â  EmpresĂĄrio nascido no interior de Minas Gerais, sua trajetĂłria no mundo dos negĂłcios comeĂ§ou cedo, aos 13 anos, por necessidade de ajudar sua famĂ­lia em meio Ă s dificuldades financeiras que enfrentavam.Â  A paixĂŁo pela lĂ­ngua inglesa surgiu ainda na infĂąncia, e a vontade de ter sua prĂłpria metodologia foi desenvolvida com o passar do tempo.Â  Ă autor do livro âQuando o Sucesso Ă© Ănica OpĂ§ĂŁoâ, em que dĂĄ dicas de gestĂŁo e lideranĂ§a atravĂ©s de suas experiĂȘncias de vida.', NULL, 'SANTA CATARINA', 1, NULL, 464, NULL, NULL, '2026-03-09 23:10:15.815', 'https://franquias.portaldofranchising.com.br/franquia-knn-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '80000', NULL, NULL, NULL, '22000', NULL, '0', '7', '28000', '30000', 0);
