INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfoz50014eh0s5tn6qavg', 'LEBRIJU', 'lebriju', NULL, 'Moda', 'ACESSĂRIOS PESSOAIS', 'Venda de bijuterias, semi joias e acessĂłrios de moda femininos', 2021, 2021, '[\"https://www.youtube.com/watch?v=OnJ0u9TI2Fk\"]', '2026-04-01 02:00:12.353', '2025-08-11 01:37:23.633', 1166, NULL, 1, 2016, 'Somos a mais completa rede de franquias de acessĂłrios, voltada para o pĂșblico feminino, com peĂ§as como: bijuterias, semijoiais, prata, lenĂ§os, bolsa, chapĂ©u, prata, aĂ§o inoxidĂĄvel, que unem design, elegĂąncia, qualidade. NegĂłcio escalĂĄvel. Fature mais de 1 milhĂŁo por ano! Todo mundo compra acessĂłrios de moda! DIFERENCIAIS DA LEBRIJU: PRODUTO E QUALIDADE: Os produtos Lebriju sĂŁo cuidadosamente escolhidos pelo nosso setor de CURADORIA E TENDĂNCIA DE MODA um amplo portifĂłlio, com qualidade e variedade que surpreende, agrada e fideliza nossos clientes. Nosso objetivo Ă© de promover o sucesso da marca e de nossas unidades franqueadas. FACILIDADE DE ABASTECIMENTO: A Lebriju adota uma estratĂ©gia de abastecimento semanal para suas unidades em todo o Brasil, com cerca de 200 novos modelos lanĂ§ados todo mĂȘs, garantindo que as clientes encontrem novidades nas lojas toda semana. ARQUITETURA: A arquitetura de nossas lojas e quiosques, alĂ©m de muito bonita Ă© fundada no bem-estar, acolhimento, modernidade e, acima de tudo, funcionalidade. A cliente tem uma experiĂȘncia de compra positiva, dentro de um ambiente lindo, acolhedor e fluido. MODELOS DE NEGĂCIOS LEBRIJU: Com investimento completo a partir de R$ 170 mil que incluĂ­: mobiliĂĄrio, estoque inicial, projeto arquitetĂŽnico e taxa de franquia, vocĂȘ pode ter um quiosque no Shopping da sua cidade. Ou, com investimento a partir de R$ 390 mil, uma loja em Shopping Center com mix completo e excelente rentabilidade. Fature mais de 1 milhĂŁo ao ano!', NULL, 'SĂO PAULO', 1, NULL, 7, NULL, NULL, '2026-02-04 10:17:23.000', 'https://franquias.portaldofranchising.com.br/franquia-lebriju-moda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '170000', NULL, NULL, NULL, '50000', '0', '4', '2', '280000', '60000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfozb0015eh0s4gmb8f8b', 'VIA CERTA EDUCAĂAO PROFISSIONAL', 'via-certa-educacao-profissional', NULL, 'EducaĂ§ĂŁo', 'Ensino e FormaĂ§ĂŁo AcadĂȘmica', 'Escola de Cursos Profissionalizantes e Idiomas.', 2014, 2019, '[\"https://www.youtube.com/watch?v=H6CdCLKdmCM\",\"https://www.youtube.com/watch?v=bvSvz_mktzU\",\"https://www.youtube.com/watch?v=PjYgrN9FfWQ\",\"https://www.youtube.com/watch?v=UKIjJfnWDVI\"]', '2026-04-01 02:00:12.363', '2025-08-11 01:37:23.639', 1167, NULL, 1, 2012, 'AtravĂ©s da uniĂŁo de trĂȘs sĂłcios, com mais de 20 anos de experiĂȘncia no ramo de educaĂ§ĂŁo profissionalizante, em maio de 2012 nascia, em Birigui /SP, a rede de ensino profissionalizante Via Certa. A partir de uma Ășnica escola, a Via Certa surgiu com o objetivo de levar conhecimento para todas as pessoas que buscam crescer profissionalmente e atualizar seus conhecimentos. O sucesso do mĂ©todo Via Certa gerou um avanĂ§o vertiginoso, ampliando a escola para uma rede de franquias presente em diversas cidades do Brasil, oferecendo mais de 30 opĂ§Ă”es de cursos nas ĂĄreas de AdministraĂ§ĂŁo e NegĂłcios, IndĂșstria e Energia, InformĂĄtica, InglĂȘs, PreparatĂłrio, SaĂșde, Beleza e EstĂ©tica. Com uma metodologia totalmente diferenciada, a Via Certa conta com cursos que acompanham as caracterĂ­sticas particulares de cada aluno, preparando-o para aproveitar totalmente o seu aprendizado atravĂ©s de um ensino individualizado, no ritmo de cada aluno, trazendo assim uma aprovaĂ§ĂŁo de 95% dos alunos. Atualmente, metade das vagas disponĂ­veis no mercado de trabalho nĂŁo sĂŁo preenchidas, pois os candidatos nĂŁo possuem os prĂ©-requisitos mĂ­nimos necessĂĄrios exigidos pelas empresas. Os cursos da Via Certa entram para suprir esses prĂ©-requisitos exigidos pelo mercado de trabalho, tornando os alunos aptos a ingressarem em um novo emprego ou ainda na promoĂ§ĂŁo de sua carreira. Desenvolvida no modelo de franquia, a Via Certa EducaĂ§ĂŁo Profissional representa uma excelente oportunidade para aqueles que querem investir em um novo negĂłcio na ĂĄrea da EducaĂ§ĂŁo Profissionalizante. Oferecemos ao empreendedor todo o apoio necessĂĄrio para seu desenvolvimento, como suporte no setor de recursos humanos, comercial, financeiro e Marketing. O Grupo Via Certa investe constantemente na formaĂ§ĂŁo de seus franqueados, professores e demais colaboradores, por meio de treinamentos especĂ­ficos, para que eles possam entregar o que hĂĄ de melhor ao aluno, garantindo seu sucesso no mercado de trabalho.', NULL, 'SĂO PAULO', 1, NULL, 61, NULL, NULL, '2026-03-10 00:12:36.224', 'https://franquias.portaldofranchising.com.br/franquia-via-certa-educacao-profissional/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '120000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
