INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp05001aeh0shc0mzpbn', 'Guia-se', 'guia-se', NULL, 'ServiĂ§os e Outros NegĂłcios', 'Consultorias e ServiĂ§os Empresariais', 'Comercio varejista', 2009, 2013, '[\"https://www.youtube.com/watch?v=heYe66W8TRI\",\"https://www.youtube.com/watch?v=60eIXwaBzb8\",\"https://www.youtube.com/watch?v=J6tOpM2qizU\",\"https://www.youtube.com/watch?v=5RSStcqAwGo\",\"https://www.youtube.com/watch?v=W7GytGSh42Q\"]', '2026-04-01 02:00:12.409', '2025-08-11 01:37:23.670', 1172, NULL, 1, 1997, 'Com 29 anos de experiĂȘncia e 16 anos como rede de franquias, a Guia-se Ă© referĂȘncia no franchising brasileiro.', NULL, NULL, 1, NULL, 97, NULL, NULL, '2026-03-10 00:34:00.707', 'https://franquias.portaldofranchising.com.br/franquia-guiase-marketing-digital/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0b001beh0s0tzggbnr', 'DEKRA', 'dekra', NULL, 'ServiĂ§os Automotivos', 'LocaĂ§ĂŁo de veĂ­culos', 'VISTORIAS PARA SEGURO, VISTORIA CAUTELAR DE AVALIAĂĂO E TRANSFERĂNCIA EM AUTOS', 1996, 1998, '[\"https://www.youtube.com/watch?v=DtZ3HI0LNFM\"]', '2026-04-01 02:00:12.418', '2025-08-11 01:37:23.676', 1173, NULL, 1, 1986, 'Torne-se um Franqueado DEKRA e Invista em um NegĂłcio SĂłlido e Lucrativo! Construir um negĂłcio prĂłprio Ă© mais do que empreender. Ă transformar sonhos em realidade, ter um propĂłsito profissional e fazer parte de algo maior. A DEKRA, multinacional alemĂŁ com 100 anos de histĂłria, Ă© lĂ­der global em vistorias veiculares e referĂȘncia no setor. Como a primeira e maior rede de franquias do segmento no Brasil, acumulamos mais de 25 anos de experiĂȘncia no franchising, oferecendo um modelo de negĂłcio sĂłlido, estruturado e consolidado. Nosso propĂłsito vai alĂ©m dos negĂłcios. Nossa visĂŁo Ă© clara: ser o parceiro global para um mundo mais seguro e sustentĂĄvel. Como franqueado DEKRA, vocĂȘ se une a uma marca que valoriza inovaĂ§ĂŁo, excelĂȘncia e credibilidade, entregando um serviĂ§o essencial para milhĂ”es de pessoas e contribuindo para a seguranĂ§a no mercado automotivo. Se vocĂȘ busca um negĂłcio estruturado, um mercado em crescimento e o suporte de uma marca reconhecida mundialmente, esta Ă© a sua oportunidade. Acima de 80 unidades e mais de 200 postos credenciados no Brasil Marca global presente em 60 paĂ­ses Retorno do investimento em mĂ©dia de 24 a 26 meses Taxa de Franquia a partir de R$ 65.000 Agora Ă© sua chance de fazer parte dessa histĂłria de sucesso!  Â  Modelos de NegĂłcio FlexĂ­veis para Diferentes Mercados Sabemos que cada regiĂŁo tem suas particularidades. Por isso, a DEKRA oferece modelos de franquia flexĂ­veis, adaptĂĄveis a diferentes demandas e perfis de mercado: Mercado P â Ideal para cidades menores, com menor fluxo de vistorias. Mercado M â Perfeito para regiĂ”es de mĂ©dio porte, com demanda crescente. Mercado G â Modelo robusto, para grandes cidades e alto volume de vistorias. Independente do porte da sua cidade, a DEKRA tem um modelo ideal para vocĂȘ! Â  Um NegĂłcio Seguro e RentĂĄvel O setor de vistorias veiculares estĂĄ em plena expansĂŁo. Com o aumento da venda de veĂ­culos seminovos e usados, cresce tambĂ©m a necessidade de laudos confiĂĄveis e empresas de referĂȘncia no mercado. A DEKRA se destaca por oferecer um modelo estruturado, processos padronizados e a credibilidade de uma multinacional. Como franqueado, vocĂȘ terĂĄ um negĂłcio consolidado, escalĂĄvel e lucrativo, em um setor que zela pela qualidade dos serviĂ§os. Invista em um negĂłcio de alto valor agregado e crescimento contĂ­nuo! Â  Modelo de NegĂłcio Estruturado Sabemos que previsibilidade e seguranĂ§a financeira sĂŁo essenciais ao investir em um novo negĂłcio. Por isso, oferecemos um modelo de franquia transparente e acessĂ­vel: Taxa de Franquia: A partir de R$ 65.000 Taxa de Royalties: variĂĄvel conforme o volume de produĂ§ĂŁo, pensamos no desenvolvimento de nossos franqueados Taxa de Publicidade: NĂŁo hĂĄ Capital de Giro: VariĂĄvel, conforme operaĂ§ĂŁo e regiĂŁo Retorno do Investimento: Em mĂ©dia, 24 a 26 meses Ărea MĂ©dia da Unidade: 375 mÂČ Com um modelo de operaĂ§ĂŁo simplificado e suporte completo, vocĂȘ terĂĄ todo o respaldo necessĂĄrio para crescer.', NULL, 'SĂO PAULO', 1, NULL, 81, NULL, NULL, '2026-03-10 00:41:45.576', 'https://franquias.portaldofranchising.com.br/franquia-dekra/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '135000', NULL, NULL, NULL, '65000', NULL, '9', '0', '70000', NULL, 0);
