ia-rede-cartorio-facil/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp0o001deh0s39dkzyrs', 'Fini', 'fini', NULL, 'Alimentos', 'Doces', 'Comercio varejista', 2020, 2020, NULL, '2026-04-01 02:00:12.437', '2025-08-11 01:37:23.688', 1175, NULL, 1, 1970, 'De origem espanhola, desde a dĂ©cada de 70 a Fini faz parte do Grupo SĂĄnchez Cano. \nCom presenĂ§a mundial em mais de cem paĂ­ses, a empresa conquistou a posiĂ§ĂŁo de uma das principais produtoras mundiais de balas de gelatina, marshmallows, regalizes e chicles. \nNo Brasil, a Fini lanĂ§ou a Linha Bem-Estar, balas enriquecidas com ativos funcionais como cĂĄlcio, colĂĄgeno, fibras e vitaminas. \nCom um DNA que busca surpreender seus consumidores, teve origem artesanal e hoje estĂĄ presente no varejo, em franquias, e-commerce, cinemas e parques de todo o PaĂ­s.', NULL, NULL, 1, NULL, 420, NULL, NULL, '2026-03-10 00:43:22.734', 'https://franquias.portaldofranchising.com.br/franquia-fini-doces/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
