INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp14001feh0swydlfb9f', 'KOOKABU', 'kookabu', NULL, 'Moda', 'VestuĂĄrios', 'A Kookabu Ă© uma rede de moda bebĂȘ e infantil do grupo Brascol, que oferece aos seus franqueados um modelo de negĂłcio no qual ele contarĂĄ com toda estrutura e irĂĄ operar com mais de 1,5 milhĂŁo de peĂ§as', 2022, 2022, '[\"https://www.youtube.com/watch?v=t5KF3FOJrd8\",\"https://www.youtube.com/watch?v=4q68ZBJ100U\"]', '2026-04-01 02:00:12.456', '2025-08-11 01:37:23.704', 1177, NULL, 1, 2021, 'Na Kookabu, nosso propĂłsito Ă© vestir a infĂąncia com amor e qualidade, de forma democrĂĄtica.Â  Com custo-benefĂ­cio e uma ampla variedade de opĂ§Ă”es, a Kookabu, torna a moda infantil acessĂ­vel a todas as famĂ­lias. Nossa missĂŁo Ă© ser a escolha confiĂĄvel para mamĂŁes e papais que buscam roupas durĂĄveis, cheias de personalidade e que nĂŁo pesem no orĂ§amento. Acreditamos que toda crianĂ§a merece se sentir especial, e estamos aqui para fazer isso acontecer! A marca foi desenvolvida pelo Grupo Brascol, que conta com mais de 35 anos de experiĂȘncia, sendo o maior distribuidor do segmento bebĂȘ e infantojuvenil do Brasil. Tenha Ă  disposiĂ§ĂŁo as melhores indĂșstrias do Brasil e amplie a variedade de opĂ§Ă”es para compor o mix ideal para a sua loja. Componha seu mix de produto de forma mais aderente Ă s peculiaridades da sua regiĂŁo, considerando costumes, clima, e poder aquisitivo. Tenha Ă  sua disposiĂ§ĂŁo todo o estoque do Brascol e reponha produtos de forma prĂĄtica e ĂĄgil, minimizando significativamente os riscos que o franqueado assumiria em um modelo de franquia tradicional.Â  Ganhe mais assertividade nas compras: menor Ă­ndice de liquidaĂ§ĂŁo, com um melhor resultado.', NULL, 'SĂO PAULO', 1, NULL, 8, NULL, NULL, '2026-03-10 00:51:53.374', 'https://franquias.portaldofranchising.com.br/franquia-kookabu/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '199990', NULL, NULL, NULL, '50000', NULL, '0', '0', '85000', '64990', 0);
