INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp2i001leh0sbm0xit5j', 'PLENA FACE', 'plena-face', NULL, 'SaĂșde, Beleza e Bem-Estar', 'CosmĂ©ticos e Perfumarias', 'A Plena Face Ă© uma rede de franquias especializada em EstĂ©tica Facial, focada na democratizaĂ§ĂŁo da beleza, com uma equipe de profissionais altamente qualificados, especializados em HarmonizaĂ§ĂŁo.', 2022, 2022, '[\"https://www.youtube.com/watch?v=WE6t5KKEaag\",\"https://www.youtube.com/watch?v=vLn-us4y7Ho\",\"https://www.youtube.com/watch?v=DWUlg2kBvak\",\"https://www.youtube.com/watch?v=JJihhLCmYD8\"]', '2026-04-01 02:00:12.516', '2025-08-11 01:37:23.754', 1183, NULL, 1, 2019, 'A Plena Face foi lanĂ§ada em 2021 com o intuito de valorizar a beleza natural de cada indivĂ­duo atravĂ©s de tĂ©cnicas de harmonizaĂ§ĂŁo facial e corporal. NĂŁo somos apenas \"mais uma\" rede de harmonizaĂ§ĂŁo. Nosso foco Ă© realĂ§ar a naturalidade e as marcas que a experiĂȘncia de vida traz para cada pessoa. NOSSA HISTĂRIA A Plena Face nasceu do sonho de Thais, que sempre foi apaixonada pelo mercado de beleza desde que entrou para este mercado, quando comeĂ§ou como trainee na Natura em 2004. Acreditamos na valorizaĂ§ĂŁo do âeuâ de cada indivĂ­duo e sabemos da importĂąncia do respeito Ă s suas raĂ­zes, opiniĂ”es, individualidades e traĂ§os. Em 2010, decidida a empreender no ramo da beleza, Thais deixou seu emprego e, junto com seu sĂłcio VinĂ­cius, iniciou a master franquia na ĂĄrea de depilaĂ§ĂŁo. A combinaĂ§ĂŁo de suas experiĂȘncias em franquias e no ramo da estĂ©tica resultou na criaĂ§ĂŁo da Plena Face. Nossa clĂ­nica traz um ambiente aconchegante e inclusivo, sem a ostentaĂ§ĂŁo comum em muitas clĂ­nicas, para que pessoas de todas as classes sociais, gĂȘneros e etnias se sintam representadas, especialmente a idade mais madura, conhecida como idade prateada. Nosso maior desejo Ă© compartilhar esse conhecimento de 20 anos de histĂłria e pioneirismo com o mundo e transformar a vida de empreendedoras e empreendedores que sonham em ter seu prĂłprio negĂłcio. Cada detalhe do nosso ambiente foi pensado para despertar os 5 sentidos dos clientes, proporcionando uma experiĂȘncia completa com sons, aromas e produtos exclusivos. A Plena Face oferece um mix de serviĂ§os completo, aliado Ă s tecnologias mais inovadoras do mercado. SĂŁo mais de 20 tipos de procedimentos estĂ©ticos minimamente invasivos a preĂ§os acessĂ­veis, com condiĂ§Ă”es de pagamento facilitadas, incluindo toxina botulĂ­nica, bioestimuladores e preenchedores. AlĂ©m disso, agregamos equipamentos inovadores como Lavieen e Ultraformer III. Estamos em constante busca das inovaĂ§Ă”es e tendĂȘncias do mercado. Trabalhamos com os melhores fornecedores homologados, nacionais e internacionais, garantindo a qualidade e rastreabilidade de todos os produtos aplicados em nossos clientes. Essa abordagem, aliada ao poder de negociaĂ§ĂŁo com fornecedores, resulta em preĂ§os competitivos para os clientes e margens atrativas para os franqueados. O modelo de negĂłcio da Plena Face Ă© robusto e rentĂĄvel, com baixo custo operacional e uma ampla variedade de procedimentos. Nossa equipe especializada oferece suporte integral aos franqueados, desde o atendimento e vendas atĂ© a gestĂŁo de pessoas e redes sociais.', NULL, 'SĂO PAULO', 1, NULL, 5, NULL, NULL, '2026-03-10 01:21:25.153', 'https://franquias.portaldofranchising.com.br/franquia-plena-face/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
