INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp37001peh0s7dqyi8lt', 'Milky Moo Milkshakes', 'milky-moo-milkshakes', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'Comercio varejista', 2021, 2025, '[\"https://www.youtube.com/watch?v=y0Lw6yNeZ2I\"]', '2026-04-01 02:00:12.554', '2025-08-11 01:37:23.779', 1187, NULL, 1, 2019, 'A Milky Moo Ă© uma marca goiana de milkshakes criada em 2019 por trĂȘs amigos que tinham um sonho em comum: fazer o melhor milkshake do muuundo!Â  \nA primeira loja foi inaugurada em GoiĂąnia (GO) em marĂ§o de 2020 em meio a pandemia, e logo virou um sucesso! \nAs primeiras unidades franqueadas foram inauguradas no primeiro semestre de 2021 e neste mesmo ano, jĂĄ totalizava 23 lojas e quiosques abertos em vĂĄrias regiĂ”es do paĂ­s. \nSĂŁo mais de 30 sabores elaborados com produtos de qualidade e reconhecidos nacionalmente, como: Leite Ninho, Nutella, PaĂ§oquita, Ovomaltine, bombom Ferrero Rocher, Rafaello ou Ouro Branco e muuuito mais, alĂ©m das novidades alcoĂłlicas com cachaĂ§a Seleta, gin Beefeater, Amarulla e Jack Danielâs Honey. \nQuem visita as lojas e quiosques encontra um ambiente super instagramĂĄvel com decoraĂ§ĂŁo em homenagem a mascote Moo, uma vaquinha milkshake influencer e nosso famooso copo malhadinho, sensaĂ§ĂŁo nas redes sociais. AlĂ©m de mimoos como as nossas almofadas, pelĂșcia, copos, baldes para pipoca, caneca e chaveiro, para presentar e colecionar. \nAtualmente, a franquia do melhor milkshake do muuundo possui 75 unidades em 20 estados mais o Distrito Federal e estĂŁo previstas em mĂ©dia as inauguraĂ§Ă”es de mais 30 unidades ainda em 2022.', NULL, 'GoiĂĄs', 1, NULL, 652, NULL, NULL, '2026-03-10 01:38:57.999', 'https://franquias.portaldofranchising.com.br/franquia-milky-moo-milkshakes/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '360000', NULL, NULL, NULL, '70000', '100000', '5', '3', '290000', NULL, 20);
