INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp3j001reh0sz7uxomeo', 'PremiapĂŁo', 'premiapao', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', '', NULL, 2020, '[\"https://www.youtube.com/watch?v=Ns-4EKx83go\",\"https://www.youtube.com/watch?v=SvxXVEjy9ac\",\"https://www.youtube.com/watch?v=KCAN8eyNak0\",\"https://www.youtube.com/watch?v=xcZr694FiRE\",\"https://www.youtube.com/watch?v=XmbHe07Q5MI\"]', '2026-04-01 02:00:12.574', '2025-08-11 01:37:23.792', 1189, NULL, 1, NULL, 'A PremiaPĂŁo Ă© uma Empresa especializada na comercializaĂ§ĂŁo de Publicidade em Sacos de PĂŁo, divulgando marcas e produtos diretamente ao pĂșblico-alvo; sem desperdĂ­cios, de forma inovadora e impactante, porĂ©m, com diferenciais que revolucionaram o mercado e tem levado os franqueados PremiaPĂŁo ao sucesso.', NULL, NULL, NULL, NULL, 67, NULL, NULL, '2026-03-10 01:48:39.128', 'https://franquias.portaldofranchising.com.br/franquia-premiapao-publicidade-e-propaganda/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp3p001seh0sakp8oha8', 'OAK\'S BURRITOS Y BOWLS', 'oak-s-burritos-y-bowls', NULL, 'AlimentaĂ§ĂŁo', 'Bares e Restaurantes', 'O Oak\'s Ă© um restaurante rĂĄpido de burritos y bowls. Nossa culinĂĄria Ă© inspirada no mĂ©xico e feita pro Brasil: com receitas que encaixam tranquilo na tua mĂŁo e na tua fome, a hora que for.', 2022, 2023, '[\"https://www.youtube.com/watch?v=wixckHoxO0c\",\"https://www.youtube.com/watch?v=Am6xNiJ66oY\",\"https://www.youtube.com/watch?v=HHvLVZi3kO8\"]', '2026-04-01 02:00:12.583', '2025-08-11 01:37:23.798', 1190, NULL, 1, 2010, 'Os burritos sĂŁo um dos alimentos mais consumidos nos Estados Unidos, superando atĂ© os hambĂșrgueres e as pizzas. Percebendo essa tendĂȘncia em uma viagem Ă  CalifĂłrnia, os universitĂĄrios de 21 anos, Rafael e FabrĂ­cio, trouxeram essa ideia para o Brasil. Em setembro de 2010, apĂłs muita dedicaĂ§ĂŁo e planejamento, fundaram o Oakâs em Porto Alegre, a primeira marca especializada em burritos do paĂ­s. Em 2015, foram selecionados para o grupo âEndeavor Promessasâ, que conecta lĂ­deres de pequenas empresas a grandes referĂȘncias do mercado. Essa experiĂȘncia impulsionou os planos de expansĂŁo do Oakâs pelo Brasil. A marca deu outro grande passo em 2019 ao captar recursos por meio de financiamento coletivo e venda de uma pequena participaĂ§ĂŁo da empresa para investidores externos. Essa captaĂ§ĂŁo trouxe recursos financeiros e profissionalizou nossa governanĂ§a. A partir disso, passamos a contar com um conselho consultivo. O Oakâs iniciou a expansĂŁo com lojas prĂłprias, expandindo para fora do RS e testando a execuĂ§ĂŁo dos processos e gestĂŁo de estoque em lojas em diferentes estados. ApĂłs testar e aprimorar os processos, deu inĂ­cio Ă  expansĂŁo por franquias em 2022. Hoje o Oakâs atua com um modelo de negĂłcio enxuto, fĂĄcil de operar e alta rentabilidade em 4 estados e com 15 unidades em operaĂ§ĂŁo. Por que investir no Oakâs? Marca consolidada: rede pioneira em trazer os burritos para o Brasil. Modelos flexĂ­veis: lojas adaptadas para a necessidade do franqueado. OperaĂ§ĂŁo enxuta: poucos fornecedores e processos simples. Retorno rĂĄpido: payback estimado de 16 a 28 meses.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 14, NULL, NULL, '2026-03-10 01:55:27.019', 'https://franquias.portaldofranchising.com.br/franquia-oaks-burritos-y-bowls/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '200000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp3v001teh0s9q7zg5hz', 'Fisk Centro De Ensino', 'fisk-centro-de-ensino', NULL, '', '', '', NULL, 2002, '[\"https://www.youtube.com/watch?v=hGQD5RIlsuU\"]', '2026-04-01 02:00:12.593', '2025-08-11 01:37:23.803', 1191, NULL, 1, 1958, 'Sua histĂłria comeĂ§a com Richard H. Fisk, um americano nascido em Tunbridge, Vermont, que se apaixonou pelo Brasil em uma visita realizada em 1950. Graduado em lnternational Relations e com o diploma Master of Arts pela School of Advanced International Studies, Johns Hopkins University, em Washington, D.C., Mr. Fisk, como Ă© conhecido, decidiu permanecer no Brasil e passou a lecionar inglĂȘs no paĂ­s.', NULL, 'SĂŁo Paulo', NULL, NULL, 724, NULL, NULL, '2026-02-06 18:54:45.000', 'https://franquias.portaldofranchising.com.br/franquia-fisk-escola-de-idiomas/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '100000', NULL, NULL, NULL, NULL, NULL, '0', '0', '80000', '20000', 50);
