INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp4j001xeh0sipaj7let', 'SofĂĄ Novo De Novo', 'sofa-novo-de-novo', NULL, 'ServiĂ§os e Outros NegĂłcios', 'NegĂłcios Especializados', '', 2019, 2025, '[\"https://www.youtube.com/watch?v=64w86L5NG5U\",\"https://www.youtube.com/watch?v=61brgRTP9bU\",\"https://www.youtube.com/watch?v=pwQmzzvZTEc\",\"https://www.youtube.com/watch?v=hNHW5s0e0cU\",\"https://www.youtube.com/watch?v=Rb-OU4JQ2IA\"]', '2026-04-01 02:00:12.632', '2025-08-11 01:37:23.828', 1195, NULL, 1, 2019, 'A maior rede de HigienizaĂ§ĂŁo e blindagem de estofados do Brasil! \nCom quase 200 unidades jĂĄ confirmadas no Brasil, a SofĂĄ Novo de Novo uma rede de franquias que chegou ao mercado em 2019 e em menos de um ano se destacou por trazer um conceito muito consolidado em grandes capitais no Brasil: Home based. \nDe lĂĄ pra cĂĄ, tem se expandido e se tornou uma das maiores redes de higienizaĂ§ĂŁo e blindagem conhecida em todo paĂ­s. \nAlĂ©m disso, trabalhamos com produtos exclusivos e de altĂ­ssima qualidade, nĂŁo inflamĂĄveis e biodegradĂĄveis, de nanotecnologia de alta secagem, e todos homologados pela ANVISA, maquinĂĄrio de fabricaĂ§ĂŁo italiana de alta resistĂȘncia. \nDentro de todo esse cenĂĄrio, a SofĂĄ Novo de Novo se destaca pelo seu baixo valor de investimento inicial, alta rentabilidade, sem espaĂ§o fĂ­sico, nĂșmero reduzido de funcionĂĄrios e\nainda todo o suporte oferecido pela rede franqueadora. \nEssas caracterĂ­sticas a tornam uma excelente oportunidade de negĂłcio para quem busca um investimento seguro. \nA SofĂĄ Novo de Novo estĂĄ no centro de inĂșmeras tendĂȘncias: franquia, modelo de negĂłcio home based, e uso da tecnologia no atendimento. \nPor isso, a tendĂȘncia Ă© que a marca continue a trilhar caminhos promissores rumo ao sucesso absoluto. \nJĂĄ somos quase 200 unidades confirmadas no Brasil e continuamos crescendo de forma acelerada.  Esperamos seu contato!', NULL, NULL, NULL, NULL, 144, NULL, NULL, '2026-03-10 02:20:44.403', 'https://franquias.portaldofranchising.com.br/franquia-sofa-novo-de-novo/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
