INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp8f002ieh0s6x3zwpgt', 'Vazoli', 'vazoli', NULL, '', '', '', 2011, 2025, '[\"https://www.youtube.com/watch?v=Ge3Uhh6cxhU\",\"https://www.youtube.com/watch?v=Ju-HycCcnqM\",\"https://www.youtube.com/watch?v=CHNGbjwh2zk\"]', '2026-04-01 02:00:12.856', '2025-08-11 01:37:23.968', 1216, NULL, 1, 2008, 'Vazoli Franchising entra no mercado de franquias com projeto de expansĂŁo avanĂ§ado Encontrar e repassar aos clientes as melhores taxas do mercado e oferecer sempre o produto mais adequado para atender as necessidades de cada um. Com essa premissa, a Vazoli se consolidou no mercado como uma das principais redes de serviĂ§os financeiros do PaĂ­s. Com seriedade, profissionalismo e estreito relacionamento com os principais bancos de crĂ©dito do Brasil, a Vazoli, nascida em SeverĂ­nia, interior do Estado de SĂŁo Paulo, atua no setor desde 2008 e em 2011, jĂĄ com 10 unidades e com o processo de expansĂŁo acelerado, iniciou suas operaĂ§Ă”es franqueadas. Em pouco mais de um ano, jĂĄ possui mais de 40 unidades franqueadas em funcionamento e em fase de implantaĂ§ĂŁo. Segundo a Austin Rating, o setor de crĂ©dito no Brasil sĂł tende a crescer. Com o cenĂĄrio positivo, o setor de crĂ©dito tem sido um dos melhores investimentos do mercado de franquias. A venda de produtos como emprĂ©stimos, seguros e investimentos via terceiros (correspondentes bancĂĄrios) estĂĄ em alta e a estrutura oferecida pela rede de franquia garante as melhores negociaĂ§Ă”es. A rede Vazoli oferece crĂ©dito pessoal, crĂ©dito consignado para aposentados e pensionistas do INSS, crĂ©dito consignado para servidores pĂșblicos, crĂ©dito imobiliĂĄrio - financiamento e refinanciamento e compra de dĂ­vidas de outros bancos e cartĂ”es (consignados). A franquia Vazoli Ă© considerada um negĂłcio seguro e com rentabilidade rĂĄpida, uma vez que seu investimento inicial Ă© baixo. \"Garantimos ao franqueado todo suporte tĂ©cnico com treinamentos teĂłricos e prĂĄticos e materiais prĂłprios que vĂŁo ajudar a administrar o negĂłcio da melhor maneira para o sucesso imediato da unidade\", explica Eric Vaz de Lima, diretor da rede. Com um crescimento contĂ­nuo, a franquia vem se consolidando como uma das principais e mais competentes redes de serviĂ§os financeiros do mercado. Por meio de parcerias estratĂ©gicas, a Vazoli estĂĄ sempre atenta ao que hĂĄ de melhor em produtos financeiros assegurando maior rentabilidade para que seus franqueados se tornem empresĂĄrios bem sucedidos e cresĂ§am com a rede Vazoli.', NULL, 'SĂŁo Paulo', 1, NULL, 87, NULL, NULL, '2025-10-31 15:41:37.000', 'https://franquias.portaldofranchising.com.br/franquia-vazoli-negocios/', '1/3 do SalĂĄrio MĂ­nimo Vigente', 'Faturamento', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '24900', NULL, NULL, NULL, '24500', NULL, '1', '33.34', '150', '250', 25);
