INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfp8r002keh0sgv2morjx', 'PIZZA CREK', 'pizza-crek', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO RĂPIDO', 'Pizza Crek, reinventou a Pizza. Pizzas Individuais enroladas. Cada \"pedaĂ§o\" um sabor. Baixo investimento e retorno rĂĄpido.', 2016, 2018, '[\"https://www.youtube.com/watch?v=fuAz4ThjBVU\",\"https://www.youtube.com/watch?v=81Y7Lc4kWjQ\",\"https://www.youtube.com/watch?v=04pC5XPB5kI\",\"https://www.youtube.com/watch?v=BVsXoFTsoJQ\"]', '2026-04-01 02:00:12.876', '2025-08-11 01:37:23.979', 1218, NULL, 1, 2013, 'InovaĂ§ĂŁo e ExcelĂȘncia na Arte Fazer Pizza. A Pizza Crek revolucionou o mercado gastronĂŽmico brasileiro ao criar um conceito Ășnico de pizzas individuais, combinando praticidade, sabor e personalizaĂ§ĂŁo em cada produto. Com uma trajetĂłria inspiradora que comeĂ§ou na periferia de SĂŁo Paulo, a marca hoje Ă© referĂȘncia nacional. Conceito Exclusivo e DiferenciaĂ§ĂŁo Nossa proposta vai alĂ©m do convencional: nĂŁo somos apenas mais uma pizzaria. Com uma massa exclusiva, extra fina e crocante, desenvolvida e aperfeiĂ§oada. Oferecemos mais de 70 combinaĂ§Ă”es de sabores criteriosamente elaboradas, divididas em trĂȘs categorias principais: Pizzas Salgadas: opĂ§Ă”es tradicionais e criaĂ§Ă”es exclusivas Pizzas Doces: sobremesas irresistĂ­veis Linha Light: alternativas equilibradas. Temos a marivilhosa CREK PASTA. Todo o sabor da cozinha Italiana voce encontra na PIZZA CREK. ExcelĂȘncia em Cada Detalhe Nossa busca pela perfeiĂ§ĂŁo se reflete em cada aspecto Ingredientes selecionados de fornecedores certificados Processo de produĂ§ĂŁo padronizado e rigorosamente controlado Embalagens desenvolvidas especialmente para preservar a crocĂąncia Treinamento constante das equipes de produĂ§ĂŁo e atendimento ServiĂ§o Primum de Eventos Como lĂ­der no segmento de eventos com pizza no Brasil, oferecemos: Estrutura completa com equipamentos profissionais Equipe especializada e uniformizada CardĂĄpio personalizado conforme o perfil do evento Atendimento para diversos portes de eventos: Eventos pequenos (30 a 100 pessoas) Eventos mĂ©dios (100 a 500 pessoas) Eventos corporativos (500 a 10.000+ pessoas) Casamentos, formaturas e confraternizaĂ§Ă”es Reconhecimento e ExpansĂŁo Presente em mais de 15 estados brasileiros PrĂȘmios Internacionais PremiaĂ§Ă”es no setor de franchising Cases de sucesso em importantes veĂ­culos de comunicaĂ§ĂŁo CertificaĂ§Ă”es de qualidade e seguranĂ§a alimentar Compromisso com a Sustentabilidade Embalagens eco-friendly GestĂŁo responsĂĄvel de resĂ­duos PolĂ­tica de compras de fornecedores locais Diferenciais Competitivos Produto patenteado e exclusivo Modelo de negĂłcio escalĂĄvel Suporte completo aos franqueados Centro de treinamento prĂłprio Tecnologia prĂłpria de produĂ§ĂŁo Sistema de gestĂŁo integrado', NULL, 'SĂO PAULO', 1, NULL, 71, NULL, NULL, '2026-01-20 15:44:33.000', 'https://franquias.portaldofranchising.com.br/franquia-pizza-crek/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '200000', NULL, NULL, NULL, '55000', '0', '6', '1', '180000', NULL, 0);
