idor.', NULL, 'SĂŁo Paulo', 1, NULL, 230, NULL, NULL, '2025-11-25 10:17:27.000', 'https://franquias.portaldofranchising.com.br/franquia-tintas-mc/', 'Compras', 'Compras', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '260000', NULL, NULL, NULL, '50000', '250000', '5', '1.5', '150000', '60000', 200);
