INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpal002seh0sua4u8acw', 'FLYWORLD O SEU AMIGO DE VIAGENS', 'flyworld-o-seu-amigo-de-viagens', NULL, 'Hotelaria e Turismo', 'AGĂNCIAS DE TURISMO', 'Hotelaria e Turismo', 2013, 2014, '[\"https://www.youtube.com/watch?v=aEWkaAmHZrE\",\"https://www.youtube.com/watch?v=3CaOvrkwRXU\",\"https://www.youtube.com/watch?v=nyhiHMokjn4\",\"https://www.youtube.com/watch?v=fHCoSpIXcD4\"]', '2026-04-01 02:00:12.959', '2025-08-11 01:37:24.045', 1226, NULL, 1, 1997, 'A Flyworld Ă© a primeira microfranquia de turismo do Brasil, com mais de 30 anos de experiĂȘncia no setor e um modelo de negĂłcio feito para quem sonha em empreender com liberdade, propĂłsito e rentabilidade. Criada a partir da trajetĂłria do seu fundador e CEO, Paulo Atencia, a Flyworld nasceu do desejo de compartilhar conhecimento com pessoas apaixonadas por viagens â e que querem transformar essa paixĂŁo em um negĂłcio lucrativo. Desde 2013, levamos essa visĂŁo para todo o paĂ­s com um modelo de franquia leve, acessĂ­vel e de alta performance. Somos associados Ă  ABF desde 2014, o que reforĂ§a nossa credibilidade no mercado de franchising. Mais do que uma franquia, a Flyworld Ă© uma escolha inteligente para quem quer empreender no turismo com estrutura, liberdade e seguranĂ§a. Mais de 30 anos de experiĂȘncia Nosso fundador e CEO, Paulo Atencia, carrega uma trajetĂłria sĂłlida no turismo e traz essa bagagem para o dia a dia da rede. Toda a metodologia, processos e suporte da Flyworld sĂŁo construĂ­dos com base em dĂ©cadas de prĂĄtica real â e isso faz diferenĂ§a. Modelo de negĂłcios flexĂ­vel Acreditamos que uma agĂȘncia em Home Office ou em um Ponto FĂ­sico, necessitam do mesmo suporte, expertise e apoio. Por isso, nosso modelo de negĂłcio Ă© Ășnico e vocĂȘ escolhe se irĂĄ empreender em home office ou loja fĂ­sica. E o melhor: se quiser mudar depois, nĂŁo paga nada a mais por isso. Liberdade real para empreender do seu jeito Na Flyworld, o franqueado Ă© dono de verdade. VocĂȘ tem autonomia para escolher os fornecedores do nosso portfĂłlio com quem vai trabalhar, decidir os tipos de viagem que quer vender e construir a sua prĂłpria carteira de clientes. A franqueadora estĂĄ ao seu lado â nĂŁo no seu caminho. Marketing estratĂ©gico para destacar a sua unidade Nosso time de marketing oferece consultoria para posicionar sua agĂȘncia, ajuda na produĂ§ĂŁo de conteĂșdo, materiais personalizados, campanhas locais e muito mais. NĂŁo importa se vocĂȘ estĂĄ comeĂ§ando ou jĂĄ tem experiĂȘncia: vamos te ajudar a se destacar. Mix completo de produtos e serviĂ§os turĂ­sticos Na Flyworld, vocĂȘ pode atender qualquer perfil de cliente, do lazer ao corporativo, com soluĂ§Ă”es completas em um sĂł lugar. Isso aumenta seu ticket mĂ©dio e fideliza seu cliente, que nĂŁo precisa buscar outros canais. Mais facilidade para ele, mais vendas para vocĂȘ. ExpansĂŁo com propĂłsito e critĂ©rio NĂŁo buscamos ter centenas de unidades a qualquer custo. Crescemos com critĂ©rio, escolhendo franqueados comprometidos e regiĂ”es com real potencial. Nossa meta Ă© que cada unidade da Flyworld seja lucrativa e duradoura.', NULL, 'SĂO PAULO', 1, NULL, 36, NULL, NULL, '2026-01-22 09:44:51.000', 'https://franquias.portaldofranchising.com.br/franquia-flyworld/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '18250', NULL, NULL, NULL, '18250', NULL, '0', '0', NULL, NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpar002teh0shgkwvk4f', 'SEGENERGY', 'segenergy', NULL, 'ServiĂ§os e Outros NegĂłcios', 'OUTROS NEGĂCIOS', 'Energia Solar - AeĂłlica - HidrogĂȘnio Verde - Mercado livre de energia', 2019, 2022, '[\"https://www.youtube.com/watch?v=57FsfIDvPog\",\"https://www.youtube.com/watch?v=yeyz40o668g\",\"https://www.youtube.com/watch?v=yIus3C4E89s\",\"https://www.youtube.com/watch?v=FvxE4Fhc_Mk\"]', '2026-04-01 02:00:12.971', '2025-08-11 01:37:24.051', 1227, NULL, 1, 2017, 'A SegEnergy Ă© uma empresa brasileira especializada em soluĂ§Ă”es integradas de energia solar, diferenciada pela qualidade desde o primeiro contato atĂ© o pĂłs-venda. Nosso objetivo, tornar a energia solar acessĂ­vel para todos - uma alternativa viĂĄvel, sustentĂĄvel e rentĂĄvel - nos tornou referĂȘncia no mercado por desenvolvermos, implantarmos e gerenciarmos sistemas que aliam eficiĂȘncia econĂŽmica e compromisso ambiental. Sonhos nĂŁo sĂŁo inacessĂ­veis quando o investimento Ă© feito com quem sabe realizĂĄ-los! Vantagens de fazer parte da SegEnergy: Mais de 7.500 sistemas instalados; Mais de 400 unidades espalhadas em todo territĂłrio nacional; Suporte comercial individual especializado; MBA de Vendas; GestĂŁo de engenharia com mais de 8 anos de atuaĂ§ĂŁo no setor; GestĂŁo de marketing com calendĂĄrios mensais para redes sociais + solicitaĂ§Ă”es individuais personalizadas; Acesso a plataforma de CRM e dimensionamento SegSystem; Capital de giro baixo; Sem necessidade de estoque; Payback rĂĄpido; Segmento em alta no Brasil e no mundo; Fornecedores com equipamentos de alta qualidade. Por que escolher a SegEnergy: Franchising de destaque: fazemos parte do Grupo Zanon - holding de franquias, uma das maiores e melhores no mercado, com atuaĂ§ĂŁo a nĂ­vel nacional e internacional. Flexibilidade de atuaĂ§ĂŁo: oferecemos os modelos home based e loja, com oportunidades de vocĂȘ trabalhar em casa ou local fixo. Facilidade de acesso a informaĂ§Ă”es da rede: possuĂ­mos uma plataforma exclusiva e de fĂĄcil uso para vocĂȘ encontrar e solicitar pedidos personalizados, e receber avisos e informaĂ§Ă”es internas e de fornecedores. Suporte e time comercial: oferecemos um time comercial especializado para te auxiliar e incentivar Ă  alcanĂ§ar seus objetivos, com disponibilidade para vĂ­deo chamadas se necessĂĄrio. Diferentes ĂĄreas de atuaĂ§ĂŁo: residencial, comercial, industrial, rural, mercado livre, autoprodutor e cooperativa.', NULL, 'SĂO PAULO', 1, NULL, 347, NULL, NULL, '2026-02-13 13:56:11.000', 'https://franquias.portaldofranchising.com.br/franquia-segenergy/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '40000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpax002ueh0shx9ipd8z', 'ORTHOPRIDE', 'orthopride', NULL, 'SaĂșde, Beleza e Bem Estar', 'ODONTOLOGIA', 'Tratamento ortodontia e estĂ©tica', 2011, 2013, NULL, '2026-04-01 02:00:12.982', '2025-08-11 01:37:24.057', 1228, NULL, 1, 2009, 'A Orthopride nasceu para oferecer aos pacientes, mais qualidade de vida, mais saĂșde e muitos sorrisos no dia a dia. Fundada em 2009, a Orthopride tem marcado presenĂ§a no cenĂĄrio da ortodontia e da estĂ©tica orofacial, proporcionando sorrisos confiantes e transformando vidas. Esta histĂłria Ă© permeada por inovaĂ§ĂŁo, comprometimento com a excelĂȘncia e um impacto positivo nos negĂłcios. A jornada de sucesso da Orthopride iniciou seus passos com a primeira clĂ­nica inaugurada em Duque de Caxias, Rio de Janeiro, concebida com foco em tratamentos ortodĂŽntico e de e?stĂ©tica, desenvolvendo um processo de produĂ§ĂŁo prĂłprio e atendimento personalizado que fizeram-na atingir a marca de 2 mil pacientes logo no primeiro ano de funcionamento. Em 2012 deu inĂ­cio Ă  sua operaĂ§ĂŁo no franchising brasileiro, e em 2016 ganhou seu primeiro Selo de ExcelĂȘncia em Franchising, da AssociaĂ§ĂŁo Brasileira de Franchising (ABF). Sua expansĂŁo foi expressiva a partir de entĂŁo, e hoje jĂĄ sĂŁo mais de 200 unidades da franquia. Nossas unidades sĂŁo projetadas para oferecer comodidade aos pacientes, atravĂ©s de um atendimento personalizado, tecnologia de ponta e profissionais capacitados para fazer o melhor. Assim, procuramos levar a nossa filosofia em cada atendimento, proporcionando uma experiĂȘncia positiva a quem nos procura. Somos a rede de franquias do ramo de ortodontia e estĂ©tica orofacial que mais cresce no Brasil. Presente em 18 estados, hoje cuidamos de mais de 250 mil sorrisos em todo o Brasil. NĂŁo Ă© Ă  toa que 70% dos nossos franqueados possuem mais de uma unidade, com um total de falĂȘncias ZERO!', NULL, 'RIO DE JANEIRO', 1, NULL, 204, NULL, NULL, '2026-01-08 17:07:01.000', 'https://franquias.portaldofranchising.com.br/franquia-orthopride-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '525000', NULL, NULL, NULL, '85000', '0', '7', '3', '290000', '150000', 0);
