INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpbr002zeh0slyt4n0ju', 'GUA.CO', 'gua-co', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO COMPLETO', 'Restaurante Fast Casual de cozinha mexicana e americana saudĂĄvel, com foco em qualidade e produtos frescos para refeiĂ§Ă”es rĂĄpidas do dia a dia.', 2017, 2021, '[\"https://www.youtube.com/watch?v=_KnZekkygek\",\"https://www.youtube.com/watch?v=2xtko2p-wJY\",\"https://www.youtube.com/watch?v=uyLkR7z06zg\"]', '2026-04-01 02:00:13.033', '2025-08-11 01:37:24.088', 1233, NULL, 1, 2016, 'O GUA.CO foi fundado em 2016 em Campinas (SP) e rapidamente se tornou uma love brand graĂ§as ao seu posicionamento disruptivo e criativo. Apesar de atualmente a expansĂŁo estar focada no Sudeste, a marca jĂĄ conquistou fĂŁs por todo o Brasil, ansiosos por novas unidades em suas cidades. Acreditamos no poder da comida fresca preparada de forma caseira, com amor e carinho. Combinamos elementos simples que juntos se transformam em algo especial. A origem do nome do restaurante remete ao guacamole, uma receita asteca tĂ­pica elaborada de quatro ingredientes que quando misturados se elevam a outro patamar. Usamos avocados, o abacate mexicano, na preparaĂ§ĂŁo de nosso guacamole e nĂłs mesmos monitoramos o amadurecimento da fruta. Temos o compromisso em servir comida saudĂĄvel e autĂȘntica. Todos nossos ingredientes sĂŁo preparados diariamente Ă  mĂŁo, com vegetais frescos, temperos e folhas colhidos de hortas da regiĂŁo. Nossas tortillas e taco shells sĂŁo legĂ­timos e de matĂ©ria prima importada, garantindo a textura e o sabor autĂȘntico da massa que se encontra na culinĂĄria mexicana e nos restaurantes mexicanos do sul e oeste dos Estados Unidos. O segmento fast-casual Ă© o que mais cresce no mundo gastronĂŽmico. Entre eles, os de culinĂĄria mexicana sĂŁo os mais populares, tendo o burrito como seu principal produto. Temos a produĂ§ĂŁo diĂĄria de um restaurante casual dining, e ao mesmo tempo servimos a comida rapidamente como no fast-food. Dessa forma garantimos a qualidade e a agilidade do serviĂ§o.', NULL, 'SĂO PAULO', 1, NULL, 15, NULL, NULL, '2026-01-28 16:17:42.000', 'https://franquias.portaldofranchising.com.br/franquia-guaco/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '750000', NULL, NULL, NULL, '60000', NULL, '5', '2', '560000', '130000', 0);
