conhecimento: Diversos prĂȘmios dos setores de franchising, grĂĄfico e marketing dĂŁo destaque Ă  forĂ§a da marca AlphaGraphics.', NULL, 'SĂŁo Paulo', 1, NULL, 25, NULL, NULL, '2026-02-04 17:01:58.000', 'https://franquias.portaldofranchising.com.br/franquia-alphagraphics-grafica/', 'Fat. Bruto', 'Fat. LĂ­q.', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '400000', NULL, NULL, NULL, '70000', NULL, '5', '2', '230000', '100000', 70);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpc20031eh0s3xpwxbr1', 'MajĂŽ Beauty Club', 'majo-beauty-club', NULL, 'Bebidas', '', 'Comercio varejista', NULL, 2020, '[\"https://www.youtube.com/watch?v=TSSb10r5ucA\",\"https://www.youtube.com/watch?v=vuwY2b1sekU\",\"https://www.youtube.com/watch?v=K4HCdKyx6jA\",\"https://www.youtube.com/watch?v=TSSb10r5ucA\",\"https://www.youtube.com/watch?v=Qx8oh1Pf_EU\"]', '2026-04-01 02:00:13.055', '2025-08-11 01:37:24.098', 1235, NULL, 1, 2020, 'A MajĂŽ Beauty Club nasceu do desejo da CEO e fundadora da marca, Claudia Vobeto, de criar um projeto com tecnologia e inovaĂ§ĂŁo. Defensora do sistema de franquias Ă©tico e transparente, a idealizadora atua hĂĄ mais de 14 anos no segmento de beleza e tambĂ©m Ă© diretora de capacitaĂ§ĂŁo da AssociaĂ§ĂŁo Brasileira de Franchising â ABF. VisionĂĄria, Claudia Vobeto criou a rede para atender uma demanda do setor em constante expansĂŁo: qualidade e respeito pelos clientes. A rede segue em constante evoluĂ§ĂŁo e reflete diretamente as expectativas do mercado e do segmento. Assim, a MajĂŽ Beauty Club tem o propĂłsito genuĂ­no de criar experiĂȘncias inesquecĂ­veis e que vĂŁo alĂ©m da prestaĂ§ĂŁo de serviĂ§os. Promovemos o bem-estar aos nossos clientes que, na grande maioria, tem pouco tempo para si mesmos. Com atendimento expresso, atendemos sem hora marcada para serviĂ§os do dia a dia, como depilaĂ§ĂŁo, manicure e sobrancelhas. E para serviĂ§os agendados, temos o aplicativo prĂłprio MajĂŽ. SĂŁo mais de 200 procedimentos de beleza, mais de 20 protocolos exclusivos e uma linha completa de produtos MajĂŽ. AlĂ©m disso, temos o Beauty Blue â o Ășnico clube de beleza select do Brasil â com vantagens e descontos exclusivos para os Clientes Select MajĂŽ. Com mais de 130 mil atendimentos no ano, trazemos soluĂ§Ă”es para o dia a dia dos clientes com beleza da cabeĂ§a aos pĂ©s.', NULL, 'GoiĂĄs', 1, NULL, 22, NULL, NULL, '2025-09-15 16:35:46.000', 'https://franquias.portaldofranchising.com.br/franquia-majo-beauty-club-saude-beleza-e-bem-estar/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '297000', NULL, NULL, NULL, '58000', '260000', '6', '2', '189000', '50000', 40);
