INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpdc003aeh0sd23m81i3', 'CROSBY', 'crosby', NULL, 'Moda', 'VESTUĂRIO', 'A Crosby foi fundada em 2015 pelos IrmĂŁos Crosby, FĂĄbio e Felipe Azevedo, comeĂ§ou em uma garagem e agora possui + de 120 lojas em todo Brasil!', 2017, 2024, '[\"https://www.youtube.com/watch?v=ImNNd_8TyWA\"]', '2026-04-01 02:00:13.147', '2025-08-11 01:37:24.144', 1244, NULL, 1, 2015, 'ExperiĂȘncia CROSBY Nos Ășltimos anos, enfrentamos de frente grandes desafios como a pandemia e as crises econĂŽmicas. Foi justamente nesses momentos que mostramos nossa forĂ§a: sabemos lidar com adversidades e transformĂĄ-las em oportunidades. AlĂ©m disso, a forma como cuidamos dos nossos franqueados faz toda a diferenĂ§a. Nosso compromisso com o sucesso resulta em um crescimento duas vezes maior do que o das demais franquias do mercado. Investir em uma marca que dobra de tamanho Ă© o caminho! InovaĂ§ĂŁo contĂ­nua em produto e logĂ­stica Investimos constantemente em tecnologia e processos logĂ­sticos para garantir eficiĂȘncia e agilidade em toda a operaĂ§ĂŁo. Agilidade na entrega O produto certo, no momento certo garantindo reposiĂ§ĂŁo rĂĄpida e assertiva para maximizar suas vendas. GestĂŁo inteligente com tecnologia exclusiva Nossos franqueados contam com sistemas exclusivos que otimizam a operaĂ§ĂŁo e proporcionam um controle de estoque preciso e estratĂ©gico. Ferramentas de vendas que geram resultado Desenvolvemos soluĂ§Ă”es prĂĄticas e estratĂ©gias comerciais para impulsionar as vendas e manter sua loja sempre em alta performance.', NULL, 'RIO GRANDE DO NORTE', 1, NULL, 90, NULL, NULL, '2025-11-04 19:07:31.000', 'https://franquias.portaldofranchising.com.br/franquia-crosby/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '228000', NULL, NULL, NULL, '28000', NULL, '0', '3', '160000', '40000', 0);
