INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpeb003heh0s3upkkf14', 'School Of Rock', 'school-of-rock', NULL, 'ServiĂ§os', 'EducaĂ§ĂŁo', 'Comercio varejista', 2013, 2022, NULL, '2026-04-01 02:00:13.223', '2025-08-11 01:37:24.179', 1251, NULL, 1, 2002, 'A primeira unidade da School of Rock no Brasil abriu em SĂŁo Caetano do Sul, no ABC Paulista, em 2013, e logo em seguida mais uma escola em SĂŁo Paulo, a unidade de Moema. Em 2017 assinamos o contrato de Master Franqueado e, de lĂĄ para cĂĄ, sĂł crescemos: temos 65 unidades assinadas no Brasil. Em 2019 comeĂ§amos nossa expansĂŁo para o continente Europeu, adquirindo os direitos de comercializaĂ§ĂŁo e suporte para Portugal e Espanha nos tornando Master Franquia destes paĂ­ses. Nosso desempenho como franqueadores tem sido constantemente reconhecido atravĂ©s de prĂȘmios nacionais e internacionais. Recentemente recebemos o Selo de ExcelĂȘncia em Franchising concedido pela ABF (AssociaĂ§ĂŁo Brasileira de Franchising). Sabemos o que Ă© necessĂĄrio para ter uma franquia de sucesso e temos mais de vinte anos de experiĂȘncia no mercado.', NULL, 'SĂŁo Paulo', 1, NULL, 60, NULL, NULL, '2026-01-28 17:32:23.000', 'https://franquias.portaldofranchising.com.br/franquia-school-of-rock/', 'Fat. Bruto', 'Fat. Bruto', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '585000', NULL, NULL, NULL, '215000', '125000', '8', '3', '300000', '70000', 250);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpeg003ieh0sz50yve2r', 'ADCOS', 'adcos', NULL, 'SaĂșde, Beleza e Bem Estar', 'COSMĂTICOS E PERFUMARIA', 'DERMOCOSMĂTICOS, COSMĂTICO, BELEZA, SAĂDE, ESTĂTICA, SKINCARE, TRATAMENTO, FACIAL', 2003, 2004, NULL, '2026-04-01 02:00:13.234', '2025-08-11 01:37:24.185', 1252, NULL, 1, 1993, 'Criada em 1993 por Ada Mota, a ADCOS Ă© uma marca brasileira de dermocosmĂ©ticos que traz em seu DNA a eficĂĄcia comprovada de seus produtos para tratamento da pele. Empreendedorismo, pesquisa, tecnologia e ciĂȘncia foram os parĂąmetros seguidos desde sempre e que a tornaram uma marca genuĂ­na e de sucesso. Dia apĂłs dia, vem se tornando referĂȘncia no ramo da saĂșde, beleza e estĂ©tica. Ada Mota Ă© farmacĂȘutica e bioquĂ­mica, com mestrado em DermocosmĂ©tica em Paris, onde acompanhou de perto o surgimento do conceito do DermocosmĂ©tico, com a exigĂȘncia de que as empresas comprovassem cientificamente a eficĂĄcia de seus produtos. Ainda em Paris, participou de um estudo da melhoria da cosmĂ©tica de pomadas utilizadas em pacientes internados por doenĂ§as dermatolĂłgicas no Hospital Saint-Louis, experiĂȘncia que direcionou e inspirou a preocupaĂ§ĂŁo da ADCOS com a eficĂĄcia associada ao sensorial agradĂĄvel dos produtos. A marca Ă© pioneira em protetores solares em formato Stick, hĂĄ quase 10 anos, desde 2014. AlĂ©m disso, Ă© expert na estabilizaĂ§ĂŁo da Vitamina C em dermocosmĂ©ticos para a pele brasileira, se tornando referĂȘncia no mercado hĂĄ 30 anos e traz em seu portfĂłlio diferentes texturas e para diferentes tipos de pele. Seu portfĂłlio conta com cerca de 200 produtos para tratamentos faciais e corporais, nos segmentos home care e profissional, todos isentos de testes em animais e com eficĂĄcia comprovada, bem como alinhados Ă s Ășltimas tendĂȘncias da cosmetologia mundial. A ADCOS tem como propĂłsito, ao desenvolver seus produtos, a busca pelas melhores formulaĂ§Ă”es, pois a marca acredita que Ă© importante cuidar de seus consumidores como cuidariam de um familiar querido, como Ă© o caso do Elastcrem, produto desenvolvido pela prĂłpria Dra. Ada em sua gestaĂ§ĂŁo gemelar. Todos os cosmĂ©ticos e dermocosmĂ©ticos da marca sĂŁo desenvolvidos por dermatologistas e farmacĂȘuticos com o cuidado de serem os melhores produtos focados em tratamentos, para o skincare e clima brasileiro, usando ingredientes biocompatĂ­veis, oferecendo aos consumidores mĂĄxima eficĂĄcia, ampla gama de texturas e tonalidades. A ADCOS possui fortes investimentos em inovaĂ§ĂŁo, o que faz com que produtos icĂŽnicos lanĂ§ados hĂĄ 30 anos, como o Reduxcel corporal, se mantenham relevantes atĂ© hoje, com grande reconhecimento dos consumidores por sua aĂ§ĂŁo comprovada na reduĂ§ĂŁo de medidas e celulite. A ADCOS oferece ao consumidor uma experiĂȘncia exclusiva em dermocosmĂ©ticos dentro do seu ambiente de lojas fĂ­sicas. O atendimento oferecido pelas dermoconsultoras permite a recomendaĂ§ĂŁo de uma rotina totalmente personalizada, focada no skincare ideal para cada tipo de pele, desde tratamentos a protocolos especĂ­ficos de cuidados, sempre de acordo com a necessidade do consumidor, possibilitando sentir na pele o sensorial dos produtos, sua textura, testar a tonalidade adequada para sua pele, tudo isso antes de comprĂĄ-los. Reconhecida por seu compromisso com a saĂșde da pele facial e corporal dos brasileiros, a ADCOS se orgulha do seu projeto para conscientizaĂ§ĂŁo e tratamento do cĂąncer de pele em parceria com PAD-UFES (Programa de AssistĂȘncia DermatolĂłgica e CirĂșrgica Ă  PopulaĂ§ĂŁo Rural VulnerĂĄvel e com CĂąncer de Pele do EspĂ­rito Santo). Um programa desenvolvido pela Universidade Federal do EspĂ­rito Santo com a Secretaria Estadual da SaĂșde, onde a ADCOS auxilia o projeto atravĂ©s de doaĂ§Ă”es de produtos e hospedagem de equipes e transporte de acadĂȘmicos para os municĂ­pios atendidos. Em 2022, ao todo, foram realizadas 2072 consultas, 875 cirurgias e 6049 crioterapias. Nos Ășltimos anos, a marca investiu em um modelo de negĂłcios multicanal, com lojas, farmĂĄcias e e-commerce que totalizam 147 lojas pelo Brasil, divididas entre 90 franquias e 54 lojas prĂłprias nos segmentos de clientes finais e profissionais. Mais de mil farmĂĄcias no paĂ­s e 650 colaboradores, sendo 75% do quadro da empresa composto por mulheres.', NULL, 'ESPĂRITO SANTO', 1, NULL, 158, NULL, NULL, '2025-12-15 14:39:22.000', 'https://franquias.portaldofranchising.com.br/franquia-adcos-beleza-e-saude/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '590000', NULL, NULL, NULL, '50000', '0', '55', '0', '490000', '40000', 0);
