INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpfc003oeh0sas27q35j', 'AĂ§aĂ­ Da Barra', 'acai-da-barra', NULL, '', '', '', 2015, 2025, '[\"https://www.youtube.com/watch?v=B0FgBIvnpmw\",\"https://www.youtube.com/watch?v=O0NINtJrk0w\",\"https://www.youtube.com/watch?v=kuaM5aEnX-o\"]', '2026-04-01 02:00:13.296', '2025-08-11 01:37:24.216', 1258, NULL, 1, 2015, 'Imagine uma saborosa experiĂȘncia em que vocĂȘ pode se deliciar com aĂ§aĂ­ e sorvete, servidos de forma rĂĄpida e sem limites de acompanhamentos, tudo do jeitinho que vocĂȘ preferir.', NULL, 'SĂŁo Paulo', NULL, NULL, 287, NULL, NULL, '2026-02-02 15:14:45.000', 'https://franquias.portaldofranchising.com.br/franquia-acai-da-barra/', 'Vendas Brutas', 'Compras', NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '255000', NULL, NULL, NULL, '60000', NULL, '0', '0', '195000', NULL, 40);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpfh003peh0s6e7io81b', 'BUBBLE MIX TEA', 'bubble-mix-tea', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO RĂPIDO', 'A Bubble Mix Ă© a rede de franquias pioneira no segmento de Bubble Tea no Brasil. Somos uma marca especializada em produtos Ă  base de chĂĄ e cafĂ©.', 2016, 2018, '[\"https://www.youtube.com/watch?v=NFoM2ZxXsqo\",\"https://www.youtube.com/watch?v=di8Ru6jwGFY\"]', '2026-04-01 02:00:13.306', '2025-08-11 01:37:24.221', 1259, NULL, 1, 2014, 'Pioneira no Brasil e LĂ­der no Mercado A Bubble Mix Tea trouxe para o Brasil a bebida que Ă© tendĂȘncia global: o Bubble Tea, criado em Taiwan nos anos 80. Oferecendo uma combinaĂ§ĂŁo deliciosa de chĂĄs, cafĂ©s, e ingredientes exclusivos, como pĂ©rolas de tapioca e poppings, a marca se destacou por sua qualidade, inovaĂ§ĂŁo e experiĂȘncia sensorial Ășnica. Fundada em 2014, a Bubble Mix Tea foi a primeira marca a adaptar o conceito de Bubble Tea ao gosto brasileiro. Participou do Shark Tank Brasil em 2017, ganhando destaque nacional. Reconhecida com o Selo de ExcelĂȘncia em Franchising em 2020 - 2022 - 2024, consolidando-se como referĂȘncia no segmento. Em 2023, deu inĂ­cio Ă  sua expansĂŁo internacional, marcando um novo capĂ­tulo em sua trajetĂłria de sucesso. Com mais de 100 unidades em operaĂ§ĂŁo ou implantaĂ§ĂŁo, a marca Ă© lĂ­der absoluta na AmĂ©rica do Sul. Por Que Escolher a Bubble Mix Tea? Mercado em ExpansĂŁo: O setor de Bubble Tea cresce de forma acelerada em todo o mundo, e o Brasil segue a tendĂȘncia, com consumidores buscando experiĂȘncias gastronĂŽmicas inovadoras. Modelo de NegĂłcio Validado: ApĂłs dois anos de testes e ajustes, o modelo foi estruturado para garantir lucratividade e escalabilidade, com faturamento mĂ©dio atraente para os franqueados. Baixo Investimento, Alto Retorno: Investimento inicial a partir de R$ 119.000 Lucro mĂ©dio entre 15% e 25% Retorno estimado entre 12 e 24 meses InovaĂ§ĂŁo Constante: Oferecemos sabores exclusivos, como chĂĄs tropicais e toppings diferenciados, alĂ©m de lanĂ§amentos regulares que atraem novos pĂșblicos. O Melhor Suporte para Seu Sucesso Na Bubble Mix Tea, vocĂȘ nĂŁo estarĂĄ sozinho. Nossa equipe acompanha cada etapa do processo para garantir o sucesso do seu negĂłcio. Treinamento Completo: Aprenda tudo sobre marketing, gestĂŁo operacional, administrativa e estratĂ©gias para maximizar os resultados da sua franquia. Acompanhamento Personalizado: Desde a escolha do ponto comercial atĂ© o pĂłs-inauguraĂ§ĂŁo, estamos ao seu lado para garantir uma transiĂ§ĂŁo tranquila e operaĂ§Ă”es eficientes. LogĂ­stica Facilitada: Com um centro de distribuiĂ§ĂŁo prĂłprio, garantimos que sua unidade tenha acesso rĂĄpido e padronizado a todos os produtos. Quem Pode Ser um Franqueado Bubble Mix Tea? Buscamos parceiros que: Tenham mais de 21 anos e residam na cidade onde serĂĄ instalada a unidade. Disponham de recursos prĂłprios e tempo para se dedicar ao negĂłcio. Possuam espĂ­rito empreendedor e gostem de trabalhar com o pĂșblico. Como Funciona o Processo de SeleĂ§ĂŁo? FormulĂĄrio de Interesse: Preencha online e tire suas dĂșvidas iniciais. AnĂĄlise de Viabilidade Financeira: Descubra como o negĂłcio pode funcionar para vocĂȘ. Circular de Oferta de Franquia (COF): Receba todos os detalhes da operaĂ§ĂŁo e tenha 10 dias para anĂĄlise. PrĂ©-Contrato: Garanta sua franquia com o pagamento da taxa e a definiĂ§ĂŁo do ponto comercial. Contrato Final e ImplantaĂ§ĂŁo: Estruture sua loja e esteja pronto para comeĂ§ar!', NULL, 'PARANĂ', 1, NULL, 81, NULL, NULL, '2025-12-29 00:00:08.000', 'https://franquias.portaldofranchising.com.br/franquia-bubble-mix-tea/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '130000', NULL, NULL, NULL, '45000', NULL, '5', '2', '165000', NULL, 0);
