INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfph40040eh0s7hqe936g', 'Zastras Brinquedos', 'zastras-brinquedos', NULL, 'Brinquedos', 'Educacionais', 'Comercio varejista', 2007, 2007, NULL, '2026-04-01 02:00:13.415', '2025-08-11 01:37:24.280', 1270, NULL, 1, 2007, 'Em 2007, a Brasil Franchising idealizou a Zastras, um novo conceito em lojas de brinquedos educativos, cultivando o interesse pelo universo lĂșdico e tomando como desafio encontrar meios de associar cada vez mais o momento de brincar com a evoluĂ§ĂŁo individual da crianĂ§a. Nosso objetivo foi fazer da Zastras esse lugar. Transformar esse sonho em realidade. Uma rede de lojas com o mesmo conceito que busca qualidade, informaĂ§ĂŁo, orientaĂ§ĂŁo aos pais e diversĂŁo para as crianĂ§as. A Zastras Ă© uma loja onde os pais encontram uma orientaĂ§ĂŁo sobre o que Ă© adequado para cada faixa etĂĄria e uma ampla variedade de produtos que estimulam o desenvolvimento das habilidades motoras, cognitivas, emocionais e sociais, tanto de bebĂȘs como de crianĂ§as. Hoje, a Zastras Ă© a maior rede de franquias no segmento de brinquedos educativos. Selecionamos os melhores livros infantis, brinquedos educativos, jogos inteligentes e fantasias lĂșdicas. Trabalhamos com um modelo de negĂłcio com produtos exclusivos e boa margem comercial. Participe dessa histĂłria de sucesso!', NULL, 'SĂŁo Paulo', 1, NULL, 98, NULL, NULL, '2026-02-06 08:18:35.000', 'https://franquias.portaldofranchising.com.br/franquia-zastras-brinquedos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, '85000', '0', '0', '299000', NULL, 20);
