INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpib0045eh0sk5th0jfm', 'ICE CREAM ROLL', 'ice-cream-roll', NULL, 'AlimentaĂ§ĂŁo', 'DOCERIAS E SORVETERIAS', 'A Ice Roll a maior rede de Sorvete na Chapa do mundo com um modelo de negĂłcio perfeito para vocĂȘ crescer, investimento atrativo lucratividade acima da mĂ©dia. Saiba mais no Portal do Franchising', 2017, 2023, '[\"https://www.youtube.com/watch?v=YHZccP5YEzQ\",\"https://www.youtube.com/watch?v=erxH93d00fo\"]', '2026-04-01 02:00:13.464', '2025-08-11 01:37:24.324', 1275, NULL, 1, 2017, 'A Ice Roll Ă© famosa pelo sorvete de rolinho ou sorvete na chapa, como quiser chamar !! Foi pioneira em trazer a ideia para o Brasil em 2017 e foi um sucesso. O primeiro quiosque da rede foi inaugurado no mesmo ano, em Indaiatuba, Ă© o ponto onde se concentra a base da Ice Cream Roll e onde tambĂ©m nascem as novidades. Os famosos rolinhos conquistaram a todos e hoje, com quase 6 anos de mercado, a Ice Roll conta com mais de 80 unidades pelo Brasil inteiro e segue expandindo suas operaĂ§Ă”es !! HistĂłria da Ice Cream Roll A histĂłria da marca comeĂ§a em 2017 com um engenheiro observador que tinha muita vontade de empreender. Depois de viajar pela TailĂąndia e descobrir as delĂ­cias do sorvete de lĂĄ, a vontade ganhou forma, sabor e ingredientes especiais. Nada mais gostoso que realizar um propĂłsito. Foi assim que a Ice Cream Roll trouxe uma experiĂȘncia Ășnica, marcante e personalizada para o paĂ­s que mais consome sorvete no mundo. Olhando para esse mercado que cresce a cada ano, estruturamos um modelo de negĂłcios de operaĂ§ĂŁo simplificada e eficiente para quem busca investir em franquias ou micro franquias. Diferenciais Planejado para oferecer muito mais que sabor ao cliente, o quiosque foi projetado para que o processo de produĂ§ĂŁo artesanal do sorvete, que desperta a curiosidade, seja acompanhado de perto. O cliente vĂȘ cada ingrediente selecionado, vĂȘ a mistura rĂ­tmica da massa pelas espĂĄtulas e a cuidadosa formaĂ§ĂŁo de cada rolinho. O grande diferencial Ă© a excelĂȘncia em qualidade, Ă© feito na hora, com ingredientes fresquinhos e massa aerada, com textura Ășnica, o sorvete na chapa Ă© irresistĂ­vel, tanto pelo sabor quanto pelo preparo. Ă base de leite sem corantes ou conservantes, a Ice Cream Roll Ă© a melhor maneira de saciar essa ĂĄgua na boca que vocĂȘ estĂĄ sentindo agora. SĂŁo mais de 1400 combinaĂ§Ă”es possĂ­veis para vocĂȘ montar do jeito que o seu coraĂ§ĂŁo mandar!', NULL, 'SĂO PAULO', 1, NULL, 60, NULL, NULL, '2026-01-23 07:50:45.000', 'https://franquias.portaldofranchising.com.br/franquia-ice-cream-roll/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '119000', NULL, NULL, NULL, '60000', '0', '5', '0', '101000', NULL, 0);
