INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpir0047eh0smrba2fg6', 'QĂCULOS', 'qoculos', NULL, 'SaĂșde, Beleza e Bem Estar', 'ĂTICAS', 'VIEMOS PARA MUDAR O MERCADO ĂTICO! UM CONCEITO MODERNO E DESCOMPLICADO QUE OFERECE AOS CONSUMIDORES UMA EXPERIĂNCIA DE COMPRA INOVADORA E AOS FRANQUEADOS MAIOR EFICIĂNCIA OPERACIONAL E RENTABILIDADE.', 2018, 2020, NULL, '2026-04-01 02:00:13.485', '2025-08-11 01:37:24.339', 1277, NULL, 1, 2014, 'A QĂculos nasceu em 2014 como uma Ăłtica online, se consolidando entre as 3 maiores do Brasil em 2015. A partir de 2018 iniciou sua expansĂŁo para o varejo atravĂ©s de lojas fĂ­sicas com o sistema de franquias. Seus principais diferenciais estĂŁo nas vantagens Ă s quais os franqueados tĂȘm acesso: - Alto know-how no ramo Ăłtico e de franquias - DivulgaĂ§ĂŁo massiva em mĂ­dias on/offline - Melhores negociaĂ§Ă”es com fornecedores - Treinamento e gestĂŁo - Marcas exclusivas com excelente markup - Estrutura omnichannel e e-commerce compartilhado com os franqueados - Ferramentas digitais de apoio Ă  operaĂ§ĂŁo: estoque online, orĂ§amento digital, espelho virtual, tabela de preĂ§os online, roleta da sorte. AlĂ©m disso, a segmentaĂ§ĂŁo do pĂșblico reflete suas instalaĂ§Ă”es. O modelo QĂculos se adapta facilmente Ă  shopping centers, grandes e pequenos centros comerciais e lojas de rua. Se apresenta em dois formatos: - Multimarcas: lojas de 35 a 75m2 com mix de produtos customizado ao pĂșblico da regiĂŁo, contando com um portfĂłlio das melhores marcas mundiais e atendendo todos os pĂșblicos. - Outlets: lojas de rua a partir de 60m2 instaladas em regiĂ”es com alto fluxo de pessoas atendendo ao pĂșblico que busca baixo preĂ§o e qualidade. Trazendo em seu DNA toda sinergia que um sistema de franquias inteligente e moderno proporciona, a QĂculos foi criada para mudar o mercado Ăłtico e oferecer aos consumidores uma experiĂȘncia de compra inovadora, resultando em maior eficiĂȘncia operacional e rentabilidade aos franqueados. Aliando a expertise da equipe com a experiĂȘncia de mais de 25 anos em expansĂŁo de franquias e notĂłrio know-how de seus fundadores, obtidos atravĂ©s de franquia anterior em que chegou a atingir mais de 600 lojas abertas, a QĂculos se consolida no mercado em rĂĄpido crescimento, performando entre as melhores franquias do Brasil.', NULL, 'SĂO PAULO', 1, NULL, 116, NULL, NULL, '2026-01-22 19:36:47.000', 'https://franquias.portaldofranchising.com.br/franquia-qoculos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '220000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
