INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpl2004keh0skn3bu3ws', 'USAFLEX', 'usaflex', NULL, 'Moda', 'CALĂADOS', 'CalĂ§ados, Bolsas e AcessĂłrios.', 2015, 2016, '[\"https://www.youtube.com/watch?v=0DD-C8TvDug\",\"https://www.youtube.com/watch?v=7EaCZT3q12I\",\"https://www.youtube.com/watch?v=3KMEKfTluXo\",\"https://www.youtube.com/watch?v=dSFX6sxEedQ\"]', '2026-04-01 02:00:13.625', '2025-08-11 01:37:24.422', 1290, NULL, 1, 1998, 'Guiada por uma tradiĂ§ĂŁo de excelĂȘncia e paixĂŁo pelo conforto, a Usaflex vem expandindo sua atuaĂ§ĂŁo para que mais empreendedores possam se beneficiar do know how adquirido pela marca. Oferecemos uma possibilidade de investimento seguro, rentĂĄvel e descomplicado, que difunde e compartilha o sucesso da Usaflex atravĂ©s de um sistema de franquias. Com 9 anos de atuaĂ§ĂŁo, o canal de Franquias da Usaflex, se tornou como a primeira rede de calĂ§ados femininos de conforto e moda do Brasil, destacando-se pela qualidade, conforto e inovaĂ§ĂŁo de seus produtos. Ao longo dos Ășltimos anos a marca constrĂłi uma sĂłlida rede de franquias, que desde 2019 recebe anualmente o selo de excelĂȘncia da ABF (AssociaĂ§ĂŁo Brasileira de Franchising). A estratĂ©gia de expansĂŁo da marca foi cuidadosamente planejada, com foco em um modelo de franquia que proporcione um suporte robusto e completo aos franqueados. AlĂ©m disso, a Usaflex soube se reinventar ao longo dos anos, investindo em tecnologia e marketing para atingir novos pĂșblicos e aumentar a sua presenĂ§a no mercado nacional e internacional. O sucesso da Usaflex pode ser atribuĂ­do a sua constante busca por excelĂȘncia, adaptabilidade as tendĂȘncias do mercado e ao forte compromisso com a satisfaĂ§ĂŁo do cliente. Com uma rede com mais de 340 lojas ativas em todas as regiĂ”es do Brasil, a Usaflex nĂŁo sĂł fortaleceu a sua marca, como tambĂ©m criou uma plataforma para quem deseja empreender no setor de calĂ§ados, conquistando a confianĂ§a dos franqueados e tornando-se um exemplo no franchising Brasileiro.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 394, NULL, NULL, '2026-02-23 13:59:09.000', 'https://franquias.portaldofranchising.com.br/franquia-usaflex/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
