INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfplh004neh0sa0i8s6wz', 'CRIAMIGOS OFICINA DE URSOS', 'criamigos-oficina-de-ursos', NULL, 'Entretenimento e Lazer', 'BRINQUEDOS E LAZER', 'ESPALHAR AMOR EM FORMA DE PELĂCIA COM A CRIAĂĂO DE UM NOVO AMIGO, LEVANDO AO CLIENTE NĂO APENAS A COMPRA DE UM PRODUTO, MAS SIM UMA EXPERIĂNCIA DE AMOR.', 2018, 2019, NULL, '2026-04-01 02:00:13.658', '2025-08-11 01:37:24.438', 1293, NULL, 1, 2016, 'VocĂȘ jĂĄ imaginou fazer parte de uma jornada que vai alĂ©m de simplesmente vender produtos? Na Criamigos, estamos moldando o futuro da experiĂȘncia de encantamento, e convidamos vocĂȘ a fazer parte dessa revoluĂ§ĂŁo como nosso prĂłximo franqueado. Ao se tornar um franqueado Criamigos, vocĂȘ nĂŁo estĂĄ apenas investindo em um negĂłcio lucrativo; VocĂȘ estĂĄ se tornando um agente de transformaĂ§ĂŁo na vida das pessoas. VocĂȘ estĂĄ se tornando um agente de transformaĂ§ĂŁo na vida das pessoas. Imagine ser o responsĂĄvel por proporcionar momentos de alegria, criatividade e afeto para famĂ­lias inteiras. Ă isso que fazemos todos os dias, e queremos que vocĂȘ tambĂ©m faĂ§a parte disso. Ao se juntar Ă  famĂ­lia Criamigos, vocĂȘ terĂĄ acesso a todo o suporte necessĂĄrio para alcanĂ§ar o sucesso. Desde treinamento especializado atĂ© assistĂȘncia contĂ­nua de marketing e operaĂ§Ă”es, estamos aqui para ajudĂĄ-lo em cada etapa do caminho. EntĂŁo, se vocĂȘ compartilha nossa visĂŁo de um mundo onde o encantamento e a magia sĂŁo elementos essenciais do cotidiano, junte-se a nĂłs na missĂŁo de tornar a Criamigos a referĂȘncia definitiva no mercado nacional de experiĂȘncia de encantamento. Venha fazer parte dessa histĂłria e transforme seu sonho em realidade conosco! Seja um franqueado Criamigos!!! Franquia de Sucesso A Criamigos Ă© a franquia de excelĂȘncia, premiada com o Selo de ExcelĂȘncia em Franchising, pela ABF ( AssociaĂ§ĂŁo Brasileira de Franchising). Chancelado e validado como Franquia de Sucesso!', NULL, 'RIO GRANDE DO SUL', 1, NULL, 66, NULL, NULL, '2025-11-20 00:00:27.000', 'https://franquias.portaldofranchising.com.br/franquia-criamigos-oficina-de-ursos/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '296000', NULL, NULL, NULL, '72000', NULL, '6', '2', '380000', NULL, 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpln004oeh0sqr7csg4x', 'DOMINO`S PIZZA', 'domino-s-pizza', NULL, 'AlimentaĂ§ĂŁo', 'RESTAURANTES DE SERVIĂO COMPLETO', 'Pizzas e Sanduiches', 1967, 2008, '[\"https://www.youtube.com/watch?v=ft8Ti4C_gaI\",\"https://www.youtube.com/watch?v=rdZXFQx2phI\"]', '2026-04-01 02:00:13.669', '2025-08-11 01:37:24.443', 1294, NULL, 1, 1960, 'Fundada nos Estados Unidos em 1960 em Michigan, a Dominoâs Pizza se tornou a maior rede de pizzaria do mundo. Estamos presentes em 90 paĂ­ses e com mais de 17 mil lojas. Desembarcamos no Brasil em 1993, inaugurando nossa primeira unidade no Rio de Janeiro, no bairro de Botafogo faz da Dominoâs um dos maiores cases de sucesso do mundo. Desde agosto de 2018, a Vinci Partners, plataforma de investimentos alternativos, especializada em gestĂŁo de recursos, de patrimĂŽnio e em assessoria financeira, assumiu a gestĂŁo da Dominoâs Pizza, como Master Franqueados da marca no Brasil, garantindo uma gestĂŁo ĂĄgil, moderna e segura, com oportunidades para expansĂŁo em todos os estados do paĂ­s. Atualmente somos uma rede com mais de 240 lojas e nossa expectativa Ă©, em 5 anos, atualizar esse nĂșmero para 650 Dominoâs no Brasil. Mesmo sendo a nĂșmero 1, seguimos com jeito de pizzaria de bairro, mantendo estratĂ©gias locais, focadas em satisfazer os clientes em qualquer regiĂŁo. E Ao longo desses anos, investimos em tecnologia e delivery, sempre com uma visĂŁo, melhorar a experiĂȘncia dos amantes de pizza. O delivery Ă© o DNA da marca, entregamos mais de 12 milhĂ”es de pizzas por ano! A estratĂ©gia Ă© sĂłlida e pautada em velocidade na entrega, promoĂ§Ă”es agressivas, produtos de alta qualidade e inovaĂ§ĂŁo tecnolĂłgica. A gente ama o que faz e sabe que o brasileiro Ă© apaixonado por pizzas. Por isso, nossa missĂŁo Ă© vender pizza com mais diversĂŁo', NULL, 'RIO DE JANEIRO', 1, NULL, 173, NULL, NULL, '2026-02-24 17:02:56.000', 'https://franquias.portaldofranchising.com.br/franquia-dominos-pizza-alimentacao/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '330000', NULL, NULL, NULL, '50000', '0', '6', '4', '240000', NULL, 0);
