INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmf004ueh0sjwl3h7qv', 'Cacau Show', 'cacau-show', 'SĂŁo Paulo', '', '', '', NULL, 2008, '[\"https://www.youtube.com/watch?v=bJ2pw45Vz64\",\"https://www.youtube.com/watch?v=6DrUi0w2su0\",\"https://www.youtube.com/watch?v=ZtnANADhMnk\",\"https://www.youtube.com/watch?v=8XjnTH1BjlE\",\"https://www.youtube.com/watch?v=zonJVZVmSI8\"]', '2026-04-02 13:17:12.859', '2025-08-11 01:37:24.472', 1300, '0165862e-523b-4bef-a4ae-c8c449dce62b', 1, NULL, 'Especialista em chocolates com diferentes intensidades de sabor, a Cacau Show estĂĄ em constante inovaĂ§ĂŁo e oferece uma variedade de produtos para todos os gostos e momentos, alĂ©m de ser lĂ­der do segmento e dona de produtos de alto giro. Com +14 milhĂ”es de seguidores nas redes sociais, estamos presente nos maiores meios de comunicaĂ§ĂŁo do paĂ­s, sendo o maior anunciante de chocolate do paĂ­s, com mais de vinte campanhas de publicidade no ano. Invista em uma marca consolidada no mercado nacional de franquias, que jĂĄ recebeu diversos prĂȘmios ao longo dos anos. Ă a seguranĂ§a e solidez que seu investimento precisa, com modelos de negĂłcio de acordo com o seu perfil.', 'Sobre a franquia CACAU SHOW\r\nFundaĂ§ĂŁo da franquia Cacau Show\r\n\r\nEspecialista em chocolates com diferentes intensidades de sabor, a Cacau Show estĂĄ em constante inovaĂ§ĂŁo e oferece uma variedade de produtos para todos os gostos e\r\nmomentos, alĂ©m de ser lĂ­der do segmento e dona de produtos de alto giro.\r\n\r\n\r\nCom +14 milhĂ”es de seguidores nas redes sociais, estamos presente nos maiores meios de comunicaĂ§ĂŁo do paĂ­s, sendo o maior anunciante de chocolate do paĂ­s, com mais de vinte campanhas de publicidade no ano.\r\n\r\nInvista em uma marca consolidada no mercado nacional de franquias, que jĂĄ recebeu diversos prĂȘmios ao longo dos anos.\r\n\r\nhttps://static.portaldofranchising.com.br/central/material-de-clientes/cacau-show/mini-site/cacaushowpremios.jpg', 'SĂŁo Paulo', NULL, NULL, 4661, NULL, NULL, '2025-10-02 14:08:03.000', 'https://franquias.portaldofranchising.com.br/franquia-cacau-show-valor/', 'Faturamento', 'Compras', NULL, 1, 4.714285714285714, 33, 7, NULL, 3, 1, '[\"RANKING_CATEGORIA\",\"QUIZ\",\"HOME_DESTAQUES\"]', '310000', NULL, NULL, NULL, '40000', NULL, '0', '0', '230000', '40000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmk004veh0saeiqdj06', 'DECOR COLORS', 'decor-colors', NULL, 'Casa e ConstruĂ§ĂŁo', 'CONSTRUĂĂO', 'Empresa especializada em revestimento e decoraĂ§ĂŁo.', 2021, 2022, '[\"https://www.youtube.com/watch?v=LdPMkF17Gk8\",\"https://www.youtube.com/watch?v=EDhVzcyWm_k\",\"https://www.youtube.com/watch?v=jqQ7_no5cgo\"]', '2026-04-01 02:00:13.746', '2025-08-11 01:37:24.476', 1301, NULL, 1, 2021, 'A DECOR COLORS Ă© uma soluĂ§ĂŁo inovadora para transformar o mercado de revestimentos e tintas, oferecendo produtos de fĂĄcil aplicaĂ§ĂŁo e resultado diferenciado. Ficou ainda mais conhecida atravĂ©s de sua participaĂ§ĂŁo no programa SHARK TANK BRASIL, onde obteve investimento recorde junto ao Sr. JOĂO APOLLINĂRIO, presidente e fundador da POLISHOP (conhecida rede de varejo do PaĂ­s). A soluĂ§ĂŁo DECOR COLORS foi criada pelo empresĂĄrio LEONARDO JOSĂ DA SILVEIRA ARRUDA, comerciante de sucesso que desenvolveu o produto/marca prĂłpria de revestimentos, com aparĂȘncia de cimento queimado. LEONARDO JOSĂ DA SILVEIRA ARRUDA, em 2010, fundou a loja de tintas e revestimentos denominada LĂO TINTAS. Para alavancar as vendas, LEONARDO idealizou oferecer produtos diferenciados que suprissem a demanda do mercado. Para tanto, desenvolveu a marca DECOR COLORS, com diferentes soluĂ§Ă”es de pinturas com efeito \"cimento queimado\", bem como espĂĄtulas especiais para a aplicaĂ§ĂŁo do produto. Os produtos da DECOR COLORS possuem excelente aceitaĂ§ĂŁo pelo mercado, atravĂ©s de vendas realizadas em todo Brasil. Nas redes sociais, a marca jĂĄ conta com milhares de seguidores, em razĂŁo da qualidade do produto e pela facilidade da aplicaĂ§ĂŁo. Ainda, o negĂłcio estĂĄ em constante evoluĂ§ĂŁo, tendo sido introduzidos novos produtos recentemente, como a SoluĂ§ĂŁo Total, Quartzo e outros. ApĂłs os investimentos realizados pelo Sr. JOĂO APOLLINĂRIO na empresa, a DECOR COLORS obteve melhorias significativas na distribuiĂ§ĂŁo, nos processos de instalaĂ§ĂŁo no mercado, tendo sido desenvolvido o modelo de franquia mais adequado para o negĂłcio.', NULL, 'SĂO PAULO', 1, NULL, 637, NULL, NULL, '2026-02-06 10:50:26.000', 'https://franquias.portaldofranchising.com.br/franquia-decor-colors/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '62845', NULL, NULL, NULL, '15000', '0', '40', '3', '2500', '1000', 0);
