INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mfpmt004xeh0sf5i9r84d', 'EMPĂRIO ESSENZA', 'emporio-essenza', NULL, 'SaĂșde, Beleza e Bem Estar', 'COSMĂTICOS E PERFUMARIA', 'A EmpĂłrio Essenza tem a natureza e os vinhedos da Serra GaĂșcha como sua principal fonte de inspiraĂ§ĂŁo para desenvolver fĂłrmulas inovadoras oriundas da cadeia produtiva do vinho e da uva.', 2011, 2014, '[\"https://www.youtube.com/watch?v=lH5cAIt_-tE\"]', '2026-04-01 02:00:13.770', '2025-08-11 01:37:24.485', 1303, NULL, 1, 2005, 'EmpĂłrio Essenza: Transforme a EssĂȘncia da Serra GaĂșcha em um NegĂłcio de Sucesso Seja o embaixador de uma marca que encanta clientes e oferece alta rentabilidade no prĂłspero mercado de bem-estar e sofisticaĂ§ĂŁo. Nascida no coraĂ§ĂŁo da Serra GaĂșcha, a EmpĂłrio Essenza Ă© mais do que uma franquia de cosmĂ©ticos e aromas; Ă© um convite para um estilo de vida. Traduzimos a beleza e a riqueza dos vinhedos em produtos de alta qualidade que criam conexĂ”es emocionais duradouras com os consumidores. Para o investidor, isso representa uma oportunidade alinhada a um propĂłsito claro, sustentada por uma demanda crescente e um modelo de negĂłcio jĂĄ validado no mercado. Nossas lojas vĂŁo alĂ©m da venda de produtos, elas proporcionam experiĂȘncias sensoriais marcantes, que atraem continuamente novos clientes e cultivam uma fidelizaĂ§ĂŁo sĂłlida e duradoura. A Oportunidade: Por que investir na EmpĂłrio Essenza? Mercado em AscensĂŁo: O setor de cosmĂ©ticos e bem-estar Ă© um dos mais resilientes e lucrativos do varejo. VocĂȘ investirĂĄ em um segmento com pĂșblico cativo e crescente. Diferencial Exclusivo: Nossas fĂłrmulas, enriquecidas com ativos da uva e do vinho, contam uma histĂłria Ășnica que nos posiciona em um patamar de exclusividade, longe da concorrĂȘncia comum. Marca Consolidada: Com mais de 20 anos de histĂłria, somos uma marca com forte reconhecimento, sinĂŽnimo de qualidade, elegĂąncia e confianĂ§a. Alta Rentabilidade: Oferecemos um modelo de negĂłcio otimizado, com excelente margem de lucro e um portfĂłlio de produtos diversificado que atende a mĂșltiplos desejos de consumo, de cuidados pessoais a decoraĂ§ĂŁo de ambientes.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 45, NULL, NULL, '2025-10-27 08:31:22.000', 'https://franquias.portaldofranchising.com.br/franquia-emporio-essenza/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '166500', NULL, NULL, NULL, '18000', '0', '30', '2', '191800', NULL, 0);
