INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme6mrx35005deh0s7n2zr1r5', 'DI SANTINNI', 'di-santinni', NULL, 'Moda', 'CALĂADOS', 'A Di Santinni Ă© a maior Franqueadora de CalĂ§ados Multimarcas. Atua com o pĂșblico feminino, masculino e infantil. E com a sua tecnologia prĂłpria DS SMART.', 2003, 2021, '[\"https://www.youtube.com/watch?v=6n8FufSkTVA\",\"https://www.youtube.com/watch?v=XNMlhNQfyHE\"]', '2026-04-01 02:00:13.934', '2025-08-11 01:46:54.018', 1319, NULL, 1, 1980, 'A Di Santinni surgiu com uma pequena fĂĄbrica de calĂ§ados em 1980. Motivados pela paixĂŁo em trazer para o mercado uma marca com modelos exclusivos e preĂ§os justos, buscamos novos horizontes e partimos de vez para o varejo com nossa primeira loja no Rio de Janeiro, no Norte Shopping em 1986. Acreditamos na histĂłria que construĂ­mos. Nossa comunidade Ă© a inspiraĂ§ĂŁo para tudo o que fazemos. Trabalhamos para entregar a melhor experiĂȘncia e acreditamos que preĂ§os acessĂ­veis com facilidade de pagamento abrem mais portas. A trajetĂłria ascendente, com a inauguraĂ§ĂŁo contĂ­nua de lojas, levou a Di Santinni a mudar seu modelo de expansĂŁo, optando em 2003 pelo franchising. SĂŁo 21 anos de parceria com empreendedores que enxergaram no poder da marca, na qualidade dos produtos e na franquia a oportunidade de crescer seu patrimĂŽnio e mudar de vida. VANTAGENS COMPETITIVAS Atende ao maior pĂșblico consumidor da categoria no Brasil (Classes B, C e D) Mix de produtos que atende todos os pĂșblicos e ocasiĂ”es Marcas e produtos exclusivos Melhores preĂ§os de aquisiĂ§ĂŁo e venda do mercado CartĂŁo prĂłprio, que oferece maior crĂ©dito e prazo de pagamento para o cliente Tecnologia proprietĂĄria 3 Centros de DistribuiĂ§ĂŁo prĂłprios, com frota prĂłpria de caminhĂŁo Com fabricaĂ§ĂŁo prĂłpria, e revendendo as principais marcas de calĂ§ados do mercado, a Di Santinni se estruturou mais ainda para o crescimento, com aĂ§Ă”es de relevĂąncia para o desenvolvimento do negĂłcio, como: LanĂ§amento do cartĂŁo de crĂ©dito prĂłprio (DS Card) em 2012; CriaĂ§ĂŁo do DS LAB em 2017, com tecnologia de automaĂ§ĂŁo no ponto de venda; InauguraĂ§ĂŁo do novo centro de distribuiĂ§ĂŁo em 2022. Hoje, a Di Santinni Ă© reconhecida como uma das maiores multimarcas de calĂ§ados do Brasil, com um ponto de venda diferenciado que dĂĄ visibilidade aos produtos mais desejados pelos clientes. Ă uma marca em franca ascensĂŁo e que estĂĄ inovando o segmento de calĂ§ados, DS Smart DS SMART Ă© o nome do atual modelo de franquia da Di Santinni. Contando com lojas a partir de 130 mÂČ, este modelo envolve muita inovaĂ§ĂŁo e tecnologia, tendo como principais objetivos as melhorias de performance de vendas, rentabilidade da operaĂ§ĂŁo e experiĂȘncia do cliente. O segmento de calĂ§ados apresenta diversos desafios e a DS SMART foi desenvolvida para resolvĂȘ-los, sĂŁo eles: Acuracidade de estoque Maior precisĂŁo na escala de funcionĂĄrios Atendimento mais rĂĄpido e personalizado para o cliente Maior rentabilidade para o franqueado A tecnologia proprietĂĄria possibilita a rĂĄpida implementaĂ§ĂŁo de soluĂ§Ă”es exclusivas para a evoluĂ§ĂŁo contĂ­nua da operaĂ§ĂŁo do franqueado.', NULL, 'SĂO PAULO', 1, NULL, 128, NULL, NULL, '2026-01-23 07:55:05.000', 'https://franquias.portaldofranchising.com.br/franquia-di-santinni/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '585000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
