INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme80t4ue005geh0swrih9mf5', 'SOULIER', 'soulier', NULL, 'Moda', 'CALĂADOS', 'CalĂ§ados, Bolsas e AcessĂłrios Femininos.', 2018, 2019, '[\"https://www.youtube.com/watch?v=hbuiorNE3Kc\",\"https://www.youtube.com/watch?v=sKAKVQ36Zgw\"]', '2026-04-01 02:00:13.964', '2025-08-12 01:07:31.510', 1322, NULL, 1, 1982, 'DESDE DE 1982 LEVAMOS CONFORTO E COR AOS PĂS DE MULHERES INDEPENDENTES, QUE SABEM ONDE PISAM. Criamos sempre um ambiente alegre, onde a felicidade passe pelo produto e equipe atĂ© chegar Ă s nossas clientes. Produto: Prezamos pelo conforto. Nosso elo de qualidade Ă© o pisar macio. E nossos pilares sĂŁo: Feito Ă  mĂŁo Couro Conforto Estampa exclusiva Feito no Brasil Atemporal Clube Soulier: O CLUBE SOULIER AUMENTA SUA TAXA DE RETORNO EM 20% AS CLIENTES BONIFICADAS QUE RETORNAM, GASTAM 4X O VALOR DO BĂNUS EM MĂDIA! O faturamento das lojas crescem de 10% a 15% em menos de 3 meses atravĂ©s de um bĂŽnus futuro concedido aos seus clientes. Marca consolidada e experiĂȘncia Desde 1982 temos experiĂȘncia em desenvolvimento, fabricaĂ§ĂŁo e comercializaĂ§ĂŁo de toda linha de calĂ§ados e acessĂłrios femininos. As melhores redes jĂĄ foram nossas clientes. GestĂŁo simples e descomplicada Nossa Equipe de GestĂŁo Ă© altamente qualificada e disponĂ­vel. Utilizamos os melhores softwares e ferramentas do varejo para que cada franqueado possa focar mais no que Ă© primordial: encantar nossos clientes e gerar lucro. Mix de produtos diferenciado com bossa carioca Nossos produtos sĂŁo 100% exclusivos e nos destacamos pelo conforto associado ao uso de cores, materiais e estampas especiais que remetem ao estilo do viver bem cada dia. AlĂ©m da variedade de modelos, o nosso mix de preĂ§os Ă© completo e competitivo, podendo atender a diversas ocasiĂ”es para uso pessoal ou para presentear. Margem de lucratividade superior ao do segmento 14% de lucro esperado com um retorno mais rĂĄpido do investimento.', NULL, 'RIO DE JANEIRO', 1, NULL, 21, NULL, NULL, '2026-01-12 00:00:10.000', 'https://franquias.portaldofranchising.com.br/franquia-soulier/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '370000', NULL, NULL, NULL, '60000', '0', '16', '6', '250000', '60000', 0);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cme80t4vg005heh0sus3xh0y8', 'KLIN', 'klin', NULL, 'Moda', 'CALĂADOS', 'Marca de calĂ§ados infantis, sempre preocupada com o caminhar saudĂĄvel dos pequenos e se consolidou como lĂ­der na produĂ§ĂŁo e venda de calĂ§ados infantis no Brasil pela qualidade e tecnologia.', 2022, 2022, '[\"https://www.youtube.com/watch?v=J_rOuID6H4g\",\"https://www.youtube.com/watch?v=fZsjfzdDnA8\"]', '2026-04-01 02:00:13.975', '2025-08-12 01:07:31.564', 1323, NULL, 1, 1983, 'A franquia Klin nasceu em um novo tempo, com um modelo de negĂłcio leve, digital e sustentĂĄvel, pensado para o varejo do futuro. Com mais de 40 anos de histĂłria no mercado infantil, aliamos tradiĂ§ĂŁo e inovaĂ§ĂŁo para oferecer uma operaĂ§ĂŁo ĂĄgil, integrada ao e-commerce e voltada para o relacionamento prĂłximo com o consumidor. Nossas lojas funcionam como centros de experiĂȘncia e distribuiĂ§ĂŁo, sem a necessidade de estruturas complexas ou caixas fĂ­sicos. O atendimento Ă© feito no celular, ao lado do cliente, com suporte de ferramentas como vendas via WhatsApp, live commerce e entregas rĂĄpidas por motoboy. Franqueados Klin contam com um modelo de abastecimento flexĂ­vel, inteligĂȘncia artificial para gestĂŁo do ponto de venda, e apoio constante em marketing digital. Tudo isso com baixo investimento inicial, rĂĄpido ponto de equilĂ­brio e alta atratividade no segmento infantil â um dos mais resilientes e promissores do varejo. Invista em um negĂłcio preparado para o presente e o futuro. Seja um franqueado Klin.', NULL, 'SĂO PAULO', 1, NULL, 11, NULL, NULL, '2026-01-22 17:57:31.000', 'https://franquias.portaldofranchising.com.br/franquia-klin/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '155000', NULL, NULL, NULL, '65000', '0', '5', '1', '90000', NULL, 0);
