INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmembbtp40007eh0sw94ltza6', 'LILICA & TIGOR', 'lilica-tigor', NULL, 'Moda', 'VESTUĂRIO', 'Somos uma empresa nacional de indĂșstria e franquias de moda infantil, com personagens de forte identificaĂ§ĂŁo com o pĂșblico infantil entre 0 a 12 anos.', 2000, 2004, '[\"https://www.youtube.com/watch?v=3pvNOXMSfoo\",\"https://www.youtube.com/watch?v=dP6iOx9SqeE\",\"https://www.youtube.com/watch?v=Cc4J_EmQKnQ\",\"https://www.youtube.com/watch?v=V2gLj-s0XVo\"]', '2026-04-01 02:00:14.185', '2025-08-22 01:10:46.168', 1349, NULL, 1, 1964, 'As marcas Lilica Ripilica e Tigor T. Tigre pertencem Ă  Marisol, a maior indĂșstria e rede de moda infantil do Brasil. LanĂ§ada hĂĄ 31 anos, a marca Lilica Ripilica jĂĄ estampou a capa da Vogue e apresentou coleĂ§Ă”es na SĂŁo Paulo Fashion Week, principal semana de moda do Brasil. Tigor T. Tigre, no mercado desde 1993, jĂĄ transportou seu tigre das estampas para uma montanha-russa no Beto Carrero World, o maior parque de diversĂ”es da AmĂ©rica Latina. Desde 2000, as marcas estĂŁo Ă  venda nas lojas Lilica&Tigor, conhecidas por mais de 102 milhĂ”es de brasileiros, segundo o Datafolha. A operaĂ§ĂŁo de franquias, em atuaĂ§ĂŁo hĂĄ 23 anos, Ă© marcada por inovaĂ§Ă”es alinhadas Ă s tendĂȘncias de mercado. Repaginadas em 2023, as lojas tĂȘm detalhes lĂșdicos que evidenciam as peĂ§as. O novo projeto arquitetĂŽnico dĂĄ ĂȘnfase aos personagens, que assumem o papel de manequins e vestirĂŁo os lanĂ§amentos das duas marcas infantis. As mudanĂ§as foram planejadas para aprimorar a experiĂȘncia dos clientes, alĂ©m de aproximar as novas geraĂ§Ă”es da loja fĂ­sica. Mix diverso de produtos AlĂ©m das coleĂ§Ă”es tĂȘxteis, as marcas Lilica Ripilica e Tigor T. Tigre lanĂ§am, anualmente, duas coleĂ§Ă”es de calĂ§ados, que permitem a compra de looks completos para crianĂ§as de 0 a 12 anos. Em adiĂ§ĂŁo, o mix de produtos oferece meias, Ăłculos de sol e mochilas dos personagens. Lilica&Tigor Ă© resultado de quase seis dĂ©cadas de expertise Gestora das marcas Lilica Ripilica, Tigor T. Tigre, Marisol, Hapier, Pakalolo Soul e Lov.it, a catarinense Marisol S.A. surgiu em 1964 como uma fabricante de roupas de praia e chapĂ©us. Hoje, a empresa dedica-se a criar produtos pensados para o futuro da infĂąncia e Ă© referĂȘncia no segmento infantil. Anualmente, sĂŁo cerca de 15 milhĂ”es de peĂ§as produzidas.', NULL, 'SANTA CATARINA', 1, NULL, 28, NULL, NULL, '2026-01-28 11:47:01.000', 'https://franquias.portaldofranchising.com.br/franquia-lilica-e-tigor-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '360000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmembg8l90008eh0sjd7xitqa', 'BESPEAK', 'bespeak', NULL, 'EducaĂ§ĂŁo', 'EDUCAĂĂO', 'A Bespeak Ă© uma franquia de escolas de oratĂłria, com cursos 100% prĂĄticos, turmas exclusivas, metodologia Ășnica e suporte completo, focada em transformar comunicaĂ§ĂŁo pessoal e profissional.', 2022, 2024, '[\"https://www.youtube.com/watch?v=kjqyogmTgOQ\",\"https://www.youtube.com/watch?v=qoh6aOplOIY\",\"https://www.youtube.com/watch?v=TWB2M_ybAGU\"]', '2026-04-01 02:00:14.195', '2025-08-22 01:14:12.093', 1350, NULL, 1, 2010, 'A Bespeak Ă© a melhor escola de oratĂłria do Brasil. Com mais de 15 anos de experiĂȘncia prĂĄtica, desenvolvemos uma metodologia autoral 100% focada em prĂĄtica, transformaĂ§ĂŁo e protagonismo do aluno, validada por mais de 5 mil alunos e mais de 100 empresas atendidas. Oferecemos cursos em trĂȘs formatos â imersĂŁo, programas de 2 e 4 meses â alĂ©m de treinamentos para crianĂ§as e soluĂ§Ă”es corporativas personalizadas para setores como agronegĂłcio, direito, varejo e polĂ­tica. Atendemos pĂșblicos das classes A e B, com diferentes opĂ§Ă”es de tempo e investimento. Mais do que cursos, criamos uma comunidade forte e engajada por meio do nosso Clube de OratĂłria, com encontros, desafios, eventos e trilhas contĂ­nuas de desenvolvimento â que fidelizam alunos e posicionam a Bespeak como referĂȘncia nacional em comunicaĂ§ĂŁo prĂĄtica. Nosso modelo de franquia foi desenhado para ser inteligente, enxuto e altamente lucrativo, com sede fĂ­sica obrigatĂłria + atuaĂ§ĂŁo regional com escola mĂłvel, permitindo expansĂŁo territorial real sem concorrĂȘncia interna. Diferenciais que tornam a franquia Bespeak Ășnica: Sistema prĂłprio e automatizado, que reduz trabalho operacional e dĂĄ escala. Time de vendas da franqueadora atua de forma contĂ­nua, gerando matrĂ­culas e permitindo operar com equipe reduzida. Custo operacional enxuto, com uso intensivo de tecnologia e estrutura compartilhada. Franqueado como professor, aumentando a margem de lucro e autoridade local. Exclusividade por regiĂŁo, e nĂŁo apenas por cidade, garantindo proteĂ§ĂŁo e crescimento sustentĂĄvel. Sem venda casada de material didĂĄtico â aqui, vendemos conhecimento e transformaĂ§ĂŁo. PortfĂłlio completo: cursos infantis, adultos, empresariais e por nicho, com opĂ§Ă”es adaptadas a diferentes pĂșblicos. Clube ativo e crescente, que gera recorrĂȘncia e fortalece a comunidade. Suporte premium e prĂłximo da franqueadora, com foco total na qualidade de cada unidade â nĂŁo na expansĂŁo desenfreada da rede. A Bespeak une excelĂȘncia pedagĂłgica, inteligĂȘncia operacional e um modelo de negĂłcio feito para quem quer impactar vidas com oratĂłria e construir um negĂłcio sĂłlido, escalĂĄvel e respeitado.', NULL, 'RIO GRANDE DO SUL', 1, NULL, 2, NULL, NULL, '2025-10-09 00:00:37.000', 'https://franquias.portaldofranchising.com.br/franquia-bespeak/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
