INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmf21euhv000leh0s3v2etpjm', 'APTK', 'aptk', NULL, 'AlimentaĂ§ĂŁo', 'BARES', 'Loja de coquetĂ©is engarrafados e acessĂłrios de coquetelaria. Diversas opĂ§Ă”es de drinks clĂĄssicos, autorais e collabs. Presentes memorĂĄveis e opĂ§Ă”es personalizadas do melhor da coquetelaria brasileira.', 2022, 2023, '[\"https://www.youtube.com/watch?v=ftPd2Bw5nR4\"]', '2026-04-01 02:00:14.295', '2025-09-02 01:17:29.826', 1363, NULL, 1, 2016, 'Tenha uma franquia da Rede APTK e faĂ§a histĂłria conosco. A APTK Spirits estĂĄ selecionando pessoas interessadas em ser franqueadas das lojas APTK Spirits, para atuaĂ§ĂŁo em diversas regiĂ”es do paĂ­s. Oferecemos um modelo de negĂłcio extremamente atrativo, com uma relaĂ§ĂŁo de serviĂ§os e suporte para contribuir com sua performance. Hoje, a Rede APTK conta com aproximadamente 20 lojas presentes nos estados de SP, RJ, DF, RS, BH e PR. Em nossos PDVs, vocĂȘ encontra coquetĂ©is engarrafados exclusivos, de produĂ§ĂŁo prĂłpria, acessĂłrios premium de coquetelaria e uma seleĂ§ĂŁo de gelos gourmet. Ă uma oportunidade Ășnica para iniciar seu negĂłcio prĂłprio no inovador segmento de coquetĂ©is prontos para beber, a categoria de bebidas alcoĂłlicas que mais cresce no mundo todo. Para facilitar a ocupaĂ§ĂŁo de pontos nos diversos territĂłrios mapeados por nĂłs, dispomos de dois formatos de franquias: lojas e quiosques. Perfil* - Lojas: 35 mÂČ e Quiosques: 20 mÂČ *Necessidade de ponto de hidrĂĄulica. Procuramos pessoas com vivĂȘncia comercial, preferencialmente no varejo bares/restaurantes, coquetelaria e alta gastronomia, e que preencham as qualidades abaixo: Residir na regiĂŁo da franquia; Disponibilidade para dedicaĂ§ĂŁo integral Ă  loja; Conhecimento do mercado regional; DesejĂĄvel experiĂȘncia no varejo; Excelente relacionamento interpessoal; Habilidade gerencial; Capacidade de vendas; GestĂŁo de equipe de vendas;', NULL, 'SĂO PAULO', 1, NULL, 11, NULL, NULL, '2025-09-12 09:51:57.000', 'https://franquias.portaldofranchising.com.br/franquia-aptk/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
