kies/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '124000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmf6bkx1x0000eh0skvzxmz9u', 'SORRIFĂCIL CLĂNICA DENTĂRIA', 'sorrifacil-clinica-dentaria', NULL, 'SaĂșde, Beleza e Bem Estar', 'ODONTOLOGIA', 'PrestaĂ§ĂŁo de serviĂ§os odontolĂłgicos com clĂ­nicas multidisciplinares.', 2016, 2018, '[\"https://www.youtube.com/watch?v=J_3xNjw4G6s\",\"https://www.youtube.com/watch?v=47gNGT3NcoY\"]', '2026-04-01 02:00:14.333', '2025-09-05 01:13:13.940', 1368, NULL, 1, 2006, 'Com 15 anos de histĂłria e mais de 100 clĂ­nicas odontolĂłgicas distribuĂ­das pelo territĂłrio nacional e uma no Uruguai, a SORRIFĂCIL â A maior rede prĂłpria de clĂ­nicas odontolĂłgicas do paĂ­s â surgiu do anseio de dois jovens dentistas recĂ©m-formados em tornar a odontologia acessĂ­vel a todas as classes sociais, atendendo desde crianĂ§as atĂ© idosos. A primeira clĂ­nica da rede abriu suas portas no mĂȘs de junho de 2006 na cidade de GravataĂ­, no Estado do Rio Grande do Sul. A SORRIFĂCIL segue seu plano de expansĂŁo embasado em valores como a acessibilidade aos produtos, serviĂ§os odontolĂłgicos e saĂșde bucal, qualidade e confianĂ§a, a fim de tornar a odontologia facilitada para todos e todas. A SORRIFĂCIL acredita tanto em seu modelo que Ă© a maior rede de clĂ­nicas odontolĂłgicas com unidades prĂłprias do paĂ­s. A filosofia inicial da SORRIFĂCIL Ă©: âVendemos o que operamosâ. A SORRIFĂCIL busca parceiros franqueados que proporcionem a seus pacientes bem-estar e saĂșde humanizados. AlĂ©m da transferĂȘncia de know-how, assessoria especializada e apoio ao FRANQUEADO, a SORRIFĂCIL, atravĂ©s de seu modelo de negĂłcios, adota, como de fato vem adotando, um posicionamento diferenciado em relaĂ§ĂŁo ao mercado, visando melhorar a qualidade de vida de nossos pacientes e FRANQUEADOS em todos os aspectos possĂ­veis. Seja um franqueado SorrifĂĄcil e venha fazer parte da nossa famĂ­lia!', NULL, 'SĂO PAULO', 1, NULL, 107, NULL, NULL, '2025-09-17 17:03:55.000', 'https://franquias.portaldofranchising.com.br/franquia-sorrifacil-clinica-dentaria-odontologia/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfewao870000eh0sxqkkr8nz', 'LIZ LINGERIE', 'liz-lingerie', NULL, 'Moda', 'VESTUĂRIO', 'Roupas Ăntimas, esporte, praia, vestuĂĄrio e acessĂłrios.', 2012, 2014, NULL, '2026-04-01 02:00:14.343', '2025-09-11 01:15:17.286', 1370, NULL, 1, 1989, 'A LIZ Uma marca, trĂȘs palavras: SoluĂ§ĂŁo, Conforto e PaixĂŁo! \"Quando se veste uma lingerie Liz, Ă© assim... VocĂȘ se sente diferente...\" DeclaraĂ§ĂŁo espontĂąnea de muitas de nossas consumidoras, simplesmente pelo fato de que: conforto nĂŁo se vĂȘ, se sente. E a Franquia Liz Ă© mesmo assim, elaborada desde o fio de nossas maravilhosas e exclusivas microfibras atĂ© os milĂ­metros que fazem toda a diferenĂ§a no vestir. Uma equipe de verdadeiras experts, que trabalha com um olho na emoĂ§ĂŁo e outro na tecnologia, a fim de atender e acompanhar com excelĂȘncia as necessidades da mulher contemporĂąnea. Especializada em lingeries, a Liz tem como um de seus grandes diferenciais a inovaĂ§ĂŁo em seus produtos, sempre com foco em alta tecnologia, altĂ­ssima qualidade, respeito ao meio ambiente e colaboradores. Pioneira no desenvolvimento de sutiĂŁs com diferentes tamanhos de bojo (A, B, C, D, DD, F e G) no Brasil. A Liz tambĂ©m exporta seus produtos para mais de 30 paĂ­ses. As lojas contam tambĂ©m com a Liz Easywear, linha elaborada com o incomparĂĄvel algodĂŁo Pima Peruano. Produtos versĂĄteis para ficar em casa, relaxar, sair e atĂ© dormir. AlĂ©m da venda de lingeries Liz e da linha Liz Easywear, outra marca presente na franquia Ă© a In.Joy, com conceito mais fashion e antenado na moda, voltado para mulheres que gostam de cor, estampas e constantes novidades. A marca possui a mesma tecnologia, qualidade e padrĂŁo de excelĂȘncia da Liz. Outro diferencial presente na loja Ă© o serviĂ§o de Consultoria Liz Fit Sense, oferecido para todas as clientes, com objetivo de proporcionar a seguranĂ§a de adquirir o sutiĂŁ no estilo e tamanho corretos para o seu tipo de corpo. Um sutiĂŁ Liz, com toda a sua tecnologia, modelagem e soluĂ§ĂŁo precisa ser vestido em seu tamanho perfeito! Fit Sense Ă© um serviĂ§o da Liz conceituado em 2007, que capacita tecnicamente profissionais de vendas para oferecerem Ă s consumidoras a experiĂȘncia de provar e usar o sutiĂŁ no tamanho correto. VANTAGENS DE SER UM FRANQUEADO LIZ - Marca consagrada, com alta fidelizaĂ§ĂŁo de clientes. - Linha de produtos consistente, de alto giro, nĂŁo perecĂ­vel. - Produtos campeĂ”es de venda desde 1999. - 52% dos produtos na curva A. - Baixo nĂ­vel de mark-down. - Excelente rentabilidade. O PROJETO DAS LOJAS LIZ â ARQUITETO MAURĂCIO QUEIROZ O renomado designer de consumo MaurĂ­cio Queiroz assina o projeto das lojas Liz. Contrastando com o tom suave de base, o negro do mobiliĂĄrio destaca os produtos iluminados individualmente nos gaveteiros com frente de vidro â ou expostos em araras. O mobiliĂĄrio Ă© modular e presa pela versatilidade em atender um pĂșblico diverso e poder assumir diferentes formas e contextos. âA loja representa o espĂ­rito da marca: contemporĂąnea, atemporal, confortĂĄvel e funcionalâ, afirma Queiroz, que tambĂ©m Ă© responsĂĄvel pelos projetos da Vivara, Montblanc, I-Stick e Etna, entre outros. O GRUPO CMR A Liz pertence ao grupo CMR, fundado em 1989. Uma empresa de capital nacional com foco em tecnologias inovadoras, qualidade premium, responsabilidade social e ambiental. Ătica e seu forte branding consagram suas marcas no mercado nacional e internacional. InformaĂ§Ă”es sobre Franquias Liz: comercialfranquializ@cmrcia.com.br (11) 3818-0360', NULL, 'SĂO PAULO', 1, NULL, 34, NULL, NULL, '2025-11-13 09:25:24.000', 'https://franquias.portaldofranchising.com.br/franquia-liz-vestuario/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '430000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
