INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmfm1cik90001eh0siderj2l4', 'POLISHOP', 'polishop', NULL, 'SaĂșde, Beleza e Bem Estar', 'CUIDADOS PESSOAIS', 'Empresa varejista de categorias como: SaĂșde e Bem Estar, Beleza, Fitness, EletrodomĂ©sticos e Casa & Cozinha', 2024, 2024, '[\"https://www.youtube.com/watch?v=8nS64I6ykys\",\"https://www.youtube.com/watch?v=E2H2Sin2ODI\",\"https://www.youtube.com/watch?v=PlsJOWKxCqA\",\"https://www.youtube.com/watch?v=RlrkLDhAnLA\"]', '2026-04-01 02:00:14.363', '2025-09-16 01:11:04.569', 1372, NULL, 1, 1999, 'Brasil em 1999 por JoĂŁo AppolinĂĄrio. A empresa comeĂ§ou com o objetivo de oferecer produtos inovadores que resolvessem problemas do dia a dia. Desde entĂŁo, expandiu-se para diversos canais de venda: TV, internet, lojas fĂ­sicas, franquias, catĂĄlogos e televendas. Com uma abordagem multicanal pioneira, a Polishop se destacou por investir fortemente em demonstrar os benefĂ­cios dos produtos em detalhes, uma estratĂ©gia que se provou eficaz no convencimento do consumidor. Com presenĂ§a nacional por meio de lojas fĂ­sicas, e-commerce prĂłprio e redes sociais. Diferenciais da Polishop Multicanalidade (Omnichannel) - Atuamos de forma integrada em vĂĄrios canais (TV, internet, lojas, call center), permitindo ao consumidor comprar onde e como quiser. Produtos Exclusivos e Inovadores - Comercializamos itens diferenciados, muitas vezes exclusivos no Brasil, voltados para bem-estar, saĂșde, fitness, culinĂĄria e beleza. Marketing Forte e Demonstrativo - Utilizamos infomerciais e vĂ­deos demonstrativos para mostrar o funcionamento e os benefĂ­cios reais dos produtos. Marca PrĂłpria e Parcerias Globais - Trabalhamos com marcas prĂłprias (como a AirFryer by Polishop) e temos parcerias com empresas internacionais, trazendo produtos que normalmente nĂŁo estĂŁo disponĂ­veis no varejo tradicional. ExperiĂȘncia do Cliente - As lojas da Polishop funcionam tambĂ©m como showrooms, onde o cliente pode experimentar os produtos antes de comprar.', NULL, 'SĂO PAULO', 1, NULL, 44, NULL, NULL, '2025-09-22 09:40:01.000', 'https://franquias.portaldofranchising.com.br/franquia-polishop/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
