INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmhk2ejhi0004eh0su2a6xzcz', 'ACADEMIA DO ROCK', 'academia-do-rock', NULL, 'EducaĂ§ĂŁo', 'EDUCAĂĂO', 'Escola de MĂșsica. Aulas de violĂŁo, guitarra, baixo, bateria, gaita de boca, piano, teclado, ukulele e canto, prĂĄtica de bandas e eventos.', 2015, 2025, '[\"https://www.youtube.com/watch?v=f-yxp7_68eI\",\"https://www.youtube.com/watch?v=LQ1sUzC5j6c\",\"https://www.youtube.com/watch?v=-C4y-17XG9I\",\"https://www.youtube.com/watch?v=0V4ZMvmAYs0\",\"https://www.youtube.com/watch?v=q7xTW6DDefw\"]', '2026-04-01 02:00:14.833', '2025-11-04 01:24:31.014', 1425, 'ee8fc575-ddee-43fe-bec8-b5f90fe96627', 1, 2014, 'Mais do que mĂșsica, aqui ensinamos RockânâRoll! Desde cantar a tocar um instrumento, nossa missĂŁo Ă© preparar o aluno para subir no palco e dar um verdadeiro show. Do Blues ao Rock, a nossa metodologia Ă© voltada para despertar a paixĂŁo pela mĂșsica e, mais do que isso, adquirir confianĂ§a para dominar seu instrumento em diversos nĂ­veis. Tudo isso praticando com outros alunos e aprendendo na prĂĄtica a tocar em uma banda. Confira aĂ­: Garagem Ă na garagem que tudo comeĂ§a. Aqui, vocĂȘ vai entrar no mundo do rock com as primeiras noĂ§Ă”es musicais jĂĄ na prĂĄtica. Vai aprender as mĂșsicas que mais curte em aulas individuais, ou tocando com outros alunos do mesmo nĂ­vel para comeĂ§ar a sentir o gostinho de estar em uma banda. Todo grande rock star um dia deu suas primeiras notas, agora Ă© a sua vez. Stage Ă aqui que vocĂȘ vai comeĂ§ar as mostrar as tĂ©cnicas que aprendeu, em um repertĂłrio consistente para subir no palco de verdade. Isso para vocĂȘ desenvolver mais confianĂ§a tanto em casa, quanto numa banda. Esse Ă© mĂłdulo para aprimorar e afinar o seu talento para dar o prĂłximo passo. Arena Aqui a coisa comeĂ§a a ficar sĂ©ria. Para quem jĂĄ toca e domina melhor o instrumento, Ă© a hora de focar em performance de palco. VocĂȘ vai aprender todas as ferramentas de criaĂ§ĂŁo musical, tĂ©cnicas de palco como execuĂ§ĂŁo, dinĂąmica e performance. Ă a partir daqui que vocĂȘ vira um profissional. Agora Ă© sĂł conquistar o mundo. Projeto de Banda Para tocar bem um instrumento nĂŁo tem jeito: vocĂȘ precisa tocar em uma banda. Ela que vai te ajudar a desenvolver a sua tĂ©cnica, bem como melhorar a sua performance, seu ouvido e a interaĂ§ĂŁo com outros mĂșsicos. Material DidĂĄtico Todas as apostilas sĂŁo contextualizadas no Rock. Elas contam a histĂłria do seu instrumento, seus principais Ă­cones e, Ă© claro, a teoria bĂĄsica voltada para o tocar. AlĂ©m disso, possuem exercĂ­cios para vocĂȘ desenvolver sua habilidade e praticar com confianĂ§a. Eventos semestrais Os eventos semestrais ajudam a integrar os alunos, alĂ©m de colaborar para a troca de experiĂȘncias entre eles. Ă por isso que a Academia do Rock oferece dois festivais de banda: o Rock Hour, para alunos de todas as idades e o Rock Kids para alunos atĂ© 13 anos. Assim, alĂ©m das aulas prĂĄticas e teĂłricas, todos podem ganhar confianĂ§a e aprender ainda mais em apresentaĂ§Ă”es com plateias de verdade. Aulas On-line A Academia do Rock pode te ensinar a ser um roqueiro onde vocĂȘ estiver. Nas modalidades EAD, ou VideoconferĂȘncia, Ă© possĂ­vel ter acesso aos mesmos mĂ©todos e apostilas que nas aulas presenciais, alĂ©m dos mesmos professores. Informe-se e faĂ§a sua matrĂ­cula. NĂŁo deixe a distĂąncia atrapalhar o seu sonho.', NULL, 'PARANĂ', 1, NULL, 4, NULL, NULL, '2026-01-09 15:46:14.000', 'https://franquias.portaldofranchising.com.br/franquia-academia-do-rock/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '395000', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
