INSERT INTO `Franchise` (`id`, `name`, `slug`, `headquarterState`, `segment`, `subsegment`, `businessType`, `franchiseStartYear`, `abfSince`, `videoUrl`, `updatedAt`, `createdAt`, `contactId`, `ownerId`, `isActive`, `brandFoundationYear`, `description`, `detailedDescription`, `headquarter`, `isAbfAssociated`, `logoUrl`, `totalUnits`, `totalUnitsInBrazil`, `thumbnailUrl`, `lastScrapedAt`, `scrapedWebsite`, `calculationBaseAdFee`, `calculationBaseRoyaltie`, `galleryUrls`, `isReview`, `averageRating`, `ratingSum`, `reviewCount`, `unitsEvolution`, `favoritesCount`, `isSponsored`, `sponsorPlacements`, `minimumInvestment`, `maximumInvestment`, `minimumReturnOnInvestment`, `maximumReturnOnInvestment`, `franchiseFee`, `averageMonthlyRevenue`, `royalties`, `advertisingFee`, `setupCapital`, `workingCapital`, `storeArea`) VALUES ('cmimopv5k026feh0swr927yxf', 'BEAUTYPARIS', 'beautyparis', NULL, 'SaĂșde, Beleza e Bem Estar', 'COSMĂTICOS E PERFUMARIA', 'Centro de DistribuiĂ§ĂŁo de CosmĂ©ticos e Perfumaria', 2014, 2025, NULL, '2026-04-01 02:00:15.101', '2025-12-01 02:04:25.591', 1548, NULL, 1, 2011, 'A EMPRESA: A marca BeautyParis jĂĄ Ă© bem conhecida do mercado dos cosmĂ©ticos profissionais. Nossos produtos sĂŁo fabricados a partir de extratos naturais e foram lanĂ§ados e comercializados junto ao mercado de profissionais (salĂ”es de cabeleireiros), em todo o Brasil desde o ano de 2011. A aceitaĂ§ĂŁo da marca e seus produtos foram espetaculares de forma que a marca decidiu lanĂ§ar uma linha destinada aos consumidores finais. Com o mesmo carinho, dedicaĂ§ĂŁo e profissionalismo, a marca BeautyParis se preparou para se lanĂ§ar no mercado de franquias. Isso porque o conhecimento de cada passo do processo de criaĂ§ĂŁo dos produtos bem como dos seus lanĂ§amentos, observando o Feedback do mercado, testando formas comerciais utilizando-se dos salĂ”es de cabeleireiros tradicionais sĂŁo agora aproveitados e somados ao know-how da BeautyParis. O Sistema de Franquias da BeautyParis Ă© fruto desse trabalho de âlaboratĂłrioâ realizado junto aos cabeleireiros de todo o paĂ­s. Assim os franqueados da Rede BeautyParis podem se beneficiar de todo o conhecimento e experiĂȘncia da marca. A FRANQUIA A Franquia BeautyParis destaca-se pelo nicho de mercado em que estĂĄ inserida: Tratamento de Cabelos! Contudo, nĂŁo desprezamos as outras ĂĄreas do segmento, como a perfumaria, maquiagem e linha de produtos para o corpo. Isso porque a marca pretende atender os clientes em todas as suas necessidades o que alĂ©m de se posicionar como uma marca completa, tambĂ©m agrega valor ao negĂłcio franqueado, vez que eleva consideravelmente o valor do ticket de compras, gerando mais lucros para o franqueado. AlĂ©m disso, a marca estĂĄ em constante desenvolvimento de novos produtos e prevĂȘ o lanĂ§amento de mais 50 (cinquenta) novos produtos ainda no ano de 2014. A BeautyParis inova tambĂ©m no formato da operaĂ§ĂŁo, lanĂ§ando as Lojas com SalĂŁo de Beleza, onde a cliente trata do seu cabelo como num salĂŁo de cabeleireiro comum, porĂ©m sendo atendida nĂŁo por cabeleireiros comuns, mas por tĂ©cnicos em cabelos. Ela trata do cabelo no salĂŁo e ainda leva pra casa os produtos da mesma linha para continuar o tratamento em casa, e isso proporciona um resultado mais duradouro para os seus cabelos.', NULL, 'SĂO PAULO', 1, NULL, 1, NULL, NULL, '2025-12-15 07:08:40.000', 'https://franquias.portaldofranchising.com.br/franquia-beautyparis/', NULL, NULL, NULL, 1, NULL, 0, 0, NULL, 0, 0, '[]', '68500', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
